insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-10-14','Ana: Correo de Miguel Ángel, Director del CRR (residenciadir@feafescaceres.com): "Buenos días Ana te remito el informe de Alta Hospitalaria de Juan Mario San Román Blasco que se procedió en el día de ayer. Nos inciden desde la UHB que no ha sido posible la derivación del mismo a la UME debido a que no ha cumplido uno de los criterios clínicos para el ingreso en la Unidad y es que no ha habido más de 4 ingresos de larga estancia en la UHB a lo largo de este año, informándonos tanto su psiquiatra de referencia como el psiquiatra de la Unidad que si se volviese a repetir la conducta de escape que les informemos para hacer un informe nuevo de ingreso. Un cordial saludo."','2');
