insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-10-14','En relación con la autorización judicial de venta de inmuebles, nos contesta el Abogado pidiéndonos disculpas por su tardanza y diciéndonos que esta semana presenta la demanda en el Juzgado. Antes nos envía borrador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-10-14','Ana: Maite, Secc. Discapacidad, me comunica que se le concede plaza a Aitor en el nuevo C. Discapacidad de Castura que abrirá el día 1 de noviembre. No sabe qué día exactamente podrá ingresar, dependera de la organizació del propio centro, pero él será de los primero en acceder. ··························· Llamo a Esther, Ed. del CAM Fco. Pizarro, y se lo comunico. Irán organizando todo de cara al traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-14','Ana: Llamada de Clara, TS C.Salud Guadalupe (927 154 305): Juan no ha acudido a la cita del inyectable a su hora. La enfermera le ha llamado a ella muy enfadada y le ha dicho que le trasladen a Juan que no acuda ya hoy, que debe ir mañana a las 13:10 h. ··············· Tras intentar hablar con Juan, sin éxito, pido a Toni de Futuex que Teresa se encargue de llamarlo y comunicárselo. ·············· Al preguntar a Toni al final de la mañana, me responde en un correo: "buenas Ana, lo ha intentado un monton de veces y todavia nada... pensaba escribirte cuando tuvieramos algo concreto Lo de intentar coincidir la visita con el dia de hoy, como comentamos la semana pasada ha sido del todo inviable, Teresa tenia otras gestiones programadas y la otra compañera de caceres del programa que te comente hasta diciembre de apoyo, esta de cuarentena preventiva unos dias, asiuqe por eso no fuero hoy, he iran en principio proximo 20 de octubre" ····················· Llamo a Clara, pero me dicen que ha tenido que salir a una consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-10-13','Ana: Correo de Miguel Ángel, Director CRR-CC: "Buenas tardes el sábado se procedió a ingreso voluntario por parte de Consuelo Nevado Pacheco en la UHB del Hospital San Pedro de Alcántara debido a desestabilización psicopatológica. Os mantendremos informados. Un cordial saludo."','2');
