insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-10-15','Ana: Adelanto escaneadas por mail a Alberto Arias, TO EVD-Brozas (alberto.arias@salud-juntaex.es), las distinta aceptaciones PIA de Julián Ramón (SAD Municipal, Prestación Vinculada al SAD privado, e Ingreso en Residencia Buenos Aires, de su localidad) debidamente firmadas y selladas por el Representante Legal. ····························· *Entrego a Belén, secc. ecca., Alta de Terceros ya firmado por el D.Gerente, para que lo lleven al banco cuando puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-10-15','TERESA LLAMO A LA PRIMA GEMA (667095756), LE COMENTO EL TEMA DEL CONTRATO QUE ES NULO PUES LHA FIRMADO JUANA Y QUE LO VAMOS A COMUNICAR A LA COMPAÑIA Y DEVOLVER LOS RECIBOS. ELLA ME COMENTA QUE VAN A PEDIR LA REMOCION DE LA TUTELA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-15','TERESA ELEN HA IDO A LA GUARDAI CIVIL A DENUNICAR AL HERMANO POR TOCAMIENTOS 4DE SU HERMANO HE HABLADO CON LOS GUARDIAS MIGUEL E IVAN (924 50 00 08) Y ME COMENTAN QUE NO TIENEN CLARO SI ELENA DICE LA VERDAD, MANIFIESTA QUE SE QUIRE IR DE CASA PERO NO QUIERE QUE LE HAGAN NADA A SU PADRE Y A SU HERMANO. LE FACILITO EL NUMERO DEL CRPS PARA QUE HABLEN CON LA PSICOLOGA TRAS HABLA CON ELLOS ME COMUNICA IVAN QUE NO LO VEN CLARO QUE VAN A MANDAR COMUNNICADO AL JUEZ Y A ESPERAR DILIGENCIAS LE INDICO QUE SE PONGAN EN CONTACTO CON LOS SSB YA QUE M ELENA NO QUIERE VOLVER A SU CASA Y ENTRAR AHORA EN UNA RESIDENCIA ES COMPLICADO POR EL COVID.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-10-08','TERESA: SE PERSONA EL TUTELA EN LA COMISION SOLICITANDO QUE QUEIRE HABLAR CON NOSOTROS. SE LE INDICA QUE AL NO TENER CITA SE LE ATENDERA MAS TARDE AMENZA CON UNA PIEDRA EN LA MANO DE PONERSE A ROMPER LOS COCHES DE LA CALLE. SEGURIDAD LLAMA A LA POLICA HABLAN CON EL Y SE MARCHAN, SE QUEDA SENTADO EN LA PUERTA DEL SEPAD A LA ESPERA DE SER ATENDIDO LE INDICAMOS QUE SUBA Y ES ATENDIDO POR ALBERTO JEFE SECCION ECO Y POR TERESA TRABAJADORA SOCIAL . ANTERIORMENE AMALIA SE INTENTA PONER EN CONTACTO CON EL PARA ESCUCHAR SU DEMANDA PERO ILDELFONOSO YA NO TIENE TELEFONO SIN DARNOS MAS EXPLICACION EN LA ENTRVISTA NOS SOLICITA ATENCION SANITARIA, ALOJAMIENTOS Y MANUNTENCION TANTO ALBERTO COMO YO LE INDICAMOS QUE 1 LA ATENCION MEDICA LA DEBE PEDIR EN EL HOSPITAL O EN SALUD MENTAL NOSOTROS NO SE LA PODEMOS DAR 2 EL ALOJAMIENTO LE INDICAMOS QUE SE LE GESTIONO INCLUIDO LA COMIDA EN EL HOSTAL EL TORREO Y QUE POR DECISION PROPIA DECIDIO IRSE. SE LE INDICA QUE VAYA DE NUEVO AL HOSAL Y PIDA ALOJAMIENTO YA QUE EL SACA TODA SU PENSION, A ESTO NOS CONTESTA QUE NO TIENE DINERO PORQUE SE LO HA GASTADO EN CRACK CON UN AMIGO LOS 225€ DE LA ASIGNACION SEMANAL ALBERTO LE PROPONE PAGAR EL HOSTAL HASTA EL DOMINGO YA QUE EL LUNES VOLVERA A COBRAR SU ASIGNACION 3. CON RESPCTO A LA MANUTENCION NO QUIERE QUE SE LA DE EN EL HOSTA SINO QUE EL SE ENCARGA DE COMPRARLA EN EL DIA, NOS PARECE BIEN YA QUE ES EL QUIEN TIENE LA GESTIONDE SU PENSION 225€ A LA SEMANA. SIN TERMINAR LA REUNION DECIDE LEVARSE Y SE MARCHA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-10-15','Ana: Llamada de Pilar, TS ESM-CC (54162), ha realizado visita domiciliaria con Pepe, Coordinador del programa de voluntariado de Cruz Roja. Clementa se niega a ingresar en residencia. Desde Cáritas se le va a retirar la ayuda con la que paga a la Auxiliar Interna que le atiende. Desde Cruz Roja le harán seguimiento e intentarán que participe en actividades de ocio (salidas acompañada al cine, por ejemplo). *Si continúa sin querer ingresar, sólo se podría, una vez constatado el empeoramiento, informar con los respectivos informes (médicos y sociales) al Jdo. y en su caso solicitar Internamiento Involuntario y/o ampliación de la incapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-15','Ana: Llamada de Clara, TS C.Salud Guadalupe (53107), me ha enviado de nuevo por fax el documento de diputación (factura) por fax. *Se lo entrego a Belén, secc. ecca. ············· En cuanto al inyectable de Juan, acudión ayer a úlitma hora y le dijeron que no iban a atenderle, que volviese hoy a las 13:10 h. ······························································································································· Correo de Toni-Futuex: "Hola ana, ya se iba Juan para ponerse el inyectable, pero estaba todo alterado porquepide el dinero ya de los 100 euros y Raquel la ts de ssb le esta "bailando el agua". Se envía adjunto, nota informativa sobre la llamada recibida de la trabajadora social del Ayuntamiento del Guadalupe, para confirmar que la ayuda que desde ese Ayuntamiento solicitaron para Juan chamorro del plan reactiva social, le ha sido aprobado (100 euros al mes durante seis meses). De ahí que este mes de octubre recibirá 200 euros de septiembre y octubre, a partir de noviembre se le ingresará los 100 euros mensuales hasta febrero 2021. Es necesario para mantener dicha ayuda, justificar el gasto de esos 100 euros, en la nota se especifica en qué se puede gastar." *Guardo en su expte. virtual la nota de seguimiento adjunta. ······························ Hablo con Alberto, jefe secc. ecca. en relación a la ayuda de diputación (plan reactiva social) concedida a Juan; acordamos que hablaré con la TS del SSB-Guadalupe, para aclarar cómo hay que justificar el gasto y si se puede llegar a un acuerdo con alguna tienda para crear allí un "depósito" de ese dinero para que adquiera los alimentos y otros productos incluídos en el programa y remitan las facturas o bien a nosotros o bien a Raquel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2020-10-15','miguel, me llaman del Jzdo de Arganda del Rey nº2 de Madrid y me piden nuestras alegaciones al respecto de pasar el expte a la CCAA de Madrid. Les expongo que no hay inconveniente al traslado del cargo a la CCAA de Madrid para lo cual me baso en el dispositivo tercero del expte de José Antonio Estrella Carrasco','2');
