insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-16','Ana: Llamo a Raquel, TS del SSB - Guadalupe (927 36 70 06 // 605 429 865): Me dicen que Raquel hoy no está en Guadalupe. Creen que en Alía. ················ Llamo al Ayto. de Alía (927 36 60 02), me comunican que está reunida, le pasarán la nota cuando termine. ·········································································· Conversación telefónica con Pilar Martín: Habló ayer con el Psiquiatra y ha decidido finalmente que la cita del día 20 sea presencial, pero a las las 12 h. *Me lo enviarán por fax desde Salud Mental, para que se lo hagamos llegar a Juan. ······················ Se lo comunico a Clara mediante email (isabel.garcial@salud-juntaex.es). ································ Una vez recibida la cita por fax, se la remito escaneada a Toni-Futuex, para que se la hagan llegar a Juan. Teresa-Delegada, o le acompaña a la consulta o tendrá que cambiar la visita programada inicialmente para ese día. ·············· Respuesta de Toni: "...De lo Juan,, parece que ha funcionado, acaba de llamar a TEresa y parece que le ha convencido el verlo escrito en el móvil. Asique ha quedado en que el lunes va a lo de la ambulancia y el martes se encuentran alli en Cáceres." ··········· Se lo confirmo a Clara por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-10-16','Ana: Conversación con Pilar Martín, TS ESM; Ayer en la subcomisión, finalmente decidieron conceder plaza en el CRR-Ba a José Manuel por emergencia social. En cuanto haya plaza libre podrá ingresar. ······· Por otra parte, ha hablado con José Manuel, este no ha acudido a la consulta de enfermería a ponerse el inyectable, le ha dicho a Pilar que está mal con la ciática y no ha podido asistir, pero *que se la ha puesto él sólo en casa. *A ambas nos resulta cuanto menos extraño. ····················· Llamo a José Manuel (667 384 817): Está muy contento con la concesión de plaza en CRR. En cuanto al inyectable, dice habérselo puesto él solo. *El enfermero le ha llamado y le ha dicho que no vuelva a hacer eso, que es peligroso. Y le mandado unos análsis, tienen que enviarles la cita. El próximo inyectable le toca en 3 meses. *Ya ha recibido la cita para la Colonoscopia: 26/11/20 a las 9:30 h. Si estuviera en Ba para esa fecha, tendrían que llevarle desde allí a CC, pues pedir el cambio a Ba supondría tener que alargarlo más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-10-16','TERESA ENVIO RENUNICA SAD MUNCIPAL ZAFRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-10-16','Ana: Llamada y correo de Alberto Nava, Secc. Admva. de la Ud. Médica de la Dirección Provincial de CC - INSS (927 62 08 62 // alberto.nava@seg-social.es ) :"Buenos días: De acuerdo a nuestra conversación telefónica, se remite por correo electrónico la carta de citación de Catalina Silva Bautista, para pasar consulta médica en relación a su expediente de orfandad tramitado en esta Dirección Provincial. Un saludo." La cita es el día 27/10/20 a las 10:20 h). ················· Guardo citación en el expte. y se la remito a Toni-Futuex, para que la acompañen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-19','Ana: Dado que el viernes no coseguí hablar con Raquel, TS SSB, que Juan reclama su dinero de la ayuda de Diputación y que desde Futuex van a trabajar con él, en qué puede gastar el dinero y cómo justificarlo para no quedarse sin la ayuda, hablo con Alberto, jefe secc. ecca. y le pido que le den 100€ esta semana y otros tanto la próxima (pues debe justificar el gasto de los 200€ correspondientes a los meses de septiembre y octubre a finales de mes) y a partir del mes que viene los otros 100€ mensuales como estime distribuírselos. El úlitmo mes que lo percibirá será el de febrero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-10-19','Ana: Correo de Miguel Ángel, Director del CRR-CC: "Buenos días Ana, os remito el informe de Alta Hospitalaria en UHB de Consuelo Nevado Pacheco." ············ *Guardo el informe en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-10-16','-Amalia : se persona Ildefonso en las oficinas del SEPAD , exige que se le atiende e intenta tirar un ordenador al suelo . Tiene que ser reducido por el vigilante de seguridad. Se llama a la policia . Activo el 112 , tras hablar con el jefe de sala y explicar la situación , envían ambulancia y refuerzo policial y es trasladado al hospital de Mérida . Lo quedan en triaje, el médico lo ve por primera vez pero le dice que espere en la sala y él se va. Hablo con el médico de triaje y me comentan que no ha habido coordinación con el 112 y que no se le había avisado . Contacto via email con el ESM exponiendo la situación :','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-10-16','-Amalia : se persona Ildefonso en las oficinas del SEPAD , exige que se le atiende e intenta tirar un ordenador al suelo . Tiene que ser reducido por el vigilante de seguridad. Se llama a la policia . Activo el 112 , tras hablar con el jefe de sala y explicar la situación , envían ambulancia y refuerzo policial y es trasladado al hospital de Mérida . Lo quedan en triaje, el médico lo ve por primera vez pero le dice que espere en la sala y él se va. Hablo con el médico de triaje y me comentan que no ha habido coordinación con el 112 y que no se le había avisado . Contacto via email con el ESM exponiendo la situación : Buenos días , perfecto , queda aclarado , en el ESM no hay informes de Jonathan , estamos a la espera de recibir respuesta desde el Centro penitenciario. He activado esta mañana el protocolo 112 con Ildefonso García Rodríguez, es el tutelado del que hablamos el otro día y del que te envié email la semana pasada , tras la visita que hizo a las oficinas del SEPAD , con actitud agresiva y amenazante para solicitar que desde el ESM se activase el protocolo de ingreso involuntario. Hoy ha vuelto , el vigilante de seguridad lo ha tenido que reducir y ha llamado a la policía. He activado el 112 , he explicado toda la patología mental de Ildefonso , y una ambulancia lo ha trasladado al hospital . Al parecer , y según me informa el médico de triaje BOX1 , no ha habido coordinación con el 112, no les han informado de nada , y estando en la sala Ildefonso se ha ido de allí. El problema , como le he explicado a este médico , es que ya no puedo volver a activarlo, vive en la calle y no tiene domicilio fijo donde la ambulancia pueda ir . Estuvo viviendo en pisos de los que fue expulsado ,igual que del hostal donde estuvo viviendo unos meses ; pero no se adapta al cumplimiento de normas. Está el número 1 en lista de espera para entrar en el Centro de transeúntes. Seguimos teniendo a este señor sin atención psiquiátrica , sin adherencia a tratamiento ,( hace meses que no se pone el inyectable) y con consumos puntuales de cocaína. Si consideráis alguna otra opción para poder atenderlo no dudéis en contactar con nosotros . Un saludo Y respuesta del ESM : hola ya te comente que este paciente está de baja en civitas porque se fue de la comunidad autónoma, por parte de este ESM no creo que haya ningún problema en darle una cita con en el ESM, para que retome su seguimiento en este equipo, lo antes posible ,pero si vosotros como tutores no sabéis donde puede estar para poderlo localizar y para activar el 112, como vamos a localizarlo nosotros y darle esa cita, de todas formas esto lo comunicare el lunes a la coordinadora del ESM por si ella tuviera otra opción ,te doy su extensión por si deseas hablar con ella 85829. y sigo pensando que este no es el canal más adecuado para estos casos, porque hay ocasiones en que no se entra al correo por falta de tiempo o porque se tienen otras cosas que hacer más prioritarias y pueden no ser vistas cosas importantes como esta que afectan al equipo. saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2020-10-15','-Amalia : nos avisa la auxiliar de que han ingresado en UCI del H.I.C a Julio muy grave. Han avisado a las hermanas que vienen de camin . No he podido contactar con el hospital para preguntar , lineas ocupadas. No se puede quedar nadie con él por protocolo covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-10-19','Ana: Correo de Sonia Leo, Directora Res. Virgen de la Montaña: "Buenos días Ana, te comunico que el sábado 17, Pedro Román García García fue derivado quedando hospitalizado en el hospital Universitario de Cáceres por presentar desaturación y oliguria. Seguiremos pendiente de su evolución, un saludo. Sonia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-10-19','TERESA RECIBO PIA DE LA TECNICO PARA SER FIRMADO GRADO II 45 HORAS PVSAD 356.79€ PIDO PRESUPUESTO A LA EMPRESA ATENCION A LA DEPENDENCIA EXTREMEÑA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-10-19','miguel, llaman preguntado por mi del CSS Plasencia y me pasan con Jairo. El resumen de la conversación es que quiere el traslado al CSS DE Mérida( para lo cual le digo que neceistamos informe del médico aconsejandolo e informes de solicitud y aceptación por el CSS Mérida, es decir petición del CSS Plasencia y aceptación del de Mérida. Me pregunta también cómo reducir la condena (si encontrase un trabajo... el cual pretende que se lo busque la Junta para su integración. Le indico que es posible que a lo mejor el Juzgado valorase la reducción de la condena si encuentra un trabajo, que yo lo único que puedo hacer es comunicarselo a la junta. Todo ello con la finalidad de optar a una incapacitación parcial donde poco a poco y viniendo a vivir a Mérida le permitiese ir recuperando su incapacidad (aunque tuviese que ingresar durante lo que dure el resto de la pena en el CSS de Mérida). Indica que desde hace 5 años que está en el CSS Plasencia el trato es vejatorio, torturas, maltrato...Dice que desde que ha comunicado al Centro su intención de abandonar el centro que le tratan peor. ************************************ Comienzó la conversación dandome las gracias por dejarle un fondo mínimo de vida (se refiere a lo que le quedará tras aplicación de lo que mensualmente pagará al Juzgado y que previo estudio y decisión de la parte económica, comuniqué al Juzgado. ********************************************* En conclusión que le digo que si me manda un informe médico recomendando su traslado al CSS Mérida, unido a un informe social que me tendrían que entregar la parte social, yo lo comunicaría al Juzgado para que éste resuelva si acepta o no trasladarle al Css Mérida.','2');
