insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-10-20','Ana: Llamo a Ana Benavente, TS ESM-Plas. (74955 // 927 458 036) pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-19','Ana: Acudo a hablar con Eva y Mariluz, Secc. de Salud Mental de la Ud. de RR. AA., dicen que a Emi no se le van a dar más oportunidades, se le han dado muchas y las ha desprovechado. En el CRR-Plas., la úlitma vez que ha estado le han dado demasiadas y por último se marchó ella de forma voluntaria. *También ha pasado ya por el de Mérida, el de Cáceres y en otra ocasión por el de Plasencia. *Mariluz indica que se lo diga tal cuál a Emi, que ya ha agotado todas la posibildades. ············································································································································································································ A las 10:00 h, muy puntual, acude Emi a su cita en la CTAEX. Lleva la ropa bastante sucia (tanto el pantalón como la blusa, acude con sandalias (para lo cuál no están ya las temperaturas) y el abrigo con el forro, que nos muestra, descosido en un lateral. Nada más entrar y saludar comienza a pedir que se le compre un abrigo y que se le dé dinero para tabaco entre otras cosas. Se le pregunta por la botas, para las que se le dió el dinero y dice que no se las puede poner porque no tiene calcetines. *Entrega una bolsa con tiques varios, 2 de la zapatería (en lugar de comprar las botas de 40€ que pidió se ha comprado unas botines de 19 uy nos "zapatos de charol" de 10 €. El resto de tiques son de gastos de bolsillo... Cuando se le dice que vamos a hablar de lo más importante y se le transmite el mensaje de Mariluz, Secc. Salud Mental, y qué por tanto que piensa hacer, empieza a decir que le ayude, que tiene que ingresar en un centro. Al mantener el mismo mensaje de que no es posible, comienza a decir que se está mareando... se abre la ventana. Expresa "estás siendo muy dura, yo pensaba que ibas a ayudarme". Se intenta reconducir y buscar alternativas. *Dice que en Salvaleón hay una casa familiar de su abuela, que falleció, podría hablar con su tía y su madre. También tiene allí amigas de la infancia y una señora que conoce desde hace mucho tiempo que podría ayudarla. Pero que tendría que ir allí, pues no tiene teléfonos de contacto de prácticamente nadie... Insiste que se le dé dinero para el autobús, tendría que hacer trasbordo, de Mérida a Badajoz y de Badajoz a Salvaleón. *Acuerdos adoptados y consensuados con Alberto, Jefe Secc. Ecca.: Se le mantendrá el hostal una semana más, se le autorizaerá retirada de efectivo para que acuda al pueblo (aunque nos extraña que no pueda hacer esos contactos/consultas por teléfono), donde, si no consigue "alojamiento gratuíto" (casa familiar) buscará un alquiler, pues allí será mucho más barato que en Mérida, donde no podría asumir el gasto de vivir sola y dificilmente compartiendo piso (Percibe PNC). Por otra parte, acudirá a Cáritas a solicitar alimentos y ropa del ropero. También se le indica dónde está el Centro de Transeuntes Padre Cristobal, donde también tienen ropero. En esta semana debe "moverse" para buscar soluciones a su situación actual. *Nos facilita el nº nuevo de teléfono, ya se ha comprado la tarjeta: 722 432 418.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-10-19','miguel, a petición de Escalona remito informe para la contestación a la demanda de la Ctaex, cuyo contenido es igual a la anterior contestación de demanda también por excusa que pidieron los padres, e incluyendo unicamente la resolución desestimatoria que dictó el Juzgado (que también era el nº2 de Montijo). ************************************************ Todo ello basado en lo hablado con Amalia, repitiendo lo ya comentado en anteriores ocasiones al juzgado (ya que no se aportan nuevos informes sociales)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2020-10-20','Ana: Llamada de Maru, TS del C. Salud Manuel Encina, pregunta por la situación legal de Félix, pues según le consta nombraron Administrador de Bienes a la CTAEX. *En el expte. veo que está aceptado el cargo de Defensor Judicial a fecha de 1 de octubre. **Consutlo a Juan Pedro y Julio, admvos. area soc. CTAEX, y pido que si hay algo más pendiente con respecto a este Sr. me lo comuniquen. ···························································································································································· Con respecto a Félix, Maru me informa que es un señor viudo, de 85 años, sin hijos, procedente de Arroyo de la Luz. Presenta Deterioro Cognitivo, realiza seguimiento en el Serv. de Neurología. Le solicitaron valoración de dependencia, solicitando a través de la misma plaza en C. Residencial de Arroyo de la Luz. Hace ya tiempo comenzó una relación afectiva con una señora que le procuraba los cuidados que precisaba. *Pero la alerta le llegó del Médico de At. Primaria, quién le derivó. Fueron a hacer visita domiciliaria y constaron que no estaba bien atendido y él así lo expresaba, no se sentía bien cuidado y añadió que estar con esta persona le había supuseto mucho gasto... Aceptó el ingreso en la Residencia Privada El Conquistador de Trujillo (donde aceptaron el pago de su pensión, aún siendo inferior a lo que suelen cobrar). Allí comprobaron a su ingreso que estaba muy sucio. Cuenta con algunas propiedades. *Esta señora, con la que manteía relación, está en la cuenta bancaria con él. Y, una vez iniciado el procedimiento de incapacitación que promovió Maru de oficio ante la situación en la que se encontraba Félix, la Sra. manifestó querer revocar el procedimiento. Maru le dijo que buscara abogado y procurador, pero respondió que no tenía dinero. *Según Maru el interés por Félix parece sincero, le llama con frecuencia y muestra preocupación y le gustaría colaborar en la atención a Félix, por ejemplo comprándoles ropa o cosas que necesite. *Si finalmente nombrasen a la CTAEX Administradora de Bienes, se podría ver la forma en que pudiera seguir colaborando (si no se desmostrara otro interés) pero sin que ella "manejase" dinero alguno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-10-20','Ana: Correo de Toni-Futuex: "Nuestro gozo en un pozo.. no va a ir a la cita, despues que todo se quedará cerrado el viernes, en el centro de salud le dijeron que la cita era presencial (según parece) y Juan se quedó con está idea fija. Te contamos mejor en la nota.. el jueves por cierto se irá a Guadalupe, para trabajar con el tema del extra para que vaya recogiendo tickets, aunque el "problema" en todo caso lo tendra el ayto que entiendo yo que es quien tiene que justificar ese problema, pero al final desde ssb no sabemos si estan trabajando algo en este sentido o como habitualmente tampoco... Se adjunta nota de Juan Chamorro Holguin en relación a la cita de revisión de psiquiatria de mañana martes 20 de octubre 2020, que a pesar de aparecer de manera telefonic en dicha citación, se programa presencial. Cuando Juan, acude, como estaba previsto desde el viernes, a su centro de salud en guadalupe para recoger copia de la cita, manifiesta qeu pone telefónica y que así se lo dice tanto la administrativa como su médico, que es telefónica y que por tanto tenga activo su teléfono. Por tanto no acudirá presencialmente a Cáceres porque su psiquiatra no lo dice, aunque le insistimos que es un error y que ha sido modificada las observaciones de dicha cita, repite que no acude a Cáceres y espera que le llame." ······················· Comtacto con Pilar Martín, quién a su vez habla con el Psiquatra y al parecer éste se enfada mucho..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-10-20','En relación con el procedimiento de modificación de medidas, nos indica su Abogado que la demanda ha sido presentada hoy en el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-21','TERESA hemos acordado finalmente con la gestión económica de estos tutelados • CATERING: 426 € x los 2 hermanos: 213 € x hermano. Lo pagamos por transferencia • TABACO: 116 €/mes x los 2 hermanos . Pagamos a través de TRANSFERENCIA, pero siempre respetando los 58 € mes x hermano. Importante que el estanco no exceda esta cantidad. (¿Quién envía la factura el estanco o a través de vosotros?) • REINTEGROS: se establecen reintegros QUINCENALES de 33 €/quincena CON ACOMPAÑAMIENTO (pendiente me facilites nombre, apellido y dni de posibles acompañantes)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-21','TERESA hemos acordado finalmente con la gestión económica de estos tutelados • CATERING: 426 € x los 2 hermanos: 213 € x hermano. Lo pagamos por transferencia • TABACO: 116 €/mes x los 2 hermanos . Pagamos a través de TRANSFERENCIA, pero siempre respetando los 58 € mes x hermano. Importante que el estanco no exceda esta cantidad. (¿Quién envía la factura el estanco o a través de vosotros?) • REINTEGROS: se establecen reintegros QUINCENALES de 33 €/quincena CON ACOMPAÑAMIENTO (pendiente me facilites nombre, apellido y dni de posibles acompañantes)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GUILLEN'and apellido2='LOBATO'),'2020-10-21','TERESA SE PONE EN CNTACTO UN PRIMO DE JOSE PARA COMENTARNOS QUE JOSE ES HEREDERO DE UNA VIVIENDA EN VALENCIA DE ALCANTARA, DICHA CASA ERA DE SUS PADRES Y AHORA SE ESTAN PAGANDO LOS SUMINOSTROS POR UNA CUENTA EN LA CUAL ESTA DE COTITULAR UNA TIA. LE INDICO QUE SE QUITE DE ESA CUENTA Y LE PASO LA INFORAMCION A LA PARTE ECO Y JURIDICA PARA LA GESTION DE LA CASA, SUMISTROS, IBI Y HERENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-10-21','miguel,respondo a email de Rafael diciendole que no podemos firmar, tal como le dije en emails anteriores hasta que tengamos el certificado de nacimiento donde aparezca en inscripción marginal el cargo nuesro de tutores','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2020-10-21','TERESA ENVIO CI PARA TAC AL HOSPITAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-10-21','miguel, a petición de Teresa llamo al jzdo de Zafra preguntando los procedimientos penales que tengan pendientes, siendo úncamente el pendiente el nº561/20 del jzdo nº2 de Zafra, el cual me remite por fax oficio del 16-10-20 comunicandonos nuestra obligación de velar y procurarle la mejor inserción, a los efectos oportunos. ******************************************************* Entiendo que deberíamos de dar respuesta al juzgado con un informe social sobre nuestras actuaciones y así, le pido a Tere que prepare el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-21','Ana: Acude Emi sin cita, un tanto alterada, pidiendo dinero para varias cosas: comida, tabaco, podólogo, tarjeta de bus urbano... *Ayer en Salvaleón no consiguió sus objetivos, se muestra enfadada con su familia y con la CTAEX. Se le da cita para el viernes a las 10:30 h. Esta semana ya ha hecho 2 retiradas de efectivo. *Se valorará con Alberto cambio de la asignación semanal antes de lo previsto. ················· Avisa la vigilante de seguridad de que Emi regresa por 2ª vez exigiendo hablar conmigo y más alterada. Le indico que, como les he comunicado antes a una y a otra, no se le va a volver a atender sin cita, se le verá el viernes a la hora acordada. *La vigilante se lo comunica y le dice que se tiene que marchar, sino se verá obligada a llamar a la policía. ················· Nuevo aviso unos minutos después, Emi ha vuelto, esta vez con una cuerda atada al cuello y marcas de haberse apretado con ella (no son profundas). Llamo al 112, enviarán al soporte básico de Urgencias del Hospital de Mérida y pedirá valoración por Psiquatría. ·············· En pocos minutos llega la Ambulancia, los Técnicos del 112 entienden que al ser "intento autolítico" y además manifestar ella que no quiere ir al hptal. es internamiento involuntario. Se contacta de nuevo con el 112, enviarán una unidad de policía. *Dado que la policía tarda bastante en acudir, tratamos de convencer a Emi para que vaya pr su propio pie, será mejor que con la policía. Finalmente accede y se marcha con los técnicos. ································· Llamada de Emi desde el Hptal. de Mérida. Dice que la van a ingresar finalmente. Le ha atendido la Psiquiatra Isabel Álvarez Morales. *Dice que va a necesitar zapatillas de estar por casa, bragas, cepillo de dientes y pasta. **Lo hablaré con Alberto y con Futuex. **Una Ed. de Futuex compraran las cosas mañana mismo y se las llevará. Comunico a Belén, secc. ecca. que el pago se hará mediante transferencia a Futuex una vez nos remitan la factura. ································· Llamo a la Dra. Isabel Álvarez Morales, Psiquiatra (39374): Expresa que Emi presenta un problema de "Egocentrismo, sólo piensa y vive por y para ella", "Al estar tonta le saca beneficio", "Es una criatura que ha alimentado el sistema". "En el CRR dejando que se vaya se han quitado un problema". Opina que "Emilia no es autónoma, la veo para U.M.E.", pero añade que tal y como estás las cosas no la puede derivar allí (hace referencia a la situación de crisis sanitaria y las restricciones por el COVID). *Le va a dejar ingresada unos días. ············································· En cuanto a la reserva del hostal, hablamos Belén, Alberto y yo. *Belén negociará con el hostal la posibilidad de que le guarden la habitación (con todas sus pertenencias, que al parecer son muchas) mientras esté hospitalizada a un precio más bajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-10-22','Enviamos al Juzgado Decano de Primera Instancia de Badajoz, soilcitud de modificacion de la capacidad de Jonathan, a instancia de la Fiscalía de Mérida, la cuál cree que puede incapacitársele totalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-10-22','Enviamos al Juzgado de Primera Instancia e Instrucción, nº 2, de Zafra, solicitud de internamiento involuntario, así como últimas incidencias acaecidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2020-10-22','Enviamos al Alcalde de Valdecaballeros correo electrónico, comunicándole las actuaciones llevadas a cabo por nosotros en relación con la venta. Les pedimos que emitan Informe Técnico del Arquitecto Municipal, en el que se constate la situación de la vivienda, las posibles reparaciones, el coste de ellas, así como de su posible derrumbe. Igualmente les solicitamos emitan un informe de valoración del mercado que pudiera tener ese inmueble, teniendo en cuenta la situación en la que se encuentra actualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2020-10-22','Solicitamos a la Notaría de Cáceres que nos envien copias autorizadas del Acta de Notoriedad y de la Declaración de Herederos, correspondientes tras el fallecimiento del que fuera su marido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-10-22','Ana: Recibo llamada de Toni, TS y responsable del Centro de Discapacidad nuevo de Castuera - Asociación Adiser Horizontes (924 76 10 09 // 678 54 22 41) en relación al próximo ingreso de Aitor. Dado que es un centro de nueva creación y me indican que desconocen el funcionamiento de la CTAEX los procedimientos a seguir, le informo de todo al respecto. Le facilito información relativa al perfil de Aitor, la situación actual y la trayectoria desde que la CTAEX ha asumido la Tutela. El ingreso se producirá en los primeros días de noviembre. Dado que el traslado lo van a realizar desde el CAM de Trujillo y van a compañarle desde allí, acordamos que facilitaré su contacto a las Ed. del centro para que se pongan en contacto y organicen el mismo acordando la fecha que más convenga a ambas partes. ················································································································································································ Llamo a las Ed. del CAM Trujillo (927 027 600), pero me dicen que no se encuentran ni Esther ni Gema, por lo que les envío un mail informando de la llamada y conversación con Toni, C.Discapacidad, y pidiendo que se pongan en contacto con ella para que acuerden día y organicen el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-22','Ana: Correo de Belén, secc. ecca: "Buenas, han aceptado el presupuesto del hostal donde se aloja Emi, al 50% mientras esté hospitalizada y lo pagamos una vez le den el alta." ································································································································· Correo de María Rangel Macarro, TS de Salvaleón, a través del contacto "Salud Extremadura": "Buenos dias! soy la Trabajadora Social de Salvaleon. El pasado martes día 20, por la tarde se me comunico que se encontraba en Salvaleon y desorientada Emilia Morales Botello, donde ella comentaba que no tenía dinero porque lo administraba su tutor. Se pone la situación en conocimiento de la Guardía Civil y se activa el 112.. Es llevada a el Hospital Universitario de Badajoz. donde es dada de alta a las 3 de la madrugada. Desde ese momento no se sabe nada de ella. Ante la posibilidad de ser una persona incapacitada judicialmente. Se pone en vuestro conocimiento para valorar la situacion . Un saludo" *No indica datos de contacto (ni teléfono ni email).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2020-10-22','Ana: Rosana, Residencia Balcón de Extremadura - Montánchez, remite por correo-e autorización para vacuna de la gripe para Isabel. *Rosana dijo que no es necesario enviarles el orinal, con el documento escaneado será suficiente. ·························· Imprimo y pongo para firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2020-10-23','Ana: Remito escaneada a la residencia Balcón de Extremadura la autorización para la vacuna de la gripe de Clementa, debidamente firmada y sellada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-10-23','Ana: En relación al correo de ayer por la tarde de Toni-Adiser (Antonia Soriano Martín), *paso a Miguel, Asesor Jurídico, la autorización de derechos de imagen para que valore si se puede firmar o no, *pongo las autorizaciones a la firma del D.Gerente y en relación al modelo de entrevista familiar y ficha de medicación, así como de las cosas que debe llevar Aitor al ingreso, **remito correo a las Ed. del CAM Fco. Pizarro: "Buenos días de nuevo Esther y Gema, Deciros que he recibido correo de Adiser con una serie de documentación que tenemos que devolver de forma previa al ingreso, de la mayoría ya nos encargamos en la CTAEX, pero hay unos documentos que entiendo que tenéis que cumplimentar vosotras, pues sois quienes mejor le conocéis y disponéis de la información que piden. Por cierto, ¿podríais encargaros también de gestionar la PCR necesaria para el ingreso? Os remito adjuntos los 3 documentos a que me refiero. Ante cualquier cuestión no dudéis en contactar conmigo. Gracias y un saludo." ················································································································································ Respuesta de Esther, Ed. CAM: "Buenos días Ana Ya hemos hablado con Toni y hemos concretado para el 4 de noviembre. Si, tranquila, nosotros nos encargamos de la PCR y vamos rellenando la documentación Un saludo, Esther" ··················································································································································· Envío correo a Toni, Adiser: "Buenas tardes Toni, Decirte que la entrevista familiar y la ficha de medicación se la he pasado a las educadoras del CAM Francisco Pizarro, pues en el día a día, son ellas quienes mejor le conocen. En cuanto al resto de documentos ya he revisado, cumplimentado y puesto todos para la firma del Representante Legal, excepto el de derechos de imagen, que se lo he pasado a mi compañero Miguel, Asesor Jurídico, y me dice que te envíe éste que adjunto, que es el mismo que habéis enviado pero con las modificaciones oportunas que debéis de hacer. Por último, decirte que el “contrato” lo he puesto por duplicado, no me dijiste nada, pero entiendo que necesitaremos 2 copias originales, una para vosotros y otra para nosotros, así que cuando esté firmada también por vuestra parte, agradecería que nos hicieseis llegar una de las copias. En cuanto tenga todo firmado, te lo adelanto escaneado y posteriori por correo certificado. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-23','TERESA ANTE LA SITUACIN DE M ELENA DECIDIMOS SOLICITAR PLAZA RESIDENCFIAL EN MAYORES POR EMERGENCIA SOCIAL CON LA COALABORACION DE GUADALUPE TS DE FUENTE DE CANTOS ELABORAMOS TODA LA DOCUMENTACION Y SE TRAMITA, ESTA PENDIENTE DE ASIGNAR PLAZA PARA EL LUNES EL SABADO HARA PCR PIDO COPIA DE LA DENUNCIA QUE INTERPUSO EL GUARIDA IVAN YA QUE M ELENA NO DABA MUCHA CREDIBILIDAD A LO QUE DECIA SU HIJO INTNTO PONER DENUNCIA EN ZAFRA PERO EN EL CUARTEL LE DIJERO QUE TENIA QUE IR AL DE FUENTE DE CANTOS ESTAN CITADOS POR FISCALIA LA TS DE FUENTE DE CANTOS Y EL HIJO PARA DECLARAR LA CTAEX TAMBIEN TIENE QUE INTERPONER DENUNCIA PUES ASI NOS O PIDEN DESDE FISCALIA DE ZAFRA (PEDRO 924552452) QUEDO PENDIENTE RESOLUNCION PLAZA RESIDENCIAL Y HABLAR CON FISCALIA PARA FORMALIZAR DENUNCIA, LO CUAL SE LO COMUNICO A MIGUEL MANTENGO INFORMADO AL CRPS Y A FUTUEX DE LA SITUACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-10-23','Ana: Correo-e de Estrella Durán, TS del CSS-Plas.: "Buenos días, Ana. El miércoles tuvimos reunión el Psicólogo de UME Borja con Pilar T.S. y Sor Marifé del Piso Tutelado y donde tiene su plaza Margarita y ésta, con objeto de programar el alta. En dicha reunión tanto Pilar como Sor Marifé le dejaron claro a la paciente de que le iban a dar una nueva oportunidad y que debería volverse a ganar la confianza que tenían en ella, que tenía que comprender que su conducta es muy disruptiva en el Piso, asustando tanto a las Hermanas de edad avanzada como a sus compañeras.... Margarita pidió perdón, dijo que no volvería a suceder, y se veía contenta con volver al Piso. Quedamos en que se le daba el alta hoy viernes. Pues ayer a mediodía protagonizó otro "intento autolítico" lo entrecomillo porque fue una raja superficial en el brazo, no obstante el equipo considera que así no se le puede dar el alta, así que se pospone. No obstante consideramos que debiáis conocer este episodio como tutores suyos. Saludos. Buen finde, Ana." ······························································································································································································· Correo-e de Pilar Sánchez, Hogar San Vicente de Paúl: "Buenas tardes, Ana. Te comunico que no hemos podido ir a por Marga, porque no le han dado el alta, ya que ayer se cortó superficialmente las muñecas y se tragó unos botones. Nos ha llamado Borja, el psicólogo, para comunicárnoslo. Con respecto a la reunión, el miércoles nos viene bien. Nos da igual que sea en Zoom o en Meet, o en cualquier otra aplicación que a tí te venga bien. Un saludo y buen fin de semana"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2020-10-23','Ana: Adelanto escaeada autorización de vacuna de la gripe debidamente firamda y sellada a Maribel Álvarez, TS de la Resisencia. ··· Se la paso a Juan Pedro, secc. social, para que la remita por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-10-23','Ana: Adelanto escaeada autorización de vacuna de la gripe debidamente firamda y sellada a Maribel Álvarez, TS de la Resisencia. ··· Se la paso a Juan Pedro, secc. social, para que la remita por correo certificado. ··························································································································· Pong para la firma del D.Gerente, los C.I. que remiten hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-10-23','Amalia : comunicado del CRR sobre medidas COVID. Comentaros respecto a vuestros tutelados que se han implementado nuevas normas desde el SEPAD en el funcionamiento del recurso. Se restringen las salidas del recurso. Solamente se puede salir por motivos terapéuticos y siempre acompañados de profesional. Se mantendrán, también, aquellas salidas que sean necesarias tales como acudir a especialistas médicos, etc. En este sentido, hemos elaborado un cuadrante y saldremos diariamente 1 profesional con 5 usuarios en turno de mañana, y lo mismo en turno de tarde. De esta forma, conseguimos que cada una de las personas residentes pueda salir una hora a la semana acompañado de un profesional del centro. Por otro lado, se suspenden las visitas familiares tanto fuera como dentro del recurso. Como en el confinamiento anterior, habilitaremos y facilitaremos el contacto con los seres queridos vía telefónica, haciendo uso siempre que sea posible de las videollamadas. Las salidas a domicilio se cancelan también. Todo esto se les ha trasladado a los residentes esta misma mañana en una Asamblea extraordinaria donde el Director del recurso ha resuelto las dudas que han ido planteando. Actualmente nos encontramos avisando a los familiares de los usuarios de las nuevas normas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-10-23','Amalia : comunicado del CRR sobre medidas COVID. Comentaros respecto a vuestros tutelados que se han implementado nuevas normas desde el SEPAD en el funcionamiento del recurso. Se restringen las salidas del recurso. Solamente se puede salir por motivos terapéuticos y siempre acompañados de profesional. Se mantendrán, también, aquellas salidas que sean necesarias tales como acudir a especialistas médicos, etc. En este sentido, hemos elaborado un cuadrante y saldremos diariamente 1 profesional con 5 usuarios en turno de mañana, y lo mismo en turno de tarde. De esta forma, conseguimos que cada una de las personas residentes pueda salir una hora a la semana acompañado de un profesional del centro. Por otro lado, se suspenden las visitas familiares tanto fuera como dentro del recurso. Como en el confinamiento anterior, habilitaremos y facilitaremos el contacto con los seres queridos vía telefónica, haciendo uso siempre que sea posible de las videollamadas. Las salidas a domicilio se cancelan también. Todo esto se les ha trasladado a los residentes esta misma mañana en una Asamblea extraordinaria donde el Director del recurso ha resuelto las dudas que han ido planteando. Actualmente nos encontramos avisando a los familiares de los usuarios de las nuevas normas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-10-23','-Amalia: la previsión va a depender de cómo evolucione su deterioro cognitivo. De momento he solicitado nueva cita médica para actualizar la información, con la que tenemos en la que se basó el informe de dependencia de julio de 2018 esta Sra. dió SIN GRADO , con lo que no podría ingresar en residencia de mayores pública. Mientras la situación esté estable mantendremos la sra. en su casa con el apoyo de la ayuda a domicilio. Hasta que se vayan agotando sus ahorros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-10-23','-Amalia: la previsión va a depender de cómo evolucione su deterioro cognitivo. De momento he solicitado nueva cita médica para actualizar la información, con la que tenemos en la que se basó el informe de dependencia de julio de 2018 esta Sra. dió SIN GRADO , con lo que no podría ingresar en residencia de mayores pública. Mientras la situación esté estable mantendremos la sra. en su casa con el apoyo de la ayuda a domicilio. Hasta que se vayan agotando sus ahorros.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2020-10-23','-Amalia : pto. cuadrado : vamos a cuadrar presupuesto de ROSA GOMEZ CEDILLO. Os paso el detalle tras la visita coordinada con FUTUEX. He hablado por tf . con la auxiliar de Ayuda a domicilio que la cuida en casa. Antes era un primo de la tutelada , 873€ el que hacía el pago a la empresa por este servicio más 200€ que se lo entregan a la auxiliar para compras de comida, higiene y limpieza. Me dice que podemos seguir así . Si consideráis hacer un cambio , daríamos la orden al banco para que la auxiliar fuese a por el reintegro. Suministros de la casa , domiciliados. De momento , su situación sociosanitaria permitiría mantenerla un tiempo en casa con apoyos. Tiene un plazo fijo del que tendríamos que ir tirando para cubrir gastos . Un saludo Área económica: Sus cuentas bancarias pertenecen a la Banca Pueyo. Perceptora de una pensión de jubilación. Ingresos: Pensión: 683.50€ Gastos: Luz, agua, etc. Ayuda a domicilio: 873.60€/mes. Gastos varios: 200€/mes. Este dinero es gestionado por la auxiliar y es destinado para alimentación, productos de limpieza e higiene y gastos de bolsillo. Gastos extras: 1 vez al mes Peluquería – depilación facial (20€) y 1 vez cada dos meses podólogo (20€ aprox.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-10-26','TERESA El motivo del presente correo es para comunicarle que su paciente tutelado y que actualmente se encuentra en esta Hospital, JUAN CARLOS RUIZ GARCIA, fue derivado de urgencia al Hospital Virgen Macarena de Sevilla a última hora del día de ayer para valoración de un cuadro de estupor poscritico por un posible origen epiléptico. En el momento de disponer información médica de interés o alta médica se les comunicará. Atte. Dr. García Briones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-10-26','TERESA En el día de la fecha, presenta Denuncia por Delito de Lesiones en esta Unidad Dª. LAURA HERNANDEZ REY, como Cuidadora del Centro de Plena Inclusión de Zafra (Badajoz), que el pasado día 23 actual, cuando se encontraba en su Puesto de Trabajo en el mencionado Centro ha sido agredida por la usuaria de dicho Centro NATALIA MEGIAS MILLON. Que la agresión vino como consecuencia de que Natalia había protagonizado esa misma tarde un altercado con otro interno y que la denunciada continuaba en actitud alterada, de tal forma que se vieron en la necesidad de llamar a la Ambulancia de los Servicios Médicos del Centro de Salud de Zafra, si bien hasta que llegó la misma Natalía comenzó a tirar sillas a sus compañeros a la vez que les increpaba a todos mediante insultos y amenazas, llegando a propinar un golpe en la cabeza a la denunciante, a la vez que le daba un tirón del cabello que provocó la caida de ambas al suelo. La denunciante presenta Parte Médico de Lesiones. Natalia fue tratada por la Ambulancia que la traslado al Centro de Salud de Zafra, donde tras el oportuno tratamiento médico, fue de nuevo trasladada a su Centro de residencia. Diligencias instruidas por esta Unidad 2020-839-1486 que serán remitidas al Juzgado de Instrucción Nª 2 de Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-23','Ana: Conversación telefónica con la Dra. Isabel Álvarez - Psiquiatra - UHB, Consutla 3 (81621): Expresa "..en estos momentos no veo descompensada a Emilia, ahota mismo está muy tranquila", en unos días le dará el alta. Pregunta dónde irá. Le indico que al único sitio que puede ir es al hostal en que ha esado los últimos días, pero no podrá estar allí mucho tiempo pues no puede permitírselo económicamente. **Dice no entender que Emi no tenga una incapacidad total. Presenta "trastorno de personalidad entre otras cosas, es envidiosa, maníaca, compulsiva, manipuladora, un poco retrasadita y muy desadaptativa", "coge fobias y filias con quienes convive", "hay que oprimirla y restringirla". *"En una situación normal sin covid es paciente para UME, pero UME ahora está cerrada por protocolo" * Fianlmente dice que va a hacer el papel de derivación a la unidad, pero que no sabe cuándo podrá acceder a la misma. ······································································································································· Correo de Toni-Futuex a última hora: "Buenas tardes Ana el pasado 22 de Octubre se compró en el Carrefour de Mérida: - 6 pares de calcetines - 6 bragas - 1 par de zapatillas de estar por casa - 1 bolsa de aseo con un cepillo de dientes y dentrífico Por un total de 28,09€ Se pidió una factura por esta compra a nombre de Emilia Morales Botello, que se encuentra ingresada en estos momentos en la UHB del hospital de Mérida. Seguidamente se llevó la compra al hospital y se entregó al personal de la UHB. Se habló por teléfono con la psiquiatra Isabel Álvarez, que lleva el caso de Emilia y comentó que la tutelada es un caso complejo ya que al haber estado tanto tiempo institucionalizada no sabe o no puede vivir de manera autónoma. Por lo que se desestabiliza con mucha rapidez y recurrirá a la unidad por cualquier tipo de crisis que tenga que enfrentar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-26','Ana: envío a Belén, secc. ecca, por mail, la factura de la compra que hicieron en Carrefour para Emi y el nº de cuenta al que se debe hacer transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2020-10-26','TERESA INGRESOS: 604,50 €/MES DE 2 PRESTACIONES AHORRO: SE PRETENDE AHORRAR 1.300 €/AÑO APROX. OTROS GASTOS: • TELEFONO: 116 €/MES (COMO TIENE CONTRATO ESTO PUEDE VARIAR Y ROMPER EL EQUILIBRIO). • DECESO Y OTROS: 15 €/MES • REINTEGRO ACTUAL: 75 €/SEMANA + 200 €/MES: 525 €/MES. • ESTOS GASTOS SON SUPERIORES A LOS INGRESOS INCLUIDAS LAS PAGAS EXTRAS. A PARTIR DE AHORA EL REINTEGRO DEBERÁ ESTAR ENTRE LOS 375 € Y 400 €. CREO QUE, HASTA QUE VEAMOS SI PODEMOS CONFIAR EN LA CONTENCIÓN DEL GASTO DE TELÉFONO, EL REINTEGRO DEBERÍA SER DE 375 €/MES = 87 €/SEMANA. UN REINTEGRO DE 400 €/MES ES EQUIVALENTE A 92 €/SEMANA. SI GASTO TELÉFONO ES ESTABLE LE SUBIRIAMOS A ESTE IMPORTE, PERO TU DECIDES. CON ESTOS GASTOS NO ES POSIBLE HACER APORTACIONES A SU MADRE. HABRÍA QUE BAJAR AÚN MÁS EL REINTEGRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2019-02-19','En relación con el procedimiento de modificación de medidas, el Juzgado de Primera Instancia e Instrucción nº 3, de Cáceres, archiva el procedimiento, por falta de capacidad procesal de José Manuel. En este procedimiento estaba representado por el Abogado de Oficio designado. Éste recurrirá el Auto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2019-05-28','En relación con el procedimiento de modificación de medidas, la Audiencia Provincial Sección 1 de Cáceres, desestima el recurso presentado y confirma la resolución de instancia, por la que se resolvía la falta de capacidad procesal de José Manuel, para ser representado por el Abogado de Oficio designado. ----------------------------------------------------------- De acuerdo a lo anterior y que los hijos, uno es menor de edad, 17 años y el otro tiene 20 años, añadido a que la madre de José Ramón es quien realmente paga esos 200 euros de la pensión de alimentos, no seguimos adelante con el procedimiento, puesto que con su pensión, que asciende a casi 700 euros, puede hacer frente a sus gastos mensuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-26','TERESA M ELENA VA FINALMENTE A LA RESIDENCIA DE MAYORES DE ALMOHARIN TLEFO DIRECTOR 639189721. HABLO CON EL DIRECTOR JUNA ANTONIO PARA INFORMALE Y PASARLE DOCUMENTACION MIGUEL ESTA PENDIENTE DE FISCALIA POR SI TENEMOS QUE HACER ALGO EL MIERCOLES VAN A DECLARAR EL HIJO Y GUADALUPE LA TS QUEDO PENDITE PEDIR TRASLADO PARA QUE M ELENA PUEDA ESTAR EN LISTA DE ESPERA DE LA RESIENCIA DE ZAFRA Y PODER VOLVER CUANDO PUEDA ENVIO CONTRATO FIRMADO enfermera de la residencia de Almoharín 927386114.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-26','miguel, a petición de Teresa Ts, hablo con Fiscalía de Zafra (Pedro 924-552452) a quién informo de lo que sabemos consistente en la enfermedad que tiene consistente fundamentalmente en trastorno mental unido a inteligencia limite. Le comento nuestro conocimiento de las distintas denuncias en 2012,2015,2017,2020 sobre los mismos hechos, los cuales quedaron archivados anteriormente. Comentarle que no podemos acreditar nada, no hay informes médicos (ella siempre se ha negado a qeu se enteraran su padre Fco Duran Granado y su hermano José Mª Duran Duran. Le informo que se ha intentado con ella sacarla de allí, que de hecho se solicito ingreso en la Residencia de Discaacidad de su pueblo en Fuente de Cantos pero que no cumplia el perfil. También se han intentado varias veces su ingresos en pisos tutelados, de los cuales simpre acaba renunciando y volviendo a casa. Ella acude habitualmente al CRPS (Centro de Rehabilitación Piscosocial) y fundamentalmente va allí a hablar con la psicologa Mª Nieves, siendo informada mi compañera Teresa por la trabajadora social del centro MªCielo Esteban Reyes. Le confirmo también que en el día de hoy la tutelada quedará ingresada en la Residencia de Mayores de Almoharín 927-387210, cuyos datos también le doy a Pedro de la Fiscalía de Zafra. En principio no necesitan nada más de nosotros, quedo a su disposición para cualquier duda. ******************************************************* Me envía Tere un documento fechado 21-10-20 de la fiscalía requiriendonos que denunciemos, contesto a Tere: si te fijas está fechado del día 21-10-20 por lo que y tras hablar hoy con la fiscalía, remitiré oficio mañana indicando que ya nos hemos puesto en contacto con teléfono el 26-10-20 y nos reiteramos en la conversación así como en el contenido de las diligencias de la guardia civil que me enviaste..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-10-26','miguel, Amalia Ts nos remite email: Buenos días , os reenvío la sentencia que me han trasladado desde menores. Según la misma se amplia la curatela para aspectos económicos de extraordinaria cuantía y para aspectos personales relacionados con su tratamiento . Si no entiendo mal , especifica los actos en los que podemos intervenir sin necesidad de autorización judicial incluido decidir su permanencia en centro de salud mental . Su consumo de cannabis , que se refleja en la propia sentencia , hace inviable su ingreso en centro de discapacidad o salud mental . Se le ha pedido cita al Cedex , no sé si ha llegado a ir , pero lo confirmaré. El ingreso en comunidad terapeútica exige su voluntariedad , cómo vamos a decidir nosotros la permanencia ?? No somos guardadores de hecho , vive de manera autónoma con su madre en un piso de alquiler , desde esta Comisión no podemos garantizar la adherencia al tratamiento. He realizado numerosos contactos con la TS del ESM , intentando coordinar algún recurso para este chico , pero como ya sabéis , el CRR con consumo no puede entrar y también exige su voluntariedad para el ingreso. Creo que hay que trasladar todo esto al juzgado , el papel lo aguanta todo , pero hay que empezar a explicar las limitaciones con las que nos encontramos . Alejandro tiene pendiente además un par de fallos judiciales por otros delitos . Otra tema pendiente es poder comprarle un piso con el dinero que le dejó el padre. La familia insiste en la necesidad de hacerlo , el problema es que de todos los pisos de alquiler por los que van pasando amenazan con expulsarles porque él no cumple con las normas mínimas de convivencia. Ha roto ya varios telefonillos de la comunidad , ruidos... Antes de que se queden en la calle , él y su madre , veo conveniente solicitar la autorización judicial para la compra. No sé si esta sentencia nos permitiría hacerlo sin autorización, no he visto esta opción entre las que enumera. Quedo pendiente de vuestra respuesta. Un saludo *********************************************************** Contestación de Alberto: • Yo no soy muy partidario de la compra de un piso: o No sabemos si, una vez gastado tal cantidad de patrimonio, tal y como dices que conduce su vida, vamos a poder pagar: multas, gastos judiciales, gastos extraordinarios, centros.... o Estamos seguros de que va a ser tutelado quién se beneficie de tener una casa?, o más bien su madre?...carcel, falta de control de su vida (idas y venidas). o únicamente expongo esto a modo de reflexión. • Me parece más útil contar conn ese patrimonio para cuestiones que vayan ocurriendo y no tener que contemplar la posibilidad de malvender la vivienda en un momento determinado. ****************************************************** contestación de Amalia: Hola ,muy respetable pero no comparto tu opinión. Podríamos dejar algo de dinero para imprevistos que pudieran surgir , del tipo judicial si no tiene dinero para pagar no lo van a obligar , haría más tiempo en cárcel. La vivienda es un bien de primera necesidad que hay que garantizar en la medida de las posibilidades , ahora es el momento porque dispone de dinero . Si no lo utiliza, lo acabará usando para otro tipo de gastos , deudas por consumo ... y al final acabará en la calle , aún disponiendo de una pensión para cubrir el alquiler , el problema es que nadie va a querer alquilarle como ocurre con Ildefonso. Si os parece , podemos dar todos la opinión y llegar a una decisión . Por otra parte , y a pesar de que se le da la pensión integra , Alejandro necesita un extra para ropa y calzado , se justificará con la factura. Teniendo dinero ahorrado no podemos permitir que vaya en esas condiciones. De su pensión paga el alquiler de la casa , y algo de comida. El resto es para sus consumos , la familia tiene miedo a sus agresiones y le da un dinero semanal . Incluso les pide más y es el abuelo el que lo paga , quedándose en situación precaria. Pero ahí no podemos ni vamos a intervenir , ya se le ha explicado a su abuelo y esa decisión ya no es nuestra. Por ello , solicito un extra de 150€ para ropa y calzado. Seguimos ... ********************************************************* Contestación de Miguel: Buenos días, varias cuestiones: En cuestiones socio económica evidentemente decidid vosotros. Opino que no se malgaste tal cantidad de dinero y se puede comprar algo, lo más barato posible en zona de Badajoz como casco antiguo, ya que si bien nadie querrá alquilarle, también tiene que tener una inmediata liquidez económica para cualquier imprevisto, debiendo tener el control, como siempre, la parte económica… Mejor el dinero en el bolsillo que en cualquier otro lado. Por cierto veo que si bien no es necesario rendir cuentas, en la hoja excell indicáis intentos de conversación con Santander para meter el dinero en fondo de inversiones? No lo aconsejo, el dinero siempre mejor en la cuenta corriente (ya son muchos los ejemplos del dineral que han perdido los tutelados por culpa de lo que tardan los bancos en desbloquear y vender productos, aunque de palabra prometan lo que sea…El último ejemplo es Pedro Román Garcia Garcia…) Por lo que veo en la sentencia, sí necesita autorización judicial para comprar, como también necesita autorización judicial para ingresos involuntario (caso que algún día sea posible). Ya me decís, qué comunicamos al juzgado cuando lo tengamos claro tanto a nivel social como económico. Seguimos. ********************************************************** Nueva contestación de Alberto: Reitero con independencia de decisión final. • Invertir un dinero en una vivienda que, x su sistema de vida actual y el que es probable que mantenga a futuro, no sabemos si va a aprovechar el y no sabemos si podríamos recuperar sin sufrir péridas, es muy arriesgado. • Por otro lado, si nadie les quiere alquilar, es muy probable que haya razones importantes. El hecho de establecer una residencia fija de la que no se puedan mover porque ahí está su vivienda propia, y que a su vez se repitan los motivos graves de confrontación con los vecinos que impiden mantener un alquiler, podría suponer un problema grave a futuro. Nos meteríamos entonces en dobles alquileres? (alquilo mi vivienda porque mis vecinos no me quieren ahí y me voy de alquiler a otra?, ventas a la baja? • Repito, creo que no deberiamos proceder a compra y si tutelado, madre y abuelo insisten en ello...que sean ellos mismos los que vayan al juzgado y soliciten esa autorización. Si el juzgado nos obliga a comprar...pues compramos. Creo que deberiamos hablar sobre esto las 3 partes y tomar una decisión y seguir la línea que acordemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-10-26','Ana: pregunto por mail, a Ángel, Asesor Jurídico si ha hablado con el sobrino de Mateo y por la solicitud de modificación de la medida de pensión de alimentos. Me han preguntado desde la residencia de mayores. ························ Respuesta de Ángel: "... hablé con el sobrino, Nacho y quedamos en que nos enviaría toda la documentación de la que dispone, con respecto a su tío. Según me cuenta, su tío se casó en Cartagena y la pensión de alimentos para con sus hijos, cree que pudieran haberse determinado en la sentencia condenatoria con respecto a la que fuera su mujer. Dispone de mucha documentación, dice. Así que habrá que esperar a recibirla y ver qué tenemos para empezar a mover el expediente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-26','TERESA ENVIO FIRMADO POR EMAIL CONTRATO RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2020-10-26','Llama su sobrino, Alfonso Jiménez (667781197), para comunicarnos que los vecinos del piso de Ángel Manuel, se han quejado de ruidos producidos por alguna puerta o ventana que no para de golpear. Va a intentar facilitarnos el teléfono de la persona que le llamó para dar esta queja.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2020-10-26','En relación con el procedimiento de División de Herencia (19 y 20/2020) seguidos en el Juzgado de Primera Instancia e Instrucción, nº 1, de Logrosán, ha llegado la denegación de la asistencia jurídica graruita del Colegio de Abogados. Queda pendiente que la Comisión Provincial confirme o no esa denegación. Posteriormente nos darán traslado del alzamiento de esa suspensión, para que designemos abogado particular que represente a Tomás.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-10-26','Ana: Tras hablar con Paula, TO CRR-Plas., envío correo a Ángel y Miguel, Asesores Jurídicos: "Buenos días compis, En relación a Antonia Bernardo Piris, a primeros de enero envié un correo Miguel que, según me dijiste, reenviaste a Ángel, pues él había estado llevando el caso, para que llamaseis a Toñi. No sé si habéis llegado a hablar con ella. A posteriori recibimos por registro este documentos que os adjunto. Y hoy me ha llamado Paula, Terapeuta Ocupacional del CRR de Plasencia para preguntar por las dos cuestiones; 1. La reclamación de responsabilidades Patrimoniales (que no sabemos si os compete ni si podéis hacer algo al respecto), por lo menos plantea que se le responda a Toñi, pues es un tema que le genera bastante malestar. 2. El proceso de Recuperación de la capacidad legal, para lo cual, si no recuerdo mal, solicitasteis abogado de oficio. ¿Podríais poneros en contacto con Paula, T.O. y aclararle ambas cuestiones? Os paso teléfonos y dirección de email: 682 704 401 // 927 32 39 78 // tocupacional.crrplasencia@grupo5.net" ************************************************************ Contestación de Angel: Buenos días, compis, ¿Responsabilidad Patrimonial ante el Consejo de Ministros? ¿Intervención de la Abogacía General de la Junta de Extremadura ante el Tribunal Supremo? A ver, suena tal cual lo lees…, no obstante, responderé a Paula, para que me llame y me comente… Con respecto a la recuperación de la capacidad igual, recordad que es el caso del poder general que otorgó a un Abogado, que la representó. Impugnamos el poder general, nos la estimaron, parcialmente, pendiente que otorgara un poder especial para este procedimiento, que puede hacerlo. Esta información está anotada en la intranet. Os voy contando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-10-26','miguel, ante la pregunta de Juana de cómo va el procedimiento contesto: Juana, por lo que he podido ver en su sentencia de incapacitación él sólo tiene derecho a los gastos de bolsillo, y el resto bajo nuestra autorización. Visto los impedimentos del Juzgado nº4 de Badajoz, porque obligan a hacerlo vía Lexnet, en mi opinión, al ser una curatela, si él insiste que sea él el que lo solicite al Juzgado… En julio remití vía fax al Juzgado nº4 nos contestasen y al no hacerlo hacerlo, les llamé y no habían hecho nada y me requerían para lo solicitáramos por escrito. El 30/9/2020 lo solicité por correo certificado con un oficio y el 20/10/20 dictan diligencia de ordenación para decirnos que si no lo presentamos vía Lexnet que no nos aceptan el escrito… Nuestra posición es y debe de ser que no le autorizamos. Si no está de acuerdo que vaya él al juzgado. No vamos a poder obtener una contestación del juzgado (salvo que contratáramos un abogado y éste lo solicitase vía Lexnet) lo cual veo inviable. Mañana lo hablaré con Alberto, pero ya digo que mi opinión es que la Ctaex le diga que no y si no está de acuerdo que se pelee él con el Juzgado nº4 de Badajoz. ********************************************************* Hola, mira intranet. Remití por escrito al Juzgado Decano la solicitud, y el viernes llegó la desestimación del escrito porque quieren que lo hagamos vía Lexnet… Intentaré hablar con el Jzdo nº4 de Badajoz mañana para me aclaren si ese escrito se refiere al fax que remití en Julio o a esto que remití vía correo certificado al Juzgado Decano y que por turno se lo hayan enviado al Juzgado nº4… En caso que se requiera vía Lexnet contestaré al juzgado de la imposibilidad de utilizar esa vía y que ante los impedimentos que realiza el mismo nos vemos obligados a transigir a las pretensiones del tutelado con las consecuencias que pare él o/y terceros puedan ocasionarse. Paciencia, ya sabemos como son los del juzgado nº4 Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-10-26','Ana: Llamada de Pilar Martín, TS del ESM-CC: indica que se ha propuesto la derivación de Aarón a la U.H.D.A.C. (CSS-Plas.). Le indico que la CTAEX, de momento, sólo tiene aceptado el cargo de Defensa Judicial. *La sentencia de incapacitación absoluta es de fecha de 8/10/20, aún no es firme. Cuando la CTAEX reciba la firmeza se podrá proceder a aceptar el cargo. ······························································································································· Juan Pedro, admvo. secc. social, especifica por correo-e: "...la sentencia no será firme hasta el 09/11/2020. A partir de dicha fecha se solicitará la firmeza de la misma al juzgado y, una vez sea recibida, se procederá a iniciar los trámites de aceptación del cargo, en tanto en cuanto hemos de esperar a ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-10-22','Ana: Correo de María, TS ASPACE (maria.gonzalez@aspacecaceres.es): "Buenas tardes Adjunto remito Informe Social de seguimiento de Santiago Eduardo Mayoral Suárez. ¿Necesitan que les envíe el original por registro o correo postal? Muchas gracias" ····························· Se lo reenvío a Coral, secc. ecca. para la rendición anual. ················ Indico a María, tal y como me dice Coral, que no necista el original. ·························· *En el informe se indica que Santi está bien, con la medicación ajustada más tranquilo. Se encuentra también más adaptado al centro. Aunque no interacciona con compañeros ni profesionales, tolera la compañía y participa en todas las actividades, sobre todas las relacionadas con la música. NO existen contactos con la familia, pero sí con un voluntario del Cetnro Cotolengo en el que estuvo, quién se preocupa por su estado de salud y realiza visitas (las últimos contactos no presenciales debido a la situación de crisis sanitaria).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-10-26','Ana: Correo de Toni-Futuex: "...Te envio en un informe bastante exhaustivo, con capturas de pantalla y demas imagenes, sobre las quejas públicas en rrss que está haciendo el hermano de Catalina y otros asuntos, y que todo esto fue tratado junto con la ts de la localidad el pasado viernes, por parte de la compañera del equipo de apoyo social comunitario, Gloria, que es quien hace el seguimiento. A la cita del INSS de mañana, está organizado que vaya en bus a caceres y alli se encuentra con la compañera." ····················· Leo informe y lo guardo en el expte. telemático. ································ *Solicto a Albeto, secc. ecca., por mail que valore la subida de asignación semanal de Clementa a 60-70 € (desde que falleción el padre no se le ha subido y no puede afrontar todos los gastos con la anterior asignación)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-26','Ana: Nos remiten desde el CSS-Plas., mediante email, informe de alta de la URH de Miguel. Lo archivo en el expte. (físico y digital)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-10-26','Ana: Llamada de José Manuel (667 384 817), ayer le volvieron a hacer una PCR, pues llamó a urgencias por encontrarse con síntomas. El resultuado de la prueba ha sido negativo. ······ Por lo demás, en su línea, pregunta si se sabe algo del centro, pues quiere ingresar lo antes posible, pregunta por la asignación económica semanal (hoy ya ha retirado los 20 €, no podrá sacar más en una buena temporada, debido a las dos retiradas de efectivo sin autorización realizadas en los últimos meses). Dice también que está con ciática y malestar por catarro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-10-26','Ana: Envío correo a Alberto, Jefe secc.ecca., "...En relación a Clementa Amado Vivas, me informa la TS del Equipo de Salud Mental, que la cuenta en la que tiene domiciliada la pensión, es de LIBERBANK, oficina de la Avda/de España 27 (Cáceres). Para que en cuanto os sea posible, comuniquéis la incapacitación parcial de Clemetna, solicitéis la inclusión de José Vicente como titular y se proceda al bloqueo, pues hay riesgo de que la hija (quién tienen orden de alejamiento judicial de Clementa) pueda retirar efectivo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2020-10-27','Ana: Llamada de Noelia, TS del C.R. Cervantes (22237), como ya me adelantó la semana pasada, nos han remitido correo desde la Ortopedia Vitasalud, con el precio del cojín con abductor Viscolástico (117 €). *Se lo diré a Alberto, Jefe secc. ecca. ·················· *Noelia me remitirá el modelo de solicitud de material ortoprotésico, para pedir la subvención del cojín, para que lo ponga a la firma del D.Gerente y le dé registro de entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2020-10-27','Ana: Remito al CSS-Plas., por correo certificado, el C.I. para ciugía de Hernia, debidamente firmado y sellado por el representante legal. *Lo adelanto escaneado a Rosa, Administrativo del CSS (rosamaria.bravop@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-10-27','Ana: Correo de Alberto, secc. ecca.: "...Se autoriza reintegro permanente de 70 €/semana (304 €/mes) a partir del lunes 02/11/2020." ······ Se lo remito a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-27','Ana: Llamada de Dra. Isabel Álvarez, Psiquiatra UHB-Hptal. Mérida (81621). Hoy mismo dará el alta a Emi, ésta lo está demandando y ella la ve "bien, tranquila, no deprimida ni maniaca". Le pregunto por la derivación a UME que dijo que iba a hacer y dice que **No va a hacer la hoja de derivación, que le han llamado del CSS-Mérida dando orden de que no deriven a nadie. **Le pido que me envíe el informe de Alta y dice que como es una curatela económica no me lo puede enviar. ···· Opina que se debería crear una unidad especializada para todos estos casos. ·························································································································································································· Miguel, Asesor Jurídico y yo, redactamos comunicado al Juzgado correspondiente y lo remitimos por fax. ············· Comunico la situación mediante correo-e a Soraya, Jefa de Ud. de RR. AA. y a las compañeras de la secc. soc. (Amalia y Teresa).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2020-10-27','Se remite por REGISTRO DE ENTRADA Aceptación del PIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-10-28','TERESA HABLO CON MARIRA PARA QUE ME COMENTE COMO HA ENCONTRADO A ADOLFO EN LA VISITA QUE HA HECHO. ME COMENTA QUE ESTA BASTANTE BIEN DENTRO DE COMO EL SUELE ESTAR. LE COMENTO QUE TENGO EL INFORME DE DERVIACION PARA UHB/UME PERO QUE LA SITUACION AHORA MISMO ES DE COLAPSO POR EL TEMA DEL COVID. ACORDAMOS ESPERAR UNOS DIAS A VER COMO SE DESARROLLA LA SITUAICON SANIARIA PARA PROCEDER AL INGRESO','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-28','TERESA Buenos días, Elena llegó bien. Ya está instalada en su habitación. Le hemos proporcionado lectura para que esté distraída y estamos pendientes de ella. Ha pasado la noche tranquila y espero que esté a gusto con nosotros. Ayer estuve hablando con Susana y hemos quedado en hacer videollamada este jueves y la visita la hemos programado para la semana siguiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-10-28','TERESA SE CONVOCA SUBCOMISION DE CASOS PARA EL 6 DE NOVIEMBRE A TRAVS DE MEET','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-28','Ana: Llamada de Emi (722 432 418): dice encontrarse bien, ya ha ido al banco a retirar el dinero de esta semana y se ha comprado unos zapatos blanditos y cómodos por 5 €. De nuevo comienza a pedir dinero para diversas cosas de forma compulsiva, para un abrigo (dice que el suyo ha desaparecido en el hptal...), unas botas, pues la que se compró no vale, se mojan, las gafas que encargó en la óptica de Plasencia, un jersey... casi no deja hablar, cuesta hacer que escuche. Ya ha pedido cita en el banco para retirar el efectivo el viernes, a pesar de que la cita es mañana y aún no se le ha autorizado nada nuevo. Consiguo que conteste a algunas pregunta y le doy una serie de indicaciones: Ayer acudió al comedor social y le dieron una bolsita de alimentos para el día. Hoy va a volver. Pedirá que le anoten como usuaria habitual. En el comedor preguntó si daban ropa y le dijeron que ahora por el covid no están dando. *Acudirá a Cáritas de la Parroquia Santa María. *Acudirá también al centro de salud para que le asignen un médico de Att. Primaria y pedirá cita para que la deriven a Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2020-10-28','Acudimos al Juzgado de Mérida, para asistir a la videoconferencia, en la que le han tomado declaración, en el procedimiento DPA 237/2020, que se ha realizado en el Juzgado de Primera Instancia e Instrucción, nº 4, de Plasencia. Queda pendiente de Resolución, de la que nos darán traslado, telemáticamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='MARTINEZ'and apellido2='LARRINAGA'),'2020-10-28','TERESA ENVIO CONSENTIMIENTO INFORMADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-10-28','TERESA RECIBO CITA CADEZ PARA EL PROXIMO DIA 6 DE NOVIEMBRE A LAS 11:05, SE LO COMUNICO A FUTUEX PARA QUE LO GESTIONE Y A LA TS DEL SSB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-28','TERESA CITACION CADEX PARA PERFIL RESIDENCIA EL 5 DE NVOBRE LO COMUNICO A FUTUEX PARA QUE OGANICE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2020-10-28','TERESA ARCHIVO TESTIMONIO DE LA SENTENCIA POR LA CUAL SE LE PRIVA DEL DERECHO DE SUFRAGIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-10-28','Ana: Tras recibir llamada de José Manuel, nieto de Manuela, envío correo-e a Alberto y Belén, secc. ecca.: "Buenas tardes a los 2, He recibido llamada de José Manuel Correa, nieto de Manuela Morato Picado, dice que aún no se ha pagado el calentador de agua, que Belén le pidió que volviera a enviarlo y que ya lo envío el chico del almacén por segunda vez al ctutelar@ a la atención del “departamento económico” (no sé si esto es así…). Por otra parte, dice que han vuelto las lluvias y que aún no saben nada de la obra del tejado (cubierta) y el albañil, que llamó a Gloria-Futuex y que nos mandarían nota, pero no sé si os han remitido algo ni cómo está este tema.. ¿vosotros me podéis informar? Preguntaré también a Toni de Futuex, pues lo último que recuerdo es que se aceptó un presupuesto de un arquitecto, no? *Al parecer el aparejador municipal iba a informar ya a Fiscalía, pues ya hace muchos meses que él hizo el informe indicando esta necesidad… Vamos hablando. Un saludo." ·································· Envío correo a Toni- Futuex: "Buenas tardes Toni, En relación a Manuela Morato Picado, cuando puedas, ¿podrías decirme cómo está la situación de la obra pendiente del tejado? ¿Hay alguna novedad? Si no recuerdo mal se aprobó un presupuesto de Arquitecto necesario para acometer la obra, pero no sé si se ha avanzado algo más al respecto, dime si se ha establecido por vuestra parte algún contacto con dicho profesional y/o albañil. Sería conveniente dar continuidad a estas gestiones para que se acometa la obra lo antes posible. Acabo de enviar también correo al Alberto, Jefe de Secc. Económica. Seguimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-10-28','Ana: Llamada de José Manuel (667 384 817), contenido similiar al de conversaciones anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RODRIGUEZ'and apellido2='PARRILLA'),'2020-10-28','TERESA ENVIO AUTORIZACION MEDICACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-10-28','Ana: Llamada de Pilar Martín, TS del ESM-CC: insiste en que desde la CTAEX tenemos que agilizar la aceptación del cargo de tutor y así solicitar autorización judicial de internamiento en la U.H.D.A.C. (ya tienen aprobada la derivación a dicha unidad en espera de cama). Por otra parte, dice que el joven ahora está estable y que le han concedido plaza en Asindi. **Le indico que hasta que la sentencia no sea firme no se puede aceptar aunque queramos. *Le facilitará mi contacto a Isabel Cuesta - Menores. ················································································································································ Llamada de Isabel Cuesta Franco - T.S. Equipo de Menores - CC (927 00 43 56): se encargarán del traslado de Aarón a Asindi, ya están en contacto con Sonia Bernabé, le enviarán informe (me lo enviarán a mí también). El ingreso está previsto para el 3-4 de noviembre. En cuanto a Aarón, ahora mismo está estable y residiendo en casa de su padre, Julio. *Tienen aprobada y está percibiendo ya la PNC. *Irán preparando la documentación para cuando puedan enviarla. ······················································································································································ Correo-e de Isabel Cuesta (isabel.cuesta@salud-juntaex.es): "Buenas tardes, tal y como acabamos de hablar os remitimos los informes que derivamos a fiscalía para iniciar el procemiento de incapacitación de Aaron Rosado Alarcón. También os mandamos la sentencia de incapacitación aunque vosotros ya lo tendreis y la asignación de ingreso en ASINDI (ALCÁNTARA) Para cualquier consulta os podeis poner en contacto con Elena Mendez 927004360 ó con Isabel Cuesta 927004356" ········ Guardo la documentación en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-10-28','Reunión mantenida el 28/10/2020, entre Amália (Social), Míguel (Jurídica) y Alberto (ECO), en la que se tratan los siguientes puntos: • Compra VIVIENDA por tutelado, con el capital del que dispone en la actualidad: Se estima no proceder, de momento, a la compra de vivienda en propiedad, ya que tutelado está pendiente de distintas resoluciones judiciales que pueden afectarle tanto penal como económicamente. • DEPÓSITO: comprobar si la recuperación del importe del depósito es de inmediata recuperación o si es necesario contar con algún tipo de autorización exigida por el banco. • Las actuaciones que se consideran adecuadas en este momento son las siguientes: o Mantener la transferencia permanente realizada a la cuenta de la madre del tutelado por la totalidad de la pensión. 666,30 €/mes en la actualidad. o Indicar a tutelado y familia que, a partir de ahora, las pagas extras se utilizarán únicamente para cobertura de gastos extraordinarios, a demanda del tutelado y con el límite de 1 paga extra (666,30 €) por semestre. o Comunicar a tutelado y familia que, por parte de aquel se va a colaborar en mayor medida aún con la economía familiar, de forma que aportará un máximo de 450 €/mes (5.400 €/año) para colaborar con el pago del alquiler de la vivienda y los consumos asociados a la misma. o Preferentemente, el tutelado hará la aportación citada en el punto anterior, pero el contrato de arrendamiento o de los consumos asociados será formalizado por su madre o su abuelo. o Amalia tratará con tutelado y resto familia esta propuesta de actuación. Puntualmente se autoriza una trasnferencia de 150 € a la cuenta de madre del tuteladoc concepto "compra ropa".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-10-21','Conversación a tres: Ana y Miguel, CTAEX, con Pablo Correa (676 783 101), nieto de Manuela Morato: se le explica el funcionamiento de la CTAEX, se le recuerda que se trata de una Tutela Administrativa y que al Jdo. al que la CTAEX, rinde cuentas, se comunican todas las incidencias oportunas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-10-28','Ana: Reunión telemática con Sor Marifé y Pilar, Hogar San Vicente de Paúl. En "la casa" quieren mucho a Marga y quieren darle otra oportunidad, "es una chica generosa, trabajadora, dispuesta, con muchas capacidades y muchas posibilidades", "pero ha estado toda su vida institucionalizada y tiene repetir patrones aprendidos". "Al inicio, cuando llegó al hogar, encajó muy bien, era todo una novedad para ella y funcionaba fenomenal, participaba en todo y llegó a ser un pilar importante, pero una vez se instaura en la rutina comienzan las dificultades". Tras los numerosos incidentes que ha protagonizado en los últimos meses, además de los ingresos en UHB y el actual en UME, ya han perdido la confianza en ella, tienen que cerrar con llaves, despachos, cocina, cajones... Incluso ha realizado hurtos a profesionales. **Sus comportamienteo interfieren de forma negativa en la conviviencia y funcionamiento del centro y en el resto de residentes. Le van a dar otra oportunidad pero será la última. *Acordamos que iré gestionando la solicitud para otro recurso alternativo. *Les iré informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-10-29','miguel, remito por email, y el original por carta certificada, el poder apud acta (que hizo el Gerente ayer en el Juzgado de Mérida para la aprobación de herencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-29','miguel, adelanto por email a Jesús Bueno (el abogado)el poder apud acta para procedimiento de gastos extraordinario. Me indica que no le remita el original, por lo que lo dejo en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-10-29','miguel, adelanto por email a Jesús Bueno (el abogado)el poder apud acta para procedimiento de aprobación de herencia junto a la autorización de venta de todos los bienes de la herencia. Me indica que no le remita el original, por lo que lo dejo en el expediente. ********************************************************* Llamo a la hermana del Tutelado para comunicarle que hoy he remitido el poder apud acta al abogado para que interponga el procedimiento de aprobación de herencia con autorización de venta de los bienes de la herencia. A petición de ella le remito a la abogada con copia a ella de los datos del abogado que llevará el procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2020-10-29','Ana: Ante los correos remitidos por Eloy Piélago, TS de Madroñera, adjuntando modelo de solcitud de ingreso en residencia y documentación para adjuntar, le envío en respuesta el siguiente correo: "Buenos días Eloy, Como se te ha comentado en otras ocasiones desde distintas áreas de la Comisión Tutelar de Adultos, con respecto a Rafael Casares García, la Comisión Tutelar sólo tiene aceptado el cargo de Administrador de Bienes, como sabes, con dicho cargo la CTAEX no está en disposición de firmar ninguna solicitud de ingreso en residencia ni ninguna otra cuestión que ataña a la esfera personal, sólo a sus bienes. La CTAEX sólo tendrá que gestionar las cuestiones económicas. Una vez internado se puede contactar con la sección económica para para el abono de la plaza y cuantas otras cuestiones económicas necesite. Un saludo." ····················· *Con anterioridad a la aceptación del cargo se mantuvieron varias conversaciones telefónicas con Eloy en las que se le explicaban lo relativo al nombramiento de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-10-29','En relación con la solicitud de autorización judicial para la venta de los inmuebles de Andrea, hoy nos comunica el Abogado que ha presentado la demanda en el Juzgado Decano de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-10-29','-Amalia : -Nueva sentencia judicial de incapacidad que amplía la curatela a aspectos económicos y personales . -Solicito información a dependencia, con el objetivo de intentar solicitar centro residencial para Alejandro . Resolución denegatoria , da SIN GRADO , en fecha 2019. -Solicito información CADEX , para valorar solicitar plaza en centro residencial de discapacidad . Valorado en 2019 a petición de la DG de Infancia y Familias . Resolución DENEGATORIA , no da pérfil , sería RAL , por consumo de drogas. -Desde el ESM -Desde CEDEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-10-29','-Amalia : -Nueva sentencia judicial de incapacidad que amplía la curatela a aspectos económicos y personales . Elevar al juzgado la imposibilidad de garantizar su tratamiento médico y su acceso a una plaza residencial . Vive con su madre en un piso de alquiler , se realizan gestiones para la búsqueda de un recurso pero es inviable por su consumo de drgoas . Tendría que ingresar en una Comunidad terapeútica para su deshabituación , pero para ello y conforme a la ley 1/99 se exige su voluntariedad. No está siguiendo tratamiento en CEDEX . -Solicito información a dependencia, con el objetivo de intentar solicitar centro residencial para Alejandro . Resolución denegatoria , da SIN GRADO , en fecha 2019. -Solicito información CADEX , para valorar solicitar plaza en centro residencial de discapacidad . Valorado en 2019 a petición de la DG de Infancia y Familias . Resolución DENEGATORIA , no da pérfil , sería RAL , por consumo de drogas. -Desde el ESM se le han dado varias citas y se le está haciendo seguimiento. El consumo de drogas le excluye del resto de recursos residenciales ( CRR ) , además se exige voluntariedad. -Desde CEDEX , contacto con Paqui , la TS , acudió a la primera cita en septiembre , pero a la segunda con el médico ya no ha acudido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-29','miguel, envío email a Teresa en relación a la petición que la hace la trabajadora social del pueblo para que pongamos denuncia de abusos ante la fiscalía: Buenos días, he hablado con Pedro de la Fiscalía, porque hoy no está el fiscal del caso (Diego Delgado Garcia tlfno 924552452). Me comenta que el problema que tenían es que la guardia civil no les había mandado el atestado, así que se lo acabo de enviar vía email. Le he explicado lo mismo que te dije ayer, en el sentido que al no ser guardadores de hecho no podemos interponer denuncia, ya que no estamos presentes en el momento de dichos hechos. El atestado de la guardia civil que le he enviado, lo verá el fiscal y ya me dirán algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-10-29','miguel, Alberto nos remite email a Belen y a mí, para tramitar una vez que ayer por fin se desembolsó el Depósito del Santander del cual ha perdido más de 7.000€, para reclamarlos a atención al cliente del santander, llegado el caso después al Banco de España y por último a Juzgado. Quedo a la espera que desde la parte económica me den los emails intercambiados con el Santander junto con algún tipo de certificado de saldo a fecha inicial y a fecha de desembolso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-10-29','miguel, llega citación ante el jzdo nº2 de Zafra por Lev Juicio sobre Delitos leves 16/20, para el 20-11-20 a 13h. Remito fax al juzgado solicitando abogado de oficio y videoconferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-10-29','miguel, tras la petición de dias atras de su hermano Rafa sobre la necesidad de algún documento como el de presentación, le comento la imposibilidad de adelantarles nada porque nada hay, en el sentido que si bien se ha irmado en plasencia la enuncia del incapacitado no se ha podido firmar la ratificación de la renuncia de la herencia en la notaria de mérida al no haber llegado el certificado de nacimiento del tutelado, solicitado a principios de mes al registro civil de Jaén.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-10-28','-email del CRR de Mérida : informaros que Luisa Rodríguez sigue ingresada en UHB. Ayer llamamos para tratar de conocer cómo se encuentra pero no fue posible la comunicación con el profesional de referencia. Volveremos a intentarlo y, si tenemos novedades, os las comentamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2020-10-28','-email del CRR de Mérida : informaros que Luisa Rodríguez sigue ingresada en UHB. Ayer llamamos para tratar de conocer cómo se encuentra pero no fue posible la comunicación con el profesional de referencia. Volveremos a intentarlo y, si tenemos novedades, os las comentamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-10-29','-Email del CRR : Ángel Pinilla: No está de acuerdo con las medidas tomadas respecto al funcionamiento (salidas) del recurso por el COVID. Suele emitir quejas, y seguimos observando labilidad emocional. Cuando hablamos con él suele reconducir. Esperemos que poco a poco comprenda que se pretende velar por la seguridad y bienestar de todos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-10-29','-Amalia : he registrado ampliació en los centros de discapacidad , desde menores sólo habían elegido La Luz. Guardo copia en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-10-29','Ana: Solicito a Alberto, Jefe secc. ecca., hacer la prueba que había acordado con Juanjo, a partir de noviembre retirará su efectivo de forma quincenal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-10-30','Ana: Envío a imprimir y pido a Terera, TS CTAEX, que ponga para la firma el documento de que nos ha remitido Miguel Ángel ramírez, director del CRR y Piso Supervisado de CC (residenciadir@feafescaceres.com): "Autorización sobre protección de datos de caracter personal" para facilitar información a familiares. ··································· Y envío el siguiente correo-e a Miguel Ángel Ramírez: "Buenos días Miguel Ángel, De acuerdo, lo pondré para la firma. Eso sí, si no me equivoco la relación con la madre es buena, si corroboráis que esto es así, por favor, indicadme los datos de la misma para que podamos incluirlos en la Autorización antes de enviarlo. Un saludo y buen día." ································· Su respuesta: "Buenos días Ana, no te podemos corroborar que la relación con la madre sea buena, en estos momentos no se está llevando a cabo una comunicación con la misma, es por esto que no te podemos informar con respecto a dicha relación. Un cordial saludo." ···························· Mi respuesta: "En ese caso no podemos autorizar en el documento que nos habéis enviado, que se le facilite información a la familia, cuando esto cambie, decídnoslo y se autorizará, por lo pronto quedará en blanco… Un saludo." ········································································································································· Remito el siguiente email a Miguel Ángel, director del CRR y Piso Supervisado de Juan José: "Buenos días de nuevo Miguel Ángel, En relación a Juan José Bergantiño, comunicaros que, a partir de noviembre, las retiradas de efectivo podrá realizarlas de forma quincenal, en lugar de semanal, a ver qué tal funciona de esta manera, llevo mucho tiempo solicitándolo, si notáis en el recurso cualquier anormalidad o incidencia, por favor hacédnoslo saber. Un saludo." ···················································································································································· Respuesta de Miguel Ángel, director P.S.: "Buenos días de nuevo Ana, en relación a la retirada de efectivo semanal en lugar de quincenal te informamos que desde el recurso se está trabajando con él varios temas relacionados con la gestión económica, salidas fuera de PS sin autorización y compra e ingesta de alimentación. No creemos que sea favorable que pueda disponer de efectivo semanalmente ya que uno de los aspectos en los cuales está presentando más problemática es en el control de impulsos con respecto a las compras de alimentación de manera individual y el uso de indebido del dinero. Un cordial saludo." ······························· Escribo a Alberto, jefe secc. ecca. para que no se haga o anulen esa última autorización, continuará retirando de forma semanal hasta que nos lo indiquen desde el piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-10-30','TERESA ARCHIVI RESOLUCION DE PFHC, QUEDA PENDIENTE RESOLUCION DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-10-30','TERESA ARCHIVO RESOLUCION DE PLAZA RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FRAILE'and apellido2='EXPOSITO'),'2020-10-30','TERESA SE ENCUENTRA EN ESTADO GRAVE CRITICO POR COVID','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-30','miguel, remito vía email al jzdo nº4 de Mérida, nuevo informe completo de la curatela, a petición de la parte económica y social (Alberto y Ana)a raíz de que las continuas trabas por parte de la curatelada que impeden ejercer el cargo de curador ya que ha pedido se le haga entrega de la totalidad de su dinero, renunciando a comida y cama que hasta ahora se la tenía contratada. Mientras tanto no puede facilitarsele ningún recurso en cuanto a Centros donde pueda ingresar. Se lo he comunicado al Jzdo nº4 de Mérida a los efectos oportunos, tras la reunión ayer con Alberto, Ana y posteriormente con Ana y Soraya. ··········································································································································· Ana: Llamada de Emi, muy acelerada en el discurso, de nuevo apenas deja hablar, ni escucha. Dice que ayer le dieron comida en el comedor social (para la comida y la cena) y ropa en cáritas, pero dice que le queda pequeña y deber ir a cambiarla. Dice que tamibén le darán calzado, pero que se ha comprado ya unas botas, dos jersey... *De repente me pasa con una tal "Susana" que ha ido a verla, resulta ser la Delegada de Futuex, que ha conseguido contactar. Al parecer finalmente ha pasado la noche en el hostal. Dice que Emi no escucha, no razona y cambia de idea a cada rato, resulta muy dicífil la intervención con ella. Cuando pueda le enviará nota a Toni para que nos la haga llegar. ············································································································································ Envío correo a Alberto. Jefe Secc. Ecca: "Buenas de nuevo Alberto, Acabo de recibir llamada de Mónica, de Opticalia-Plasencia (927 04 37 84). Ya les he explicado la situación y les he dicho que no vuelvan a hacer ningún producto ni a Emi, ni a ninguna persona que haga mención a la Comisión Tutelar, sin la previa aprobación de presupuesto por parte de la sección económica. Que no obstante finalmente se van a pagar las gafas de Emi, no sé si habéis localizado el presupuesto/factura que enviaron y que os pondréis en contacto con ellos desde la sección económica para confirmar. Seguimos." ··························································································································································· Correo de Toni-Futuex, a última hora: "Te dejo por aqui, las anotaciones que ha hecho la compañera del primer seguimiento con Emi, porque creo puede resultar interesante de cara a la siguiente semana o las posibles gestiones con ella. Hoy 30 de Octubre se llama por teléfono a Emilia para quedar con ella en Mérida sobre las 10:00h de la mañana. Ella comenta que está en el banco para retirar su asignación y recomienda que nos veamos por el centro de la ciudad porque es el lugar por donde ella se mueve. Se va a una terraza y se la encuentra allí tomando un café, empieza a hablar muy aceleradamente y casi no deja que nos presentemos ni le preguntemos cómo está. Se la deja hablar durante un rato y luego se le pide algo de silencio y calma para poder responder a sus preguntas. Emi comienza diciendo que ha ido a la oficina de Liberbank esa misma mañana temprano y ha retirado 91€ para sus gastos, de ese dinero se ha gastado 10€ en terminar de pagar unas botas que tenía reservadas, 20€ en dos jerseys de punto, 4€ en revistas, 5€ en comida en el Carrefour Express, otros pocos euros en tabaco y otros tantos en tomar café. Relata que se está quedando en el hostal Senero pero cuenta que ella no puede gastar 800€ al mes en hospedaje porque se queda sin ahorros. Seguidamente cuenta que el día anterior estuvo comiendo en el comedor social de Mérida porque le dan comida y cena y le sale gratis. Por lo que se le pregunta por el catering que se le había buscado desde la comisión, a lo que ella responde que no se va a gastar 8€ al día cuando la comida le puede salir gratis. Se llama al hostal Senero y se habla con Noelia, una de las encargadas, ella confirma que Emi está hospedándose allí y que tiene reservada su habitación hasta el martes de la semana siguiente, como mínimo. Además se concertó con un bar cercano el desayuno, comida y cena por 8€ pero el dueño del bar ha tenido que cerrar por motivos personales hasta la semana que viene por lo que el hostal le ofrecía a Emi la entrega de los 8€ al día para que comprara comida en el Carrefour Express y se la calentara en el hostal. Se le comenta a la tutelada todo lo que se ha hablado con Noelia, y ella contesta por un lado, que va ir a comer al comedor social porque le sale gratis, y por otro, que va a coger los 8€ diarios porque sino se queda con hambre. Cambia de opinión muy rápidamente, casi al mismo tiempo que habla. Por último se recibe un mensaje de coordinación en el que se cuenta que el día anterior Emilia hizo un escrito en la comisión tutelar renegando del hostal y del dinero de la comida porque quería irse de Mérida y buscar suerte por otra parte. Por lo que pidió que se le administrara la pensión en pagas semanales de 91€ para que ella pudiera disponer de dinero. Cuando se le pregunta por esto a Emi, ella cuenta que ha estado hablando con una trabajadora social del Comedor social y le ha pedido que le busque un albergue en Badajoz, que le saldría más barato. Aunque por otro lado comenta que quizá se quede en el hostal hasta el martes 3 de Noviembre y luego se vaya a Cáceres para intentar ingresar en el CRR, que es lo que ella realmente quiere. Le explicamos que esto de CRR no funciona asi, pero como si nada... Se deduce del primer encuentro con Emilia que en estos momentos, es una persona muy inestable, verborreica y que no debería haber recibido el alta de la UHB porque no se encuentra bien. Está absolutamente obsesionada con el dinero y con poder comprarse las cosas que ella considera que necesita. No tiene capacidad de escucha y no permite que la persona que tiene al lado articule más de dos frases seguidas, por lo que se hace muy difícil intervenir con ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-10-30','Envío correo electrónico al área social (Amalia) y económica (Alberto) el siguiente: "Buenos días, Me ha llamado la abuela de Alejandro, se llama Primitiva (924235578), muy alterada, aterrada por la situación que están viviendo con Alejandro, desesperada, llorando, sollozando, con lamentos que le impedían casi hablar. Tras 23 minutos de reloj, insiste en que hagamos algo con urgencia, porque teme que pueda ocurrir una desgracia Intento explicarle que somos curadores, tras calmarla, me escucha, entiende y no lo que le digo, porque está desesperada. Le he indicado que debe poner en conocimiento de la Fiscalía y el Juzgado nº 4, de Badajoz, todas estas circunstancias. Por lo que al área jurídica se refiere, propongo que pongamos en conocimiento del Juzgado esta situación, con todas las actuaciones que hemos intentado llevar a cabo con Alejandro, la imposibilidad de materializarlas, así como las continuas quejas de los abuelos y solicitemos que se modifique la capacidad de Alejandro, para que se le incapacite totalmente, a los efectos de solicitar el internamiento involuntario, que viendo su consumo de cannabis, no sé si sería la solución. Amalia, si te parece, redacta en un documento todas estas actuaciones, como hiciste con Ati y las enviamos al Juzgado. La abuela va a llamarte, porque quiere que le des cita para ir a verte y exponerte presencialmente todos los problemas que les genera la convivencia con el nieto. Alberto, va a llamarte a ti también, para insistir en el tema de la compra del piso y/o alquiler. Saludos".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-10-30','Ana: Correo-e de Alfredo (resiplase@gmail.com): "Buenos días, Ana. Acabo de llamar al equipo del DNI de Cáceres, para ver como está la solicitud de desplazamiento del Equipo para realizar el DNI de Rosa María Laureano y me han comentado que debido al COVID el equipo no se está desplazando a ninguna Residencia a realizar los DNI. Si quereis consultar vosotros, el teléfono es: 927 626 544. Un Saludo. Alfredo Moreno.". Contesto y pongo en copia a Juana, secc. ecca. para que esté al corriente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-10-30','TERESA ME LLAMA OLGA 924 56 21 27, ME COMENTA QUE JOSE MARIA ESTA NEGANDOSE A QUE LE CAMBIEN LAS SABANAS Y QUE LE LAVE LA ROPA, NO LE DEJA A LA AUXILIAR COMPRALA COMIDA QUE NECESITA. HEMOS ESTABLECIDO CONVENIO CON COMERCIO PARA GASTOS DE COMIDA HE PEDIDO CITA EN SALUD MENTAL PARA QEU LO VEN PRESENCIAL HAY QUE RECORTAR EL REINTEGRO PUES SACA TODO VA A EMPEZAR A IR UNA NUEVA AXILIAR PUES LA QUE ESTABA LLENDO NO QUIER VOLVER POR LAS CONDICIONES EN LA QUE ESTA AHORA MISMO JOSE VAMOS A PROBAR COMO FUNCIONA SI CONTINUA CON ESTA PROBLEMATICA HABRA QUE PLANTEAR INGRESO INVOLUNTARIO EN RESIDENCIA DE MAYORE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-10-30','TERESA CIERRO CONTRATO DE SAD VAMOS A INICIAR EL SERVICIO ADELANTANO EL DINERO, EMPEZARA EN NOVIEMBRE DE LUNES A VIERNES, AVISO A FUTUEX PARA QUE PASEN A VISITARLA Y TAMBIEN SE LO COMUNICOA BEARTRIZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-10-30','Ana: Envío correo-e a Alberto, Jefe secc. ecca.: "Buenas Alberto, Como te comenté, Aitor Moreno Felipe, ingresará el día 4 en el nuevo centro de discapacidad de la asociación Adiser Horizontes de Castuera. En teoría tiene que ir provisto, inicialmente de 30 € para gastos de bolsillo, pero he hablado con el centro de menores (donde seguirá viviendo hasta el día 4 y me han dicho que ese dinero se lo van a dar ellos. Pero que el teléfono móvil de Aitor está estropeado y sería conveniente comprarle uno nuevo antes de irse. Por mi parte, si se puede, no hay inconveniente, les he dicho que envíen, desde el centro o la tienda, presupuesto previo al ctutelar@, para que estéis pendiente. Seguimos." ··································································································································· En cuanto a la documentación a aportar al centro de discapacidad, en conversación con Esther, Ed. CAM. (Tlf. personal 645 76 65 72) acordamos que ellos llevarán en mano el día del ingreso las fotocopias de CADEX, Dependencia, su DNI, Tarjeta Sanitaria... ·································································································································· Tal y como me solicita Esther en nueva llamada, le envío adjunta, escaneada, a resolucón de plaza RAL de Aitor. *La necesitarán para cerrar el expte. de menores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-10-30','miguel, remito la solicitud de incoación de procedimiento de jurisdicción voluntaria de retirada del carne de conducir a Secretaria General (Mª Guerrero) para intentar por tercera vez (primero fax, después por escrito al jzdo decano de Badajoz y ahora vía lexnet) que nos acepten dicha solicitud, para lo cual tendrán que remitir todo desde abogacia. ********************************************************* Contestación de Maria Guerrero: Buenas tardes. Coméntales si admiten el Inside, que ya lo tenemos configurado y a lo largo de la semana que viene o la siguiente lo tendréis vosotros. En todo caso, remítenos la documentación de rechazo del juzgado para que lo vea la Abogacía. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-10-30','miguel, remito a Amalia y Angel borrador de informe a presentar al Jzdo nº4 de Badajoz en relación a la situación del curatelado y las decisiones adoptadas desde la Comsión Tutelar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-10-30','Ana: corro-e Pablo Correa, nieto de Manueal: "Buenos días, como en la conversación que tuvimos por teléfono que seguiré informando sobre el cuidador de la abuela,lo que me comentan de que la chica que está por sustitución,por la otra trabajadora que está de vacaciones a la cual no entra a cuidar a la abuela ,por lo visto Jose Manuel Correa Morato , le da la lista de la compra y la manda a comprar,y a la abuela ni la ve. No se si la empresa que manda a esta trabajadora a los cuidados de la abuela tiene constancia de estos hechos. y sin mas un saludo." ··············· Le constesto agradeciendo la comunicación. ································································································· Envío correo a Toni futuex, para que hagan coincidir la próxima visita de seguimiento con el horario de la Aux. de SAD y nos lo corroboren. *Yo llamaré la semana que viene a la empresa de SAD. ······················ Respuesta de Toni-Futuex: "Hola! si haremos coincidir con la auxiliar, le he preguntado a la compañera si ella era conocedora de alguna incidenia y me comenta esto: Contacta José Manuel para comunicar que llevan sin auxiliar desde varios dias, según comenta, la auxiliar de referencia está de baja desde hace tiempo, en la empresa desconocen si ya le han dado el alta… Y la auxiliar que fue a sustituirla, al parecer, ha tenido que aislarse porque su hija dio positivo en COVID-19 y no volvió a acudir nadie. Se le dice si se han puesto en contacto por el asunto del positivo de la hija de la auxiliar, José Manuel establece que no y que tiene miedo por ello, se le dice que normalmente los rastreadores, si hay posibilidad de riesgo, son las personas que se ponen en contacto para comunicar las pautas que se deben seguir, pero si no lo han hecho, quizá sea porque no es necesario. José Manuel establece que duda que se haya comunicado el contacto con Manuela, pues cree que la auxiliar no estaba dada de alta por la empresa de Servicios del Fresno y por ello no diría nada… no se sabe si es cierto, se le dice que en ese caso observe de cera a la abuela y cualquier síntoma llame al médico, establece que mañana tienen que acudir a verla porque tuvo una infección de orina muy fuerte, se le dice que se lo comente. También solicita que se exija la atención por parte de la auxiliar y saber qué ocurre con las que acudieron, se le dice que eso debe comunicarlo la empresa y, para las sustituciones, normalmente, no se tarda más de una semana, pues igual tiene que buscar auxiliar disponible. . esto hace un par de semanas o asi, según me comenta la compañaera, y no nos ha vuelto a decir nada al respecto hasta esta nueva información que tu nos das" ····································································································································· Con respecto al Arquitecto, nuevo correo de Toni "30/10/2020 Solicitud autorización firma para arquitecto: Contacta el arquitecto de que se ha contratado para la realización del proyecto de obra de Manuela, considera que al ser una persona tutelada, aunque los datos del proyecto los rellene con el nombre de Manuela para la formalización del documento precisa que sea firmado bien por los tutores de Manuela adjuntando autorización expedida por la CTAEX, en este caso, para la misma. Se le dice que se consultará cómo se puede proceder y se comunicará, mientras va adelantando en la realización del mismo. Le hemos dicho que o bien se ponga en contacto directamente y pueda enviar por fax o email el documento para firma o nos lo facilite a nosotras para hacerlo llegar.. Si cualquier otra consideracion al respecto me dices porfa". ··············· *Confirmo que sí, que nos hagan llegar el documento y se lo devolveremos firmado por el representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-10-30','Ana: correo de Borja Vázquez, Psicólogo Clínico del CSS-Plas.: "Buenos días Ana, soy Borja Vázquez Antolínez, psicólogo clínico del Centro Sociosanitario de Plasencia, donde se encuentra actualmente ingresada Isabel María Cano Blázquez, recientemenete incapacitada y tutelada por la Comisión Tutelar del Adulto. El motivo del email es porque la propia paciente me solicita ponerse en contacto con algún/a responsable de dicha comisión para obtener información sobre su nueva situación y conocer qué puede hacer, qué no, y resolver dudas. Entonces, si pudiese hacerse una llamada de teléfono (en mi despacho y conmigo delante) en el que ella pudiese contactar con vosotros sería lo ideal. Quedo a vuestra disposición para que me indiquéis la forma de proceder. Un saludo". ································· Mi respuesta: "...Me parece bien tu propuesta, para lo que cuál fijaríamos días y hora de la semana que viene y yo hablaría con vosotros 2, podríamos poner manos libres si lo consideráis oportuno. Ya me dices cuándo os viene bien e intentamos cuadrar..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2020-10-30','Ana: Correo de Sonia Leo, Directora de la Res. Virgen de la Montaña: "Buenos días, solicito autorización para que Isidora Leal Román, paciente ingresa en nuestro Centro y tutelada por ustedes, pueda recibir el servicio de peluquería y podología, los cuales no se incluyen dentro dentro de su tarifa de estancia, así como la compra de un peto perineal, ya que el suyo se ha deteriorado. En espera de su respuesta, reciba un cordial saludo. Sonia." ·················· Se lo remito a Alberto, Jefe secc. ecca. Por mi parte Ok. *Indico a Sonia que en próximas ocasiones, las cuestiones económicas, las remita al ctutelar@ a la A/A: Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-10-29','Ana: Atención presencial a Emi. Decide abandonar hostal y rechazar también el menú diario (desayuno, comida y cena). Lo pone por escrito. Sólo queire dinero en efectivo. Se acuerda, desde las secc. ecca. y social con ella, que se le dividirá su pensión semanalmente y se autorizará para que pueda retirarlo de esta manera. **Miguel enviará nuevo escrito al Jdo. ·································· Se mantiene también reunión con Soraya Masa, Jefa de Ud. RR.AA., no hay más alternativas, lo único que podrá hacerse es derivarla a UME en caso de que vuelva a ingresar en UHB. *No entiende que la psiquiatra Isabel Álvarez, no haya hecho la derivación, pues dice que no se ha dado tal orden de no dervación desde el CSS...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-10-30','Ana: Respuesta de Toni-Futuex, a mi correo intersándome por Desideria: "...Pues Desideria de alta, en principio mas tranquilos ambos.. a ver lo que dura. La proxima semana van con ellos a la retirada de asignacion y commpra, a ver que tal los encontramos, te trasladare la info."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-10-29','Ana: Correo de Toni-Futuex, adjunta el informe de seguimiento de Miguel, realizado el día 27 en el domicilio familiar. Lo guardo en su expte. En el mismo expone que el hijo se encuentra presente en todo momento durante la visita. *Se les percibe inquietos con respecto a la cuestión económica. *No parece tener demasiado claro su situación económica con respecto a deudas y demás cuestiones. *Cree que se le ha asignado una cantidad insuficiente. ··········· **Explico a Toni y pido que se lo expliquen bien a él, que la cantidad que ha retirado, es la parte proporcional a los días que restan del mes. *La 1ª semana de enero podrá retirar la asignación mensual completa. Se le ha aprobado el presupuesto que él elaboró junto a Mariví, T.S. del CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-10-29','Ana: Correo de Toni-Futuex: "Te adjunto el informe de Clementa Amado Vivas, y el primer segumiento en el domicilio, asi como la información que se ha ido recabando hablando con diferentes personas en el caso. La señora presenta una resistencia total, aunqeu parece que todo apuntaria a un internamiento en centro.. En el informe va todo, mucho mejor detallado ······················ *Guardo el informe en el expte. ················ En el informe indican que Clemena no colabora lo más mínimo en ningún momento de la visita, no quiere ni mirar a la educadora. En cuanto al Centro de Salud, no se encuentran ni la MAP ni la T.S.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-11-03','miguel, reenvío email de ejecutoria del tutelado a Ana y Alberto: Buenos días, ha llegado el auto de ejecución de Jairo. Como podéis ver ponen 730 días (2 años ) orden de alejamiento a 200 metros de y en cuanto al pago de la multa e indemnización entiendo que han aceptado la propuesta que hicisteis la parte económica consistente de los 10.570€ a pagar de la siguiente forma: 2.700€+27 cuotas mensuales (26 de 300€ y 1 de 70€). Ana, cuando hables con el centro comunícaselo, aunque a lo mejor ya lo saben. ************************************************ Datos que me indica el jzdo de lo penal nº1 Plasencia: Nº c/c: ES 55-0049-3569920005001274 Beneficiario: Jzdo de lo Penal nº1 Plasencia Concepto: 1145000078045120 ·································································································································· Ana: Lo comunico a Emilia Almodóvar, TS del CSS-Plas.','2');
