insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-03','Ana: Envío correo-e a Toni-Futuex en relación a alugnas cuestiones indicadas en el informe de seguimiento de la semana pasada: "...He pasado a Alberto las cuestiones económicas. Y en cuanto esta cuestión que indicáis en el informe de seguimiento: “… Posibilidad de darse de alta en su centro de salud, por lo cual debe empadronarse de nuevo en Guadalupe (hasta la fecha está en Cáceres) y así se le pueda asignar MAP, para llevar su control según se sugiere en su informe de alta y desde aquí, reactivar las consultas de revisiones en área de salud mental. A Miguel le corresponde por zona Trujillo (Dr. Medina), pero él desea y solicita se le pueda derivar a ser controlado ambulatoriamente por zona de salud mental en Cáceres, por mala experiencia anterior. De ahí que, dude en solicitar médico en Guadalupe, si esto le impide seguir en salud mental de Cáceres.” Si no os importa, decirle que acuda él mismo a empadronarse, pues quién le tiene que autorizar para empadronarse en el domicilio familiar es su padre. En algunos casos, no en todos los aytos. le piden la firma del representante legal en uno de los formularios, si se lo piden, que nos lo haga llegar. Y al centro de salud, puede ir a que le asignen ya el médico, no necesita estar empadronado, sólo tienen que indicar el domicilio. Y cuando tenga asignado MAP, que le pida el seguimiento de Salud Mental en Cáceres (como Juan Chamorro)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-03','miguel, contesto al abogado, veo bien la demanda de autorización de gastos extraordinarios y le pido la interponga hoy mismo. *********************************************************** Contestación a email de Ana: En la parte que me toca comentaros: -Tema vehículos: estamos a la espera que resuelva el juzgado si le quita el carne o no. Lo último que sé es que le iba a ver el Forense. En cuanto esté la resolución (si fuera estimatoria, en cuanto a retirarle el carne) si os parece los daríamos de baja y pondríamos a la venta o desguace según el estado que se encuentren. -Tema viviendas: la de la c/General Margallo el abogado interpondrá hoy demanda en el juzgado para que nos acepten los gastos extraordinarios para la reparación para la que el ayuntamiento nos dio 4 meses. -Tema internamiento de nuevo: Habría que reiniciar todo en cuanto se desestabilice y por tanto en cuanto te llegue nuevo informe psiquiátrico que recomiende internamiento + informe social, prepararía de nuevo demanda de internamiento involuntario. Si hay algo más que deba hacer me vais diciendo. Seguimos. ********************************************************* Buenos días Alberto y Miguel, En relación a Miguel Santos Cordero, comentaros que Futuex fue a visitarle la semana pasada. Os copio extracto del mismo en relación a las demandas que hace a la CTAEX: “…Exponemos las siguientes peticiones y solicitudes que, en diferentes áreas ha realizado para valoración y AUTORIZACIÓN: • Reforma de vivienda de Guadalupe: (recibos devueltos de luz, seguros, ect.) • Situación de las otras dos viviendas en Cáceres: (una embargada, que según Miguel informa, se ha pagado seguro de hogar) y la otra con ocupación ilegal y en condiciones no óptimas de habitabilidad. • Gestión de los dos vehículos que posee: Entregar uno al desguace y la furgoneta que es la que se quiere quedar, llevarla al taller, mediante grúa y presupuestar la puesta a punto, para utilizar el vehículo por la población y su entorno más cercano. (se adjunta copia del carnet de conducir en vigor y comenta que el seguro ha sido pagado) • Solicita le sea proporcionada información sobre las diferentes deudas y embargos que mantiene en sus dos cuentas bancarias. …” Alberto, ya miráis vosotros las cuestiones económicas. Miguel, he mirado la sentencia, y en la misma no he visto nada con respecto a la prohibición de conducir, no sé qué opinas o si quieres que hagamos algo… Por otra parte, una vez más, aunque en la sentencia, autorizan al Internamiento Involuntario, le han dado el alta, por haber cumplido medida judicial de internamiento y no considerar que existan criterios clínicos para mantenerle ingresado…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-11-03','miguel, nueva contestación a María Guerrero: Buenos días Maria, el documento nº5 es el documento de rechazo que te comentaba en el email anterior. Te remití también la documentación a enviar al juzgado y que te reenvío de nuevo. Comentarte que el Juzgado por ahora no acepta otra vía que Lexnet con lo que cuando esté en marcha el nuevo programa inside a ver si logramos vayan aceptándonos esa vía de presentación de documentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-11-03','Ana: llamada de Esther, Ed. CAM-Trujillo (645 766 572 - nº personal). Le han llamada del C. Discapac. Adiser Horizontes, comunicando que el ingreso de Aitor ha de posponerse una semana como mínimo, pues han dado positivo en Covid algunos trabajadores del centro y en estos momentos está todo el equipo en aislamiento domiciliario ··· En cuanto al tlef. que hay que comprar a Aitor, enviaron 2 presupuestos, pero dicen que aún no han tenido respuesta de la secc. ecca. *Ellos optan por el más económico (140 €). *Se lo comunico a Alberto, jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-10-30','Ana: A petición de Miguel, Asesor Jurídico-CTAEX, solicito a Rosa, Admvo. CSS-Plas. que nos remita Informe de Ingreso en Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-11-03','Ana: Reenvío a Miguel, Asesor Jurídico-CTAEX: Informe de ingreso ininterrumpido en CSS remitido por Rosa,Admvo. CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='NOGALES'and apellido2='MATADOR'),'2020-11-03','TERESA VISITA FUTUEX • Teléfonos de contacto: 615 077 685 (Piedad TS – SSB) Desarrollo: Desde los SSB de Torremejía nos informan que Manuel Nogales Matador acude cada día al Ayuntamiento a solicitar dinero. Destacan que el tutelado se encuentra muy nervioso pues dice que no tiene ni dinero ni comida y en el banco no se lo dan. Se les informa que se comenzará a retirar dinero de forma quincenal y siempre con acompañamiento. Dadas las circunstancias sería conveniente valorar la posibilidad de comenzar con dicha gestión la próxima semana aprovechando que es principio de mes. Por otro lado, debido al descontrol observado en cuanto a la medicación y cumplimiento de la misma, sumado a los problemas conductuales de Manuel, desde el equipo de apoyo social comunitario contactamos con su médico de atención primaria el Dr. José Luis Sánchez Álvarez para tener conocimiento y recabar información en cuanto al área sanitaria. Nos informa que desde el 2014 que tuvo el ictus, no constan informes médicos de Manuel. A pesar de ser un enfermo crónico por tener problemas de corazón y diabetes no cumple con el seguimiento en el centro de salud. Además, no les consta que acuda y cumpla con las citas médicas y tiene una próxima cita en salud mental el 12 de Noviembre 2020 a las 9:00h en el C.S. Mérida Norte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-11-03','Ana: Llamada de Juan José (667 958 878), explico que por indicación del responsable del P.S. de momento se mantendrá la autotización de retirada de efectivo semanal, pues los profesionales del recurso no ven apropiado en este momento que lo retire de forma quincenal. Cuando me digan que es buen momento haremos la prueba. Se queda conforme. ··· Por otra parte, dice que, a modo de entrenamiento, ha estado mirando/buscando vivienda, para estar preparado para cuando llegue el momento, pues en el CRR le dijeron que sería bueno que entrenara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-11-03','TERESA ME LLAMA EL TS DE ALMOHARIN PARA PEDIRME INFORAMCION DE ELENA LE COMENTO EL TEMA DE SOLICITAR TRASLADO PARA QUE ESTE MAS CERCA DE SU HIJO LE INDICO LOS CENTROS PARA SOLICITARLO SE VA A ENCARGAR EL TSOCIAL1@MANCOMUNIDADSIERRADEMONTANCHEZ.ES TELF 654222195','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-03','TERESA En la mañana del día 28 de octubre recibimos llamada de Alfonso (jefe de la Policía Local de Zalamea de la Serena) para informarnos de que Pablo lleva unos días consumiendo alcohol, con el agravante de ponerse agresivo con vecinos de la localidad llegando a agredir a la dueña de un establecimiento que no le dispensaba bebidas alcohólicas. No tenemos ni idea de donde puede sacar el dinero para beber (él dice que le da la gente) pero dudo que le den tanto dinero como para que pueda ingerir grandes cantidades de alcohol. El dinero creemosque lo obtiene pidiendo por la calle, indicando a la gente que no tiene para comer. Aprovecho para comentar que ninguno de los dos hermanos tiene tratamiento en Cedex, Guillermo creo que lo tuvo en algun momento pero hace tiempo que no esta en seguimiento, tampoco hay un reconocimiento claro del problema por lo tanto el tratamiento de desintonxicación voluntario es complicado. Hoy día 29 de octubre de 2020 volvemos a recibir otra llamada de la Policía Local (María) para informarnos que ha llegado una denuncia a nombre de Pablo, la misma se la pusieron el pasado 20 de febrero por insultar e increpar a unos agentes de la Guardia Civil. La cuantía de la denuncia es de 300 euros.No se si estará en plazo de alegaciones o se podrá hacer algo a nivel júridico, es un poco surrelista una denuncia de 300 por proferir insultos, sobretodo proviniendo de una persona con graves limitaciones intelectuales. ARCHIVO DENUNCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-03','Ana: Llamada de José Luis, hermano de José Manuel, éste le pide que por favor le llame yo, que está sin saldo. ··· En cuanto al catering, José Luis dice que a su hermano no le llevan pan, preguntaré a Futuex. ······· Llamo a José Manuel (667 384 817): pide dinero. Le recuerdo, que a mí no debe pedirme dinero, a la secce. ecca. *En cuanto al ingreso en centro, como en las conversacione anteirores, reitero que tiene que tener paciencia y esperara a que queda la plaza libre. ·································································································································· Envío un correo a Toni-Futuex en relación al cáterin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-11-03','TERESA Paloma Rodriguez y su cita de hoy del rehabilitador, acaba de hablar con ella la compañera y le dice que no ha ido a la cita porque ella quería que la llevara una prima suya y se ha enterado hoy que está en Asturias. Pero vamos, que ayer fue Mariola, la trabajadora social del centro de salud a casa de Paloma a llevarle el volante de la ambulancia para ir hoy a Badajoz y le dijo que lo anulara porque se iba a ir en coche. Ufff, esta mujer es un desastre!!Le hemos dicho que ha perdido la cita porque le ha dado la gana y que luego no se queje de que le duelen las rodillas. A la cita del cadex del proximo viernes, de modo excepcional y dada la importancia de la cita y las veces que la ha perdido, la llevaremos nosotras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-11-03','Ana: Llamada de Sonia Bernabé - Asindi (669 602 920): ya le dijeron que el Pacto de Asistencia a centro lo tienen que firmar Aaron mientras no se haya aceptado el cargo de tutor por la CTAEX, hasta el día 10 no es firme la sentencia. Considera que el joven es muy joven para firmarlo, quiere consultarlo con Ángel, Asesor Jurídico, le indico que le llame si lo considera, pero que entiendo le dirá lo mismo que yo, que hasta que no sea firme no se puede aceptar el cargo y que sin el cargo aceptado no se puede firmar ningún documento en su nombre. *La única opcion que se me ocurre, es que a día de hoy lo firme Aaron y una vez aceptado el cargo que nos lo envíen para que lo firme a posteriori el Representante Legal. ·············································································································································· Correo de Ángel-Asesor Jurídico CTAEX: "Me ha llamado Sonia Bernabé, de Asindi, para tratar el caso de este chico. Me ha comentado que ha estado hablando contigo de este expediente. Te cuento. Nos nombraron tutores, pero aún no hemos aceptado el cargo, al no ser firme la Sentencia. El 9/11, cumple el plazo del recurso, posteriormente solicitaremos testimonio de la firmeza, con lo que hasta que no recibamos ésta, no aceptaremos el cargo. Normalmente estos testimonios de firmeza suelen tardar, con lo que se alargará nuestra aceptación. Sonia necesita que alguien firme el ingreso de este chico en el centro, menores ya no se hace cargo, nosotros tampoco podemos. Va a plantearle al gerente de los pisos tutelados, que sean ellos quienes firmen el ingreso en Asindi, como guardadores de hecho que son en la actualidad. Al margen, he hablado con Maite para preguntarle por la plaza de Asindi. Me comenta que no corre peligro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-11-03','Ana: correo de Borja Vázquez, Psicólogo Clínico del CSS-Plas.: Buenos días Ana. Qué te parecería que te llamase este mismo jueves 5 de noviembre a las 10 de la mañana? Serán un par de preguntas nada más. Un saludo" ················ Confirmo ese día y hora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-03','Ana: Llamo a la oficina de la Empresa de SAD Servicios del Fresno de Valencia de Alcántara (927 58 20 86), me dicen que la responsable no está, dejan nota para que me devuelva la llamada. ······················· Amelia, Servicios del Fresno (924 677 705), me devuelve la llamada, indica que Quini, la Aux. de SAD habitual, ha estado de baja (no por covid), la auxiliar sustituta tuvo que ponerse en aislamiento por contacto estrecho con un positivo en covid. La nueva sustituta, Mª Dolores Romero, sí que ha estado acudiendo, pero en el domicilio no entraba, José Manuel por miedo a un posible contagio de la abuela, no ha dejado entrar a ninguna que no sea la habitual, por lo que les encargaba las compras de supermercado, farmacia y similar. Desde el día 21, Quini, que ha sido dada de alta, ha vuelto a realizar el servicio, ella sí entra en el domicilio, no obstante, sólo se encarga de las tareas del hogar, pues a Manuela, la asea José Manuel, no quiere que nadie más le atienda para minimizar riesgos de contagio. *Durante las vacaciones de Quini, cuando José Manuel volvió a llevarse a Manuela a Toledo, la Aux. que acudió, cuando ellos no estaban, era Mª Carmen. **En relación a las supuestas cámaras de video que ha colocado en la casa José Manuel, según informa su hermano Pablo, Amelia no sabe nada. Le preguntará a Quini.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-11-03','TERESA CON ESTA TUTELA LE VAMOS A RESTRINGIR LA ASIGNACION MENSUAL A 300€, ACTUALMENTE SACA 600€. ULTIMAMENTE NO SE ENCUENTRA MUY ESTABLE, HE PEDIDO CITA A SALUD MENTAL PARA QUE LO VEAN PRESENCIALMENTE, ESTOY A LA ESPERA QUE ME LA DEN. LA RESCTRICCION SE LA VAMOS A PONER PARA EL MES DE DICIEMBRE PARA QUE ESTE MES LE DE TIEMPO A SUSANA DE TRABAJAR CON EL ESTE TEMA, NO NECESITA ACOMPAÑAMIETNO LOS PUEDE SACAR EL SOLO PUES NO HACE MALA GESTION DEL DINERO, AL REVES ES BASTANTE TACAÑO Y SEGURO QUE TIENE GUARDADO EL DINERO EN SU CASA. HEMOS NEGOCIADO CON UNA TIENDA PARA QUE LA AXUIAR PUEDA COMPRAR LO QUE NECESITE SIN QUE SE ENTERE JOSE MARIA PORQUE ESTA EN ESE PLAN AHORA DE NO GATAR DINERO Y APENAS LE COMPRA LO QUE LA AUXILIAR NECESITA PARA HACER DE COMER. ESTE TEMA LO TIENE GESTIONADO YA OLGA LA TS CON LA TIENDA. QUEDO PENDIENTE DE AVISARTE CON LA CITA PAR QUE LA ACOMPAÑE LA DELEGADA, Y GESTIONAMOS EL TAXI PARA EL DESPLAZAMIETO. LE DAMOS DE BAJA A LA TELEASISTENCIA CON CRUZ ROJA PUES TIENE TAMBIEN CON MAPRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-03','Ana: Tras los intentos en días previos de contacta con José Miguel Manzano, Responsable de Pisos de Menores Área de Badajoz, (924 01 00 57) hoy consigo hablar con él. Mañana me llamará para hablar con más calma sobre el caso. *Tal y como me indica, le envío un mail solicitando la documentación (josemiguel.manzano@salud-juntaex.es); "Buenas tardes José Miguel, Tal y cómo hemos acordado mediante conversación telefónica, en relación a COSTI ALEXANDRU RIZEA, tutelado recientemente por la Comisión Tutelar de Adultos, solicito nos envíes, cuanto te sea posible, informes y documentación relativa al mismo, de cara a la conformación del inventario y al adecuado ejercicio del cargo de tutor. Gracias y un saludo." ························· **El joven por lo pronto puede permanecer en el Dulce Nombre de María, Málaga, hasta el día 21 de diciembre, fecha en que desde Menores dejarán de abonar la plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-04','Ana: Respondo al nuevo correo de ayer de Pablo, nieto de Manuela (pablocorreamorato46@gmail.com): "Buenos días Pablo, Precisamente ayer estuve hablando con Amelia, de la empresa de Ayuda a Domicilio y me dijo que Quini, la Aux. habitual está incorporada desde el día 21, que está yendo a la casa y que ella sí entra. A las sustitutas no les ha dejado entrar por miedo a posible contagio de Covid, y les enviaba, como tú bien dices a hacer compras/recados (también tareas de las Auxiliares), pero Quini sí entra. Si tienes alguna prueba de que esto no sea así, háznoslo saber. Gracias por tu interés e implicación. Un saludo y buen día." *Guardados en el expte. digital. ············································································································································ Escribo a Toni, para que averigüen qué auxiliar está yendo a prestar el servicio, pues la información de Pablo difiere de la Amelia, Empresa SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2020-11-03','Ana: Correo de Miguel Ángel Ramírez, director del CRR-CC (residenciadir@feafescaceres.com): "Buenos días Ana, se han puesto en contacto con nosotros los técnicos de Ley de Dependencia para informarnos que vendrán a hacer valoración de Agustín Castaño Tornavacas el día 9 de noviembre a las 10:00 de la mañana en el CRR. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-10-29','Ana: Correo de Toni-Futuex: "Te adjunto informe sobre la situación actualizada del tema de la obra, como sabes es muy complicado trabajar con Jose Manuel, ya que si no presta su consentimiento para que se revise la casa el arquitecto no puede hacerlo, también estuvo el tema que se marchó en septiembre a Toledo, y estuvo una buena temporada, y ultimamente no permite a la compañera entrar en la casa (según el por miedo a contagio a su abuela por el covid). Sabes como es su proceder... aveces en el conflicto, en la amenza de denuncia, se encuentra mas cómodo que colaborando por un bien común... en el informe te detallamos todo. Hemos concertado con el arquitecto de los dos presupuestos que se aprobó (Jose Manuel queria el otro presupuesto, y era mucho mas caro..) y este esta de acuerdo finalmente también, y se va a pasar por la casa para valorar e indicar el tema de las obras que serian necesarias. Te voy informando, de lo que nos trasladen." Guardo informe adjunto en el expte. digital. ········· *El arquitecto acudirá a la vivienda el sábado 31 a las 11 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-03','Ana: llamada de Emi (722 432 418), está bastante animada, pues retiró el viernes 91 € y hoy otros tantos, se ha comprado ropa y unas botas, entre otras cosas. Le han dado comida en el comedor social a diario y hasta esta misma noche ha estado pernoctado en el hostal. *Le recuerdo que no puede seguir con dicha asignación semanal y pernoctando en el hostal, si no me equivoco hoy finaliza las noches reservadas y pagadas previamente. Pide cita presencial, como esta semana no puede ser, le doy cita para el día 12 a las 10 h. ···················· Envío correo-e a Belén y Alberto, Secc. Ecca.: "Buenos días, Comunicaros que a pesar de su negativa del jueves pasado, Emi ha seguido pernoctando en el hostal hasta esta misma noche. Además, al parecer el bar donde habían contrato el menú, ha tenido que cerrar por asuntos personales y lo que han hecho ha sido darle los 8€ diarios a ella en mano, quién a su vez se lo ha gastado en lo que le haya dado la gana, pues ha estado yendo a recoger la comida al comedor social. *Tal y como pidió ella, y puso por escrito, no se va a renovar más tiempo la estancia en el hostal y mucho menos el menú del bar. Pues ya está retirando los 91€ semanales como pidió. Por favor aclararlo en el hostal, pues creo que se plantean renovarlo y/o guardarles sus cosas (en este caso no considero que haya que pagar para que lo guarde, si lo hacen es decisión propia) Le he dado cita presencial para el jueves día 12. Vamos viendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-11-04','Ana: Llamo a Ana Benavente, TS ESM-Plas. (74955 // 927 458 036): Ayer vió la psiquiatra a Eugenia, acudió acompañanada de Gloria-Futuex. En el informe hace constar *La Alcaldesa del pueblo ha llamado preocuada por las conductas y actos de Mª Eugenia en el pueblo. La Psiquiatra realiza ajuste farmacológico y le indica que si no mejora sus conductas se valorará ingreso en Psiquiatría. Próxima cita presencial el 26 de noviembre. ···· En cuanto a la plaza en residencia de mayores, seguimos a la espera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-11-03','TERESA ARCHIVO INFORME SOCIAL DONDE SE PROPONE POR PARTE DE LA TS HACER OBRA EN LA VIVIENDA PARA DEJAR EL PISO DE ALQUILER PUESTO QUE NO LE ESTA DANDO USO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2020-11-04','Reunión 04/11/2020: Miguel, Juana, Alberto. La tutelada tiene una cuenta en IBERCACA, con número ES37 2085 4619 9503 3037 0821 (antiguamente: 20866119550000206647 - CAJA3), en la que figura como titular junto con su madre: DOMINGUEZ IZQUIERDO, CARMEN (titular y TUTELADA) DOMINGUEZ IZQUIERDO, MANUELA (titular y MADRE) SERRANO GARCIA, MARIA CONSOLACION (Reperesentante Legal CTAEX) Saldo a 04/11/2020: 3.909,49 € Ultima pensión cobrada por tutelada en esta CCC: 19/04/2020: 395,60 € Ultimo acceso (a través de reintegro) de la tutelada a esta CCC x bloqueo del banco de la CCC x estar madre fallecida: 01/07/2020: 392 € A partir de esa fecha, los únicos movimientos de esta cuenta son las comisiones cobradas x el banco (4,2 €) y un embargo del que desconozco el origen x un importe de 12,22 €. Fallecimiento madre: 26/06/2007. Padre: ENRIQUE ESCALERA ROSADO, fallecido el 21/04/200. ASUNTO: hay un procedimiento de división de la HERENCIA (Procedimiento Ordinario 440/219, Jdo. 1ª Instancia, nº 5 Badajoz) de los padres. Este procedimiento afecta a esta CCC ya que en el reparto de la herencia se le atribuye a la tutelada un 5,5 % del total de la herencia, retrotraida al momento del fallecimiento de la madre (26/06/2007). En el caso concreto de esta CCC el saldo en ese momento era de 1.489,60 €, de los cuales a tutelada le correspondieron 198,91 €, conforme a Testimonio del Decreto 35/15 de 26 de enero de 2015 del Procedimiento División Herencia 698/2012, Jdo. Instancia nº 5 Badajoz). Cuestión a tratar: con independencia de la anterior y conforme al histórico de movimientos bancarios de esta CCC, queda claro que en esta CCC únicamente se han contabilizado como INGRESOS, el cobro de la PENSIÓN de la tutelada. Lo que pretendemos es DESBLOQUERA esta cuenta, de forma que todo lo que supere la liquidación de la Herencia (1.489,60), pase a titularidad única y exclusiva de nuestra tutelada. Para ello Miguel va a obtener la RESOLUCIÓN JUDICIAL del procedimiento actual de División de Herencia (Procedimiento Ordinario 440/2019 del Jdo. 1ª Instancia nº 5 de Badajoz), que será remitida a IBERCAJA (x Juana). Juana: en su momento hay que valorar si hay que actualizar el REPRESENTANTE LEGAL y en todo caso, en el momento en que sea posible, transferire el importe que nos corresponda a la otra CCC de la que la tutelada es titular.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-04','miguel, ya presentado por el abogado Jesús Bueno la demanda para gastos extraordinarios','2');
