insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-03','TERESA ARCHIVO INFORME SOCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-04','miguel, actualizo borrador a enviar al juzgado sobre si incluir si o no la decisión de no comprar y sobre la posible autorización de internamiento involuntario (quizás no sea necesario por recogerlo ya la sentencia) ******************************************************* Angel, Volviendo al contenido del escrito que vamos a enviar al Juzgado, en mi opinión no deberíamos incluir mención alguna referente a la compra o alquiler del piso, debido a que es una cuestión que nos compete y que hemos decidido adoptar, por el bien de Alejandro. Llegado el caso, si la familia planteara la cuestión en el propio Juzgado y éste nos pidiera explicaciones, se las daríamos. Pienso que debemos hacer más incapié en el resto del escrito, manifestando la problemática que nos produce el ejercicio de la curatela de este chico, como hicimos con Ati, a los efectos de poner en conocimiento del Juzgado esta situación y, a consecuencia de lo anterior, solicitar que se modifique su capacidad, para pasar de curatela a tutela, como hemos hecho con Jonathan ***************************************************** Amalia, Buenos días , en lo que refiere a la compra o alquiler de piso yo no voy a valorarlo , lo que decida Alberto me parece bien . Veo conveniente , explicar las dificultades y limitaciones con las que contamos en el ejercicio de esta curatela extensa, sobre todo en la dificultad de garantizar el tratamiento médico y el ingreso en centro. Sobre todo , teniendo en cuenta las últimas agresiones que según verbaliza la familia han tenido lugar la semana pasada. No creo que sea oportuno volver a solicitar una revisión de la sentencia , la nueva, a petición de la Dirección General de Menores no tiene ni un mes . Y a mi juicio , me parece muy acertada , en la línea de la Convención de la personas con discapacidad , especificando las áreas en las que necesita supervisión y control. ******************************************************** Angel, ¿A qué nueva sentencia te refieres? La que está escaneada en el expediente, la de la Audiencia Provincial, es de octubre del 19. ********************************************************** Amalia, Buenas , vamos a ver, la primera sentencia de Alejandro era sólo curatela económica , esa era de 23 de abril de 2019. Contra esa sentencia, menores reclamó una tutela total y el juez decretó una sentencia de curatela extendida también para la parte personal y de supervisión médica . No sé de qué fecha es , pero a mí me ha llegado hace un mes por el compañero de menores . La envié en un email a Miguel la semana pasada , te la he guardado en el expediente de Alejandro en el apartado de sentencias . Por eso te decía , que no es posible volver a pedir otra vez la tutela , cuando el juez ya ha resuelto esta petición. Seguimos ... ********************************************************* Buenas, A ver, te explico, Efectivamente esa es la sentencia de la que estamos hablando y es de fecha, 28 de octubre de 2019. Puedes ver la fecha si abres el documento, en la primera página. Esa sentencia, la dicta la Audiencia Provincial, estimando parcialmente el recurso que presenta la Abogacía General de la Junta de Extremadura, por el que solicitaba la tutela, resolviéndose la curatela, para el control terapéutico de sus enfermedades y el sometimiento a tratamiento, así como para la administración y disposición de sus bienes, autorizándonos a su ingreso en centro, sin necesidad de solicitar autorización judicial. En cuanto a la posibilidad de solicitar la modificación de su incapacitación, en este caso pasando de curatela a tutela, si es posible y además nos correspondería a nosotros iniciar el procedimiento, debido a que, y te cito literalmente: “la sentencia de incapacitación no impedirá que, sobrevenidas nuevas circunstancias, pueda instarse un nuevo proceso que tenga por objeto dejar sin efecto o modificar el alcance de la incapacitación ya establecida. Corresponde formular la petición para iniciar el proceso a que se refiere el apartado anterior, a el presunto incapaz, el cónyuge o quien se encuentre en una situación de hecho asimilable, los descendientes, los ascendientes, o los hermanos del presunto incapaz, a las que ejercieren cargo tutelar o tuvieran bajo su guarda al incapacitado y al Ministerio Fiscal”.','2');
