insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-11-04','miguel, llega del colegio de abogados de Cáceres la aceptación del servicio de justicia gratuita, quedando pendiente de la asignación de abogado para el proceimiento DP 498/2019 del Juzgado nº4 de Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-04','-Amalia : en su expediente papel he archivado la incidencia de ayer en el piso de menores , intentó agredir a compañeros y monitoras y se autolesionó . Está ingresada en el hospital en observación , posiblemente le van a dar el alta. Contacto con Jose Miguel del Manzano para preguntar y me deriva a Guadalupe , coordinadora de pisos .La he llamado para saber si acude al ESM para plantear al equipo la derivación a la UHDAC . Solicito a la parte eco información sobre el dinero que pueda tener por si hay que contratar a alguien en hospital. Por PIA abril de 2020 , tiene pérfil RAL , he ampliado zonas , a la espera de plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-04','-Amalia : me llama Esmeralda Guisado MOreno, es hermana biologica de Nerea. Son 5 hermanos biologicos , ella es la mayor , le sigue Nerea , Juanjo , Jésica y Fran , son menores de edad. Todos fueron adoptados menos Nerea que se quedó en el centro. De padre portugues y madre española , de las " Malvinas " en Badajoz. NO quiere tener contacto con sus padres biologicos pero sí con sus hermanos , solicita permiso para verla . Tiene 19 años y estudia en Caceres , lleva los apellidos de los padres adoptivos que son de Navalvillar de Pela. Tf 640636228. Contactaré con las monitoras del piso y le doy respuesta.','2');
