insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-04','-Amalia : me llama Esmeralda Guisado MOreno, es hermana biologica de Nerea. Son 5 hermanos biologicos , ella es la mayor , le sigue Nerea , Juanjo , Jésica y Fran , son menores de edad. Todos fueron adoptados menos Nerea que se quedó en el centro. De padre portugues y madre española , de las " Malvinas " en Badajoz. NO quiere tener contacto con sus padres biologicos pero sí con sus hermanos , solicita permiso para verla . Tiene 19 años y estudia en Caceres , lleva los apellidos de los padres adoptivos que son de Navalvillar de Pela. Tf 640636228. Contactaré con las monitoras del piso y le doy respuesta. Me dicen que lo van a consultar con el hospital y en función de cómo se encuentre avisarán directamente a Esmeralda para la reunión. ------------------------------------------------------- Buenas tardes. Informo del tema de las citas de salud mental de la joven, según hemos tratado en conversación telefónica. Desde que Nerea reside con nosotros, 24 de agosto de 2020, no ha asistido a ninguna cita. Adjunto la que tenía en octubre. La misma fue cambiada a través de llamada telefónica para el 22 de marzo de 2021, señalando que si existía alguna urgencia se podía contactar antes. Espero sea de ayuda, seguimos en contacto. Un saludo. Guardo la cita en su expediente. GUADALUPE DÁVILA INFANTES gdavila@cerujoviservicios.com 669 34 84 64','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-04','-Amalia : me llama Esmeralda Guisado MOreno, es hermana biologica de Nerea. Son 5 hermanos biologicos , ella es la mayor , le sigue Nerea , Juanjo , Jésica y Fran , son menores de edad. Todos fueron adoptados menos Nerea que se quedó en el centro. De padre portugues y madre española , de las " Malvinas " en Badajoz. NO quiere tener contacto con sus padres biologicos pero sí con sus hermanos , solicita permiso para verla . Tiene 19 años y estudia en Caceres , lleva los apellidos de los padres adoptivos que son de Navalvillar de Pela. Tf 640636228. Contactaré con las monitoras del piso y le doy respuesta. Me dicen que lo van a consultar con el hospital y en función de cómo se encuentre avisarán directamente a Esmeralda para la reunión. ------------------------------------------------------- Buenas tardes. Informo del tema de las citas de salud mental de la joven, según hemos tratado en conversación telefónica. Desde que Nerea reside con nosotros, 24 de agosto de 2020, no ha asistido a ninguna cita. Adjunto la que tenía en octubre. La misma fue cambiada a través de llamada telefónica para el 22 de marzo de 2021, señalando que si existía alguna urgencia se podía contactar antes. Espero sea de ayuda, seguimos en contacto. Un saludo. Guardo la cita en su expediente. GUADALUPE DÁVILA INFANTES gdavila@cerujoviservicios.com 669 34 84 64','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-04','Ana: Convesrsación con Ana Benavente, TS ESM-Plas., le informo acerca de la situación acutal. *La solicutud de calanización externa sigue su curso. ········································································································································· Llamada de Esperanza, TS - ESM-Mérida: Emi ha acudido sin cita a hablar con ella, el vigilante no ha podido retenerla. Le ha atendido. *Dice que ha encontrado un piso de cuatro habitaciones para compartir, se queda libre una habitación, son 150€ al mes. *Plantearé la posibilidad a Alberto, jefe de la sección económica, para que se abone por transferencia y se reajuste su asignación. ·············· Envío correo a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='TORRES'and apellido2='SANTOS'),'2020-03-08','EXITUS Los diferentes sistemas de bases de datos informan de su fallelcimiento el 08/03/2020. Se solicitó Certificado Literal de Defunción que lo confirma. Se remite el mismo al nº. 4 de Mérida para solicitar el archivo del procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2020-11-03','TERESA CON RESPECTO A ESTE TUTELADO QUISIERA SABER EL TIEMPO QUE LE QUEDA POR CUMPLIR CONDENA PARA GESTIONAR DONDE VA AIR UNA VEZ SALGA DE PRISIÓN. HEMOS HABLADO CON SU MADRE Y NOS MANIFIESTA QUE ELLA NO QUIERE QUE VUELVA A CASA, QUE DURANTE EL CONFINAMIENTO HA ESTADO CON ELLA Y HA SIDO MUY COMPLICADA LA CONVIVENCIA CON SU HIJO HE SOLICITADO EL CAMBIO DE NUMERO DE CUENTA DE LA PRESTACION DE ORFANDAD QUE PERCIBE, UNA VEZ NOS LO APRUEBEN EL CAMBIO, GESTIONAREMOS DESDE LA COMISION TUTELAR LA PENSION, POR ELLO NECESITO SABER LOS GASTOS MENSUALES QUE TIENE GUSTAVO PARA ENIAROS DINERO (¿TIENE CUENTA PECULIO?) ANTERIORMENTE LA MADRE LE PASABA TODA LA PENSION PERO A PARTIR DE AHORA SE LE PASARA LA CANTIDAD QUE ACORDERMOS CON EL FIN DE IR AHORRADO DINERO PARA LOS GASTOS EXTRAORDINAROS QUE SE NOS PUEDAN PRESENTAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-11-05','TERESA Se propone x Área Social posibilidad trabajar la mejora de tutelada a través, entre otros, de incentivos ECO, incrementando la asignación o con reintegros puntuales según su nivel de implicación y comportamiento. Para ello se establecen los límites que, en opinión de Área ECO no deberían superarse a la hora de gestionar esos incentivos: a) La situación ECO actual se resume básicamente en: • Ingresos tutelada: 2 prestaciones x 1.122,30 €/mes (sin tener en cuenta las extras). • Transferencia permanente mensual a hermano (Antonio) para gasto de alimentación y vivienda: 270 €/mes apróx. Esto está funcionando bastante bien y ha constado mucho trabajo instaurarlo. En mi opinión no deberíamos de tocar esto salvo que fuera totalmente necesario. • Reintegro autorizado tutelada: 100 €/semana = 434 €/mes SI INCLUIMOS EXTRAS (incluido abono Villanovense): el reintegro mensual de media alcanza los 503 €/mes aprox. • Otros gastos: No significativos hasta la fecha b) En 2015 la tutelada tenía autorizado un reintegro permanente de 200 €/semana = 867 €/mes. Este importe se ha venido disminuyendo a lo largo del tiempo por 2 motivos: • Considerarse por la CTAEX que era lo mejor para la vida y salud de la tutelada. • Abrir siempre la posibilidad de mejora del comportamiento y calidad de vida de la tutelada a cambio de incentivos positivos (limpieza hogar, orden de vida...). c) Para finalizar, los límites ECO para la nueva propuesta de funcionamiento con tutelada, podrían oscilar entre los 100 €/semana (433 €/mes) actuales y los 200 €/semana (866 €/mes), aunque no creo adecuado para ella disponer de tanto dinero en efectivo. Si no se ve positivo incrementar el reintegro semanal pero si incentivar a tutelada supondría que, cada mes, contariamos con un máximo de 433 € para dichos incentivos (dinerarios o en especie), además de los 100 €/semana que ya tiene autorizados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-05','Finalmente se adopta la decisión de no ser necesario autorización judicial para el internamiento involuntario, como tampoco para la autorización de compraventa. ************************************************************* Angel: Esta sentencia de Alejandro, se asemeja mucho a la de Rafael Santos Gómez, de hecho la dicta el mismo Juzgado, el de Primera Instancia, nº 4, de Badajoz. Os recuerdo que para Rafa, solicitamos hasta 3 veces autorización judicial para vender la finas rústicas, las acciones y el apartamento de la Línea de la Concepción y en las 3 nos indicaron que no precisábamos autorización judicial, tan sólo ASISTIR a Rafa, es decir, firmando, junto con él, en Notaría, todas las actuaciones que hemos realizado hasta la fecha. Algo similar va a suceder con Alejandro. La clave la encontramos en los términos ASISTIR, CONTROL, SUPERVISIÓN, términos utilizados igualmente para Rafa, aunque en el caso de Alejandro, y entiendo que lo hace para que no haya lugar a dudas, recalca que para realizar todas las actuaciones del 271 del código civil, esto es, internamiento en centro o venta/compra/alquiler de inmueble, que son las actuaciones que más nos preocupan, hasta la fecha, no precisamos contar con autorización judicial. ********************************************************** Amalia, Buenas , lo que va a dar de sí este caso. Queda claro , no necesitamos autorización judicial para el ingreso involuntario. Antes de activar nada , quiero hablar con la familia y ver si estarían dispuestos a colaborar , he gestionado para hacer visita si es posible mañana . La madre tendría que facilitar la entrada en el domicilio. Estoy intentando contactar con su psiquiatra , voy a solicitarle que le adelante la cita programada para que me oriente en la intervención , de nada sirve que yo active el 112 si en la UHB no lo ingresan al menos unos días. Si no está descompensado a nivel psiquiátrico no procedería el ingreso . Sin su colaboración la intervención va a ser complicada , tiene que acudir a las citas de salud mental y de CEDEX . ********************************************************* miguel, Entonces por lo que decís, asunto solucionado y por ahora no hay que comunicar al juzgado nada. No obstante a mi me quedan dudas no por la compraventa, sino por el internamiento porque literalmente decía la sentencia: “…necesitará asistencia del curador, sin necesidad de autorización judicial, para los siguientes actos: -para decidir su permanencia en una residencia o en un establecimiento de salud mental o de formación especial. En este caso no habla de ingreso en centro, sino de permanencia.. -…o celebrar contratos o realizar actos que tengan carácter dispositivo, susceptibles de inscripción.Aquí para la compraventa estoy de acuerdo que no se requiere autorización judicial. No obstante, Angel si estas seguro que es un caso similar al de Rafa Santos… que no hay problema para el internamiento por mi adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-05','Ana: Recibo correo de Alberto, Jefe Secc. Ecca., con nuevo presupuesto calculado, de acuerdo a la propuesta de compartir piso de alquiler: "...• Alquiler: 150 €/mes • Consumos: 50 €/mes (ESTIMADOS: si los reales son superiores, se minoraría el REINTEGRO) • Reintegro: 45 €/semana (195 €/mes): COMIDA, ROPA, CALZADO, TELÉFONO, OTROS. Forma de pago: tanto alquiler como consumos (nos tienen que enviar facturas para poder comprobarlo) se intentarían abonar x transferencia. Debemos saber con cuanta gente comparte el piso (4 habitaciones has comentado) ya que le tocaría abonar su parte correspondiente. ..." ············································································································································································· Convesación telefónica con Emi(722 432 418): Dice que ha cambiado de idea, que ya no quiere irse al piso de alquiler, que quién le hizo la propuesta "es un negro que se quiere aprovechar de mí", expresa. Qué quiere volver al hostal, pues no quiere quedarse en al calle. Ya se ha gastado los 182€ que sacó entre el viernes (día 30) y el martes (día 3). Le indico que es lo que ella pidió y puso por escrito, no puede cambiar de idea cada día. No debía haberse gastado todo ese dinero en tan poco tiempo sin procurarse alojamiento y habiendo rechazado todo lo que se le había gestionado previamente desde la CTAEX. **Con repecto a dónde ha pasado la noche, dice que en el hospital en Urgencias. Refiere haberse tomado varias pastillas de golpe, le habían puesto el gotero, pero esta misma mañana se ha arrancado la vía y ha insistido en que la dejaran irse. dice que se ha ido del hospital sin informe ni nada, que le había atendido la Dra. Rosa. ······················································································································································· Conversación a 3; Alberto, Teresa y yo: Se acuerda que no se le atenderá sin cita hasta el día 12 a las 10 h, como ya se le indicó. Y que no se le dará más dinero hasta que pueda retirar su asignación semanal el próximo lunes. *Teresa lo comunicará al vigilante de seguridad para que lo deje anotado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-11-05','Ana: Recibo llamada de Juan, Seg. Social (927 620 874). Solicitó por escrito Certificado de Fallecimiento de la madre de Catalina y Declaración Jurada de Ingresos. El plazo de presentación es de 10 días. *Explico la situación, es una tutela aceptada recientemente, no disponemos el Cdo. de Defunción de la madre, pues hace muchos años que falleció. Lo entiende. *Me facilita su dirección de correo-e: juan-antonio.canalo@seg-social.es para que le adelante cuando pueda la declaración jurada de ingresos y le indique la situación del documento que falta para tenerlo en cuenta. Cree que dadas las circustancias actuales sanitarias no serán extrictos con los plazos. *Si le envío la documentación por email no será necesrio enviarla física. ················································································································································ Envío un correo-e a Coral, CTAEX, pidiendo que solicite el Cdo. de Defunción de la madre de Catalina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-11-05','miguel, llega resolución del juzgado nº2 Montijo desestimando la demanda de remoción del cargo de excusa de curador','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-06','Ana: En relación a la llamada de esta semana de Pilar Cerrillo, TS de la Res. Virgen de la Montaña, envío correo-e a Ángel, Asesor Jurídico CTAEX; "...Desde la residencia de Mateo Ruano Moreno, me vuelven a preguntar si hemos recibido los documentos que te dijo el sobrino y si se ha iniciado ya algún procedimiento, imagino que aún es pronto… El director está muy preocupado con la gran deuda… y según me dijo Pilar está pensando en enviar un escrito al Jdo. Le dije que hagan lo que consideren, y que nos envíen a nosotros comunicado de la Deuda, más que nada de cara al Inventario (aunque acabo de revisar el informe social y en este sí lo especifican)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-10-26','enviamos el siguiente correo electrónico al sobrino de Mateo: "Buenos días, Siguiendo con la conversación telefónica, envío este mensaje, a los efectos que nos remita cuanta documentación disponga, relativa a su tío, D. Mateo Ruano Moreno, tutelado de esta Comisión Tutelar de Adultos, a los efectos de poder solicitar una modificación de las medidas adoptadas judicialmente y por las que abona una pensión de alimentos por sus dos hijos, uno de ellos fallecido. (Certificado de matrimonio, Sentencia condenatoria con respecto a la que fuera su mujer y en la que pudiera llegar a determinarse la pensión de alimentos, datos de los hijos, DNI, certificados de nacimiento, de defunción del que falleció, si el otro hijo trabaja, etc), así como cualquier otra que pudiera sernos de utilidad. Le facilito la dirección postal: Comisión Tutelar de Adultos de Extremadura Avda. de las Américas, 4 06800 Mérida (Badajoz) A/A Ángel Muchas gracias por su colaboración, Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-05','Ana: Correo de José Miguel Manzano (josemiguel.manzano@salud-juntaex.es): "Hola Ana. disculpa la tardanza en enviarte los archivos. Si te parece, cuando le eches un vistazo, hablamos para informarte más detalladamente. El resumen de su situación actual y anterior, está en el documento 7 Inf Sit Actual Costi....... El documento Contrato Costi..., es la última ampliación que se le ha hecho en el Dulce Nombre de María, al parecer improrrogable."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-11-06','miguel, llega a el certificado literal de nacimiento del curatelado. ************************************************* Se lo reenvío a José Luis de la notaria de romero leal para firmar la ratificación de la renuncia de la herencia que firmó el curatelado en la notaria de virgen de guadalupe de Cáceres el 24-9-20. Le pido firmarla hoy o como mucho el martes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-06','Volvemos a ponernos en contacto con el sobrino, para recordarle el correo electrónico que se le remitió el 26/10, solicitándole nos enviara documentación relacionada con su tío, Mateo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-11-04','Ana: Llamo a la Oficina de DNI-CC (927 626 544). Me indican que que la coordinación de la Unidad Móvil la lleva Manuel Vasallo, Subinspector, pero en estos momentos no está. Me facilitan su número directo: 927 629 092.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-11-06','Ana: Llamo a Manuel Vasallo, Subinspector de la Policía Nacional, oficina DNI-CC (927 629 092): me comunica que desde marzo, debido a la crisis sanitaria, no están visitando residencias de mayores, pues además de que les da respeto por el riesgo para residentes, recibieron una circular de Madrid desaconsejándolo. Pero dada las circunstancias, harán una excepción. Tienen previsto visitar Plasenzuela o el 30 de noviembre o el 22 de diciembre, aún tiene que cuadrar viajes. *Se pondrán en contacto 2 días antes con Alfredo-Residencia, para organizarlo bien. ············· Se lo comunico a Juana y a Alfredo por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-04','miguel, nos contestan por email por el juzgado que nos remitamos por fax a servicios comunes de los juzgados de Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-06','miguel, remito de nuevo el fax del día 29-10-20 a servicios comunes de los juzgados de Mérida, y esta vez sí da ok','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-06','-Comunicación del ingreso en la UHB : davila@cerujoviservicios.com Jue 05/11/2020 14:26 Buenas tardes, finalmente han ingresado a Nerea en el área de psiquiatría, ya no puede tener visitas, ni puede estar ninguna profesional con ella. No tienen informe aún, pero han entregado un justificado de asistencia desde el día que está en observación. Haremos una incidencia detallando todo y lo adjunto, si os parece. Nos han facilitado un número de teléfono para poder llamar al área, os lo facilito por si lo precisáis: 924218100. También nos han comentado que le han realizado ajustes en la medicación y que será un ingreso de corta duración y que al salir puede ser derivada a una residencia, imagino que han comentado esto aplicando a “casos habituales de personas sin familiares”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-11-06','Ana: Reenvío a Ángel y Miguel, Asesores Juridicos, el documento de Resolución de Justicia Gratuita de Mª Antonia remitido por Paula, T.O. CRR-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-11-05','Ana: Conversación telefónica con manos libre con Borja, Psicólogo del CSS, e Isabel Mª. Se le aclaran ciertas dudas acerca de la tutela. *Pide ayudar económicamente a su madre, pues pasa por una situación difícil. Le explico que el inventario aún no está hecho y la CTAEX aún no tiene acceso a sus cuentas. Cuando los compañeros vean las posibilidades eocómicas se decidirá. *Es paciente de larga trayectoria en el CSS, con ingresos frecuentes. Habitualmente, cuando no está ingresada, reside en una vivienda de alquiler con su madre y la pareja de ésta. Borja indica que *cuando a criterio clínico se estime oportuno, le daán pases de visita para acudir con su familia, con quienes regresará cuando llegue el momento de darle el alta clínica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-11-06','Ana: En relación a la converación telefónica de ayer con Borja e Isabel, envío correo-e a Alberto, Jefe Secc. Ecca.: "Buenos días Alberto, En relación a Isabel Mª Cano Blázquez, tutelada recientemente, ayer tuve conversación con manos libre con ella y el Psicólogo del C. Sociosanitario de Plasencia, en que actualmente reside. *Solicita, cuando se tenga acceso a las cuentas, realizar una aportación mensual a su madre, con quién reside habitualmente en Trujillo en vivienda de alquiler cuando no está ingresada en el CSS (ingresa con cierta frecuencia), pues la mujer debe estar pasando dificultades económicas. No hemos hablado de cantidad, cuando tengáis la ficha hecha y veáis las posibilidades económicas, me decís y lo vemos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2020-11-06','Se pone en contacto con nosotros Juan Ramón Díaz Díaz, Abogado (927214788-639390991) (jrdiaz@icac.es), para comentarnos dos procedimientos relacionados con Martín: 1. Juicio por delitos leves, procedimiento 79/19, seguido en el Juzgadol de Primera Instancia e Instrucción, nº 5, de Cáceres. Martín ha acudido a su despacho para contratar sus servicios, llama para preguntar si puede hacerlo. Se le indica que no, que para esos casos se acude a la justicia gratuita. Nos pondremos en contacto con el Juzgado, porque el juicio es el 23/11. En este procedimiento, Martín es el acusado. 2. Otro procedimiento por daños a un vehículo. Le asistió en diligencias previas con lo que entiende se le designará por el Juzgado. Una vez se le designe, nos solicitará documentación para representarle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-11-06','miguel, tal y como quedé con Paula del Crr en llamarla el miercoles, la he llamado para que me pase con la tutelada Toñi, acerca del escrito que nos hizo donde solicitaba la reclamación patrimonial. Le comento que ese escrito esta falto de consistencia,pruebas, fundamentación y concreción y la pido lo redacte de nuevo aclarando motivos, fechas, pruebas...todo lo que se le ocurra y que adjunte toda la documentación que crea que tiene como prueba. La explico como funciona la justicia y portanto que no puede dirigirse directamente al tribunal supremo ni al consejo de ministros... Una vez que lo escane me enviará la documentación. **************************************************** Aprovecha para preguntarme porque no pagamos la facura al abogado que ella contrató para solicitar a remoción del cargo. Le explico que ella tiene derecho a abogado de oficio y que si fuera de pago tendría primero que haberse puesto en contacto con nosotros y que hubieramos pedido varios presupuestos antes de contratar a uno. Le comento que al abogado ya se le ha explicado que no se le iba a pagar y éste declinó el procedimiento. La explico que está en su derecho a solicitar cuando quiera remoción del cargo pero que como tiene derecho a justicia gratuita que tendría que solicitarla en el colegio de abogados de Plasencia. Me dice que así lo hará. Les explico a ella y Paula que valoren la posibilidad en vez de pedir la remoción soliciten la modificación de la capacidad, pero en cualquier caso que tendrán que hablar con a trabajadora social, sin que yo pueda decirles si nos opondremos o no porque depende de muchos factores como son los informes que envían desde el centro, y todo ello bajo el criterio de la parte social, y el resto de la ctaex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-06','Ana: Llamada de Emi (722 432 418), dice que **está en Don Benito, que se ha ido a trabajar a una casa como Interna. Han venido a recogerla en coche. Está colocando ya sus cosas. Aún no sabe la dirección para poder decírmela. *Pide que le hagan la autorización para retirar el efectivo en la oficina de Don Benito el lunes o marte. Que le llamen para confirmarle en qué direccíón está. *También dice que va a dejar de fumar... ··························· Correo de Icíar, secc. ecca., unos minutos después: "...me acaba de llamar Emi para que te dé la dirección donde vive ahora, C/ Chile 9, Bajo A, Don Benito. ..." ················ Respondo a Iciar y pongo en copia a Tere, Amalia y Alberto, CTAEX, para que estén al corriente de la nueva situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-11-06','miguel, tras el intento fallido de remisión por fax de la comunicación de la resolución del Colegio de Abogados asignando abogado de oficio al tutelado por el procedimiento abreviado 498/2019, se lo remito vía email tomasa.hernandez@justicia.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-11-06','-Amalia : Centros pedidos para Cristofer : aprosuba 3, la Luz , CAMP Don Benito y añado Castuera. Envio el documento a los auxiliares para firmar y entregar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-06','Ana: Llamada de Pilar Martín, TS ESM-CC: Le han dicho en Dependencia, que José Manuel tienen aprobado el SAD por dependencia desde el día 1/10/20 y que lo está cobrando (Le ingresan 195 €/mes. *Nosotros no hemos recibido la resolución ni comunicación alguna al respecto. *Y la cuantía no se corresponde con la que aparecía en la Aceptación PIA que se firmó: 415,14 €. *Teniendo en cuenta que percibe PNC+complemento ATP, pero que pasa manutención a sus hijos... con esta prestación no podría asumir un servicio con coste: 495,98 €. ···································································································································· Llamo a la Secc. de Dependencia CC (927 00 43 89) varias veces, pero no obtengo respuesta. Llamo también a un número del área económica (927 00 43 04) sin éxito. Pruebo por último en el 927 00 42 47, hablo con Yolanda, confirma que tiene aprobada la Prestación Vinculada al SAD desde 1 de octubre, pero no puede mirar la cuantía. *Le extraña que sea tan baja, pues en capacidad económica se indica 692,30 €. *Me indica que compruebe la cuantía que le han ingresado y sí es así, acuda personalmente a hablar con las compañeras de dependencia de Mérida. ··········································································································································· Envío correo a Alberto, Jefe de Secc. Ecca.: "Buenas tardes Alberto, En relación a J. M. Romero Mediavilla, me comunican que al parecer tiene aprobada Prestación Económica Vinculada a SAD desde 1 de octubre y que le han ingresado 195 €/mes. Cuando puedas corrobórame que esto es así, pues si es así me va tocar reclamar, una vez más no es la cuantía que constaba en la Aceptación PIA que se firmó…. Y con ese dinero no daría para asumir el coste del servicio (495,98 €/mes )… Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-11-06','Ana: Correo de Miguel Ángel Ramírez, Director CRR-CC (residenciadir@feafescaceres.com): "Buenos días os informamos que ayer en la tarde-noche se procedió a ingreso en la Unidad de Hospitalización Breve del Hospital San Pedro de Alcántara del usuario Juan Mario San Román Blasco debido a las reiteradas salidas del recurso sin autorización expresa y derivando estas al consumo de sustancias tóxicas (se informó también a Salud Pública debido a que cuando vinieron a realizarle la valoración por protocolo 112 para posible ingreso presento conducta de escape y estuvo durante 4 horas fuera de las instalaciones). Se entrego informe facultativo de su psiquiatra de referencia (había tenido consulta con la misma el día anterior 4 de noviembre de 2020) a los servicios sanitarios que acudieron a realizar valoración ya que está presentando en el momento actual una conducta negativista y sin conciencia de la realidad y la problemática que estamos viviendo en el día de hoy con respecto a la COVID-19, siendo en todo momento un peligro de salud pública. No podemos aportar más información debido a que se realizó llamada telefónica al HSPA para preguntar por su estado y se había realizado cambio de turno y no disponían aún de toda la información. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-11-06','-Amalia : Centros pedidos para Cristofer : aprosuba 3, la Luz , CAMP Don Benito y añado Castuera. Envio el documento a los auxiliares para firmar y entregar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2020-11-06','-Amalia : pongo para firma gerente la aceptación Pia , solicito plara en centro discapacidad. Se registrará en Dependencia , de allí lo derivaran al CADEX para ver perfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='GONZALEZ'and apellido2='ROJAS'),'2020-11-08','EXITUS El centro comunica que el óbito tuvo lugar el 08/11/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-11-09','Ana: Correo de Sonia Leo, Directora Res. Virgen de la Montaña, Casar de CC (virgendelamontana@grupociudadjardin.com): "Buenos días, me pongo en contacto con ustedes para comunicarles el fallecimiento de Don Pedro Román García García el sábado día 7. Existen problemas para realizar su entierro. estoy intenetando ponerme en contacto con ustedes, Les ruego se pongan en contacto conmigo en el 927290550 con urgencia un saludo. " ··········································································· Reenvío el correo a Alberto, Coral y Belén, secc. ecca. ··························· Conversación con Sonia Leo (927 290 550), puesto que Pedro Román falleció el sábado en el hptal., pidió que lo mantuvieran en la cámara frigorífica, mientras podían ponerse en contacto con nosotros para las gestiones oportunas. *Dice que el sobrino de Pedro le ha manifestado que él se quiere hacer cargo del entierro en el mismo nicho de la madre de Pedro Román.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-10-27','Ana: Recibimos Resolución de Orfandad: SUSPENDEN la pensión que venía percibiendo debido a que el banco ha devuelto 3 mensualidades consecutivas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2020-11-09','TERESA RECIBO PF FEHCA EFECTO 1/1/21 IMPORTE 593,40','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-09','Ana: Tras recibir llamada de Nacho (927412540), sobrino de Mateo, envío correo-e a Ángel, Asesor Jurídico - CTAEX: "...Me ha acaba de llamar Nacho, sobrino de Mateo Ruano Moreno (927412540), dice que el fin de semana, que es cuando puede, se ha puesto a preparar la documentación que le pediste, pero que ha perdido el correo, ha debido eliminarlo sin querer…. Pide que por favor, se lo reenvíes de nuevo para poder preparar todo y hacértelo llegar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-11-09','EXITUS F/ del óbito: 07/11/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-11-09','Ana: Llamo a Control de Pensiones - Seg. Soc.(927 62 00 49), en relación a la SUSPENSIÓN DE LA P. ORFANDAD. Me pasan con Rafa, quien tras comprobarlo, me informa que al parecer ha sido un error, lo solucionará hoy mismo y lo enviará a cobro para que procedan a los pagos que faltan. ····················· Más tarde recibo llamda de Rafa - Control de Pensiones (927 620 051), dice que el nº de cuenta no debe estar bien, pues no entra. Me facilita un a dirección de email para que le envíe el corecto. *Envío un correo a Alberto y Juana comunicándolo y pidiendo el nº correcto. ································· *Envío a Rafa el nº de cuenta que me facilita Alberto a la dirección: rafael.sanchez1@seg-social.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-09','En relación con la herencia correspondiente a la hermana de Antonia, la cual falleció en el CSS de Plasencia, se solicita a Adela Rueda (adela.rueda@salud-juntaex.es), certificado de defunción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-09','Ana: Envío correo a Ángel y Miguel, Asesores Jurídicos - CTAEX: "...En relación a Miguel Santos Cordero, considero que hay que comunicar el alta del Centro Sociosanitario de Plasencia a fecha de 26/10/2020, día en que se trasladó a vivir a la casa de su padre con éste y su hermano en la siguiente dirección: Avda. Alfonso el Onceno, 27 - 10140 Guadalupe (Cáceres). Os adjunto el informe de alta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-09','Ana: Envío coreo conjunto a varios compañeros de la CTAEX: "... En relación a Emilia Morales Botello, os escribo a todos por agilizar, con esta mujer últimamente no se puede intervenir, por sus constantes cambios de ideas, mentiras, incidencias, etc. Me ha llamado para decir que lo que me contó el viernes de que estaba en casa de una señora en la que iba a trabajar como interna, es mentira… Dice que sí que está en Don Benito, pero en casa de su novio, un tal Miguel Ángel Mateo Martínez, a quién conoció en el comedor social de Mérida. Según narra, están viviendo en la casa de la madre fallecida de Miguel Ángel, la cuál pertenece a todos los hermanos, pero le dejan quedarse allí. • Juan Pedro y Julio, el que pueda que vuelva a cambiarlo en al BD, la nueva dirección que da es: C/Chile, portal 9, bajo A. Don Benito. • Miguel, creo que deberíamos comunicarlo de nuevo al Jdo. Simplemente añadir esta nueva incidencia. • Alberto, pide retirar allí ahora la asignación semanal, en la oficina de Liberbank de la C/Groizard, nº 13. *Si quieres, de todas formas mañana lo hablamos. • Tere, Amalia y Pedro (Bienvenido, espero que estés bien), sólo para que estéis al corriente y por si queréis aportar algo de cara a la intervención."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-11-10','Ana: Envío correo a Juan Antonio, Seg.Soc. (juan-antonio.canalo@seg-social.es), adjuntanto declaración jurada de Catalina: "... Tal y como acordamos la semana pasada mediante conversación telefónica, te envío adjunta Declaración jurada para el derecho a mínimos en la prestación de orfandad, relativa a Catalina Da Silva Bautista, tutelada por la Comisión Tutelar de Adultos de Extremadura, debidamente firmada y sellada por su representante legal. En relación al Certificado Literal de Defunción de su madre, decirte que estamos haciendo las gestiones oportunas para poder solicitarlo, en cuanto lo tengamos, te lo haré llegar también por este mismo cauce. Por último, comunicarte que a fecha de 21/09/2020, además de registrar la solicitud de prestación de orfandad, solicité así mismo la Prestación Familiar por Hijo a Cargo, para sustituirla por la PNC que venía percibiendo, por motivo de compatibilidad. Ante cualquier cuestión no dude en contactar. "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-11-10','Ana: Llamada de Gema, Ed. CAM-Francisco Pizarro; Aitor por fin podrá ingresar mañana en el C. Discapacidad ADISER de Castuera. ····································································································································································· Correo-e de Rafa, Seg. Soc. (rafael.sanchez1@seg-social.es): "YA ESTÁ REHABILITADA LA PENSIÓN DE AITOR MORENO FELIPE DESDE 01-10-2020 TAMBIÉN HE REENVIADO LOS RECIBOS IMPAGADOS DE JULIO, AGOSTO Y SEPTIEMBRE. SALUDOS,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-09','miguel, me dice Amalia que no prepare por ahora el internamiento involuntario: "Miguel ,de momento , con respecto al internamiento lo quedamos en suspenso hasta que desde el Equipo de Salud Mental nos orienten . Están valorando de hacer una subcomisión previa. Ya te ire diciendo".','2');
