insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2020-11-10','miguel, tras la conversación con Tere me comenta lo mismo que vimos en septiembre, y es quién y cómo renovar el pasaporte (ya ha renovado con extranjería el centro el permiso de residencia por un año). La comento lo mismo que le dije a Toñi el 15-9-20, sin embargo tras verlo con Ana vemos como opción que una vez obtenido el permiso de residencia durante 1 año, sólo quedaría renovar el pasaporte para lo cual lo suyo sería que fueran con la tutelada y con una autorización de la Comisión Tutelar de Adultos a poner la denuncia a la policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-11-10','ana: Adelanto por email a Pablo Guillén Caro, Habilitado (info@guillenzancas-habilitados.es), Declaración jurada de la Pensión de Clases Pasivas: "Buenos días, en relación a Dña. Anita Priscila Saquero Sánchez, Tutelada por la Comisión Tutelar de Adultos de Extremadura, adjunto remito Declaración Jurada relativa a la pensión de clases pasivas que percibe, debidamente firmada y sellada por su representante legal. Dado el colapso actual en el Registro, le remito directamente el original por Correo Certificado. Ante cualquier cuestión no dude en contactar. Un saludo." ·············· Lo envío por correo certificado.','2');
