insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-11-10','Ana: Recibimos la Resolución aprobatoria de de la PFHC. Fecha de efecto: 01/01/2021. Cuantía: 395,60 € ······································································································································· Envío correo-e a Alberto, Jefe Secc. Ecca: "Buenas, Cuando podáis, comprobar si a Julia Morón Hernández le están ingresando correctamente su PFHC. *La resolución que hemos recibido indica fecha de efecto a 1/01/2021… Seguimos." ······························································································································· Respuesta de Alberto: "Hola Ana. A día de hoy, todavía no ha entrado la PRXHC en Liberbank"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-11-10','Ana: Recibimos Resolución de Revisión del Grado de Discapacidad de Felisa. Grado reconocido: 76 %. *Guardo en el expte. tanto el Certificado como el Dictámen Técnico Facultativo. ········································································································································ Los envío escaneado a Estrella, TS del CSS. ················· Dejo a Julio, CTAEX, la Tarjeta para que la remita por correo certificado al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-11','Ana: Envío correo-e a Pilar Cerrillo, TS Res. Virgen de la Montaña - Casar de CC: "Buenos días Pilar, ¿cómo estás? En relación a Mateo Ruano Moreno, dado que sus cuentas están prácticamente a cero y la deuda contraída con la residencia, ya de forma previa a la aceptación del cargo por la CTAEX, es muy elevada, y los trámites para la reclamación de la pensión de alimentos se puede demorar bastante, consideramos necesario solicitar plaza en recurso residencial público, y teniendo en cuenta sus circunstancias económicas, la idea es solicitarlo por emergencia social, pues no puede pagar a día de hoy vuestro centro y de seguir así acumulará una deuda que difícilmente podrá saldar. Dado que tiene reconocido grado I de Dependencia, a priori no se le puede pedir por esta vía, pues además, si no recuerdo mal, me comentaste que es bastante autónomo y difícilmente le darán grado II si se solicita la revisión, así que, a no ser que se considere que pueda dar grado II, habrá que solicitarlo Vía Decreto. Te agradecería por ello, que hables al respecto con la compañera Trabajadora Social del SSAB, y le expongas la situación para que pueda emitir el informe social correspondiente (modelo de la solicitud vía Decreto). Así mismo, habría que solicitar además informe médico a su MAP (también el modelo correspondiente) para que desde la CTAEX se pueda completar y registrar las solicitud. En cuanto a la documentación que nos iba a enviar Nacho, hablé el lunes con él, aún no ha podido enviarlo, al parecer ha estado ocupado y luego ha debido perder el correo que le envió mi compañero Ángel especificando lo que necesitaba. Ya se lo ha enviado de nuevo. Seguimos en contacto. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-11-11','Ana: Llamada de la oficina del DNI de CC - Policía Nacional (927 626 546), me dicen que me ponga en contacto con Identificación de Madrid, pues ha aparecido otro DNI más actual que piensan puede ser de Rosa, con los mismos apellidos, pero con otro nombre… y que tienen que cotejar las huellas… ······················ Llamado a Identificación de Madrid (91 582 28 55) me dicen que existe una variación en sus datos de filiación, seguramenre un error, pero que enviando el Certificado Literal de nacimiento podrán solventarlo. *Enviarlo a la dirección: dd.identificaciones@policia.es, a la A/A de Sandra. ······················· Dado que no tenemos el Cdo. Literal de Nacimiento en el expte. hay que solicitarlo. ···································································································································· Llamo al Registro Civil de Oliva de la Frontera (924 740 000​): lo buscarán y hoy mismo nos lo enviarán por correo (no los lo envían por correo-e por no tener escáner)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2020-11-10','teresa hospitalizada en Mérida desde el Domingo 8 de Noviembre por COVID 19. Según nos informa el médico, su estado es grave.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FRAILE'and apellido2='EXPOSITO'),'2020-11-10','teresa dada de alta y se encuentra estable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-11','miguel, escribe el arquitecto, Adrian Cancho Clemente, pidiendo información para la obra de general Margallo: Buenos días, les escribo para conocer la situación de la disponibilidad económica para llevar a cabo la obra de reparación del inmueble de D. Miguel, así cómo el pago de la factura de honorarios. Necesitamos conocer este dato para poder cerrar el contrato con la empresa constructora. Necesitamos empezar ya porque la cubierta está al límite. ****************************************************** Le contesto, Buenos días, le informo de que la aprobación del proyecto depende de que nos autoricen desde el Juzgado de este gasto extraordinario, ya que por ley se exige este requisito para el tutelado. En cuanto a cuándo sabremos si el juzgado nos autoriza o no, no sabríamos decirle ya que la interposición de la demanda ha sido realizada por el abogado esta semana por lo que ruego tengan paciencia y nos vayan llamando o escribiendo a este email para les vayamos informando. En cuanto esté aprobado dicho gasto extraordinario inmediatamente daremos orden desde la Comisión al banco para que ingresen la parte que corresponda abonar de la obra al tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-11-11','miguel, en relación a la renuncia de la herencia llamo sin éxito a la notaria de Mérida (Romero Leal), previamente hablo con Antonio (Iñigo) de la notaria de Virgen de Guadalupe quién me confirma que enviaron sobre el 23 o 24 de septiembre a través de la plataforma sigma? a Don Gonzalo Fdez Pugnaire la escritura de renuncia de herencia firmada por el notario Don Carlos del Solar Barroso con Protocolo 1155. Tanto la semana pasada, como ayer, y hoy intento hablar sin éxito con José Luis de la notaria de Mérida, y le he mandado varios emails para me dé cita para ratificar dicha renuncia de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-11','miguel, me contesta el arquitecto:Muchas gracias por la información Miguel Ángel, vamos a intentar empezar las obras por el riesgo que corre el inmueble. Espero que este procedimiento no se demore en exceso. ********************************************************** le contesto: En cuanto sepamos algo del procedimiento les mantendremos informados. En caso de que transcurra tiempo sin que lo hagamos por favor recuérdemelo para ir preguntando al abogado. Gracias y disculpen las molestias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-11-11','CORREO Se remite, a ASPACE CÁCERES, Solicitud de Cédula de Inscripción o Título de Viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-11','miguel, de nuevo me escribe el arquitecto: No le he comentado, pero en caso de ser necesario, le podemos facilitar todos los presupuestos solicitados (todos de mayor importe), de tal modo que se justifique la inversión*********************** le contesto: Caso de que los importes varíen con respecto a los facilitados aportados al procedimientos por favor remítamelos para enviárselos al abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-11-11','miguel, llega este email de Curro: En relación a la petición sobre el PERMISO DE CONDUCIR. Se trataría de una modificación de la capacidad, en dicho aspecto por l o que ruego que a la mayor brevedad remitáis escrito en tal sentido, del Director de la CTAEX, además lo remitís también soporte WORD. Pero sobre todo pido que se remita algún elemento de prueba de la necesidad de modificación de la capacidad en tal aspecto. Con la documentación que habéis remitido no se incluye. ********************************************************* le reenvío el email de Curro a la parte económica (Alberto y Juana), social (Amalia y Pedro): Buenos días, en relación a Fco Javier Rodriguez Robles, tal como me solicitasteis desde la parte económica he solicitado por fax al Jzdo nº4 Badajoz retirada del carne, a lo cual hicieron caso omiso, tras hablar con el Jzdo 2 meses después no tenían ni idea donde estaba el fax y me pidieron lo enviara por escrito y oficio, así lo hice a final de Septiembre, 20 días después nos denegaban dicha petición por no estar solicitada vía Lexnet. Dicha incidencia junto con la documentación se la remití por 2 veces a secretaría general (Mª Guerrero) para que remitieran dicha documentación. Hoy nos llega este email de Curro, donde nos viene a indicar que fundamentemos nuestra petición. Dicha petición no pude acreditarla pues me basaba en lo que me comentabais desde el departamento económico de que era un peligro y que a Juana la insistía constantemente en que le adelantemos dinero para recuperar el carne de conducir (y de ahí nuestro dilema…sino estamos de acuerdo con que recupere el carne de conducir, estamos o no obligados a adelantarle ese dinero?), es por ello que hice las comunicaciones o solicitudes anteriores al juzgado. Pedro no sé si podrás hablar con Curro y que te aclare un poco qué es lo que quiere. No sé si por la parte social (Amalia) y económica (Juana) podéis aportar algo en que fundamentemos nuestro escrito al juzgado(emails, quejas…lo que sea). Como veis cada juzgado actúa de una forma, pues con Santos Cordero hicimos lo mismo por fax y ya está pendiente que resuelva el juzgado (ya le ha visto el forense). Por mi parte salvo que me aportéis documentación o algo no puedo hacer más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-10','Ana: Correo de Pilar Sánchez, Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Buenos días, les informo que el viernes 6 de Noviembre dieron el alta a Margarita del Centro Sociosanitario. Desde ese día, ha tenido un buen comportamiento en nuestro Centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2020-11-10','Ana: Correo de Carmen, TS del EVD- Secc. Plasencia (carmen.garciamarti@salud-juntaex.es): "...visite a una chica del CRR , ella tiene curatela. como afecta al PIA ? ella puede firmarle verdad . Se llama Flora Gutierrez Garcia" ······················································································································································· Le indico que la CTAEX tiene asumido el cargo de Tutor, pero es cierto que en la sentencia especifica que es una Incapacitación Parcila, sólo para la esfera patrimonial. Por tanto Flora puede firmar la Aceptación del PIA. Pido que nos envíen copia a posteriori para el expte. y el seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-11','Ana: Llamada de José Miguel Manzano (924 010 057): le ha llamado Virginia, TS del Centro Dulce Nombre de María, para comunicar que a Costi Alexandru le han concedido plaza en Centro de Discapacidad de Málaga, a través de la Ley de Dependencia. Cuando le envíen la resolución nos la remitirá. *Me enviará así mismo los contactos de las TS (Virginia y Susana) y el número de cuenta bancaria. ··············································································································································· Correo-e de José Miguel (josemiguel.manzano@salud-juntaex.es): "Contactos en el dulce Nombre: Macarena: Directora Ricardo: Secretaría Susana Romero trabajadora social Virginia Flores trabajadora social Carlos: Coordinador Res. 952290499, 645215203 653985002, 682092199 FAX: 952206060" ··· Adjunta documento del contrato en Banco Santander con nº de cuenta que reenvío a Alberto, jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2020-11-11','Ana: Según el informe remitido por ASINDI para la Rendición Anual al Jdo. Roberto continúa bien adaptado al centro, participando en acividades grupales y con sus tratamientos con diferentes profesionales (Estimulación Basal, Ocio y Tto. Psicológico). Necesita apoyo para algunas de las ABVD y acompañamiento en las salidas a la comunidad. Echa en falta las visitas al domicilio familia que hacía durante un fin de semana cada mes, y que dada la situación de crisis sanitaria hubo que suspender, se han sustituído por videollamadas y llamadas que resultan insuficientes para ambas partes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-10','Ana: Correo de Toni-Futuex, remite nota de seguimiento telefónico: "No acepta se le realice entrega mensual a través de transferencia bancaria, ni al padre, ni a sus hijos. Confirma que ya se ha empadronado en Guadalupe y que también se le ha asignado médico de atención primaria en el centro de salud, y que seguirá control de salud mental en Cáceres sin problema alguno, que es lo que deseaba. Insiste nuevamente en la posibilidad de recibir información en relación a sus cuentas y deudas en la actualidad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-11-11','TERESA Comentar que el pasado 10 de Noviembre se quedó con Rosi Mejías, hermana de Beatriz, en Calera para que hiciera entrega de las llaves del piso de alquiler que su hermana Beatriz Mejías, tenía en Zafra. Rosi entregó las llaves y otra copia que había hecho Beatriz para que la tuvieran sus padres y comentó que el fin de semana anterior había terminado de recoger todas las pertenencias de su hermana del piso. Pero no había podido limpiarlo ni se había podido llevar unas literas que le habían regalado a su hermana meses atrás. Seguidamente se visita a Paqui, la arrendataria del piso y se le hace entrega de las llaves que nos había facilitado Rosi. Se le comenta todo lo que se ha hablado con Rosi con respecto al piso y ella cuenta que irá a echar un vistazo lo antes posible y hará una lista de los desperfectos y de los arreglos necesarios que le había pedido la comisión tutelar (entiendo que para justificar el que no devuelva la finanza, pero desconocemos si hubo otras conversaciones con la casera).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-11-11','(Pedro)Llamada de lqa hermana de Dª Soledad solicitando información sobre la herencia. +++Se remite la Juzgado de 1ª Instancia nº 1 de Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-11','Ana: Respondo al correo de ayer de Toni y pongo en copia a Alberto, Secc. Ecca.: "Hola de nuevo Toni, El presupuesto detallado que elaboró en el Sociosanitario lo tenemos, de hecho se aprobó por la CTAEX. Pero en ningún momento se le dijo que el dinero para la aportación a su padre y la ayuda a sus hijos, se le fuera a dar en mano. Es más, su hija vive en Madrid, no podría dárselo mensualmente. A Mariví, TS del CSS, se le indicó que debían aportar los nº de cuenta para las correspondientes transferencias, ésta dijo que sí, pero que ya las facilitaran cuando Miguel estuviera en el domicilio, aunque ahora me genera la duda de si llegó a decírselo a él… En cualquier caso, pongo en copia a Alberto, Jefe de secc. ecca., para que lo lea y ya vemos, pero creo que la opción de dárselo a él en mano no se va a aceptar. Si quiere aportar dinero entiendo que tendrá que ser así, mediante transferencia. Seguimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-11-11','Ana: Puesto que la solicitud de PFHC la registré de entrada el 25/09/20, llamo a PFHC (927 62 00 23), varias veces, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-12','Ana: Recibimos correo de Miguel Ángel Ramírez, Director del CRR-CC (residenciadir@feafescaceres.com): "Buenos días os informamos de la incidencia presentada por Antonia Canelada del Rio en el día de ayer. A primera hora de la mañana se muestra irritable, de mal humor y con un comportamiento inadecuado y maleducado al dirigirse a monitoras desde el inicio del turno. En horario de pagas coge su monedero y se lleva todo el dinero que había en él, no entregándolo. Coge su papel de salidas le pedimos que lo deje en la mesa y que seremos nosotras quién se lo dé y así lo hace. Hace gestos tocándose sus partes íntimas en la puerta incomodando a los compañeros y se marcha. Al no acudir a las 13h. Al centro incumpliendo el protocolo por ausencia no autorizada se llama al 112 activando protocolo, nos pasan con la policía nos piden datos de Antonia y su descripción, si la encuentran nos la acercaran al centro y a su vuelta es cuándo tendremos que activar de nuevo protocolo para valoración Psiquiátrica. No ha tomado la medicación de la comida. Turno de tarde: Se llama a la policía para preguntar novedades sobre la situación de Antonia (según indicación). Nos comentan que han dado el aviso pero que sin que haya denuncia de desaparición, ellos sólo pueden dar aviso a sus patrullas de Cáceres. El protocolo para una búsqueda fuera de la localidad requiere una denuncia en la comisaria. A las 19:30 horas se vuelve a llamar al 112, donde nos vuelven a pasar con la Policía Nacional (que nos indica lo mismo que antes) y tras consultarlo con ellos, se llama a la Guardia Civil. La Guardia Civil nos indica que lo único que pueden hacer es dar aviso a las patrullas de la zona de Logrosán, pero sin denuncia este tipo de búsqueda más general no se puede realizar. Se les informa de todos modos de los posibles destinos a los que ha podido desplazarse Antonia. Se le facilitan los datos a Responsable de Coordinación para que sea él quien interponga la denuncia de desaparición. Turno Noche: Llama Responsable de Coordinación para informarnos que se ha puesto la denuncia y se ha activado la búsqueda. En caso de regresar Antonia al CRR, llamaremos directamente a la policía. No habiendo acudido en toda la noche al recurso y no sabiendo ni teniendo información de donde puede estar en estos momentos. Un cordial saludo." ······················································································································································ Correo-e de Miguel Ángel, a última hora: "Buenas tardes, os informamos que después de realizar llamada telefónica a su hermano (también padece enfermedad mental) que vive en Colmenar Viejo (Madrid) nos comenta que Antonia Canelada del Rio está allí con él desde ayer, nos comenta que realizó llamada telefónica al recurso no siendo cierta esa información. Esta asustado porque no la observa estable y no sabe como puede actuar. Ella sigue demandando que quiere su tarjeta de crédito y la tarjeta sanitaria, en estos momentos está sin medicación de salud mental ( solamente se ha tomado un Tranxilium que le ha administrado su hermano). Se va proceder a avisar al 112 para comunicarles que se encuentra en dicha población y la situación de la misma a nivel psicopatológico. Un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-11-11','TERESA Comienza la reunión a las 9:00 horas el miércoles día 11 EQUIPO PLENA INCLUSION Pili Arenas: comenta que en el periodo de diciembre a mayo han observado que Andrés tiene una necesidad constante de atención, necesita recompensas a corto plazo y cuando no las obtiene tiene grandes frustraciones. Tiene 3 ideas que le obsesionan, su madre, su cambio de género y tener pareja. Para trabajar esas obsesiones se le ha dado una atención siempre positiva, tenerlo ocupado la mayor parte del día y establecer relaciones positivas. Destaca la necesidad de una ratio 1/1 necesidad que no se puede cubrir en el centro porque no hay personal suficiente Sara: Se le ha incluido en varios talleres con el fin de tenerle ocupado (manualidades, musicoterapia, fotografía), muestra poca tolerancia al esfuerzo, enseguida se cansa. En los talleres ha habido ingesta de objetos. Muestra dependencia en la ABVD, demanda continuamente ayuda a pesar de que puede hacerlo solo. Ha intentado establecer una relación sentimental lo cual ha generado algún conflicto. Requiere atención exclusiva Mayte: Las llamadas de Begoña (profesional de menores) le venían bien. UDAHC Matilde Vivas: Comenta la gran necesidad de apoyo que demanda Andrés, por ello se ha pedio el cambio de perfil a Cadex de cara a la vuelta a Plena Inclusión El paso progresivo a centro alternando la estancia en centro y en la unidad se puede llevar a cabo siempre y cuando las condiciones de la pandemia nos deje La continua demanda de profesionales va a complicar la adaptación de nuevo a plena inclusión La idea es que participe en todas las rutinas que se hacen en la unidad pero no hay muchas tareas que hacer en la unida Nuria Bravo: Cuando se le ha dejado participar en algunas taras ha excedido las funciones llegando a hacerse pasar por un auxiliar Es una unidad cerrada en la que hay pocas cosas que hacer fuera de las ABVD, su única motivación es el alta y vivir solo. Mª Paz: Comenta que durante los ingresos en la unidad se ha mostrado poco colaborador y demanda continuamente el alta. Allí manifiesta que tiene novio y dos hijos en Almería y es por ello que tiene depresión y no cuenta con el apoyo de su familia. El no es consciente de la gravedad de las conductas que presenta en el centro y presenta un discurso muy pueril. Habla del rechazo que sufre por parte de su madre y comenta que tiene una abuela pero no reclama hablar con la familia. El móvil por norma no lo puede usar pero tampoco lo ha reclamado Durante los ingresos demanda mucha atención por parte de los profesionales Con respecto al control de impulsos ha presentado alteraciones y algunas graves. Su conducta es desafiante con intentos de fuga, de ingesta, amenazas y una agresividad importante Estrella: Comenta que las llamadas con la madre no son convenientes, esta pendiente del cambio de perfil de RAL a RAE IRIS Alberto: Comenta el poco progreso que se ha obtenido en las intervenciones debido a la inmadurez emocional que tiene, todo lo dirige hacia la tristeza y el es muy impermeable. Aporta que seria más necesaria la psicoterapia que un cambio de medicación. Con respecto a la disforia de género hay que conseguir primero una estabilidad psiquiátrica. La psiquiatra no lo tiene claro tras entrevistarse con el, aun no esta tomada la decisión. Con respecto al cambio de perfil RAE de vuelta al centro sin tener ratio 1/1 es difícil su control por ello plantea un paso progresivo al centro alternando udahc y plena inclusión. Alfonso: Las carencias afectivas y de relaciones justificaría su comportamiento. La vida que ha tenido, el rechazo de su familia y su disforia de genero le generan mucha frustración Habría que trabajar el apoyo conducta positivo para aumentar la motivación y asi disminuir conductas. Su única motivación es vivir de manera independiente y eso no es un objetivo realista. No tiene nada que le motive y que se realista Los problemas de conducta son la consecuencia de la vida complicada que ha tenido y la vida tan vacía que tiene. Se finaliza la reunión a las 10:30 Se plantea establecer contacto telefónico con Begoña y con Raquel (trabajadora del P.I.), sería positivo establecer videollamadas, ya las ha tenido con el centro pero no ha mostrado gran interés en ellas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-11-12','miguel, contestación de la parte económica: Demasiadas vueltas le estamos dando a esto y demasiado tiempo perdido. Desde la parte ECO, en lo que se refiere a este asunto, no tenemos más que aportar. Es evidente que, en este caso concreto, porque a Juana y Alberto no les parezca prudente que este tutelado conduzca un coche, no es un motivo suficiente para negarselo. Por tanto, si alguien tiene algo que aportar o que decir, o que gestionar, que lo haga (no que lo diga, que lo haga) ahora o que calle para siempre. Si no hay nada más que aportar, y la parte jurídica no encuentra inconveniente alguno, entiendo que la CTAEX, está obligada a facilitarle la realización de ese curso para que pueda volver a conducir, en caso de que su situación económica lo permita. Rogaría que no me preguntéis por la situación económica, porque ese no es el tema. *********************************************************** Conforme hablo con Pedro, Amalia, y de acuerdo con la decisión de la parte económica comunico a Curro la decisión de desistir del escrito remitido: Buenos días, no podemos acreditar documentalmente la necesidad de modificación de la capacidad de este curatelado a estos efectos de retirada de carnet. Se trata de una persona que quiere recuperar el carnet que le habían retirado y por tanto tendrá que pasar el filtro de la autoescuela y seguramente el médico para la recuperación del mismo. Al tratarse de una curatela no podemos impedir autorizarle a retirar su dinero con este objeto. La intención que teníamos desde la Comisión Tutelar es comunicar al Juzgado de 1º instancia e instrucción nº4 de Badajoz, que es peligroso tanto para él como para terceros debido, como dice en su sentencia de incapacitación: a su trastorno de la personalidad grave de carácter crónico y permanente que evoluciona en período de crisis, que altera gravemente la capacidad de juicio en relación a su cuidado por abuso en consumo de drogas y alteración en control de impulso. Dicho Juzgado se comunica con la Comisión a través de fax (cuando solicita por ejemplo rendiciones de cuenta…), pero cuándo se trata de presentarles cualquier tipo de documento todo son pegas, ya que se les ha comunicado en otras ocasiones que no disponemos de Lexnet para la presentación de documentos, siendo ésta la vía que ellos solicitan para poder comunicarnos con ellos, y lo cual entendemos en aquellos procedimientos en que se requiera representación procesal. En definitiva, que la intención desde esta Comisión Tutelar era comunicar y si fuera posible que éste dictara una resolución en el sentido de requerir a la DGT para la retirada definitiva del carnet de esta persona, pero viendo la imposibilidad manifiesta de poder conseguirlo, se ha decidido por la parte económica de esta Comisión Tutelar a que pueda disponer de la cantidad que solicita a efectos de que intente la recuperación de dicho carnet, repito siempre y cuando logre pasar el filtro del examen de autoescuela y el de los servicios médicos a efectos de poder certificado médico de aptitud. Por tanto damos por desistidos del escrito que os remitimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-11-11','miguel, recibo email de curro: En relación a la petición sobre el PERMISO DE CONDUCIR. Se trataría de una modificación de la capacidad, en dicho aspecto por l o que ruego que a la mayor brevedad remitáis escrito en tal sentido, del Director de la CTAEX, además lo remitís también soporte WORD. Pero sobre todo pido que se remita algún elemento de prueba de la necesidad de modificación de la capacidad en tal aspecto. Con la documentación que habéis remitido no se incluye. ******************************************************** se lo reenvío a la parte económica (Alberto y Juana) y la parte social (Pedro y Amalia): Buenos días, en relación a Fco Javier Rodriguez Robles, tal como me solicitasteis desde la parte económica he solicitado por fax al Jzdo nº4 Badajoz retirada del carne, a lo cual hicieron caso omiso, tras hablar con el Jzdo 2 meses después no tenían ni idea donde estaba el fax y me pidieron lo enviara por escrito y oficio, así lo hice a final de Septiembre, 20 días después nos denegaban dicha petición por no estar solicitada vía Lexnet. Dicha incidencia junto con la documentación se la remití por 2 veces a secretaría general (Mª Guerrero) para que remitieran dicha documentación. Hoy nos llega este email de Curro, donde nos viene a indicar que fundamentemos nuestra petición. Dicha petición no pude acreditarla pues me basaba en lo que me comentabais desde el departamento económico de que era un peligro y que a Juana la insistía constantemente en que le adelantemos dinero para recuperar el carne de conducir (y de ahí nuestro dilema…sino estamos de acuerdo con que recupere el carne de conducir, estamos o no obligados a adelantarle ese dinero?), es por ello que hice las comunicaciones o solicitudes anteriores al juzgado. Pedro no sé si podrás hablar con Curro y que te aclare un poco qué es lo que quiere. No sé si por la parte social (Amalia) y económica (Juana) podéis aportar algo en que fundamentemos nuestro escrito al juzgado(emails, quejas…lo que sea). Como veis cada juzgado actúa de una forma, pues con Santos Cordero hicimos lo mismo por fax y ya está pendiente que resuelva el juzgado (ya le ha visto el forense). Por mi parte salvo que me aportéis documentación o algo no puedo hacer más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-12','TERESA la valoración realizada en el CADEX a Guillermo Galán Gilgado el pasado 5 de noviembre de 2020. En primer lugar, fue valorado por la trabajadora social. Le preguntó por su entorno familiar, por la realización de las actividades básicas de la vida diaria y por su desempeño. A todas las cuestiones Guillermo respondía maquillando la realidad, afirmando que su desempeño era autónomo y que las relaciones familiares son óptimas. Desde el programa de apoyo social comunitario, explicamos la realidad a los diferentes profesionales sobre todo haciendo hincapié en la dependencia diaria que manifiesta y en la imposibilidad de seguir viviendo en su domicilio, ya que su situación socio-sanitaria no le permite tener un mínimo de calidad de vida si sigue en su entorno. En la valoración médica, percibieron alteración a nivel cerebral, pero considerándolas, el especialista, como leves (esto nos sorprendió bastante). Valoró la marcha, reflejos y equilibrio. Se basó en informes médicos y comprobó en la última analítica el cese del consumo de alcohol. El psicólogo en su entrevista, pudo percibir como Guillermo no reflejaba toda la realidad de su día a día, aun así, nos pido en varias ocasiones aclaraciones y al igual que al resto de profesionales le indicamos que es totalmente dependiente para su autocuidado y para el control de la medicación, delegando dichas tareas a la policía local de la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2020-11-12','TERESA El pasado 6 de Noviembre se visita a Paloma en su domicilio y se la encuentra sentada en el salón de su casa preparada para salir, con el bolso encima de la mesa y aseada. Se le pregunta si tiene algún informe médico o de salud mental ya que se los pedirán, Paloma contesta que no suele guardar los informes médicos por lo que no puede llevarse nada. Seguidamente se la acompaña hasta la calle para que se monte en el taxi y se saluda a Julio, el taxista. Se vuelve a ver a Paloma a la llegada al CADEX y se la acompaña hasta la sala de espera. La llama el psicólogo a su despacho y permite que entre con ella la deducadora del equipo social comunitario. El psicólogo le hace una serie de preguntas a Paloma sobre su vida diaria, sus rutinas de sueño y de alimentación y los hobbies y las amistades que ella pudiera tener en Jerez. La tutelada responde a todas las preguntas de manera muy vaga, y comenta que se encuentra bien en general, que tiene relación con su familia y que se encarga de organizar su casa los fines de semana. También cuenta que vive con su padre y está muy feliz en su piso, y que no quiere moverse de allí por ahora, quizá más adelante cuando su padre esté en peores condiciones, pero por ahora no. Al finalizar la entrevista, el psicólogo pide la palabra al equipo social comunitario para que aporte una visión más objetiva de la realidad de la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-11-11','miguel, conforme email de Escalona, nos requiere para que emitamos informe complementario complementario al que emitimos en noviembre del año pasado a efectos de presentarlo antes del día 20-11-20 en el Jzdo nº2 de Coria, debido a que ha habido traslado de expediente desde el Juzgado de Zafra. ************************************************************ Remito email a Teresa para que emita informe complementario social y pida el económico','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-11-12','miguel, Teresa me remite el informe social y económico, que yo completo con el jurídico y redacto ya completo como borrador, que remito a Escalona por email para que me de su visto bueno, antes de su firma por nuestro Gerente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-11-12','Ana: Conforme recibo el Certificado Literal de Nacimiento de Rosa, lo envío escaneado a Sandra, Identificación DNI-Madrid (dd.identificaciones@policia.es). ···· Se lo comunico a Juana, CTAEX, y a Alfredo, Res. Plasenzuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-11-12','Ana: Correo de Toni-Futuex: "...los datos de fallecimiento de la madre de Catalina Da Silva, ... ella nos comenta que falleció en el 82, no recuerda fecha exacta pero sobre el dia de la Hispanidad..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-11-13','Ana: Llamo al Registro Civil de Valencia de Alcántara (927 66 81 77): para informar que desde la CTAEX ya se envió solicitud por escrito de Cdo. de Defunción, pero aún no nos constaban más datos de la madre, sólo nombre y apellidos: María Bautista Piris. Y facilitar fecha de defunción: Octubre de 1982. *Hoy mismo nos enviarán por correo ambos certidicos de defunción (del padre y de la madre)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-13','Ana: Correo de ayer de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Hola Ana, respecto a José Manuel Romero Mediavilla ¿miraste el asunto del SAD que te comenté que por lo visto se abona pero el paciente no cuenta con el servicio?. Además hoy le he llamado y dice que tiene fiebre y se encuentra muy mal recomendándole su médico que guarde cama, yo creo que es muy necesario que tenga el SAD cuanto antes." ··············································································································································· Mi respuesta: "Buenos días Pilar, El jefe del área económica me ha informado de que en su cuenta bancaria no han ingresado aún nada y nosotros seguimos sin recibir la resolución. Intenté hablar, sin éxito, con una jefa de sección para que me lo mirara y confirmara. He pedido a otros compañeros que hagan una consulta en SIDEX, que yo no tengo acceso. Y en cuanto me confirmen, volveré a intentar hablar con la Jefa de Sección de la Dirección Gerencia. Mientras tanto, José Manuel debe seguir las recomendaciones de su MAP. Un saludo." ··························· Llamo a Pilar Martín, peo me dice que está ocupada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-11-13','miguel, vuelven a llamar de la fiscalía preguntando si vamos o no a interponer una denuncia y cuál es nuestra postura, contesto vía email lo siguiente: Buenos días, conforme a la nueva llamada por parte de esa fiscalía (Pedro)preguntando de nuevo si vamos o no a interponer denuncia, contestarles, esta vez por escrito, como en anteriores ocasiones lo mismo. Entendemos que desde el momento que la tutelada se persono ante la guardia civil y ésta remitió las diligencias adjuntas, es obligación de la Fiscalía si lo estima conveniente incoar el procedimiento que corresponda. A nuestro parecer dichas declaraciones por la tutelada son dignas de la apertura del procedimiento judicial oportuno en base a dichas diligencias de la guardia civil, quienes además realizaron las investigaciones testificales oportunas a las trabajadoras sociales del pueblo y de la Comisión Tutelar (Teresa Blanco). Nos consta, sin que podamos demostrarlo que estos hechos han sido alegados por la tutelada en reiteradas ocasiones en años distintos. Al igual que en anterior conversación con Pedro de dicha oficina de Fiscalía, se le indicó que desde la Comisión Tutelar entendemos que por ley la fiscalía es garante de los derechos del tutelado y que la Comisión Tutelar realiza una tutela meramente administrativa con los tutelados (hay más de 700), lo cual significa que no somos guardadores de hecho y que al no poder presenciar lo alegado por la tutelada no podemos denunciarlo, puesto que no podemos acreditarlo. Además entiendo que aunque sea una persona tutelada no es óbice para que pueda interponer una denuncia. Asimismo indicamos a Pedro de dicha oficina que entendemos una ratificación de esos hechos en la declaración que pueden tomar al hijo de la tutelada y a la trabajadora social del pueblo que obra en dichas diligencias, así como si lo estiman conveniente solicitar un informe del forense. Quedamos a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2020-11-13','miguel, me requiere la parte económica y social para contestar al email de la representante de la familia: Buenos días, en relación a su escrito como representante de la familia, les comunicamos que conforme al artículo 276.3 del Código Civil hemos cesado en el cargo de tutores y por tanto cualquier aclaración o duda tendrán que dirigirse al juzgado donde se remitirá la cuenta final una vez se tengan todos los datos y documentos necesarios. Comentarles que conforme a la Ley de Protección de Datos tampoco podemos facilitarles información sin que seamos requeridos por el Juzgado. Los datos para poder dirigirse al juzgado son los siguientes: Juzgado de 1º instancia nº4 de Cáceres, procedimiento de incapacitación 635/15. Reciban nuestro más sentido pésame. ****************************************************** email de ayer de Cristina, representante de la familia: Estimados Señores: El pasado sábado, 7 de noviembre, falleció Pedro Roman Garcia y Garcia de Paredes con DNI 08486970Q. Este Señor estaba tutelado por la Junta de Extremadura y residía en la Residencia Geriátrica. Virgen de la Montaña del Casar de Cáceres y era natural de Santa Amalia. En julio de este año, enfermó y aunque su familia no sabe bien y con claridad que tipo de patología ha sufrido, ha pasado estos meses entre ingresos en el hospital y periodos de vuelta a la Residencia Geriátrica. En un estado grave y preocupante. Sus familiares, por la situación actual, Covid 19, no han podido visitarlo ni acompañarlo, únicamente han tenido la información que le facilitaban desde la Residencia Geriátrica Virgen de la Montaña. Infelizmente el 9 de noviembre ha fallecido y aún no hemos recibido ninguna comunicación de sus tutores legales, teniendo que adelantar los gastos del traslado, funeral y corona.con el esfuerzo económico inmediato que ello ha significado. 3520 € ( incluye el ir a recogerlo a Cáceres , tramitación en Cáceres y Sta.Amalia , caja y corona ) Les rogamos contacten con nosotros mediante esta vía, para que nos informen de como transferirles estos gastos y la factura original a sus tutores legales. Factura emitida por Tanesa Don Benito Estamos intentando contactar con ustedes mediante el teléfono 924008548, pero es imposible por lo que les volvemos a pedir que se comuniquen con nosotros por la urgencia de la situación. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-12','miguel, recibo email de Amalia indicando que no es posible el internamiento involuntario: Buenas tardes , con respecto a Alejandro , y como os comentaba en emails anteriores , la intervención social pasaba por una estrecha coordinación con el ESM de Valdepasillas , que es el que le corresponde. A pesar de que en la nueva sentencia el juzgado nos faculta para la permanencia en un centro , no indica explícitamente el internamiento involuntario que queda sujeto a interpretaciones judiciales , antes de solicitar la autorización judicial de ingreso quería tener la opinión de sus psiquiatras. He solicitado a FUTUEX visitas periódicas a Alejandro ,con el objetivo de intentar adherencia al tratamiento , a través del acompañamiento a las citas de salud mental y CEDEX . Alejandro ha aceptado y se están reprogramando todas las citas. Desde el ESM no se ve viable la vía del ingreso por urgencia a través del 112, ya que no presenta una desestabilización clínica aparente, si no mas bien conductas disruptivas a consecuencia de la patología dual de base ( consumo de drogas ) Por lo tanto , de momento , no vamos a solicitar la autorización judicial de ingreso. He aclarado el concepto por el que Alejandro ha percibido de su padre los 140.000€ que tiene ahorrado . Es de una indemnización que le dieron cuando estuvo destinado en el País Vasco como G. Civil . Tras 12 años desaparecido , en los que la familia no supo de él , se le ha dado por fallecido , de ahí la prestación de orfandad que tramité por Clases Pasivas que está percibiendo y se le entrega a la familia . Con respecto a la compra de vivienda con ese dinero ,la familia sigue solicitándolo. Desde esta Comisión ya se valoró esta opción con área jurídica , económica y social y se ha decido esperar de momento a que cumpla las penas judiciales pendientes . No creo que tengamos que justificar nada al juzgado con respecto a este tema . También os informo que el abuelo me ha comentado que ha contratado un abogado porque quieren ser los tutores del chico y poder así tomar este tipo de decisiones . Al parecer , en el proceso de incapacitación no se les citó .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-12','Ana: Correo de Toni-Futuex: "Hola de nuevo Ana, A colación de los ultimos asuntos de Manuela Morato y sus nietos, te paso a detallar por un lado lo que ha observado la compañera al respecto de la auxiliar y por otro nuestro parecer sobre quedar con el otro nieto para esas supuestas pruebas documentales.. (entendemos que es algo que no puede enviar por email no??, no existe objección alguna en quedar con el pero, ya en el pasado cuando era Teresa la que hacia el segumiento, pasó algo similiar.. nos intentaron utilizar para ponernos de una de las partes en el conflicto familiar... lo complejo sobretodo es que si Jose Manuel se entera que quedamos con el otro hermano, cualquier intervencion en la casa o con el se haría si cabe mucho mas compleja. Situación actualizada sobre auxiliar 9-11-2020: 6/11/2020 Se contacta con José Manuel, con la excusa de comunicar la visita de la educadora, el próximo lunes, por la localidad, se aprovecha para consultarle qué tal va el asunto de la auxiliar, pues había tenido problemas por las bajas y demás… Él comenta que está yendo la de siempre, Quini, porque ya está incorporada tras una caurentena preventiva, va en horario de 12:30 a 14 horas, reduciendo su servicio a realizar la compra, se le dice que entonces no recibe ayuda para el aseo de Manuela, higienización del domicilio y demás, que se supone es para lo que más necesita el servicio… Indica que prefiere que no entre, pues la otra auxiliar que estuvo sustituyéndola, Carmina, resultó contacto directo de una persona contagiada, su hija, y nadie le ha comunicado si la auxiliar también era positivo o no… Se le dice que si lo hubiese sido y hubiese contagiado algo, ya les había dado la cara. Se le dice que no debe pasar siempre y menos si toman medidas, establece que prefiere tener precaución, ya que Quini también tiene un hijo de 18 años que sale por ahí y le da miedo porque duda que Manuela supere el virus, en caso de contagiarse. 9/11/2020 Se acude al domicilio, no abre nadie, se llama por teléfono, se le dice, a José Manuel, que se había aparcado por la zona y se aprovechaba para visitar, (pretendiamos ver si coincidiamos con la auxiliar en realidad) este indica que no está en casa porque ha salido a hacer la revisión del coche, se le pregunta si ha dejado a Manuela sola, comenta que está con Quini, la auxiliar, pero él ya está de vuelta, cita a la educadora en los alrededores del centro de salud. Se intenta escuchar en la puerta del domicilio, pues si la auxiliar está dentro debería escucharse algún movimiento, pero no se oye nada… no siendo que no la deje ni limpiar, ni tocar nada… Cuando llega José Manuel se le pregunta cómo ha dejado entrar a la auxiliar, se muestra inquieto, balbucea y acaba diciendo que lo ha hecho como algo excepcional, dejando a Manuela en la habitación y sin que Quini entre ahí, a su llegada desinfectará todo… José Manuel indica que hay mucha humedad en casa, se le consulta si se aprecia, a la vista, en las paredes de la vivienda, establece que sí, se le propone ir a fotografiar las humedades, aprovechando que la educadora está allí; primero pone de excusa que la educadora tiene mucha tarea y no la quiere enredar, se le dice que no hay problema, pues ya que se está allí no importa llegar más tarde, pero con todo hecho; después dice que no es necesario, ya otro día que prepare para poder acceder, además que está la auxiliar y ya va a ser mucha gente, que tiene que desinfectar primero, además tiene que salir a comprar…Osea que en la casa no pudimos entrar y por lo tanto comprobar si estaba Quini, aunque sospechamos que no. En relación a la cita que solicita Pablo, el nieto de Manuela, para facilitar las pruebas que indica tener en posesión, se duda sobre la viabilidad de hacerla efectiva,como te comentaba antes, no por imposibilidad de quedar, sino por poder ser una acción contraproducente en el seguimiento de Manuela y, al final, suponer más problemas que soluciones debido a sumarnos a las trifulcas familiares, las cuales deben estar en auge de nuevo por lo que se aprecia. En este tiempo se ha conseguido que José Manuel tenga cierta confianza en la educadora, acceda a algunas de las peticiones, como aceptar al arquitecto seleccionado y no al que él indicó de confianza, sin poner objeción; proporcionando datos de lo que hace la auxiliar o lo que hace con Manuela… Y quizá, si llega a ser conocedor de un encuentro con su hermano, todo esto vuelva para atrás y se vuelva al momento en el que había un trato de falta de respeto, ocultación, búsqueda de problemas continuos (que no quiere decir que no continúe con ello, pero parece que ha disminuido, en cierto modo). La situación hace dar alguna vuelta más, pues, por otra parte, igual es importante disponer del material, documentación y/o argumentación que pueda facilitar el otro hermano, pues se podría llegar a comparar y tener otro punto de vista; debido a ello, se plantea, ¿cabe la posibilidad de que envíe dichas pruebas por e-mail? De este modo se dispondría del material que menciona y se mantendría la distancia con esta persona. Ya me dices que te parece de acuerdo?? la compañaera va ir para alla de todos modos la proxima semana para ver a otros tutelados de valencia asique en el caso de que tenga que quedar con Pablo podria hacerse" ················································································································································································································ Otro corre de Toni: " Hola Ana! te adjunto el e-mail enviado por el arquitecto de Manuela Morato Picado, lo ha enviado también a la CTAEX, pero para que lo tengas tb!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-13','Ana: Mi respuesta al correo de ayer de Toni-Futuex: "Ok, gracias Toni, En cuanto a la “relación de confianza” puede que tengas razón, sobre todo en cuanto a la aceptación de Gloria, pero por lo que nos narras de las últimas llamadas y visita, se infiere que no es sincero, oculta cosas y tergiversa información… Propondré a Pablo que nos remita las “pruebas” por mail. Seguimos." ················· En cuanto al otro correo del presupuesto del Arquitecto, pregunto a Alberto si están en ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-13','Ana: Correo de Miguel Ángel Ramírez, director del CRR-CC: "Buenos días os remito las actuaciones que se llevaron en el día de ayer con respecto a la conducta de escape de Antonia Canelada del Rio. - Recibimos llamada telefónica al inicio del turno, nos comentan no tener más información sobre el paradero de la misma. Sigue en paradero desconocido. Tenía mañana por la mañana cita con el podólogo queda anulada. Llamamos por teléfono a su hermano Daniel al comprobar que teníamos el teléfono por si supiese algo de ella. Nos comenta que está en Colmenar el Viejo con él, nos informa su hermano que ha cogido un autobús hasta allí y que él acudió a recogerla. Turno de tarde: Nos ponemos en contacto con el 112 Extremadura y con la Policía Nacional para informar del paradero de Antonia. Desde el 112 nos derivan al 112 de la Comunidad de Madrid. Se les explica el estado de Antonia, y que requiere una valoración psiquiátrica. Nos indican que se le derivará o bien al Hospital de la Paz o bien al de Colmenar Viejo. Al cabo del rato nos llaman por este orden, Guardia Civil, Policía Local de Colmenar y el equipo del SUMA, que están esperando a que Antonia y su hermano regresen al domicilio. Posteriormente nos vuelve a llamar la Policía Local para indicarnos que se le está valorando por parte del SUMA y la llevarán al Hospital de la Paz. Nos confirman a las 16:45 que Antonia ha sido trasladada al Hospital de la Paz. Nos llama el hermano para comentar la situación e informarnos del traslado al Hospital de la Paz y que no le han dejado acompañarla. Cree que se ha dejado algunas pertenencias en la casa. Quiere obtener información sobre qué va a pasar con ella, se le comenta que en cuanto se tenga información, se le trasladará aquella que pueda ser proporcionada (por ser familiar). A las 17:50 horas nos llaman desde el Hospital de la Paz para pedir el tratamiento de Antonia y para recabar información adicional sobre el caso. Se les informa de lo acontecido en los últimos días. Indican que los psiquiatras se pondrán de nuevo en contacto con nosotros para ver cómo proceder. A las 18:15 horas nos llaman el equipo de psiquiatría del hospital de la Paz para recabar mayor información sobre Antonia. Nos indican que le van a dar la medicación pautada y que se van a poner en contacto con la unidad de psiquiatría del HSPA para ver cómo proceder, tanto si hacen traslado como si deciden otras alternativas. Se le facilita el número del HSPA. Nos vuelven a llamar por parte del Hospital de La Paz para hablar con los tutores legales de Antonia, se le comenta que está tutelada por parte de CTAEX de la Junta de Extremadura. Llamarán mañana para solicitar los teléfonos de la comisión tutelar (por temas legales) y así poder coordinar el traslado hasta Cáceres (HSPA). Está noche quedará ingresada en el box de observación y mañana procederán al traslado. Un cordial saludo." ······························ Llamo a Miguel Ángel Ramírez (687 487 908), en conversación telefónica de la unidad de psiquiatría del Hptal. de la Paz de Madrid, le han dicho que Antonia está tranquila. Quieren trasaladarla al HSPA-CC pero antes quieren hablar con nosotros. Les ha facilitado 3 número de la CTAEX, entre ellos el mío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-11-13','Ana: Correo de Alberto, jefe de secc. ecca: "Hola Ana. Tal y como hemos hablado, dadas las circunstancias actuales, no parece necesario ese incremento de la pensión. En caso de que se modifiquen sustancialmente esas circunstancias (cambio de centro y cuota, incremento de reintegros o de gastos extraordinarios, otras), como bien dices, podríamos tramitar esa mejora de la PNC, a posteriori. Alberto." *Dado el interés manifiesto en correo-e, le comunico a Estrella, TS del CSS, dicha decisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2020-11-16','miguel, Tere me manda documentación (denuncia) para solicitar emisión de nuevo pasaporte. ************************************** Tras intentar hablar con el consulado de Argentina sin éxito (salta contestador y habría que pedir cita previa)relleno un documeto online para agilizar la gestión de ponerme en contacto con dicho consulado previo a la cita previa. Ante la falta de información de los padres de la tutelada para solicitarlo, le envío a Tere email para que lo solicite al centro: Ahí tienes la copia de la denuncia por el tema de la renovación del pasaporte a ver que puedes averiguar para poder hacérselo….. o bien hacerle el DNI español, te recuerdo que ahora solo tenemos el permiso de residencia por validez de un año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-11-16','miguel, me escribe la abogada para indicarme que ya tiene nº de procedimiento para la aprobación de la herencia X37 ACEPTACIÓN O REPUDIACION DE LA HERENCIA 847/2020, DEL JZDO DE 1º INSTANCIA Nº4 DE BADAJOZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2020-11-16','(Pedro)Llamada de D. Tomás Esteban López (652-892180, desde Barcelona, donde vive: "Tengo 69 años y una pierna cortada y yo no quiero nada de mi hijo, solo quiero poder hablar con él y saber que está bien...He estado en prisión por un problema que tuve con un socio..." +++SE queja de no poder hablar con su hijo cuando llama todos los viernes. Le han dicho que se pone nervioso cuando habla con él. +++Hace referencia a las malas relaciones que mantiene con su cuñada y que cree que ha influciod con el centro para que no le dejen hablar con él..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2020-11-16','miguel, hablo con Felipe Muriel (abogado) que tramitará la aprobación de la herencia y la autorización de venta. Quedo en reunirme con él el viernes para ver el expte y preparar el escrito que recoja ambas cuestiones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-11-16','miguel, me confirma Mª Guerrero que finalmente vía lexnet se ha presentado solicitud de retirada de carnet de conducir del curatelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='NOGALES'and apellido2='MATADOR'),'2020-11-16','ingreso de Manuel Nogales Matador (Torremejía) en el Hospital de la UHB de psiquiatría. Se le acompañó a la cita en salud mental el pasado jueves, y debido a la valoración que hizo la psiquiatra que lo atendió se considero prioritario el ingreso para diagnostico y estabilización, entendemos que estara pco tiempo ingresado, pero que será pernitente y beneficioso para él, de cara a que tena un tratamiento adecuado y ajustado. Adjuntamos informe y nota donde desarrollamos lo sucedido en la consulta, intentaremos esta semana hablar con el unidad (aunque segun la normativa adjunta hay que pedir cita para hablar con el psiquiatra) y con el mismo para saber como se encuentra y cuando se prevee el alta, también por el tema de la retirada de dinero que tenia pautado para esta segunda quincena que no podremos retirar con el, si permanece muchos dias en la unidad. El se quedó relativmente tranquilo y bien, el dia del ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-16','TERESA GUILLERMO – PABLO GALAN GILGADO Tras evaluar el desarrollo de los diferentes seguimientos junto a las numerosas demandas y reprimendas al Equipo de apoyo social comunitario recibidas por parte de la policía local de Zalamea de la Serena debido a las gestiones y tareas que realizan a los hermanos Galán (tareas y funciones que se han adjudicado por su libre elección), mas, las circunstancias personales y sociales del caso, se continua contemplando el Servicio de Ayuda a domicilio del Ayuntamiento de Zalamea como una buena opción para dar respuesta a muchas de las necesidades actuales del caso. Dicha gestión se ha intentado tramitar en varias ocasiones desde el equipo de apoyo social comunitario con la trabajadora social de los SSB del Ayuntamiento de Zalamea de la Serena, obteniendo siempre una negación excusándose en algunas situaciones en las que se han producido agresiones físicas ocasionadas por problemas conductuales de Pablo. Tras leer el reglamento de funcionamiento del servicio de ayuda a domicilio del Ayuntamiento de Zalamea de la Serena, consideramos que pueden cumplir los criterios para ser beneficiarios de dicho recurso comunitario. Por todo lo mencionado, se sugiere explorar la posibilidad de iniciar el trámite de dicha solicitud. Para ello, se adjunta el reglamento del funcionamiento del SAD del ayuntamiento de Zalamea de la Serena y los Anexos I – II.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-16','TERESA GUILLERMO – PABLO GALAN GILGADO Tras evaluar el desarrollo de los diferentes seguimientos junto a las numerosas demandas y reprimendas al Equipo de apoyo social comunitario recibidas por parte de la policía local de Zalamea de la Serena debido a las gestiones y tareas que realizan a los hermanos Galán (tareas y funciones que se han adjudicado por su libre elección), mas, las circunstancias personales y sociales del caso, se continua contemplando el Servicio de Ayuda a domicilio del Ayuntamiento de Zalamea como una buena opción para dar respuesta a muchas de las necesidades actuales del caso. Dicha gestión se ha intentado tramitar en varias ocasiones desde el equipo de apoyo social comunitario con la trabajadora social de los SSB del Ayuntamiento de Zalamea de la Serena, obteniendo siempre una negación excusándose en algunas situaciones en las que se han producido agresiones físicas ocasionadas por problemas conductuales de Pablo. Tras leer el reglamento de funcionamiento del servicio de ayuda a domicilio del Ayuntamiento de Zalamea de la Serena, consideramos que pueden cumplir los criterios para ser beneficiarios de dicho recurso comunitario. Por todo lo mencionado, se sugiere explorar la posibilidad de iniciar el trámite de dicha solicitud. Para ello, se adjunta el reglamento del funcionamiento del SAD del ayuntamiento de Zalamea de la Serena y los Anexos I – II.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-11-16','miguel, a petición de Angel veo expte del curatelado porque hay una abogada (Olivia Novillo Fertrell Fernández que nos remite la minuta del procddimiento abreviado ante el Jzdo de lo Penal de Don Benito nº 190/2019 (Ejecutoria 74/2020). Contesto a Angel mi disconformidad al abono de dicha minuta: Buenos días compi, aquí vamos tirando, espero tu bien también. Comentarte que yo no he hablado nunca con esta mujer, aunque sí Pedro y no se acuerda. Lo que sí contesté al Ayto de Helechosa de los Montes de algo que pidieron pero no sabíamos qué querían realmente (si reclamaban por algún contrato o algo que tuviera pendiente con ellos el curatelado) He mirado el expte físico y virtual. Se trata de una curatela reciente (1 año aproximadamente), no hay rendición de cuentas aunque sí inventario y sólo cobra una PNC y no tiene ahorros. Sí que me he fijado que está cumpliendo una condena y que le quedaba pendiente alguna otra, pero con la referencia que nos envía la abogada no veo nada. Tanto en su expte físico como el virtual no tenmos relación de judicios pendientes o finalizados salvo lo que puedes ver en cuanto a situación de sus condenas en el expediente virtual dentro de la carpeta de Juzgados. En cuanto a la sentencia de incapacitación, y en concreto a la del nombramiento de curador a la Ctaex veo que se trata de una curatela muy amplia que consta de la protección de la salud y de los gastos que se salgan de lo ordinario, como es el caso de esta cantidad reclamada por la abogada. A mi entender no tenemos la obligación de abonarla no sólo porque no ha contado con la Ctaex, sino además porque hubiese tenido derecho a la justicia gratuita y además es insolvente, pues como digo sólo cobra una PNC. Por tanto y salvo la hubiera contratado antes de estar incapacitado creo no tiene derecho a que se le abonen los honorarios. Míralo y le contestas tú o yo como quieras. ******************************************************* contesto a la abogada: Buenas tardes en relación al email que nos ha enviado en relación con el procedimiento abreviado nº 190/2019 (ejecutoria 74/20) del juzgado de lo Penal de Don Benito, necesitamos nos remita la documentación judicial tanto del procedimiento como de la ejecución, ya que desconocíamos su existencia. También necesitamos que nos acredite la fecha en la que la contrataron y quién.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-16','(Pedro)Llamada de Jose Manuel. +++PCR negativo el jueves pasado y el día 26 tiene la colonoscopia. +++Dice que necesita unas zapatillas y ropa de invierno. +++Virginia ha enviado presupuesto del podólogo para cortarse las uñas. +++CRR: "...Me da igual uno u otro. Me ha ingresado 195 euros...me van a poner una mujer..." Se le insiste en que ese dinero es para pagar el SAD si finalmente se le puede poner.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2020-11-16','-Emai de Soledad de la Luz , el padre ha llamado porque el hijo quiere irse a vivir con él. Buena tardes, . Hace algo más de una semana estuvo aquí el abuelo de Cristofer que es con quien él convivía cuando era un niño, antes de proceder a la tutela por parte de la Administración (Menores). Conozco al abuelo desde hace muchos años. Me dijo que quería llevarse a Cristofer a vivir con él porque se encontraba enfermo y necesitaba que le cuidara y le acompañara. Te puedes imaginar cuál fue mi respuesta. Además de esos posibles motivos, supongo que también habría otros. Por supuesto, si Cristofer se fuera con el abuelo, Cristofer encantado pero la cuestión es que Cristofer reciba todos los Apoyos que necesite y la asistencia especializada necesaria. Estamos pendientes de él en el piso y sus tutores del taller también. El abuelo me pidió vuestros teléfonos y se los di. No creo que os llamen. Muchas gracias por avisarme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-16','(Pedro)Llamada de Nuria (22912)(Rocío:22944), de la Subdirección de Salud Mental. +++Tienen la documentación para la canalización pero no saben dónde se encuentra. El día 4 de noviembre estuvo en el ESM de Mérida, con Esperanza, la T. Social, para que se pusiera en contacto con nosotros por motivos de dinero. ++Nuria wse ha puesto en contacto con la UHB de Mérida por si ingresara allí para que fuesen consdcientes de que está pendiente de una canaliazación. +++Pregunta si ella va a querer volunatriamente ser canalizada, a lo que le respondo que dudo de que así sea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-13','-Amalia : envio email a todas las secciones de CTAEX Buenas tardes , con respecto a Alejandro , y como os comentaba en emails anteriores , la intervención social pasaba por una estrecha coordinación con el ESM de Valdepasillas , que es el que le corresponde. A pesar de que en la nueva sentencia el juzgado nos faculta para la permanencia en un centro , no indica explícitamente el internamiento involuntario que queda sujeto a interpretaciones judiciales , antes de solicitar la autorización judicial de ingreso quería tener la opinión de sus psiquiatras. He solicitado a FUTUEX visitas periódicas a Alejandro ,con el objetivo de intentar adherencia al tratamiento , a través del acompañamiento a las citas de salud mental y CEDEX . Alejandro ha aceptado y se están reprogramando todas las citas. Desde el ESM no se ve viable la vía del ingreso por urgencia a través del 112, ya que no presenta una desestabilización clínica aparente, si no mas bien conductas disruptivas a consecuencia de la patología dual de base ( consumo de drogas ) Por lo tanto , de momento , no vamos a solicitar la autorización judicial de ingreso. He aclarado el concepto por el que Alejandro ha percibido de su padre los 140.000€ que tiene ahorrado . Es de una indemnización que le dieron cuando estuvo destinado en el País Vasco como G. Civil . Tras 12 años desaparecido , en los que la familia no supo de él , se le ha dado por fallecido , de ahí la prestación de orfandad que tramité por Clases Pasivas que está percibiendo y se le entrega a la familia . Con respecto a la compra de vivienda con ese dinero ,la familia sigue solicitándolo. Desde esta Comisión ya se valoró esta opción con área jurídica , económica y social y se ha decido esperar de momento a que cumpla las penas judiciales pendientes . No creo que tengamos que justificar nada al juzgado con respecto a este tema . También os informo que el abuelo me ha comentado que ha contratado un abogado porque quieren ser los tutores del chico y poder así tomar este tipo de decisiones . Al parecer , en el proceso de incapacitación no se les citó . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2020-11-16','CORREO. Se remite al CRR de Badajoz documentación correspondiente a la derivación a Piso Supervisado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2020-11-16','-LLama Domingo Diaz Rivera 618832000 , arrendador de unas fincas de Lali y su hno Fco. El contrato lo tiene hasta el 2021 , lo dejará por jubilación y hay otra persona interesada . Contactarán en esa fecha . por otro lado solicitaba que se le bajase el alquiler y no es posible pq no se estableció en el contrato . Lo llamo pra darle la respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-11-16','miguel, la abogada nos remite una factura de un procedimiento que ha llevado y desconocíamos y la respondo vía email lo siguiente: Buenas tardes en relación al email que nos ha enviado en relación con el procedimiento abreviado nº 190/2019 (ejecutoria 74/20) del juzgado de lo Penal de Don Benito, necesitamos nos remita la documentación judicial tanto del procedimiento como de la ejecución, ya que desconocíamos su existencia. También necesitamos que nos acredite la fecha en la que la contrataron y quién.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-11-17','Ana: Correos-e de Toni-Adisher; del domingo 15: "Buenas noches Ana, me gustaría preguntarte una cosa sobre un tema referente a Aitor Moreno. Estamos observando, tanto yo como el resto de mis compañeras, una actitud de Aitor que nos hacen pensar y sospechar que consume porros dentro del centro. Ya te digo que son sospechas, pero la verdad que estamos preocupadas, más que nada tanto por él como por otro residente que es compañero de habitación y que ha tenido adicción a las drogas, y su madre nos comentaba que llevaba un año limpio. Somos novatas en este tipo de centro, dado que es de nueva creación, e ignoramos el procedimiento a seguir. Te pregunto a ti como referencia de la tutela de Aitor. Me podrías indicar el procedimiento a seguir con Aitor para aclarar las dudas con este tema?. Gracias Ana y un saludo." ····················································· Correo-e del lunes 16: "ANA BUENAS NOCHES ANA, TE CONSULTO LO SIGUIENTE: AITOR QUIERE PASAR LAS VACACIONES DE NAVIDAD EN CASA DE SU TÍO JOSE MANUEL MORENO ARAUJO, EN BILBAO. POR FAVOR DIME SI ES POSIBLE ELLO Y LOS TRÁMITES QUE NECESITARÍA PARA SOLICITARLO. GRACIASSSS" ································································································································ Mi respuesta: "Buenos días Toni, Perdona, pero ayer tuve el día de asuntos propios, por eso no vi ninguno de tus 2 correos. Vamos por partes: 1- En relación a la visita a su tío, yo es la primer vez que escucho hablar del mismo… no sabía ni que tenía un tío… de momento, decidle que por la situación de crisis sanitaria no es posibles. Y decidle también la verdad con respecto al tío, que no le conocéis ni vosotras, ni nosotros y que desde el CAM, tampoco nos han hablado/informado acerca de él. De momento, si tiene interés, puede ir llamando al centro para hablar con vosotras y con él, o hacerle alguna videollamada, e incluso, si quiere, llamar a la CTEX, para que le vayamos conociendo y en función de estos contactos, con el tiempo ya iremos valorando la posibilidad. Cuando el tío venga por Extremadura, si quiere también puede ir visitar a Aitor (siempre acorde a vuestro funcionamiento interno y a las medidas establecidas en cada momento por el Covid) 2- En cuanto al consumo de porros, creo que deberíais hablar con él al respecto, preguntarle directamente y decirle que en el centro está prohibido e incluso que tendrá que comenzar a hacerse controles en el CEDEX. Pues sí se confirma el consumo y continúa con él tendrá que comenzar a acudir y tendrán que intervenir desde allí también con él. La tutela de Aitor, la tenemos desde hace unos meses, en el CAM llevaba más tiempo y es donde mejor le conocen, en este sentido, igual estaba bien que hablaseis con las educadoras de referencia (Esther y Gema) y le preguntéis al respecto, quizá puedan orientaros un poco con respecto a la atención directa. No obstante, seguimos en contacto con respecto a estos y otros asuntos. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-17','Ana: Llamo a María González Palomo, T.S. de la Asociación Autismo Sur de Málaga (693 759 016 /teayudamos@autismosur.es), en que han concedido plaza a Costi. Hoy tieen una entrevista extensa con el personal del C. Dulce Nombre de María. Aún no está fijada la fecha de ingreso. El joven tendrá que abonarl el 75% de la plaza. Así mismo tendrá que asumir otros gastos; de farmacia (parte que le corresponda de la medicación), parafarmacia, transporte para actividades (lo pagan entre todas las familias...). *A Costi no le han gestionado ningún tipo de ingresos siendo menor, por lo que en su cuenta bancaria no hay nada de dinero... *Irán remitiendo al ctutelar@ unos excel con el desglose de los gastos que se vayan ocasionado para que a posteriori se puedan abonar. ······························································································································ Llamo al C. Dulce Nombre de María (952290499, 645215203 653985002, 682092199), hablo con Virginia, TS: Costi tiene tanto la tarjeta de residencia comunitaria como el pasaporte caducados desde 2016. **No sabe por qué desde menores no se le ha tramitado su documentación ni se le han gestionado ningún tipo de prestación económica... ································································································································· Llamo a José Miguel Manzano, Menores (924 01 00 57) me dicen que está de baja. *Mª José, una compañera, me indica que puedo hablar con Pilar Salguero, Jefa de Secc. (924 01 00 60), me pasa pero no obtengo respuesta. ········································································································································· Llamo a María Bueno, PNC, la solicicitud de PNC la tengo que hacer en Andalucía, dado que el joven reside y está empadronado allí.','2');
