insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELINA'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2020-11-17','Ana: En relación a la llamada de Raquel, TS de Cuacos de Yuste, envío a Alberto, Jefe Secc. Ecca. el siguiente correo-e: "Buenos días Alberto, Me ha llamado la TS de de Cuacos de Yuste, en relación a Marcelina Sevillano Sevillano, fallecida, le están instando desde el Ayto para que me llame y se soluciones la cuestión: al parecer la factura del nicho está pendiente de pago. Dicen que han intentado ponerse en contacto con 2 número de la secc. ecca. ... ¿Podéis poneros en contacto con Domingo, de intervención del Ayuntamiento para aclararlo? El nº del ayto. es: 927 17 20 58. Seguimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-11-17','(Pedro)Llamada de Ana Morano (22536), de Resp. Urgencias y Emergencias, en relación al traslado de Juan carlos. +++SE ha puesto en contacto con la subdirectora del 112 y ellos se encargan del trasladao. +++Respecto a su pregunta de si es por orden judicial se le aclara que es puesta en liobertad tras cumplir condena. +++En cuanto al acompañamiento, el 112 hablará con el Psiquiátrico Penitenciario para concretar que tipo de acompañamiento pued erequerir:sanitario, policial...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-17','(Pedro)Conversación y correo-e con /de Eva Rivero, T. Social del Hospital de la Paz (447077). +++Buenos días, A través del presente, se comunica que Antonia Calelada del Río ingresó de manera involuntaria el 13/11/20 en la UHB de la Paz y en el día de hoy será trasladada a su hospital de referencia, Hospital San Pedro de Alcántara (Cáceres). También hemos contactado con la Dirección de la Miniresidencia Cáceres, en la que la paciente reside habitualmente. Un saludo, Eva M Rivero Serrano. Trabajadora Social. UHB Hospital Universitario La Paz. Tfnos. 917277077, 917277376, 912071454, 917277520. evamaria.rivero@salud.madrid.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2020-11-17','El domicilio y teléfono de Martín es, Calle García Márquez, 10, de Cáceres, DNI 06998750-B, teléfono 603836970.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NURIA BELEN'and edp.apellido1='GARCIA'and apellido2='OLIVERA'),'2020-11-17','En relación con una posible herencia de sus abuelos, hablamos con su hermano, Javier (667 30 96 00). Unos primos y él, quieren vender una casa, que es propiedad de los abuelos, según dice. Al margen, nos llama José Luis (678840500), vecino de Guijo de Galisteo, interesado en la compra. Esta casa está en muy mal estado, se debe mucho dinero en concepto de contribuciòn, que además desconce a quién se lo estaría reclamando el Ayuntamiento y para afrontar todos los gastos, quieren venderla. Se le informa que antes deben formalizar la herencia de los abuelos, que tuvieron 4 hijos (1, la madre de Nuria y Javier) (2, otro que renunció), (3, otra que murió y que tuvo 3 hijos, que siguen vivos) y (4, otra que aún vive), así como la herencia de los padres. Todo ello para poder poner la vivienda a nombre de los herederos. Se le informa que habría que pedir autorización judicial para aceptar la herencia y para vender. Se le aconseja que acuda a los servicios sociales del pueblo, a los efectos de poder ayudarle en la solicitud de justicia gratuita, para que, una vez se la concedan, puedan llevar a cabo todos estos trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-11-17','TERESA Telefono de Rosa hermana de Bea 696337732 El dueño del piso de Beatriz nos ha traido dos cartas que le han llegado a su piso. Las dos las voy a enviar al Centro Sociosanitario de Mérida mañana (se que ella ingresa tambien mañana); una de las cartas creo que es la tarjeta sanitaria por el sobre que trae. Tambien me ha llamado varias veces la hermana de Beatriz, que ha intentado hablar con vosotros en varias ocasiones y no ha podido; esta tarde tiene que comprarle tabaco y algunas cosas a Beatriz y no tiene dinero para hacerlo. Me pide que os diga que os pongais en contacto con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2020-11-17','Recibimos Auto, de fecha 28 de octubre de 2020, dictado por el Juzgado de Primera Instancia e Instrucción, nº 4, de Plasencia, en relación con el procedimiento DPA 237/2020, por el que resuelven continuar con la tramitación del mismo, danto traslado al Ministerio Fiscal, para que formule escrito de acusación o solicite el sobreseimiento de la causa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-11-18','TERESA SE PROCEDE AL INGRESO INVOLUNTARIO EN UHB DE MERIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-18','-Amalia : email de Angel ( jurídico ) , no necesitamos autorización judicial para promover un internamiento involuntario : Tal y como os comenté en otros correos, la Sentencia que incapacita a Alejandro, se asemeja mucho a la de Rafael Santos Gómez, de hecho la dicta el mismo Juzgado, el de Primera Instancia, nº 4, de Badajoz. Os recuerdo que para Rafa, solicitamos hasta 3 veces autorización judicial para vender la finas rústicas, las acciones y el apartamento de la Línea de la Concepción y en las 3 nos indicaron que no precisábamos autorización judicial, tan sólo ASISTIR a Rafa, es decir, firmando, junto con él, en Notaría, Oficinas Bancarias, etc. En el caso de Alejandro, en todas las decisiones de mayor transcendencia que afecten al ámbito económico-patrimonial y el sanitario. Estamos para ASISTIR, CONTROLAR Y SUPERVISAR a Alejandro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-18','Ana: Llamo al C. Dulce Nombre de María (952290499, 645215203 653985002, 682092199), hablo con Susana, TS: solicito Certificado de Ingreso en Centro para solicitud de PNC y Resolución de la Ley de Dependencia en que se adjudica plaza en Asoc. Autismo Sur. El certificado de ingreso intentarán hacerlo y enviarlo hoy mismo. En cuanto a la resolución no se la han enviado de dependencia todavía. ························································································································································ Remito a María Glez., TS de la Fundación Autismo Sur, toda la documentación que nos enviaron para el ingreso de Costi, debidamente cumplimentada, firmada y sellada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2020-11-18','-Email de Angel , jurídicio sobre el tema de renovar el carnet de conducir : En la Sentencia de Incapacitación, esta persona, a pesar de sufrir incidencias de fibromialgias, distimia, estrés adicional, trastorno depresivo de base y trastorno por acumulación, éstas no inciden en el gobierno de su persona, gozando de suficiente estabilidad psíquica para mantener el juicio. Está sometida a tratamiento médico y psicofarmacológico, acudiendo regularmente a consultas concertadas. Es aquí donde podemos comprobar si de los medicamentos que toma, en los prospectos limitan o incluso prohíben conducir, tal y como hicimos con José Florencio (podéis ver la contestación que se hico al Juzgado en su expediente). En ese caso, podríamos oponernos a que pudiera conducir. No olvidemos que esta es otra de las ya conocidas curatelas (como la de Rafa Santos, Alejandro Nuñez, etc), donde estamos para SUPERVISAR, APOYAR Y ASISTIR, cualquier acto económico y patrimonial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-18','-Amalia : email a Cerujovi : Buenos días , en primer lugar preguntar cómo sigue Nerea , imagino que ya le habrán dado el alta. Ha contactado con vosotros , no sé si contigo o con otra compañera , la delegada tutelar , como te comenté hará un seguimiento de la situación Nerea , visitándola periódicamente . Si ya está de alta les indicaré que vuelvan a contactar para empezar las visitas. Con respecto a esta petición por parte de su hermana , autorizamos la visita. Gracias , Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-18','-email Cerujovi : Buenas tardes, Soy Fátima Agudo, educadora de Nerea Da Costa Lorenzo. El motivo de este correo es porque la hermana de Nerea ha solicitado tener una visita con ella. Me comenta que habló con usted y con José Miguel, técnico de la Junta, y que ambos le dieron el visto bueno. Por nuestra parte no habría ningún problema, para ello adjunto el siguiente documento para solicitarla, y para que así conste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2020-11-18','TERESA Rosa se acaba de ir a casa…muy emocionante , la verdad… y su padre me ha dejado la autorización firmada. Me insiste en que no va a haber problemas… que no van a salir… ni a relacionarse con muchas personas, que su hijo ahora está muy bien y prevé que la relación entre los hermanos va a ser buena. Esperamos que así sea. ARCHIVO AUTORIZACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2020-11-18','TERESA SOLICITIO POR ESCRITO INFORME SOCILA DEL SSB PARA PLZA RESIDENCIAL DISCAPACIAD HABLO CON FERNADO TS CENTRO DE SALUD 41504 Y LE PIDO INFORME MEDICO MODELO OFICIAL PARA PLAZA RESIDENCIAL ME QUEDO A LA ESPERA DE LA RECERPCION PAA ENVIARLO A MARIBEL MESA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-11-18','Ana: Correo de Paula, TO-CRR-Plas: "Buenos días Ana, quería comentarte que hoy han visto en dermatología a Guadalupe Barragán con motivo de una lesión en la nariz que ha resultado cancerosa. Por lo que nos comentan si se interviene puede no tener mayor repercusión, por lo que nos han facilitado ya el documento de consentimiento informado (que os enviamos por correo para su devolución firmada) así como un breve informe en el que se notifica esta circunstancia (que también os facilitamos en el mismo sobre). Muchas gracias por adelantado. Esperaremos la respuesta. Un saludo. Paula."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-11-18','(Pedro)Llamada de Ceferino (641881543). +++"Quiero más dinero, poque solamente me dan 1,5 euros al día..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GLORIA'and edp.apellido1='VERA'and apellido2='LLORENTE'),'2020-11-18','(Pedro)Llamada de Constanza, Psiquiatra de la UHB de LLerena. +++Agresión de Gloria a su madre, orden de alejamiento y el padre dice que no quiere que vuelva a casa. +++Parece que la intención es devolver a la Comisión la Tutela. +++Lo ha puesto en conocimiento de Beatriz,Subdirectora de Salud Mental para convocatoria de la Comisión Regional de Casos. Ya la derivó hace algún tiempo a la UHDAC pero fue rechazada por por CI limite y no ser un caso de Retraso mental. +++Tras ser una Unidad limpia de Covid-19, mañana regresa al Hospital de Llerena desde el de Mérida donde ha estado ingresada por este motivo. +++Envío la documentación por correo electrónico a Soraya (Unidad de Programas).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2020-11-19','Ana: Llamo a Sandra, trabajadora social de la residencia de mayores de Coria (927 508 000 - Ayto. de Coria - Ext. de la Residencia: Sandra, TS - 283 // Director: 281/282), varias veces, pero no obtengo respuesta... Llamo al nº directo de la residencia: 927 50 80 50, me dicen que hoy no ha ido a trabajar, ha pedido el día. *Le dejan nota para que me llame mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2020-11-18','Ana: Recibo correo de Juana, secc. ecca. CTAEX: "Buenos días compi, Ha llamado Sandra, trabajadora social de la residencia de mayores de Coria (927508000) para un tema de renovación de la tarjeta de residencia de Rosario González Jorna, la tiene también caducada y dice que hace tiempo que lo intentó ella pero que al ser los tutores nosotros no pudo. Te dejo su teléfono y ya lo comentas con ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2020-11-17','Ana: Correo-e remitido por Toni-Futuex, a la secc. ecca.: "Hola buenos dias, Recopilando información, que nos comenta M.Carmen Gonzalez Gonzalez, residente en vivienda propia en la localidad de Corian, ha estado bastante tiempo sin abonar la cuota la mayoría de los vecinos por un problema administrativo y de gestión, desde enero de este año 2020 se regularizó la situación y se envió todos los vecinos una carta con las cantidades por abonar y la forma para hacer efectivo el pago, la tutelada solicita a la CTAEX que dicha deuda fuera abonada. La tutelada está molesta y preocupada por este asunto, porque los vecinos se lo han reclamado en varias ocasiones, se mantuvo también conversación con el presidente de la comunidad para explicarle la demora en el pago de la parte correspondiente a la tutelada, se comprende la situación por parte de los vecinos pero argumentan que ha pasado casi un año y la comunidad necesita hacer frente a diversos pagos. En el documento adjunto se especifican las cuotas que le faltan por abonar, así como el número de cuenta para el ingreso, el importe total de la deuda que tiene M Carmen asciende a 360€ correspondiente a las cuotas de 2017,2018 y 2019 y el número de cuenta para el pago es: ES95 2048 1179 1030 0004 4011. El presidente de la comunidad de vecinos es Miguel Ángel Gordo Hurtado TF: 638006366."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='VENEGAS'and apellido2='AGUDO'),'2020-11-19','CIERRE EXPTE. El Jzdo. nº. 2, de Almendralejo, remite DIOR, de 12 de noviembre de 2020, para confirmar la firmeza de la ST. de Incapacitación. En ella se nombra curador a D. Juan Carlos Venegas Agudo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-11-19','Ana: Llamada de la Ofincia del DNI - Policía Nacional de CC (927 626 544), al parecer, le han dicho desde Identificaciones - Madrid, que no han recibido el Cdo. Literal de Nto. de Rosa. ··············· Se lo envío por correo-e (caceres.dni@policia.es): "Buenos días, Tal y como hemos acordado mediante conversación telefónica, les remito adjunto el Certificado de Nacimiento de Dña. Rosa Marín Laureano, Tutelada por la Comisión Tutelar de Adultos de Extremadura. Ante cualquier cuestión no duden en volver a contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-19','Ana: Correo-e de Miguel Ángel, Director CRR: "Buenos días Ana, ayer en turno de mañana nos pusimos en contacto con la UHB del Hospital San Pedro de Alcántara y nos informaron que Antonia Canelada del Rio está ingresada en la Unidad pero no nos dieron ninguna información más. Un cordial saludo." ····························· Mi respuesta: "Buenos días Miguel Ángel, A lo largo de la mañana intentaré llamar yo y ya os informo al respecto. Un saludo." ······························································································································· Llamo al HSPA (927 25 62 00): me pasan con el Serv. de Psiqiatría. Los Psiquiatras tienen reunión en este momento. Le dejarán nota al Dr. Enrique Daniel para que me devuelva la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-11-19','TERESA SE AUTORIZA SALIDA DE 7 DIAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-11-19','TERESA SE AUTORIZA SALIDA A VALDEOBISPO, ESTARA CON SU HERMANO LA IDA HA SIDO EN TREN Y LA VUELTA ESTAMOS VALORANDO LA OPCION DE QUE LA HAGA EN TAXI PARA EVITAR CONTAGIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-19','Ana: Correo-e María González Palomo, T.S. de la Asociación Autismo Sur de Málaga (teayudamos@autismosur.es): "Perfecto Ana... la documentación que tengamos te la iré enviando... el contrato lo sacaré ahora y te lo escaneo, aunque cuando tenga la prestación habrá que modificarlo... Hay un documento que nos lo pide la junta anualmente aparte del certificado de los ingresos... Te lo adjunto y cuando lo tengas me lo envías ... y si os da tiempo lo envías al igual que el resto de documentación. Con la documentación de identificación ya me decís si debemos de hacer algo... Un saludo " ······················································································································································ Llamo al C. Dulce Nombre de María (645 215 203): hablo con Virginia, no tienen ningún Cdo. de Empadronamiento reciente de Costi, por lo que tendrían que pedir cita para solicitarlo, puesto que los compañeros admvos. de la CTAEX lo pidieron de oficio el día 12/11, decido esperar a recibirlo. ··········· En cuanto al Cdo. de Ingreso en Centro, me lo enviarán al email cuando puedan. **Me confirma que el ingreso de Costi en Autismo Sur será el próximo miércolse días 25/11.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-11-19','Ana: para hacer la solicitud de PFHC como "entidad jurídica", necesito nº de Seg. Soc. (no lo tenemos ) y CCC. ····························· *Pido a Alberto; Jefe secc. ecca. que me lo faciliten cuando tengan acceso o se le abra cuenta nueva. ····················· Pido a Estrella, TS CSS-Plas., el nª Seg. Soc. ····················· Correo de Estrella: "...El número de la Seguridad Social de Isabel es: 101019765781"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-11-19','Ana: llamo a PFHC (927 62 00 23), tras comprobar los datos en el expte. me comunican que la baja en la PFHC que cobraba a nombre de su padre, tiene fecha de baja a 31 de diciembre, ha habido un error y la solicitud la han gestionado a fecha de octubre y no de la de registro (25/09/20). *Es decir, estos meses los debe seguir cobrando en la cuenta habitual y a partir de enero ya constará a nombre del tutor (CTAEX). El hacer el cambio ahora les supone mucho transtorno. **Pido a Icíar que cuando pueda compruebe que no han dejado de ingresarle al PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-19','(Pedro)Llamada de Enrique Daniel, Psiquiatra (56964).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-19','(Pedro). Llamada de Enrique Daniel (56964). +++Mañana, 20 de noviembre, dan el ALTA a Dª Antonia y regresa al CRR. +++Enrique me dice que lo va a comunicar al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-17','Ana: Hablo con Clara I. Gómez, Jefa Secc. Depend. (924 00 92 69): Al parecer el cálculo de ahora para la prestación de SAD está bien hecho. Cuando la Aceptación PIA no habían tenido en cuenta el Complemento a Tercera Persona. *Sobre la posibilidad de reducir las horas de atención y cuánto supondría en ese caso la prestación económica, me dice que lo hable con Ana Isabel Teomiro (927 00 67 88)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-18','Ana: Llamo a Ana Isabel Teomiro (927 00 67 88): Me dice que ella hizo la valoración incial del grado, pero para la revisión PIA y solicitud de SAD le atención otra compañera, que es con quién debo hablar. *Según la aceptación PIA es Marisa González.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-11-19','(Pedro)Visita de D. Lorenzo (678731543), hermano de D. Adolfo. +++Se le indica que la decisión que se ha tomado es la que se ha creído más apropiada para el bienestar de su hermano. +++Si quiere manifestar otra cosa, se le dirige al Juzgado correspondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-11-20','En relación con el procedimiento de cambio hormonal, tras conversación con el Juzgado, vuelven a decirnos lo mismo que la anterior vez que llamamos, debido a una reorganización de personal del Juzgado, tienen los expedientes parados. Les hemos insistido que por favor lo agilecen, por el estrés que le produce a Joaquín/Cristina. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-11-20','En relación con la autorización judicial de venta de inmuebles, el Juzgado de Primera Instancia nº 4, de Badajoz, en procedimiento X15 AUTORIZ JUD DISPOSICION BS MENORES/DISCAPAC 0000828 /2020, va a acordar el nombramiento de perito para valorar los bienes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-19','Ana: Conversación con Marisa González, Técnica PIA. Ella ve injusta la reducción por tener complemento a Tercera Persona, pero es lo establecido. *Hablará con alguien de prestaciones con respecto a la posibilidasd de reducción de las horas de atención y en cuánto ser reduciría tamibén la prestacióncon vincualada y nos dirá. ················· Correo de Marisa (marialuisa.gonzalezs@salud-juntaex.es) a última hora: "Hola Ana He hablado con Paqui Berrocal, es quien lleva prestaciones económicas en servicis centrales del SEPAD. Me ha dicho que mañana a primera hora la llames para que solvente las dudas. Su teléfono es el 924930401."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-20','Ana: Llamo a Paqui Berrocal, Prestaciones SEPAD - Dirección Gerencia (924 93 04 01) tras hacer cálculos según el precio/hora del SAD (13,24 €/hora según el contrato con cláusula suspensiva que tenemos) y aplicar la fórmula correspondiente, me indica que si se redujera el servicio a 21 h, le correspondería por prestación 100€/mes. *Dado los gastos que tienen habitualmente José Manuel (catering, luz, agua/comunidad vecinos, manutención hijos, asignación semanal...) *Hablá que renunciar a la prestación vinculada de SAD. *No obstante le envío a Alberto un correo pidiendo que haga él los cálculos y nos lo corrobore. ······························································································································· Conversación con Pilar Martín, ESM-CC; insiste en que hay que agilizar el ingreso de José Manuel en CRR, le recuerdo que no depende de nosotros. Tiene que esperar a que haya plaza. Con respecto a la Prestación vinculada de SAD, le explico la situación. Preguntará por el SAD municipal en el IMAS. **Me informa que José Manuel ha amenazado a Virginia-Futuex: "A los chivatos en la carcel le rajan la car ay le cortan la lengua" dice que le ha dicho.································································································································· Conversación con José Manuel Romero, pregunta de nuevo cuando podrá ingresar en el centro y pide dinero. *Le recuerdo que de dinero debe hablar con la sección ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2020-11-18','Ana: Tras haber intentado, a petición de Ángel, CTAEX, contactar con Martín en múltiples ocasiones en distintos horarios, envío un correo a Toni-Futuex: "Buenas tardes Toni, En relación a Martín Domínguez García, te reenvío el correo que me envió mi compañero Ángel, asesor jurídico. Yo he intentado hablar con este hombre numerosas veces a lo largo de la mañana en distintos horarios y: “el teléfono marcado no se encuentra disponible en este momento, por favor inténtelo de nuevo más tarde…”, ¿podríais intentar, desde el programa, poneros en contacto con él por teléfono o en el domicilio para comunicar que tienen el juicio y cerciorarnos que asistirá?..." ········································································································································· Respuesta de Toni: "Hola Ana, pues este hombre no está en el programa, hemos considerado de hecho la baja, hace poco.. poruqe se intentó localizarlo en varias ocasiones, al principio sin ninguna fortuna, no se si la dirección que teniamos es la misma que me facilitas, lo podemos intentar.. fuimos a la casa, de la direccion que nos facilitasteis y alli, nada y nadie sabe nada de el, como si estuviera en paradero desconocido. Le paso la direccion a la compi, y le digo que vea si esta es distinta y lo intentamos!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-11-19','Correo de Maite, TS Secc. Discapcidad (maria.gomezma@salud-juntaex.es): "...Le he dado plaza a FELISA BUNO SAAVEDRA en ASINDI. se lo acabo de comunicar a centro. Les he dado tu teléfono para que contacten. ..." ·············································································································································· Recibo llamada de Soni Bernabé-Asindi, un poco preocupada pues no sabe como llegará Felisa de la UHDAC, y en estos momentos cuentan con el ingreso reciente de otro joven (del que aún la CTAEX no ha aceptado el cargo pero será cuestión de tiempo), que ya ha manifestado alteraciones de conducta con heteroagresividad... Contactará con la UHDAC (Estrella, TS y Psicóloga) y con la entidad en la que residía Felisi antes de ingresar en la UHDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-20','Ana: Correo-e de Belén a José Manuel Correa: "Buenos días, José Manuel, en relación con las obras en la vivienda, hemos contactado con el arquitecto, el cual nos ha enviado presupuesto de sus honorarios por importe de 600€ +IVA y las hojas de encargo del proyecto de la misma por importe de 9371,77€ + IVA, pero él desconoce el presupuesto real de la obra del albañil y nosotros tampoco hemos recibido presupuesto alguno del albañil, quedamos a la espera de que nos remitas el mismo. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2020-11-20','Ana: correo-e de Miguel Ángel Ramírez, director CRR-CC: (residenciadir@feafescaceres.com): "Buenos días Ana, te remito el informe de alta en la UHB del Hospital San Pedro de Alcántara de Antonia Canelada del Rio. Según refieren en el mismo durante el ingreso no ha presentado en ningún momento alteraciones de conducta ni problemas de manejo, creemos que es debido a que ya consiguió lo que se proponía que era entregarle dinero en efectivo a su hermano." ······················· *Guardo informe en el expte. digital: "Desde la consulta de Salud Mental, el día 27 de noviembre de 2020, la Dra. Rubio contactará telefónicamente con la paciente para seguimiento ambulatorio"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-11-20','Ana: correo-e de Miguel Ángel Ramírez, director CRR-CC: (residenciadir@feafescaceres.com): "Buenos días de nuevo Ana, te remito el informe de alta en UHB de Juan Mario San Román Blasco." ················ Guardo informe en el expte. digital. *Próxima cita presencial en la consulta de la Dra. Rubio en Salud Mental el próximo 27/11/20 a las 10:30 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='SANDEZ'and apellido2='MAMAJON'),'2020-11-21','TRASLADO HOSPITAL "Se comunica a esa Comisión Tutelar de Adultos que el interno Manuel..., ingresado en este Centro y Tutelado por esa Comisión, ha sido trasladado al Hospital de Mérida el 19/11/20, a las 01:00 A.M., por crisis asmática grave." transmitido por CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2020-11-23','Recibimos correo de Leonor Chamorro Mera, nos traslada Monitorio nº 1274/2020, dictado por el Juzgado de Primera Instancia nº 2, de Badajoz, por el que le reclaman 383,73 euros, en concepto de facturas impagadas de vodafone. Respondemos al correo pidiéndoles que nos remitan las facturas reclamadas, al objeto de comprobar fechas y, de proceder, efectuar el pago, o contestar al requerimiento oponiéndonos (tenemos de plazo hasta el 4/12).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-20','Ana: Correo-e María González Palomo, T.S. de la Asociación Autismo Sur de Málaga (teayudamos@autismosur.es):"Sí Ana, el próximo 25 de noviembre, si la PCR sale el resultado negativo... Hemos conseguido que la junta abone el 100% de dicha plaza teniendo en cuenta la situación excepcional hasta que se regule la PNC. Aunque hay gastos que se os enviaran y los tendréis que abonar con carácter retroactivo. Por otro lado, con las últimas incorporaciones hemos dado esta posibilidad a las familias de tener una persona más encargada para la acogida... Donde ellos sientan un vinculo y una mayor y rápida integración en el grupo ya creado. Las familias son las encargadas de asumir dicho gasto, esta situación es muy diferente.... Pero si podéis abonar la cantidad ocasionada os lo agradeceríamos... una vez que ya tenga su PNC por supuesto... Esto lo vamos hacer ya que nuestro hogar está actualmente muy estable, con las rutinas muy marcadas, y cualquier movimiento pueda tambalear todo lo conseguido en un año de trabajo. Ya me dices como lo veis... Muchas gracias por todo Estamos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2020-01-07','SALIDAS Entre el 07/01/2020 y el 10/01/2020. Domicilio Familiar. Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2020-01-31','SALIDA Entre el 31/01/2020 y el 03/02/2020. Domicilio familiar. Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2020-02-21','SALIDA Entre el 21/02/2020 y el 27/02/2020. Domicilio familiar. Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-11-23','Enviamos correo electrónico al área social (Amalia): "Buenos días, compi, Me dice Teresa que Ati ha ingresado en la UHB y que vas a hablar con el psiquiatra. Como sabes, solicitamos ingreso involuntario al Juzgado de Zafra y se le citó para reconocimiento forense el día 19/11/2020, que no habrá ido, porque estaba en paradero desconocido. Necesitamos que emitan un certificado de ingreso para enviarlo al Juzgado. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='FERNANDEZ'and apellido2='MARTINEZ'),'2020-11-23','TERESA se encuentra ingresada en el Hospital de Mérida. Su estado según nos informan, es grave.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-11-23','TERESA había estado hablando con su primo Diego, el fiscal jefe de Zafra, según ella. Le había comentado que tenía un juicio el día 24 de Noviembre en Zafra al que tenía que asistir en calidad de testigo y su primo le había respondido que ella al estar incapacitada estaba exenta de ir. Diego le pide a María que hable con sus tutores para que le envíen su certificado de discapacidad y la sentencia de incapacitación y así no tendrá que presentarse al juicio. Porque si llegara el día del juicio y ella no fuera, la podrían multar por no haber asistido. SE ENVIA DOCUMENTACION AL JUZAGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2020-11-23','TERESA SE AUTORIZA ASISTIR A CLINICA PRIVADA DE OFTALMOLOGIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2020-11-23','CORREO Se remite Derivación a Piso Supervisado al CRR de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-23','TERESA HABLO CON ANA DE LA GERENCIA DE BADAJOZ Y LE COMENTO QUE YA FUE GUILLERMO A CADEX, LO HA CONSULTADO Y YA TIENE PERFIL ME QUE A LA ESPERA DE RESOLUCION DE LA PLAZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2020-11-23','En relación con el monitorio 96/20, seguido en el Juzgado de Primera Instancia e Instrucción, nº 6, de Avilés, enviamos correo electrónico al Juzgado (juzgado 6.aviles@asturias.org), solicitando nos envíen documentacion relacionada con este procedimiento, a los efectos de personarsnos y emprender las acciones que correspondan en defensa de los derechos de Rafael.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-11-23','Ana: Correo-e de Rosa Bravo, CSS-PLAS: "...os comunicamos que la incapaz, tutelada por esa Comisión, Isabel Mª Cano B., tuvo que ser trasladada al Hospital Universitario de Cáceres el pasado fin de semana, por ingesta de cuerpo extraño. En la mañana de hoy se encuentra en la Unidad de Psiquiatría del Hospital "San Pedro de Alcántara."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-11-23','Ana: Correo-e de María, TS - Autismo Sur: "Buenos días Ana, el documento referente a los ingresos de Costi, lo necesitamos antes de su ingreso.... Ya que si no nos para toda la facturación. Es un documento escrito por vosotros... Otra cosilla... me preguntan desde dirección como ya te comenté el tema de los gastos extras... el problema está en que actualmente no estamos teniendo ningún margen de beneficio... es más hemos pedido un préstamo, para poder pagar las nominas... No sé si allí tendréis un sistema de ayudas o algo para poder colaborar mientras se gestiona la PNC. La idea del dinero que daban al dulce nombre de Maria ya han dicho que no..." ·························································································································································· Respondo al correo con copia a Pedro, Jefe Secc: "Buenos días María, Siento decirte que en la CTAEX no tenemos partida presupuestaria para absolutamente nada, desde aquí se gestiona lo que tienen las personas que se tutelan, por lo que me temo que dada vuestras circunstancias, y las nuestras, sí que va a ser un problema… Pongo en copia al Jefe de Sección, para que esté al corriente, y por si lo puede poner en conocimiento del Vicepresidente de la Comisión Tutelar. Con respecto a la declaración jurada de los ingresos de Costi (escrito firmado por el Representante Legal), no se puede hacer hasta que tengamos los documentos oficiales que indiquen que efectivamente este chico no tienen prestación alguna del INSS ni PNC, o que al menos el Representante Legal esté puesto en la cuenta y las compañeras puedan corroborar que efectivamente no hay saldo ni hay domiciliado ningún ingreso. Como te comenté, los documentos están pedidos desde el primer momento, pero aún no los hemos recibido. Por nuestra parte, desde la CTAEX, tratamos de agilizar lo más posible todo, y aún más en relación a este caso dadas las circunstancias, pero hay cosas que dependen de terceros. El procedimiento habitual, es conformar primero el Inventario (para lo cuál el Juzgado nos da 60 días desde la aceptación del cargo), antes de comenzar a intervenir, y como ves estamos intentando dar respuestas en la medida de nuestras posibilidades desde el principio. Gracias por tu paciencia y comprensión. Seguimos en contacto." ······················································································································································· *Guardo en el expte. digital el contrato residencial de la F. Autismo Sur firmado por ambas partes que nos han remitodo por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-11-23','Ana: Correo-e de Toni-Futuex: "Hola Ana, a continuación pasamos a exponer la situación actualizada de Eugenia Pacheco Situación actualizada 16 y 17/11/2020: El día 16, a primera hora, se acude a visitar a Eugenia, nada más llegar a su casa exige el dinero e ir al estanco, se le dice que por un lado, el estanco todavía está cerrado y, por otro, primero hay que ir a hablar con la trabajadora social y consultar sobre su situación, hacer la entrega del dinero en presencia de esta profesional y después las gestiones que sean necesarias. Se acude a ver a la Trabajadora Social, Gema comenta que han comunicado que han encontrado una residencia que tiene plazas disponibles, en Torre de San Miguel, pero están poniendo muchas pegas por la edad, el perfil de Eugenia… por lo que se duda que acepten, aún así, el viernes 13 se envió el informe de la psiquiatra. Durante la cita con la Trabajadora Social, se habla con la tutelada sobre su comportamiento inadecuado en el pueblo, lo niega todo, establece que son los habitantes del pueblo que son mala gente, se le menciona que hasta han tenido que llamar a la guardia civil, comenta que no le dijeron nada, fue culpa de quien llamó… En presencia de Gema, se intenta hacer un nuevo trato para la entrega del resto de asignación, se le propone darle 100€ y el día 26 de noviembre, cuando acuda a la consulta de la psiquiatra, se le dan los 50€ restantes, así se asegura que llega a final de mes con dinero; se altera mucho, se pone muy nerviosa porque quiere dinero… se aprecia la ansiedad, alteración y necesidad de disponer de dinero propia de un síndrome de abstinencia. Se le dice que su dinero nadie se lo va a quitar, sólo se le propone a ayudarle pues tiene un problema con el juego, reivindica su derecho a tenerlo, a saber controlarse… Se le acaba entregando los 150€, se le dice que si en una semana se ha gastado el dinero se solicitará a la CTAEX que se reduzca la asignación y se retiré en dos mensualidades, en lugar de sacarlo todo junto; Gema, por su parte, le dice que si no cumple lo indicado, se puede llegar a retirar la ayuda del Plan Reactiva, pues está dejando ver que no precisa el dinero para artículos de primera necesidad, ya que lo echa en máquinas. Eugenia establece que también debe dinero, 20€ a la del supermercado, se acude a la tienda a hablar con la dependienta, confirma lo comunicado por la tutelada, se le pide que por favor no haga eso, pues está siendo muy difícil trabajar la gestión económica con Eugenia, con ese gesto, lejos de ayudarla la está perjudicando más… Maribi indica que la tutelada la engañó, pero no volverá a suceder, se le agradece Después de dejar a Eugenia, se comprueba que rápidamente se va al bar, pero no al que suele tomar café, pues se acude a ver si está y no se encuentra, busca otro en el que pueda jugar… A última hora de la mañana, vuelve a contactar la Trabajadora Social para comentar a Gema el incidente que se conocía de la Guardia Civil y contar que la tutelada está vendiendo pañales por las casas… se desconoce dónde los consigue. 17/11/2020 Contacta la Trabajadora Social de la localidad para comunicar que le acaban de llamar de Dependencia para poner en conocimiento que ya tiene una plaza en residencia asignada Eugenia, es el la Cervantes, en Cáceres, el ingreso se puede hacer efectivo en cuanto tenga una prueba PCR negativa. También solicitan un certificado de pensiones, se le dice que cobra una prestación por desempleo. Imaginamos que te lo habran solicitado a ti, pero por si acaso. Se contacta con Eugenia, ya se lo han comunicado, se altera mucho diciendo que hasta primeros de mes no se va porque tiene muchas cosas que hacer, además no tiene casi dinero… Se le dice, por un lado, que si no tiene dinero es porque ha vuelto a hacer mal uso, pues ayer se quedó con 120€ después de pagar la deuda a Maribi; por otro lado, se le dice que se le ha llamado para que vaya preparando las cosas, haciendo maletas, recogiendo enseres… no quiere decir que se vaya a ir mañana, pues primero se tiene que hacer la prueba y luego se organiza el traslado. Dando voces, sin atender a razones, que no se va hasta primeros, que además Pedro le va a dejar la casa a ella, que sus hijas no mandan… se intenta relajar y que escuche, se le dice que la situación actual no es la que menciona por lo que, como ya se le había dicho, debe dejar la vivienda; además, se ha pedido que fuese algo cerca de Pedro y así se le ha concedido, por lo que si por un lado se ha cumplido la palabra, lo más adecuado es que colabore y ponga de su parte… Acaba mostrando resistencia a irse antes de diciembre pero, por otro lado, acepta la situación. Se le dice que se está intentando localizar a la médica de cabecera para solicitar que le hagan la PCR, en cuanto se tenga fecha se le comunicará; la cita con la médica, vía telefónica, se consigue para el día 18, pues en el consultorio no responden al teléfono. Con la médica han existidobastantes problemas ya que no queria acceder a realizaciónde PCR.. incluso ha estado de muy malas formas con lacompañera, aunque parece que finalmente le darian cita parael proximo lunes, por lo que en dos dias, tendria queingresa en la residencia. Esta semana seguiremos encontacto intentando que la situacion sea lo mas favorablepara Eugenia, dado qeu está volviendo a jugar y en unasituaicon muy compleja, la idea es acompañarla a realizaciónde PCR y al ingreso ya me comentas como se putaría"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-11-24','Ana: Llamo a Noelia, TS Resi. Cervantes (927 00 55 75 / 22237) en relación al ingreso de Eugenia. Le facilito cierta información en relación a la curatelada (percibe Subsidio para mayores de 52 años, trayectoria desde que salio voluntariamente del CRR-CC, relación con su pareja sentimental...) y le envío por correo-e el cdo. de discapacidad y dictamen técnico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2020-11-24','Se suspende el juicio a celebrar en el Juzgado de Primera Instancia e Instrucción, nº 2, de Villanueva de la Serena (Badajoz), en el procedimiento LEV 38/2019, en el que Carmelo tiene la calidad de denunciante y que en principio iba a celebrarse el 1/12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2020-11-23','Ana: Llamada de Sandra, TS Residencia de mayores de Coria (927 508 000 - Ayto. de Coria - Ext. de la Residencia - Sandra, TS: 283), Rosario no tienen DNI, ya habló hace tiempo con alguna TS de las que ha estado anteriormente en la CTAEX. Tiene un número de Identificación de Régimen Comunitario: X-0745160-Y (Estuvo muchos años viviendo en Francia. La pensión que percibe es de allí). *Al parecer ha perdido la nacionalidad española. En su día cuando llamó a la oficina del DNI, le dijeron que debíamos promover estos trámites desde la CTAEX, por tener su tutela y que sería necesario un Certificado Literal de Nacimiento. Es natural de Guijo de Coria. Fecha de nacimiento: 28/05/36 *Está encamanda, por lo que sería necesario que acudiera el Equipo Móvil de la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2020-11-23','Ana: Llamada de Sandra, TS Residencia de mayores de Coria (927 508 000 - Ayto. de Coria - Ext. de la Residencia - Sandra, TS: 283): Rogelio está un tanto alterado, su hermano le ha comunicado algo sobre la venta de un inmueble. Pediré a los compañeros jurídicos que se pongan en contacto con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2020-11-24','Ana: Envío correo a Ángel y Miguel, Asesores Jurídicos: "...En relación a Rogelio Fernández Vega, ¿podríais poneros en contacto con la TS de la Res. Mayores de Coria? Se llama Sandra, más abajo os anoto el nº y extensión. Quiere hablar con vosotros en relación a la venta de un inmueble, ella no está al corriente de nada y un hermano de Rogelio ha acudido a visitarlo y le ha dicho que la han vendido. Ayto. de Coria: 927 508 000 - Ext. de la Residencia: 283..." ·········································································································································· Respuesta de Ángel, CTAEX: "...Efectivamente, se ha vendido. Rogelio tenía un porcentaje en esta vivienda (30%). Estamos al corriente de esta venta, de hecho en los próximos días la ratificaremos en Notaría. Ya he hablado con la TS para comunicárselo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-11-24','TERESA ME COMUNICA ANA QUE ESTA PREVISTO EL INGRESO PARA EL DIA 4 VIERNES EN LA RESIDENCIA CERVANTES DE CACERES. HABLO CON TONI LA TS DEL CENTRO DE SALUDN 924780501 PARA QUE GESTIONE LA PCR Y LE ENVIE EL RERSULTADO A ANA EN UN PLAZO NO MAYOR A 48 HORAS QUEDO PEDITE ACTIVAR EL 112 LA SEMANA QUE VIENE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2020-11-24','TERESA HABLO CON LA TS PARA SOLICITAR DE NUEVO LA INFORMACION QEU LE HE PEDIDO POR EMAIL, QUEDO PENDIENTE ME LA ENVIE. SE HA CAMBIADO LA PENSION A LA CTAEX EN CUANTO LA RECIBAMOS HAY QUE GESTIONAR TRANSFERENCIA A CUENTA PECULIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-11-23','TERESA ME LLAMA LA TS DEL CENTRO PENITENCIARIO PARA COMENTAR SOBRE COMO SE VA HA HACER EL TRASLADO, LE COMENTO QUE ESTA TODO GESTIONADO Y QUE SE PONDRAN EN CONTACTO CON ELLOS PARA ULTIMAR DETALLES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-11-24','miguel, me llega reclamación del hermano de la tutelada para saber cómo va la tramitación de la venta del inmueble. Compruebo tras hablar con Angel que no hemos sabido nada de la abogada de oficio a la cual solicitamos en mayo del 2019 nos indicara qué necesitaba para la interposición de autorización de venta. Tras hablar con la abogada me confirma que lo tiene todo y que le remita informe médico, lo cual hago vía email La llamo por teléfono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-24','Ana: Envío correo-e a Estrella, TS del CSS-Pla.: "...Por cierto, con respecto a Margarita, varias cuestiones: 1. ¿qué tal sigue? 2. ¿podrías decirme en qué unidad está y cuál es la previsión? 3. En el Hogar San Vicente de Paúl nos dicen que allí no puede volver. ¿Podríais por favor hacer la solicitud de revisión del PIA para que le concedan plaza en Centro de Discapacidad?. Lo ideal es que mientras tanto pueda permanecer en el CSS, pues de lo contrario no tendríamos donde llevarla." ······················································································································································ Respuesta de Estrella (estrella.duranc@salud-juntaex.es): "Margarita, está ingresada en la UHDAC porque en UME hemos tenido un brote de covid, así que los nuevos ingresos van a UHDAC. La previsión era hablar con vosotros, justo para lo que has propuesto tú es decir, que permanezca en UHDAC hasta que se le encuentre Centro de Discapacidad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-21','Ana: Correo-e de Pila Sánchez, Hogar San Vicente de Paúl: "Buenos días, anoche a la 1,30 h, le dieron el alta a Margarita y la trajo la ambulancia al Hogar, dejándola en el portal. El lunes me pondré el contacto con el centro sociosanitario, ya que durante el fin de semana no podemos solucionar nada. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-23','Ana: correo de Pilar, Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Buenos días, Ana, Margarita se encuentra en el Centro Sociosanitario desde el sábado a las 19,00 h, aproximadamente, ya que el sábado se levantó con las mismas ideas y tuve que volver a subirla a urgencias. Durante esta mañana, llamaré a Estrella, la Trabajadora Social, para ver qué tal se encuentra. Un saludo" ··············································································································································· Conversación telefónica con Pilar: Margarita el sábado sustrajo de la despensa un brick de vino blanco y lo ingerión enmenos de 10 minutos. Acto seguido, cuando comenzó a comer con el resto de residentes en el comedor comenzó a vomitar y tuvieron que llamar al 112. La trasladaron a urgencias, pero de madrugada le dieron el alta. La ambulancia la dejó en le portal del hogar a la 1:30 a.m. *Al día siguiente comenzó a autolesionarse, arañándose en las muñecas. Tuvieron que volver a activar el 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2020-11-24','Ana: Correo de Estrella Durán, TS del CSS-Plas.: "Buenos días, Ana Me dice la madre de Isabel, que le enviés una copia de la Sentencia de Incapacitación. Su dirección es: Francisca Blázquez Borreguero C/ Diego de Trujillo nº 5 10200.-Trujillo Cáceres Saludos" ··················································································································································· Mi respuesta: "Buenos días Estrella, Desde la CTAEX no tenemos por qué enviársela. Si no te importa, si te lo vuelve a decir, dile que puede dirigirse al Juzgado de 1ª Instancia e Instrucción nº 3 de Plasencia, donde podrá solicitarla. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-11-24','-AMALIA: Ati ingresó ayer en la UHB de Mérida . Ya he hablado con su psiquiatra ,David, le conté su trayectoria sociosanitaria y le pedí que considerase la opción de derivarlo a UME . Ati necesita un tiempo en el CSS para estabilizarse . Iremos valorando según su evolución en la Unidad y las posibilidades de ingreso .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-24','(Pedro)Llamada de José Manuel (667384817). +++Dice que antesdeayer se tomó varios transilium y que le hicieron un lavado de estómago en el hospital. Se quedó ingresado esa noche. +++Demandas: irse al centro urgentemente y dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2020-11-24','(Pedro)Envío Consentimiento Informado a Victoria (86643), T. Soc. de H. Don Benito-Villanueva. +++Para esófagogastroscopia y sedación la endoscopia digestiva. +++Tanto por correo electrónico como ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-24','(Pedro)Llamada de Isabel Álvarez, Psiquiatra de la UHB de Mérida (81621). +++Emilia se quiere marchar y no tengo argumentos clínicos para mantenerla si insiste en ello. +++Tampoco acepta ya la canalización a Málaga. +++Hablará con ella para tratar de hacerle ver lo psoitivo de esta oportunidad, pero si insistwe en el alta no podrá evitarlo.Intentará mantenerla en la Unidad durante esta semana. +++Lo pomngo en conocimiento de Soraya (U.Programas) y de Nuria (Subdiercción de Salud Mental). +++La canalización está en marcha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2020-11-24','-Alberto , Jefe Seccion Eco : Hola Toni. Varias cuestiones: a) VODAFONE: en conversaciones mantenidas entre tutelada e Iciar, María Rosa manifestó que quería dar de BAJA Vodafone y que devolviesemos ese recibo de 122,90 €, porque la habían engañado. Se procedíó a solicitar dicha devolución, pero dado que aún tenemos problemas de acceso a esa CCC, no te puedo confirmar. Nuestra intención es que, de momento, la tutelada únicamente funcione con LOWI (teléfono de su marido). b) SUPERMERCADOS: tal y como quedamos anteriormente el gasto en SUPERMERCADO no podrá superar los 60 €/semana (260 €/mes). c) BUTANO: El día que cobre la pensión su marido a finales de noviembre, se autorizará un REINTEGRO de 395,60 €. Con ese dinero deberá: Pagar la botella de BUTANO. Pagar la deuda que mantiene con la FARMACIA de ARCADIO: 71 €. Iciar se encarga de transmitirle este compromiso a la tutelada y Gloria de que lo cumpla. Resto para su libre utilización. d) Tarjeta móvil con conexión INTERNET: tened en cuenta que en cuanto la pensión tutelada pase a LIBERBANK no se va a aceptar contrato con ninguna compañía y deberá comenzar a funcionar con TARJETA PREPAGO. Creo que habría que trabajar con Maria Rosas esa cuestión. No podemos permitir acceso a internet con el problema que ella tiene con las compras compulsivas. e) FUNCIONAMIENTO: en principio el SUPERMERCADO se seguirá abonando a través de transferencia con el límite de 60 €/semana. reintegros: seguirán con el acompñamiento de Gloria pero si es cierto, que debemos hacer un presupuesto mensual que incluya: recarga móvil ropa. mascotas farmacia otros Debemos tener en cuenta que aún mantiene deudas diversas en el pueblo que habrá que ir abonando. X cierto, cualquier ocasión que tengais de hacer saber que cualquier cosa que quiera comprar la tutelada deberá abonarla ella misma en EFECTIVO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-11-24','(Pedro)Comunico a Soraya la información transmitida a Teresa desde el Psiq. Penitenciario de SEvilla: Informaron que D. Juan Carlos “…anda muy nervioso y continua con conductas disruptivas. Al centro que vaya debe tener medidas de contención…” . Queda tiempo, pero me temo que a medida que éste pase los nervios del cambio, después de diez años allí, pueden hacer que su llegada a la UHDAC sea complicada para el Centro. Si vamos teniendo nuevos datos a medida que se acerque la fecha te lo hacemos saber.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2020-11-25','-Amalia : hecha la PFHC , SE LA HE ENVIADO A LOS AUXILIARES PARA QUE LA IMPRIMAN , ACOMPAÑEN LA DOCUMENTACIÓ Y LA REGISTREN .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-11-24','miguel, la renuncia de herencia fue firmada el 23-9-2020 ante el notario de Cáceres Don Carlos del Solar Barroso (927-240577), nº de protocolo 1155, siendo ratificada hoy 24-11-20 por la Comisión Tutelar de Adultos ante el notario de Mérida Don Francisco Javier Hernández Téllez con nº de protocolo 1455.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-11-24','Ana: Correo-e de Amalia, TS CTAEX; "... Con Brahim va a ver problemas para el ingreso en ASPACE , después de hacerle ayer el PCR la entidad tiene el caso de un supuesto caso y han decidido no ingresar en 10 días . Ya te contaré , voy a ver si puedo hacer algo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2020-11-24','Ana: Correo-e de Emilia Almodóvar, TS del CSS-Plas.: "Buenos dias Ana. por recomencion de profesionales sanitarios, Antonia Ayuso Tena ha sufrido recaida sanitaria, y su movilidad y capacidad de movimento es muy muy reducida, tienen que tener los miembros inferiores en alto en posicion de flower o semi-flower, lo que su silla de rueda no se lo permite por inestable, esta mdeteriorada y es muy antigua y a dado lugar a varias caidas de la paciente. Actualmente necesitaria una silla ortopedia donde fuera posible realizar los cambios corporales en ella, pueda ser basculante y con soporte para los miembros inferiores, hemos estudiados las sillas y las mas recomendable, confortable y que ayude a la prevencion de ulceras por presion es Rea Clematics tienen un presupuesto 1.107 aproximadamente. Estoy a la espera del presupuesto" ························ Una vez recibido el presupuesto, se lo envío a Alberto, Secc. Ecca. con mi Ok a la compra, pues la necesita y según la rendición tienen dinero más que suficiente para adquirirla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2020-11-25','Enviamos a la Oficina de Liberbank, de Cáceres, documento firmado, junto con escrituras, para el rescate del saldo existente en la cuenta de los padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-24','Ana: Pedro y yo remitimos un correo electrónico a Pilar Márquez, TS del SSASB de Valencia de Alcántara y un fax a Lidia, TS, y _, MAP del C.Salud de la misma localidad, solicitando realicen visita domiciliaria conjunta y emitan informes acerca del estado de Manuela, la suficiencia o no de las atenciones que percibe, propuesta de alternativas de intervención, así como de la vivienda y si reune condiciones para permanecer en ella. **El FAX al centro de salud lo remito varias veces a lo largo de la mañana, pero el reporte da OCUPADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-23','Ana: Envío correo a Toni-Futuex, con copia a Pedro: "...En relación a Manuela Morato Picado, necesitamos que no envíes un informe firmado, de los seguimientos presenciales realizados por Gloria este año, indicando las visitas en las que José Manuel le ha permitido entrar en las vivienda y en las que no. Especificar, así mismo, el estado de habitabilidad/salubridad en que se encuentra la casa y cómo ve a Manuela, si en su opinión está bien atendida o si se aprecia que pudiera necesitar algún servicio o atención que el nieto no le pueda proporcionar. Por otra parte, os pedimos también que, en cuanto sea posible, acuda de nuevo a hacer seguimiento, coincidiendo con las horas de atención con la Auxiliar, para corroborarnos también en un informe, que, tal y como decías en el anterior correo, la auxiliar no está realizando las tareas ni de atención personal a Manuela ni del hogar (según la empresa Quini sí que entra en la vivienda…) y que sólo se encarga de hacer recados y compras en el exterior. ..." ············································································································································· Llamo al C. Salud de Valencia de Alcántara (927 58 02 95), hablo con Lidia, TS. Me indica que la MAP, es ahora la Dra. Nuria Díaz Mendoza. En relación a realizar una visita, junto con la Médica y la TS del SSASB, a Manuela, se muestra reacia. Que lo hablemos con Pilar, TS de SSASB (le indico que se le pedirá también a ella, la idea es que sea una visita conjunta y el informe también podría serlo), que por qué no lo hace la visitadora de Futuex (repondo que ella sigue haciendo visitas y que también nos remitirán un informe al respecto) y para terminar, dice que si el Jdo. necesita dicho informe que se lo pida el Jdo. No me facilita su dirección de mail, dice que enviemos la solicitud por fax (927 58 07 36).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-11-24','CORREO ELECTRONICO. Se adelanta por e-mail, a la trabajadora social del ayuntamiento, Consetimiento Informado para adenomectomía. El original se remitirá por correo ordinario (a la espera de registro del oficio).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-11-23','Ana: Llamada de Jairo, de nuevo pide que desde la CTAEX solicitemos el cambio de centro al CSS-Mérida. Dice que ha estado hablando con el Dr. Herrero, y que éste le ha dicho que no tienen inconveniente en hacer un informe si se lo pedimos desde la CTAEX. *Pasa por allí el Dr. Herrero y le pide su dirección de email: agapito.herrero@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-11-24','Ana: hablo con Miguel y Pedro, CTAEX, acerca de la petición de Jairo; si el médico considera que existen criterios clínicos para solicitar este cambio, ha de ser él quien nos lo comunique y nos envíe informe a tal fin. ·································································································································· Conversación con Emilia, TS del CSS-Plas.: -El Dr. Agapito Herrero, Psiquiatra, le dijo cuando hablaron del asunto, que él no ve criterios clínicos que justifiquen este cambio. ·············· *Emilia, por su parte, sí que ve conveninente un cambio para Jairo. No obstante, de cara al Jdo. lo que prevalecerá será el Informe de Psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-11-25','Ana: Llamo al C. Salud de Valencia de Alcántara (927 58 02 95). Me corroboran el nº de fax: 927 58 07 36. Como les digo que ayer daba ocupado todas las veces, dicen que lo intente hoy de nuevo y si no funciona, que lo remitamos a la siguiente direccion de email: beatriz.piris@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-11-25','(Pedro)Correo de Alberto, tras reunión sobre el caso: +++Reunión mantenida el 25/11/2020 x Pedro Gracia, Amália Díaz, Ángel Marín y Alberto Martín, sobre situación y posibles actuaciones en relación con el curatelado ALEJANDRO NUÑEZ BONO. Se expone lo siguiente: • Compra vivienda: la CTAEX la desestima actualmente x no considerarse que, dadas las circunstancias, sea algo positivo para el curatelado y su futuro: o La solicitud de compra proviene básicamente de su familia: madre y abuelo. No del curatelado. o Se está pendiente de las posibles actuaciones judiciales que pudieran tener consecuencias penales y patrimoniales para el curatelado. • Temporalmente y basándonos en la situación social y personal del curatelado, existente en este momento, se decide x la CTAEX mantener lo acordado con anterioridad con la familia del curatelado: o Transferencia x manutención y gastos curatelado de totalidad de la pensión a madre (666,30 €/mes). o Transferencia x Ayuda al Alquiler de 450 €/mes a madre. o Esta situación se mandendrá en tanto en cuanto se tenga un conocimiento de:  Entrada o no en prisión de Alejandro.  Cuantía sanción económica/patrimonial o Esta situación, con independencia del punto anterior, se REVISARÁ con anterioridad al día 31/01/2020. La nueva reunión se convocará por ÁREA SOCIAL, salvo que con anterioridad, se disponga de información suficiente que justifique su anticipación. • La parte JURÍDICA, se encargará de obtener toda la información posible sobre la causa penal, o de cualquier otra índole, que afecte al curatelado. • Se tiene conocimiento de que el abuelo de Alejandro, está planteándose seriamente pedir la REMOCIÓN de la curatela de la CTAEX y solicitar asumir la figura de curador. Esta circunstancia modificaría todo lo expuesto con anterioridad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-25','(Pedro)Correo de alberto tras reunión conmigo. +++Buendos días. Acabamos de revisar la CCC Pedro y yo y NO es viable pargar los 178,04 €/mes de Ayuda a Domicilio. Tiene unos gastos relacionados con Juzgado, consumos, reintegros y, sobre todo, cátering, que no permiten afrontara dicho gasto. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2020-11-25','Ana: Tras llamar a Longina, TS del SSASB de Madrigalejo, envío respuesta al correo de Icíar, CTAEX: "...En cuanto a Josefa Fernández Serrano, el año pasado que estaba yo, no recuerdo nada relativo a la paga extra y en la intranet no hay nada apuntado… Sobre si se le puede dar todo o no… pues por un lado que valore Alberto cómo está su situación económica, y por otro, he llamado a Longina, TS del SSASB, para que no dé su opinión. Se ha mostrado muy extrañada, a ella no le han dicho nada y no entiende esta petición. Cree que en años anteriores, que ella recuerde, no ha sido así. A no ser que lo necesitaran por algo en concreto, no vemos la conveniencia de darle la extra completa, como mucho una asignación extraordinaria para navidad o reyes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2020-11-24','Ana: Correo-e de Icíar, secc. ecca. CTAEX: "Me ha llamado la cuñada de Josefa Fdz Serrano, vive en Madrigalejo con su pareja, pide la extra de Navidad para Josefa, comenta que en años anteriores se le dio aunque yo no veo la autorización por ninguna parte, sabes algo de este caso? Se le podría autorizar?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-25','Ana: Tras valorarlo Pedro y Alberto, se decide que no se puede contratar el SAD con la prestación ecca. vinculada que le han concedido por la Ley de Dependencia a José Manuel, pues no puede asumir ese gasto ni aún reduciendo las horas del servicio. *Se ponge para REGISTRO DE ENTRADA la comunicación - RENUNCIA de la prestación vinculada para SAD. ······················ Remito por email Paqui Berrocal (francisca.berrocal@salud-juntaex.es)y Marisa (marialuisa.gonzalezs@salud-juntaex.es) dicha renuncia. ·········································································································································· Llamo a Adiper, empresa de SAD (924 66 75 78 – 645 99 80 48), me dicen que Marian está de baja. Hablo con su compañera Gema. Comunico la renuncia al SAD por no poder asumirlo económicamente (Habíamos firmado en mayo con esta empresa contrato con cláusula suspensiva)······················································································································································ Correo de Pilar Martín, TS ESM-CC: "Ana José Manuel Romero Mediavilla ha solicitado el cambio de psiquiatra, no sé si necesita la autorización vuestra, pero supongo que sí. Ya me dices." ··············· Se realiza consulta a Pedro y Secc. Jurídica - CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2020-11-24','Ana: Llamo al registro civil de Guijo de Coria, la persona encargada, hoy no se encuentra. A petición mía, Coral, CTAEX, solicita, por correo certificado, Certificado Literal de Nacimiento al Registro Civil de Guijo de Coria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-11-25','(Pedro)Correo de P.I. Montijo y respuesta de la CTAEx. +++Buenas tardes Amalia. Qué tal va todo? Ya se por Cristina que ha hablado contigo en estos días. Me comenta cada día el tema de la tardanza del juez, yo le he dicho que tiene que ser paciente porque estais poniendo de vuestra parte para que se agilice, pero aún así ha llamado al juzgado para pedir información. Allí le han dicho que tiene que saber que número de procedimiento es porque, al haber dos jueces, no saben a quién preguntar. Me ha vuelto a preguntar si se ha autorizado el tema de que pase las navidades con su madre, yo le he dicho que hasta que no llegue diciembre no sabríamos nada. Dijo en su momento que su madre y la pareja de esta han pasado el COVID. Como te dije en su momento, nosotros haremos lo que autoricéis desde CTAEX, pero no nos reponsabilizamos de lo que pueda pasar con ella y su madre, pues tiene que estar mínimo una semana para poder volver después al piso y, con todo el tiempo que hace que no se ven no sabemos como saldrá todo, por eso te decía que si al final pensáis que puede irse, necesitamos una autorización firmada por vuestra parte. +++RESPUESTA CTAEX: +++++Buenos días , vamos por partes : -Cristina : mi compañero el jurídico ha vuelto a llamar esta semana al juzgado y le dicen que no está resuelto por volumen de trabajo . Puedes preguntarle directamente si quieres por el Nº de procedimiento, por si ella quiere preguntar directamente ( angel.marin@salud-juntaex.es).Tf 924003190 Con respecto a la autorización de salida con la madre ,como te comenté en otro correo sobre este tema , tenéis una autorización general al respecto para todas estas salidas , la Comisión no tiene que volver a autorizarla , sólo precisa vuestra conformidad . Tendréis que valorar si es seguro por protocolo covid y conveniente la salida . Únicamente tenéis que comunicarnos la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2020-11-27','Ana: Redacto oficio, para adjuntar solicitud de revisión de grado de discapacidad firmada para enviarlo a la Asociación Vera. Pido a Coral, secc. ecca, (que está en la ofi) que lo ponga para registro de salida y solicito a Julio y Juan Pedro, que cuando llegue todo lo envíen por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-25','Ana: Correo-e de Estrella Durán, TS CSS-Plas.: "Ana, he mirado cómo está PIA Margarita. Tiene perfil de Salud Mental, el último recurso que se le pidió fue un CRR, así que debéis pedir revisión Cadex, para ver si le cambian a perfil de discapacidad porque si no, me temo que no se le puede hacer PIA para centro de discapacidad....."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-11-25','(Pedro)Entrego renuncia firmada por el Director Gerente a la plaza RAL que Dª Felisa tenía en Aprosuba 3. +++La entrego mediante nota interior a Maribel Ramos. +++Escaneada en su espediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2020-11-23','Visita de Antonio Lozano( 636472667) (Proines): la familia está preocupada porque no pueden contactar con Isabel. +++La llamo varias veces pero no coge el teléfono. +++++++++++++++++++++++Pongo en contacto con FUTUEX.Correo: +++++Hola Pedro, te escribo por el tema que acabamos de hablar, te he llamado pero estaras ocupado. He contrastado con la compañera la info reciente sobre Isabel Valadez , te paso a detallar las ultimas visitas y actualizaciones (sabemos por Catalina Miranda que el dia 16 se vieron en el banco y que tenia el cargador del móvil roto). • 14/10/20: Se realiza seguimiento presencial. Isabel con el tema del coronavirus no quiere salir mucho de casa y por el momento, se están evitando las visitas domiciliarias a no ser que sea estrictamente necesario. Se le propone visita presencial y se excusa pidiendo que la veamos el próximo mes. Pendiente: solicitar cita previa en atención primaria para pedir analítica y reactivar tarjeta sanitaria. • 10/11/2020: Se realiza llamada y no responde. • 16/11/2020: Catalina Miranda, una de las tuteladas a la que se le realiza el seguimiento, coincide los días de las retiradas de dinero en efectivo con Isabel. Se conocen y siempre conversan. Ayer, Catalina nos informa que ha visto a Isabel y le ha comentado que tiene el cargador del móvil estropeado, aprovechando con la retirada de dinero en efectivo iba a comprarse uno. Coincide con las numerosas llamadas que se le realizan a Isabel y siempre sale apagado. Por otro lado nos consta también que tiene el telefonillo de casa roto (pendiente que se lo arregle el casero) está misma semana, podemos ir a visitarla, picando en otro telefonillo para acceder a la casa, ya que teniamos pendiente visitarla ya. ++++++++++++++++++++++++Comunico a Antonio la información dada por Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-11-26','miguel, llega la aprobación judicial de la herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-11-24','miguel, llega auto dictado por jzdo nº4 Plasencia del procedimiento DPA Diliegneicas Previas Proc Abreviado 498/2019 indicando que se procede a la apertura de juicio oral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-11-26','miguel, llegó con fecha de entrada en registro del Sepad del tutelado con un formulario relleno solicitando abogado de oficio con la finalidad no se sabe muy bien, un complot. Lo veo con Pedro y decidimos archivarlo sin más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2020-11-25','Ana: Correo de Icíar, secc. ecca.: "...nos aparece en su cuenta de Caixabank que tiene una retención de pensiones que no sabemos a qué hace referencia, la retención asciende hasta 24.000 €, una barbaridad, de hecho no se pueden hacer transferencias porque dice que no tiene saldo, me dice Alberto que te comente si pudieras tú tener idea y puedes averiguar algo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2020-11-26','Ana: Llamo a Control de Pensiones del INSS (927 62 00 65 / 927 62 00 49); no les consta ninguna retención de ninguna de las 2 pensiones que percibe (Viudedad y Jubilación por incapacidad absoluta). No hay movimientos en el expte. desde 2013. ····················· Se lo comunico a Icíar y Alberto, secc. ecca., por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2020-11-26','Ana: Pongo para la firma del Director Gerente la solicitud de Revisión del grado de discapacidad remitida por Cristina Castro, Asoc. Vera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2020-11-26','Ana: Pongo para la firma del Director Gerente la solicitud de Revisión del grado de discapacidad remitida por Cristina Castro, Asoc. Vera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2020-11-26','Ana: Correo-e de Cristina Castro, Ed. Soc. Asoc. Vera: "...Aprovecho para informar sobre Dña. Mª del Carmen Mellado Guardabrazos, el día 19 de noviembre acudió a su consulta de revisión de cirugía dónde la han diagnosticado de nuevo la misma operación que se le realizó a principios del 2019 (Extirpación de lipoma cervical). Para poder realizar la operación se necesita autorización para incluirla en la lista de espera quirúrgica y Consentimiento informado (éstos los he enviado por correo postal para proceder a su firma y remisión)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-11-25','Ana: Recibo llamada de Toni, Residencia Adhiser, pone el manos libre, hablamos ella, Aitor y yo. Aitor expresa muestra muy contento en el nuevo centro. A continuación *pide el poder hacerse un tatuaje. *Le digo que es algo que tenemos que valorar en el equipo, le daremos respuesta una vez lo hayamos hablado.','2');
