insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-11-26','miguel, Mely me vuelve a preguntar por el estado del expte. Llamo al Juzgado nº2 de Zafra para preguntar por el procedimiento de solicitud de aprobación de herencia y autorización de venta, proc. X15 nº129/20 y me comentan al igual que anteriormente que todavía el Colegio de Abogados de Badajoz no les ha remitido contestación de abogado y procurador de oficio. Le comento que desde Agosto este tutelado se encuentra residiendo en Coria y que está conociendo el nº2 de Coria la remoción del cargo de tutor, a efectos por si tienen que remitir el expte a Coria y desde allí soliciten abogado y procurador de oficio al Colegio de Cáceres. Se toma nota desde el juzgado nº2 de Zafra de mi nº de tlfno e email porque lo va a consultar y me diría. ******************************************************* Llamo a Mely y la explico la situación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-11-26','Ana: comento con Pedro, Jefe de Secc., la petición de Aitor de hacerse un tatuaje. ··············· Envío correo a Toni - Adiser (adiser@castuera.es): "Buenos días Toni, He tenido ocasión de hablar con Pedro, Jefe de Secc, en relación a la petición de Aitor Moreno Felipe, de hacerse un tatuaje. Desde la CTAEX no aceptamos estas peticiones dados los riesgos para la salud que pueden entrañar el hacérselo. Hemos consultado algunas fuentes y pasamos a enumerar algunos de ellos: • Infecciones de la piel. • Enfermedades de transmisión sanguínea. Si el equipo utilizado está contaminado, puedes contraer el tétanos, la hepatitis B y la hepatitis C. • Reacciones alérgicas. El tatuaje tiene colorantes —especialmente el rojo, verde, amarillo y tintes azules— éstos pueden causar reacciones alérgicas, ya sea inmediatamente después de hacerte el tatuaje o años más tarde. • Cicatrización, lo que provoca deformidad de la piel. • Complicaciones en resonancias magnéticas. En casos raros se ha sabido que el maquillaje permanente o tinta causan hinchazón o ardor durante los estudios de resonancia magnética. Por tanto, agradeceríamos que explicaseis a Aitor, que tras haberlo valorado y debiendo velar por su salud y bienestar, no autorizamos dicha petición. Quizá podría valorar alguna otra alternativa que pueda gustarle, que no implique dichos riesgos. Ante cualquier cuestión no dudéis en contactar. Gracias por la implicación y un saludo. PD: Aprovecho para remitir adjunta una circular que se envió en su día todos los centros de la Comunidad Autónoma en que residen personas tuteladas por la CTAEX, para que también la tengáis, pues contiene una serie de indicaciones que os puede aclarar algunas dudas en cuanto al funcionamiento. La verdad es que no he caído en enviárosla antes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-11-26','Ana: Correo-e de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, ya hemos contactado con la UDAC y con Aprosuba 3 de Badajoz, y tenemos un poco de información sobre Felisa. Estamos a la espera de recibir los informes por escrito que nos aclararán más dudas. Seguramente ingresa el día 1 de Diciembre. Creo que mi compañera ya lo ha hablado con la UDAC, para que informen a Felisa del procedimiento de PCR y posterior asilamiento. La idea es que termine el aislamiento al finalizar el puente y, el equipo técnico pueda conocerla y evaluar de manera que antes del periodo navideño quede preparado su programa de intervención. ¿Me puedes pasar el informe social y personal que tenías? Desde la UDAC también nos mandarán informe. De este modo tendremos una base para poder informar al personal que le atienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-26','(Pedro)Conversación con Isabel Álvarez, Psiquiatra de la UHB de Mérida: +++Le da el alta voluntaria a fecha de hoy, 26 de noviembre3 de 2020, al no existir además criterio clínico para mantener el ingreso. +++Se envía fax al Juzgado de Primera Instancia e Instrucción nº 4 de Mérida con la información referida alta voluntaria y la imposibilidad de llevar a cabo la canalización a la Unidad Específica para la atención del Trastorno Límite de la Personalidad de Málaga dado que la dedcisión de Dª Emilia ha cambiado y no quiere ya marcharse a dicha Unidad. +++++++++++++++++++++++++(Pedro)Conversación con Nuria (Subdirección de Salud Mental): +++En contacto con la Unidad de TLP de Málaga, les dicen que en estos moentos no se puede hacer la canalización porque no hay plazas, debiendo quedar en lista de espera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-11-26','Ana: Recibimos informe médico y C.I. para la cirugía dermatológica con anestesia local. Recabo la firma del D.Gerente, escaneo el CI y lo adelanto por mail a Paula, TO del CRR-Plas. y lo envío por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='NOGALES'and apellido2='MATADOR'),'2020-11-26','Buenos días, Teresa. Te reenvío el correo de Esperanza, del ESM de Mérida, para que estés al tanto del caso y el lunes hablemos sobre él. En la intranet no hay nada recogido tras el alta de la UHB y tampoco en el expediente. Buen día. De: ESPERANZA GALLEGO GARCIA >esperanza.gallego@salud-juntaex.es> Enviado el: jueves, 26 de noviembre de 2020 9:00 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: Manuel Nogales Matador Buenos días antes la imposibilidad de contactar con vosotros me pongo en contacto por esta via al ser derivado este paciente en nuestro equipo la coordinadora del mismo me ha derivado al paciente para que os solicite información sobre el mismo y actuaciones que se hayan realizado con el a la salida de la UHB para cuando se le dé cita tengamos conocimiento sobre este paciente os quedaríamos muy agradecido si esa información nos la hicierais llegar desde esta vía de todas formas a lo largo de la mañana seguiré intentando contactar con vosotros por vía telefónica . muchas gracias un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-11-12','-Amalia : Adjunto documento, correspondiente a nota interior de 25/11/2020 de renuncia de plaza en Aprosuba 3 de Da. Felisa Bruno Saavedra. _ Felisa ha cambiado de pérfil de RAL a RAE , le han dado plaza en ASINDI . Ana se encargará del traslado.','2');
