insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-11-26','(Pedro)Llamada de D. Alberto(se identifica como hijo de D. José)(619614739). +++Comenta que su padre tiene un fondo como bastante dinero y quiere saber si la residencia podría participar de ese fondo para cubnrir las necesidades de su padre, que en ocasiones le han reclamado a él. +++Se le contesta que cualquier necesidad que pueda tener su padre la residencia la comunicará a la Comisión Tutelar para cubrir la misma en la medida de sus posibilidades.','2');
