insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2020-11-25','Ana; Correo-e de Alberto, Jefe secc. ecca., en relación a la compra de la silla de ruedas: "Hola Ana. Ya se ha dado el visto bueno a este presupuesto. Iciar se está encargando del pago del mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2020-11-27','Ana: Redacto oficio, para adjuntar solicitud de revisión de grado de discapacidad firmada para enviarlo a la Asociación Vera. Pido a Coral, secc. ecca, (que está en la ofi) que lo ponga para registro de salida y solicito a Julio y Juan Pedro, que cuando llegue todo lo envíen por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-26','Ana: Correo-e de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. En reunión de equipo, hemos acordado poner en vuestro conocimiento que, en el Informe Médico de ingreso en la unidad de agudos del día 22 de noviembre, se pone de manifiesto que tanto las responsables del Piso Tutelado "San Vicente de Paúl", como la paciente se niegan al ingreso de nuevo, en dicho piso, con lo que cuando se normalice la situación hospitalaria en este centro socio-sanitario debido a la pandemia y si la paciente sigue estable, se procederá a su traslado a la Unidad de Larga Estancia de este centro, que fue de donde partió cuando se fue al citado Piso. Lo que comunicamos con objeto de que se baraje la posibilidad de solicitar otra plaza en un entorno más abierto a la Comunidad. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2020-11-27','(Alberto/Pedro). Visita domiciliaria a Isabel para comprobar su situación, dado que hace días que no se puede contactar con ella.Acomopañan D. Atilano (propietario del piso) y dos Policías Locales. +++Ayer, visita de Futuex: no pudieron entrar ni al portal, porque desde ningún timbre les habrían. +++D. Atilano envió hace 2-3 dái al Seguro para unos arreglos en la cocina y tampoco pudieron entrar. +++Desde Comisión hemos llamado varias veces a lol largo de la semana y dejado mensajes en el contestador...sin respuesta y hemos comprobado que el pasado 16 de noviembre sacó el dinero del banco. VISITA: nos abre Isabel a la primera, sin insistir, sorprendida por la visita.LA ENCONTRAMOS MUCHO MEJOR QUE LA ÚLTIMA VEZ QUE HABLAMOS CON ELLA EN LA COMISIÓN, TANTO FÍSICA COMO ANÍMICAMENTE: sonriente, diálogo tranquilo, no demandante, nos invita a pasar. la casa está en condicones aceptables de limpieza, pero algo desordenada. +++++MOTIVO DE LA INCOMUNICACIÓN: tiene que comprar una TARJETA NUEVA DE MÓVIL porque se le rompió la anterior. Alberto le dará un extra para que la semana que viene la compre. +++++Pendiente de programar visita de Sonia para la semana que viene: quedamos con Isabel en que será el martes a las 11:30 si Sonia puede. Avisada Sonia nos dice que el martes no puede, nos confrimará si el lunes. +++++Un vecino, abogado, se ofrece para ayudar a Isabel si en alguna ocasión le hace fala algo. +++++D. Atilano enviará nuevamente al Seguro y arreglarán el portero automático.','2');
