insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-27','Transcribo correo electrónico enviado a área social y económica: "Buenos días, Con respecto a este caso, Ana me facilitó el teléfono del sobrino (Nacho). Tras hablar con él, me indicó que dispone de mucha documentación y quedamos en que nos la remitiría por correo ordinario. Se lo pedí también por correo electrónico varias veces, el último el 6/11. Acabo de hablar con él por teléfono ahora mismo y me dice que casi tiene toda la documentación fotocopiada, pero que como lo hace en el trabajo y al ser mucha, no le ha dado tiempo a enviárnosla. Cree que la semana próxima nos la remitirá. Una vez que recibamos esa documentación, tendremos información para poder solicitar la modificación de medidas en cuanto a la pensión de alimentos de sus hijos, uno fallecido y otro que al parecer ya trabaja. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-27','Ana: Respuesta al corro de Estrella de ayer: "Hola Estrella, Ok, gracias por la información. Decirte que tras hablar con Pedro, a quién pongo en copia, hemos decidido esperar a ver cómo evoluciona Margarita antes de solicitar nueva valoración al CADEX y pedir un recurso concreto. Agradeceríamos por ello que nos mantuvieseis informados al respecto. Por cierto, antes de las gestiones, necesitaríamos nos hicierais llegar los informes oportunos, lo iríamos viendo. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-27','Ana: Llamo a Pilar Cerrillo, TS de la Res. (618 90 85 06): la semana que viene me enviará tanto el informe médico como el informes social para solicitud de plaza residencial por emergencia social vía Decreto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2020-11-27','Ana: Envío correo-e a Eloy Piélago, TS del SSB-Madroñera (ssb079@gmail.com): "Buenos días Eloy, En relación a D. Rafael Casares García, cuya Administración Provisional de Bienes ostenta la Comisión Tutelar de Adultos de la Junta de Extremadura, mediante Auto 30/2020, de 18 de mayo de 2020, ¿serías tan amable de informarnos acerca de cómo está la situación y de si D. Rafael permanece en su domicilio o ha ingresado ya en un centro y en este caso en cuál? Necesitamos saber con quién hemos de coordinarnos para ejercer el cargo aceptado de forma adecuada. Gracias por tu colaboración. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-11-27','Ana: Llamada de Emi (722 432 418), ha dormido hoy en un hostal en Mérida que dice qe ha pagado su novio. De aquí quierien ir a Cáceres, al banco a pedir un duplicado de la cartilla, pues según dicen, se la robaron y luego ya irán para Don Benito. La semana que viene su novio irá a la recogida de aceitunas a Jaen, ella se quedará en el piso en Don Benito. Expresa que está muy bien con él y que cuando le dijo lo contrario a Pedro es porque ella estaba malita, pero tras el ingreso está muy bien...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2020-11-25','Ana: Pedro, Jefe de Secc., me reenvía este correo de Marisa, T.O. EVD-CC (marialuisa.gonzalezs@salud-juntaex.es): "Buenos días Soy Mª Luisa González, técnico del equipo de valoración del equipo de Cáceres. He valorado a DON AGUSTÍN CASTAÑO TORNAVACA, tutelado por la Junta de Extremadura. Se encuentra ingresado en un centro de salud mental, CRR de Cáceres, y la idea es solicitar, por edad y grado de dependencia, residencia pública de mayores. Necesito hablar con el/la técnico/a que lleve su expediente para seleccionar los centros y para enviarles la documentación afirmar. Saludos Mª Luisa González Sánchez Terapeuta Ocupacional SEPAD. Gerencia Territorial de Cáceres. Ext. 22047"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2020-11-27','Ana: Llamo a Miguel Ángel Ramírez, Director CRR-CC: Consutlará con la psicóloga, Cristina, qué centros sería más conveniente pedir para Agustín, para tener en cuenta sus preferencias, necesidades, etc. ········ En función de su respuesta contestaré a Marisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-26','Ana: Correo de Toni, Futuex: "Buenas tardes, a continuaicon adjuntamos nota de Jose Manuel Romero, con informe de urgencias y presupuestos para ropa y la del podólogo que cada dia le van creciendo más uñas...( él dice que lo ha hablado con Pedro y le ha dicho que se aprobarían..).pero eso no sabemos si es o no cierto, ya sabemos que juega con la información.. Detallamos a continuacion la secuencia de estos ultimos dias José Manuel Romero Mediavilla 23/11/2020 A primera hora de la mañana se recibe llamad de José Luis, hermano del tutelado que informa que José Manuel, está en observación de urgencias del hospital San pedro de alcántara desde el domingo (22/11/2020), a la espera de ser ingresado o no en planta de psiquiatría, según cuenta José Luis, el motivo del ingreso fue la ingesta masiva de medicación extra y fue llevado al hospital por los servicios de emergencia. Con posterioridad, se recibe llamada del tutelado y explica que está en urgencias y que ha pasado allí la noche en observación con contención física, el tono de voz del tutelado es bastante alto, mucho más teniendo en cuenta que se encuentra en un centro hospitalario, gritando explica a la educadora “me tienen atado y sin comer” y no me dejan irme, se mantiene conversación con él y se realiza contención para que siga los consejo e instrucciones de los profesionales que le está atendiendo, explica que no quiere que lo ingresen y exige que se le “busque con centro con urgencia” se le recuerda nuevamente el protocolo de acceso al centro y porque no se le puede ayudar en ese aspecto.Pasadas unas horas se recibe llamada el tutelado explicando que ya está en casa porque le han dado el alta, se le nota bastante más tranquilo y se le pregunta el motivo del ingreso, explica que se tomó 40 comp. De tranxilium, pero en el informa de alta (que facilita el martes 24) se refleja por el equipo médico que no se encontraron evidencias de esta ingesta en el lavado gástrico que se le realizó a su llegada a urgencias, por lo que se evidencia que es una llamada más de atención. 24/11/2020 Se realiza vivista de seguimiento en las intermediaciones de su domicilio, en dicha visita facilita el informe de urgencias del día anterior (se adjunta copia), y comenta que se le ha cambiado la pauta de medicación psiquiátrica, aporta también presupuesto para la compra de ropa de invierno y solicita nuevamente que se le apruebe le presupuesto para acudir al podólogo para que le corten las uñas porque el no se llega y las tiene tan largas que hasta ha roto las zapatillas que se compró a principios de verano, se adjuntan dichos presupuesto a esta nota. Expresa que no va a acudir a la colonoscopia de hecho le han llamado para confirmar la cita y la ha anulado por lo que aunque cambiara de opinión ya no podría ir al haber cancelado la cita, se intenta motivarlo para que acuda durante todo este tiempo estaba inquieto por la espera y ahora que tiene la cita le ha entrado miedo, recibirá una nueva citación. Por otro lado exige que e trámite su ingreso en centro residencial petición en la que lleva insistiendo desde su salida de prisión en noviembre del pasado 2019,para rebajar la frustración que le provoca esta y otras situaciones se le transmite que debe tener paciencia dado que las plazas en los centros son limitadas y con la crisis sanitaria todo se ha ralentizado y más aún los ingresos en centro, también se le recuerda que debe estar estable para que le concedan plaza en CRR (dato que ya le había proporcionado la TS de salud mental y su psiquiatra) y que para ello debe hacer un esfuerzo y seguir las pautas médicas con respecto a la toma correcta de la medicación, se le explica no obstante que las plazas residenciales no son competencia de la comision, ni de la educadora." *Reenviré los presupuestos a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-11-30','(Pedro)Se guarda en su carpeta electrónica el correo de Toni con el Informe Médico y presupuesto de podología. ··························································································································································································································································· Ana: Correo de Ángel, Asesor Jurídico - CTAEX: "Buenos días, Revisada la sentencia de incapacitación de José Manuel Romero Mediavilla, os comento. Por un lado se le incapacita PARCIALMENTE, debiendo ser ASISTIDO, para el mantenimiento de su saludo, cuidado de sí mismo y prevención de enfermedades (en cuanto a aspectos que tienen que ver con la salud). De haberse resuelto así, podría solicitarlo y nosotros tendríamos que firmar con él. Sin embargo, en el fallo, nombran TUTOR a la CTAEX, más propio de incapacitados totalmente, como sabéis, que es lo que aceptamos y estamos desempeñando. En cualquier caso, él no puede solicitar por sí mismo cambios de profesionales que afecten en su salud, cuidado de sí mismo o prevención de enfermedades, como puede ser este caso. Por lo tanto, deberemos ser nosotros quienes lo solicitemos, si lo consideramos oportuno. Un saludo."','2');
