insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2020-11-26','miguel, remito a la embajaa de Argentina en Madrid solicitud de emisión de nuevo pasaporte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-11-30','(Pedro)Ana me reenvía dos correos de Futuex de3l pasado 26 de noviembre. +++En uno remite Informe de Futuex. +++En el otro fotografías de la vivienda y recibos impàgados de luz de la casa sita en la C/. Caballero Virgen 7, de Guadalupe. Se lo paso a Alberto. +++Guardo ambos correos en su carpeta electrónica, dentro de la carpeta de Futuex. +++INTERVENCIONES: ¿limpieza de la casa?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-11-30','TERESA Buenos días Teresa, ya hemos hablado con el marido de la cocinera que trabaja en Ibercaja, nos comenta que no hay problema, que también tiene a otros Tutelados, por lo que hacemos lo que quedamos le remites el fax a la sucursal de Fuenlabrada de los Montes, el trae el recibo se lo firma Elena y le entrega el dinero. Ese problema está resuelto, estoy viendo con Susana lo de la tarjeta del móvil para también solucionarlo. Para que tú tengas conocimiento ayer por la tarde llamaron del juzgado de Zafra, quiere la fiscal hacer una videoconferencia el viernes, hoy haremos la prueba con el juzgado para ver si funciona con nuestra Tablet.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO MANUEL'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2020-11-23','TERESA ENVIO BAJA PLAZA FCO','2');
