insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-11-30','(Iciar)Correo del Habilitado. +++Después de hablar con el habilitado de Mateo Ruano, me envía el cdo del cobro de la pensión, y, como indica, el aumento del importe de la pensión se debe a que deja de pagar el IRPF por su grado de minusvalía. Me apunta así mismo que el hermano, antiguo tutor, estaba al tanto de que Mateo estaba pasando la pensión al hijo fallecido pero que no hizo nada pues sería el mismo quien se quedaba con el dinero. +++Guardo certificado en carpeta electrónica.','2');
