insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-11-30','miguel, llega requerimiento del Jzdo de lo Penal nº2 Cáceres en relación a la ejecutoria 16/15 (Procedimiento abreviado 278/2014)para que se informe del porque no se le acompaña a las visitas médicas. Pedro y yo vemos que ya se les contestó de estos términos en 2018. Pedro hablará con Futuex para nos envíe un nuevo informe para sumarlo al anterior y remitirlo al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-11-30','TERESA RECIBO PETICION DE INFORME DE LA SITUACION DE BEA DESDE LA SECCION DE APOYOO Y RECURSOS A LA INFANCIA Y FAMILIA. SOLICITIO DICHO INFORME A PLENA INCLUSION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-11-30','miguel, hago videollamada para el juicio al que estabamos citados con el jzdo de Coria nº2 en relación a la división de Herencia 72/2018 de los padres. Se suspende la vista ya que han incorporado certificado del saldo de la cuenta de liberbank y además el día antes a esta citación han solicitado se incorporen al resparto más bienes y deudas. El juzgado dará nos dará traslado de dicha documentación al resto de las partes y nos darán un período de alegaciones. Nos vuelve a citar el 8-2-20 a 10:30h para ver si hay o no acuerdo y caso negativo para nombrar un contador partidor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-11-30','-Amalia : Soy Fátima Agudo, educadora de Nerea Da Costa Lorenzo. El motivo de este correo es para informarla de que Nerea realizó finalmente la visita con su hermana el pasado sábado 21, sin ningún problema. Por otro lado, se ha puesto en contacto una antigua educadora de Nerea, del CAM San Juan Bautista, Rocío. Ella ha mantenido contacto, vía telefónica, con la menor. Así que solicita pasear, o pasar con Nerea alguna tarde. Queríamos saber si sería posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-11-30','Pedro solicita a Toni de Futuex informe social: "Buenas tardes, Toni. Hemos recibido del Juzgado de lo Penal nº 2 de Cáceres exhorto por el cual debemos informar del motivo por el que D. Jesús no acude acompañado por su curador a las consultas del Equipo de Salud Mental, tal como se recoge en el Informe del ESM de 16 de octubre de 2020, en el que se pide al Juzgado lo siguiente: “El juzgado debe ordenar que el curador acompañe al paciente a consultas. EL PACIENTE DEBE VENIR ACOMPAÑADO. UNA PERSONA DEBE RESPONSABILIZARSE DE QUE ACUDE A PONERSE EL INYECTABLE.” La Fiscalía indica que se de traslado del mismo a la Comisión para que informe al respecto. Ya se remitió un informe a dicho Juzgado por parte de la Comisión Tutelar, en base a vuestros Informes, de febrero de 2019, en el que se hacía constar la negativa de D. Jesús no solamente a ser acompañado a consulta, sino a cualquier tipo de intervención con él por parte de la Comisión Tutelar, basándose en aquel momento en que solamente tenía una curatela económica. Sin embargo, en el fallo de la sentencia se indica también la curatela para “el control de la medicación.” Por favor, enviadnos un Informe actualizado en el que se hagan constar los cambios que se hayan podido producir desde entonces (si los ha habido) en cuanto a la actitud de D. Jesús para aceptar dicho acompañamiento y cualquier otra intervención que se le proponga. Indicad también las ocasiones en las que ha aceptado dicho acompañamiento en este tiempo (si las ha habido). Ya en vuestro anterior Informe indicabais que solamente las había aceptado en dos ocasiones (4 de julio y 4 de diciembre de 2017). Con esta información, más la ya remitida al Juzgado, elaboraremos una nueva contestación al requerimiento del Juzgado".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2020-11-30','-Amalia : pregunto en pensiones Chema , por el cambio de Nº cuenta en la pensión. No tienen nada , va a intentar localizar el documento . Si no tendremos que volver a reenviarlo a la D. Provincial del InSS de Sevilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2020-11-30','miguel, contestación al email recibido por Amalia confome le remite la trabajadora social con respecto a la inmobilización del vehículo y la reclamación por impago del alquiler: Hola sigue sin quedar claro si quiere o no baja definitiva del vehículo. Si fuese así habría que inmovilizarlo en algún sitio (no la calle) con el coste que conlleva. En mi opinión o se vende o al desguace. En cuanto al alquiler habría que ver cuánto dinero le debe a fecha de hoy el inquilino y si ha abonado o no algo. En caso contrario y tras haber transcurrido el plazo establecido por ley para el levantamiento de la acción de desahucio, podríamos ponerlo en manos de un abogado de pago y comenzar con los trámites de requerimiento de deuda y posterior desahucio, para el caso que no abonase los importes debidos. Ya me decís de ambas cuestiones. Necesitaríamos el burofax original, que si no recuerdo mal lo puso ella. Buenos días , tras la petición de Juana de documentación necesaria para proceder a la baja de su coche , solicité a FUTUEX una visita concertada para hacer averiguaciones al respecto. Os envio la documentación que han podido conseguir . Podemos averiguar cómo va el expediente de su tema de alquiler ?? Un saludo Antonia María Ramirez >areasocial3@futuex.es Se envía adjunto, en relación a la recogida de documentación e información del vehículo de Carmen leal Benito, esta nota informativa de dicha visita presencial. Enviamos una copia del seguro donde se refleja los datos del vehículo, el resto no sabe ella dónde está, puede que dentro de dicho vehículo, que se encuentra en el garaje al que hace años no accede, como ya sabemos. En otros momentos desea dar de baja definitivamente al vehículo, pero no entregarlo al desaguace, quizás por su negativa constante a entrar en el garaje o aproximarse a su vivienda alquilada. Se le ha explicado que, desde este equipo de apoyo social de Badajoz, le podemos acompañar al garaje y a las gestiones precisas para dar de baja a dicho vehículo y su posterior entrega al desguace, solucionando así, estos puntos que Ella misma ha demandado en otras ocasiones. Pero su respuesta es negarse totalmente a ello: No quiere acercarse allí y si lo hacemos se le puede obligar a que se traiga algunos muebles que también guarda. Que le harían falta, ya que carece de mobiliario en su casa, que no reúne condiciones óptimas de habitabilidad. Consideramos que, conocer en qué situación ha quedado la reclamación realizada a los inquilinos de dicha vivienda (posible impago y nula relación con Carmen), donde se encuentra el garaje, con el vehículo y otros objetos de valor, pudiera facilitar el posible acceso, bien por este equipo de apoyo social o acompañando a la propia tutelada o incluso si fuera necesario la ayuda de la policía local para poder acceder. Siendo una demanda constante de Carmen, que, al no tener información, dificulta aún más las posibles gestiones. Cualquier cosa al respecto me dices, y vemos como se puede abordar el tema','2');
