insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='FAJARDO'and apellido2='ABRIL'),'2020-12-02','- De: Maria Redondo >mredondo@puentereal.es> Enviado el: lunes, 30 de noviembre de 2020 16:19 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: DOLORES FAJARDO ABRIL Buenas tardes: Esta mañana estuve hablando con su compañera Itziar, en esta semana les haré llegar la documentación solicitada, pero me pongo en contacto con ustedes porque Fernando Sosa, la persona que se ha estado haciendo cargo de Dolores hasta el momento, y quien me consta que ya se ha puesto en contacto con ustedes, se ha puesto en contacto conmigo porque quiere que le facilite una copia de la sentencia. Como la tutela de esta señora es vuestra, entiendo que es una decisión que no me compete. Yo no le he entregado obviamente esta copia, hasta no tener vuestra respuesta al respecto. Muchas gracias Un cordial saludo, María Redondo Responsable Residencia de Mayores Puente Real I','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='FAJARDO'and apellido2='ABRIL'),'2020-12-02','-Amalia : vuelve a llamar Fernando Sosa, 657546107, dice ser el heredero de Lola , el que la ha cuidado y cuida de los perros . Quiere tener acceso a la pensión y hablar del tema de la casa , dice que tiene que heredarla él . Le he explicado la situación actual , le pido que guarde facturas de pienso de los perros y se le abonará. Cuando esté cuadrado el caso hablaremos con él . NO sé si el ingreso en centro residencial es puntual o permanente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-12-02','miguel, llega auto estima la retirada del carnet de conducir','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-12-02','miguel, recibido el siguiente email del centro ASIDER HORIZONTE, de su trabajadora social Antonia Soriano Martin: BUENOS DÍAS ME PONGO EN CONTACTO CON USTEDES PARA SOLICITAR LA PARTICIPACION DE AITOR MORENO FELIPE EN EL VIDEO QUE ESTAMOS GRABANDO PARA CELEBRAR EL DÍA 3 DE DICIEMBRE. ESTE CORREO ES ALGO PRECIPITADO PERO HA SIDO AITOR EL QUE ESTA MAÑANA HA SOLICITADO PARTICPAR. UN SALUDO ********************************************************** La contesto: Buenos días, la autorización a firmar por el representante de la Comisión Tutelar de Adultos debe remitirla siempre el centro. Aara poder participar en actos propios del centro deben concurrir una serie de requisitos: -Se trate positivo para la inserción social del tutelado, lo cual debe indicarse en dicha autorización (es positivo para él, por tales o cuales motivos) -Debe recoger dicha autorización que en todo momento se cumplirá con la ley de protección de datos y con la Ley Orgánica de Derecho al Honor, intimidad y propia imagen. Una vez nos la remitan nosotros tras su firma se la remitiremos como se hace con todas las peticiones al Ministerio Fiscal por si entiende que debe prohibirla o no. De entrada tal y como les indicamos siempre, no pueden facilitarse en dichas publicaciones datos personales de los tutelados, ni tampoco pueden publicarse en redes sociales o medios de comunicación externos al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2020-12-02','TERESA RENDICION ANUAL sigue viviendo solo en su localidad natal (Fuenlabrada de los Montes). Carmelo vive sólo, Su sobrino le visita regularmente. Se ha propuesto varias veces el servicio de ayuda a domicilio para ayudarle a las tareas domésticas, pero dice apañarse bien el solo. Se desenvuelve correctamente TIENE UN SALDO DE 4000 EUROS PERCIBE PENSION INCAPACIDA ABS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-12-02','TERESA RENDICION ANUAL JOSE ANTONIO VIVE CON SU MADRE DE 86, LAS RELAICONES SON COMPLICADAS. LA MADRE ERA LA QUE SE ENCARGA DE LA LIMPIEZA Y DE LA COMIDA PERO DEBIDO A SU ELEVADA EDAD ESTA TODO DESCUIDADO SE NIEGAN A RECIBIR NINGUN TIPO DE AYUDA LA CONVIVENCIA CADA ES PEOR INCLUSIO TENIENDO QUE IR LA POLICIA AL DOMICILIO ESTA PENDIENTE LA INCAPACITACION DE LA MADRE SALDO DE 22000 EUROS PERCIBE PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-12-03','TERESA ENVIO INFORME SOCIAL A LA SECCION DE APOYO Y RECURSOS PARA LA INFANCIA A PETICION DE ELLOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-12-03','CORREO Se pone al correo autorización gral. de salidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-12-03','TERESA HABBLO CON MARIBEL TS DE LA UME 924 388081. LE DOY EL NUMERO DE CUENTA PARA QUE PUEDAN SACAR DINERO PARA TABACO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2020-12-03','Se ponen en contacto con nosotros un Abogado, Javier Fierro, fierro7811@hotmail.com, en relación con una venta de un inmueble, que formaba parte de la herencia de la madre de Concepción, Josefa Vázquez Domínguez, fallecida el 2/11/2012. Nombró herederos a sus 8 hijos, más dos nietos. En la herencia dejó un inmueble, sito en C/. Concepción, 6, 4 de catastro, en Alajar (Huelva), que quieren vender por 19.000. De hecho han formalizado un contrato de arras, en el que han entregado la parte compradora 17.500. La venta ser haría en la Notaría de José Antonio Rey Jiménez (Notario de Sevilla, 955560560, en la NOtaría no saben nada de esta operación). Se presentó el Impuesto de Sucesiones el 30/4/13. También había una cuenta de ahorro con un saldo de 1.495,70 euros y el 3% del ajuar doméstico valorado en 1.424,87 euros. Pregunto al Abogado si aceptaron la herencia, antes de estar incapacitada Concepción (nosotros aceptamos el cargo el 5/8/13). De no ser así, habría que pedir autorización judicial para aceptar la herencia y para vender. También le pido que nos envíe certificado telemático del catastro, donde aparezca el titular del inmueble, valor catastral, etc. La vivienda no está inscrita en el RP. El Abogado me envía certificado de inexistencia de deudas de la causante y tasación de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2020-12-01','TERESA ME LLAMA LA TS ANOTONIA DEL SSB DE ALMENDRALEJO 682 20 90 60 PARA COMENTARME QUE BARTOLOME HA IDO PORQEU NO PUEDE SACASR DINERO DEL BANCO LE EXPLICO QUE ESTMOS EN PROCESO DE INVENTARIO ME FACILITA EL TELEFONO DE JOSE MANUEL TRABAJADOR DE CAJA ALMENDRALEJO 924 67 75 26 EL CUAL ESTA CON EL BASTANTEO AUNO NO ESTA INCLUIDO EN LA CUENTA JOSE VICENTE VAMOS A HACER UNA AUTORIZACION PARA QUE SAQUE UN EXTRA HASTA QUE PODAMOS TRABAJAR CON LA CUENTA SE LE VA A ANULAR LA TARJETA DE CREDITO MANDO A FUTUEX PARA QUE HABLE CON EL Y LE EXPLIQUE LA SITUACION YA QUE EL COMENTA NO SABER NADA AL RESPECTO DE SU INCAPACITACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='MARTIN'and apellido2='GALLEGO'),'2020-12-01','TERESA RECIBIMOS LLAMADA DE UNA VECINA QUE LINDA CON UNA PROPIEDAD DE MANUEL LA CUAL SE QUEJA QUE ESTA SUFRIENDO FILTRACIONES ENVIO SOLICITUD AL TECNICO MUNICIPAL PARA QUE VALORE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-12-04','miguel, a petición de la parte económica(Alberto) remito fax al jzdo nº1 de Plasencia (ante la imposibilidad de contactar con ellos vía telefónia y fax donde sale ocupado) con el siguiente contenido: En relación a la ejecutoria 23/2020 de ese juzgado contra D. JOSÉ MANUEL ROMERO MEDIAVILLA, con DNI 28941714-D, tutelado de esta Comisión Tutelar de Adultos de la Junta de Extremadura, les adjuntamos justificante justificativo de haber abonado en Agosto de 2020 el importe reclamado por este juzgado, con el concepto siguiente: 1169000076007620, por importe de 288,51€ (Adjuntamos orden al banco, así como movimiento de la cuenta justificativo) Por otra parte le han citado sin conocimiento de esta Comisión Tutelar de Adultos, en fecha 16/2/20 a 12:40h, por lo que ruego nos remitan al fax abajo referenciado diligencia de citación a los efectos de poder identificar el procedimiento y motivo por el que se le cita. Si es preciso la intervención en dicha citación (cuyo procedimiento, repito, se desconoce), ruego se nos cite vía videoconferencia a través del SCACE de Mérida,para lo cual deberán ponerse en contacto con ellos. En caso de ser necesario abogado, deberán asimismo nombrarlo de oficio ya que la abogacía de la Junta de Extremadura no interviene para este tipo de procedimientos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-11-30','Ana: Correo de Borja Vázquez, Psicólogo de CSS-Plas (borja.vazquez@salud-juntaex.es): "Buenos días, Remitimos este correo electrónico la psiquiatra y el psicólogo clínico de la Unidad de Media Estancia del Centro Sociosanitario de Plasencia (Rosa Fernández y Borja Vázquez), para comentar la situación clínica actual de Margarita Antich Arroyo y demás temas en relación con su situación clínica. Actualmente, la paciente se encuentra estable psicopatológicamente hablando, atendiendo su ingreso al único objetivo de querer abandonar el recurso en el que estaba (Hogar San Vicente de Paul), como así consta en informe de urgencias del día 21 de noviembre de 2020. Para ello, realizó una serie de conductas que la llevaron a urgencias y posteriormente a este centro. Proponemos concretar una fecha y hora para una cita telefónica con algún/a responsable de la Comisión Tutelar de Adultos de la Junta de Extremadura para hablar con los anteriores profesionales señalados y la paciente, con el objetivo de valorar alternativas residenciales y escuchar la voluntad de Margarita, dado que actualmente se encuentra en una Unidad de Hospitalización Breve, no cumpliendo criterios clínicos que justifiquen la prolongación del ingreso en esta unidad. Un saludo cordial"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-12-09','Ana: Respuesta al correo de Borja, Psicólogo CSS-Plas.: "Buenos días Borja, Supongo recibiste la respuesta automática informando de la mi ausencia la semana pasada. Con respecto a Margarita Antich, de acuerdo, hablaré con Pedro, Jefe de Secc., para fijar un día de la semana que viene, para hacer la llamada con manos libre y que ambos estemos presente. Le pongo en copia. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2020-12-09','Ana: Correo de Alfredo, Res. Plasenzuela: "Buenos días Ana, ya está todo solucionado, ya envíe una copia del DNI al correo de la Comisión tutelar el 3 de diciembre. Un saludo. Alfredo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-12-04','Ana: Correo de Estrella, TS-CSS Plas.: "Buenos días, Ana. Hoy le han traído las monjas todos los enseres, documentos y 50 euros. Necesitaríamos que, nos enviaséis la autorización para sacar dinero de la paciente, y la cantidad que le tenéis estipulada. Gracias. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-12-03','Ana: Correo de Pilar Cerrillo, Res. Casar de Cáceres: "Buenas tardes Ana, recientemente hemos comenzado a gestionar la Res. de Alcuescar Amada Corra. Tiene plaza publicas para Pisos Tutelados (validos) libres. Sería posible trasladar allí a mateo Ruano?. Pagaría el 75% de la pensión hasta un maximo de unos 800€/m. Creo que encajaría bien allí. Y el ingreso puede ser rápido. Si quieres hablamos mañana. De todas maneras ya he hablado con Rosa la compañera del CS de Casar para que haga el informe social y tenemos cita para el informe médico. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-12-09','Ana: Mi respuesta al correo de Pilar Cerrillo: "Buenos días Pilar, Supongo que recibirías el correo-respuesta automático, informando de mi ausencia la semana pasada. Pues si crees que Mateo encajaría bien en los pisos tutelados, me parece una opción estupenda. Si puedes hablamos luego o el viernes (mañana es festivo local en Mérida). Un saludo." ························· Respuesta de Pilar: "Genial, ya tengo la documentación que me pediste te la puedo enviar por correo certificado urgente el viernes para que la tengas cuanto antes y mañana que voy a Alcuéscar vemos que día se puede ingresar. De todas maneras, luego hablamos. Un saludo Pilar" ········································· Conversación con Pilar Cerrillo: Los PP.TT. de Alcuescar son de Titularidad Municipal y Gestión Privada, recientemente asumida por el Grupo Ciudad Jardín. El viernes 11 Pilar me enviará documentación por email y por correo certificado (tanto la referente al ingreso en PP.TT. como para la solicitud de plaza de la Junta vía Decreto, pues ya estaba solicitada y por si acaso hiciese falta cambiarle en un futuro se solicitará también). El ingreso en los pisos se efectuará próximamente. *Del traslado también se harán cargo desde la resi, pues cuentan con una furgoneta adaptada de un C. Día que también gestionan. ······················ Lo comunico por mail a la secc. ecca. y a Pedro, Jefe de Secc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-12-09','Ana: Tras intercambiar correos acerca de la solicitud de cambio de médico especialista, se cierra la cuestión con el siguiente correo de Pedro-Jefe Secc. CTAEX: "Buenos días a todos. Respecto al cambio de especialista, y dado que estamos pendientes del ingreso de D. José Manuel en CRR, no creo que sea conveniente solicitar en estos momentos dicho cambio. Es cierto que tampoco sabemos a ciencia cierta cuánto pueden tardar en resolver su plaza, pero como tú dices, Ana, su psiquiatra actual es el que mejor lo conoce y cambiarlo ahora quizá solamente supondría una interferencia en su acceso a centro. Vamos a esperar que tenga pronto plaza en el CRR y vemos cómo evoluciona en dicho ingreso. Buen día." ··········································································································································································································· Envío correo a Pilar Martín (pilar.martinp@salud-juntaex.es): "Buena tardes Pilar, En relación a tu correo acerca del cambio de médico especialista por parte de José Manuel, mi compañero Ángel, Asesor Jurídico de la CTAEX, tras haber releído la sentencia de incapacitación y nombramiento de José Manuel, comunica que en este caso, desde la CTAEX debería firmarse dicha solicitud de cambio. Sin la firma del Representante Legal no tendría validez. Por otra parte, dado que en un futuro, esperemos que próximo, José Manuel ingresará en el CRR, y en este caso sí que tendrá que cambiar sí o sí de especialista, consideramos que en estos momentos no es conveniente proceder al cambio, así pues te pedimos que el cambio que ha solicitado José manuel no se haga efectivo. Si necesitáis que remitamos algún documento al respecto, por favor, háznoslo saber. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-12-03','Ana: Correo de Alberto, Jefe secc. ecca.: "Buenos días. A TRAVÉS DE ESTE CORREO SE PRETENDE CONVOCAR UNA REUNIÓN PARA LA TOMA DE DECISIÓN SOBRE EL FUTURO DE LA TUTELADA MANUELA MORATO PICADO Por ello, se remite COSTE total de obra, según información que transmitida por el aparejador (el ha escogido el presupuesto más bajo de los 3 que nos habían remitido, x entender que todos ellos se ajustaban a lo deseado): • Licencia de obras: 281,16€ • Ocupación de la vía y Gestión de Residuos: 150€ aproximadamente • Presupuesto de albañil ganador de la licitación: 7.502€ (IVA INCLUIDO) • Honorarios del Aparejador: 726€ (IVA INCLUIDO • TOTAL: 8.659,16 € • Aviso: este sería el coste salvo que Ayuntamiento obligue a incorporar alguna modificación. Recordaros que a nivel ECO: • Saldo noviembre 2020: 6.791,93 € • Evolución saldo últimos 12 meses: -1.970,03 € (cama articulada, colchón relax, farmacia, otros...) y SUPONEMOS que por evolución y edad tutelada estos gastos se incrementarán. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-12-09','miguel, a petición de Pedro y debido a que el tutelado saldrá del Hopistal Psiquiatrico de Sevilla el día 12-12-20 solicito vía fax INTERNAMIENTO INVOLUNTARIO al Jzdo nº1 de Castuera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-12-09','Ana: Pedro me informa que con respecto a la retirada del permiso de conducir de Miguel, han coordinado para que el próximo lunes acuda la Delegada de Futuex y la Guardia Civil al domicilio para que se lo entreguen. *No obstante desde la Guardia Civil informan que llevan días sin ver a Miguel por el pueblo y piden que nos aseguremos primero de que sigue allí. ················ Ana: Llamo a Raquel, TS del SSB - Guadalupe (927 36 70 06 // 605 429 865): Miguel y su hermano acudieron a su despacho el día 1 de diciembre. Desde entonces no ha vuelto a verle. En cuanto a la cuestión económica que le plantea el hermano de Miguel, según le dice le están manteniendo, le detallo el presupuesti que el propio Miguel elaboró estando en el CSS, que es el que se ha aceptado. *Si el padre o hermano no facilitan nº de cuenta no se le podrá realizar la transferencia de los 100 € que quería aportar (a parte de los 200 para alimentación y aseo). **En cuanto a la petición de la Guardia Civil, mañana Raquel llamará al hermano para corroborar que sigue en el pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2020-12-09','miguel, Pedro y yo nos reunimos con Inma (Policía Judicial) quién nos entrega la relación de procedimientos judiciales tramitados contra nuestro- tutelado. Nos comenta que muchos son por contratación de telefonia, por suplantación de identidad, etc. +++CONTACTO DE Inma: Complejo III Milenio.Centralita: 924-314711///Directo UDEV (Unidad de Delincuencia Especilizada y Violenta):924-387253. FAX: 924-387473','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-12-11','(Pedro) Llamo al C. Salud de Valencia de Alcántara. Lidia, la T. Social no está y la Dra.Nuria Díaz no estará disponible hasta las 09:30h, una vez termine la atención a los PCR. Volveré a llamar. ++++++++++++++++++++++++Llamo al Pilar, T. Social del SSB. No cogen el teléfono. ++++++++++++++++++++++++Llamo a Toni (Futuex): prevista la visita domiciliaria para el miércoles 16 de diciembre. Le dejo el teléfono de contacto de la Dra.Díaz. ++++++++++++++++++++++++Llamo a la Dra. Nuria Díaz. +++Tenían previsto hacer la visita domiciliaria solicitada la próxima semana. Muestra total predisposición a hacer la visita junto con Futuex. Le dejo los correos electrónicos de ctutelar, el de Ana y el mío, además de los teléfonos de ambos y el de Futuex. +++CORREO-e de la Dra. Nuria Díaz: nuria.diaz@salud-juntaex.es. Teléfono: 927 58 02 95 (Ext. 54208).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-12-11','(Pedro)Conversación con Raquel, sobre la interposición de la denuncia que plantea en correo-e del día 3 de diciembre el Director del CRR por la agresión sufrida por D.Ángel por parte de otro residente: +++Correo-e: Buenas tardes, He intentado contactar con vosotros vía telefónica pero no ha sido posible. Es para informaros que un usuario del CRR ha agredido a Ángel P.C (el mismo usuario que ya le agredió anteriormente). Ángel se encuentra bien, según refieren los residentes que estaban delante le ha dado golpes en la cabeza. Ángel quiere interponer denuncia, como ha habido presencia policial a la llegada de los facultativos médicos, hemos informado de su intención pero también de que está tutelado por la Junta de Extremadura por lo que estamos pendientes de vuestra decisión. Muchas gracias, Buen día. +++Raquel me confirma que finalmente se interpuso la denuncia dada la insistencia de D. Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2020-12-11','miguel, llega por fax la denegación por la comisión provincial del abogado y por tanto Angel solicitará uno de pago. Le remito a Angel la resolución así como la citación para el 5-2-20 para que solicite también videoconferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2020-12-11','miguel, escribe el abogado de Camilo Y le contesto: Buenos días, conforme a lo establecido en el artículo 276.3º CC se ha extinguido la tutela por fallecimiento de la persona tutelada, fallecida en la Residencia de Ancianos de San Miguel de Santa Amalia el 1-7-2020, y habiendo otorgado testamento se desconocen parientes cercanos. Asimismo se le indica que desde esta Comisión Tutelar de Adultos se procedió conforme establece el artículo 279 CC a la remisión al Juzgado de 1º instancia e instrucción nº2 de Don Benito a la rendición final de cuentas, en relación al procedimiento de incapacitación 604/2008 del Juzgado de 1º instancia e instrucción nº1 de Villafranca de los Barros. En cuanto al procedimiento de solicitud de autorización de gastos extraordinarios del que conocía el JUZGADO DE PRIMERA INSTANCIA E INSTRUCCIÓN Nº 2 DE DON BENITO (X15 AUTORIZ JUD DISPOSIC BS DISCAPAC 226/2019, le indicamos que con fecha del 2/12/20 hemos remitido fax a este Juzgado indicándoles además del fallecimiento, la falta de resolución del procedimiento indicado a los efectos oportunos. Por tanto y debido a que desde esta Comisión no se ejerce actualmente la tutela y conforme a la Ley de Protección de Datos les remitimos al Juzgado de 1º instancia e instrucción nº2 de Don Benito para cualquier aclaración. *********************************************************Compruebo que está mal remitido al Juzgado la rendición final de cuentas y remito email a la parte económica: Buenos días, en relación a la rendición de cuentas finales que remitisteis al Juzgado de 1º instancia nº2 de Don Benito, está mal, os lo adjunto para que lo veáis (deberíais remitir el certificado de últimas voluntades correcto al juzgado). Habéis puesto un certificado de últimas voluntades de otra persona e indicáis que no otorgó testamento cuando sí lo hizo. El abogado de Camilo está preguntando y ya le he respondido. Os lo adjunto para que lo veáis (aunque está en su expte virtual)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-12-11','TERESA HE RECIBIDO PRESUPUESTO DEL ALBAÑIL, ES BANTANTE ASEQUIBLE,NOS FALTA EL DE LA PINTURA. UNA VEZ HECHO ESTA REFORMA PUEDE VOLVER AL DOMICILIO Y DEJAR EL ALQUILER. SERIA CONVENIENTE QUE SE HICIERA LIMPIEZA GENERAL DE TODO LO QUE TIENE ALLI Y NO LE SIRVE.-','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-12-11','(Pedro)Reunión telefónica con Rosa (Psiquiatra), Borja (Psicólogo), Estrella (T. Social) un Residente (¿?)y Margarita. Por parte de la Comisión Tutelar Ana y yo. +++CONCLUSIONES: +++++El deseo de Margarita es quedarse en la ULE "para siempre". ++++Todos los profesionales implicados estamos de acuerdo en que lo mejor para ella es pasar a la Unidad de Larga Estancia, pero con la finalidad de ver cómo es su evolución y en función de la misma valorar otro tipo de recurso, un CRR. Si la evolcuión lo aconsejara, se podría solictar cambio de perfil por si pudiera ser candidata a una plaza de discapacidad, pero en opinión de la CTAEx, al menos en estos momentos, creemos que el recurso adecuado debe estar dentro de la Red de Salud Mental. +++++En cualquier caso, su paso a ULE no se plantea en ningún momento como una medida definitiva: creemos que Margarita tiene potencial sufieciente para ganar en autonomía e independencia y, si es así, ser candidata a CRR llegado el momento. +++++DE hecho, en la conversación mantenida con ella y a pesar de haber solicitado quedarse en la ULE "para siempre", ella misma manifiesta también su deseo de "...poder algún día compartir un piso de alquiler con alguna chica..." +++++Dado que en ULE sí teien que pagar la plaza, solictamos nos envíen un presupuesto con los gastos más frecuentes para ajustar el presupuesto actual (lo comento con Belén) y, para los Reyes, como Margarita ha pedido algo de dinero, de momento se pueden organizar con los 40 euros que le quedan desde su ingreso en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-12-11','(Pedro)Correo de Amalia: Buenas días, hoy le dan el alta a Ati en la UHB , he hablado con su psiquiatra, está muy compensado a nivel de psiquiatría y tiene la unidad totalmente saturada . He organizado su estancia , al menos durante una temporada para que permanezca en Mérida , su intención es marchar a Palafolls. -Reserva de habitación con Hostal Senero . Enviará las facturas por email semanalmente. -Sacará hoy su asignación semanal en BBVA en la oficina de Juan Carlos I , y la de la semana que viene también , siguiendo indicaciones de Juana . -Le he dado la dirección del Banco Caixa Geral donde acudirá con su DNI para escanearlo. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-12-11','miguel, llega por fax de las Diligencias previas procedimiento abreviado 132/20, Delito leve robo con violencia o intimidación, providencia del 9-12-20 del Juzgado de 1º instancia nº3 de Mérida por el cual el Ministerio Fiscal propone el sobreseimiento y archivo del caso. Se lo envío a Angel vía email por si entiende que debemos intentar oponernos a la resolución judicial o no.','2');
