insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-12-11','TERESA Me llaman de la empresa de teleasistencia, que tiene un problema con la conexión, ha ido 2 veces el técnico y no terminan de solucionarlo, creen que el problema podría resolverse comprando un microfiltro con doble clavija. la empresa es sar quavitae. Me preguntaban cuál era la compañia de telefono, si estaba al corriente en el pago,... como desconozco estos datos, creo que es más operativo si hablais vosotras directamente con ellos. Me facilitan el siguiente número de teléfono 954642790. Desde que lo tiene instalado nunca ha tenido problemas, hasta ahora, tras el día de la tormenta que os comentamos. Teresa, ya me comentas LLAMO A LA EMPRESA TRAS COMPROBAR QUE ESTAMOS AL DIA DE PAGOS, ME COMENTA QUE PROBREMO CON EL MICROFILTRO LE COMENTO A OLGA LA TS QUE LA AUXLIAR LO COMPRE Y PRUEBEN Y CONTINUA EL PROBLEMA QUE LLAMEN A LA COMPAÑIA TELEFONICA A VER SI EL PROBLEMA ES DE LA LINEA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-12-14','TERESA FUTUEX: , las circunstancias personales y sociales del caso, se continua contemplando el Servicio de Ayuda a domicilio del Ayuntamiento de Zalamea como una buena opción para dar respuesta a muchas de las necesidades actuales del caso. Dicha gestión se ha intentado tramitar en varias ocasiones desde el equipo de apoyo social comunitario con la trabajadora social de los SSB del Ayuntamiento de Zalamea de la Serena, obteniendo siempre una negación excusándose en algunas situaciones en las que se han producido agresiones físicas ocasionadas por problemas conductuales de Pablo AHORA QUE PABLO VIVE SOLO VAMOS A SOLICITARLO DESDE LA CTAEX CON LA DOCUMENTACON QUE FACILITA FUTUEX','2');
