insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2020-12-14','Fátima Agudo >fagudo@cerujoviservicios.com> Lun 14/12/2020 10:15 Buenos días Amalia, Te escribo este correo para comentarte varias cosillas; Por un lado, ya hemos recibido la carta, nos la han dado desde el cole de la Luz donde asiste Nerea. La dirección en la cual reside actualmente Nerea es c/Castillo de Olivenza, nº12, c.p. 06006 de Badajoz. Por otro lado, y también desde su cole, le han realizado dos pcr, siendo ambas resultado negativo. En tercer lugar, hemos solicitado el campamento de plena inclusión para Nerea, que va del 26 al 30 de Diciembre. En verano ya asistió y como se lo han comentado en el cole está muy emocionada por ir, aunque estamos a la espera de si es aceptada o no. En cuarto y último lugar, finalmente no se produjo la visita con su tía por lo que solicita que se realice este próximo sábado 19. Esto es todo, también tengo entendido que Teresa se pondrá en contacto con nosotras esta semana para conocer a Nerea. Saludos y buena semana. Fátima Agudo Zarza (Educadora Social) fagudo@cerujoviservicios.com 620 30 35 25','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-12-13','recibo email de la abogada: BUENAS TARDES, ATENDIENDO A SU PETICION, LE ENVIO LA DOCUMENTACION ESENCIAL DEL PROCEDIMIENTO PENAL EN EL QUE HE INTERVENIDO EN CALIDAD DE ABOGADA DE D. JOSE VICENTE VICENTE DESPUES DE HABERLE DADO TRASLADO DE LA DOCUMENTACION INTERESADA, ESPERO EFECTUEN LA TRANSFERENCIA DE MIS HONORARIOS PRP0FESIONALES A LA CUENTA INDICADA SIN MAS, QUEDO PENDIENTE DE SUS ATENTAS NOTICIAS. UN SALUDO OLIVIA NOVILLO-FERTRELL FERNANDEZ ABOGADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-12-14','contesto a la abogada: Buenos días, no nos ha remitido su número de cuenta y concepto para que pueda remitírselo a la parte económica de la Comisión Tutelar de Adultos. *************************************************** Buenos dias, el concepto es pago de los honorarios profesionales devengados y que constan en la minuta que les remití en mi primer correo En cuanto a mi ccc bancaria, se la indico a continuación BBVA ES80 0182 6437 8502 0152 9146 ****************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-12-14','miguel, tras consultar con Alberto comprobamos que se le abona mensualmente casi el total de la PNC que gana. Consulto con Angel y me comenta: Este procedimiento trae origen de unos hechos ocurridos en junio de 2017 (antes de la incapacitación). Las actuaciones judiciales se inician el 17/12/19 (después de la incapacitación, que es de marzo de 2019), en el Juzgado de Herrera del Duque (PA 19/18). La Abogada, por tanto, debió comunicarnos que iba a actuar en este procedimiento, se supone que "contratada" por José Vicente, para que le diéramos, o no, el visto bueno a su intervención. En su sentencia de incapacitación, J.V., está curatelado para cuestiones de carácter patrimonial que excedan de una gestión ordinaria, es decir, para este caso que nos ocupa. Por tanto, debimos haber tenido conocimiento antes, ya que habríamos acudido a un abogado de oficio, tal y como comentas, al no disponer de más que una pnc. En mi opinión, habría que indicarle esta circunstancia a la Abogada, para que nos especifique por qué actuó en nombre de José Vicente, en base a qué Hoja de Encargo, con la fecha de su formalización, que como sabes, no tendrá, porque no se haría. Hasta que no justifique todo esto, no podremos abonar nada en nombre de José Vicente, debido a que cualquier actuación que realice sin nuestra intervención, es nula.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-12-14','miguel, contesto a la abogada: Buenos días, siento comunicarle que no se puede proceder al abono de dichos honorarios. Comentarle que tras consultar a la parte económica me confirman que esta persona no podía contratar los servicios de un abogado de pago ya que únicamente cobra una pensión no contributiva, y por tanto debería haber sido representado por un abogado de oficio. Desde la Comisión Tutelar se desconocía la contratación suya como abogada, siendo la aceptación del cargo de esta curatela por la Comisión Tutelar de Adultos el 18-12-2019. Otra cuestión es que hubiese sido contratada anteriormente en cuyo caso debería dirigirse a quién la hubiese contratado. Por otra parte en la sentencia 7/19 de 11-3-2019 correspondiente al procedimiento ICP incapacitación 142/2018 dictada por el Juzgado de 1º instancia e instrucción nº1 de Herrera del Duque, en cuyo fallo se estableció su incapacidad parcial para todas las decisiones relacionadas con actos de carácter patrimonial que impliquen cierta trascendencia y excedan de la gestión ordinaria de cantidades económicas de escasa cuantía. Y determina que Don José Vicente Vicente quede sometido a un régimen de curatela y se designa como curador a la Comisión Tutelar de Adultos. Por tanto, para que usted pudiera haber intervenido en nombre del curatelado tendría que haberse puesto previamente a su representación en contacto con esta Comisión Tutelar de Adultos, donde le habríamos solicitado una hoja de encargo, un presupuesto estimativo. Al no haberlo hecho y no haber por tanto sido contratada por esta Comisión no podemos proceder a autorizar un gasto (honorarios). En cualquier caso debido a la imposibilidad económica de este curatelado, ya se le habría comentado que tendría que haber sido representado por un abogado de oficio, el cual y debido a su situación económica le hubiera correspondido. Reciba un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2020-12-14','miguel, angel me comenta que Con respecto a este tema, recuerdo que acudí con Pedro Tomás al Juzgado, él expuso su relato y quedó el asunto pendiente de tomarle declaración a la otra parte, que ignoro cuál habrá sido el contenido de la misma. En cualquier caso, es la declaración de uno contra la de otro, por un supuesto robo en el cajero, del chico al que le debe dinero por el tema de drogas. No hay pruebas de nada. *********************************************** Por tanto dejaremos que se archive','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2020-12-14','TERESA SOLICITO PNC PUES LES ES MAS BENEFICIOSA QUE LA PF','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2020-12-13','EXITUS El centro informa de su fallecimiento acaecido el 13/12/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2020-12-14','miguel, mellega los movimientos bancarios del área económica del tutelado. Vuelvo a poner en registro de salida (igual al del día 2-12-20) oficio para remisión al abogado Felipe Muriel de Solicitud de aprobación de herencia y autorización de venta. ******************************************** Llega de nuevo petición del abogado para que le remitamos dicha solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-12-14','Ana: Envío correo a Sonia, Asindi (trabajosocial@asindi.e.telefonica.net), y Pilar, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Buenos días Sonia y Pilar, Espero que estéis bien. En relación a Aarón Rosado Alarcón, comunicaros que ya ha hemos recibido en la CTAEX la firmeza de la sentencia. Mis compañeros están con los trámites de aceptación del cargo de tutor. Por ello, en relación al ingreso pendiente en UHDAC, a petición de mis compañeros jurídicos, os solicito, que cuanto podáis no enviéis Informe Social actual e Informe Médico del Servicio de Psiquiatría, que justifiquen la Solicitud de Ingreso en la UHDAC, para que puedan adjuntarlo a su escrito-solicitud al Juzgado. En principio con uno de cada es suficiente, si ambas queréis enviar Informe Social, mejor. Cuando podáis os coordináis y ya me decís. Gracias a ambas y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-12-09','Ana: Envío correo-respuesta a Pilar Martín, ESM CC (pilar.martinp@salud-juntaex.es): "Buenas tardes Pilar, Acabo de hablar con Pedro, Jefe de sección CTAEX, al respecto de tu correo. Le pongo en copia. En primer lugar comunicarte que aún no hemos recibido la firmeza de la sentencia, a pesar de que mis compañeros la han reclamado al Juzgado. Ya no es cuestión de plazos, ya es cuestión de que, si nadie ha interpuesto recurso, el Juzgado nos la remita. En segundo lugar, en relación al ingreso en UHDAC, entendemos que, tal y como ha ocurrido en otras ocasiones, si el Equipo Terapéutico ha concluido que el joven reúne criterios para ingresar, puede ingresar en cuanto haya cama disponible y una vez esté allí, soliciten desde el centro ratificación al Juzgado. No obstante, una vez recibamos la firmeza y sea aceptado el cargo, mis compañeros jurídicos podrán valorar la pertinencia o no de solicitar el ingreso involuntario, si llegado el momento no hubiera tenido aún lugar. Por último, tal y como hablé con la responsable de Asindi, cada vez que Aarón manifieste alteraciones de conducta, tendrán que llamar al 112 y activarlo (tanga o no tenga la CTAEX aceptado el cargo de tutor) Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2020-12-14','RENDICION ANUAL Se encuentra residiendo en la Residencia El Encinar de Las Cruces de Don Benito (Badajoz) desde el 14 de febrero de 2019. Precisa revisión y ayuda continuada. Es autónoma en la movilidad y en la comida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-12-14','miguel, llega citación para el 16-2-21 en calidad de denunciado por agresión sufrida por Jose Mª Vicho. Solicito abogado de oficio y videoconferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-12-14','miguel,llega citación para el 16-2-21 en calidad de denunciante por agresión de José Mª Vicho Alfonso Solicito abogado de oficio y videoconferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-12-14','miguel, nos remite email Amalia de la Ts de la zona: Hola Amalia, quería comentarte dos asuntos sobre JUAN CARLOS RUBIO GALAN: por un lado la persona que te comenté que estaba interesada en alquilar su casa o la de Rosario Moreno, ya envió el mail a c.tutelar indicando que estaba interesada en cualquiera de las dos, pero aún no ha recibido respuesta y le urge saberlo para buscar otra vivienda o no, si no te importa pregunta a los del servicio jurídico a ver qué dicen. Por otra parte, la situación de Juan Carlos en su casa cada vez es más insostenible, sobre todo cuando viene un puente, o como ahora las navidades, en los que pasa varios días seguidos sin auxiliar. Cada vez me cuesta más trabajo que las auxiliares acepten ir, porque ya puedes imaginar que se encuentran la casa en unas condiciones indignas para una trabajadora. Hablé con Adriana y resulta que la solicitud estaba en ORVE enviada desde hace tiempo pero no se la habían pasado a ellos, se la volví a enviar por mail. No sé si puedes agilizar el tema de que le asignen un centro lo antes posible, yo creo que es muy necesario en la situación actual que tiene, no solo por la situación económica, si no y sobre todo por que necesita un volumen de cuidados y supervisión que es muy difícil darle, aunque hacemos por encima de lo que podemos. Gracias, y un saludo. ************************************************* Buenas , leed la primera parte del email y nos decís . Un saludo ************************************************************ Hola ya se trato este tema. La vivienda de la c/ Hinojo, que según ley, no se puede alquilar porque es VPO con limitación de precio máximo legal y requiere autorización de venta. En la zona no van a pagar lo que la junta va a estimar que vale que es unos 150000€, ya que hay una inmobiliaria que se llama Colón que según me remitió Sindy la vivienda de ella de alquiler con opción a compra (exactamente igual que la de nuestro tutelado) tenía un valor de 60.000€ precio acordado entre particulares siendo el precio fijado por la Consejería de Vivienda de más de 150.000€. Por tanto si no podemos alquilar y si no nos van a dar lo que vale la vivienda es un problema mantenerla así…y como digo otra solución no le veo. Si se encuentra alguien que quiera comprar o alquiler con opción a compra que se dirija a la consejería de vivienda pues yo ya intenté solicitar el precio de venta y la autorización de renuncia de la Junta del derecho de tanteo y retracto y me dieron 10 días para subsanar requiriéndonos para que indicáramos nosotros el precio por el que se quería vender (lo cual no era el caso porque Sindy solo quería comprar) 2.-Vivienda de la c/ Constitución es donde vive el curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-12-14','-Amalia : me comunica Eva , TS de P.I. Montijo que Cristofer está ingresado en la UHB desde el jueves . Está bastante descompensado y al parecer la psiquiatra les ha comentado que será necesario un entorno cerrado para él . LLamaré a UHB Badajoz para preguntar por su estado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-12-14','-Amalia , tras conversación telefónica con Eva , TS de P.I. Montijo , me comenta que el día 3 de diciembre fue dado de alta en la UHB donde ha estado unas semanas ingresado . Ha vuelto al chalet familiar de manera temporal , al parecer los padres están buscandole una casa en alquiler o en propiedad. Ha pasado unos días en un hostal que han pagado los padres. Está acudiendo a C.O. de P. Inclusión pero sin tener plaza ( el CADEX no le ha dado pérfil hasta en 2 ocasiones ) , me dicen que van a volver a solicitarlo desde el SSASB por dependencia. Le están dando el menú diario , mañana me pasará el importe que tendremos que pagar de la prestación , habrá que bajarle la asignación semanal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CRESPO'and apellido2='MARTIN'),'2020-12-14','Ana: Mariví, TS del CSS-Plas, comunica a Juana - CTAEX, que "José Crespo Martín se encuentra ingresado en el Virgen del Puerto, dice que hasta ahora no han dicho nada de acompañamiento pero para que lo supieras por si se ponen en contacto".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-12-14','Ana: Correo-e de Toni-Futuex: "respecto del carnet de conducir de Miguel Santos, comentar, que mi compañera Teresa Pacheco, ya ha salido de Guadalupe y tal y como quedamos para agilizar todo, va a pasar por Mérida por la comisión para entregaroslo. Finalmente el propio Miguel lo ha entregado en la comandancia de la guardia civil, para según él, ahorrarle a su padre anciano el mal trago de que acudiera al guardia civil ha su domicilio. Yo le he dicho a la compi, que pregunte por alguno de vosotros cuando llegue abajo al control del sepad"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-14','Ana: Correo de Ana Soledad Porras Ramos, Ayto. CC (ana.porras@ayto-caceres.es): "Buenos días. Siguiendo las indicaciones de Mª Pilar Martín Parra se informa que según la última revisión de la Tasa por prestación del Servicio de Ayuda a domicilio realizada a la usuaria Clementa Amado Vivas en febrero de 2020, el coste hora de servicio asciende a 7,905 euros. Actualmente el servicio se encuentra en suspensión. Se podría reiniciar la prestación con un servicio diario (de lunes a viernes) de 7 horas semanales y con un coste aproximado de 235 euros mensuales. Quedamos a la espera de su decisión para reiniciar servicio o tramitar baja definitiva. Gracias. Saludos." Lo pasaré a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-15','Ana: Con respecto al correo de ayer del Ayto. CC sobre el SAD, envío correo-e a Alberto, jefe secc. ecca.: "Buenos días Alberto, Te reenvío este correo del Ayto. de CC con respecto al Serv. De Ayuda a Domicilio Municipal, en mi opinión sería conveniente contratar el servicio, dado que lo ideal sería que ingresara en residencia pero, hasta ahora, la señora se niega y no cuenta con más apoyo. No sé si ya habéis hecho la ficha y si se lo podrá permitir. Ya me decís. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-12-11','Ana: Correo María González, TS - Autismo Sur: "Buenas Ana, Todo va genial, Alex se ha adaptado genial... Parece que lleva aquí toda la vida... Estamos teniendo bastantes problemas con la gestión de documentos de él, ya que al no tener ningún documento identificativo en vigor... ya que desde el centro de salud por no tener documentación y ser inmigrante como ellos dicen... debe pagar el 100 % de la medicación. Además no tiene ni la tarjeta sanitaria... por lo que son un montón de trámites que debemos de ir haciendo... Por otro lado el tema del pasaporte, es algo que debemos ver como realizarlo.. El tema de los gastos tenemos un Excel con los que se van ocasionando, si queréis los necesitáis os lo enviamos a final de mes. ..." ···················································································································································· Envían del C. Dulce Nombre de María por mail (trabajo.social@ipdnm.com) "Informe Final" de Costi Alexandru en su centro. *Lo guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-12-15','Ana: Solicito a María Glez. - Autismo Sur, por mail, Certificado de Ingreso en centro. ······· *Del C. Dulce Nombre de María, a pesar de haberlo pedido varias veces, no lo hemos recibido. ········································ Llamo a la Oficina de Extranjería de Badajoz (924 97 94 47) varias veces, pero no obtengo respuesta. ··········· Llamo a la Oficina de Extranjería de Málaga (952 98 04 60), salta una "locución" pero no consiguo hablar con nadie.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-12-01','TERESA SE GESTIONA PIA SAD COMIENZA EL UNO DE DICIEMBRE, ARCHIVO CONTRATO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-12-15','miguel, tras conversación con Ana me indica que procedamos a la contestación al Juzgado de Valencia de Alcantara nº1 al requerimiento que nos hizo (llegó a principios de diciembre) donde nos da 10 días para que contestemos. Tras ponerme al día Ana remito el siguiente email a la parte económica y social, mientras yo voy preparando el borrador que después pasaré a Ana para su confirmación: Buenos días, a principios de diciembre llegó este requerimiento solicitando que informemos en 10 días al juzgado sobre este tutelado por lo que vamos justos de tiempo para remitirlo, por eso os ruego me remitáis por aquí o bien me indiquéis en qué carpeta virtual del tutelado dejáis los siguientes documentos que os pido: Parte Económica: 1) Mirad en la carpeta de Futuex donde desde Febrero se indicó presupuesto para limpieza de la vivienda. Necesito me hagáis una relación de si se ha conseguido hacer dicha limpieza junto con la fecha en qué se ha hecho y la factura. 2) En cuanto al arreglo del Tejado, a fecha de hoy desconozco si os han dado o no presupuesto de arreglo, sí me consta que pagasteis el anterior arreglo de cuando se le cayó el techo de la vivienda. Es por ello que necesito que me indiquéis que se lleva hecho y no sobre este asunto (si ya se ha acordado con la Comunidad de Vecinos el arreglo, a cuánto asciende el importe, cuándo se va a proceder a dicho arreglo?) Si no se ha concretado nada os recuerdo que al ser tutelado habríamos de pedir autorización previa al juzgado por gastos extraordinarios (si el importe que deba pagar nuestro tutelado es importante) 3) Catering: necesito me indiquéis desde cuándo se está pagando el servicio de catering y me enviéis la relación de facturas pagadas. 4) Para las rendiciones de cuentas veo que la Trabajadora Social de Valencia de Alcantara no os remitió el Informe Social que adjuntáis, os lo ha enviado para la rendición de cuentas del 2020? 5) Si podéis indicarme también a modo de resumen cuáles son los gastos ordinarios y extraordinarios de este tutelado en el último año así como el saldo actual de sus cuentas. En caso de que el importe para el arreglo del Tejado sea importante habría de pedir Autorización para Gasto Extraordinario al Juzgado (y si es superior a 3000€ tendría que contratar un abogado de pago pues veo por la última rendición de cuentas que al menos tiene 22.000€). Por favor, necesito que entre hoy y mañana tengamos preparado esto, miradlo y me decís. Parte Social: Conforme he hablado con Ana, necesito (miraré en la carpeta de personal): 1) Gestión de Tráfico: aportaré todas las gestiones que hicimos con este tutelado. 2) Dependencia: indicaré que aunque hicimos las gestiones para su valoración en 2019, hasta Octubre de 2020 no nos han aceptado el PIA para que nos ayuden a cualquiera de las 3 cosas solicitadas: -Ayuda a domicilio por el Ayuntamiento (se encuentra en lista de espera) -Ayuda económica para contratar empresa privada para ayuda a domicilio (para lo cual nos primero nos tiene que confirmar la parte económica si ya han limpiado o no la vivienda) -Residencia de Mayores Buenos Aires: a día de hoy está en lista de espera, aunque él por ahora rechaza esta opción indicaré al Juzgado que si ellos lo estiman resuelvan si hemos o no de ingresarlo aquí llegado el momento. Ana se me ha olvidado preguntarte si tenemos actualizado algún informe médico (salud mental) para aportarlo también (nos vale que sea de los últimos 2 o 3 meses). Si no es así a ver si pudieran enviarte algo. En cuanto al informe social que la trabajadora social del Ayuntamiento de Valencia de Alcantara habéis solicitado desde hace más de un año y nunca os a remitido, y salvo que la parte económica lo tenga, se lo comunicaré también al juzgado a los efectos oportunos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-12-15','miguel, me llega email de Amalia para ver si podemos o no vender la vivienda de la c/ Constitución. *********************************************************** contesto a Amalia y Alberto: Hola a ambos, no veo ninguna limitación para vender o alquilar la vivienda de la c/ Constitución 13. Al ser curatela no es necesario pedir autorización para vender lo cual agiliza todo si quieres ingresarlo como dices en centro. Recuerdo que finalmente no ampliamos su incapacidad y pedimos su internamiento involuntario precisamente para intentar agilizar cualquier venta de inmueble. Por otra parte creo que es buena noticia si él quisiera voluntariamente ingresar en centro. Para cualquier alquiler o venta o bien yo lo pondría en manos de la Inmobiliaria Colón, quién os podrá indicar un precio ajustado al mercado (no es obligatorio pedir tasaciones como hacemos con los tutelados cuando pedimos las autorizaciones de venta judiciales). Podéis ver que según escritura de Compra el importe fue de unos 51.000€…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-12-15','Correo de Soraya Cobos, Directora CSS-Plas (soraya.cobos@salud-juntaex.es): "Buenos días: Desde el Centro Sociosanitario contactamos con vosotros para solicitar la compra de ropa y lencería para cubrir sus necesidades básicas, de vuestro tutelado Jairo Martín Puertas. 4 camisetas de interior maga larga---39,96 euros 6 calzoncillos slip-------------------------15.96 euros 6 pares de calcetines --------------------18 euros 1 chandal------------------------------------39,96 euros 1 zapatillas de estar en casa------------15, 98 euros Total: 128, 79 euros Quedamos a la espera. Gracias. Un saludo." ··········· *Se lo reenvío a Alberto, jefe seccc. ecca. y pido que le respondan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2020-12-16','Ana: Envío correo a Mariví Clemente, TS del CSS: "Buenos días Mariví, Tal y como acordamos, te envío adjunta escaneada la “Solicitud de salida” del suplemento nº 238 del DOE, debidamente firmado y sellado por el representante legal, relativa a Mª Jesús Martín Calle. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2020-12-16','Buenos días , he tramitado el servicio de teleasistencia domiciliaria para los 3 hermanos , siendo el titular Alonso . Los 3 tendrán un dispositivo ( pulsera o colgante ) para que en momentos de urgencia puedan pulsarlo y ser atendidos . Estará asociado a su móvil pq no tienen linea fija . He explicado la siuación sociofamiliar y la necesidad de cubrir principalmente el turno de noche , en ese caso ante una emergencia activarían los servicios que precisen . Si como ocurrió la última vez precisa de servicio médico activarían el servicio con el centro de salud . Los tf. de trabajo de personas de contacto que he dado son el mío , el primero y si no tenéis inconveniente he pensado indicar el de Pedro de la CTAEX y alguno de SSASB . El servicio cubre las 24h , todos los días del año y cuesta 29,50€ al mes que se abonará por ellos . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='SANTANTON'and apellido2='GOMEZ'),'2020-12-16','TERESA RENDICION ANUAL SE ENCUENTRA BIEN ADAPTADO A LA VIVIENDA TUTELAR DE PLENA INCLUSION LLERENA, ACUDE A CENTRO OCUPAICONAL DONDE TIENE BUENA RELACION CON SUS COMPAÑEROS, MANTIENE UNA RELACION ESPECIAL CON UNA COMPAÑERA LO CUAL LE FAVORECE PUES ESTA MAS PARTICIPATRIVO. TIENE UN SALDO DE 3000 COBRA PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-12-16','Ana: Envío email al CADEX-CC (cadex.caceres@salud-juntaex.es), solicitando Cdo. Discapacidad: "Buenos días, En relación a Julia Morón Hernández, tutelada por la Comisión Tutelar de Adultos de Extremadura, a fecha de 1/07/20, se registró solicitud de Certificado de Discapacidad, que a día de hoy no hemos recibido. No sabemos si se habrá extraviado. ¿Serían tan amables de enviarnos tanto del Certificado como el Dictamen Técnico y a ser posible adelantárnoslo escaneado por este mismo medio? Adjunto copia de la solicitud indicada. Gracias y un saludo." ································································································································· Me remiten desde el CADEX ambos documentos. Según el Dictamen Técnico, Julia presenta: "Inteligencia Límite" y "Trastorno de la Afectivdidad por Trastorno Bipolar" ································································································································ Pido a Juan Pedro, Admvo. CTAEX, que donsulte en SIDEX: Julia fue valorada por Dependencia en 2015: SIN GRADO. ················· *Hablaré con la TS del SSASB, habrá que solicitar nueva valoración e ingreso en centro si diera grado (como es el deseo de Julia, lo reitera cada vez que llama por teléfono)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='PARIENTE'and apellido2='LUCAS'),'2020-12-16','EXITUS El centro comunica su fallecimiento el 16/12/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-12-16','miguel, llega citación de abogacía del Jzdo nº1 de Jerez de los Caballeros. Al indicar el procedimiento X04 Rendicición de cuentas Tutor 463/2014, ante lo cual llamo al juzgado para que me informen y me comentan que se les ha olvidado remitirme a parte de la citación requerimiento del Fiscal para nos personemos el 12-1-21 a 11:30h en dicho juzgados a los efectos de tratar el tema de la compra del ciclomotor por Ramón. Al mirar el expte veo el fax que se remitió al juzgado en su día. Pongo a Tere el siguiente email: Buenos días, te remito citación para el 12-1-21 a 11:30h donde según me indican desde el juzgado es para analizar la compra de motocicleta que compró Ramón. Tienes que conseguir que alguien acompañe a Ramón (nosotros asistiremos desde los Juzgados de Mérida por video conferencia) Vamos a necesitar lo que en su día se indicó en el fax, que es que no tiene seguro, ni revisión periódica de ITV, y que se ha puesto en conocimiento de la guardia civil de Jerez de los Caballeros y a su vez lo ha trasladado a la Policía Local. En dicho fax que también te adjunto se indicaba que a los efectos de poder inmovilizar dicha motocicleta, como medida cautelar, al suponer un riesgo para la circulación de todos los ciudadanos y del propio Ramón. Hazte por tanto con las diligencias de la policía y algún informe social desde julio aproximadamente hasta ahora… Por mi parte voy a solicitar videoconferencia y en caso que fuera necesario que le nombren un abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2020-12-16','miguel, llega el siguiente email de Soledad Olmos del Colegio de Ntra Señora de la Luz de Badajoz: Buenas tardes, Amalia y Miguel. Me dirijo a vosotros para comunicaros que JUANA BUENO GUISADO, curatelada por la CTAEx, es propietaria junto con sus dos hermanos ROSA Y FRANCISCO, de una finca rústica en la localidad de Alburquerque (Badajoz). Quieren venderla y hay un comprador interesado en ella. La documentación pertinente está en la Notaría de Alburquerque (Badajoz) cuya titularidad la ejerce Dña. Eva Rodríguez Vidiella. Las gestiones relativas a la operación de compraventa las han realizado a través de una Gestoría de Alburquerque cuyos datos van expresos en archivo adjunto así como la forma de contactar con ellos . Solicitan que en la mayor brevedad posible se autorice a un letrado de la CTAEx para que intervenga en representación de Juani ante la notaría en la firma de la escritura de venta (ver documento en archivo adjunto). Miguel, me he tomado la libertad de enviarte a ti también este correo. Desconozco si te correspondería a ti este expediente o a tu compañero. Los teléfonos de los dos hermanos de Juani son los siguientes (por si queréis contactar con ellos): KIKO: 617 836 710. ROSA: 648 534 634. Un saludo. ***************************************************** Tras intentar sin éxito hablar con la notaria de Alburquerque para informarnos de esta venta (ni la parte económica (Alberto), ni la parte Jurídica conocíamos nada en relación a esta venta. Por eso envío email al mediador Jesús Lara Bueno (email larabuenoasesores@gmail.com y móvil 659-255734. Le remito el siguiente email: Buenas tardes, conforme a su solicitud y debido a la imposibilidad de hablar con la notaria de Alburquerque, necesitaría que nos indicara el número de teléfono de esa notaria y un email a efectos de que nos remitan el borrador de la escritura. Necesitamos nos acrediten la valoración de dicha venta, si hay tasación que nos la remitan, caso contrario nos remitan ibi, certificado de catastro e ibi. Si todo estuviera correcto y previo consentimiento de la persona curatelada, ésta firmaría la venta en la notaria y posteriormente desde la notaria de Romero Leal de Mérida nosotros procederíamos a la ratificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='DIAZ'and apellido2='TINOCO'),'2020-12-16','ANA DÍAZ TINOCO , tutelada el día 1 de diciembre falleció el día 3 . No creo que haya que hacer nada de inventario pero sí hay que comunicarlo al juzgado y darle de baja en la base de datos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2020-12-16','Ana: Envío mail a Cruz Blanca (et-caceres@cruzblanca.org): "Buenos días, Adjunto remito solicitud de revisión del CADEX firmada electrónicamente por el Representante Legal. Ante cualquier otra cuestión, no duden en volver a contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='DIAZ'and apellido2='TINOCO'),'2020-12-16','EXITUS Falleció el día 03/12/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-12-16','miguel, llega propuesta por email del abogado de la hermana de la herencia de los padres, donde se propone dar 68.000€ efectivo+local de Luis Alvaréz Lencero (valor catastral sobre 30.000€, a cambio de la parcela en la Dehesilla del Calamón. Tras verlo en catastro+nota simple y pasos que en su día se dieron y la valoración dada al local (en la escritura de herencia ya que en dicha escritura sólo se valoró el suelo de dicha finca rústica de la Dehesilla del Calamón por 20.000, siendo el valor catastral aproximadamente 114.000€). ******************************************************** Alberto me remite el siguiente email con las conclusiones: En relación con el posible acuerdo para la repartición de los bienes derivados de la herencia de sus padres, se van a realizar las siguientes actuaciones a 16/12/2020: • la consideración inicial por parte de los 3 (Juana, Miguel y Alberto), es favorable al acuerdo remitido por el abogado de la hermana del tutelado. • JUANA: llamará expresamente a Yolanda (esposa del tutelado) para obtener su parecer. • JUANA: hablará con tutelado y le solicitará un documento donde manifieste de forma clara que está de acuerdo con el "acuerdo" remitido x el abogado de su hermana. • JUANA:posibilidad de hablar con TECNICASA. • MIGUEL: hacer INFORME explicativo de la valoración que hemos hecho y que nos lleva a pensar que es un acuerdo aceptable. • MIGUEL: una vez tomada la decisión definitiva de aceptación del acuerdo se pondrá en contacto con ABOGADO hermana tutelado para cerrar el asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2020-12-10','Ana: A través de la dirección de contacto (inf.saludextremadura@salud-juntaex.es), recibimos correo de la TS de Torrecilas de la Tiesa: ": Hola Soy Montaña la Trabajadora Socialde Torrecillas de la Tiesa, me pongo en contacto con uds. porque la persona que estaba al cargo de Encarnacion Patilla Castro, les mando un comunicado el 30 de octurbe de 2020, para informarles que ya no se podia hacer cargo de ella porque dejaba el centro. Espero se pongam en contacto conmigo para hablar de este tema, ya que no consigo contactar por telefono con uds, mi numero de telefono es 621 247 249 Gracias y un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2020-12-17','Ana: Llamo a Montaña, Trabajadora Social de Torrecillas de la Tiesa (621 247 249): La residencia de mayores pasa a ser de gestión municipal, por lo que Lucía Ávila, anterior directora ya no continúa, es necesario que se autorice a otra persona para las retiradas de efectivos y otras cuestiones económicas/bancarias. **Le indico que envíen correo al ctutelar@, A/A de la secc. ecca. espeficando los datos de la persona responsable que vaya a encargarse a partir de ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-12-01','Ana: Correo de Rosa, CSS - Plas.: "Buenos días: Os adjunto Informe de Alta de la paciente Felisa B.S., trasladada en el día de la fecha a ASINDI Alcántara. Por correo ordinario os remito justificante de gasto. Un saluldo. Rosa Bravo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2020-12-17','miguel, recibo email de Alberto: Buenos días. En relación con el tutelado 2 cuestiones: • ACLARACIÓN SENTENCIA: esto va dirigido al ÁREA JURÍDICA: x favor indicádnos el alcance de la sentencia, ya que, desde un principio se entiende que sólo afecta al ámbito sanitario (cuestión aceptada también x área social (Pedro)). TENGO DUDAS AL RESPECTO. o Por ejemplo, nos acaba de solicitar 400 €, además de lo que le pasamos. Podemos no autorizarlo? • PAGO FACTURA ABOGADA: Miguel, 2 cuestiones: o saldo 17/12/2020: 518,42 €. Imposible de abonar en este momento y, en ningún otro momento si no puedo/debo limitarle más la CCC. o Hay que tener en cuenta que la contratación de la agobada ha sido SIN AUTORIZACIÓN (al menos, que yo sepa) de la CTAEX. Xfavor, échadle un vistazo a la sentencia, ponedla en común, y lo hablamos. ********************************************************** Contesto: Buenos días, trascribo lo que dice literalmente la sentencia: “ La Comisión Tutelar deberá velar por el incapacitado parcialmente tanto en el orden personal en lo ateniente a las decisiones que afecten a la esfera sanitaria como en lo referente a la administración extraordinaria de sus bienes, quedando al margen los actos de disposición de escasa cuantía (más arriba indica: el demandado es apto para gobernar su persona en lo que se refiere a actos básicos de la vida diaria y gestionar cantidades económicas de escasa cuantía, pues mantiene suficiente potencial volitivo y cognitivo. Y más arriba en relación a las conclusiones del Forense: …”requiriéndose el concurso de terceras personas para adoptar decisiones de carácter patrimonial que revistan cierta entidad (concertar contratos, tomar dinero a préstamo, aceptar/repudiar herencias, legados, donaciones) , para los que José Vicente Vicente se encuentra facultado para efectuar por si solo”. En mi opinión deja claro como actos extraordinarios, pedir un préstamo, hacer herencias, contratar un abogado para un procedimiento judicial…Fuera de eso con su dinero mensual puede hacer lo que quiera. Por otra parte olvídate de la abogada la conteste por email que no la pagaremos, te transcribo aquí el email: “Buenos días, siento comunicarle que no se puede proceder al abono de dichos honorarios. Comentarle que tras consultar a la parte económica me confirman que esta persona no podía contratar los servicios de un abogado de pago ya que únicamente cobra una pensión no contributiva, y por tanto debería haber sido representado por un abogado de oficio. Desde la Comisión Tutelar se desconocía la contratación suya como abogada, siendo la aceptación del cargo de esta curatela por la Comisión Tutelar de Adultos el 18-12-2019. Otra cuestión es que hubiese sido contratada anteriormente en cuyo caso debería dirigirse a quién la hubiese contratado. Por otra parte en la sentencia 7/19 de 11-3-2019 correspondiente al procedimiento ICP incapacitación 142/2018 dictada por el Juzgado de 1º instancia e instrucción nº1 de Herrera del Duque, en cuyo fallo se estableció su incapacidad parcial para todas las decisiones relacionadas con actos de carácter patrimonial que impliquen cierta trascendencia y excedan de la gestión ordinaria de cantidades económicas de escasa cuantía. Y determina que Don José Vicente Vicente quede sometido a un régimen de curatela y se designa como curador a la Comisión Tutelar de Adultos. Por tanto, para que usted pudiera haber intervenido en nombre del curatelado tendría que haberse puesto previamente a su representación en contacto con esta Comisión Tutelar de Adultos, donde le habríamos solicitado una hoja de encargo, un presupuesto estimativo. Al no haberlo hecho y no haber por tanto sido contratada por esta Comisión no podemos proceder a autorizar un gasto (honorarios). En cualquier caso debido a la imposibilidad económica de este curatelado, ya se le habría comentado que tendría que haber sido representado por un abogado de oficio, el cual y debido a su situación económica le hubiera correspondido” Creo que queda claro por tanto que es una curatela prácticamente sólo sanitaria (excepto para casos extraordinarios…compraventas, herencias, préstamos, procedimientos judiciales…) **************************************************** contestación de Angel: Buenos días, El alcance de la curatela va más allá del ámbito sanitario, en concreto se extiende a: 1. Todas las decisiones relacionadas con la esfera sanitaria (decidir altas médicas, tratamientos médicos, etc., en centros sanitarios). 2. Actos de carácter patrimonial que impliquen cierta transcendencia y excedan de la gestión ordinaria de cantidades económicas de escasa cuantía. Con respecto a los 400 € que solicita, si desde el área económica, se entiende que excede de la gestión ordinaria de cantidades económicas de escasa cuantía, podemos no autorizarlo. Con respecto al pago de la factura de la Abogada, ya lo hablamos Miguel y yo. Quedamos en que se le solicitaría a la Abogada la Hoja de Encargo que en su día firmara el curatelado con ella, para ver la fecha de su formalización, de llevarse a cabo, que lo dudo, toda vez que las actuaciones judiciales se inician el 17/12/19 (después de la incapacitación, que es de marzo de 2019), en el Juzgado de Herrera del Duque (PA 19/18), por ese motivo la Abogada debió ponerse en contacto con nosotros, para solicitar intervenir en su nombre. De haber procedido así, habríamos acudido a un Abogado de Oficio, para beneficiarse de la justicia gratuita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-12-17','Ana: Llamo a la Oficina de Extranjería de Málaga (952 98 04 60), sin éxito. **Envío un correo-e a la dirección de atención a profesionales (infoextra.malaga@correo.gob.es): "Buenos días, Me pongo en contacto con ustedes en relación a un joven procedente de Rumanía residente en la localidad de Málaga, del cual desde la Comisión Tutelar de Adultos de Extremadura se ha asumido recientemente la Tutela como adulto (cumplió la mayoría de edad a final de septiembre). Ha llegado a tutela de adultos sin nada de documentación en vigor, agradecería se pusieran en contacto conmigo para informarme acerca de los trámites que debemos llevar a cabo y aclarar algunas cuestiones al respecto. O me facilitaran algún número de teléfono para contactar. Gracias y un saludo." ··················· Respuesta automática: "Gracias por dirigirse al correo de información de la Oficina de Extranjería de Málaga. Las solicitudes de información, sobre materias competencia de esta Oficina de Extranjería, se responderán a la mayor brevedad posible. Por favor, no reitere la consulta. A partir del lunes 15 de junio de 2020, se asignará la cita previa para todos los trámites presenciales en nuestro servicio de atención telefónica 952 980 460 opción 5, El aforo en la Oficina de Extranjería se ha disminuido para garantizar las medidas de distanciamiento social y evitar la concentración de personas en espacios cerrados. Para aprovechar al máximo el número de citas disponibles, es muy importante que se asegure de disponer de toda la documentación necesaria para presentar su solicitud antes de solicitar la cita. Si ha solicitado información sobre trámites que se realizan en las comisarías de la Policía Nacional: Solicitud de Tarjeta de Identidad de Extranjero (TIE - trámite de huellas) Retirada de la TIE Certificados de registro de ciudadanos de la UE. COMUNITARIOS Asignación de NIE Autorizaciones de Regreso Cartas de invitación Certificados de Residencia Duplicado de TIE Cita previa para trámites de Policía Debe dirigir su consulta a la Comisaría de la Policía Nacional que le corresponda por su localidad de residencia. Para información sobre protección internacional (tarjeta roja) o citas para la entrevista debe dirigirse a la Comisaría Provincial de la Policía Nacional. En estos casos, su consulta ya ha sido contestada. Por favor, no reiteren sus consultas, no disponemos de la información. Muchas gracias por su colaboración. Reciba un cordial saludo." ··························································································································································································· Llamo a la Comisaria Provincial de la Policia Nacional de Málaga (952 04 62 00) varias veces sin respuesta. ························· Llamo a la Brigada Provincial de Extranjería y Fronteras de Málaga (952 04 64 68 / 952 046 213): Me comunican que al ser ciudadano comunitario, **sólo necesaitaría el pasaporte o tarjeta de identidad de Rumanía en vigor, pues el Certificado de Registro de Ciudadano de la Unión no caduda, pero sin el Pasaporte o tarjeta de identidad no tiene validez. ··········································································································································································································· Llamo al Consulado de Rumanía de Sevilla (954 62 40 53 / 954 233 243 / 954 624 070 / 954 230 947): No obtengo respuesta en ninguno de ellos. ···· *Envío e-mail a la dirección que aparece en la web del Consulado (sevilla@mae.ro): "Buenos días, Me pongo en contacto con ustedes, desde la Comisión Tutelar de Adultos de la Junta de Extremadura, para solicitar información a cerca de los trámites a realizar y documentos necesarios para la obtención de la Tarjeta de Identidad o el Pasaporte de un joven natural de Rumanía del que recientemente se nos ha asignado la Tutela mediante sentencia judicial. Agradecería me comuniquen a la mayor brevedad todo lo necesario para poder iniciar los trámites lo antes posible, con el objeto de ejercer el cargo de forma adecuada y poder procurar a nuestro tutelado la protección y recursos que necesita. Gracias por adelantado. Un saludo." ····················································································································································································· Llamo a María González Palomo, T.S. de la Fundación Autismo Sur de Málaga (693 759 016): Le informo acerca de las gestiones realizadas hasta ahora. ···························································································································································································· Tras reiterar la petición, recibimos del Dulce Nombre de María Certificado de Ingreso en centro, con fecha de ingreso y fecha de salida del recurso. *Se lo envío a Ángel y Miguel, Asesores Jurídicos CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-12-17','Con motivo de la Ejecutoria 30/2020, dictada por el Juzgado de Primera Instancia nº 1, de Llanes (Asturias), en el que le requieren al pago de una multa de 180 euros, enviamos escrito al Juzgado, a través del correo electrónico (mixto1.llanes@asturias.org), solicitando nos remitan documentación relativa a este procedimiento y número de cuenta iban donde poder realizar el pago mediante transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-12-17','miguel, me pregunta Juana si está o no confirmado por el juzgado el abono de las cantidades a que fue condenado. Entiendo que sí ya que desde el fax que remití el 30-9-20 no nos han dicho lo contrario y además el 3-11-20 me dieron desde el juzgado nº de cuenta y concepto. La pido que comiencen ya los pagos al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2020-12-17','miguel, escribo al mediador de la venta de la rústica en Alburquerque Jesús Lara Bueno:entiendo que recibe entonces 1/3 parte y que gastos no conlleva con lo que recibirá entre 1800 y 2000€ por la venta. Es así? Por nuestra parte no hay problema para que hagan dicha venta y sea firmada por la curatelada si está de acuerdo. La Comisión Tutelar de Adultos una vez firmada la venta ratificaría en la notaria de Mérida de Romero Leal el mismo día o máximo al siguiente, para lo cual la notaria de Alburquerque deberá remitir telemáticamente la compraventa a la notaria de Mérida tras la firma de la venta. En cuanto al ingreso deberán hacerlo al siguiente nº de cuenta de Ibercaja 2085 4509 83 03330383127 indicando en el concepto venta de la rústica nº de finca 7165 Ba2. Indíqueme la fecha en que se firmará con una antelación de una semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-12-17','TERESA salida el próximo martes 22 de diciembre y regreso el miércoles 13 de enero de 2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-12-17','TERESA miércoles 5 de enero de 2021 hasta el miércoles 20 de enero de 2021. Volveríamos a realizar las gestiones como la vez anterior con la Trabajadora Social de la localidad para que se le pudiera realizar prueba PCR necesaria para reingreso en la fecha indicada.','2');
