insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2020-12-17','miguel, envío email a Alberto y Juana de valores fiscales parecidos al acuerdo que se quiere llegar de reparto. En cuanto a los valores fiscales de las fincas objeto de reparto son los siguientes: 7499304PC7979N0001ID casa de la Dehesilla del Calamon, valor fiscal 209.057,50€ ******************************************************** Juana habla con la exmujer Yolanda: Acabo de hablar con Yolanda, ella no está para nada de acuerdo con el reparto, según su valoración el local estaría en 60.000 euros y la dehesilla en 300.000 euros (parcela de 5.000 m2 con casa de 300 m2 y nave de 80 m2). Ha quedado en preguntar a una amiga suya que tiene una inmobiliaria para que le diga a ver en cuanto puede ella valorarlo. Con respecto a las fincas rústicas que mencionas no me ha comentado nada Fco. Javier del reparto, le pregunto el próximo día a Yolanda. 5141301PD7054A0031GQ local comercial, valor fiscal 54.111,82€ En cuanto a las 4 fincas rústicas: 7499304PC7979N0000US, valor fiscal 268€ 7499303PC7979N0000ZS, valor fiscal 273,15€ 7397706PC 7979N0000HS, valor fiscal 251,35€ 06900ª291000790000EP, valor fiscal 2.964€ Por tanto, coincide con lo hablado ayer y si estamos todos de acuerdo, estaría correcto. Recordemos que hay que avisar al abogado que el curatelado es únicamente propietario en las 4 últimas rústicas indicadas propietario del 8,34€. En cuanto me deis el visto bueno hablo con el abogado para poner en marcha el reparto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2020-12-18','TERESA EMIAL DE CAJA ALMENDRALEJO Con respecto a la Incapacitación de D. BARTOLOMÉ COLCHÓN CARMONA (11912387C), le manifestamos que en nuestra Entidad no teníamos conocimiento de que se le hubiese incapacitado judicialmente, por lo que, no se nos había presentado con anterioridad a su gestión la sentencia con testimonio de firmeza de declaración de la incapacidad. Les insistimos y les rogamos que entiendan que nos resulta necesario para calibrar el alcance de la incapacitación. Ya que pudiera estar incapacitado total o parcialmente y sometido a tutela o a curatela, por ejemplo. Al señor gerente el Juzgado que la dictó es quien le dará copia. Si debería estar en nuestra posesión no lo estaba porque D. Bartolomé no aparenta estarlo y el padre no hizo manifestación ni entrega de documentación alguna al respecto. NO PODEMOS SOLUCIONAR LA PROBLEMATICA CON EL BANCO PORQUE PARA PODER PONER A JOSE VICENTE EN LA CUENTA NOS PIDEN LA SENTENCIA DE INCAPACITACION Y NOSOTROS SOLO TENEMOS LA DE REMOCION LA HEMOS SOLICITADO AL JUZGADO SE HA AUTORIZADO UN EXTRA PARA QUE PUEDA TENER DIENERO FUTUEX VA A HA REALIZAR VISITA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2020-12-18','TERESA el pasado 15 de Diciembre se recibe una llamada a primera hora de la mañana de Rosa, de los SSB de Higuera. Rosa comenta que el domingo de madrugada se llevaron a Josefa, la madre de José Antonio a Llerena porque tenía una perforación intestinal y había que operarla de urgencia. José Antonio se fue con su madre y lleva con ella en el hospital desde entonces. Seguidamente se llamó a la trabajadora social del hospital de Llerena, Isabel Pilar para comentarle que se iba a ir a Llerena para pasar a ver a José Antonio, para hablar un rato con él y ofrecerle apoyo en estos momentos tan complicados para él. Al ir al hospital, pasamos por el despacho de Isabel y comentamos un poco el caso del tutelado y de su madre, ésta comentó que una tía de José Antonio y una prima acababan de llegar de Huelva. Se avisa a José Antonio de la llegada del Equipo social comunitario y éste pide que se suba al pasillo de Trauma porque él no puede bajar. Se le ve dando paseos nerviosos de un lado para otro y diciendo que están curando a su madre y le han echado de la habitación. Se le pregunta cómo se encuentra y comenta que está bien pero preocupado por su madre porque la ve muy mal. Se le intenta tranquilizar un poco aunque que la familia esté allí no ayuda mucho. Se le pregunta si se ha llevado la medicación y contesta que si, pero que para el día siguiente ya no tendrá. Se conversa un rato con los familiares de José Antonio en el pasillo y se pasa otro rato más con el tutelado, se le comenta que se le llamará a menudo para hablar un rato con él y para preguntar por el estado de su madre. Y se le dice que se hablará con la trabajadora social del hospital para intentar arreglar el tema de sus medicación. Se baja al despacho de Isabel y se le cuenta la problemática de la falta de pastillas del tutelado, se le comenta que la psiquiatra de José Antonio es la Dra. Marisa Álvarez de Zafra e Isabel dice que va a hablar por su coordinador para plantearle la situación. Probablemente desde el hospital se pongan en contacto con salud mental de Zafra y se le pueda facilitar medicación a José Antonio para el tiempo que su madre pase ingresada. Se queda con Isabel en llamar a diario para conocer el estado de Josefa y para conversar un rato con el tutelado. Seria bueno que esta mujer pudiera alomejor ir algun centro desde el hospital, dado que tanto la convivnecia con el hijo como las necesidades de apoyo que precisa lo requerrian pero no sabemos si esto seria factible ME COMUNICA ROSA TS DE HIGUERA QUE HA FALLECIDO LA MADRE DE JOSE ANTONIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='QUINTIN'and edp.apellido1='SANCHEZ'and apellido2='ALAMILLO'),'2020-12-18','TERESA • El tutelado tiene CCC en Banco Santander (dfesconocemos a día de hoy la información y además el banco nos pone problemas: incluso habla de que debemos hacer testamentaría porque en la CCC esta la mujer del tutelado fallecida) • Iciar ha habierto CCC en LIBERBANK y le pasa el nº a Tere para que pase la pensión (Jubilación: 899,16 € x 14). En diciembre Tere ha hecho la solicitud. • B santander informa que alguien está sacando dinero de la CCC. No sabemos quién: o Tere hablará con centro para averiguar si son ellos quienes sacan el dinero. o Tere pedirá información sobre CCC al centro. o El centro sigue DOMICILIADO en BSantander o El Seguro Deceso (SANTA LUCÍA), sigue domiciliado en BSantander. TERE: TE ENCARGAS DE RECORDARLE A CORAL QUE PIDA LA PÓLIZA A SANTA LUCIA. o CAMBIAR CCC RECPCIÓN VINCULADA A LIBERBANK','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GALLEGO'and apellido2='CALDERON'),'2020-12-18','TERESA En relación con la tutelada os pongo al día sobre su situación: • EDAD: 95 años (nacimiento en 1.926) • Tiene 2 CCC siendo el saldo actual total: 16.436,52 € Este saldo no es real ya que, dado que x EDAD no tiene seguro DECESO, si presupuestamos este x 3.000 € aprox., el saldo sería de 13.436,52 €. • INGRESOS: sumadas pensión (395,60x14), prestación Junta (625,47x12) e ingreso x alquiler (150x12)= 1.237 €/mes • GASTOS: 1.452 €/mes o Paga centro GAMEX, x una media mensual de 1.400 €/mes o OAR: 21 €/mes o Otros: 31€/mes • DIFERENCIA ING-GTO: 1452-1237= - 215 €/mes = 2.580 €/AÑO • Con este nivel de ingresos y gastos tendríamos para 5 años aprox. (13.436,52/2580= 5,2), SI SOBREPASA ESTE PERIODO HABRÁ QUE BUSCAR UN CENTRO QUE PUEDA ABONAR TERE: ANOTATE ESTA TUTELADA PARA VERLA DENTRO DE 1 AÑO O MÁS (LO QUE CONSIDERES DOY EL OK A LA BADAJA DEL AQUILER REVISAMOS EN UN AÑO CUENTAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2020-12-18','Ana: Llamo a Pilar Cerrillo, TS de la Res. (618 90 85 06): De cara al ingreso de Mateo en los PP.TT. de Alcuescar, desde la CTAEX no podemos firmar el documento que remiten "Declaración de responsabilidad de los familiares de los gastos de sepelio en caso de fallecimiento". No habrá problema. No obstante en cuanto se pueda se le contratará un Seguro de Decesos. La solicitud ya está firmada y sellada. En cuanto tengamos firmado el resto de documentos (secc. ecca.) se lo adelantaré escaneado y a posteriori por correo certificado los originales. Me indica que se lo envíe a la Res. San Jorge (C/Héroes de Baler) de CC a su atención. *La documentación a aportar la tienen ellos. *Procurarán el ingreso en los PP.TT. antes de que finalice el año.','2');
