insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-12-14','(Pedro)Correo de Amalia del 14 de diciembre: +++Buenos días , Hostal Senero , tf 924317207 , la habitación cuesta 25€ la noche . De momento he cerrado para una semana ( de viernes a viernes ) e irán enviado la factura semanal a ctutelar para que se abone . Mi intención es que permanezca ahí por lo menos un mes , se quiere ir a Palafolls y eso no podemos evitarlo pero dado a las limitaciones y restricciones para la movilidad entre Comunidades por el covid , considero que es más seguro que se quede un tiempo y luego se marche si es su deseo. Con la asignación semanal tiene que cubrir sus gastos de manutención y ropa . Tiene dinero ahorrado , creo que puede cubrir sin problemas la estancia de hostal . Si consideras que no es viable económicamente y hay que reducir su asignación se lo puedes comentar el viernes. A nivel sanitario , su psiquiatra en la UHB considera que está compensado y que no es necesario derivación al Centro sociosanitario . Desde la parte social , toda la intervención posible se ha realizado . Seguimos en contacto. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2020-12-21','(Pedro)Correo de Pilar, T. Soc. del Hogar San Vicente de Paul: +++Buenas tardes, les informamos que el viernes, día 11, dio positivo por Covid 19 una de las trabajadoras del Hogar San Vicente de Paúl. Ayer, día 14, nos hicieron una PCR a las residentes y trabajadoras y hoy, cuando nos han dado los resultados, una de nuestras residentes también es positivo. No es Mª del Carmen, pero quería que supieran que estamos aislados debido a la situación acaecida. Esta mañana, llamé por teléfono, pero no pude contactar con ustedes. Deseo que se encuentren bien. Un saludo Pilar Sánchez','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2020-12-21','Ana: Correo de Sonia Bernabé, Asindi, el sábado por la tarde: "Hola Ana, te escribo para comunicarte que ha fallecido la hermana de Juan Gabriel Sobrino Tardío, Araceli. Su familia nos ha llamado para comunicárnoslo y porque quieren que se vaya a casa con ellos un mes aproximadamente. Llevan un año sin verse, y aunque Juan sabía que su hermana estaba enferma, dudo que conociera la gravedad. Queremos organizar la salida, si la autorizáis. Te mando el modelo de solicitud para ver si autorizáis y quedamos todo organizado el lunes por la mañana. Te llamo el lunes y lo concretamos. Un saludo" ···································································································································· Tras intercambiar correos y mantener conversaciones con Sonia, Asindi, y con Pedro, CTAEX, se decide autorizar dicha salida. *Juan será atendido por su cuñado (esposo de su hermana fallecida) y su sobrina. Saben que hubiera sido el deseo de su hermana y quieren cumplirlo. ······ Se recabará la firma en cuanto nos envían la solicitud cumplimentada. ··············· *Envío a Sonia escaneada la Autorizacion firmada. ········· Estará con su cuñado y su sobrina del 21/12/2020 al 23/01/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-12-21','Ana: Llamo al hospital de Mérida (924 38 10 00), me pasan con el UHB. Emilia continúa ingresada. La Dra. Álvarez no está esta semana. La Dra. Virginia está ocupada, pero le pasan nota con los teléfonos para que nos llame cuando pueda a Pedro o a mí. ++++++++++++++++++(Pedro) Llamada la Dra Gajardo, Psiquitra de la UHB de Mérida (81284). +++DªEmilia sigue ingresada desde el pasado día 10 de diciembre. No se le ha dado antes el alta porque consideran que es una forma de que entienda que no se pueden estar utilizando los recursos de manera caprichosa. +++Si sigue así, tiene prevista el alta entre hoy y mañana. +++Se le comenta el tema pendiente de la canalización a Málaga y que la "pareja" con la que actualmente dice convivir, auqnue la desconocdmos, sí que es verdad que según a ella le interesa habla bien o mal de ella. +++Volverá a hablar con ella y si sigue igual le dará el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-12-21','(Pedro) Correo de Futuex del pasado 18 de diciembre (se guarda también en su expediente virtual, carpeta futuex/seguimiento 2020: +++A continuación aportamos nueva y grave situación de el tutelado Saturnino Miguel Salgado Jiménez, por si no se hubiera dado traslado aun a la CTAEX: 16/12/2020 A primera hora de la mañana y aprovechando el acompañamiento de otro tutelado a la consulta de psiquiatría de salud mental, y dada la coincidencia de profesional se mantiene conversación, en privado, con la Dra: Wendolin, psiquiatra actual del tutelado para realizar seguimiento sobre su estado actual y la toma de medicación, la dra. transmite que se estableció con el compromiso de realizar tratamiento oral en lugar de inyectable, dato notificado en anteriores comunicaciones, se trasmite a la psiquiatra la escasa conciencia de enfermedad del tutelado y la consecuente resistencia al tratamiento en cualquiera de sus formas por lo que se considera adecuado que se le haga mayor seguimiento con citas más frecuentes, dato que acude a consulta desde septiembre, la doctora recoge la solicitud y expresa que se le citaría pronto. Pasadas 2 horas aproximadamente, se recibe llamada de Paco, hermano de Saturnino y su único apoyo desde que el estado de salud de su madre empeoró. Y transmite que hace 3 ó4 días que no saben nada de Nino y está en comisaría para poner una denuncia o averiguar algo sobre su paradero. Se contacta con el equipo de salud mental de nuevo y se transmite la situación a la psiquiatra del tutelado que comprueba que no ha habido atenciones en urgencias ni ingresos hospitalarios en los últimos meses, por lo que se descarta que pueda estar ingresado en algún centro hospitalario. Por la tarde, del mismo día se recibe nuevamente llamada de Paco, para comunicar que el pasado día 11 de diciembre fue detenido en su domicilio y el día 12 pasó a disposición judicial, por lo que se encuentra recluido en el centro penitenciario de Cáceres acusado de un delito de violación. 17/12/2020 Se recibe de nuevo varias llamadas de Paco, hermano de Saturnino para comunicar que Nino se ha puesto en contacto con ellos para ropa y dinero les ha explicado que para poder disponer de dinero en prisión se debe abonar en una cuenta de la institución y para ello se necesita que la CTAEX realice o autorice esta gestión y se ponga en contacto con el centro penitenciario. Más tarde se recibe sms de Paco (Hermano de Nino 630211717) donde aporta el num. de cuenta para la gestión bancaria y el número de tf. del centro penitenciario, a continuación, se reflejan los datos recibidos: ES75 0049 6747 8320 1601 6108 Tf: 927181799 Nos ha impactado enormemente esta informacion, desconocemos las circunstancias, entendemos estará pendiente de juicio... o no sabemos en que punto del procedimiento penal que suponemos se habra iniciado contra el, por la comision o la tentativa de un delito tan grave.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-12-21','Ana: Ante la respuesta del Consulado de Rumanía; "Buenos dias, Con el fin de poder darles información acerca de los tramites para documentar al joven, rogamos nos indiquen, o en su caso, nos envien: -la situación en la que se encuentra el joven, ya que nos indico que se encuentra tutelado -la sentencia del tribunal competente -los datos personales del joven (nombre, apellidos, fecha de nacimiento, lugar de nacimiento) -si posee algún tipo de documentación emitida por Rumania Atentamente", **envío el siguiente correo con la documentación pertinente adjunta: "Buenos días, Tal y como me solicitan, le envío adjunta la siguiente documentación relativa a Costi Alexandru Rizea, nacido en Alexandría, Rumanía, a fecha de 21/09/2002, tutelado por la Comisión Tutelar de Adultos de Extremadura: - Testimonio de la Firmeza de la Sentencia Incapacitación - Testimonio de Aceptación del Cargo de Tutor - Pasaporte emitido por Rumanía (Caducado en marzo de 2016) - Certificado de Registro de Ciudadano de la Unión Europea Espero indicaciones para solucionar su situación administrativo-legal, con el objeto, tal y como ya indiqué, de ejercer el cargo de forma adecuada y poder procurar a nuestro tutelado la protección y recursos que necesita. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-12-21','(Pedro)Hablo con Emi, T. Soc. del Centro Penitenciario de Badajoz (924-289117). +++En relación a la multa (180 euros) que debe pagar por el robo de un queso en el Carrefur (Jonathan ha llamado antes para decir que si no pagábamos la multa no podría salir mañana de prisión).Emi no sabe nada al respecto, pero tratará de enterarse y nos llamará. +++La multa se pagó el pasado 6 de noviembre de 2020, pero la devolvieron al haberse abonado fuera de plazo y embargaron la cuenta.LA MULTA ESTÁ PAGADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-12-11','(Pedro)Llamada al Dr. Agapito al CSS de Plasencia. +++No consigo comunicar con el Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-12-21','(Pedro)Nueva llmada de Jairo. +++Quiere cumplir la pena en el CSS de Mérida. Quiere solicitar abogado de oficio para ello. +++Según él, el Dr. Agapito está dispuesto a enviar Informe al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='RODRIGUEZ'and apellido2='RASERO'),'2020-12-18','EXITUS. Nos comunican su fallecimiento desde el SSB, en el Hospital de Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2020-12-21','(Pedro)Se contesta al correo, de 14 de diciembre de 2020, de Rosa Bravo (CSS de Plasencia)en relación al ingreso de D. Juan Carlos en la UHDAC: +++Se adjunta la documentación firmada por el Vicepresidente de la CTAEx.Se enviará también por correo ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-12-17','Ana: Envío un email a Vanesa: "Buenas tardes Vanesa, Aún estoy a la espera de que nos me remitas el contrato de trabajo y certificado de empresa de los últimos contratos (agosto de 2020) y el contrato en “Hostelería El Polígono CB” desde marzo de 2020 hasta la actualidad. Te adjunto el documento que nos han enviado. Como te expliqué la semana pasada mediante conversación telefónica puedes tener problemas con la pensión, te la pueden suspender si no lo presentas. Si no me lo envías no podré intentar ayudarte. Espero tu respuesta. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-12-21','Ana: Recibo llamada de Joaquín, Técnico de la Mancomunidad, Programa de Atención a Víctimas de Violencia de Género (927 345 117). A Vanesa le han concedio una ayuda como víctima cuya cuantía asciende a 2.341 €, que debe justificar. Ha de presentar recibos. Al parecer según le ha dicho a Joaquín le ponen problemas en el banco. ················· Envío email a Icíar: "...¿Sería posible imprimir en PDF los recibos de la cuenta de Vanesa y enviárselos a Joaquín por mail? Su dirección es: jsachezg@gmail.com y los recibos que necesita son al menos los siguientes: - Alquiler del a vivienda - Agua Ya me dices. Muchas gracias" ·········································································································································· Respuesta de Icíar: "Ana, les estoy comprobando la cuenta de Liberbank a Vanessa, en negativo, y desde el 3 de febrero de 2020 no se ha vuelto apagar ningún recibo de alquiler, supongo que este le haríamos nosotros antes de que ella pudiera gestionar todo. De agua tampoco hay nada, de hecho en la cuenta a laque nosotros tenemos acceso no hay ningún recibo. Es todo lo que te puedo decir, no podemos enviar nada" ······················· Respondo con copia a Ángel y Miguel, Asesores Jurídicios, entiendo habrá que comunicarlo al Jdo. ··························· Llamo e informo a Joaquí, Técnico de la Mancomunidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-12-21','(Pedro)Correos de D. Francisco Villegas (Hermano) del 12 de diciembre de 2020: +++¡AH! PARA TU CONOCIMIENTO MI HERMANO PEPE.-TIENE UN BUEN SEGURO TODO CUBIERTO Y UNA BUENA PÓLIZA CON UNA MÁXIMA COBERTURA LA QUE ESTA EXENTA DE PAGAR NADA DE NADA. CON LA COMPAÑIZA SANTA-LUCIA, CON SEDE EN LA CIUDAD DE PLASENCIA. CON DOMICILIO : Avdª La Salle,49.- Tel 42.14.90 Un abrazo ________________________________________ De: Francisco Villegas Enviado: sábado, 12 de diciembre de 2020 9:31 Para: Pedro Miguel Gracia López >pedromiguel.gracia@salud-juntaex.es> Asunto: mi hermano Pepe. BUENOS DIAS PEDRO-MIGUEL: Estoy en la certeza que mi hermano José-Pedro Villegas Serrano; esta ingresado desde hace unos días en el HOSPITAL de Plasencia habitación 519. por CORONAVIRUS. Se lo han COMUNICADO A LA COMISIÓN TUTE LAR DE ADULTOS. ¿Es así? ESPEREMOS QUE SE RESTABLEZCA PRONTO. Y VUELVA A LA RESIDENCIA DE ANCIANOS DE NAZARET. NO y NO A OTRO LUGAR. TE SIGNIFICO PEDRO-MIGUEL: Y ASI TE LO PIDO QUE CUANDO FALLEZCA MI HERMANO. POR FAVOR NO LLEVES AL CREMATORIO. EL FUNERAL EN LA CIUDAD DE CORIA EN SU PARROQUIA QUE ES SAN IGNACIO DE LOYOLA DE LA CIUDAD DE CORIA. Y UNA VEZ CELEBRADA LA MISA SU CUERPO AL CEMENTERIO EN CORIA. ASI ME LO PIDIO MI HERMANO. por lo tanto cumplamos su voluntad. RECIBE ESTIMADO AMIGO PEDRO-MIGUEL. Un cordial saludo y deseando que se restablezca pronto Pepe. +++Llamo al Hogar de Nazaret para confirmar esta información, pero no cogen las llamadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2020-12-21','Ana: Tras varios contactos e intercambios de correo, tanto con el CRR-CC como con Marisa González, Técnica PIA (927 00 67 88), se decice que se solicitarán los centros cercanos al municipio en que reside su hija, con quien mantiene buena relación. ········· Adelanto a Marisa la ACEPTACIÓN PIA firmada electrónicamente. Mañana la pondré para registro de entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-12-22','Ana: Envío por fax a Noellia, T.S. Res. Cervantes, la póliza del Seguro de Decesos de Eugenia, pues al enviarlo por mail no se le abría correctamente y no podía leer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2020-12-22','Ana: Correo de ayer por la tarde del Consulado de Rumanía en Sevilla (sevilla.consul3@mae.ro): "Buenas tardes, Analizados los documentos adjuntos, nos surge la pregunta de si disponeis de la partida de nacimiento rumana en original, ya que a la hora de emitirle un pasaporte, la partida de nacimiento es fundamental. Rogamos pues, nos diga si dispone de ello. Cordialmente," ············································································· Mi respuesta: "Buenos días, No disponemos de la partida de nacimiento. ¿Podría informarnos sobre dónde y cómo solicitarla? ¿Se demoraría mucha esta gestión? No sé si ustedes podrían interceder para que sea más ágil. Espero su respuesta. Gracias de nuevo y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2020-12-18','Ana: Pongo para la firma del D.Gerente, varios documentos remitidos por Cruz Blanca, entre ellos informe con valoraciones de los distintos profesionales. *Escaneo éste y lo archivo en el expte físico y digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-12-22','Ana: Pongo para la firma del D.Gerente, varios documentos remitidos por Cruz Blanca, entre ellos informe con valoraciones de los distintos profesionales. *Escaneo éste y lo archivo en el expte físico y digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2020-12-22','Ana: Pongo para la firma del D.Gerente, varios documentos remitidos por Cruz Blanca, entre ellos informe con valoraciones de los distintos profesionales, que piden devolvamos firmado. *Escaneo éste y lo archivo en el expte físico y digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-21','Ana: Correo de Toni-Futuex: "Se contacta con el Área de TS del equipo de Salud Mental Ronda del Carmen de Cáceres para comunicar la nueva situación de la tutelada, pero comunican que Pilar Martín, la trabajadora social del equipo, está de vacaciones y no se incorpora has el día 28 de diciembre que es el día que Clementa se queda sin cuidadora. Se contacta por tanto con el Centro de Salud de referencia “Manuel Encinas” y se mantiene conversación con Mª Ángeles Rodríguez Trabajadora Social del centro. Cuya extensión telefónica es la siguiente, 630300088852937. En conversación se le informa de la situación actual de Clementa y de la marcha inminente de la cuidadora, por lo que existe necesidad real de buscar soluciones, se le transmite también que desde la CTAEX se solicita informes médicos y de trabajadora social para solicitar ingreso involuntario, dado que no se dispone del consentimiento de Clementa. Ella propone realizar visita conjunta mañana martes 22 de diciembre a las13:00 hrs. y trabajar la aceptación de ingreso y en caso que no aceptara poder notificar a fiscalía la situación. Ingreso, que según informa Mª Ángeles se podría hacer en un plazo breve de días en un centro acreditado por la ley de dependencia ya que está valorada con un Grado III, aunque en la documentación que aporta la tutelada aparece como GRADO II. Mañana una vez se realice la visita conjunta desde equipo informaremos tb"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-12-22','REGISTRO. Se envía por registro de entrada solicitud de cambio de PIA a recurso RAE. Quedamos a la espera de que nos devuelvan el original registrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2020-12-22','TELÉFONO DE PISO SUPERVISADO DE ZAFRA: 650-266760. Lola (Psicóloga). +++Visita de Dª (Teo)Dora Salamanca, madre de Framncisco, informando que no ha llegado al centro el "OK" para lñas vaccaiones. Me pongo en contacto con Lola para confirmarlo. +++Se remite autorización de vacaciones para salir con la familia. Lo envía Juan Pedro por correo electrónico (pszafra@feafeszafra.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2020-12-22','-Adjunto se envía informe de visita presencial al tutelado Alejandro Nuñez Bono. En relación a la necesidad de tener ocupado el tutelado algunas horas al día en actividad de trabajo ocupacional, como ayuda a una organización de su rutina diaria, se ha contactado con la Fundación Sorapan de Rieros, (Marian, resposable de rehabilitación laboral-ocupacional) que ya estuvo trabajando con él. Desde la Fundación ofrecen talleres de: Manualidades en cuero (lunes y miércoles) e informática (martes y jueves) en horario de mañana. Hay que solicitar derivación a este recurso ocupacional desde su área de salud mental (Valdepasillas) con un informe derivación de su trabajadora social (Carmen Díaz). Se sigue gestionando que la consulta de psiquiatría se haga de manera presencial. Su próxima cita de control en CEDEX es el 12 de Enero 2021, a la que acude sin registrar oposición ni incidencia, pero hasta la fecha no deja de consumir. cManteniendo la misma rutina diaria de no control horario, de comida, sueño, ect.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2020-12-16','Te escribo para notificarte que Manuel C.M ingresó el día 13 de diciembre en el HUB por descompensación en su patología mental. Está previsto que sea un ingreso corto y tras ajustar medicación regrese al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='LIRON'),'2020-12-22','llega requerimiento del jzdo nº2 de Navalmoral del procediiento de división de herencia 43/2010 donde se refieren a provisión de fondos de perito. Desde el jzdo me indican que está al corriente de todo el compañero de la Ctaex (nº de cuenta al que hacer el ingreso, concepto, etc), se lo remito a Angel vía email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-12-22','Ana y Pedro: Llamada al Centro Penitenciario de Cáceres (927 18 11 45), habla con Maite, TS, confirma que Saturnino Miguel ingresó en el centro el día 12 de diciembre. Hasta hoy ha estado en aislamiento por la pandemia Covid. No sabía que está tutelado. Se remite por fax (927 18 11 50) a la atención del Director del C. Penitenciario, información actual de la situación. Se les remite Sentencia de incapacitación y aceptación del cargo. *Reporte Ok. **Pendiente solicitar nº de cuenta peculio y presupuesto de gastos de bolsillo para que se le haga ingreso desde la CTAEX. +++D. Saturnino ingresó en el Centro el pasado día 12 de diciembre, terminando el aislamiento preventivo por covid en el día de hoy. +++Causa de la prisión provisional: a.sx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2020-12-22','Ana: Redacto oficio y lo pongo para registro de salida para remitir Hoja de Inscripción en el Padrón Municipal de Alcánatara, que ya nos han devuelto de firma del D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-12-22','Ana: Redacto oficio y lo pongo para registro de salida para remitir Hoja de Inscripción en el Padrón Municipal de Alcánatara, que ya nos han devuelto de firma del D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-12-18','Ana: Recibimos informe de la Asoc. Vera, detallando todas las incidencias acaecidas con Adrián desde su ingreso. Expresan que "...está en peligro la integridad física de los usuarios e integrantes de la asociación." Expresan haber implementado un Plan de Modificación de Conducta, tal y como se les indicó en abril desde el SEPAD, pero no han obtenido ningún resultado positivo. "...después de una amplia valoración por el equipo multidisciplinar del centro, hemos determinado que su estancia en el mismo no es posible..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-12-22','Ana: Tras hablar con Pedro, Jefe de Secc., sobre la situación de Adrián en la Asociación Vera, se le remite el informe a Soraya Masa, Jefa de Ud. de RR. AA., mediante Nota Interior. ····································································································································· Envío correo-e a Cristina Castro, Ed. Soc. Aso. Vera: "Buenas tardes Cristina, En relación al informe que nos habéis remitido, relativo a las incidencias protagonizadas por Adrián, comunicarte que hemos remitido el mismo a la Jefa de Unidad de Recursos Asistenciales del SEPAD. Cualquier otra incidencia que pueda ocurrir, por favor, transmitirlas a dicha unidad, aunque también nos la comuniquéis a nosotros para que seamos conocedores. Ya sabéis que es en dicha unidad a quién corresponden las gestiones de cambios de centros. Por otra parte, no dudéis en activar el 112, cuando Adrián presente alteraciones de conductas inabordables por profesionales del centro así como interponer las denuncias pertinentes cuando sea necesario. Pongo a Pedro, jefe de sección, en copia. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-12-22','Ana: Correo de Blanca, CRR-Plas. (coordinaciontecnica.crrplasencia@grupo5.net): "Buenas tardes, Respecto a Damián Salvador Granados Heredia os enviamos la carta que hemos recibido en el CRR una abogada con la que ha contactado Damián. El documento es para que lo firme él, pero entendemos que por su situación legal, el no puede firmar estos documentos. Damián hoy no nos ha querido comentar qué trámites desea hacer, entendemos que también tiene que ver con. La petición de la nueva valoración del grado de dependencia. Un saludo." **El documento no se puede leer, el formato en que lo envían no debe ser compatible. *Pediré que vuelvan a enviarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2020-12-23','Ana: Correo de Noelia, TS C.R. Cervantes (noelia.garciac@salud-juntaex.es), al ctutelar@: "Hola! Adjunto carta que ha llegado al centro de Mª Luisa Montaña Aliseda. Es para que desde la comisión se autorice o no la realización de dicho test. Espero respuesta lo más rápido posible Saludos" *Carta sobre el Programa de Diagnóstico Precoz de Cáncer Colorrectal. "...test sencillo para detectar presencia de sangre oculta en heces..." ······················ Mi respueta: "Buenos días Noelia, Con respecto a la carta informativa que os han enviado y nos adjuntas, en mi opinión, siempre que no haya contraindicación médica al respecto, es recomendable hacer este tipo de pruebas, por ello, agradecería realizaras las llamada que indican al Centro de Salud para pedir cita y que te faciliten más información al respecto. Pongo en copia a Pedro, Jefe de Sección, para que esté al corriente y por si quiere añadir algo. Un saludo y felices y saludables fiestas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-12-23','(Pedro)Envío correo electrónico a Maite, T. Social del C.Penitenciario de Cáceres (927-181145). +++Remito teléfonos de contacto de sección social y económica (para tratar el tema de la cuenta peculio). +++FAX C. Penitenciario: 927-181150. +++Correo-e: trabajosocialcpcaceres@dgip.mir.es ++++++++++++++++++++++++++++++SE recibe por fax información relativa a D. Saturnino, en contesatción a nuestro fax, dirigido al Director del C.Penitenciario, solcitando información de la situación de nuestro tutelado: +++"Por la presente informo que el interno arriba indicado INGRESÓ en prisión el 12 de diciembre de 2020 en calidad de preventivo a disposición del Juzgado de Instrucción nº 6 de Cáceres en D. Previas 751/2020. Ha permanecido en cuarentena 10 días, según el protocolo seguido en el centro Penitenciario con los ingresos de libertad, pasando el día 22 a un módulo de régimen de vida ordinario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-12-22','(Pedro)Conversamos Ana y yo con el Dr. Agapito, del CSS de Plasencia (24140). +++Tema: deseo de Jairo de cumplir la medida de seguridad en el CSS de Mérida. +++El Dr. Agapito considera que no existe motivo clínico para realizar un informe justificando esa petición, la cual solamente parte de un deseo de Jairo de salir del CSS donde es cierto que lleva muchos años, pensando además que en otro centro va a sentirse mejor, lo cual no es posible tampoco asegurar dado que la atención que pudiese recibir allí no va a ser ni mejor ni pero que la que actualmente recibe en el CSS de Plasencia. +++Agapito le ha planteado la posibilidad de derivar a CRR o Piso Supervisado, pero Jairo se niega. Aunque el pide salir del Centro, cuando se le plantean estas posibilidades se niega a aceptarlas, alegando que el quiere una vida normalizada (piso de alquiler compartido, etc.), pero quizá se deba al temor que pueda sentir, al vértigo de salir de una situación conocida a otra que le genera incertidumbre. +++Planteamos a Agapito la posibilidad de que se pueda acompañar a Jairo a Hacer una visita al CRR para que lo conozca (tanto Agapito como nosotros consideramos que el CRR puede ser un recurso más apropiado para él al menos en estos momentos, dada su necesidad de supervisión). Agapito parece ver bien esta posibilidad y plantea intentar ponerla en práctica una vez transcurridas las vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2020-12-23','Ana: Envío correo-e a Ana Benavente, TS del ESM-Plas. (anamaria.benavente@salud-juntaex.es) "Buenos días Ana, Espero que tanto tú como tu familia estéis bien. No sé si estarás de vacaciones, así que te escribo y ya cuando puedas me contestas. En relación a Damián Salvador Granados Heredia, decirte que me ha llamado varias veces, sigue preocupado con la reclamación de revisión de su grado de dependencia. Me dijo que le habían cambiado la Psiquiatra y que la nueva ha emitido nuevo informe que podría servirle para presentar de cara a la nueva valoración. Qué al parecer no pasó a recoger dicho informe por no molestar. No sé si todo esto que comenta es así. En tal caso, ¿podrías corroborármelo? Y si hay tal informe a favor de sus solicitud, ¿crees que podríamos presentarlo o enviárselo al equipo de valoración? Ya me vas diciendo. Un saludo y felices y saludables fiestas! Cuídate."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-12-21','Ana: Correo-e de Toni, Adiser Horizontes (adiser@castuera.es): "Buenos días Ana, me pongo en contacto contigo para que me orientes sobre la manera de proceder: La madre de Aitor lleva llamando desde la semana pasada para notificar que se va a pasar las navidades a su pueblo y quiere que vaya Aitor también. Yo le he dicho a ambos, que eso lo tiene que poner en conocimiento vuestro. Dime si os ha llamado o se ha puesto en contacto con vosotros y la manera de proceder por favor. Un saludo y siento molestarte." ················ Mi respuesta: "Hola Toni, mañana lo hablo con Pedro, jefe de sección, y te decimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-12-22','Ana: Tras convesación con Pedro y posterior conversación a tres con Toni-Asiser, decidimos que si Jesús, pareja de Felisi, madre de Aitor, firma la Declaración Responsable de la última resolución (11/12/20) Aitor podrá ir a casa por navidad. ··············· Correo-e de Toni: "Hola Ana, acabo de hablar con Jesús, la pareja de la madre de Aitor. Es conocedor de la situación, y sí que quiere que vaya Aitor con ellos en Navidad, y firmar la Declaración Responsable. Aitor iría a Cáceres en tren y allí iría a recogerlo él. Yo sí le veo con ganas de que madre e hijo pasen estas fechas juntos, pero sí os digo que yo no le conozco de nada. Mañana hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2020-12-23','(Pedro)Se autioriza reintyegro extraordinaruio de 100 euros para alimentación y ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-12-23','Ana: Envío correo-e a Sonia Bernabé, Asindi: "Buenos días de nuevo Sonia, Te remito adjunto los documentos pertinentes para el empadronamiento de Aarón Rosado Alarcón, tutelado por la CTAEX, en Alcántara: - Copia del DNI de Aarón - Testimonio de Nombramiento de Tutor - Acuerdo de Aceptación del Cargo El DNI del tutor legal es el mismo que se presenta para Felisa Bruno. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-12-23','Ana: Recibo corre de Toni-Adiser, con los modelos de autorización y declaración responsable. Pero no son los modelos actuales. Le envío el suplemento del DOE del 11/12/20 (última resolución). ··················· Llamada de Felisi, madre de Aitor (722 494 033), le explico como está la situación y cómo se va a intentar solucionar. ················· Llamada de María, Educadora del Progama de Famlia e la Mancomunidad Tajo-Salor (659 926 956), le informo de lo acordado ayer con Toni-Adiser. Dice que si el documento no se le enviamos ya, no podrá entregárselo a Jesús para que lo firme hoy, pues tiene que acudir a otros pueblos. También hablamos de la fechas pertinentes para la estancia. *Le envío el suplemento adjunto para que Jesús, pareja de Felisi, dirme la declaración responsable. ··············································································· Llamo a Toni-Adiser, pero el teléfono está ocupado. Le envío el siguiente email: "Hola de nuevo Toni, He intentado llamarte ahora pero el teléfono está ocupado. Decirte que he hablado con María, del Programa de Familia Tajo-Salor. Le he enviado también a ella el suplemento del DOE del día 11. Le dará a Jesús la Declaración Responsable para que la firma y nos la devolverán firmada escaneada. Con respecto a la solicitud, si queréis, no os compliquéis, haced lo mismo. Cumplimentad ese mismo modelo y enviármelo. Yo hoy estoy teletrabajando y no tengo impresora en casa, por lo que no puedo imprimirla y cumplimentarla yo misma. En cuanto la tengamos intento obtener firma digital o pedir a alguien en la oficina que recabe la firma. Por otra parte, hemos planteado como fechas de visita, del 24 al martes 29 de diciembre, para que el lunes pueda hacerse la PCR, antes de volver. Además no queremos alargarlo más por si la situación se complica más en Extremadura, pues tiene pinta de ello. María se va a encargar de pedir la cita al centro de salud. Ya me vas diciendo. Un saludo." ································································································································· Recibo correo de María, Programa de familia, con la Declaración Responsable firmada por Jesús. ···· Se la reenvío a Adiser y contesto a María con el siguiente correo: "Hola de nuevo María, Muchísimas gracias, sin vuestra colaboración no habría sido posible organizar la salida de Aitor. Esperemos que todo vaya bien, no surjan incidencias y que Aitor pueda volver al centro en la fecha acordada. Esperemos que el resultado dela PCR puedan dárselo el mismo martes para que pueda volver al centro, en el caso de que no estuviera a tiempo pues que vuelva el miércoles si no hay más remedio, pero sin el resultado negativo no puede regresar. Deciros también que Aitor saldrá del centro mañana, llevará 70 €, con los que tendrá que pagar también el tren (de ida y de vuelta), el resto para lo que necesite comprar la familia estos días. Llevará así mismo un buen lote de productos navideños que le van a proporcionar desde el centro para que no tengan que invertir el dinero en eso. Ante cualquier cuestión estamos en contacto. Un saludo y felices y saludables fiestas para todo el equipo y vuestros seres queridos." ····································································································································· *La PCR se la hacen el lunes a las 12 h. en el centro de Salud. ······························ Envío a Toni la documentación firmada. ··································································································································· Correo de Toni-Adiser: "Ana en archivo adjunto te remito también para su custodia los dos modelos. Ya hemos contactado con la familia. Aitor sale en autobús de Castuera a las 9.15 h. y llega a la estación de autobuses de Cáceres a las 11.35 h. Lo he hablado con Jesús, que del dinero que lleva tiene que tener para el viaje de vuelta. Un saludo y felices fiestas Ana." *Guardo ambos documentos en su expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-12-23','Ana: tras llamda del hermano de Consuelo (643 352 548), envío correo a Icíar: "Buenos días de nuevo Icíar, Supongo que estás muy liada también… es que no sé si el anterior correo lo envié a Alberto o a quién… Consuelo Nevado Pacheco está pasando unos días con su familia en Valencia de Alcántara y necesita un extra de 40 € para algo de ropa. Lo pedí el viernes pasado, pero me acaban de llamar de nuevo. No sé si se ha autorizado. ¿Podrías mirarlo y si no está hecho hacerlo para que lo puedan retirar hoy o mañana? Y por favor, confirmarles cuando pueden ir a retirarlo (643 352 548). *Si no puede ser para hoy o mañana, a las malas para el lunes próximo. Gracias!!! Seguimos." ······································································ Íciar me confirma que le ha hecho la autorización para retirar mañana el extra y que le ha pedido cita. La tiene a las 10 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-12-18','Ana: Tras llamada de Consuelo y su hermano (643 352 548), pidiento que se autorice la retirada de un extra de 40 € en la oficina bancaria de Valencia de Alcántara, pues está pasando allí unos días con la familia, *paso nota a Alberto con dicha petición, indicando además que les confirmen qué día pueden ir a retirarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-12-23','Ana: Envío correo a Noelia, TS de la Res. Cervantes: "...Por favor, cuando te sea posible, ¿podríais gestionarle Psiquiatra y cita para seguimiento en Salud Mental a Eugenia Pacheco Vicente? Me acaba de confirmar, Ana Benavente, TS el Equipo de Salud Mental de Plasencia, que aún no tiene en Cáceres..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-12-23','Ana: Llamo a Marta, TS de Cilleros (927 51 20 37). En el Ayto. de Cilleros me comuncian que etá de vacaciones. Le dejarán nota para que me llame a ser posible el día 4.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-12-18','Ana: Correo-e de Toni, Futuex: "Ademas de la entrega del carnet de conducir, realizada con exito, en la visita del pasado lunes, se recogieron las siguientes demandas y cuestiones por parte de la familia de MigueL:: La familia de Miguel se ha mostrado muy exigente en los diferentes puntos de demanda: • Solución urgente de buscar una vivienda, incluso la posibilidad de alquilar en Guadalupe, ante la NEGATIVA QUE EXPONEN SU PADRE Y HERMANO. No aceptan más tiempo que esté con ellos y puesto que la vivienda en propiedad que Miguel posee en C/ Caballeros de la Virgen de Guadalupe, no reúne las condiciones para vivir en ella, reclaman o alquilar, o solicitar un recurso residencial. Entendiendo, tanto ellos, como su hijo, que lo recomendable es que no viva solo. • Que teniendo la pensión tan elevada, disponer de mayor cantidad y aunque reclaman colaboración en el domicilio familiar, se han negado rotundamente a entregar número de cuenta para que reciban un ingreso de colaboración mensual. Es contradictorio lo que demandan: por un lado, colaborar económicamente, por otro se niegan a ello y reclaman que el propio Miguel, reciba su pensión u otra mayor asignación. En la visita presencial, observamos la exigencia tanto del hijo del tutelado, con amenaza de denuncia o solicitud de remoción de tutela al juzgado, como del padre y hermano de Miguel: la salida lo antes posible de la vivienda. Pero con otra petición, que si es a un recurso residencial mucho mejor. Miguel ha entregado voluntariamente el carnet de conducir que le era requerido judicialmente. Confirmamos que sigue pasando muchas horas al día en la vivienda de su propiedad, que NO reúne condiciones para ello. Un camión de limpieza del Ayuntamiento se ha llevado algunos enseres, pero más bien poco o nada en relación a la limpieza y orden necesario, ya que para él todo es válido. Se niega a que nadie entre en dos habitaciones de la casa y no da respuesta alguna, ni su hijo o su padre han podido entrar, nosotros tampoco. Nos informa su hijo que eso lo utilizaba incluso como gallinero. Nula relación y colaboración en la convivencia familiar, parece que está en un hotel, acude a dormir y horas de comer. En su demanda de mayor asignación, Miguel expone que debe realizar reformas en la vivienda y tiene que pagar en efectivo. Se le ha explicado desde la primera visita, que la reforma de su casa debe ser presupuestada y autorizada ante de nada. Que su asignación entregada semanalmente es para sus gastos de bolsillo y colaboración familiar, según expuso él en un listado previo y entregado a la comisión. Escaso lenguaje verbal, solo con monosílabos, como si la situación no fuera con él. En espera de citación en área de salud mental en cáceres, previa solicitud de cambio a Trujillo, según nos ha comunicado la coordiandora de este área. GRACIAS"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-12-23','Ana: Respuesta al último corro de Toni-Futuex: "Buenas tardes Toni, Teníamos pendiente este tema aún. Gracias por la información. A ver, ¿sabemos cuál es el deseo de Miguel? Lo digo para valorar si procede buscar un piso de alquiler o solicitar un recursos residencial. En ambos casos, entiendo que la vivienda no se arreglaría. En cuanto a su negativa a dar el número de cuenta, la respuesta es que no se le puede ingresar el dinero que Miguel solicitó para colaborar con los gastos de la casa. Si no hay cuenta no ha y dinero. Y con respecto a la reforma y limpieza de la vivienda que tiene en propiedad, como bien le habéis explicado, sin presupuestos previos no se le va a autorizar más dinero. Mantened el mismo discurso. En cuanto tenga cita en Salud Mental en Cáceres, habrá que solicitar informe, el cuál se tendrá en cuenta en la valoración del recursos más apropiado, en su caso. La vía más rápida, a los problemas de convivencia sería un alquiler, pero por lo que decís, no estoy segura si el que viva solo es la mejor opción… Seguimos en contacto. Un saludo y FELICES Y SALUDABLES FIESTAS!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-12-28','TERESA Cuando las compañeras estuvieron en Cáceres con ella para hacer esta gestión, le quitaron la tarjeta de Yoigo y le pusieron la nueva de Digi. La tarjeta de Yoigo la metieron en un plastiquito con la factura de la compra de la tarjeta. Y cuando hablaron con la enfermera de la residencia, Laura, se comentótodo lo que María Elena llevaba y está dijo que le guardaría la tarjeta de Yoigo junto con el resto de sus cosas. Así es que no nos explicamos muy bien, cómo puede estar usando la tarjeta anterior. Aun y todo intentaremos ir para allá en cuanto podamos y ayudar a gestionar esto del telefono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2020-12-28','TERESA SOLICITO AL JUZAGADO VIA EMAIL COPIA SENTENCIA DE INCAPACITACION QUE NOS PIDE EL BANCO : ICP587/2009 Juzgado 1ª Instancia Nº4','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-12-28','TERESA Con relación a Juana Nieto: ayer ya se ha producido la salida de Juana por Navidad con su familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-12-28','TERESA - Ida: Ya se ha comprado el billete de tren por importe de 20,80 Euros igual que la vez anterior. Sale de Zafra a las 14:25 h y llega a Plasencia a las 17:11 - Regreso : el lunes hablamos con Rafael, el hermano de Josefa y está dispuesto a volver a traerla en la fecha acordada de vuelta como la vez anterior. Así lo podéis tener en cuenta de cara al kilometraje. - Autorización de permanencia, condiciones y regreso con PCR negativa. Volverá a devolverla firmada Rafael, al igual que la vez anterior, cuando traiga a Josefa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2020-12-28','TERESA el pasado 21 de Diciembre se visitó a Cándido en su localidad y se le propuso comprar dos tarjetas regalo en una tienda de deportes por valor de 25€ para regalárselas a sus sobrinos, pedir factura y así poder justificar el extra de 50€. Cándido se niega en rotundo alegando que él siempre les ha dado el dinero en mano a sus sobrinos y este año no va a ser diferente, de hecho comenta que la semana anterior estuvo hablando con Teresa, de la comisión, y le dijo que quería entregarles el dinero a sus sobrinos como siempre y ella le dijo que si. Al no querer comprar tarjetas regalo, se le propone la idea de acompañarle a casa de sus sobrinos para que él les entregue el dinero en mano, pero se niega igualmente diciendo que su hermana se pasará por la tarde por su casa para recoger el dinero porque sus sobrinos están muy ocupados y no tienen tiempo. Se habla con Cándido sobre las retiradas quincenales que se harán con él a partir de Enero de 2021 y aunque tiene muchas dudas y no está muy convencido, después de hablar durante un buen rato sobre este tema, se queda más calmado y tranquilo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2020-12-28','TERESA HA TENIDO CITA EN PSIQUIATRIA, ESTA TODO BIEN CONTINUA CON EL MISMO TRATAMIETNO (ARCHIVO INFORME)','2');
