insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-28','(Pedro). Correo elcetrónico remitido a Miguel. +++Respecto de Dª Clementa, tenemos que pedir al Juzgado autorización para su ingreso involuntario en Centro Residencial, ya que ella es muy ambivalente respecto a aceptar o no dicho ingreso.. Hemos recibido informes actualizados de la situación por parte del Centro de Salud y de Futuex que he guardado en la carpeta de “Juzgados” en su expediente. Cuando leas los informes, verás que indican que, a partir del día 28 de diciembre la Auxiliar que tiene, de manera privada, iba a dejar de acudir para atender a Dª Clementa, porque Cáritas ya no puede costear más su atención. He tratado de hablar con la T. Social del C. Salud pero no me cogían el teléfono. He hablado finalmente con D. José Mirasierra, Coordinador de Cáritas, y me ha dicho que otra Auxiliar había decido mantener el servicio durante un mes más. Le he pedido que, por favor, nos den ese mes para tramitar por vía de urgencia la solicitud al Juzgado y me ha dicho que sí. De todas formas él iba a hablar con la Auxiliar para cerciorarse y lo volveré a llamar dentro de un rato. +++++++++++++++++++Tras llamr de nuevo a D. José, Coordinador de Cáritas, me confirma que ha hablado con la Auxiliar (interna) y me puede comfirmar que va a continuar con su trabajo durante el mes de enero. +++++++++++++++++++++++++++Envío correo-e a Futuex informando de esta circunstancia: +++En relación al Informe que nos habéis remitido sobre las últimas visitas de seguimiento de Dª Clementa, un aspecto importante era el referido al hecho de que la Auxiliar que tiene interna iba a dejar de prestar el servicio a partir del día de hoy, 28 de diciembre. He tratado de hablar con Mª Ángeles Lozano, pero debe estar de descanso. He hablado con D. José Mirasierra, Coordinador de Cáritas, quien me ha confirmado que otra Auxiliar, también interna, ha decidido mantener el servicio durante el mes de enero. Esto nos da cierto margen para tratar de solicitar un ingreso involuntario (digo tratar porque se trata de una Administración Provisional de Bienes) al Juzgado, dado que por el contenido de los informes no podemos esperar a que acepte voluntariamente dicho ingreso. Por favor, si podéis hablar con Mª Ángeles comentádselo y si podéis visitar a Dª Clementa próximamente seguid intentando que acepte el ingreso voluntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2020-12-29','(Pedro)Correo-e de Carmen Franco: +++Adjunto os envío parte médico de un usuario tutelado por CTA donde especifican que en la revisión se acompañe por el tutor legal. Un saludo +++Ver Nota de Evolución del S. de Otorrinolaringología en expediente virtual/informes médicos.','2');
