insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2020-12-29','(Pedro)Comunican desde el CSS de Plasencia el fallecimiento de Dª Modesta el pasado 26 de diciembre en el Hospital Virgen del Puerto de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-12-23','(Pedro)Visita de Jonathan a la Comisión Tutelar. +++La cita la tenía solcitada para ayer, pero comemnta que no pudo venir. +++SE presenta hoy con un taxi, procedente de Badajoz. Hablo con la taxista para que nos envíen el pago del taxi mediante factura en el que se haga constar el número de cuenta en el que abonar el importe. Jonathan dice haber pagado ya 80 euros del viaje a Mérida,lo cual corrobora la taxista. +++Se le autorizan 200 euros, porque dice que se va a quedar a vivir con el amigo con el que viene hoy en casa de su madre y tiene que pagarle algo por su estancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2020-12-29','BELEN: NUEVO NºTF MOVIL DE CARMEN LEAL: 636593574','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-12-29','(Pedro)Conversación con Puerto, Directora del Hogar de Nazaret (927-416563). +++Efectivamente, D. José Pedro estuvo unos días ingresado en el Hospital, en principio por Covid-19. Luego se descartó y el motivo fue por atragantamiento (SOLICITO NOS ENVÍEN INFORME CLÍNICO DE SU ESTANCIA EN EL HOSPITAL). +++Salió del hospital con Covid-19 NEGATIVO Y ahora se encuentra muy bien, ha engordado y está mejor que cuando ingresó. +++Quedamos pendientes del informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2020-12-29','(Pedro)Conversación con D. Jesús, Director de la Residencia Madre Francisca de Azabal. +++Respecto de la vacuna contra el Covid-19: ¿qué pasa si se niega a ponérsela a pesar de nuestra autorización?','2');
