insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-12-30','miguel, remito al jzdo de valencia de alcantara nº1 contestación a la petición de información que hicieron','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2020-12-30','TERESA NOTA DE FUTUEX En la tarde del día 29 de diciembre de 2020 se pone en contacto con el equipo de apoyo social comunitario, por vía telefónica, Lupe la coordinadora de la Residencia La Salud de Villanueva de la Serena. Nos indica que en el centro residencial existe un brote de coronavirus, por lo que continuamente se les realizan PCR tanto a los residentes como a los profesionales. Ese mismo día en las pruebas realizadas, José Antonio Quirós Sauceda ha dado positivo. Dentro del protocolo establecido, el médico llama por teléfono a todos los familiares de los usuarios positivos en covid 19 para indicar su estado de salud, llamándonos también a nosotros instantes después de indicarnos la situación Lupe. Nos informa que José Antonio se encuentra bien de salud, sin sintomatología hasta la fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-12-30','TERESA ENVIO PIA DE RAMON A JUAN PEDRO APOLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2016-03-16','Contactamos con Charo (Dra. Aprosuba 1), nos informa de la próxima salida de 26 de Junio a 3 de Julio de 2016 al Albergue Nonte do Gozo. Actividad organizada por AD El Bellotín (asociación de Aprosuba), donde participa la tutelada. El coste del viaje son 200€ pensión completa y el autobús corre a cargo de la Asociación. La Comisión acepta el viaje siempre y cuando tenga capacidad económica para asumir el coste en su momento. Acordamos con Charo que la autorización valdría con la trimestral y que nos enviarán documentación redactada del viaje y sus actividades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='QUINTIN'and edp.apellido1='SANCHEZ'and apellido2='ALAMILLO'),'2020-12-28','TERESA HE HABLADO CON EL CENTRO, CON MAMEN LA DIRECTORA, 924 60 00 46, Y POCO ME HAN PODIDO DECIR PUES A ELLOS TAMPOCO LES FACILITAN NINGUN TIPO DE INFORMACION ME COMENTA QUE PUEDE SER SU HERMANO VALENTIN EL QUE SAQUE EL DINERO DE LA CUENTA DEL SANTANDER, CUANDO INGRESO EN LA RESIDENCIA SU HERMANO DEJO ALLI 2000 EUROS PARA LO QUE NECESITARA SU HERMANO, A FECHA DE HOY LE QUEDA 140 EUROS. QUINTIN SOLO TIENE GASTOS DE PELUQUERIA Y PODOLOGIA LO QUE SUPONE UNOS 25 EUROS AL MES. EL GASTO EN MEDICINA VIENE INCLUIDO EN LA FACTURA QUE NOS PASAN DE PLAZA RESIDENCIAL YA HE PEDIDO EL CAMBIO DE CUENTA PARA LA PRESTACION VINCULADA DE RESIDENCIA, HABRA QUE ESTAR ATENTO A VER SI LA INGRESAN EL MES QUE VIENE…. AL IGUAL QUE LA PENSION.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2020-12-30','(Pedro)Llamada de Dª Estefanía Fdez. Fdez., abogada (985-170250). +++ Motivo de la llamada: el hijo de Dª Alfonsa falleció el día 6 de junio de 2020.Era marido de su cliente. Por diversos, motivos tras el fallecimiento, se llamó a una Funeraria que no era la que tenía contratada Dª Alfonsa. Ahora reclaman a la mujer del fallecido el abono del servicio prestado (algo más de 3000 euros). La Funeraria de Dª Alfonsa, a pesar de que estaba de acuerdo en hacer el pago, dijo que no lo hacía hasta que se solucionase el tema de la herencia. +++Doy el correo de ctaex a Estefanía para que nos explique el caso y nos envíe la documentación relativa al mismo. Le doy también los teléfonos de Miguel y Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2020-12-30','(Pedro) Correo enviado a Sección Eco. +++He recibido la llamada de D. Miguel O.G (de Nuestra Señora de la Luz). Dice que ha contratado una tarjeta prepago de Correos. Al parecer lo ha comunicado a la dirección del Centro. Por favor, estad atentos a las cuentas por si hubiera algún extracto fuera de lo normal y si es así se anula esa tarjeta (creo que no está vinculada a la cuenta y que funciona con recarga en las oficinas de Correos). Un saludo y Feliz 2021. Cuidaos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-30','(Pedro) Se envía por fax al Juzgado de 1ª Instancia nº 4 de Cáceres solicitud de autorización de ingreso involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2020-12-03','Ana: Correo de Toni-Futuex: Te reenvio el informe que nos solicitó Pedro, tb para tu conocimiento, sobre Jesus Ramos Bargon, y lo que el juzgado os reclamaba, porque acude solo a adminstracion de tto y psiquiatara (no colabora, ni comunica, ni accede a que se le acompañe en esta gestion desde nunca)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-04','Ana: Correo de Toni-Futuex: "Hola Ana, buenas tardes se informa sobre esta tutelada incorporada al programa hace escasas fechas Clementa Amado Vivas Se realiza visita de seguimiento en domicilio, dado que en la anterior visita la tutelada se negó a colaboraren esta ocasión se acude en compañía de Pepe el responsable del voluntariado de Cáritas de la parroquia de Fátima. Ha recibido notificación del SEPAD por la que se le concede Grado II de dependencia con derecho a servicios de teleasistencia, Ayuda a domicilio, centro de día, noche o residencial y promoción de la autonomía y prestaciones económicas para cuidados en el entorno, vinculados a la adquisición de servicios o para la asistencia personal. Se adjunta notificación a esta nota Actualmente tiene contratada una cuidadora a tiempo completo gracias a las aportaciones económicas de Cáritas, dado que su pensión no alcanza para hacer frente al pago de la empleada. También disfruta del servicio de teleasistencia de Cruz Roja. Se explora en conversación con la tutelada la posibilidad de que se ingrese en un centro de forma voluntaria, y sólo contempla la posibilidad de que sea en Brozas, se le invita por tanto a reflexionar transmitiéndole la oportunidad de que sea en un centro público, con lo cual le resultaría más económico, pero aun así la tutelada se niega a abandonar el domicilio si no es la residencia de Brozas, su localidad natal. Se deja la puerta a abierta a la reflexión por parte de la tutelada una vez se le transmiten las ventajas de la institucionalización. Pero es importante que se comiencen a valoras las posibilidades que hay en referencia a su ingreso, aunque sea con carácter involuntario, dado que necesita atención y cuidados de forma permanente y su situación económica no le permite asumir estos gastos. Esto lo veras a la vuelta de tus vacas asique no ponemos en contacto cuando sea esto. un abrazo!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-12-04','Ana: correo de Toni-Futuex: "...Te dejo por aqui, el informe del Ingreso de Eugenia Pacheco el 2 de diciembre, tuvo de todo.... y se complicó bastante por aparentemente dificultades burocraticas, pero finalmente se pudo llevar a cabo y se encuentra ya alli, esperemos que se vaya adaptando a la residencia Cervantes de forma adecuada. En el informe se detalla todo..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-01-04','miguel,llamo a la abogada Doña Estefanía (móvil 605033474) quien me comenta el problema que es el siguiente: Nuestra recien tutelada tenía un hijo que era profesor de música y tenía dependencia (alcoholismo cree). A su vez nuestra tutelada tenía otro hijo que premurió a este último. La cuestión es que cuando fallece el hijo de la tutelada en vez de llamar a la compañía del seguro "La Almudena", un primo (drogadicto) contrato a la compañía la "Siberia", quienes ahora reclaman a través de un procedimiento monitorio. La abogada (Estefanía) me remite el email que dice envío a ctutelar con la documentación de que dispone (presentación de liguidación de sucesiones en la oficina liquidadora de Herrera del Duque, declaración de herederos, factura de entierro y reclamación de la compañia la Siberia de los 3.100€). ******************************************** Ella lo que quiere es que la demos una autorización pra presentar una autoliquidación y pagar el importe a la compañia la siberia. Me comenta que ha intentado que se compensaran estas compañías pero el seguro le exige la liquidación del impuesto de sucesiones, por lo que quiere hacer la complementaria del impuesto incluyendo una cuenta bancaria. ********************************** La comento que no podemos darle por ahora ninguna autorización puesto que estamos todavía en fase de formación del inventario, y no sabemos la capacidad económica de nuestra tutelada (madre del fallecido hijo), además no sabemos si el ACTIVO es mayor o no que el PASIVO, ya que sólo nos remite la portada de lo que la Gestoria que contrató la viuda? (mujer del hijo fallecido de nuestra tutelada y clienta de esta abogada Estefanía) ********************************************* Le planteo las opciones: 1 Ver todas las cargas que pueda tener la herencia yacente cuyos unicos herederos son nuestra tutelada (madre del fallecido) y la viuda (clienta de la abogada), para ello ella se hará con todos los posibles préstamos personales y comprobará si hay préstamos hipotecarios y embargos. 2 Si todo es positivo y el ACTIVO es superior al pasivo tendríamos que esperar a comprobar nuestro Inventario, ya que tal como veo y comento a la abogada lo que presentaron en la oficina liquidadora era una liquidación no autoliquidación, lo que significa que tienen hasta 4 años desde la oficina liquidadora para girar el impuesto de sucesiones. Y esto significa que no sabemos si han solicitado o no en plazo las posibles bonificaciones y deduciones que puedan corresponderles por ser parientes directos (en caso de que no puedan solicitar ya dichas bonificaciones y deduciones no sabemos que importe de liquidacion del impuesto de sucesiones tendría que pagar nuestra tutelada y si sería viable o no para ella. Es pòr eso que necesitaremos saber cuanto antes el inventario de este expte. Por que la otra opcion para no renunciar a la herencia y poder pagar el impuesto llegado el momento sería solicitar abogado (de oficio/de pago según su capacidad económica) tanto para aceptar, como para aprobar la herencia, como para poner en venta alguno de los inmuebles de la herencia. 3 Caso que vaya para largo la liquidación de la oficina liquidadora de Herrera del duque, es decir que pueda tardar hasta máximo 4 años desde su presentación en diciembre de 2019 y por tanto hasta diciembre de 2023 y a la abogada no la dejaran presentar como autoliquidación la complementaria de la cuenta bancaria que comenta, no la quedaría más remedio que oponerse al procedimiento monitorio y obligarles a que vayan contra la herencia yacente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2020-12-26','EXITUS. Comunican desde el CSS su fallecimiento el día 26/12/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2020-12-16','Ana: correo de Teresa, TS CTAEX: "...Se hizo ingreso involuntario un viernes (día 9). -Dice Noelia que esta bien…. Que cualquier cosa que necesite se pondrá en contacto contigo. He autorizado que se ponga la vacuna covid. Hay un tema que tenemos que ver sobre su cartilla de desempleo porque él está cobrando un subsidio, en principio con el tema del covid no hay que sellar pero más adelante habrá que estar pendiente para cuando le toque sellar…. Creo que con futuex lo hacían con una clave de manera on line a través de la paginas del sepe. Háblalo con Noelia aunque yo algo le he comentado….. sobre todo a ver cuando le toca sellar de nuevo¡¡ imagino que tendrá el documento sino hablamos con el sexpe de Castuera que yo tengo los contactos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-01-04','Ana: Envío correo a Noelia, TS C. Residencial Cervantes (noelia.garciac@salud-juntaex.es) y a Teresa, T.S.-CTAEX: "Buenos días a las 2 y feliz año! Espero que estéis bien. Noelia, no sé si estarás trabajando estos días, Teresa sí que está de vacaciones esta semana, pero también la pongo en copia, pues como sabes ha llevado el caso de Guillermo hasta ahora, lo leerá a su vuelta. ¿Qué tal siguen Guillermo y Eugenia? Espero que la adaptación esté siendo adecuada. Ya me informarás cuando puedas. En ambos casos, perciben subsidio del SEPE, por lo que es importante tener al día la Demanda de Empleo del SEXPE. Actualmente, debido a la situación de pandemia, no hay que renovarla (“sellar”), se están haciendo las renovaciones automáticas, pero habrá que estar pendiente para cuando sí haya que hacerlo. No obstante, lo que supongo que sí habrá que hacer es inscribir a ambos en la oficina correspondiente del SEXPE de Cáceres comunicando el cambio de domicilio, pues Guillermo seguirá en la de Castuera e imagino que Eugenia en Plasencia. ¿Noelia, podrías ponerte tú en contacto con la oficina para pedir cita y que te informen de la documentación a aportar y las gestiones oportunas? Ya nos vas diciendo. Muchas gracias. Cuidaros. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-01-04','Ana: Envío correo a Noelia, TS C. Residencial Cervantes (noelia.garciac@salud-juntaex.es) y a Teresa, T.S.-CTAEX: "Buenos días a las 2 y feliz año! Espero que estéis bien. Noelia, no sé si estarás trabajando estos días, Teresa sí que está de vacaciones esta semana, pero también la pongo en copia, pues como sabes ha llevado el caso de Guillermo hasta ahora, lo leerá a su vuelta. ¿Qué tal siguen Guillermo y Eugenia? Espero que la adaptación esté siendo adecuada. Ya me informarás cuando puedas. En ambos casos, perciben subsidio del SEPE, por lo que es importante tener al día la Demanda de Empleo del SEXPE. Actualmente, debido a la situación de pandemia, no hay que renovarla (“sellar”), se están haciendo las renovaciones automáticas, pero habrá que estar pendiente para cuando sí haya que hacerlo. No obstante, lo que supongo que sí habrá que hacer es inscribir a ambos en la oficina correspondiente del SEXPE de Cáceres comunicando el cambio de domicilio, pues Guillermo seguirá en la de Castuera e imagino que Eugenia en Plasencia. ¿Noelia, podrías ponerte tú en contacto con la oficina para pedir cita y que te informen de la documentación a aportar y las gestiones oportunas? Ya nos vas diciendo. Muchas gracias. Cuidaros. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-12-17','Ana: Correo de Toni-Futuex: "A continuación adjunto informe de la visita, con fotografías, efectuada ayer en el domicilio de la tutelada Manuela Morato, a la que acudieron la ts de ssb la ts del centro de salud, la médico de A.P de la tutelada y nuesta compañera educadora de equipo de apoyo social comunitario." ······· *Según informe adjunto: "...Tanto la Dra. como la trabajadora social del centro de salud, coincidiendo con el criterio de la educadora, establecen, especialmente la Dra., que hay algo oculto, no consigue entender la situación ni ese modo de aferrarse a estar en una vivienda que se encuentra en tan malas condiciones. La Trabajadora Social del centro de salud establece que no concibe que no quiera llevarla a otra vivienda o una residencia si mira tanto por el bienestar de su abuela; aspecto por el que la Dra. indica que ahí debe haber un interés oculto..." y "...Todas las profesionales coinciden en que la vivienda está en muy malas condiciones y la insalubridad ocasionada por vivir en la misma, lo cual reflejarán en sus informes, según indicaron, así como sus impresiones." Destacan, sus impresiones, comunes en el caso de todas las asistentes, difiriendo tan solo el criterio de la ts del ssb, siendo mas favorable digamos a Jose Manuel. Quedamos a la espera de cualquier intervencion que tenga que ver con este caso, una vez reviseis el informe..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2020-12-30','miguel, voy con el gerente a los juzgados de Mérida para hacer el poder apud acta. Entrego dicho poder en persona a la oficina del abogado Felipe Muriel para aprobación de herencia y autorización de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-18','Ana: Correo de Toni-Futuex: "Buenas tardes Ana, adjunto nota Clementa Amado y toda la documentacion que hemos conseguido de ella, está en una situación de riesgo extremo ya que desde el proximo lunes 28 se queda sin auxiliar y necesita apoyo para todo, te explico mas en detalle, la informacion recogida: Se realiza de seguimiento en domicilio en compañía de Pepe, José Mirasierra (coord. Cáritas): 620352636 que transmite que desde esta entidad llevan mucho tiempo haciéndose cargo de los gastos de la tutelada, dado que no dispone de fondos para cubrir los gastos de las cuidadoras que necesita de forma permanente, transmite también que no pueden hacerse cargo durante más tiempo y en el momento actual tan sólo se pueden hacer cargo de abonar el salario de la última cuidadora interna en el domicilio, que a partir del 28 de diciembre dejará el trabajo porque no se le puede garantizar el pago, y la asistencia a la tutelada quedará desierta. Es importante encontrar una solución de forma urgente porque Clemente necesita ayuda constante y supervisión de lo contrario se teme por su integridad puesto que se quedaría sola en la vivienda. Se mantiene conversación con la tutelada pero no colabora en la aportación de datos al respecto de su situación ella tan sólo contempla la posibilidad de ingresar de forma voluntaria en la residencia de Brozas, su localidad natal, sin valorar que la residencia de esa localidad es privada y sin conocer si puede hacerse cargo, se considera conveniente por tanto la posibilidad de programar un ingreso por emergencia social, dada la gravedad de la situación, tras charlar un rato con la tutelada se percibe un ligero grado de aceptación a la posibilidad de ingresar en un centro residencial diferente al de brozas….aunque pudiera valorarse un traslado posterior, por lo que se valora la coordinación con el área de trabajos social del equipo de salud mental, se establece contacto con la profesional a cargo del servicio Pilar Martin pero no se consigue localizarla. La cuidadora expresa que las relaciones con la hija no han mejorado, comenta que incluso ha acudido al domicilio saltándose la orden de alejamiento hacia su madre y se ha llevado dinero, también se han observado movimientos extraños en la cuenta de la tutelada (se adjunta copia de los movimientos reflejados en la libreta) y una tarjeta de crédito que al parecer no ha utilizado nunca. Clementa percibe una pensión de viudedad cuyo importe asciende a 969,86€ y también tiene una hipoteca sobre la vivienda en la que reside y un garaje en el mismo bloque, se aporta copia del registro de la propiedad, la hipoteca está domiciliada en la misma cuenta en la que cobra la pensión y de la cual se adjunta copia. También tiene los suministros de luz agua y gas domiciliados en esta cuenta de Liberbank en la oficina de Avenida de España 27. Cáritas la está proporcionando ayuda económica a y de alimentación a través de la contratación de las cuidadoras internas que acuden a prestar sus servicios al domicilio y del banco de alimentos que ellos mismos gestionan, pero informan que ya no podrán hacerse cargo porque los fondos de los que disponen son bastante limitados, aporta resumen de las cantidades abonadas por esta entidad a beneficio de Clementa. Anexos: se aportan a esta nota además de los documentos expresados en el contenido de la misma, la totalidad de la documentación personal que se ha conseguido recopilar hasta la fecha actual. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-23','Ana: Correo de Toni-Futuex: "Se recibe llamada telefónica de la Trabajadora social del centro de salud Manuel Encinas de Cáceres, para comunicar que ha hablado con el equipo de dependencia y para gestionar la solicitud de ingreso en centro por la ley de dependencia es necesario presentar un nuevo PIA y que la tutelada lo acepte mediante la firma del documento, existe la duda si lo puede firmar ella al estar incapacitada. Nos comenta que se iba a poner en contacto con la comision, pero que no lo ha logrado, está su numero en el informe adjunto, por si se le quiere consultar. Solicita para este trámite la colaboración de la educadora del equipo de apoyo social comunitario, realizando nuevamente visita al domicilio y poder mantener la intervención de estos días donde Clementa aceptaba su ingreso en un centro público de la comunidad. Qeudamos pendiente de poder cuadrar con ella para realizar este trámite Lamentablement han ido a su casa a ultima hora de esta mañana y no han conseguido en absoluto, que firmara, ahora se niega en rotundo. Por lo que, la unica alternativa seria solicitarlo involuntariamente os iba a enviar la documentacion la ts del cnetro de salud al parecer, y yo os hago llegar el informe tal y como hemos quedado de parte del equipo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-01-04','miguel, remito a Ana email con la citación del tutelado para que alguien lo acompañe el 17-2-21 para que le tomen declaración. Desde el Jzgado nº4 Plasencia me confirman que no es necesario que asistamos nosotros, pero sí él ya que quieren tomarle declaración por el procedimiento delito lesiones DPA 602/2019','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2020-12-30','miguel, nos remite el abogado Jesús Bueno, aprobación de herencia y autorización judicial de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-01-04','miguel, el abogado Jesús Bueno nos remite escrito de subsanación al juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-01-04','Ana: Reenvío a Ángel y Miguel, Asesores Jurídicos CTAEX, el documento que me remiten de nuevo del CRR en PDF, que les ha enviado una abogada para que firme Damián. En el documento le autoriza "...para que realizar en su nobre todos los trámites y gestiones para atender a su situación de residente en el centro de referencia y para realizar la reclamaciones oportunas en relación con su situación de dependencia y trámites jurídicos en general."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-01-04','miguel, a petición de Pedro confirmo con el Juzgado nº2 de Cáceres que no hay ningún procedimiento penal vigente o pendiente de trámite de este tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-01-04','Ana: Envío correo a Toni-Futuex, con copia a Pedro, para derivar al programa a Rafael: "Hola de nuevo Toni, Procedo a haceros una nueva derivación de seguimiento de un nuevo cargo aceptado por la CTAEX en el tercer trimestre del pasado 2020. Se llama Rafael Casares García, se trata, al igual que en el caso de Clementa, de una Administración de Bienes. Vive en el municipio de Madroñera en domicilio particular, sito en la Plaza de Portugal nº 6. Informaros de que a priori es un caso complicado, el Juzgado dictó AUTO disponiendo acordar medida cuatelar de Internamiento en centro adecuado a su patología. Los últimos intentos de contactar con el Eloy Gómez Piélago, Trabajador Social del SSB de Madroñera, no han dado resultados. Él es quién promovió la incapacitación. Y a él le remitió el Jdo., a fecha de 25 de junio de 2020, OFICIO para “realizar los trámites administrativos de su competencia para que se produzca dicho ingreso a Ia mayor brevedad”. Que sepamos a día de hoy no se ha producido aún el internamiento, pero no he conseguido confirmarlo. La vivienda no reúne requisitos básicos de habitabilidad, acumula objetos y suciedad. Él presenta aspecto descuidado y falta de higiene personal. En su día (1976) fue separado del servicio militar por presentar esquizofrenia, pero no está en seguimiento por Salud Mental ni toma medicación, en Jara no consta ningún antecedente médico de interés. Sólo hay constancia de la enfermedad en un informe médico de dicha fecha de una clínica psiquiátrica militar de Ciempozuelos (Madrid). *En el reconocimiento médico forense estuvo “colaborador, tranquilo y educado” Tienen 2 hermanos que viven fuera (uno en Badajoz y otra en Suiza) y otra que vive en el pueblo, Josefa, pero parece ser que no existe relación. Os facilito datos de contacto de Eloy, TS: 662 545 510 // ssb079@gmail.com *Lo que os pido es que, cuando os sea posible, os pongáis en contacto con Eloy, confirméis si sigue en el domicilio y en tal caso le hagáis seguimiento, para ver cómo está, y preguntéis a Eloy por el procedimiento de internamiento. Con Eloy ya habló tanto Ángel, Asesor Jurídico CTAEX, como yo, pretendía que nos encargásemos del internamiento, y se le explicó por ambas partes, que en este caso no es la CTAEX quién debe encargarse de los trámites y gestiones necesarios para ello ni de activar el 112. Si necesitáis algo más dímelo. Ya nos vais informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-01-05','Ana: Correo de Estrella, TS CSS-Plas., de ayer: "...Me comunica la Psicóloga de la UHDAC, Maripaz que el paciente ha manifestado deseos de hablar por teléfono con su madre, sabiendo que la relación entre ellos es conflicitiva, hemos preferido hablar antes con vosotros, a ver qué os parece.... Espero tu respuesta. Saludos" ·································· Mi respuesta: "...Pues entiendo que en estas fechas quiera hablar con su madre, a pesar del tipo de relación que han mantenido siempre, yo creo que se le puede dar la oportunidad y en función de cómo veáis que le afecta a posteriori, valoráis si es positivo o contraproducente para él el mantener este tipo de contactos. Ya me vais informando al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2021-01-05','Ana: correo de Pilar, Hogar San Vicente de Paúl: "Buenos días, les informamos que Dª Mª del Carmen Matillas Jiménez ha dado negativo en la última prueba PCR a la que se sometió el día 31/12/2020. Creemos que esta semana o la que viene procederán a vacunar a las residentes y personal..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-01-05','Ana: Envío correo-e a Toni-Futuex (areasocial3@futuex.es): "...Te reenvío correo que me envía Miguel, Asesor Jurídico de la CTAEX, a quien por cierto pongo en copia. ¿Sería posible que alguna compañera le informara al respecto e incluso le acompañara? Ya nos dices. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-01-05','Ana: Respuesta de Miguel, Asesor Jurídico: "...Comentarte que al tratarse de una curatela, como sabes la capacidad es compartida entre él y nosotros. No se trata de un poder (con el que pueda actuar en juzgados para un procedimiento judicial por ejemplo), en realidad no tiene validez por ser un documento privado y por tanto no tiene efectos ante terceros. Puede servirle por ejemplo para localizar información, si la persona receptora (por ejemplo un funcionario o un empleado de banco consideran dicha autorización suficiente y válida). En definitiva que no es más que una autorización en sí, lo cual supone que dichas gestiones le costarán un dinero y que al haberlo contratado él sin nuestro consentimiento tendrá que hacerse cargo él de los honorarios a que se comprometa…Si quiere que nosotros nos comprometamos a algún gasto tiene que darnos, como se hace siempre, presupuesto previo de lo que quiere hacer y para qué quiere hacerlo." ···················· Se lo reenvío a Blanca, Coordinadora del CRR-Plas. ································································································································································································ Conversación con Ana Benavente, TS ESM-Plas. (74955): estuvo hablando con Damián, el informe de Psiquiatría que insiste en que me envíe es de septiembre, no hay ninguno nuevo. Me lo enviará en PDF por e-mail. Revisa la gestión que hizo ella en septiembre. **Finalmente solicitó revisión de grado por empeoramiento en lugar de hacer una reclamación y aportó precisamente este informe clínico del Servicio de Psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-01-05','Ana: me devuleven de registro el PIA (ingreso en C.Residencial) con REGISTRO DE ENTRADA de fecha: 30/12/20.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-01-05','Ana: Conversación con Ana Benavente, TS ESM-Plas. (74955): estuvo hablando con Damián, el informe de Psiquiatría que insiste en que me envíe es de septiembre, no hay ninguno nuevo. Me lo enviará en PDF por e-mail. Revisa la gestión que hizo ella en septiembre. **Finalmente solicitó revisión de grado por empeoramiento en lugar de hacer una reclamación y aportó precisamente este informe clínico del Servicio de Psiquiatría.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-01-05','Ana: me comunica Icíar que se le ha aprobado una asingación mensual a Rafael de 200€, al parecer Rafael ya los retiró pero ha vuelto a banco a pedir más dinero. Entiendo que nadie se lo ha explicado. *Pido también a Futuex que aborden esta cuestión y propongo aprueben, al menos este mes, otra asignación de 200€, pues está acostumbrado a retirar toda la pensión. // *Por tanto confirmado que sigue en el domicilio. ···················································································································································································· Correo-e respuesta de Toni-Futuex: "Intentaremos realizar el seguimiento la proxima semana, sin falta, te voy contando que nos encontramos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-05','Ana: Llamo a Pilar, TS del ESM-CC (54612), acaba de volver de hacer una visita domiciliaria a Clementa, quien finalmente, aunque con mucha reticencia, ha firmado el PIA, pero solicitando sólo la Residencia de Villa del Rey (cercana a Brozas). *Le informo de la solicitud remitida al Jdo. para internamiento involuntario, por si finalmente fuera necesario. *La auxiliar, mientras le sigan pagando, está dispuesta a continuar con Clementa hasta que le den plaza residencial. ······· *Valorar con Alberto, jefe sección económica, la posibilidad de seguir pagando a la auxiliar hasta entonces y si CÁRITAS cede a seguir costeando la diferencia. ···················································································································································································· Mª Ángeles Rodríguez, TS del CS, está de baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-01-04','Ana: Correo-e de Paula, TO del CRR-Plas. del día 30/12/20: "Hola Ana, felices fiestas. Te escribía para comentarte que está previsto, tal y como te conté, que Toñi se incorpore al piso en Enero, el día 18. El plan es trabajar de forma intensiva durante 6 meses, prorrogables si es necesario, para preparación para una vida autónoma. Según este plan enviaremos informe de evolución en Abril y en función de esta evaluación iremos coordinándonos para dar los siguientes pasos. Estaremos en contacto con vosotros y el equipo de salud mental para apoyar a Toñi. Si os parece oportuno contactar con nosotros telefónicamente para concretar más, no lo dudeis. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-01-05','Ana: Recibo llamada de Luz, TS del C. Penitenciario de CC (927 181 407), a Saturnino aún no se le ha ingresado nada en la cuenta peculio. Hablo con Juana, secc. ecca. acordamos que se la autorizará 200 €/mes, hará transferencia periódica mensual. Y pedirán que se le active en la tarjeta 50€/semana. **Mantiene el mismo NIF del Penitenciario y Nº Cuenta Peculio de la vez anterior. *Se enviará escrito a la Dirección del Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-01-05','Nos llama Rosa, del CSS de Plasencia (24145), en relación con el fallecimiento de la madre de Flora. Tienen joyas en el centro. A parte de Flora, tenía dos hijas más. Nos van a remitir documentación relacinada con su madre (certificado de defunción, contacto de hermanas, etc), a los efectos de iniciar testamentaría. Al parecer, tenía un piso también y disponen de las llaves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-01-05','Ana: Ángel, Asesor Jurídico CTAEX, me comunica que hemos recibido citación para reconomiento médico forense de Felisa. Deberán acompañarla al Instituto de Medicina Legal de Cáceres. Fecha: 26/01/2021 a las 18:30 h. ······································ Aunque habrán recibido la citación en ASINDI, se lo recuerdo a través de mail a Sonia Bernabé.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2020-12-24','Ana: Correo de Pilar, Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Buenos días, les informamos que ayer, día 23, nos repitieron la PCR al Centro y, en esta ocasión, Mª del Carmen ha dado positivo. Se encuentra sin síntomas y tendrá que estar aislada durante diez días. Les mantendremos informados de los cambios que se vayan produciendo..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2021-01-05','Ana: Pongo para registro de entranda, escrito a PNC comunicando cambio en el cargo aceptado de Vanesa. Como Curadora, la CTAEX no puede aportar la documentación que no solicitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-01-07','(Pedro) Llamada de Emilia (722-432418). +++Solo quiere dinero. No acepta ingreso en UHB ni plaza en Centro Residencial: "Yo me sé cuidar perfefectamente...Estoy esperando la plaza de Málaga...Yo solo quiero mi dinero. El lunes me voy con Francis a Cáceres, porque con el que estoy ya no quiero estar...Ya no quiero ir a la clínica del dentista." +++A pesar de los intentos para que entre en razón, se mantiene en sus trece sde no querer ingresar en ningun centro..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-01-07','Buenos días Os quería comentar un asunto referente a José Martínez Ortega, tutelado de la Comisión, su deterioro cognitivo ha empeorado gravemente tras pasar el covid19, se mantiene agitado y con ansias de ingerir todo los que se encuentre en su camino. Ha intentado ingerir guantes, gel hidroalcoholico, etc. Este trastorno de conducto persiste tanto por la mañana como por la noche. Su próxima revisión con neurología es en mayo, hemos intentado adelantar su revisión con neurología, aún pendiente de la respuesta. Consideró necesaria sujeción física para evitar conductas del residente que ponen en riesgo a su persona. He hablado con su familia y me comentan que los que tienen que dar el consentimiento debe ser la Comisión, ya que el residente es tutelado. Espero vuestra respuesta Un saludo. Atentamente, Dra. Maritza Gutiérrez Tello Nº coleg: 06/06/07430','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-01-07','NUEVO TELÉFONO de José Manuel: 678-150472','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2021-01-07','(Pedro)Se reciben en la Comisión Tutelar tres copias del piso de D. José Luis, junto con una Code Card de ABUS Security Tech Germany. +++En el C.M. La Granadilla de quedan dos copias en su expediente. +++SE deja en su expediente el oficio y carta de la Dirección de la Residencia junto con la Code Card.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-01-07','-Amalia : Nerea sigue ingresada, está bien, sin novedades, ingresó en Navidades en la UHB .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-01-07','Le dieron el alta en nochevieja y se fue con su tía. La situación no es muy buena y no sabemos cuánto le va a durar estar tranquilo. Ya ha vuelto a la VT , están a la espera del traslado a otro centro . Toda la solicitud se envió .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-01-07','(Pedro)Llama la vecina de Carmen en Valdecaballeros , Aurora Sanchez Sánchez , tf 924643480. +++Preguntando cómo están los trámites para la venta o e su caso derribo de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-01-07','Por otro lado, te escribo para informarte que Nerea ha estado ingresada de nuevo en la unidad de psiquiatría, debido a dos nuevas crisis, desde el sábado 26 hasta ayer 30 que le dieron el alta. Le han ajustado la medicación. Creemos que las crisis le dan por la incertidumbre que tiene en su interior sobre qué será de ella habiendo superado la mayoría de edad, todos sus hermanos han sido adoptados, hormonales, etc. Además se le añade la noticia de no poder irse con su familia como ella contaba. Se encuentra estable en casa y mostrando arrepentimiento y cariño hacia los profesionales, al igual que la otra vez. Creo que mi compañera Guadalupe te ha mantenido al corriente a través de este medio. Por último, su hermana Esmeralda, tiene pensado venir a visitarla el 6 de enero de 2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2021-01-07','Sólo comentaros que ayer por la noche Julián O.C se marchó a su pueblo ya que su hermano había fallecido la noche anterior. Pasará allí unos días para hacer las gestiones pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-01-07','CORREO. Se remite por e-mail al centro consentimiento informado de sujeción. El original se enviara por correo ordinario una vez suba de registro el oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-01-08','(Ángel/Pedro)Conversación con D. Gregorio Rodíguez, Alcalde de Valdecaballeros (628-556073). +++Recordamos los correos que en octubre y noviembre Ángel envió al Ayuntamiento en relación al estado de la vivienda y al precio de mercado en la zona.No se han remitido porque el Técnico Municipal está de baja. +++Explicamos las dificultades para la venta: una sola oferta de 6000 euros, muy lejos del precio autorizado por el Juzgado (valor catastral alreddedor de los 50.000). +++Solicitamos nuevamnete los informes y precio de mercado y coste de derribo y desescombro llegado el caso. +++Nos lo enviarán en cuanto el Técnico esté de alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2021-01-08','(Pedro)Llamda de la Policía Judicial de Mérida. Mila y Enrique (Inspector UFAM)(924-387140). +++han localizado a D. Rafael en Mérida, siendo POSITIVO en Covid-19, tras la SEGUNDA PCR realizada el pasado 4 de enero. La médico indicó aislamiento durante 14 días y repetir la prueba.Se presentó ASINTOMÁTICO.. +++Ingresó en la UHB pero se marchó de ella. +++La Policía Judicial presentó ante el Juzgado de 1ª Instancia nº 5 de Mérida el ATESTADO 23/2021 en el día de ayer (07 de enero de 2021), del cual a día de hoy no han recibido respuesta. ++++++++++++++++++++++++++++++++++Hablo con Manuel Zambrano para comunicar esta situación a Salud Pública. Me da el teléfono de D. Diego Domínguez, Director del Área de Salud de Mérida (616-556055). +++Tenían conocimiento del caso, pero no me ha podido decir la fecha de la primera PCR: SI TRAS LOS DIEZ DÍAS DE AISLAMIENTO TRAS LA PRIMERA PCR, EN LOS TRES DÍAS ANTERIORES A FINALIZAR EL MISMO SE MUESTRA ASINTOMÁTICO, AUNQUE LA SEGUNDA PCR SEA POSITIVA SE CONSIDERA QUE LA PERSONA NO ES INFECTANTE. ES DECIR, NO HAY RIESGO DE TRANSMISIÓN. ++++++++++++++++++++++++++++++++++Hablo con el Jzgado de 1ª Instancia e Instrucción nº 5 de Mérida (924-380607): su Señoría dice que con ese atestado el Juzgado no puede hacer nada. Debe ser la Policía la que solicite a la Junta que se tomen las medidas sanitarias procedentes. Por lo tanto EL ATESTADO SE HA ARCHIVADO. ++++++++++++++++++++++++++++++++++Comunico nuevamente Mila (Policía Judicial UFAM) la información recibida tanto del Juzgado como de Salud Pública.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-08','(Pedro)Llamada de Pilar Martín. +++Dª Clememta ha dado Grado II. El Técnico PIA está de vacaciones. Vuelve a finales de enero. +++En la reewsidencia de Villar del REy no hay lista de espera para entrar, por lo que una vez se tramite el PIA será la primera en entrar.(TODO SUJETO A QUE SEA DE MANERA VOLUNTARIA). +++Plantea que ingrese y pagar los 800 euros de una plaza privada hasta que acceda a la pública: ya le he dicho que eso de pende de la situación económica. Tenemos que tener en cuenta que Cáritas estñá aportando la parte del Servicio de Asistencia docmiciliaria que no cubre con us pensión y que cabe la posibilidad, que sería lo más razonable, de tener que devolver el dinero que han adelantado para menatener el servicio (otra persona se puede benficiar de ello al igual que lo ha hecho Dª Clementa).Si hubiera que devokverlo, con el 25% que le queda de pensión tyras pàgar la plaza se podría ir pagando la deuda que haya con Cáritas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2021-01-11','Desestiman la solicitud de ingreso involuntario, por falta de competencia objetiva, proponiendo se realice la solicitud de modificación de capacidad, que por otro lado también se solicitó y se desestimó.','2');
