insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-01-12','Ana: Correo-e de Toni (ANTONIA SORIANO MARTIN, T.S. ADISER): "Buenos día Ana, y Feliz Año Nuevo. Te comento, no llevamos a término la autorización del vídeo porque ya no había tiempo suficiente para ello. Prepararemos una autorización en los términos que se nos indicó desde la Comisión y para la próxima lo haremos con más antelación. En relación a las vacaciones con su familia bien; solo que volvemos a pasar por la difícil situación de adaptación al centro. Estamos teniendo con él algunos problemas, todo relacionado con el consumo. Se que trajo algunas monedas de su pueblo y ha estado intentando quedar con un grupo de aquí de esta localidad para que le pasaran algo por las rejas, intentando Aitor salir del centro sin autorización y saltándose por entre las rejas y los setos. A partir de la próxima semana que estamos el equipo al completo empezaremos a trabajar con él este tema y pediré cita al CEDEX. Aitor nos comunica constantemente que él se quiere ir de aquí, y en parte es lógico, le ha tocado vivir además de la adaptación al centro y a nosotras, el encierro que supone no poder salir por el tema del COVID y que el resto de usuarios ronda los 40 años. Yo estuve leyendo en sus informes que a ser posible el centro residencial que se le adjudicara fuese en Cáceres, sé que la plazas de este tipo de centro son escasas e incluso nulas, pero me gustaría que si algún día hubiera alguna posibilidad se pudiera barajar. El día 12 de enero Aitor tiene cita en el Equipo de Salud Mental de Don Benito en Psiquiatría. El precio estipulado por el centro de este servicio que incluye el transporte y el acompañamiento, si éste corre por cuenta del centro son 30 euros. Dime a quién tengo que mandar esta autorización para que me la firme. No haría falta un ingreso extra de dinero porque se cogerían de su presupuesto mensual de 100 euros. Un saludo y vamos hablando." ························································································································································································ Mi respuesta: "Buenos días Toni, Espero que estéis bien. Lo importante ahora es el Seguimiento tanto desde Salud Mental como desde el CEDEX, así como vuestra intervención al respecto. Por este tipo de cuestiones nos replantearemos el autorizar o no nuevas salidas con su familia, pues, como estamos constatando, el trabajo de límites y hábitos a la vuelta es arduo para vosotras y el problema de consumo se retoma y acentúa… Si os sirve en la intervención, cuando lo consideréis, podéis utilizar también este argumento con Aitor. En cuanto al cambio de centro, deciros que ya, cuando hablé en su día con las educadoras del Centro de Menores de Trujillo, no sabía muy bien por qué se indicó la cercanía a Cáceres, pues de hecho el acercamiento a la familia no está claro que se positivo para Aitor… Además, en mi opinión, Aitor va a presentar estos problemas tanto en vuestro centro como en cualquier otro, pues lo que quiere es no tener límites, que nadie le establezca horarios y poder hacer lo que le apetezca cuando le apetezca (conductas y deseos propios de la adolescencia). Es cierto que el momento en que se ha producido el ingreso no es nada propicio y que está resultando difícil en general para la mayoría de las personas que residen en centros, más con población tan joven. Os pido paciencia. Y ante posibles alteraciones de conducta, primero vuestra intervención, segundo comunicarlo a la Unidad de Programas Asistenciales del SEPAD (poniéndonos en copia se queréis para hacernos conocedores de los hechos) y en caso de ser necesario, no dudéis en activar el 112. Confío en que esto no llegue a ser necesario, pero os indico todo para aclarar el procedimiento, por si acaso. Si llegado el caso, repito, confío en que no sea necesario, os vieseis en la necesidad de solicitar por vuestra parte cambio de recurso, tendríais que plantearlo a la Unidad mencionada. Por cierto, acabo de darme cuenta que la cita en salud mental es hoy, normalmente cuanto se hacen acompañamientos desde los centros a citas médicas no se hacen autorizaciones específicas. Si económicamente tampoco hay que pedir un extra, pues no habría que hacer nada más. En caso de que necesitéis sí o sí, la autorización, envíamela. Ante cualquier otra cuestión no dudes en contactar. Un saludo y buen día." ································································································································································································ Nuevo correo de Toni por la tarde: "...el tema de las vacunas no había tiempo para ello porque nos avisaron ayer por la mañana de que hoy vendrían a vacunar; no obstante tenemos una autorización firmada para el proceder por parte del centro para urgencias médicas firmada por el gerente. Hoy nos hemos puesto todos la vacuna incluido Aitor, supongo Ana que no habrá problema, si quieres te remito copia del documento que te digo. Un saludo y gracias por todo y perdona si te acribillo a correos, pero es que en estos temas de comisión no quiero hacer nada sin ponerlo antes en vuestro conocimiento. De todas formas nosotras siempre vamos a actuar velando por el bienestar de Aitor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-01-12','Queda sin efecto la videoconferencia que estaba prevista para hoy, en el Juzgado de Primera Instancia e Instrucción, nº 1, de Jerez de los Caballeros, en relacion con la motocicleta adquirida, resuelven que no procede adoptar medidas cautelares de inmovilización solicitada por nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-12','Ana: Correo-e de Pilar Martín, el día 8/01/21 (pilar.martinp@salud-juntaex.es): "Hola Ana, he hablado con la residencia de Villa del Rey y me dicen que por dependencia no va nadie por delante ahora mismo, le he dejado un correo a Manuel Casado que es el técnico PIA, yo me voy de vacaciones del 11 al 15. También he hablado con Mª Cruz (TS de Alcántara ) y me dice que también podría ocupar una plaza libre con un coste de 800 euros ahora mismo, y luego pasar a la plaza de dependecia cuando se le concediera en esa misma residencia. El teléfono de Mª Cruz es el 927/39-00-02 y el de la residencia 627-846-557 Alicia -directora. Un abrazo. El teléfono de Mané es el 22049." ···································································································································································································· Mi respuesta: "Buenos días Pilar, Ya leerás esto a tu vuelta, espero que hayas disfrutado de tus vacaciones. De momento el mes de enero lo tienen cubierto, si hiciera falta para febrero lo de la otra residencia se vería, pero si ella no quiere, por lo pronto no podemos hacer nada más. A ver si hay suerte y puede ingresar pronto en Villa del Rey. Un saludo." ··························································································································································································· A última hora recibo correo-e de Ana Soledad Porras Ramos, TS del Ayto. de CC (ana.porras@ayto-caceres.es): "Buenos días, Ana. ¿Se ha tomado ya una decisión respecto a la prestación del servicio municipal de ayuda a domicilio? Tenemos reservado un horario disponible... Gracias y un saludo." *Me pondré en contacto con ella el próximo día.','2');
