insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-01-12','Ana: Se remite por mail autorización para la vacuna Covid-19 para Santi a María González, TS ASPACE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-01-12','Ana: Correo-e del Consulado de Rumanía en Sevila (sevilla.consul3@mae.ro): "Buenos días, En relación con la solicitud del pasaporte del señor Costi Alexandru Rizea, tutelado por su entidad, le comunicamos que la cita para la renovación del documento es el día 20/01/2021, a las 14:05. Tiene que venir acompañado por un representante de la entidad tutelar, y tiene que aportar toda la documentación que usted nos ha mandado por correo electrónico, en original: -testimonio de la Firmeza de la Sentencia Incapacitación, -testimonio de aceptación del cargo de tutor, -una certificación para la persona que lo va a acompañar, que certifique que representa la entidad tutelar, -pasaporte anterior, -NIE (el certificado de registro de ciudadano de la UE). Se tiene que acordar que el día de la cita del pasaporte tiene otra cita ( a las 14:40) para solicitar su partida de nacimiento rumana (tarda entre 3-5 meses en llegar desde Rumanía), porque para la renovación del próximo pasaporte le va a hacer falta, ya que el próximo pasaporte va a ser un pasaporte electrónico con validez de 10 años. Un saludo" ····························································································································································· Mi respuesta: "Buenas tardes, Muchas gracias. Realizaré las gestiones oportunas para intentar que Costi Alexandru acuda el día de la fecha indicada. No obstante, nuestro tutelado es una personas dependiente que reside en un centro, veré si es posible que se le acompañe desde el Centro y les confirmaré la asistencia a ambas citas. Por otra parte, ¿sería posible que la persona que acompañase al joven acudiera con una autorización de la persona física que ostenta el cargo de tutor legal? Gracias por su atención. Un saludo." ·············································································································································································································· Envío correo a María Glez. Palomo, TS-Autismo Sur con copia a Miguel y Ángel, Jurídicos-CTAEX: "Buenos días María, He recibido del Consulado de Rumanía el correo que te envío. Hay documentos que nos pide, de los que no dispongo del original (como por ejemplo el anterior pasaporte y el original del certificado de registro de ciudadano de la UE), no sé si te los pasaron a ti desde el anterior centro. Otra cuestión importante, es si desde vuestro centro podríais acompañar a Costi para realizar estos trámites el día de la fecha que indican. Espero que así sea, si no, dímelo para que intente gestionar el cambio de la misma ((entiendo que vosotros que le atendéis a diario y le conocéis sois los más indicados) Por otra parte, pongo en copia a mis compañeros jurídicos, para ver si se te podría hacer a ti, o a la persona que nos indiques, una autorización para que podáis representar a la CTAEX vosotras mismas en dichos trámites, y así no tener que desplazarse nadie más desde la CTAEX también. Ya me contestáis cuando podáis desde las distintas partes. Gracias y un saludo."','2');
