insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-01-13','TERESA Ayer día 12 de enero de 2021 se pone en contacto con el equipo de apoyo social comunitario, por vía telefónica, Lupe la coordinadora de la Residencia La Salud de Villanueva de la Serena. Nos indica que han ingresado en el hospital al tutelado, debido a una hemorragia por vía oral posiblemente causada por sus problemas digestivos que son anteriores a la detección del contagio por covid19. Ya tenía pautado tratamiento para una úlcera estomacal, con revisiones periódicas. Desde el hospital, hasta la fecha, solo han informado al centro residencial que debe seguir ingresado para la realización de pruebas que determinen la causa de la hemorragia. En relación al contagio por covid19 sigue sin sintomatología.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-01-13','TERESA el pasado 12 de Enero se acompañó a Ramón González a los juzgados de Jerez de los Caballeros ya que tenía una citación a las 11:30h. Cuando se llega a los juzgados se va a la zona de registro civil para preguntar dónde se tiene que esperar para que llamen a Ramón y una de las trabajadoras del juzgado comenta que la cita de Ramón se ha anulado, se hizo el día anterior. La trabajadora comenta que ha hablado con alguien de la comisión para decírselo esa misma mañana y que ellos no sabían nada porque cuando se cancela una citación, primero se avisa a los abogados y luego a la comisión y todavía no les había llegado la información. Se les pregunta si se sabe para cuándo se va a aplazar la cita pero responden que no lo saben porque la compañera que lleva ese caso no está trabajando ese día en los juzgados. Se entiende que avisarán por escrito de la nueva cita. PIDO DOCUMENTACION DE LA MOTO A FUTUEX PARA INTENTAR DAR DE BAJA A TRAVES DE TRAFICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2021-01-13','TERESA RENDICION ANUAL continúa en su domicilio familiar en la C/ Miraflores, nº 50 de Villanueva de la Serena. Aurora mantiene contacto permanente con esta Comisión Tutelar. Convive con sus dos hermanos con los que mantiene una relación a veces tensa. La limpieza en la vivienda es escasa, así como su propia higiene personal. No se aprecian cambios con respecto al año anterior PERCIBE PF Y ORFANDAD ABSOLUTO SALDO 28.000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-01-13','TERESA RENDICION ANUAL ESTA CUMPLIENDO CONDENA EN EL HOSPITAL PSIQUIATRICO PENITENCIARIO DE SEVILLA . Es huerfano absoluto, tiene varios hermanos, con sus hermanas Consolación, Dolores y Angustias no tiene ningún contacto, Genaro se encuentra en Aprosuba de Cabeza del Buey y está también curatelado por esta Comisión Tutelar de Adultos y Manuel también interno en el Hospital Psiquiátrico de Mérida y tutelado por esta Comisión Tutelar de Adultos TIENE PF Y ORFANDAD ABSOLUTO SALDO50000€ HAY QUE PEDIR RECURSO DE CARA A FIN DE CONDENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='FERNANDEZ'),'2021-01-13','TERESA RENDICION No hay cambios con respeto al año anterior en cuanto a la situación de nuestro tutelado. Continúa ingresado en el CAMP “Ntra. Sra. de las Cruces” de Don Benito desde el 14 de noviembre de 1985. No tiene ningún tipo de contacto con familiares o conocidos. No realiza ninguna actividad por él mismo PERCIBE PNC CON ATP SALDO 38000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='ANDREU'and apellido2='DAVILA'),'2021-01-13','TERESA Dávila continúa residiendo en el Centro Residencial Ciudad de Lares que Aprosuba 9 tiene en Villanueva de la Serena. Está adaptado en su entorno y con el grupo de usuarios del Centro, participa y disfruta de todas las actividades que este año han tenido que ser talleres, debido a la situación por la pandemia. Ya que requiere apoyo extenso para las actividades de la vida diaria. PERCIBE PF Y ORFANDAD ABOS SALDO 48000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2021-01-13','TERESA RENDICION continúa residiendo en el Centro residencial de Plena Inclusión desde el 11 de junio de 2003. Se encuentra adaptado al Centro y acude al Taller de Mantenimiento del Centro Ocupacional. Visitaba mensualmente a su familia en Zafra. Las estancias en el domicilio familiar se han visto suspendidas o limitadas por la situación debida a la COVID/19 , siendo respetadas y comprendidas por el PERCIBE PNC SALDO 2.800€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2021-01-13','TERESA RENDICION V A DIA DE HOY SE ENCUENTA EN LA UDHAC (ASI LO PONE EN EL IFORME SOCIAL QUE SE ADJUNTA. Yolanda sigue presentando problemas conductuales, con agresiones a compañeros y cuidadores. Desde UDHAC se ha planteado un programa de refuerzo positivo PERCIBE PNC SALDO 6500€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2021-01-13','TERESA continúa residiendo en el Centro Residencial COMSER de Almendralejo abonando mensualmente 1450 € por la estancia. Es viuda y no tiene hijo. Como familiares directos tiene hermanos y una sobrina. PERCIBE VIUDEDAD Y JUBILACION . TIENE VARIAS CUENTAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2021-01-13','TERESA RENDICION Gallego continúa residiendo en el Centro la Casa de la Misericordia Padre Leocadio de Pinofranqueado. Durante este año ha sufrido un deterioro importante. Recibe llamadas telefónicas de su madre ya que es mayor y ya no puede visitarle, sus hermanos no le visitan. PERCIBE ORFANDAD Y PF SALDO 15000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='GARCIA'and apellido2='SANTOS'),'2021-01-13','TERESA RENDICION continúa residiendo en el Centro de Atención a Minusválidos Psíquicos “Ntra. Sra. de las Cruces” de Don Benito. Es independiente para las actividades básicas de la vida diaria. Participa en las actividades y excursiones del centro. Este año por caudas de la Covid/19 no ha podido recibir las visitas de una hermana que vive con su madre, la otra reside en Mad PERCIBE ORFANDAD Y PF SALDO 20000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2021-01-13','TERESA RENDICION se encuentra residiendo en la actualidad en el Servicio de Residencia de Madre Teresa Jornet en Don Benito. Se encuentra plenamente integrada en el centro. Es muy sociable y se relaciona con facilidad. No recibe visitas de familiares y/o amigos. Mantiene conversación telefónica con sus hijas esporádicamente PERCIBE PENSION DE VIUDEDAD Y VINCULADA AL SERVICO TODOS SUS INGRESOS LOS GESTIONA LA RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2021-01-13','TERESA RENDICION continúa residiendo en el C.A.M.P. “Nuestra Sra. de las Cruces” de Don Benito desde 1990 junto con otros 4 hermanos más, todos tutelados por esta Comisión Tutelar de Adultos de Extremadura. Su hermana menor Conchi es la única de los seis que no tiene discapacidad, esta reside en Madrid y cuando las circunstancias lo permiten suele viajar a Don Benito a visitarlos este verano no ha podido ser por causa de la pandemia PERCIBE PF SALDO 2000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-01-13','Buenos días Amalia. No me ha dado tiempo de contarte que ayer nos dijeron que ya tiene Cris la autorización firmada, me acaba de decir que te lo ha dicho ella, je A ver cuando nos llega y podemos ponernos en contacto con la endocrina para comenzar con el proceso de hormonas. Imagino que tardará un poquito por la situación tan complicada a nivel sanitario en la que nos encontramos en estos momentos. Lo que ocurre es que, al ponerse la primera dosis de la vacuna tienen que protegerse bien durante los primero 28 días para no contagiarse porque sino no se pueden poner la segunda y eso a ella la ha disgustado mucho, piensa que es cosa nuestra y está bastante enfadada. Te lo comento porque seguro que te llame para decirte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2021-01-13','-AMALIA: RAFAEL HA ESTADO UNOS DÍAS ALOJADO EN EL CENTRO DE EMERGENCIA DE CÁRITAS EN MÉRIDA , UBICADO EN EL ANTIGUO HOSTAL SALUD. ES UN CENTRO HABILITADO SÓLO PARA ACOGIDA HASTA ABRIL DE 2021 COMO APOYO AL CENTRO HERMANO POR LA SITUACIÓN PROVOCADA POR EL COVID. EL TS ES DAVID TOBAJA TF 674629463 . HE HABLADO CON INMA , TS DEL CTRO . HNO QUE ES LA QUE ME FACILITA ESTA INFORMACIÓN. AL INGRESAR LE HICIERON LA PRUEBA COVID Y DIÓ POSITIVO . ESTUVO INGRESADO EN LA UHB Y AL ALTA VOLVIÓ AL CENTRO . PERO SE CANSÓ DE HACER EL AISLAMIENTO Y SE MARCHÓ DE ALLÍ EL DÍA 5 DE ENERO . HE PEDIDO QUE SI VUELVE SE PONGAN INMEDIATAMENTE EN CONTACTO NOSOTROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-01-14','Ana: el día 12 por la tarde las educadoras del CAM Francisco de Pizarro, Trujillo, remitieron un email con la Resolución de PFHC de Aitor, que a pesar de venir a nombre de la CTAEX, le remitieron a ellos. Le aprueban la PFHC (395,60€ x 12) con fecha de efectos 01/10/20. *Atrasos que ingresarán: 1.186,80€ ····························· Volveré a comunicar a la Seg. Soc. la dirección a efectos de comunicaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-01-14','TERESA TELEFONO DE SU HERMANO RAMON 642582774','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-01-14','Ana: Tras recibir llamada de José, Director de la Residencia de Jaraicejo (608 962 782) y leer el correo-e de Toni-Futuex, de ayer, llamo a Ángel, Asesor Jurídico. ··············· A posteriori remito correo a Toni-Futuex con copia a José, director de la Res. de Jaraicejo (josevillegassanchez356@gmail.com): "Buenos días Toni, Como sabes ayer no trabajé y tengo aún correos pendientes por revisar... En relación a este caso, es mi compañero Miguel, Asesor Jurídico, quién estuvo en contacto en septiembre, en distintas ocasiones, con el abogado que representó a Isabel. Te copio aquí lo que anotó en la Intranet al respecto tras una de las conversaciones: “…me confirma que es inviable el recurrir la sentencia porque es absolutoria y únicamente contiene la prohibición consistente en la expulsión del municipio durante 6 meses. Sólo queda por tanto como vía alternativa una vez que esté en trámites el procedimiento de ejecución comunicar y justificar al juzgado motivo por el que no se puede cumplir dicha sentencia (incluso solicitando un cambio de dichas medidas de prohibición). Pero me asegura que hoy por hoy al ser una sentencia absolutoria (sin multas ni prisión) no se puede hacer más.” He hablado esta mañana con José, Director del recurso, y posteriormente con Ángel, compañero Asesor Jurídico. Hoy mismo enviará un comunicado al Juzgado, explicando que no es viable que abandone el recurso residencial, pues no tiene dónde ir. *Comunicarte, que en cualquier caso, se pidió un cambio de recurso por acercamiento familiar a Plasencia (solicitud modificación PIA) en abril de 2016, pero aún debe seguir en lista de espera… Lo consulté en marzo de 2020 y sigue igual. Esta información también la añadirá Ángel al escrito. Pongo en copia a José, director de la residencia de Jaraicejo, para que esté al corriente de las gestiones previas y las que se llevarán a cabo a día hoy. Gracias a los 2 ( y a Gloria). Ante cualquier otra cuestión, seguimos en contacto. Un saludo." ································· Respuesta de José, Director del Centro: "Muchas gracias Ana por la información, a ver si tenemos suerte y no tiene Isabel que marcharse, porque para ella sería un golpe muy duro. Un saludo!!!" ······························································································································································································· Correo de Toni-Futuex: "...Comentarte solo en relación a este asunto, que según me dice la compañera en verano estaba la segunda en la lista para la residencia San Francisco de Plasencia, suponemos que no se habrá movido nada con todo este asunto, me dice que en Julio se reunió con la ts de la localidad, te paso datos de contacto por si os resultara de interes de cara a la notificación al juzgado : M. Jesús Gómez Lozano, 927 33 60 04 es el del ayuntamiento de Jaraicejo, va los lunes" ···················· Respondo agradeciendo la información y pongo en copia a Ángel-CTAEX, para que esté al corriente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-01-13','Ana: Correo de Toni-Futuex: "Buenos dias, a continuación hacemos llegar una informacion remitida por el gerente de la residencia de Jaraicejo donde se encuentra Isabel Muñoz, en relación a un asunto júridico en el que se deben presentar alegaciones para que no abondone la localidad (fue denunciada por una vecina). El gerente se muestra absurdamente enfadado con la comisión, para que lo tengais en cuenta si teneis que contactar con el centro. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-01-14','Ana: Correo del Alberto, Jefe de Secc. Ecca.: "...En relación con el asunto de la vivienda de la tutelada, Feli, la Secretaria del Director Gerente, nos ha informado que el nieto de Manuela esta llamando insistentemente a José Vicente, muy enfadado, exigiendo una reunión con el. Se queja de la falta de solución y comunicación de la misma por parte de la CTAEX. Es probable que José Vicente nos convoque para darle toda la información. Me decís lo que sea."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-14','Ana: envío un correo-e de Ana Soledad Porras Ramos, TS del Ayto. de CC (ana.porras@ayto-caceres.es): "Buenos días Ana Soledad, Pues aún no me han dado respuesta desde la secc. Económica. Si bien es cierto, yo no he insistido ni vuelto a preguntar, pues a fecha de hoy Clementa continúa teniendo atención 24 h. con 2 auxiliares, una los días de diario y otra los fines de semana, gracias a la ayuda de Cáritas. Por otra parte ha aceptado el PIA para ingreso en la Residencia de Villa del Rey, donde al parecer hay plaza, pero no sé si se demorará mucho el ingreso. Me da apuro, y no parece bien, que tengáis reservado el servicio, habiendo seguramente más personas que lo necesiten, pero dado lo complejo del caso y la necesidad de atención que presenta esta persona… tampoco me atrevo a rechazarlo directamente. Desde luego para enero no lo necesita. Así que, en consecuencia, tomad la decisión al respecto que consideréis desde el servicio. En mi opinión, lo ideal en este caso, sería el ingreso voluntario en residencia, al menos dada su situación actual. En el futuro ya se vería. Disculpa las molestias y la falta de respuesta hasta el momento y gracias por tu implicación. Un saludo. PD. Pongo en copia a Pilar, TS del Equipo de Salud Mental, para que pueda leerlo a su vuelta de vacaciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2021-01-14','TERESA ENVIO SOLICITUD CAMBIO N DE CUENTA PF','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2021-01-14','Ana: Envío correo a Gema, Res. El Pendere, de Santiago del Alcántara con la Autorización de la Vauna Covid relativa a D. Arturo José firmada mediante huella digital por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-01-14','Ana: Correo de Felisa Custodio, TS del CAMF - Alcuescar: "Buenos días, les informo que en relación a la solicitud por la compra de cojín asiento para silla de ducha; subvención para beneficiarios/as de centros estatales para personas con discapacidad cuya titularidad corresponde al IMSERSO, según la Resolución de 1 de septiembre de 2020, para silla de ducha; ha llegado Resolución aprobatoria por importe de 98,62 euros. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-01-14','Ana: Correo de Noelia, TS de la Res. Cervantes: "Hola! He informado al Sexpe de la nueva dirección de los residentes Guillermo Galán Gilgado y Eugenia Pacheco Vicente. Saludos" ····················· Mi respuesta: "Hola Noelia, Ok, gracias. Supongo que ya estarás pendiente tú de la renovaciones de la demanda de empleo, verdad? Ya nos vas diciendo. Un saludo." ······································································································································································································· Nuevo correo-e de Noelia, TS CR Cervante, nos remite por mail la RENOVACIÓN de la DEMANDA DE EMPLEO. Próx. fecha de renovación: 15/04/21. Guardo el documento en su expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-01-14','Ana: Correo de Noelia, TS de la Res. Cervantes: "Hola! He informado al Sexpe de la nueva dirección de los residentes Guillermo Galán Gilgado y Eugenia Pacheco Vicente. Saludos" ················································ Mi respuesta: "Hola Noelia, Ok, gracias. Supongo que ya estarás pendiente tú de la renovaciones de la demanda de empleo, verdad? Ya nos vas diciendo. Un saludo." ································································································································································· Nuevo correo-e de Noelia, TS CR Cervante, nos remite por mail la RENOVACIÓN de la DEMANDA DE EMPLEO. Próx. fecha de renovación: 19/02/21. Guardo el documento en su expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-01-14','En relación con la medida impuesta a Dª. Maria Isabel Muñoz Melchor, en la sentencia nº 34/20, dictada por el Juzgado de Primera Instancia e Instrucción, nº 1, de Trujillo, en el procedimiento LEV JUICIO SOBRE DELITOS LEVES 4/2020, ponemos en conocimiento del Juzgado la imposibilidad de cumplir dicha medida, toda vez que ella tiene plaza en la residencia de Jaraicejo y no tiene plaza en otra residencia de otro municipio, prueba de ello enviamos también la solicitud que se hizo para trasladarla a la Residencia San Francisco, de Plasencia, en 2016 y que a día de hoy no se ha resuelto. Comentar que la sentencia no es firme, está pendiente de dictarse la ejecutoria. No obstante, el Juzgado ya conoce nuestro parecer al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-01-15','Ana: Una vez leído el correo de Ángel, Asesor Jurídico CTAEX, remito correo-e a José, Director Res. Jaraicejo (josevillegassanchez356@gmail.com): "Buenos días José, ¿qué tal? Tan sólo, informarte de lo que me transmite mi compañero Ángel, Asesor Jurídico - CTAEX, literalmente: “Ayer envié el escrito al Juzgado, por el correo electrónico de la oficial que lleva el expediente”, “No obstante, comentarte que la sentencia en la que se decide la medida, no es firme y que para su ejecución está pendiente dictar la ejecutoria. Aún así, nuestra postura ya la conoce el Juzgado, para que la tenga en cuenta.” Ahora sólo queda esperar a ver qué determinan en el Juzgado, en cualquier caso espero que sea favorable para Isabel. Ante cualquier cuestión, no dudes en volver a contactar. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-01-11','Correo de Sonia Bernabé, ASINDI, al ctutelar@: "...- Felisa Bruno hoy ha sido derivada y ha quedado ingresada en Salud Mental porque esta mañana presentó conducta con agresividad. Haremos seguimiento y mantendremos informados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-01-15','Ana: Conversación con Sonia Bernabé: Felisi continúa en la UHB, Hpal. CC, pero evoluciona favorablemente, seguramente el próximo lunes le den el alta. *Le han hecho tanto PCR como prueba de Serología y ambas han dado negativo en Covid. ·····················*El día que presentó las conductas disruptivas, estaba alterada, en gran parte poque le afectó negativamente los cambios de habitación y de zonas (reorganización en el centro residencial) acaecidos en el centro con motivo de los casos positivos de Covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='REMEDIOS'and apellido2='CASATEJADA'),'2021-01-15','TERESA ESTABLECEMOS PRESPUESTO GASTOS DE BOLSILLO 100 € AL TRIMESTRE POR REINTEGRO HABLO CON LA TS M CARMEN PARA QUE ME FACILITE LOS DATOS DE LA PERSONA AUTORIZADA PARA QUE PUEDA SACAR EL DINERO EN LA PRIMESA SEMANA DE CADA TRIMESTRE Y NO GENERAR DEUDA EN LA RESIDENCIA QUE QUE EL TUTELADO NO PUEDE DESPLARSE A LA ENTIDAD BANCARIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-01-15','TERESA MANDO DOCUMENTACION QUE ME FACILITA ANTONIA LA TS DEL SSB DE ALMENDRALEJO, LA ENVIO POR EMAIL A J.MARTINEZ@CAJALMENDRALEJO.ES ME RESPONDE QUE NO ES LA DOCUMENTACION QUE NECESITAN, NOS QUEDAMOS A LA ESPERA DE LA QUE NOS MANDEN EL JUZGADO LA SENTENCIA DE INCAPACITACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-01-14','Ana: Recibo llamada de Carmen Martínez, TS del SSASB de Coria (927 50 80 00 Ext. 318 // carmen.martinez@coria.org). Han nombrado a la CTAEX Defensa Judial de Emilia. El Auto ordena litaralmente se proceda ", se proceda a “la inmediata apertura de cuenta corriente titularidad de Dª EMILIA GUTIÉRREZ SERRADILLA con DNI 06881495X en entidad bancaria Caja Almendralejo sucursal de Coria, Cáceres, o si excepcionalmente ello no fuera posible, en otra de las de esta ciudad”. **El banco Santander decidión unilaterlamente cerrar la cuenta de esta Sra. En consecuencia, lleva varios meses sin cobrar la pensión, le han cortado los suministros, está sin dinero y sin comida. *Con el único familiar con el que mantiene relación es un hijo con el que convive, pero éste presenta problemas por consumo de sustancias tóxicas. *Desde el SSASB, han intentado abrir cuenta en distintas sucursales bancarias, pero no lo han conseguido. ················ *Hablo con Alberto, Jefes de Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-01-15','Ana: Convesación con Belén, Secc. Ecca. CTAEX, ha hablado ya con Caja Almendralejo, a pesar de las reticencias se procederá a la apertura de cuenta (mediante trámites habituales con personas incapacitadas - Asesoría Jurídica). *Necesitarán que acudan a llevar el DNI para su digitalización. ··················································································································································· Llamo a Carmen, TS Coria (927 50 80 00 Ext. 318); solicitará a la Policía Local que la acompañe a la sucursal a digitarlizar el DNI. *Cuando tengamos el nº de cuenta se lo facilitaré para que puedan solicitar la activación de las pensiones (percibe jubilación + viudedad. Unos 800€/mes apróx.). *Acudirá también al domicilio para solicitar recibos de los suministros y nos hará un presupuesto aproximado de gatos para fijar una asingación semanal. ·············································································································································· Llamada de Belén, CTAEX, en Caja Almendralejo le han dicho que no van a abrir la cuenta a esta Sra. *Les ha pedido que respondan por escrito a su solicitud para poder comunicarlo al Jdo. *Probarán en otras entidades bancaria. ············· Lo comunico por escrito a Carmen Martínes, TS (carmen.martinez@coria.org)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-01-15','Ana: Remito a Chus, Responsabel PP.TT. Tierra de Barros (tierradebarrosserv.sociales@gmail.com), el Consentimiento Informado para la administración de la vacuna Covid relativa a Esteve, firmada mediante firma digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-15','Ana: correo-e de Ana Soledad Porras Ramos, TS del Ayto. de CC (ana.porras@ayto-caceres.es) de ayer por la tarde: "Buenas tardes, Ana. Viendo la situación actual consideramos conveniente tramitar la baja definitiva del Sad municipal. Gracias por todo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2021-01-15','Ana: Envío a Paz Boticario, Hermanos de la Cruz Blanca (et-caceres@cruzblanca.org), el Consentimiento Informado para la Vacuna Covid, firmada digitalmente.','2');
