insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-01-15','Ana: Envío a Paz Boticario, Hermanos de la Cruz Blanca (et-caceres@cruzblanca.org), el Consentimiento Informado para la Vacuna Covid, firmada digitalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-01-15','Ana: Llamo a María González Palomo, TS - Fundación Autismo Sur (693 759 016): Justo esta semana está de vacaciones... En principio acordamos que se le acompañará desde su entidad, el problema principal de nuevo, la falta de ingresos de Alexandru, pues supone un gasto importante y la entidad continúa con déficit económico. Tienen que hablarlo con la Gerente. *Será necesario que le acompañen 2 personas, debido a su patología, se pone muy nervioso al viajar en coche. **Hablaremos de nuevo el lunes. Tendrán que facilitarme los datos de la persona a la que se le autorizará desde la CTAEX, para que acuda en representación del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2021-01-15','Ana: Llamada de Jesús Manuel (635 336 539), dice que necesita dinero para comprar el lunes una botella de butano. Dice que como no consigue hablar Alberto ni con Icíar me llama a mí. ··· *Se lo comunico a Alberto, Secc. Ecca. por mail.','2');
