insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-01-15','Ana: Correo de Noelia, TS de la Res. Cervantes-CC: "...La prueba de detección precoz de cáncer de colon de Mª Luisa Montaña se la van a realizar en el centro. Ya está pedida al laboratorio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-01-15','Ana: correo-e de Noelia, TS C. Residencial Cervantes (noelia.garciac@salud-juntaex.es): "...Se ha solicitado la intercconsulta al Equipo de Salud Mental de Cáceres para Eugenia Pacheco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GUTIERREZ'),'2021-01-14','EXITUS El letrado, José M. Escalona, informa (adjunta certificado) la defunción de Dña. María del Carmen. Ésta tuvo lugar el 02/01/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-01-18','Ana: Nuevo correo de Toni, Asiser, durante el fin de semana: "Buenas tardes Ana, solo hacerte una consulta, porque prefiero preguntar y que tú me asesores. Aitor al estar incapacitado y tutelado por vosotros, sois vosotros los responsables (por decirlo de alguna forma) de su bienestar y seguridad. Pero al estar aquí en el centro, nosotros somos los responsables de su bienestar a todos niveles. Te digo esto porque ayer ante una actitud sospechosa y rara de Aitor, intentando salir del centro sin permiso (más que nada también porque estamos vacunados), hoy le he mirado el móvil, cosa que he hecho pensando siempre en su bienestar, y he visto una conversación con una persona de aquí de Castuera, donde le dice que le pasa un lote de productos que suyos y otros que ha robado al resto de compañeros (caja tila, colonia, cortauñas,...) y al centro a cambio de 2 porros. Esta cuestión la hemos puesto en conocimiento de la policía local de Castuera, para que vigile el centro por las tardes y noches, y puedan darnos cierta seguridad y controlar que en el centro no entre, bajo ningún concepto, ningún tipo de drogas. Pero el sentido de este correo, es conocer de vuestra mano, hasta donde podemos llegar nosotros desde el propio centro, en cuanto a decisiones a tomar, con respecto a Aitor. Y si está registrado en algún documentos cuales son nuestras competencias con respecto a aquellas personas que se encuentran tuteladas por la comisión. Un saludo" Pido a Ángel y Miguel, Asesores Jurídicos CTAEX, que le den respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-01-18','Ana: Envío a Julio, Admvo. de la Res. May. San Antonio de Valencia de Alcántara (auxdireccionspa@valenciadealcantara.es) el C.I. para la Vacuna Covid, firmado digitalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-01-18','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, adjunto te remito informes que nos mandaron al ingresar Aaron. Revisaré por si tenemos alguno más. Te mandaré uno que referente a el tiempo que lleva en ASINDI. Un saludo" *Adjunta un informe educativo del Centro PROA y el informe final del Piso de Menores gestionado por la entidad CERUJOVI.········································································································ Mi respuesta: "Buenos día Sonia, Ok, gracias. Me ha venido bien poder leer los informes del joven para conocer mejor el caso. Eso sí, además del informe actualizado que nos enviéis, recuerda que necesitamos informe médico también para que mis compañeros hagan la solicitud de ingreso en al UHDAC al Juzgado. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-01-18','llega citación del Juzgdo de 1º instancia nº1 de Badajoz sobre el procedimiento X53 Conciliación 923/2020 para vista del día 20-1-21 a 9h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-01-18','Ana: Correo de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): "Hola, os quería informar que el viernes hicieron una segunda PCR a los residentes y profesionales que dieron negativos en la primera, y el sábado por la noche nos comunicaron que Ignacio Rodríguez Alcántara es positivo. El se encuentra sin síntomas, según me indican las compañeras. Está en una habitación de aislamiento y de momento lo lleva bien. Os iré informando, pero ahora esperemos que esté sin síntomas y que se le pasen rápido los 10 días. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-01-18','Ana: Llamada de Leticia, Enfermera del ESM-CC (927 213 730), lleva una semana intentado contactar con Saturnino sin éxito. Le informo de que ingresó en el penitenciario el pasado mes de diciembre. Se coordinará con la TS del equipo para que a su vez se coordine con las TS del Penitenciario para establecer el seguimiento de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-01-18','Ana: Llamada de Damián, le explico que hablé con Ana Benavente y que me dijo que había había solicitado que volvieran a valorarle de dependencia y adjuntó el informe de psiquiatría de septiembre de la nueva Psiquiatra. Además le tranquilizo de nuevo, él ya tiene su plaza en el CRR. ······· *Por otra parte dice estar arrepentido de la solictitud que hizo a la abogada y por la carta que ésta ha remitido al CRR. No ha firmado el documento que la abogada envió. Por último, comenta que ayer dijo a una monitora que en agosto, cuando su piso quede vacío le gustaría irse allí. Pero que lo ha pensado mejor y aún no se siente preparado para vivir solo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-01-18','Ana: Llamada de José Mauel (678 150 472). Ha acudido hoy a la consulta de Psiquiatría. Dice que le han cambiado la medicación. Y le ha dicho que está el 3º en la lista de espera de acceso al CRR. Por otra parte, expresa que necesita cortarse el pelo, cuestión que corrobora Pilar Martín, TS ESM en un correo. *Se lo digo a Alberto, jefe secc. ecca. mediante un email. ································································································································································································· Respuesta de Alberto, jefe secc. ecca: "Hola Ana. Ya le han devuelto el dinero de las compras de Amazon tras la gestión de Iciar. De momento seguimos con la misma cuenta. Hace tiempo quedé con Iciar en que si tu estabas de acuerdo, las gafas se compraban x se una cuestión sanitaria. Resto de cuestiones...de su asignación. Le he reiterado a Iciar que si tu has dado el ok a las gafas...las compramos (se pondrá en contacto contigo si no lo había hecho ya)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2021-01-18','Ana: Correo-e de Maribel, TS de la Re.M. Ciudad Jardín Parque del Príncipe (trabajosocial@grupociudadjardin.com) : "Buenos días, Ana: Te adjunto la resolución del SES de Rafael Fernández Bermejo en la que le estiman la solicitud de reintegro de gastos ortoprotésicos, concretamente la silla de ruedas que se le pidió. Saludos" *Le ingresarán 285,15. Se lo comunico al Alberto, Jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-01-18','Ana: Correo de Alberto Arias Bueso, EVD (alberto.arias@salud-juntaex.es): "Buenos días Ana, hasta hoy no me ha llegado la documentación por registro. Me ha llegado aceptación para solicitar plaza pública residencial, aceptación ayuda a domicilio pública y aceptación y alta de terceros de una prestación económica a ayuda a domicilio. Si desea ayuda a domicilio por empresa privada me falta el contrato con la empresa. Dime lo que sea. Un saludo y gracias." ······································································ Mi respuesta: "Buenos días Alberto, Pues sí que está mal el registro…. Hace mucho que lo puse, daba por hecho que estaba todo tramitado…. Lo último que hablamos, pues así me lo recomendabas, que se le daba prioridad al SAD de gestión municipal, y que estarías pendiente de las listas, creo recordar. NO obstante, en su día estuve en contacto con una empresa para el SAD privado y pedí presupuesto, pero a día de hoy no sé si continuará en vigor… igual no tiene que hacer uno nuevo… consulto y te digo. Dime tú si puedes si tienen posibilidad con el del Ayto. ..." ························································································································································································································· Respuesta de Alberto Arias: "Con el Ayuntamiento a día de hoy se pone el primero en lista de espera. Si solo va a querer la del Ayuntamiento no tramitaría la prestación económica vinculada a la ayuda a domicilio privada." ····· *En principio lo dejaremos así, si se demorara mucho el SAD municipal se tramitaría el privado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GRANADA'and edp.apellido1='CANO'and apellido2='MARQUEZ'),'2021-01-19','EXITUS FUTUEX informa de su fallecimiento el 15/01/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2021-01-19','Ana: hasta día de hoy no se da registro al escrito a PNC. ··················· Llamo a Marina Carmen Cintas, jefa de secc. PNC (924 00 59 22) y le explico la situación actual. Tendrán que pedirle a ella los contratos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='SANCHEZ'and apellido2='BANDA'),'2021-01-19','EXITUS El centro informa de su fallecimiento, acaecido en el el H. de D. Benito-Villanueva, 19/01/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-01-19','Ana: En relación a la consulta que realizan sobre la autorización para administrar la vacuna del Covid a Adela, tras varios intentos en los días previos, contacto con María Álvarez, TS del Aldea del Cano (924 38 30 02) y Alcuescar (924 38 40 02) - (Mancomunidad - Sierra de Montánchez: 927 38 90 30) y le explico que como Defensa Judicial, la CTAEX no puede firmar dicho documento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-01-19','Ana: Llama de José Manuel (678 15 04 72): le comunico que se ha autorizado la compra de las gafas. Que el resto de gastos debe hacerlo con su asignación. *José Manuel acudirá mañana a la óptica. *Envío un correo a Icíar para que se ponga en contacto con la óptica para comunicar el ok y que le envíen el presupueto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-01-19','TERESA RECIBO LLAMADA DE MARIBEL, PAREJA DE PEDRO PARA EL TEMA DE LA BODA LO COMENTO CON EL DEPARTAMENTO JURIDICO En estos casos, ocurre igual que cuando nos plantean la opción de otorgar testamento por un incapaz, cuando la sentencia de incapacitación no lo contempla. En teoría, si cuentan con un dictamen médico que acredite su aptitud para prestar el consentimiento, podrían casarse. Ahora bien, en la práctica, ningún médico va a comprometerse en esto. En este caso además, Pedro Tomás cuenta con una incapacidad total, con privación completa de su capacidad patrimonial y personal, privándole incluso de hacer testamento. ¿Cómo va a ser capaz de gobernar un matrimonio?. Y a la pareja la conozco porque fui a un juicio con ellos y está poco más o menos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2021-01-19','Ana: Tras conversación con Marina Carmen Cintas, jefa de secc. PNC (924 00 59 22 / marinac.jimenez@salud-juntaex.es) le envío el siguiente correo: "Buenos días Marina Carmen, Tal y como hemos acordado esta mañana mediante conversación telefónica, te adelanto adjunta la solicitud de cambio de datos bancarios relativos a Dña. Rosa Marín Laureano, con DNI 00066159B, tutelada por la Comisión Tutelar de Adultos. Adjunto así mismo el Certificado Bancario y la copia del DNI renovado. Recordar que desde el mes de abril no percibe la PNC, pues se haya en suspensión cautelar debido a dificultades con la entidad bancaria anterior y a las complicaciones añadidas para poder renovar su DNI, por hallare encamada y por la situación de crisis sanitaria. Solicitamos se reactive la misma y se abonen los atrasos correspondientes. Gracias y un saludo." ·························· *Pongo la solicitud de modificación de datos bancarios para REGISTRO de ENTRADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-01-19','Ana: Correo de Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Me dispuse a escribir a Pedro, pero veo que hasta el día 25 no se incorpora... Te escribo porque ayer pidió hablar conmigo Juan Carlos Ruíz García que como sabes cumplió su pena en el psiquiátrico penitenciario de Sevilla y se ha incoporado a la UHDAC hasta que el SEPAD le busque una plaza en un centro de discapacidad...Le está costando adaptarse ya que le gusta estar al aire libre, en Sevilla cultivaba un huerto, cuidaba pájaros y aquí eso desgraciadamente no podemos ofrecérselo... Una de sus demandas era que lo llamara su tutor...así que te agradecería que lo llamaras tú hasta que pueda hacerlo él....No sé si lo conoces, tiene una discapacidad importante, apenas tiene adquirido el lenguaje y su nivel de comprensión es limitado por lo que hay que hablarle con frases cortas y simples... Muchas gracias, Ana. Saludos" ······················· Mi respuesta: "Hola Estrella, Acabo de leerlo. No tengo inconveniente en llamarle, aunque yo no le conozco ni he hablado nunca con él. Dime día y hora e intentamos cuadrar. Un saludo." ·························· Acordamos que llamarán mañana a las 12 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-01-19','Ana: Entrego a Charo, Secc. Discapacidad, en mano la Aceptación PIA del Servicio Residencial en Asindi de Felisa, debidamente firmado y sellado por el D-Gerente. Me quedo copia firmada como Recibí para el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-01-19','NOTA INTERIOR. Se remite por nota interior a Unidad de Programas Asistenciales (A/A de manuela González Delgado), escrito informando sobre la no formulación de alegaciones al documento de la Comisión técnica de observación sobre cambio de PIA a recurso residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2021-01-19','Ana: Solicito a Noelia, TS RM Cervantes, por mail, la factura original del cojin abductor, para la solicitud de la ayuda para material ortoprotésico del SES. ················································································ Cumplimento el modelo de alta a terceros y lo pongo para la firma del D.Gerente. *Las compañeras lo llevarán al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-01-19','Ana: Pongo para REGISTRO DE ENTRADA las comunicaciones de cambio de domicilio y domicilio a efectos de comunicaciones al INSS (Tanto para PFHC como para Orfandad).','2');
