insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2021-01-20','TERESA ENVIO AUTORIZACION PARA PARTICIPAR EN PROGRAMA DE CANAL EXTREMADURA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-01-20','miguel, Jesus el abogado del procedimiento de gastos extraordinarios me adjunta la remisión del modo de citación por videoconferencia a la ctaex y solicitud al juzgado para que no citen al tutelado. Asimismo ha hablado con el arquitecto quién le confirma que asistirá presencialmente para acreditar la necesidad del arreglo de la vivienda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-01-20','miguel, acudo a la citación del procedimiento de acto de conciliación que nos llego ante de ayer, el cual concluye sin avenencia y por tanto nos volverán a citar. Doy mis datos al procurador para que el abogado se ponga en contacto conmigo acerca de este procedimiento. Parece ser que los 147.000€ que hay en la cuenta de nuestro curatelado son reclamados por una hermanastra, pues parece ser que fruto de un matrimonio anterior del padre donde tuvo otros dos hijos, los cuales reclamarían que dicha cantidad se divida entre 3. Recordemos que el padre era guardiacivil desaparecido durante más de 12 años y dado por muerto (y este dinero corresponde a una indemnización)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-01-20','Ana: Correo de ayer de Felisa Custodio, TS CAMF-Alcuescar: "Estimada Ana, refiere la residente que ha recibido en su antiguo domicilio un aviso de recogida de carta de la Seguridad Social, de Madrid. No sabe darme más datos, ya pasó en otra ocasión, hicimos el cambio de domicilio por teléfono pero se lo siguen mandando a Segovia. Estamos llamando al tfno. de la Seguridad Social pero es imposible, he pensado llamar también a la Seguridad Social de Madrid pero hay muchas oficinas y la carta puede ser de cualquiera de ellas. No sé si desde la CTAEX tenéis acceso más fácil a la Seguridad Social para poder averiguar que carta es la que están intentando notificar a la residente. Ya me dices. Muchas gracias." ··································································································································· Mi respuesta: "Buenos días Felisa, Espero que estéis bien. En relación a lo que informas sobre Carmen, puesto que percibe una PNC, en principio no sé de qué puede tratarse la carta del INSS. Y tampoco sé, por qué habiendo modificado ya la dirección se lo siguen enviando a su domicilio anterior… A nosotros nos ha pasado con escritos acerca de algunas pensiones y lo que hemos hecho ha sido registrar nuevas comunicaciones indicando la dirección a efectos de comunicaciones. Nosotros no tenemos contacto directo con ninguna de las oficinas del INSS de Madrid. Si no conseguís contactar telefónicamente, igual podéis enviar alguna comunicación de este tipo. No obstante, si el aviso para recogida de la carta es de correos, y en 10 días no recoge la carta, supongo que se la devolverán al INSS y desde aquí revisarán los datos e intentarán de nuevo enviarla o ponerse en contacto de otra manera. Siento haber sido de tan poca ayuda. Ya me dirás si averiguáis algo. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-01-20','Ana: Llamada de Carmen, TS del SSASB-Coria (927 50 80 00, Ext. 318) le informo de que aún no hay novedad con respecto a los bancos. Además, la compañera de la secc. ecca. que se está encargando está de vacaciones. Le preguntaré el lunes. ······ Ha llamado a la Seg. Soc. y excepcionalmente podría cobrar por ventanilla una mensualidad, siempre y cuando haya 2 negativas a abrir cuenta de distintas entidades bancarias. Ya tienen la del Santander, que le cerró la cuenta. Y necesitaría por escrito la negativa de Caja Almendralejo a abrirle una. (*Belén, CTAEX, ya se lo pidió a la Caja)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-01-20','Ana: Se pone para la firma del D.Gerente la solicitud de PNC-Andalucía. ······································································································································· En cuanto la Renovación del pasaporte, acudían hoy desde la F.Autismo Sur, a realizar la gestión con Costi al Consulado de Rumanía en Sevilla. *Ángel, Asesor Jurídico CTAEX, envió esta mañana a primera hora la Autorización para que hicieran la gestión en nombre de la CTAEX (Tanto a María, TS de Autismo Sur, como al Consulado de Rumanía). ············································································································ Llamo al final de la mañana a María, TS F.Autismo Sur (693 759 016), Todavía están en el Consulado. En la primera gestión al parececer no han sido muy agradables con ellas. Y el viaje para Alex ha dido un suplicio. Acordamos hablar mañana de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-01-20','miguel, me llega por Juan P. una providencia del juzgado nº2 de Plasencia, procedimiento X15 Disposicion de bienes del discapacitado 533/2020, que tras hablar con Juan Carlos del Juzgado me dice que ha interpuesto este procedimiento la tutelada por su cuenta y riesgo, de forma privada, es decir que ha contratado a un abogado para solicitar la venta de todos los inmuebles que es propietaria. Al enviarme sólo la providencia y darme un plazo de 5 días, me indica que acaba de enviarme a lexnet el resto de documentación, demanda, etc. Que una vez nos llegue le avisemos para que comience a contar los 5 días. Se lo reenvío a Angel ya que él tenía en trámites la venta de un inmueble con una abogada de oficio, ya que creo que debe de tratarse de los mismos bienes. Evidentemente al haber contratado dicho abogado sin conocimiento de la Ctaex, la tutelada habrá de hacerse cargo del pago del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-01-20','Ana: Se pone para la firma del D.Gerente, comunicaciones al INSS de variación de datos bancarios, tanto para P.Orfandad como para P.F.H.C. Con el nuevo nº CCC que me facilita Icíar, CTAEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-01-20','Ana: Ante la imposibilidad de hablar con Marta-TS, llamo al Ayto. de Cilleros de nuevo y me informan que actualmente la TS no está realizando att. presencial. Que llame al siguiente número: 927 50 80 00, Ext. 231.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-01-20','Ana: Correo de Sonia Bernabé, Asindi: "Hola, de nuevo, nos han informado que dan el alta en Salud Mental a Felisa Bruno Saavedra y regresa hoy.Viene con PCR y estará en aislamiento unos días. Se pondrá la vacuna mañana al igual que sus compañeros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2021-01-20','Ana: correo de Sonia Bernabé, Asindi: "... Juan Gabriel Sobrino Tardía, está con su familia en Mérida. Hemos avisado a todas las familias de los residentes que están en casa y no han regresado por tener en el centro positivos. Los que viven en zonas próximas vendrán para ponerse la vacuna. A Juan Gabriel no podía traerle para ese rato, cuando regrese intentaremos organizar la vacunación de estos residentes que ahora no pueden."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-01-20','Ana: Correo-e de Jesús, Dir. de la Resi. de El Torno: "BUENAS TARDES ANA. QUERIA COMUNICARTE QUE MARIA ROMERO HA DADO POSITIVO EN COVI-19. UN SALUDO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-01-21','Ana: Correo de ayer por la tarde de Paula, TO CRR-Plas.(tocupacional.crrplasencia@grupo5.net): "...para fechar entrevista conjunta con Toñi, Nuestra idea era intentar poner la entrevista mañana sobre las 12.30, aunque Toñi mostraba su disconformidad, a priori, pues desconfía y mantiene que la hemos engañado. Si puedes comunicar con nosotros mañana para confirmar un horario de llamada estaría genial, si luego Toñi sigue negándose, veríamos la posibilidad de cerrar el proceso actual de incorporación a piso e ir valorando en los próximos meses los siguientes pasos. Un saludo." ··············· *Respondo confirmando que podemos hablar hoy a las 12:30 h. ····························································································································································· A las 12:30 h. recibo llamada de Paula, TO, y Carolina, Psicóloga. Toñi se niega a tener la conversación todas juntas. Informo con respecto a conversación que mantuve con Toñi el día que me llamó. *Ahora opina que le han engañado en el CRR y no quiere ir al PPSS. *Intentarán trabajar con ella para que cambie de idea. **Por otra parte, a mí me surgen dudas, con respecto a la sentencia de Incapacitación y el hecho de irse a vivir de forma independiente. Pues en la Sentencia se autoriza el Internamiento Involuntario en el CSS. *No obstante desde el CSS se derivó al CRR. Y aquí también expresan que los objetivos terapéuticos se han conseguido y es conveniente que siga avanzando en su proceso de recuperación. Paula y Carolina argumentan que sino este recurso no tendría sentido. Habría que buscar otro. *Lo hablaré con Pedro, Jefe de secc. a la vuelta de sus vacaciones y con los compañeros jurídicos si fuera preciso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-01-21','Ana: correo de Marisa, TO del EVD, Gerencia Territorial de CC (marialuisa.gonzalezs@salud-juntaex.es): "Buenos días Ana He consultado con Mérida y tenemos que gestionar un documento para regularizar el mantenimiento en Centro Residencial de Rehabilitación de Agustín hasta que le concedan la residencia de mayores. Te envio el documento adjunto para que lo registres al código A11030403, igual que el anterior. Saludos" *Pongo el documento para la firma digital del D.Gerente. ················································································································································· Adelanto a Marisa escaneado la Aceptación del PIA para mantenimiento de plaza en CRR, firmado digitalmente y lo pongo para REGISTRO DE ENTRADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2021-01-21','Ana: Remito a Cruz C. Merino, TS - Mancomunidad Tajo Salor, UTS. Alcántara (cruzmerino@tajosalor.es) el CI para la administración la Vacuna Covid a Mª Salvadora, residente en los PP.TT. de Villa del Rey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-01-21','TERESA RECIBO COMUNICADO DE LA DIRECCION GENERAL DE INFANCIA Y FAMILIA EN LA QUE NOS PIDEN QUE ORGANICEMOS EL TRASLADO Y LO AUTORICEMOS YA QUE ES INMINENTE EL ALTA EN LA UHB, SE LE DERIVA A RECURSO DE DE LA RED DE MENORES ESPECIFICO PARA AISAMIENTO DE COVID EN EL PUEBLO DE HERNAN PEREZ. HABLO CON EL TS DEL HOSPITAL Y ME DICE QUE LE TRALADO SE ENCARGA EL MEDICO QUE ESTAN A LA ESPERA DE LA RESOLUCION DE LA PLAZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-01-21','Ana: En relación a las conversaciones y correos intercambiados con Alberto, Jefe Secc. Ecca., referentes a la necesidad de reducir la asignación a Felisi, remito correo a Toni-Futuex: "Buenos días Toni, En relación a Felisi Felipe, tengo que pediros que abordéis con ella, y no va a ser fácil, una cuestión económica. Ella percibía en su cuenta la pensión de orfandad de su hijo Aitor, como sabéis también tutelado ya por la CTAEX. Al cumplir Aitor la mayoría de edad, y con vistas a su ingreso en recurso residencial para personas con discapacidad, como así ha sido, solicité el cambio de la pensión a la cuenta de Aitor, pues tiene que abonar su plaza y contar con su dinero para sus gastos (hecho del que informé a Felisi en su día). El caso es que Felisi ahora ve “reducidos sus ingresos” y Alberto ha recalculado, exponiendo lo siguiente: “…REDUCIR el reintegro permanente de la tutelada: pasa a 75 €/semana (325 €/mes) - anterior 80 €/semana (347 €/mes). Xfavor, comunícaselo a ella.” (Esto se lo ha pedido a Juana, que así lo hará esta semana) “Ana: Gastos mes a partir de febrero: • Reintegro: 325 €/mes • Gastos vivienda (luz y agua): 29 €/mes • Alquiler: 90 €/mes • Seguro deceso: 17 €/mes • TOTAL: 461 €/mes. INGRESOS TOTALES INCLUIDAS PAGAS EXTRAS (tiene una PNC simple): 461 €/mes Como puedes observan SE GASTA ABSOLUTAMENTE TODO LO QUE SE INGRESA. X tanto NO extras, NO incremento reintegros.” Tienen un dinero ahorrado en su cuenta, pero como sabéis, esto se intenta guardar para los imprevistos, necesidades urgentes… que puedan acontecer. Yo ya le expliqué esto a Felisi la semana pasada, pues se quejaba amargamente de que no se le dio extra en Navidad (*Aunque su hijo fue a visitarles finalmente y llevó dinero y un lote de productos navideños). Pareció entenderlo, pero no está muy conforme. Lo que no le expliqué es que a partir de febrero le reducirán la asignación en 5 €. Juana como te digo se lo va a comunicar. ¿Podríais por favor tratar este asunto con ella, explicándoles a ella y Jesús, el desglose, para que vean que realmente se les da toda su pensión con las asignaciones semanales?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-01-20','Ana: Conversación con manos libres con Juan Carlos, se encuentran presentes Estrella, TS CSS y Mª Paz (responsable UHDAC) quienes participan en la conversación y apoyan, cuando es necesario a Juan Carlos en su discurso. Quiere irse a un centro donde poder realizar actividades al aire libre y talleres. Le gustan mucho los animales. Pide tener un pero o un gato. Juan Carlos se muestra muy contento de poder hablar conmigo, aunque le gustaría hablar también con Pedro, jefe de secc. Pide hablar todos los días, le explico que no puede ser, pero acordamos fijar llamadas cada 10-15 días mientras permanezca en el CSS. ··········································································································································· Correo de Estrella (estrella.duranc@salud-juntaex.es) al final de la mañana: "Hola de nuevo, Ana. He rescatado el expediente de Juan Carlos del SEPAD para tramitar yo misma lo de la plaza, para ello en primer lugar debe firmar su tutor, la solicitud de revisión PIA. Mi duda es, la puede firmar nuestra Directora con la autorización que le dáis cuando ingresan aquí??? Ya me dices...gracias. Buena tarde" ············· Respondo que debe firmarlo el Representante Legal. Cuando lo tenga puede enviármelo por mail para que recabe su firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-01-20','Ana: correo de Toni-Futuex: "--Buenos dias, que tal todo? a continuación pasamos información sobre el nieto de la tutelada Manuela Morato Picado, en relación al asunto de siempre.. que va a "denunciar" a la comisión y a todo el mundo, su modo de comportamiento habitual está basado en las amenzas, pero como sabemos que encima aveces del juzgado atiendes sus absurdas peticiones, no se si estaria de mas estudiar la posibilidad de que directamente desde la comisión os pongais en contacto con el juzgado para argumentar la no viabilidad economica de la obra o lo que sea que se decida. 19/01/2021 Incidencia: Contacta con nosotras Jose Manuel, altivo y desafiante, como es habitual. Comenta que era para consultar si se sabe algo sobre el asunto de la obra, se le dice que no, que además según nos consta el ya habia hablado en alguna ocasion con el area economica, habia recibido algun email, que no podemos decirle mucho mas… señala que todo son excusas para no responderle y atrasarlo todo… Comenta que ha acudido al juzgado y el secretario le ha indicado que emitirá la denuncia por la vía penal, ya que es el único modo que tire para delante, ya ha notificado al fiscal… (a mi esto me parece inviable, pero no se, a nivel juridico si un familiar, puede imputar o reclamar nada a un tutor legal que por otro lado ha nombrado ese mismo juzgado) Establece que la denuncia es contra Pedro y Alberto, concretamente, porque son quienes no están haciendo caso de las peticiones que necesita Manuela y quienes están proporcionando dejadez y trato poco adecuado a su abuela tutelada… (alucina) Solicita datos de FUTUEX y de las trabajadoras, se le dice que no se le van a proporcionar, establece que buscará en internet y pondrá los nombres, pues va a llamar a testificar a todas las trabajadoras que han pasado por su abuela.... Se le dice que se notificará de todo, como se ha hecho siempre. Porque poco mas se le puede decir. Pero como te comento, no se si seria bueno comunicar con el juzgado, antes de nada, para evitar cuestiones que son simples y claras de justificar desde la gestión de la tutela por una entidad juridica." ····································································································································· Mi respuesta: "Buenas tardes Toni, Esta historia… no termina nunca… La semana pasada José Manuel estuvo llamando y hablando con la Secretaria del Director Gerente del SEPAD… posiblemente tengamos una reunión con éste próximamente. Hablé con Alberto el jueves pasado sobre este asunto de nuevo (Pedro está de vacaciones). Estamos esperando a recibir los informes de la visita que hicieron de forma conjunta las distintas profesionales de Valencia de Alcántara, pues a día de hoy sólo hemos recibido el vuestro… Con estos informes queríamos terminar de justificar al Jdo. Y tomar la decisión definitiva. Que yo creo que será la del traslado a una vivienda de alquiler, pero necesitamos los informes… De todas formas hablaré de nuevo con Alberto y con los compañeros jurídicos la respecto. Gracias de nuevo por informar, por la paciencia y por a implicación. Seguimos en contacto. Buena tarde." ·············································································································································· Nuevo correo de Toni al final de la jornada: "Te actualizo un poco el tema, he hablado con el, (Jose Manuel) para puntalizarle que por favor, no trate de amenzar o ningunear a mi compañera y que la permita hacer su trabajo, (que ya varias veces ha pasado) nada, como siempre es un liante.. que el no ha dicho eso y que tiene mucho miedo por el tema del covid que por eso no la permite entrar.. bueno lo de siempre. Creo que de nuevo le ha dicho a la cuidadora que no vaya.. porque hay muchisimos casos de covid en el pueblo, pero claro esto no lo puedo confirmar claro y ademas ahora aunque quisieramos y el lo permitiera, Gloria esta confinada como contacto de un positivo, y le quedan aun unos dias, para poder ir. Se dice y se descide en las conversaciones, y como sabes su actitud es confrontativa casi siempre, le he insistido que todo el mundo quiere lo mejor para su abuela, que todo el mundo trabaja para ello pero que el debe colaborar tambien y que por supuesto, en este caso Gloria, pero han pasado mas compañeras, estan ahi para ver a su abuela, por que nos lo ha encomendado la comisión, que vela y se preocupa por ella. Nada, como dices lo de siempre... yo espero que bueno el también sea capaz de reflexionar y buscar consensos y tener la paciencia suficiente para entender que las cosas son como son y no como nos gustaria, en lo que respecta a los seguimientos te ire informando e iremos trasladando las cuestioens que surjan. que seguro que surgiran! Saludos y buena tarde!"','2');
