insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-01-22','En relación con el procedimiento PS PIEZA DE SITUACIÓN PERSONAL 21/2021 01, seguido en el Juzgado de Primera instancia e Instrucción, nº 1, de Mérida, ponemos en conocimiento del hermano de Jonathan, que se ha decretado la libertad provisional, pero que debe acudir al Juzgado los días 1 y 15 de cada mes. Caso de no hacerlo decretarán prisión provisional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-01-22','En relación con el traslado de Nerea, desde el Infanta al pueblo de Hernán Pérez, donde existe un centro indicado para afectados del Covid, tras gestiones de Teresa con el Infanta, pongo en conocimiento de JOsé Vicente que Nerea aún no tiene el alta hospitalaria, con lo que seguirán en el Hospital, porque aún no tiene plaza en el centro de Hernán Pérez. Una vez dispongamos de la plaza, nos remitirán la solicitud para tramitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-01-22','miguel, envío email a Tere pidiendole que pida un justificante de donde reside actualmente José Lara y desde cuándo. ******************************************************* Tras conversación con el Juzgado nº2 de Zafra por el expte de aprobación de herencia y autorización de venta X15 nº129/2020 donde estaban a la espera que el Colegio de Abogados de Badajoz nombrara un abogado de oficio y al no residir ya en Zafra el tutelado, me requieren para que aportemos un justificante de dónde reside y desde cuándo (según email que mandaron el 12-1-21 a ctutelar). ****************************************************** A su vez remito email explicativo de la situación a Mely, hermanastra del tutelado. ********************************************************* Este procedimiento de aprobación de herencia y autorización de venta es paralelo al otro procedimiento de remoción del cargo de tutor interpuesto por su hijo Raúl y el cuál ya se encuentra en el Juzgado nº2 de Coria (ya que el Juzgado de Zafra se inhibió y lo remitió allí, y a cuya demanda contestamos hace más de un mes a petición de Escalona)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-01-22','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net) de ayer : "Hola Ana, quería hablar contigo o con Angel sobre la citación de Felisa para el 26. Hoy nos han puesto la vacuna, y nos han hecho mucho hincapié en que no salgan los residentes, que es importante que evitemos situaciones de riesgo de contagio. Entonces, no sé si se podría retrasar un mes hasta que tenga todos los efectos con la segunda dosis o cómo proceder, el médico nos podría hacer un justificante o un informe. Como no teníamos fecha de alta en la UDAC, no había empezado a organizar el viaje. Por otro lado, quería saber un poco las circunstancias o el motivo por el que va al médico forense, porque si al final tiene que ir, la persona que va con ella, no saben nada y hay que situarla. La verdad es que conocemos poco a Felisa todavía. Mi número es el 669 60 29 20. Es importante que lo quedemos ya organizado." ······················ Mi respuesta: "...Pongo en copia a Ángel, supongo que él, dadas las circunstancias, podrá solicitar un aplazamiento, cuando lea estos correos nos dirá." ···················· Nuevo correo de Sonia: "...le he mandado la cita a Angel y a lo largo de esta mañana le envío, justificante de la doctora para poder aplazar la cita en el Juzgado hasta finales de febrero. En cuanto tenga el documento se lo mando a Angel."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-01-22','TERESA Tenemos ingresada en el hospital a Nerea Da Costa Lorenzo, con COVID positivo como sabréis, sin criterios de ingreso además según la psiquiatra para mantenerla más tiempo y a la espera de cambio de centro (parece ser que no va a poder ser trasladada a centro de la Asociación Nutria por el perfil de las pacientes), por lo que nos urge muchísimo que a la mayor brevedad posible se le busque un centro a esta chica debido a la situación sanitaria en la que estamos y la necesidad de camas actualmente, o posiblemente mañana sea dada de alta a los pisos donde se encontraba. Podéis comunicaros conmigo en el 48991 ó 924218100 (Ext. 31806).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2021-01-22','TERESA HABLO CON MERCEDES DEL PISO DE CARITAS PARA PONERLA AL DIA PUES ELLA LA QUE VA A LLEVAR AHORA EL CASO TELF 637353364 EMAIL MCRUZ.CDMERIDA@CARITAS.ES LE PONGO AL DIA DE AL ACTUACIONES REALIZADAS ETAMO PENDTE CAMBIO DE LA PNC A LIBERBANK SOLICITAR ORFANDASD ME TIENE QUE DECIR DONDE FALLECIO EL PADRE PUESTO QUE NO COSEGUIMOS HACERNOS DEL LIBRO DE FAMILIA CITA CADEX PARA QUE LO VALOREN PARA CENTRO','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-01-22','Ana: correo-e de ayer de Mª José Polo, TS del SSASB la mancomunidad (ssbm@trasierratierrasdegranadilla.es) al ctutar@ "Adjunto remito informes sociales tanto mios como de mi compañera del SES, sobre la situacion actual de Florencia y la posible valoracion de ingreso en centro residencial IGUALMENTE LES INFORMAMOS DE LA ESCASEZ DE RECURSOS ECONOMICOS QUE TIENE. NOS CONSTA QUE POSEE OTRA CUENTA EN LIBERBANK, A LA CUAL NO TENEMOS ACCESO, SI ES POSIBLE QUE SE LE ASIGNE UNA CANTIDAD MAYOR; YA QUE NO LLEGAMOS PARA CUBRIR TODOS LOS GASTOS. SI NECESITAN LOS ORIGINALES DE LOS INFORMES NOS LO COMUNIQUEN Y SE REMITEN POR CORREO ORDINARIO" ·························································································································································································· Reenvío el correo a Alberto, jefe secc. ecca., y pido valores la posibilidad de aumentar la asignación e indagen la otra supuesta cuenta bancaria. ······························································ *Tras leer los informes que adjuntan (SSB y C.Salud), lo guardo en el expte. digital. ···· El retorno de Felicita, hermana de Florencia, al domicilio familiar ha desestabilizado la convivencia, la relación familiar,entre las 2 hermanas, no es buena, han llegado incluso a agradirse. Y además se están generando deudas debido a que Felicita se niega a hacer frente a los gastos correspondientes (con los ingresos de su madre) tal y como estaban organizados. *Ambas TS proponen ingreso en centro residencial e informan del procedimiento iniciado para incapacitar a Marcelina, Madre. ·························································································· Llamo a Mª José Polo, TS de Zarza de Granadilla (664 01 82 09 / 927 48 60 04 ext.5) sin éxito. ···················· *Contesto al correo: "Buenos días Mª José, Espero que estés bien. Ayer no pude leer el correo. Tras leer ambos informes he tratado de ponerme en contacto contigo por teléfono pero no ha sido posible. Si quieres/puedes llámame el unes y lo hablamos. No obstante, la cuestión económica la he pasado al jefe de la sección económica para que la estudie y nos diga, yo espero que no haya problema. Y en cuanto a la posibilidad de ingreso en residencia, ¿ella está dispuesta? Pues sino hay que pedir autorización de internamiento involuntario, en este caso le pasaría los informes a mis compañeros jurídicos para que se encarguen y sí sería bueno contar con los originales. Por otra parte, habría que solicitar un cambio de PIA para el acceso a recurso residencial, pero tienen grado II, si consideráis que ha empeorado habría que solicitar una revisión del grado por empeoramiento. Ya me dices y/o hablamos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-01-22','ICIAR: Recibimos escrito del amigo médico del CAdex que se ocupa de gestionar asuntos de Jesús desde el fallecimiento d su madre, en su expteen carpeta personal. Le llamo por teléfono, Pedro Pastor Villegas 630617157, para que me explique situación de Jesús y me indica que en el juicio que habrá en marzo 2021 para remoción de tutela de Jesús él va acudir como testigo y que no está de acuerdo con dicha remoción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-01-22','Ana: Llamo a los SSASB de la Mancomunidad, Marina, TS de Coria, me comunica que en Cilleros la plaza de TS no está cubierta actualmente, posiblemente tardará semanas en cubrirse. *Con respecto a Julia, me dice que puedo hablar con Carmen Torres, TS de Moraleja, pues conoce el caso, trabajó hace un tiempo en Cilleros. *Llamo sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-01-22','Ana: Recibo llamada de Amelia, Empresa Serv. del Fresno (924 677 705). Ayar habló con Quini, Aux. de SAD de Manuela, y ésta le manifestó que José Manuel, el nieto, le ha dicho que no quiere que entre en el domicilio, pero que esté antenta al teléfono para cuándo necesiten que les haga compra o algo. *Les pido que me lo pongan por escrito. *Expresa que es una persona conflictiva y exigente, que siempre está pidiendo cosas para su abuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-01-22','Ana: Llamada de Juanjo (667 958 878), con el discurso habitual, cuándo podrá ir a retirar el dinero solo sin acompañamiento, cuando podrá sacar todas su pensión y cuándo podrá ir a vivir de forma independiente. *Le vuelvo a explicar que todo dependerá de su evolución y proceso terapéutico. Cuando haya informes favorables que así lo indiquen se podra valorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-01-22','Ana: Llama Noelia, TS del C.R. Cervantes, me pide que hable con Mª Luisa. ··········· Llamo a Mª Luisa, dice que a su hija le han robado todo el dinero del mes, que ha puesto denuncia en la policía y que quiere ayudarla. Quiere que se le haga una transferencia de 100 €. Le digo que no creo que esto se pueda aprobar teniendo en cuenta la trayectoria de su hija, pero que no obstante lo hablaré con el jefe de la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-01-21','Ana: Llamo a María, Autismo Sur, ayer realizaron lo trámites, tanto de renovación de DNI, como de solicitud de la Partida de Nacimiento. ··· Correos de María: En uno pide que solicitemos la nacionalidad española, ha estado mirando ella y dice que al estar tutelado por la Junta es más sencillo. En otro adjunta el pasaporte escaneado. *Guardo en su expte. digital y una copia en el de papel. ························································································································································································································ Registrado de entrada (sistema de registro ORVE-SIR), la solicitud de PNC de la Junta de Andalucía para Costi Alexandru. Se adjunta toda la documentación pertinente. *Se archiva copia en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-01-25','Ana: Registrado de entrada a través del Sistema de Registro ORVE-SIR, comunicaciones al INSS de variación de datos bancarios, tanto para P.Orfandad como para P.F.H.C.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-01-25','Ana: Me devuelven de REGISTRO, las comunicaciones. *Como con el SIREX ya no envían papel, ya no pueden registrar ningún documento que no vaya dirigido a la JUNTA. ······ Llevo las comunicaciones al registro del SES. **Registradas de entrada a través del Sistema de Registro ORVE-SIR, comunicaciones al INSS de variación de datos de domicilio (se indica también el domicilio a efecto de comuncicaciones), tanto para P.Orfandad como para P.F.H.C.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-01-22','Ana: Correo de Paula, TO CRR-Plas.(tocupacional.crrplasencia@grupo5.net): "Hola Ana, finalmente Toñi accede a incorporarse el miércoles al piso. Ahora un tiempo de prueba y nos seguimos coordinando. Un saludo..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-01-19','Ana: conversación con Paula, TS del CRR-Plas: Toñi ha cumplico los objetivos terapéuticos establecidos en el CRR, desde el CRR plantean que pase al PPSS, como paso intermedio a vivir de forma independiente en un piso de alquiler, pues aún no está preparada para vivir de forma autónoma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2021-01-25','TERESA EXITUS: COMUNICA FALLECIMIENTO FUTUEX EN EL HOSPITAL DON BENITO VILLANUEVA ELPASADO DOMINGO 24','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2021-01-24','EXITUS El centro informa de su óbito, acaecido el 24/01/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-01-14','Ana: Recibo llamada de Toñi (617 223 527), quiere irse a vivir directamente de alquiler, no quiere pasar por PP.SS. Le han dicho en el CRR que la decisión de pasar al piso es de la CTAEX al tener la tutela. Le explico que nosotros trabajamos en coordinación con los profesionales del CRR, que son quienes mejor le conocen pues trabajan a diario con ella y por tanto, nosotros tomamos las decisiones basándonos en gran medida en su criterio como equipo técnico. Sabe que está en proceso terapéutico y lo recomendable es dar ese paso antes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-01-21','Ana: Recibimos Informe Soc. de Pilar Márquez, TS del SSASB de Valencia de Alcántara, sobre la visita domiciliaria: "...la vivienda no presenta buenas condiciones de habitabilidad... evidente necesidad de obra de adecuación para solucionar múltiples problemas", "...tras evaluación física de efectuada a Dña. Manuela porla Médico de cabecera, ésta manifiesta el perfecto estado general en el que se encuentra.", "Este Servicio de Atención Básica considera adecuado... la interactuación de Dña. Manuela Morato con sus otros familiares directos, nietos, biznietos, etc.", "No tenemos información suficiente para poder arrojar con claridad nuevas intervenciones alternativas..." **El martes que se incorpora Pedro de Vacaciones hablaré con él al respecto para tomar ya una decisión con respecto a la vivienda de Manuela (*La obra económicamente no puede asumirse).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='MARTIN'and apellido2='GALLEGO'),'2021-01-25','TERESA RECIBO PRESUPUETO ARREGLO DE HUMEDADES, LO PASO A LA PARTE ECO Y A MIGUEL PARA VALORACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-01-18','Ana: Recibo llamada de Carmen Valerio (927 004 254 / carmen.valerio@salud-juntaex.es) en relación a la hija de Francisco. Lleva tiempo en Acogimiento familiar. Con vistas a dictar resolución de Formalización de dicho acogimiento, y dado que la CTAEX ostenta la tutela de Francisco, nos enviarán escrito informativo y concediendo un plazo de 10 días para presentar alegaciones. *En principio, si desde Protección de Menores estiman que los más conveniente para el bienestar de la menor es formalizar dicho acogimiento, desde la CTAEX no se pondrá impedimento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-01-25','Ana: Recibido el escrito de Infancia y familia, relativo a la formalización de acogimiento familiar de la menor Ana Belén Cacho Caballero, hija de Frco. Trato con Ángel, Asesor Jurídico el asunto y nos reiteramos que si desde Protección de Menores estiman esta opción como la mejor para la mejor, desde la CTAEX NO se presentarán alegaciones. ········ *Llamo a Carmen Valerio para comunicárselo. *La persona acogedora, es la misma con la que lleva en acogida más tiempo y todo va bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-25','Ana: Llamada de Pilar Martín, TS del ESM-CC. Considera que Clementa podría ingresar en la Res. Privada, en la única que quiere ingresar, mientras le asignan plaza pública. *Percibe una pensión de viudedad de 966 € y abona una hipoteca (vivienda habitual) de 180 €. La plaza privada de residencia asciende a 800 €. **Teniendo en cuenta que requiere atención continuada y que desde Cáritas manifiestan no poder mantener la ayuda económica para pagar una auxiliar interna por más tiempo (el "plazo" vencía el mes de enero), puede ser una buena alternativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-01-25','CORREO. Se envia al centro por correo certificado, consentimientos informados para la realización de tomografía de emisión de positrones, paratiroidectomía y tiroidectomía. Previamente se han remitido por correo elctronico a Soledad Olmos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-01-25','Ana: Conversación con Mª José Polo, TS del SSASB (664 018 209). La convivencia con la hermana resulta perjudicial para Florencia y no ven la forma de que la hermana abandone el domicilio familiar. Aunque lo ideal sería llevar de manera conjunta a Florencia y a su madre a una residencia y no separarlas, no es aconsejable que mientras se resuelve el procedimiento de incapacitación de la madre, que puede dilatarse en el tiempo, Florencia siga en el domilio con los conflictos que se están produciendo. ······ Por otra parte, se está generando una deuda con el "catering" del comedor, ya se deben más de 100€, habría que abonarlos para que tanto Florencia como su madre puedan seguir comiendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-01-26','Ana: Envío correo-e a Mª José Polo, TS SSASB Mancomunidad Trasierra de Granadilla (ssbm@trasierratierrasdegranadilla.es ): "Buenos días Mª José, En relación a la deuda con el “catering” del comedor, se me ocurre que quizá sería mejor abonar directamente lo que se debe mediante transferencia bancaria e incluso domiciliar futuros pagos en la cuenta que consideren desde la sección económica y así esa parte quedaría cubierta y sería algo de lo que no os tendríais que preocupar y un gasto menos que afrontar con la cuantía de la que dispone habitualmente Florencia. Si te parece buena opción, facilítame cuando puedas los datos, deuda, coste mensual y el número de cuenta para que se lo plantee al Jefe de la sección económica y si le parece bien se proceda a ello directamente. Seguimos en contacto. Buena mañana." ···································································································································· Respuesta de Mª José: "Es complicado, por que es una persona del pueblo que se dedica a llevar las comidas por las casas y lo hace en negro le cobra 3 euros diarios y en funcion de los dias les paga el mes. Hay que pagarselo en mano"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='MARTIN'and apellido2='GALLEGO'),'2021-01-26','miguel, me llega email de Tere: Buenas de nuevo, no se si fue el area economica directamente o través de ti, pero te lo hago llegar para que voloreis, en archivo adjunto toda la documentación de la visita al domicilio de Manuel Martín Gallego, en Castuera, este señor esta en una residencia pero nos indicasteis unas gestiones en la casa, pq estaba ocasionando daño a una vecina, se hizo la visita antes de navidades pero hasta ahora no nos han hecho llegar el presupuesto de obra, (6350 eu mas IVA) adjuntamos también la documentación para dar de baja el contrato de suministro de agua. Y en la nota toda toda la información con mayor detalle ******************************************************** Respondo a Tere y Alberto:Buenos días, si estáis de acuerdo con el arreglo y el importe os comunico que al ser 6.350+iva (os tenéis que asegurar que sea precio cerrado), creo que en la medida de lo posible deberíais pedir 1 o 2 presupuestos más. Como digo, para dicho importe se requiere comenzar un procedimiento judicial de autorización para gastos extraordinarios. Por lo que veo en la última rendición de cuentas tiene más de 24.000€ en cuenta por lo que no tiene derecho a abogado de oficio. Habríamos de contratarle un abogado en Castuera de pago. Ya me decís si comenzamos dichos trámites para que el juzgado autorice dichos gastos extraordinarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2021-01-26','miguel, recibo contestación de Jesús Lara (intermediario en la venta de la rústica que pregunta Soledada Olmos del colegio de la Luz). Me envía el siguiente email: Mis clientes aún no me ha comunicado nada, creo que la parte compradora tiene que solicitar un préstamo bancario. Cuándo firmen la compraventa ante notario se lo comunico por correo electrónico y se envía a la Notaría indicada para ratificar su visto bueno ******************************************************** recibo email de Soledad Olmos del Colegio de la Nuestra Señora de la Luz: El motivo es en relación al correo que te envié el pasado 16 de Diciembre. Juana Bueno está curatelada por vosotros . Ella junto con sus dos hermanos son propietarios de una finca rústica (olivar) en la localidad de Alburquerque y quieren venderla. Tienen una compradora. Las gestiones en relación a la venta las llevan una Asesoría y Notaría de Alburquerque que dirigieron un escrito a la CTAEx , el cual te envié , solicitando la intervención de un letrado en representación de Juani ante la Notaría que también te di los datos. ********************************************************* Reenvío de nuevo email a la asesoría intermediaria para que me informe si ya está todo a punto para dicha firma: Buenos días, en relación a la rústica que tienen pendiente de firmar en Alburquerque se sabe ya cuándo se quiere firmar? Le recordamos que para dicha firma de venta necesitan la participación de esta Comisión Tutelar de Adultos en representación de Doña Juana Bueno Guisado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-26','Ana: Correo de ayer de Toni-Futuex: "Buenos dias Ana, Aunque la educadora que visita este caso continua de baja, me traslada esta información que creo que es relevante sobre Clementa Amado Vivas La ts de ssb de Villa del Rey, M. Cruz con telefono 924390002 y cruzmerino@tajosalor.es, ha recibido una llamada de Pepe el coordinador de la parroquia de Fátima (Cáceres) para informarse de los requisitos y las plazas que hubiera disponibles para Clementa Amado Vivas, de cara a un posible ingreso. Le hemos comentado que deberia comentarlo también con la comision y con Pilar Martin de salud mental que estaba en el seguimiento del caso. Para que tú estes al tanto. No sabemos porque el coordinador de caritas contacto con este centro y no con otro. Lo que sabiamos es que Clementa decia querer irse a Brozas que es su pueblo pero la residencia de alli no era viable para ella al ser privaeda. Seguimos, buen dia!" ························································································································································································ Mi respuesta: "Buenos días Toni, Ayer precisamente estuve hablando yo con Pilar Martín sobre el caso. No sabía que Pepe, de Cáritas, hubiera llamado a la residencia privada... Pero sí existe el planteamiento desde Salud Mental de que acceda a plaza privada de Villa del Rey, donde al parecer Clementa también acepta por cercanía a Brozas, mientras le conceden plaza pública. Económicamente es más viable que mantener las 2 auxiliares que tiene en la actualidad, pues desde Cáritas van a dejar de abonar la diferencia. La otra alternativa a partir de febrero es que continúe en su domicilio sin este apoyo. Con el SAD sólo contaría con unas horas a la semana. *Ya he pedido a Alberto, jefe secc. Ecca. , que lo estudie, pues como Administrador de Bienes sólo podemos decidir al respecto. *Según Pilar Martín, hay otro procedimiento de incapacitación en curso y con planteamiento de medidas cautelares. Espero que estéis bien. Seguimos en contacto. Buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-01-26','(Pedro)Visita programada de Ildefonso. +++Peticiones: gestión del cambio de entidad bancaria de BBVA a La Caixa. +++++INTENCIONES DE Ildefonso: Pasar por esa cuenta el alquiler de la vivienda (en Cataluña) y los recibos de consumo; el resto lo ingresará él en efectivo, a través del cajero, en la cuenta de Joaquina; las PAGAS DOBLES quiere que sean para Joaquina: "quiero que lleve ella las reindas de las cuerntas". +++++DESPLAZAMIENRTO A CATALUÑA: dice que esperará a que las autoridades sanitarias levenaten los confinamientos en las distintas Comunidades Autónomas. +++Se le recuerda que tiene pendiente el cumplimiento de los Servicios a la Comunidad: "Sí, ya lo sé, cuando vaya a Barcelona hablaré con el Juez sobre ello." +++En estos momentos sigue en el Hostal "Salud" de Mérida. +++Queda pendiente hablar de la situación económica con Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2020-12-30','miguel, Pedro y yo remitimos por fax la Solicitud de Internamiento Involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-04','miguel, remito por correo certificado la Solicitud de Internamiento Involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-01-26','Ana: Tras comunicarme Pedro, Jefe de Secc. que hay una autorización de ingreso involuntario en la Residencia de Torres de Don Miguel, aunque a día de hoy la CTAEX sólo tiene aceptado el cargo de Defensa Judicial, llamo a la Residencia Virgen de la Asunción (927 44 10 97), hablo con Ana, TS: Ángeles lleva ingresada en su residencia desde el día 29/12/20, se ha adaptado perfectamente, está muy bien. Fue derivada desde el CSS de Plasencia. *Ayer tenía cita en el Jdo, reconocimiento médico forense, pero tuvieron que solicitar el aplazamiento, pues ayer mismo le pusieron la vacuna del Covid. Lo comunicaron al Jdo. la semana pasada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2021-01-26','(Pedro) Conversación con Puerto, Directora del Hogar de Nazaret. +++Tras explicarme las circunstancias en las que se produjo el fallecimiento (D. José Pedro desayunó con normalidad y se quedó tranquilo. Al poco le entró una febrícula que el médico dijo pudo deberse a una aspiración), agradezco a Puerto toda la colaboración aque ha prestado a la Comisión en relación a D. José pedro y su hermana Dª Cristina. +++Respecto de la llaves que tienen en el Hogar, le pido que nos las envíe a la Comisión para tenerlas aquí hasta que finalemnte sea aprobada la rendición final por el Juzgado. +++D. Francisco y D. Julián agradecieron el trabajo realizado desde el centro con su hermano ( la carata está recogida en el expediente digital, junto con el correo-e del centro que es quien nos la envía).Como dice Puerto, después de remitir esa carta les pidieron expliocaciones sobre lo ocurrido, amenazando con denunciar al Centro. +++ENTIERRO: Puerto me informa que, a pesar de las indicaciones que D. Francisco remitió a la Comisión (recogidas en la incidencia de 21 de diciembre), finalmente el sepelio se llevó a cabo en la ciudad de Plasencia, tras la decisión tomada entre ambos hermanos para que así fuera. ++++++++++++++++++++++++++++++++LLamo a D. Francisco para dar el pésame en nombre de la Comisión, pero no cogen la llamada. Dejo mensaje en el contestador con nuestro pésame por lo ocurrido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2021-01-26','Ana: Llamada del Dr. Luis Alberto Gía Martín (685 858 698), Urólogo del HUC; Rafael está sangrando de la zona del riñón, donde tiene el tumor. Necesitan el C.I. firmado por su representante legal para extirparle el riñón con carácter de urgencia. La intervención tendrá lugar esta misma mañana. ························ Julio, CTAEX, se encarga de recabar la firma del D.Gerente y remitirlo al médico: luisalberto.garcia@salud-juntaex.es ················································································································································· Nueva llamada del Dr. Gía, Urógolo, dice que le han llamado los radiólogos, pues justo ahora no está sangrando. La intervención se la realizarán igualmente, pero no de urgencias hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2021-01-26','En relación con el procedimiento DPA 179/2020, en el que aparece como demandado José María Vicho Alfonso y como demandante, José Luis Murillo Horrillo, seguido en el Juzgado de Primera Instancia e Instrucción, nº 3, de Plasencia y con motivo de la citación para el 24/2/2021, a las 10:00 horas, solicitamos que nuestra comparecencia se realice a través de videoconferenca en los Juzgados de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2021-01-25','Ana: Registro de ENTRADA en el SES, Sist. Reg. ORVE-SIR, la solicitud de ayuda para el material ortoprotésico (cojín abductor viscoelástico), adjunto factura original, informe médico, documento con datos bancarios y copia del resto de documentación solicitada.','2');
