insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-01-27','TERESA DECIDIMOS ABRIR NUEVA CUENTA EN LIBERBANK ANTE LAS DIFICULTADES QUE NOS PRESENTA CAJAALMENDRALEJO CON EL TEMA DE LA SENTENCIA DE INCAPACITACION ME QUEDO A LA ESPERA DEL NUMERO DE CUENTA PARA CAMBIAR PENION Y PRESTACION POR DESEMPLEO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-01-25','Juana: Se pone en contacto con la Comisión Tutelar, Soledad, trabajadora social del Centro la Luz donde residen Antonio y Juan José Martínez Pérez, en relación al padre de ambos, José Martínez Ortega. Se encuentra ingresado en el Hospital Perpetuo Socorro de Badajoz con pronóstico grave, necesita acompañamiento. Nos ponemos en contacto con la empresa El Ángel de Badajoz (Nieves) y se contrata acompañamiento durante una semana (estimación) por las noches, de 8 de la tarde a 8 de la mañana por el precio de 80 euros/noche y por indicación tanto de la médico de Caser Residencial Olivenza como por su cuñada Valentina que es quien está hasta ahora acompañándole. Se pone en contacto a la empresa con Valentina ya que es el familiar de referencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-01-27','miguel, tal como hablé con la persona de contacto del Juzgado de 1º instancia nº2 de Zafra (Miguel A. Perez Castillo), le remito el certificado donde actualmente reside el tutelado a los efectos de que remitan lo antes posible las actuaciones del procedimiento al que corresponda y nos lo comuniquen lo antes posible. Actualmmente el tutelado reside en la Residencia de Mayores Virgen de la Asunción, Torre de Don Miguel (Cáceres)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-01-27','Ana: Recibimos escrito de INSS, en relación a la PFHC: "informamos que al haber cumplido la mayoría de edad y no tener constancia de estar calificado de discapacidad en grado igual o superior al 65%, se ha procedido a mecanizar baja en el expte." ······································································································································ Solicito al CADEX por mail el Certificado de Discapacidad y Dictamen Técnico, pues a pesar de estar pedido desde un inicio para conformar el inventario aún no lo hemos recibido. *Les adjunto escrito-solicitud remitido con anterioridad así como Testimonio de Sentencia y Acuerdo de Aceptación del Cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-01-27','Ana: Llamo al C. Salud de Valencia de Alcántara (927 58 02 95 - 54298), me comunican que la Dra. Nuria Díaz está de baja. ·············· Lidia, TS, no está en su despacho, le dejarán nota para que me llame. ········· Recibo llamada de Lidia, TS C.Salud (54209 / lidia.cabanillas@salud-juntaex.es). Se extraña mucho de que no lo hayamos recibido, pues lo redactaron tanto ella como Nuria el día siguiente a la visita domiciliaria (17/12/2020). Finalmente los encuentra los 2 en un sobre en el mostrador de recepción, creía haber acordado con Pilar Cerrillo que pasaría por allí a recogerlos para enviar los 3 informes juntos. **Me los adelantará por email (si puede hoy y sino el lunes) y a posteriori enviará también los originales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2021-01-27','TERESA ENVIO AUTORIZACION MEDICACION FIRMADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-01-27','Ana: conversación con Pilar Martín, TS ESM (54612), tal y como he hablado con Pedro, Jefe de Secc., le comunico que si Clementa, accede finalmente a ingresar en plaza privada de la Res. de Villa del Rey (Firmó la aceptación PIA), por nuestra parte puede ingresar el día 1/02/2021. Eso sí, dado que la hipoteca la tiene domiciliada, le pido que cuando hable con la TS de la Res. le indique que peude que no haya, en inicio, dinero suficiente para abonar la totalidad de la mensualidad, pero que en cuanto se pueda se irá poniendo al día. ······ Pilar me indica que le está llamando la hija de Clementa, me volverá a llamar después de hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2020-11-25','Ana: Recibimos EXPTE. DE MENORES, registrado de entrada el día 23/11/20.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-01-27','miguel, tras email de la Abogacía General (Elena Sanchez Simón)nos comenta a Pedro y a mi, a raíz del email que nos remitió el 25-1-2021 para ver si la Ctaex quiere llegar o no a una conformidad. La comentamos que una vez que conozca el contenido de dicha conformidad con el MF nos lo diga con tiempo suficiente para saber si aceptamos o no dicha conformidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2021-01-27','miguel, Pedro y yo hablamos con Soledad del Colegio de la Luz, quién me informa que la rústica que se quiere vender entre la curatelada y sus dos hermanos se vende en la realidad en unos 9.000€ aunque en escritura se quiere poner unos 6.000€ por lo que antes de la firma nos tenemos que asegurar que se ha abonado en la cuenta la parte de la fianza correspondiente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-01-27','Ana: Correo de María, TS F.Autismo Sur: "Buenas tardes Ana! Te adjunto copia de la solicitud del cambio de padrón". Guardo resguardo de presentación en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAO DANIEL'and edp.apellido1='CARVALHO'and apellido2='VENTURA'),'2021-01-27','TERESA Me pongo en contacto para comunicaros que Joao Daniel Carvalho lleva tiempo padeciendo dolor en una muela y tras varias consultas con dentista nos dicen que hay posibilidad de hacerle una endodoncia pero que no entra por la Seguridad Social. Una compañera va a preguntar presupuestos en dos clínicas dentales que hay en Llerena pero será en torno a unos 200€. Hoy le han mandado antibióticos, pero como sigue con bastante dolor, necesito que me digáis si existe posibilidad económica de que se haga la endodoncia lol antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-01-27','(Pedro) Tras conversación con Juana (CTAEx), Soledad (La Luz). +++Correo de Soledad: +++++ Buenas tardes, Pedro. He hablado por teléfono con la cuñada de José Martínez Ortega. Me dice que hoy está mejor aunque el médico ha hablado con su marido y le ha dicho que sigue estando grave. Un pulmón no le funciona y el otro mal. Le tienen que administrar oxígeno. Al principio de estar ingresado se lo administraban por la boca pero las gomas le han producido heridas así que ahora se lo administran por la nariz y parece ser que por esta vía el oxígeno le llega peor. Tose mucho por lo que hay que invertir mucho tiempo para darle de comer para evitar aspiraciones pulmonares. Le está dando de comer su hermano, Severo. Ayer tuvo gastroenteritis. Está muy delgado. Vamos, que el asunto pinta mal. Si sé algo nuevo, os voy informando. Un saludo. Soledad Olmos Olmos - Trabajadora Social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-01-22','Ana: Estrella, TS CSS, me remite la solicitud de dependencia en PDF, la ha cumplimentado a mano y está incompleta y además hay algunos datos incorrectos. Hablo con ella y decidimos, finalmente, por esta vez, cumplimentarla yo directamente. *El lunes la pondré para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-01-27','Ana: Una vez firmada la solicitud de dependencia, la pongo para registro de ENTRADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-01-28','Ana: Cumplimento y pido a Julio, admvo. CTAEX, que ponga para la firma la SOLICITUD DE VALORACIÓN DE DEPENDENCIA PARA SERVICIO RESIDENCIAL, marco tanto Serv. Res. de Discapacidad como de Salud Mental, pues no está claro el perfil. Ya dirá el CADEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-01-28','miguel, el abogado me remite email que indica la incompetencia del Jzdo de Plasencia para conocer el asunto ya que cuando interpuso la demanda, el tutelado acababa de salir del CSS y se fue a Guadalupe, con lo que espero me avise del juzgado que conocerá el asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-01-28','Ana: Llamada de Paula, TO CRR-Plas. (682 704 401): Guadalupe acudió el lunes a la cita de Cirugía Plástica en CC con motivo del carcinoma en la nariz y la intervención pendiente. El especialista le expuso sin mucho tacto todas las consecuencias negativas de la operación, entre ellas la cicatriz que le dejaría. Explicando también que su carcinoma es de evolución muy lenta y con bajo riesgo de metástasis. *A raíz de la consulta Guadalupe dice que NO QUIERE OPERARSE. *Desde el CRR pidieron cita en Att. Primaria para contrastar la información que la había dado el cirujano y tener otro criterio. El médido sustituto que le atendió mantiene que aunque sigue recomendando la intervención, sí es que este tipo de carcinoma es de evolución lenta. Pero sí se extiende de aquí a unos años, la citatriz será más grande. ···· Guadalupe tiene 77 años y padece también fibromialgia. ···· *Pedirán nueva cita en Att. Primaria para consultar también a su médica habitual. *Nos mantendrán informados y llegado el momento nos enviarán un escrito con toda la información y la decisión de Guadalupe. ···························································· Otra cuestión de la que me informa es que le han llamado de Dependencia, en relación a la plaza de residencia. ···· *Envío correo a Carmen (carmen.garciamarti@salud-juntaex.es) y Laura (laura.pulido@salud-juntaex.es) de la Secc. de Dependencia de Plas.: "...En relación a Guadalupe Barragán García, Tutelada por la CTAEX, me han llamado del CRR de Plasencia en que reside, comunicando que les habéis llamado para informar que tiene aprobada una plaza en la Residencia de Malpartida de Plasencia y que necesitáis que firmemos la aceptación. ¿Podríais, por favor, corroborarme esta información y en tal caso enviarme la resolución de plaza y el documento a firmar?..." ···················································································································································································· Respusta de Carmen Cía, EVD: "Hola Ana, buenos dias... me lo ha dicho también hoy la psicologa del CRR. He hablado con Noelia y me dice que lo pregunte por email a mayores. Así lo hare, ya te dire."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-01-28','Ana: En relación a la llamada de ayer de Mariví, envío un correo a Carmen (carmenmaria.ferrer@salud-juntaex.es) y Eva (eva.paredes@salud-juntaex.es), Secc. de Salud Mental: "...En relación a Francisco Cacho Garrido, tutelado por la CTAEX, me han llamado del CSS de Plasencia, pues se le aprobó plaza en Piso Supervisado de Mérida (que por cierto no lo sabía, no tenemos la resolución) pero sigue a la espera por no habérsele podido hacer la entrevista previa por parte de la Responsable del Recurso. Me indican que ya hace en torno a dos meses que se le ha generado estas expectativas de ingreso que tanto ansía y que hay riesgo si no se cumplen. ¿Podríais decirme cómo está las situación al respecto?..." ····················································································································································································· LLamada de Eva, Psicóloga de Secc. Salud Mental (924 93 03 52): La resolución de plaza aún no está. *La plaza de Asun, Responsable del piso no se ha cubierto tampoco, están a la espera y la *entrevista previa y el seguimiento durante el periodo de prueba lo tiene que hacer sí o sí la persona responsable. *Están pendiente del caso, si hubiera otra plaza libre en cualquier otro piso antes se la ofrecerían. *Revisa la documentación mientras habla conmigo y se da cuenta que la Aceptación PIA remitia por Estrella, TS CSS, está firmada por el propio Fco., por tanto no está bien. La modificarán y me la darán para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-01-27','Ana: LLamada de Mariví Clemente, TS URA - CSS Plas.: Dice que a Francisco le aprobaron plaza en PPSS (a nosotros no nos lo había comunidado nadie) , la entrevista previa al ingreso, debía haber tenido lugar en diciembre, pero al estar la responsable del piso de baja no ha tenido lugar. *Ella ya ha hablado con Carmen Ferrer y con Soraya Masa al respecto. Al parecer la sustitución va a tardar. Me pide que hable con ellas para ver si hay alguna manera de agiliar el ingreso, pues existe riesgo para Francisco, por haberle generado hace dos meses unas expectativas que no se están cumpliendo. Él ansía ir a piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-01-28','Ana: Conversación con Eva, Psicóloga de Secc. Salud Mental (924 93 03 52): en relación a la plaza de José Manuel, dice que está el segundo en la lista de espera, no obstante la persona que está delante podría ir a otro recurso, por lo que seguramente la próxima plaza que quede libre en CRR-Ba, será para él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-01-27','Ana: llamada de José Manuel (678 150 472): expresa que Pilar Martín, ESM, le ha dicho que está el 2º en la lista de espera para el CRR. ···· A parte de esto dice que lleva 2 días con pitidos en los oídos, fue al C.Salud, le dieron unas gotas para echarse durante 2-3, de momento no nota mejoría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-01-26','Ana: Llamada de José Manuel, dice que lleva unos días malo, que cree que la medicación nueva no le va bien. El jueves le atendió la Psiquiatra, "pero abajo, no en la consulta". ···· En cuanto a su hijo, se ha llevado una manta cara que era de su madre. Le sigue dejando entrar y sigue teniendo problemas con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2021-01-28','(Pedro)LLamada de D. José Tello (635-981922). +++Sobre el olivar. Enviará correo-e explicando la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-01-21','Ana: Llamada de Alicia Cueto, prima de Damián (635 525 519), ella ya en su día llevó la tutela de Damián. Se ofrece a ayudar en las gestiones que sean necesarias allí en Málaga, por su trabajao tiene relación con técnicos municipales. Damián le ha dicho que aún le debe dinero del piso de alquiler, pero no sabe qué credibilidad darle. *Le pasaré su contacto a Miguel, asesor jurídico CTAEX, por si en algún momento necesitara contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-01-28','Llamada de Miguel. +++Quejándose de la comida del centro y de la cocinera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-01-28','Ana: Correo de Sonia Bernabé: "Hola, quería informaros que esta mañana nos han comunicado desde el centro de Salud que le pueden poner hoy a Ignacio Rodriguez Alcántara la primera dosis de la vacuna. El jueves 21 no pudieron ponérsela porque fue uno de los residentes que dio positivo en la PCR y no lo consideraron al no haber pasado el tiempo suficiente. Hoy, al hacer casi 14 días que se detectara su positivo y no presentar síntomas, lo han considerado, y han aprovechado que vacunan en la residencia de mayores para que le acerquemos en vehículo de la entidad y sin bajarse se la pongan allí y espere el tiempo estipulado por si hay reacción."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-01-29','Ana: Correo-e de Carmen Gía, EVD Secc. Plas. (carmen.garciamarti@salud-juntaex.es): "Hola esta señora tiene solicitada una plaza T-4 para Malpartida de Plasencia y le podemos dar la plaza pero estamos pendiente de la Comisión Tutelar para su aceptación. Un saludo. Ana, esto es lo que me han respondido . supongo que os diran algo en breve." ···················· Es la respuesta que le han dado desde mayores (mayores.sscc@salud-juntaex.es) ································································································································································································· Mi respuesta: "Ok Carmen. Supongo que nos lo enviarán, de momento no hemos recibido nada. Si le quieres facilitar mi contacto, no hay problema." ·························································································································································································· Envío correo a la Secc. de Mayores: "Buenos días, En relación a Guadalupe Barragán García, Tutelada por la CTAEX, esta mañana me ha comunicado mi compañera que habéis bajado a hablar conmigo. Ayer hablé con el CRR e intercambié correos con Carmen García del Equipo de Valoración de la secc. De Plasencia. Según me informaron se ha concedido plaza a Guadalupe en la Residencia de Malpartida de Plasencia. ¿Podríais comunicarme fecha prevista de ingreso para que desde el CRR, en que reside actualmente, puedan gestionar la PCR?. Así mismo me dijeron que hay unos documentos pendiente de firma por el Representante Legal, confirmarme si es así, y en tal caso hacédmelos llegar, bien en papel, bien a esta dirección de correo. Gracias y un saludo." ······························································································································································································ Correo de Celia Llera Rodríguez, Secc. Mayores - Serv. Centrales SEPAD (mayores.sscc@salud-juntaex.es // 924 00 92 71): "Buenas tardes, La plaza que se le ha concedido y habéis aceptado es una sociosanitaria T4 en Malpartida de Plasencia. La resolución e ingreso se realiza 24h máximo 48 h tras la PCR. Cuando tengan programada la PCR que nos lo comuniquen y preparamos todo. Un saludo." ··················································································································································· Envío correo a Paula y Carolina CRR-Plas. (tocupacional.crrplasencia@grupo5.net / coordinaciontecnica.crrplasencia@grupo5.net): "Buenas tardes Paula, Pongo en copia a Carolina (si no me equivoco este es su correo) por si acaso, por los problemas informáticos que soléis tener. Tras varias conversaciones e intercambios de correos, os remito el último que me envían desde mayores. ¿Podéis vosotras gestionar la cita para la PCR y comunicarla tanto a Celia (dirección de correo que aparece abajo) como a mí para que estemos al corriente y puedan organizarlo todo? Así mismo habréis de comunicar el resultado negativo (supongo y espero, jeje) para que pueda procederse a su ingreso en el nuevo centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-01-28','Ana: Correo de Noelia, TS Res. Cervantes: "Hola! Hemos recibido resolución de servicio de atención residencial de Eugenia Pacheco Vicente. Te la adjunto por si es de vuestro interés. Saludos" ···························· Guardo documento en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-01-14','Ana: Noelia, TS CR Cervante, nos remite por mail la RENOVACIÓN de la DEMANDA DE EMPLEO. Próx. fecha de renovación: 19/02/21','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2021-01-28','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net), en relación a la vacuna COVID: "...De los tutelados quedaría pendiente de ponerse la vacuna, Juan Gabriel Sobrino, que está en su casa, y estamos viendo cómo organizar el regreso, según nos indiquen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-01-29','Ana: Envío correo-e a Ángel y a Miguel, asesores jurídicos CTAEX: "...He recibido llamada de Maribel, de la Inmobiliaria Etxea Mendi de Valle de Trápaga (Vizcaya), su teléfono es: 637 19 91 17 y su correo: info@etxeamendi.es Me dice que están haciendo la herencia de un piso, del que acaban de enterarse que Aitor Moreno Felipe es heredero de una parte (por su padre fallecido). Después de la herencia tienen intención de proceder a su venta. Necesitan: - Copia del DNI de Aitor - Copia del DNI del tutor - Copia de los documentos acreditativos de la tutela No he querido enviarles nada sin haberos informado al respecto. Le he dicho que alguno de los dos os pondréis en contacto con ella. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-01-29','Ana: Tras hablar con Raquel, TS del SSASB de Guadalupe (605 429 865) envío correo a Ángel y Miguel, Asesores Jurídicos CTAEX: "... He recibido llamada de Raquel, TS del SSASB de Guadalupe (605 429 865) en relación a Miguel Santos Cordero y su hijo. Resulta, que aunque no nos lo había comunicado, Miguel se está mudando podo a poco a su casa. Cuando le dieron el alta en el SocioSanitario se instaló de forma temporal en casa de su padre, con éste y con su hermano, pero la convivencia no es muy buena (eso sí lo sabíamos), por lo que ha empezado a pasar cada vez más hora en su casa e incluso a pernocta allí. Como ésta no reúne adecuadas condiciones de habitabilidad, su hijo Miguel, que reside en Logrosán, le está ayudando a limpiarla y acondicionarla. Pero hoy le ha parado la Guardia Civil y le ha puesto una multa. La cuestión y lo que nos pide la TS, es ¿podemos hacerle algún escrito desde la CTAEX indicando que Miguel Santos Antequera (hijo), acude a diario a atender a su padre dependiente y tutelado por la CTAEX? La verdad es que le viene bien este apoyo, no cuenta con ningún otro. Decidme cómo lo veis vosotros y si consideráis que hagamos un escrito. *En caso afirmativo la TS pide que le lo enviemos hoy para que pueda presentarlo en la Guardia Civil." ············································································································································· Datos de contacto de Miguel Santos Antequera (hijo de Miguel): 623 197 407 // m.santosantequera@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2021-01-29','TERESA ARCHIVO RESOLUCION RECONOCIMIENT DERECHO A TRATAMIENTO','2');
