insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-01-29','Ana: Llamo a Control de Pensiones, de la Tes. Geranal de la Seg. Soc. Miguel, Jefe de Secc (927 62 00 49) me comunica que efectivamente causó baja en PFHC y que no hay expediente de P.Orfandad. *Le aparece en el sistema que percibe PNC. ······························································································································································································ Llamo a María Bueno, PNC (924 00 60 31), me confirma que Aarón está de alta en la PNC. Pide que le haga la solicitud del certificado por escrito al mail: maria.buenomar@salud-juntaex.es ······ *Me remite certificado de PNC (402,80 €). Lo guardo en el exte. digital y se lo reenvío a Icíar - CTAEX. ························································································································································································· Como no consigo contactar por teléfono con Sonia- Asindi, le envío un correo informándole al respecto. ···································································································································································································· Me remiten del CADEX el Certificado de Discapacidad y el Dictamen Técnico solicitados. Archivo en expte. digital.','2');
