insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-02-01','Se cita a Felisa para reconocimiento forense en el IML de Cáceres, para el 2/3/2021, a las 10:00 h, para la elaboración de informe de imputabilidad (DPA 191/2020), seguido en el Juzgado de Primera Instancia e Instrucción, nº 4, de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2021-02-01','TERESA el pasado 26 de Enero se recibe una llamada de la Dra. Rosa, psiquiatra de la UME que lleva el caso de Carmen Rubiano. Rosa comenta que tiene pensado darle el alta a Carmen en la próxima semana ya que la tutelada se encuentra muy bien, y considera que es importante que vuelva a su entorno para que comience con sus actividades diarias. Se le pregunta a Rosa si ha comunicado esta decisión a la comisión tutelar ya que son sus tutores legales y deberían saberlo y para que vayan gestionando, de nuevo, la retirada de su asignación mensual en el banco. Rosa responde que no lo había hecho y comenta que hablará con Manoli, una de las trabajadoras sociales del sociosanitario para que se comunique con la comisión y les haga llegar la información del alta. Por otra parte, se comenta con Rosa que Carmen en su domicilio recibe ayuda a domicilio y también le llevaban a casa la comida y la cena desde el centro de día. Por lo que se hablará con Maribel de los SSB de Llerena para que organice a las auxiliares y haga un cuadrante nuevo incluyendo la casa de Carmen otra vez en la planilla. Maribel comenta que el tema de la comida del centro de día lo lleva una compañera de los SSB que solamente va al ayuntamiento dos veces en semana. Hablará con ella sobre este tema cuando vuelva al ayuntamiento pero preveía que este tema se demoraría un poco. Se vuelve a hablar con Rosa y se le comenta que desde los SSB de Llerena se está organizando el tema de la ayuda a domicilio y se tramitará lo de la comida del centro de día pero que probablemente tardará un tiempo en estar todo listo. Rosa contesta que no hay problema, que el alta de Carmen se puede atrasar todo el tiempo que sea necesario hasta que ella tenga todos los servicios en su domicilio. Se habla seguidamente con Mari Cielo, la trabajadora social del CRPS de Zafra, y se le comenta que el alta de Carmen es inminente. Ella cuenta que el servicio que se estaba desarrollando para visitar a Carmen una vez por semana no está activo porque no les ha llegado aún la subvención. Pero que en el momento en que se ponga en marcha, las visitas a Carmen volverían a realizarse. El pasado 28 de Enero se volvió a hablar con Maribel de los SSB de Llerena, ella comentó que ya tenía a una auxiliar de ayuda a domicilio en reserva para cuando Carmen volviera a su casa para empezar el servicio de una hora diaria. Se intentará avisar a los SSB en cuanto se sepa la fecha exacta del alta de Carmen para que ese mismo día o al día siguiente como muy tarde vaya la auxiliar, porque la casa estará sucia y desordenada, ya que no se ha tocado desde que ella se fue en Septiembre de 2020. Se le pregunta seguidamente por el tema de la comida y la cena que se le llevaba a Carmen a casa desde el Centro de Día de la localidad, a lo que Maribel responde que ha hablado con su compañera del ayuntamiento que lleva ese tema. Ésta le ha dicho que ha llamado a los pisos tutelados de Llerena y ha hablado con su director, Manolo ( 924 87 20 69 ) y éste le ha comunicado que solamente hace falta que la comisión se ponga en contacto con ellos para activar de nuevo el servicio y con ello los pagos del mismo. Por lo que solo quedaría que la comisión contactara con el centro para poner en marcha el catering.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-02-01','Ana: Llamo al CSS-Plas. Me dicen que Estrella, TS, no está. Me pasan con Mariví Clemente, le comunico que la llamada programada para que hablaran Pedro, Jefe Secc. CTAEX, con Juan Carlos, no podrá tener lugar pues Pedro hoy no ha acudido a trabajar. Indico que si Juan Carlos quiere puede llamarme a mí. *Mariví se lo comunicará la responsable de la UHDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-01','Ana: Llamo a Mariví Clemente, TS CSS-Plas., en relación a la plaza de PP.SS., le comunico lo que me transmitió Eva, Psicóloga Secc. Salud Mental, la semana pasada. ···························································································································································································· Correo-e de Eva Paredes, Psicóloga Secc. Salud Mental: "Buenos días Ana: En relación a la plaza del tutelado Francisco Cacho de la que nos preguntabas el jueves, comentarte que la situación para su posible ingreso en la Plaza de Piso supervisado de Mérida sigue en las mismas condiones que te informamos, es decir, no está cubierta aún la plaza de la Psicóloga Coordinadora del PS, que sería la técnico encargada de realizar todos los trámites para la incoporación al recurso, desde la entrevista previa al acceso, como el seguimiento en el periodo de adaptación, y el resto de intervenciones. La segunda de las opciones que barajamos para no seguir en esta situación que está perjudicando al paciente, sería la de ingresar en otra plaza de otro Piso supervisado, cosa que ahora mismo no es posible por no tener ninguna plaza vacante para ofrecerle a Francisco. La primera vacante que haya va a ser para él, pero mientras tanto, os queríamos plantear la única opción que es viable de realizar en estos momentos, que sería la de ofreceros una plaza temporal en el CRR de Plasencia, donde tenemos una vacante para ello, hasta que se pueda hacer el cambio de plaza de Francisco a un Piso supervisado, momento en el que ya le adjudicaríamos la plaza definitva de PS por vía resolución de Dependencia. Entendemos que esta opción de plaza temporal en un recurso diferente, además de la autorización de vosotros como CTAEX, tendréis que valorarla con el propio Francisco. Esperamos vuestra respuesta para realizar los trámites correspondientes. Por otro lado, el tema que nos preguntabas de su Resolución de adjudicación, comentarte que al revisar su documentación PIA veo que se han cometido errores, ya que viene firmada por el propio Francisco, con lo cual, hay que recoger de nuevo la petición de Servicios PIA para que sea debidamente firmada por el Director Gerente, ya que en estos momentos, tal y como está el expediente de dependencia no es posible hacer la Resolución PIA. Os pasaremos la documentación por Nota Interior, para ir gestionando estos trámites también. Para cualquier cosa estamos disponibles y quedamos a la espera de vuestra respuesta sobre la propuesta, ..." ······························································································································································································ Mi respueta: "Hola Eva, Pues en inicio la opción que planteas de plaza temporal en el CRR hasta que que haya una plaza en PS a mí me parece muy buena alternativa. La ha consultado también con Mariví Clemente y a ella también le parece bien, no cree que Francisco diga que no, “dado el grado de desesperación” expresa literalmente Mariví. No obstante va a decírselo al Psiquiatra para plateárselo de forma conjunta los 2. Por otro lado, Mariví quiere que le confirmemos si tendrá que hacer también entrevista previa (entiendo que sí) por videollamada, para organizarla. Ya nos dices (puedes escribirnos a los 2 si quieres) Muchas gracias Eva." ······························································································································································································ Llamada de Mariví Clemente: ya han hablado con Fco. Éste está abierto a ir temporalmente al CRR y a hacer las entrevistas que hagan falta. ····························································································································································································· Nuevo correo de Eva: "...En el momento que me confirméis definitivo que Fco Cacho quiere la opción de plaza temporal en CRR a la espera de PS, y sabiendo que a la CTAEX os parece bien, enviaremos su expediente a la directora del CRR Plasencia, (con la que también hemos hecho ya la consulta, está informada), para que ella haga los trámites normales de ingreso en CRR, entre ellos la Entrevista previa de acceso, que ultimamente viene siendo telemática. Elolos se pondrán en contacto con Mariví Clemente ara fijar la fecha de entrevista. También es importante que Fco finalice su vacunación en el CSS, que creo que ya mismo les tocaría la segunda dosis. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2021-02-01','Ana: Envío correo a Pilar Cerrillo (calidad@grupociudadjardin.com): "Buenos días de nuevo Pilar, quería preguntarte qué tal resultó el traslado y la adaptación de Mateo Ruano Moreno al nuevo recurso, espero que haya ido todo bien, ya me cuentas cuando tengas un momento. Un saludo y buena mañana." ······································································································································· Respuesta de Pilar: "...No te he comentado nada porque aun no se ha podido hacer el traslado, por dos motivos, primero, hubo un fuerte brote de COVID en la residencia y segundo, al tener el alta epidemiológica, se nos vacunó. La segunda dosis es el jueves y a partir de ese momento se hará el traslado. Te mantengo informada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-01','Ana: Llamada de José Manuel (678 150 472): El jueve pasado en urgencias le tuvieron que poner un inyectable pues no se encontraba bien, su enfermera de referencia hablará con la Psiquiatra, pues en principio no tenía pautada esta medicación. *Él dice que le ha vendio muy bien, que se encuentra mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-01','Ana: Llamada de Damián, pide que le diga a Icíar, secc. ecca. CTAEX, que ha cambiado de opinión, pues la última vez que habló con ella le dijo que se iba a marchar a su piso de Málaga, pero que ha decidido quedarse en el CRR.','2');
