insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-01','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Buenos días Ana, hemos hablado con la residencia de Malpartida y con Celia de la sección de mayores del Sepad. Ya hemos pedido cita para la PCR de Guadalupe y es para mañana 2 de febrero. Si la respuesta es el día 3 por la mañana esa sería la fecha de ingreso, si no tendría que ser el día 4 pues los ingresos son por la mañana. Seguimos en contacto"','2');
