insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-02-01','TERESA HABLO CON MARISA DE LA RESINENCIA SAN ROQUE 924638023, ME COMENTA QUE TIENE DOS VIVIENDAN UNA EN TALARRRUBIAS EN LA CUAL HAY 3 PERROS QEU SE ENCARGA UNA VECINA DE ATENDERLOS DE FORMA ALTRUISTA OTRA VIVIENDA EN MADRID LA CUAL ELLA PAGA EL IBI Y LA NUERA LA COMUNIDAD MIGUEL HA PEDIDO CERTIFICADO DE BIENES Y SOLO APARECE A SU NOMBRE A DE TALARRBIAS ELLA COBRA DE PENSION 1200 Y PAGA EN LA RESIDENCIA 1100 CON LO CUAL NO LLEGA PARA PAGAR Y ESTA GENERANDO DEUDAS TAMBIEN COMENTA QEU HAY UNOS FONDOS DE TELEFONICA QUE SE PUEDEN RESCATAR TIENE UN GRADO DOS DE DEPENDENCIA QUEDO PENDIENTE DE VER CON MIGUEL TEMA DE HERENICIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-02-01','TERESA ENVIO SOLICITUD SAD AL AYTO POR CORREO CERTIFICADO.Esta pedido el ingreso involuntario y plaza en centro de discapacidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-02','Ana: Envío correo a Eva Paredes, Psicóloga Secc. Salud Mental (eva.paredes@salud-juntaex.es): "Buenos días Eva, Pues confirmado ya, Francisco tiene tanta necesidad de salir del C. Sociosanitario que ha aceptado la propuesta de buen grado. En la CTAEX también estamos de acuerdo, así que podéis remitir el expediente a la dirección del CRR. Por cierto, no sabía que había cambiado, pensé que seguía Javier. Seguimos en contacto. Un saludo y buena mañana." ······················································································································································································ Envío correo-e a Mariví Clemente, TS CSS-Plas. (victoria.clemente@salud-juntaex.es): "Buenos días Mariví, Confirmado ya todo con Eva. Enviarán el expte. de Francisco Cacho Garrido, a la dirección del CRR, ya han hablado con ella. Desde allí se pondrán en contacto con vosotros para organizar la entrevista por videoconferencia, que sí que hay que hacerla, y todo los demás de cara al ingreso. Mantenedme informada por favor. Ante cualquier otra cuestión, hablamos. Un saludo y buen día." ····················································································································································································· Correo-e de Eva Paredes: "...De acuerdo Ana, entonces una vez me lo confirmas, preparo el expediente y el correo de envío al Recurso CRR Plasencia. En los próximos días ellos contactarán con el CSS para hacerle poder hacerle la entrevista. Hay que esperar a la vacunación completa de Francisco Cacho y unos días que el CRR necesitarán seguramente para preparar el ingreso, pero ya estariamos hablando de un corto plazo para el ingreso de Francisco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2021-02-02','Ana: Correo de la Dra. Ana Isabel Ferrer, HSPA-CC (anaisabel.ferrer@salud-juntaex.es): "Le escribo porque vamos a intervenir a Rafael Fernandez Bermejo el día 4/2/2021 de nefroureterectomía radical por masa renal izquierda. Anestesia vino a valorar al paciente previo a intervención pero le ha dado la categoría de NO APTO SEGUIMIENTO porque sus representantes no han podido firmar los consentimientos de anestesia general. Te paso el documento de anestesia para que sea firmado y podamos continuar con la intervencion" ············································ *Una vez firmado y sellado el CI, se lo remito escaneado por el mismo medio a la Dra. Ferrer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-02-02','CORREO. SE REMITE POR E-MAIL AL CENTRO CONSENTIMIENTO INFORMADO PARA SUJECIÓN CON MUÑEQUERAS. EL ORIGINAL SE REMITIRA CUANDO DEVUELVAN EL OFICIO DE REGISTRO.','2');
