insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-02-02','Ana: Me devuelven de registro la Solicitud de Valoración de Dependencia de Juan Carlos. REGISTRADA DE ENTRADA a fecha de 28/01/2021. ··············· *Se la remito a Estrella, TS del CSS por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-02-02','Ana: Recibimos escrito de ASPACE informando de la subida del coste de la plaza de Santi. Para este 2021 el importe asciende a 453,15€/mes. ··············· Se lo paso a Alberto, jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-02-02','Ana: dice que esta mañana ha tenido algunas taquicardias pero que ya se le han pasado. Está pendiente de una cita de cardiología. Por lo demás, vuelve a su tema recurrente sobre el dinero, expresa que está ahorrando más y que le gustaría poder retirar el dinero una sola vez al mes. Se le recuerda que cuando los informes del personal técnico del rucurso así lo recomienden, podremos probar con retiradas quincenales en lugar de semanales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-02','Ana: Llamada de José Manuel, insiste en que se le suba la asignación semanal, pues no tiene dinero para tabaco, su hermano ha decidido dejar de darle. Quiere 10 € diarios sólo para tabaco. Le digo que eso no puede ser. Y le recuerdo los motivos por lo que su asignación semanal es más baja desde hace unos meses. *Dice que va a hacer algo que no debe para comprar tabaco. Que le ha pedido al médico una receta para comprar Trankimazin, diciendo que era para él, pero que ha pensado en venderlas para conseguir dinero para tabaco. *Le recuerdo dónde puede volver como cometa delitos. *En este momento se retracta y promete que no lo hará. ········· *Le pregutno por qué no pida cita al CEDEX para, al menos, reducir el consumo de tabaco. Pues sería bueno para su salud y para su economía. Dice que es verdad, que debería hacerlo. Le planteo si quiere que llame yo al CEDEX y me dice qu no hace falta, que él tiene el número.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-02-02','Ana: Llamada de Ceferino, dice que quiere que le aumenten la asignación mensual, pues su pensión es mucho más alta de lo que se le dá. Y que en el CRR le den mayor catidad diaria, en lugar de los 3 € diarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-02-02','Ana: ponga para REGISTRO DE ENTRADA la SOLICITUD DE VALORACIÓN DE DEPENDENCIA PARA SERVICIO RESIDENCIAL junto con la documentación pertinente relativa a la tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2021-02-02','Ana: recibimos un correo-e en el ctutelar@ de Montaña Castro, TS, a través de la dirección de contacto: inf.saludextremadura@salud-juntaex.es: "Hola soy Montaña la Trabajadora Social de Torrecillas de la Tiesa, y me vuelvo a poner en contacto con vosotros porque Encarnacion Patillas Castro con DNI 06904497N, sigue sin tener tutor desde que lo dejo la persona que tenia la tutela anteriormente. Desde el Ayuntamiento y la residencia se propone a Lcinia Iñigo Jimenez DNI 06997183P, su movil es 659889549, esta persona es personal de la residencia Para cualquier informacion pueden llamarme al 621 247 249". Entendemos que son los datos de la persona que quieren que se autorice para la retirada de dinero de Encarna. *Como no está Alberto, jefe secc. ecc., se lo paso a Belén.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-02','En relación con el procedimiento Juicio sobre delitos leves 119-20, seguido en el Juzgado de Instrucción, nº 4, de Badajoz, se ha dictado sentencia condenatoria de multa por 180 euros, más indemnización de 210 euros. Una vez que se dicte la Ejecutoria, procederemos a pagarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='POZAS'and apellido2='GOMEZ'),'2021-02-02','Ana: Recibimos correo en ctutelar@ de Emilia Almodovar, TS CSS-Plas. (emilia.almodovar@salud-juntaex.es): "Buenos Días. Informamos por recomendacion sanitaria, vamos a solicitar la compra de recurso ortopedico "andador" para los pacientes tutelados por C.T de adulto: • Angel Pozas Gomez : 076156199 W. unidad Psicogeriatria... ". ····················································································································································································· Respondo: "...Decirte que para estas compras, tenéis que enviar al menos un par de presupuestos a la Secc. Económica, a esta misma dirección, a la A/A. de la Secc. Económica. Cuando os den el visto bueno, se abonará mediante transferencia a la Ortopedia. En la factura debe aparecer los datos de la persona tutelada. Para solicitar las ayudas del SES para material ortoprotésico, podéis remitirnos la solicitud cumplimentada para que la firme el representante legal. Y, o bien os la devolvemos firmada para que adjuntéis la documentación pertinente, o bien nos remitís toda la documentación junto a la solicitud para que lo lleve yo al registro del SES. Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZA'and edp.apellido1='BONILLA'and apellido2='DOMINGUEZ'),'2021-02-02','Ana: Recibimos correo en ctutelar@ de Emilia Almodovar, TS CSS-Plas. (emilia.almodovar@salud-juntaex.es): "Buenos Días. Informamos por recomendacion sanitaria, vamos a solicitar la compra de recurso ortopedico "andador" para los pacientes tutelados por C.T de adulto: • Lorenza Bonilla: 011762131 T. unidad de larga Estancia... ". ····················································································································································································· Respondo: "...Decirte que para estas compras, tenéis que enviar al menos un par de presupuestos a la Secc. Económica, a esta misma dirección, a la A/A. de la Secc. Económica. Cuando os den el visto bueno, se abonará mediante transferencia a la Ortopedia. En la factura debe aparecer los datos de la persona tutelada. Para solicitar las ayudas del SES para material ortoprotésico, podéis remitirnos la solicitud cumplimentada para que la firme el representante legal. Y, o bien os la devolvemos firmada para que adjuntéis la documentación pertinente, o bien nos remitís toda la documentación junto a la solicitud para que lo lleve yo al registro del SES. Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-02-02','Ana: Tras recibir llamada de Carmen, TS del SSASB-Coria (927 50 80 00, Ext. 318) envío correo a Icíar, secc. ecca.: "Buenos días Icíar, Acaba de llamarme Carmen, TS de Coria (Tlf. 927 50 80 00 ext. 318), dice que te envió un correo el día 29, ya le he dicho que no estabas trabajando. Lo he localizado y te lo reenvío. Pide que la llames cuando puedas. Al parecer la situación ya es crítica, ayer tuvieron que prepararle un kit básico de emergencia con papel higiénico, latas de comida, etc. Espero que lo de la cuenta bancaria pueda solicitarse pronto, ya me informarás." *Carmen en el correo envía adjunto escaneado a color su DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='REMEDIOS'and apellido2='CASATEJADA'),'2021-02-01','EXITUS viernes día 29/01/2021 falleció, D. JOSÉ REMEDIOS CASATAJADA. COMUNICA TS DE LA RM IBARRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-02-02','miguel, recibo de Teresa el siguiente emaiil: AYE LLAME A LA RESIDENCIA DONDED SE ENCUENTRA ESTA TUTELADA, HABLE CON MARISA QUE ES LA QUE LLEVA SU EXPEDIENTE ME INSISTE EN QUE TIENE UNA VIVIENDA EN MADRID PUES EN LA CUENTA LE PASAN EL IBI Y LA COMUNIDAD LA PAGA LA NUERA, ADEMAS TAMBIEN PAGA LOS SUMINISTROS DE AMBAS VIVIENDAS…. HASTA EL JUEVES NO ESTA ALBERTO PARA VER CON EL TODO ESTE TEMA TAMBIEN ME COMENTA QUE TIENE UNOS ACTIVOS DE TELEFONICA QUE AL FALLECER EL HIJO NO LOS HAN PODIDO COBRAR ME DICE QUE ME MANARA DOCUMENTACION DE TODO ESTO… NO SE QUE ME PUEDES DECIR TU DE ESTE CASO, IMAGINO QUE HABRA QUE HACER LA HERENCIA EL CASO ES QUE A FECHA DE HOY ENTRE PAGAR LA RESIDENCIA Y LOS CARGOS VARIOS QUE LE PASAN NO LLEGAMOS…. PARA MAS INRRI EN LA VIVIENDA DE TALARRUBIAS TIENE 3 PERROS LOS CUALES CUIDA UNA VECINA…. YO IBA A DARLE DE BAJA A LOS SUMINISTROS PERO CLARO AGUA TENDRA QUE HABER PARA ESOS PERROS…. EN FIN QUE ME CUENTES SI SABES ALGO MAS DE ESTE CASO PARA CUANDO HABLE CON ALBERTO PORQUE HABRA QUE TOMAR DECICISIONES ******************************************************* Hablo con ella y la comento: Que en su día llamó la abogada de la exnuera para pedir autorización para liquidar un ipuesto de sucesiones y la dijimos que era una tutela recien recibida y necesitabamos tiempo para el inventario. Pues bien, el inventario ya está y no aparece en nota simple ningún bien en Madrid a nombre ni del exmarido, hjijos fallecidos y la tutelada. Tampoco tenemos constancia como dice la trabajadora social de la cuenta de acciones. Por tanto únicamente cabe o bien alquilar alguno de los bienes que puedan quedarla, trasladarla a una residencia pública, o comenzar los trámites de herencias de los dos hijos, al tiempo que nos justifiquen que esa vivienda de Madrid es de ella. Caso contrario le indico deberían de devolver todos los recibos que no le correspondan. Caso que quiere que tramitemos las herencias del exmarido e hijos necesitamos que nos manden toda la documentación de testamentaria y la que acredite todos los bienes de que diponian los fallecidos. Me comenta que el jueves lo hablará con Alberto y me comentará','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-02-02','-Ultimas incidencias de Jonathan : hace un par de semanas me llamó su hno. Ramón , Jonathan había vuelto a la casa del padre en el Peri ( Mérida ) y allí no se podía quedar porque vive él con su familia y por la O.de alejamiento que tiene de su padre . Solicita que le ayudemos y le busquemos un recurso habitacional de urgencia. Tras hacer varias gestiones , consigo que lo acpeten en el Hostal Salud en Mérida , actualmente gestionado como Centro de emergencia social por Caritas . Le hacen PCR por la tarde , da negativo y se procede al ingreso . Ayer fue expulsado del recurso por robar , y por consumir drogas en la habitación. Solicitó un extra para ropa que le denegué , la ropa se la van a facilitar gratuitamente desde Caritas . Desconozco a dónde se habrá digirido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-02-02','ültimas incidencias de Ildefonso : En diciembre se le gestionó el hostal Senero donde permanecía hasta hace unos días que sin comunicarlo al HOstal ni a la CTAEX se ha ido al H. Salud , que es gratuito y le dan tb la comida . El dinero que se le autorizaba para comida lo ha gastado en una TV , un robot de cocina ... para llevarselo a JOaquina cuando se vaya a Barcelona .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-11-12','Ana: Recibimos en la CTAEX informe del SSASB para la rendición anual registrado de entrada el 10/11/2020: "Valoración profesional: Se observa qu eel estado de D. Juan Chamorro Holguín se va deteriorando cada año más, abandonando las actuaciones básicas de la vidad diaria (higiene, alimentos)..." "...cabe la posibilidad de abandono del tratamiento." "...tiene que ser estudiado y tratado por profesionales especialistas, debido a la enfermedad mental..." "...Necesita ayuda ya que no tiene red socio-familiar de apoyo y un segumiento continuo de sus tratamientos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-02-03','TERESA RECIBO A TRAVES DE SU HERMANO LORENZO RESOLUCION DEL SEPAD DE LA PRESTACION ECONOMICA DE SAD POR DEPENDENCIA LE LLAMO Y ME DICE QUE NO SE ESTA HACIENDO EL SERVICIO PORQUE LA EMPRESA NO ENCONTRO HA NADIE COSA QUE NO HAN COMUNICADO A LA COMISION TUTELAR. EL CONTRATO SE HIZO CON FECHA DE INICIO CON LO CUAL AHORA HAY QUE DEVOLVER TODO LO QUE NOS VAN A INGRESAR LE HE DICHO QUE VAYA A LA EMPRESA Y A AVERIGUE , QUE DAMOS EN LLAMARME UNA VEZ HAYA HABLADO CON ELLOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-02-03','Ana: Envío correo-e a Carmen, TS Coria (carmen.martinez@coria.org) comunicando el nº de cuenta que se le ha abierto a Emilia en ABANCA y preguntando la fecha de suspensión para reactivarla. ······················································································································································································ Una vez cumplimentados y sellados por el D.Gerente, la Comunicación al INSS de cambio de datos bancarios y la Solicitud de de Abono de Mensualidades Impagadas, se las dejo a Juanpe, Admvo. CTAEX, para que las lleve mañana al registro ORVE-SIR del SES (ya está cerrado hoy)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-02-03','Ana: Remito a María Glez., TS Autismo Sur, por mail, la Declaración Responsable que nos remitieron, con firma digital. *Guardo copia en su expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-02-03','TERESA HABLO CON ROSA TS PARA PREGUNTAR POR JOSE ANTONIO ME COMENTA QUE ESTA BIEN PERO SIGUE SIN DEJAR QUE ENTRE AYUDA A DOMICILIO PLANTEA QUE LE CAMBIEMOS EL PIA POR SAD Y QUE LE PAGUEMOS UN CATERING PARA QUE LE LLEVE LA COMIDA TAMBIENM LE VOY A PEDIR LA ORFANDAD ABSOLUTA QUEDO PENDIENTE ME MANDER PRESUPUESTO DE CATERING PARA VALORAR CON PARTE ECO LE SOLICITO DOCUMENTACION PARA TRAMITAR LA ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2021-02-03','TERESA YA TENEMOS LA PENSIN EN LA NUEVA CUENTA, VUELVO A MANDAR EMAIL AL CENTRO PARA QUE ME CONFIRMEN GASTOS DE BOLSILLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-02-03','TERESA: FUTUEX Mantiene muy buena relación con las usuarios del programa e intenta ayudar a los compañeros que le necesitan, aunque siempre lo hace con los pies en la tierra, sin olvidarse de sí mismo. Esto no era así hace unos años, en 2010 y 2011, Bartolomé consumía todo tipo de drogas y se relacionaba con gente problemática. No tenía conciencia de enfermedad ni tomaba la medicación. De hecho tuvo un altercado en un bar con un policía local que no estaba de servicio y le rompió un brazo, ya que Barto tiene conocimientos de Taekwondo. Por lo que estuvo ingresado en el sociosanitario de Mérida durante dos años por orden judicial. Elena comenta que al salir del sociosanitario, era una persona nueva ya que se convirtió en alguien muy responsable, que cuidaba mucho de su medicación y sus citas médicas y que tenía los pies en la tierra. Con respecto a la organización del dinero, Elena comenta que siempre ha sido algo alocado y que ni su hermano cuando era su tutor ni su padre después, le pusieron límites a la hora del control del dinero, por lo que Bartolomé está acostumbrado a manejar tanto su pensión como la de su padre para comprar lo que le apetece: ropa, cosas para la casa, comida, ...etc. Elena considera que le costará algo de tiempo adaptarse a la nueva situación con respecto al dinero ya que nunca le han puesto límites de ninguna clase y le va a costar aceptarlos. Se le pregunta cómo se está organizando en casa sin poder sacar dinero ( ya que no se le comenta que se sabe que está retirando dinero del banco con la tarjeta de crédito ) y contesta que está bien porque está ayudando a un amigo en una obra en la que está trabajando como albañil y le ha pagado por ello. Cuando se le pregunta cuánto le ha pagado, Bartolomé no contesta con una cifra, solamente dice que ha podido comprar comida y tabaco y que le quedaban 5€. Aunque al comentar este dato, no se le notaba nervioso ni alterado, como si no le preocupara estar con tan poco dinero. Se supone que él está tranquilo porque seguirá pensando que puede usar la tarjeta de crédito como lo ha hecho hasta ahora, pero cuando se de cuenta de que se le ha anulado, vendrán los agobios y los nervios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-02','Ana: Correo de Toni-Futuex: "Hola Ana que tal todo? te escribo en relación a la tutelada Clementa Amado Vivas, no sabemo si ha producido el traslado de su piso definitivamente a un centro, de no ser así, nos ha llamado mucho la atención que su piso salga publicitado en la página de facebook de la emprea "Alquiler sin Riesgo", te adjutno el enlace, y el pantallazo donde sale la vivienda, la compañera me asegura que está complementamente segura que se trata de la vivienda de Clementa. No sabe si puede tratarse de alguna argucia de la hija, o a que se debe. Sabeis algo ? https://www.facebook.com/511229298987580/posts/3478641372246343/ ..." ··············· *Se lo reenvío a Alberto, Jefe Secc. Ecca, Ángel y Miguel, Asesores Jurídicos. ·························································································································································································· Correo de Pilar, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Clementa desde hace dos días se encuentra viviendo con su hija, cosa que comunico la situación de riesgo al juzgado, y le han citado para el forense el próximo día 11, (para el internamiento involuntario), me han mandado la cédula de citación y se la he entregado ya a su hija. Un abrazo." ······················· Lo pongo en conocimiento de Ángel y Miguel, Asesores Jurídicos CTAEX y Toni - Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-03','Ana: Conversación con Mai - Secc. Acceso Recursos de Mayores: En cuanto reciban el resultado de la PCR remitirán la Resolución a la Residencia para que pueda ingresar Guadalupe. ························································································································································································· Correo de Blanca, CRR-Plas. (coordinaciontecnica.crrplasencia@grupo5.net) al ctutelar@: "Buenas soy Blanca Conejero González, psicologa del CRR de Plasencia, os enviamos el certificado de la prueba de covid negativa de Guadalupe Barragán García para que el ingreso en la residencia de Malpartida." ······················································································································································································ Conversación telefónica con Mari, Directora Residencia La Luz de Malpartida de Plasencia (927 459 100, ext. 1): Guadalupe ingresará en 1 hora apróx. Me remitirá por mail la documentación necesaria para el ingreso. Su dirección de correo es: direccion@residencialaluz.com ····················································································································································································································· *Pido a Coral, CTAEX que les envíe la Póliza del Seguro de Decesos. ············································································································································································································································ **Yo le remito la Autorización para la vacuna del Covid con firma digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2021-02-03','Ana: Recibimos del INSS la revalorización para 2021 de la pensión de ORFANDAD ABSOLUTA de Manuel: 384,97 €/mes . *Viene a nombre de "María de los Dolores Beltrán de la Cruz" *Redacto escrito comunicando cambio del tutor al INSS y lo pongo para registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-02-04','Ultimas incidencias de Macarena : Este fin de semana se ha registrado la incidencia con Macarena Otano, como te indicaba en el email anteriror, pues estaban saliendo juntos. Macarena ha tenido un episodio de enfrentamiento con sus padres y el sábado 30 de Enero, hizo una maleta y se marchó a casa de Alejandro pasando allí la noche del sábado al domingo 31. Exponiendo que no quería seguir “con esos padres que tanto le exigen y no la quieren”, que ella tiene dinero (400 euros al mes) y se los puede gastar en un solo día si le apetece”. (esto nos dice la madre de Alejarndo que dijo Macarena) El domingo recibió una llamada de su madre y ante la exigencia también de la familia de Alejandro, para que abandonara la casa, se marchó de nuevo a su domicilio. Alejandro en esta visita nos comenta que ya no están saliendo, puesto que ella no acepta que él consuma drogas. Nos expone Alejandro que no le ha dado oportunidad alguna para cambiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2021-02-04','- Amalia : está ingresado en H. U. Badajoz por covid , se envia consentimiento informado elaborado por Angel para administratar tteo. covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-04','ultimas incidencias : 02 de febrero de 2021; visita presencial (acompañamiento a consulta en ortopedia) Se realiza visita planificada para acompañamiento a consulta de valoración y gestión de presupuesto de plantillas ortopédicas, ante la necesidad de ayuda ortopédica que Alejandro presenta por su deformación congénita (sindactilia) que le produce problemas de destreza motora, así como dificultad en su vida diaria para actividades básicas, caminar, realizar deporte, ect., sumado al sobrepeso que tiene en la actualidad. El técnico ortopédico Amalia Villafaina Muñoz, que ya le estaba haciéndole seguimiento hace un tiempo, pero Alejandro no acudió a revisiones y abandonó el uso de plantillas, recomienda encarecidamente su uso, ante la deformación tan agudizada y la gravedad que supone no ayudar con estas plantillas esta situación. Junto con el uso adecuado de calzado más conveniente y no cualquier zapatilla, por muy de marca que sea, tal como Alejandro quiere. Se adjunta presupuesto por importe de 168 euros (88 euros las dos plantillas realizadas a medida y 80 euros el coste de las dos consultas) Tanto la madre de Alejandro, como su abuelo, solicitan que sea presentado el presupuesto a la comisión tutelar, aunque ellos reciben la pensión integra del tutelado. Ellos reclaman que estos gastos extras, se realicen aparte de lo que se recibe mensualmente. También reclaman la paga extraordinaria de navidad, dicen que se les ha informado que se entrega prorrateada, que es algo no aceptable, porque esto no es una empresa y que Alejandro demanda constantemente dinero y compras. Asique según tu consideres, o se abona a parte o les indicamos que tiene que se de la asignacion, nos tememos que si esta segunda opcion puede que no se laas hagas, y es cierto que le hacen falta. El tutelado, mantiene su dinámica de compras compulsivas, pero es algo que también ve en su madre, pues junto a ella realiza estas compras online, sin importar precios, siempre de marcas. Y si no se satisface esa demanda constante, Alejandro reacciona con violencia. Este fin de semana se ha registrado la incidencia con Macarena Otano, como te indicaba en el email anteriror, pues estaban saliendo juntos. Macarena ha tenido un episodio de enfrentamiento con sus padres y el sábado 30 de Enero, hizo una maleta y se marchó a casa de Alejandro pasando allí la noche del sábado al domingo 31. Exponiendo que no quería seguir “con esos padres que tanto le exigen y no la quieren”, que ella tiene dinero (400 euros al mes) y se los puede gastar en un solo día si le apetece”. (esto nos dice la madre de Alejarndo que dijo Macarena) El domingo recibió una llamada de su madre y ante la exigencia también de la familia de Alejandro, para que abandonara la casa, se marchó de nuevo a su domicilio. Alejandro en esta visita nos comenta que ya no están saliendo, puesto que ella no acepta que él consuma drogas. Nos expone Alejandro que no le ha dado oportunidad alguna para cambiar. Pero confirmamos que sigue consumiendo, algo menos, ya que por las medidas establecidas, pasa más tiempo en casa, aunque ahora vuelve a tener contacto otra vez con esos amigos que le proporcionan el consumo. Ha recibido ya la sentencia que le condena por los delitos leves que le produjo a un amigo en el propio domicilio, siendo condenado a pagar multa. Su madre nos dice que ya ha entregado copia a la comisión tutelar. La siguiente cita y visita presencial, será el próximo martes 09 de Febrero para control de cedex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-02-04','-respuesta del ESM: "Respecto a la toma de medicación de Mercedes P., me indica su Psiquiatra que ha hablado hoy con la Médico de Atención Primaria del Centro de Salud de la Zona Centro, para comprobar si la medicación pautada se la está tomando, ella nos confirma que se la toma correctamente." Saludos, Mar Sánchez','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-02-04','llega por fax del Jzdo nº6 providencia dandonos 5 días de alegaciones por si queremos oponernos a la competencia del jzdo nº4 de Badajoz para seguir conociendo del procedimiento de internamiento 167/2021 en lo referente a su seguimiento. No tenemos nada que alegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-03','Ana: Correo de ayer a última hora de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Ana, José Manuel me ha llamado hoy dos veces para decirme que no tiene dinero para tabaco, (pero tampoco quiere reducirlo en el CEDEX). Bueno intenta habla con él. Un abrazo." ··························· Mi respuesta: "...Con José Manuel hablé el jueves, el viernes, el lunes y ayer martes también. Yo le dije que debería reducir el consumo y que pidiera cita al CEDEX… desde la CTAEX no se le van a autorizar 10€/día, como pide, para tabaco… no puede autorizar 300€ al mes en tabaco, ni por su economía ni, mucho menos, por su salud…" ································································································· Respuesta de Pilar Martín: "De acuerdo en lo de José Manuel, creo que en el CEDEX Mª Victoria le realiza gestiones telefónicas, pero parece ser que no le interesa, de todas formas, puedes hablar con Victoria el corto es 54622, también le he propuesto para voluntariado de Cruz Roja y le van a llamar seguramente hoy. (Por cierto, me llama varias veces a lo largo de la mañana, intenta hablar con él para que no lo haga)." ···································· Respondo: "Cuando hable con él hoy, porque hablo prácticamente a diario, se lo diré. Pero es algo que desde la CTAEX se le ha dicho numerosas veces, que no debe llamar ni a los recursos ni a la Comisión tantísimas veces como llama a lo largo de cada mañana. Díselo tú también si no te importa, a ver si entre una y otra conseguimos algo… pero me extraña."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-02-04','-Amalia : Ultimas incidencias de Ildefonso : Me avisan desde el comedor social que está acudiendo allí a comer y que hay gente que se queda sin atender cuando conocen que percibe una pensión. Les informo que sus 1100€ de pension se le dan prorrateados semanalmente . El dinero de este mes lo ha gastado en comprar una TV , un robot aspirador ... para llevarselos a su novia a Barcelona. Les explico que tambien he hablado con el Hostal Salud , gestionado por Cáritas como centro de emergencia por la pandemia , donde les he informado que tiene una plaza que se está abonando en el Hostal Senero . Le expulsan del recurso. Después de dos días sigue sin acudir al Hostal Senero , al que avisé de que volvería a ir . He hablado con él por tf y dice que seguirá viviendo en la calle . POr lo tanto , vive en la calle teniendo un recurso donde vivir y come en el comedor teniendo 1100€ para comer por voluntadad propia. Al hablar con migo , se ha echado a reír , y dice que seguirá haciendo " lo que le de la gana " . Valorad si es necesrio comunicarlo al juzgado ahora o en la declaración anual .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='FRAILE'and apellido2='FRAILE'),'2021-02-04','TERESA RECIBO ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-02-04','TERESA ARCHIVO INFORME MEDICO DE ALTA ACUDE A CITA CON PARTE ECO Y NOS COMENTA QUE ESTA VIVIENDO EN DON BENITO EN UN PISO DE LA MADRE DE SU NOVIO FALLECIDA HACE DOS AÑOS NOS COMENTA QYUE SU NOVIO HA GANADO UN JUICIO Y LE VAN A INDEMNIZAR CON 9000€ ACORDAMOS DARLE LA PENSION COMPLETA A PETICION SUYA, LA ENCONTRMOS TRANQUILA Y CENTRADA COMENTA QUE LE VAN A DAR UNA VIVIENDA SOCIAL EN MERIDA A SU NOVIO MIGUEL ANGEL PERO ELLA NO QUIERE VIVIR EN MERIDA DICE QUE SE ENCUENTRA MUY BIEN DON BENITO NOS DEJA PRESUPTO DENTINSTA DE 230€ LO VALORARA LA PARTE ECO EL PROXIMO 19 DE FEBRERO TIENE CITA CON SALUD MENTAL EN DON BENITO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-04','Ana: Remito correo a Alberto, Jefe Secc., Julio y Juan Pedro, Admvos. CTAEX: "Buenos días a todos, Os comunico que ayer Guadalupe Barragán García cambió de recursos residencial, del CRR de Plasencia a la Residencia Nuestra Sra. La Luz de Malpartida de Plasencia. - Juanpe y/o Julio, podéis proceder al cambio correspondiente en la base de datos. Es la primera persona tutelada que ingresa en dicho centro, por lo que no estará en la base: Calle Cáceres, 0, 10680 Malpartida de Plasencia, Cáceres Tlf. 927 459 100 Directora: Mari. Ext. 1 Email: direccion@residencialaluz.com - Alberto, habrá que hacer “reajustes” económicos. En el CRR, como sabes, no pagan nada. Ahora tendrá que abonar el 75% de su pensión para abonar su plaza. Percibe una PNC, cuyo importe para 2021 son 402,80 €/mes x 14 pagas. Han acordado enviarme toda la documentación pertinente, incluida la relativa al cobro de la plaza. En cuanto lo tenga te lo paso. Para contactar con ella para el resto de cuestiones económicas puedes anotar los datos de contactos arriba indicados. Seguimos. Buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-04','Ana: Conversación con Pilar Martín, en relación al hecho de que Clementa se ha trasladado a vivir con su hija: Según Pilar las agresiones por parte de la hijan se han estimado como "falta leve" y la hija ahora está colaborando y la acompañará el día 11 a la cita con el Médico Forense.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2021-02-04','TERESA En conversación mantenida en el dia de ayer, con la psiquiatra que la atendie en UME, comentó que se les había puesto la segunda dosis de la vacuna el día anterior y que prefería darle el alta a Carmen para el lunes de la semana siguiente, el día 8 de Febrero, y así diera tiempo a avisar a todos los profesionales que trabajan con la tutelada en Llerena. Se preguntó a Rosa si podría confirmar una hora aproximada de la llegada de Carmen al domicilio ya que habría que saberlo por llevarle la comida de ese día y por si fuera posible que la auxiliar de ayuda a domicilio fuera un rato a organizar algo la casa. Ella respondió que intentarían que estuviera en casa antes de comer. La compañera llamará a Maribel, de los SSB de Llerena para que esté informada y avise a la auxiliar que irá a casa de Carmen a partir de la semana que viene. Y también avisará al área de salud mental del centro de salud de Llerena para que sepan cuándo llegará Carmen a su domicilio. Solamente quedaría que desde alli os pusierais en contacto con el centro de día de Llerena para activar el servicio de cátering a partir del lunes día 8 , tal y como habiamos comentado y así la tutealada recibiría la comida y la cena en su domicilio como antes de ingresar en el sociosanitario LLAMO AL CENTRO DE DIA Y COMUNICO LA ACTIVACION DEL SERVICIO DE CATERING','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-04','Ana: Tras conversación con Pilar Martín, TS ESM, llamo a Mª Victoria, CEDEX (927 22 59 41 / 927 22 16 40). La persona que me atiende, tras intentar pasar la llamada, me indica que por orden dela Dra. Boticario (Mª Victoria), le haga la consutla/petición por escrito, si queremos al fax: 927 22 02 03. Pues ya no facilitan información por teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2021-02-04','EXITUS Hoy, 4 de Febrero se recibe una llamada de Mª Carmen, la trabajadora social de la residencia Juan Carlos Rodríguez Ibarra, en la que comenta que Blas Guerreo acaba de fallecer por Covid19. Nos informaron de su positivo hace pocos dias, y y hemos ido llamando para preguntar, pero nos indicaron que aunque lo notaban flojito, habian considerado que no requeria hospitalización. Cuenta que estaba muy débil estos últimos días y esa misma mañana cuando ella ha llegado al centro le han dicho que se encontraba muy mal. Se le ha preguntado si los responsables sanitarios no habían previsto un traslado al hospital ya que el tutelado estaba tan grave, pero Mª Carmen ha contestado que no, que no lo han considerado. Mª Carmen también ha comentado que estas últimas semanas Blas estaba muy triste y melacólico ya que el brote de Covid en el centro estaba ocasionando muchas bajas entres sus compañeros y la residencia estaba desierta. El estado anímico ha influido muy negativamente en la evolución de la enfermedad. La trabajadora social ha comentado que se pondrá en contacto con vosotros para informar del fallecimiento. DEP','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-02-04','Ana: Llamo al registro civil de Guijo de Coria (927 449 078): Me dicen que recieron el oficio-solicitud, pero que con los tatos y fechas de nacimiento indicados, no le consta nadie, y rastreó 10 años para adelante y otros tantos para atrás, por si hubiese habido alguna confusión. *No obstante lo volverá a comprobar y me devolverá la llamada mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-02-04','Ana: Correo de ayer de Mª Jesús Gómez Lozano, TS de la Mancomunidad Comarca Trujillo (ssb32mancomunidadcomarcatrujillo@hotmail.com): "Buenos días Ana: En relación a Mª Isabel Muñoz Melchor, tutelada por la Comisión de Adultos de Extremadura, que actualmente ocupa plaza pública residencial en la Residencia de Mayores de Jaraicejo, como en años anteriores, se solicita carta de revalorización de pensión 2021 de la Seguridad Social a efectos del cálculo cuota mensual 2020 por dicha plaza pública residencial A la espera de recibir dicha documentación solicitada, se le seguirá pasando la cuota mensual 2020- Una vez recibida, se le calcularía la cuota 2021, teniendo que abonar la diferencia o se le descontaría la misma si existiese Ruego sea remitida a la mayor brevedad posible Muchas gracias Ana" ············· Mi respuesta: "Buenos días Mª Jesús, Aún no hemos recibido dicha carta. En cuanto la tengamos te la hago llegar escaneada. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-02-04','NOTA INTERIOR. Se remite por correo interno a la sección de discapacidad (A/A de Maribel Ramos) solicitud de elección de centros y se archiva copia en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-02-04','Desde el equipo de salud mental, se nos comunica de nuevo, que para la próxima semana, desean planificar una visita presencial al domicilio de Mercedes, por parte de su psiquiatra Fernando Galán y la ts Mar, para intentar hablar con ella y poder reconducir la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-02-04','or fin terminan de enviar movimientos de la cuenta en el Santander de Mª Luisa Espinar del Arco. A fecha 31/12/2020 tenía un saldo de 79.057,45 €, y le sigue entrando la pensión de Alemania por 919,60 €, además recibe otra pensión de 115,19 del INSS, y otra de la Junta de 426,12 €. También los recibos de electricidad, y comunidad de propietarios del piso en la calle Osuna. Paga 1812,39 de residencia. Seguimos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-02-04','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net), al ctutelar@: "Hola, quería informar que Felisa Bruno Saavedra está ingresada en la unidad de Salud Mental en Cáceres. Presentaba conductas que preocupaban a los cuidadores y al médico que le atendió. Ha contactado la compañera con el psiquiatra y considera que precisa de un ajuste de medicación. Seguramente en pocos días regrese al centro. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2021-02-05','TERESA Ayer por la tarde a última hora, se cayó en el salón Paula López Ruiz, y está ingresada en el hospital de Don Benito con una rotura de cadera. Lo comunico porque imagino que por la operación, pedirán la autorización para la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-02-05','TERESA DATOS PROGENITORES DE TOMAS PARA SOLICITAR ORFANDAD El padre de Tomás falleció en Zahínos, y la madre sigue viviendo en la Residencia de Mayores de Medina de las Torres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-02-04','TERESA TRAS REUNION ALBERO, MIGUEL Y YO AOCORDAMOS CAMBIAR LA PENSIO Y VINCULADA A NUEVA CUENTA MIGUEL VA A HA NEGOCIAR CON LA NUERA LA HERENCIA YA QUE ES USUFRUCTUARIA EN UN 25% DE TODO CON LO CUAL NO PODEMOS NI VENDER NI ALQUILAR NI DAR DE BAJA A LOS SUMINISTROS QUEDO PENDIENTE CONFIRMAR GASTOS MENSUALES DE ALFONSA PARA VER SI PODEMOS PAGAR CON LA PENSION MAS VINCULADA QUE RECIBE DE RESIENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-02-05','TERESA Por fin conseguimos la sentencia y está enviada a caja Almendralejo, ahora que les valga, aún no he tenido contestación por su parte. La autorización para sacar los 100 € ya está enviado pero ya había sacado toda la pensión así que este mes nada podemos hacer. Voy a hacer cambio de la prestación por desempleo que se supone que cobra lo antes posible a una nueva cuenta que le hemos abierto en Liberbank y ahí ya controlaremos gastos, esperamos a Marzo a ver qué pasa….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-02-05','Ana: Soraya Masa acude a la CTAEX comunicando que Ana Mª está abajo totalmenet fuera de sí y delirante. *Consulta ella el seguimiento en Salud Mental, y confirma que no acude a consulta desde 2017. *Consideramos que es necesario activar el 112 para que puedan valorarla en Psiquiatría. ················· *Activo el 112 (924 38 76 69). Me confirman que acudirá la ambulancia con el soporte sanitario. ···························································· ························································································································· ······· Más tarde llamo al hospital numerosas veces; centralita: 924 38 10 00, UHB: 924 38 10 42 / 924 38 10 49 / 924 38 10 43. **En UHB no saben nada. En Urgencias dice que no han llevado a nadie con estos datos. ······································· Llamo de nuevo al 112 y me informan que una vez atendida y valorada por la médica, se ha marchado. Está delirante y Doctora ha solicitado TRASLADO PSIQUIÁTRICO. Pero *Según la policía, ella misma, Ana Mª, ha llamado para decir que no fueran porque ella se iba de allí.... y así lo ha hecho. * Desde el 112 han dado la descripción a la policía y le han dicho que si la ven o alguien les avisa, que vayan a buscala y se vuelva a activar el 112, que enviarán de nuevo la unidad... ························································································································································································ Me avisa Teresa, TS CTAEX, tiene al teléfono a Ana María (635 608 658), que va en un taxi camino de su casa. ··············· Lo comunico al 112, pero me dicen que mientras nadie pueda corroborar este información no pueden enviar la ambulancia. *No obstante lo comunicarán a los cuerpos y fuerzas de seguridad, cree que al ser Proserpina corresponede a la Guardia Civil. *Pero no sabe si ésta podrá movilizarse hasta allí si no hay seguridad de que esté en su casa, pues también tienen recursos limitados... ·············································································································································· Llamo a Ana Mª, al nº desde el que ha llamado a Tere: 635 608 658. Pero salta el buzón de voz cada vez que lo intento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2021-02-05','TERESA EL CENTRO NOS SOLICITA QUE TRAMITEMOS PF YA QUE COBRA ORFANDAD, LE NIEGO PEDIRLO YA QUE TIENE MUCHO DINERO AHORRADO Y PROPIEDADES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-02-08','Ana: Correo de Noelia, TS C.R. Cervantes (noelia.garciac@salud-juntaex.es): "Hola! Me acaba de comunicar la doctora que el día 15 Eugenia Pacheco Vicente tiene cita en el Hospital Universitario. Para acudir a la cita tiene que ir y venir en taxi. El próximo día 9 viene Gloria para acompañarla al banco. Pero Eugenia sólo puede sacar 15 € para sus gastos Cómo se ha de proceder para el abono de dinero para el pago de los taxis? Este es el caso también de Mª Luisa y de Guillermo cuando tenga que acudir a citas hospitalarias. Saludos" ························································································································································································ Mi respuesta: "Buenos días Noelia, En relación al abono del taxi suele hacerse mediante transferencia bancaria, el/la taxista tendrá que emitir factura a nombre de la persona en cuestión especificando el nº de cuenta en que haya hacérsela. Esta factura ha de enviarse (bien por el propio taxista, bien a través tuya) a la atención de la sección económica a la otra dirección de correo: ctutelar@salud-juntaex.es "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='FERNANDEZ'and apellido2='VILLANUEVA'),'2021-02-05','Ana: Correos de Estrella Durán, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenas de nuevo, Ana. Hoy no está mi compañera Emilia que es la Trabajadora Social del Psicogeriátrico, así que te escribo yo, para informaros de que hemos tenido un brote de covid en dicha unidad y hay pacientes tuteladas por vosotros, son las siguientes: .- Antonia Ayuso Tena .- Juana Fernández Villanueva .- Andrea Recio García Saludos. Buen finde" ···· "Se me olvidó decirte, que están las tres bien y que el domingo se pusieron la segunda dosis de la vacuna."','2');
