insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-02-08','Ana: Hablo con Belén, secc. ecc. CTAEX, comunico que Julián está ya el 1º en lista de espera del SAD del Ayto. Por lo que es necesrio que se haga la limpieza en el domicilio lo antes posible. *Volverá a hablar con la empresa de limpieza, quedaron en avisar con nueva cita pero no han contactado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-02-08','Ana: Recibimos escrito de la Delegación Territorial de Málaga, de la Consejería de Pª Sociales, Certificado Negativo de Pensiones de Costi Alexandru. Como ya sabíamos, no percibe ni ayuda FAS, ni LISMI ni PNC.','2');
