insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-02-08','miguel, llega citación del juzgado para el 8-3-21. Me comentan desde el juzgado que en próximos días nos llegará el resto de documentación del juzgado (informe de fiscal, etc). Remito email informando de la citación al abogado Jesús Buenos y a Angel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEVERIANO'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2021-02-08','Ana: Pido a Julio, que remita por correo certificado el escrito comunicando cambio de tutor al INSS, ya registrado de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-08','miguel, llamo al juzgado nº1 de Plasencia en relación al procedimeitno LEV JUICIIO SOBRE DELITOS LEVES 123/90, en relación a la citación del día 16-2-20. Me confirman que ya les ha contestado el SCACE con la comunicación de que hay videoconferencia, Vicho acudirá al juzgado de Plasencia y Romero Mediavilla por videoconferencia desde Cáceres. Tras hablar con Miguel del Juzgado de Mérida (SCACE) me confirma que el martes de carnaval es fiesta también para ellos y por tanto no habrá nada abierto. Hablo con la del juzgado nº1 Plasencia, e insiste que no cree que el juicio se suspenda y en todo caso mañana llamará a Angel (tras hablar con el juez) para confirmarnos si hay o no juicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-05','Ana: correo-e de Paula, TO, CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Hola Ana, te enviamos adjunto el informe de Alta de Guadalupe Barragán por su paso a Residencia de Mayores." Archivo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-02-08','miguel, me pide Tere: JOSE ANTONIO DELGADO RODRIGUEZ ESTA CURATELADO, HA FALLECIDO SU MADRE CON LA CUAL VIVIA, EL PADRE TAMBIÉN FALLECIO YA HACE AÑOS. EL CONTINUA VIVIENDO EN LA CASA DE SU MADREA. NOSOTRO TENEMOS QUE HACER LA HERENCIA O ALGO? PORQUE CLARO EL AHORA SE TIENE QUE HACER CARGO DE TODOS LOS GASTOS QUE TIENE LA VIVIENDA…. ES HIJO UNICO ******************************************************** La indico que para hacer la HERENCIA de los padres me remitan: necesitamos hacer la herencia para lo cual te tienen que enviar fotocopias (y cuando se vaya a firmar en notaria la herencia llevar los originales que te indico): -Certificado de defunción. -Certificado de últimas voluntades. -Testamento. -Certificado de saldo de las cuentas bancarias de los padres a fecha del fallecimiento de cada uno. -Nota simple de las fincas rústicas o urbanas que tuvieran los padres. -Si lo tuvieran, el libro de familia Por ahora que te manden eso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2020-11-19','SALIDA Salida a la naturaleza del entorno (Chorrituelo de Ovejuela).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCOS'and edp.apellido1='GARRIDO'and apellido2='PEREZ'),'2020-11-19','SALIDA Salida a la naturaleza del entorno (Chorrituelo de Ovejuela).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-02-08','Ana: correo de Mª José Polo (ssbm@trasierratierrasdegranadilla.es): "Con fecha de hoy se ha remitido al banco WI ZINK escrito comunicando que esta señora esta incapacitada, ya que nuevamente le han vuelto a mandar una tarjeta de credito, ya sabemos que ella tienen contrajo con dicho banco un prestamo que lo genero su hijo sin ser ella consciente de lo que hacia; actualmente dicha tarjeta esta custodiada en el Ayuntamiento de Zarza de Granadilla, ya que no nos gustaría que volviera a estar en manos de su hijo. Por lo que considero queseria positivo que desde dicha comision tutelar se icidiera en la incapacitacion de esta señora al banco para que no remitan nuevamente tarjetas de credito. Un saludo" ······· Se lo reenvío a Alberto, Jefe de secc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2021-02-09','Ana: Correo de ayer por la tarde de Pilar Cerrillo, TS Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "Buenos días Ana, esta mañana se ha hecho el traslado de Mateo Ruano a la Res. Amada Corral de Alcuescar. El Tel es (927)38 45 19 y el correo electrónico es a.corral@grupociudadjardin.com. Las responsables del centro son Rosana e Inocencia, aunque también puedes contactar conmigo para lo que necesites. Se lo he comunicado a su sobrino Nacho. Si necesitas algo mas me dices. Un saludo" ···················································································································································································· Contesto a Pilar y le pregunto cuál es la dirección de la nueva Res. Según la pág. web del SEPAD, hay varias fases. ···················································································································································································· Llamo a los PPTT. Amada Corral (927 38 45 19 / 601 64 49 74 llamar mejor a éste) xa hablar con Rosana (Directora " es la misma directora de la residencia de Montanchez: 699 19 81 86) o Inocencia ("Ino", la responsable en ausencia de Rosana). Dirección oficial, para envíos y demás cuetiones: C/ 3 de abril s/n. ······················ En cuanto a Mateo, el ingreso ayer fue bien, tanto la tarde como la mañana la pasó bien. ························································································································································································ En relación al correo informativo enviado a Alberto, recibo correo de Juana: "Hola, Respecto a este tema... _ He hablado con la residencia antigua para que nos pase un certificado de deuda actualizado, puesto que el que tenemos es de noviembre de 2020. _He hablado con centro nuevo para que nos mande certificado de precio actual de la plaza, cuando lo tengamos le daremos el número de cuenta para el cargo, que será en Liberbank, donde cobra la pensión actualmente. _Con respecto a los gastos personales, dice que tendrá podología, peluquería y farmacia y que lo cargarán en la cuenta para que no maneje allí dinero. Nos hará un presupuesto aproximado de los gastos mensuales una vez esté establecido allí, ya que acaba de llegar. Seguimos... Juana.-"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2021-02-09','Ana: Tras varios correos de Jesús Manuel pidiendo cambio de piso y exponiendo los supuesto problemas con la vecina y el arrendador, así como correo de la secc. ecca. informando de las posibilidades económicas. Se valora la posibilidad de cambio de piso. ···························································································································································································· Remito correo a Toni-Futuex (areasocial3@futuex.es): "Buenos días Toni, A la vista de tantos problemas de Jesús Manuel Ramos Bargon en la vivienda actual, al menos todo lo que manifiesta él tanto por teléfono como por correo electrónico, estamos valorando la posibilidad de que cambie de piso de alquiler. Sabemos que la búsqueda anterior no fue fácil pero queremos pediros colaboración en la búsqueda de nuevo piso de alquiler, al menos intentarlo. La sección económica me comunica que lo siguiente: “Cobra una pensión de 683,50 € más 200 € que mensualmente le transfiere su madre, paga 250 € de alquiler, pasa tb 200 € a sus hijos, más los suministros y los extras, no podría permitirse un alquiler mayor, igual 10 € más, hasta 260 €.” Así que el límite sería justo ese, 260€. En el caso de no encontrar nada adecuado a ese precio (sinceramente, no sé cómo están los alquileres a día de hoy en Cáceres capital), se podría valorar y tratar con él la posibilidad de hacer una limpieza en la vivienda actual, y en este caso agradecería que lo trataseis con él y pidieseis presupuestos para remitir a la sección económica. Ante cualquier cuestión, hablamos. Un saludo y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-12-17','En relación con el borrador del contrato de alquiler de José María, en la vivienda sita en C/. Laurel, 15, bajo derecha, de Zafra, envío correo electrónico a la inmobiliaria zafra@alfazafra.com, para que modifiquen algunos puntos del mismo, una vez que le solicité los datos a Toni, de Futuex, que fue quien nos envío el borrador inicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-02-09','Ana: Correo de María Glez. Barroso, TS de ASPACE (maria.gonzalez@aspacecaceres.es): "Buenos días, Mi compañero, el coordinador de Residencia me pasa el siguiente presupuesto para adquirir ropa para Santiago Eduardo. 4 Sudaderas= 24€ 4 Polar con cremallera= 32€ 3 Jersey=17,97€ 4 Camisetas de manga larga= 18€ 3 camisetas básicas= 6€ Total presupuestado= 97,97€ Dado que Santiago Eduardo destroza la ropa (se la come), me preguntan si es posible asignar un presupuesto mensual, o trimestral directo a adquisición de ropa, o si es mejor hacer el presupuesto para más largo plazo (por ejemplo en lugar de mensual, hacer una compra grande para 6 meses). Quedamos a la espera de aprobación del presupuesto actual y la valoración por su parte de la forma más ágil de proceder en el caso anteriormente comentado. Un saludo" ··········· Aunque también lo han remitido al ctuelar@ lo reenvío a Alberto, Jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2021-02-07','EXITUS El 07/02/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-02-09','Ana: María Glez. Palomo, TS Autismo Sur, me remite otro documento para la firma del D.Gerente. ·············· Subo el "Consentimiento Telemático de Ingresos" de la Junta de Andalucía para la firma digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-09','Ana: Envío correo a Alberto, jefe secc. ecca., con copia a Toni-Futuex: "Buenos días Alberto, En relación a José Manuel Romero Mediavilla, ¿hasta cuándo estipulaste que debía continuar con 20€ de asignación semanal? Dime cuándo se le podrá volver a aumentar. Y de momento, ¿sería posible darle puntualmente algo más de dinero para productos de higiene personal? Su hermano me informa que necesita comprar productos de higiene personal: papel higiénico, jabón, espuma de afeitar… ya sé que en teoría debería comprarlo con la asignación semanal, pero viendo sus prioridades, no le da… Se me ocurre que para asegurarnos que lo invierte en estos productos y no en otra cosa, podrían acompañarle desde Futuex tanto a la retirada del “extra” como a al compra y remitirnos el comprobante de compra. Pongo en copia a Toni, a ver qué os parece. Seguimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-01-12','En relación con el borrador del contrato de alquiler de José María, vuelvo a contactar con la Inmobiliria Alfa, de Zafra (924 55 19 38), para preguntarles si han visto las modificaciones que les indiqué para incluir en el contrato de alquiler. Me dicen que no y que lo miran y me dicen. No he obtenido respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2021-02-09','En relación con los procedimientos de diviión de herencia 19/20 y 20/20, seguidos en el Juzgado de Primera Instancia e Instrucción, nº 1, de Logrosán, acudimos el 5/2/21, a videoconferencia en los Juzgados de Mérida, a la formación de inventario de ambas herencias. Hay acuerdo con el activo, pero no con el pasivo. Así que se pospone la resolución a la celebración de Juicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-02-09','Ana: Llamo de Sandra, TS Residencia de mayores de Coria (927 508 000 - Ayto. de Coria - Ext. de la Residencia - Sandra, TS: 283), me comunica que ha conseguido el Certificado Literal de Nacimiento a través de la hija. Nació en Villamiel. Me lo remitirá al correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-02-09','En relación con el contrato de alquiler de José María, vuelvo a hablar por teléfono con la inmobiliaria (924551938), para recordarles las modificaciones a introducir en el borrador del contrato. Lo mira y me dicen algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2021-02-09','Ana: Tras conversación con Sandra, TS del Patronato Residencia de Coria, remito correo a Ángel y Miguel, Asesores Jurídicos CTAEX: "... En relación a Rogelio Fdez. Vega, me comunica la TS del Patronato Residencia de Coria, que tiene caducado el DNI (hay que renovárselo, de hecho lo necesitan también las compis de la secc. Ecca. para tema banco). ¿Podríais por favor preparar una autorización para que ella acompañe a Rogelio en nombre de la CTAEX para la renovación? Si se firma digitalmente casi mejor, para que tenga validez sin necesidad de enviar el original en papel. Sus datos son: ALEXANDRA ALFONOS MAESTRE. DNI: 76032974B. Habría que remitírselo a la siguiente dirección: sandraalfon@hotmail.com ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-02-02','Ana: Corre-e de Eloy Piélago, TS de Madroñera: "Buenos días, Don Rafael Garcia Casares, sigue en su domicilio en Madroñera. Segun el SEPAD con plaza publica para ingreso en Residencia, es perera que alguna administración decrete una PCR para su ingreso involuntario en dicha residencia de Mayores." Atentamente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-02-08','Ana: Hablo con Mai, Jefe de Secc. de Mayores, me indica que en este caso, el propio TS del SSB, Eloy, puede acudir al C. Salud y activar el protocolo establecido para que acuda persona sanitario a realizar la PCR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-02-09','Ana: Remito correo a Eloy Piélago, TS del SSASB de Madroñera (ssb079@gmail.com): "Buenos días Eloy, Espero que, a pesar de las circunstancias actuales, estés bien. Informarte que ayer hablé con la Jefa de Sección de acceso a recursos de mayores, al respecto de la PCR pendiente de Rafael. Ésta me manifestó, que tal y como han hecho en otros casos similares (casos en que la Ctaex no tiene la tutela), es el propio Trabajador/a Social del Centro de Salud correspondiente quién debe activar un protocolo que hay establecido para que acuda personal sanitario al domicilio para realizar la PCR, y en su defecto (si éste/a no ha intervenido en el caso) el TS del SSB, es quién tiene que acudir al Centro de Salud a exponer la situación y solicitar que se active dicho protocolo para que una vez se tenga el resultado se pueda proceder al ingreso involuntario. Ante cualquier otra cuestión no dudes en contactar. Un saludo." ·························································································································································································· Respuesta de Eloy, TS: "Buenos días, está aún en el domicilio. Está todo muy parado, en teoría a prueba de una PCR, para que pueda ingresar en una residencia de Mayores. El SEPAD tiene reconocida plaza en espera de saber si se hace la prueba del codid. Ha estado una Educadora, Gloria la semana pasada y estuvo en la puerta de su casa para hablar con Rafael. Es reacio a ingreso en residencia por decir que no lo ve necesario, sino para el dia de mañana. Gloria quedó en volver esta semana o la que viene. Atentamente.." ························································································································································································ Mi respuesta: "Hola de nuevo, Sí, yo he propuesto las visitas de Gloria, del programa de apoyo que hay firmado. Pero insisto, para el internamiento involuntario puedes activar el protocolo para que acuda personal sanitario a realizar la PCR, al igual que llegado el momento de ingresar (una vez se tenga el resultado, no más de 24 horas después a ser posible) se activaría el 112 para dicho ingreso involuntario. Tú mismo lo puedes activar llamando al médico de sala para organizarlo. Cuentas con la documentación necesaria (Autorización de Ingreso del Juzgado) y la resolución de la plaza, supongo. Por experiencia te digo que suele ser bueno que estés presente como trabajador social de referencia. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2021-02-09','TERESA ARCHIVO CONSENTIMIETNO INFORMADO FRACTURA FEMUR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2021-02-09','TERESA ENVIO OPCION PNC QUEDA PENDIETNE ALTA A TERCEROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-09','Ana: Llamada a José Manuel, continúa con los pitidos y con malestar, dice que está descentrado. Le indico que tiene que hablar de todo ésto con la Psiquiatra. ···· También neceita mascarillas, ropa interior y un abrigo/cazadora. ··············· En cuanto al CEDEX, han acordado en llamarle esta semana. ············ También está pendiente de que le llamen del programa de voluntariado de Cruz Roja, para hacer alguna actividad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-09','En relación con el anuncio de una vivienda de alquiler en Cáceres, que se cree que es de Clementa y en el que no hemos intervenido, hablo con la inmobiliaria (Jesús 927042834) y me indica que ya se ha alquilado. Se trata de la vivienda en la que Clementa dispone del 50% de propiedad. Ha intervenido la hija de Clementa, Pilar (638530172), que dispone del otro 50%. Me dice que no sabía que su hija estab sometida al régimen de Administración de Bienes por nuestra parte. El número de cuenta donde se empezará, a partir de marzo de 2021, el alquiler, es la cuenta de Clementa, de Liberbank. Vamos a realizar un anexo al contrato de alquiler, donde también aparezca como arrendadora, Clementa. La renta es íntegra para Clementa, porque la vivienda está hipotecada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2021-02-09','En relación con la pensión que abona a sus dos hijos por 781,32€/mes y tras recibir documentación que nos ha facilitado su sobrino, Nacho Ruano, os indico. Esta pensión la está pasando, porque fue condenado, el 18/3/2002, por un delito de asesinato al quitarle la vida a la que fuera su mujer y madre de sus dos hijos. Se fijó una condena de 12 años de cárcel y una indemnización de 60.000 euros para sus dos hijos. Al mismo tiempo, se condenó al Estado (180.000 de principal + 10.391,25 de intereses), como responsable civil subsidiario, toda vez que hizo caso omiso a las advertencias del propio Mateo, antes de estar incapacitado, en relación con su salud mental. Al mismo tiempo, se dictó un Auto el 31/3/03, por el que se declaraba a Mateo insolvente (este auto no lo tenemos). Uno de los hijos falleció y el otro trabaja.------------------------ He pedido datos económicos al área económica, a los efectos de solicitarle abogado de oficio que pueda iniciar el procedimiento de modificación de medidas para dejar sin efecto esta pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-02-09','NOTA INTERIOR. Se remite por correo interno a la sección de discapacidad (A/A de Maribel Ramos) solicitud de elección de centros solicitando toda Extremadura y se archiva copia en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2021-02-09','Ana: Llamada de Maribel, TS Res. Parque del Príncipe: Ayer, día 8, falleció Rafael. Ya han getionado todo. *Enviarán por email y despues originales en papel, el cdo. de defunción y la factura de la funeraria A/A. de las secc. ecca. al ctutelar@. ···· *Maribel dará de baja la pensión y la tarjeta sanitaria del SES. *La plaza T3, ya la ha dado de baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-02-09','Ana: envío correo-e a Toni-Futuex para derivar a Ana María al programa: "...Procedo a hacerte derivación de un nuevo expte. Llevo casi 2 semanas con intención de hacerlo la verdad, pero entre cosa y cosa… hasta ahora nada. Se trata de Ana María Rosco Ávalos, es un cargo aceptado a finales de años. Reside en Mérida, en la Urbanización Balcón de Proserpina. Domicilio: C/ Aries, nº 8. Aunque a priori, es zona de Amalia, el Plan de Intervención Inicial lo voy a hacer yo, de ahí la derivación. Del seguimiento posterior se hará cargo Amalia. Tiene 51 años. NO tienen grado de discapacidad reconocido. En cuanto a Dependencia, me acaban de corroborar que tampoco se le ha solicitado nunca dicha valoración. Sabemos que es paciente de salud mental, pero no acude a consulta desde 2017. Esto habrá que trabajarlo con ella, pues es necesario que se le valore y haga seguimiento. Aunque tienen familia en Mérida, madre y hermano que conozcamos, no tiene relación con ninguno de sus miembros. A día de hoy percibe la Renta Garantizada Extremeña (537, 84 € x 12 pagas). Si consigo resolver otras cuestiones con el INSS, ya os informaré. *En este mes concreto se le ha autorizado para sacarlo todo cualquier día. No sé si habrá ido a sacarlo, las veces que he intentado contactar el teléfono estaba apagado. Su teléfono actual de contacto: 635 608 658. Y éste es otro que nos constaba de ella: 616 729 463. A ver si tenéis suerte. *Necesitamos también un “presupuesto de gastos” para limitar la cuenta y realizar autorizaciones periódicas. ..." ····················································································································································································· Llamo a Control de Pensiones del INSS - BA (924 21 61 90). Me informan de que Ana Mª percibía una Pensión de Incapacidad (1160 €) que causó baja el 14/03/19 con fecha de efectos: 08/03/19. *En el extpe. consta baja por "mejoría". En el caso de querer volver a revisarla, supone que habría que solcitarlo y que volviera a pasar por tribunal médico. **Me facilita el contacto de Carmen Curado, Jefa de Secc. de Reclamaciones (924 21 62 22)- La llamo: Efectivamente consta "mejoría de las lesiones". Realizó reclamación en junio de 2019. Es un expte. muy amplio. Han tenido dificultades para contactar con ella, debido a los múltiples cambios de domicilio y teléfono. +Ya han pasado todos los plazos. No obstante, podemos realizar por escrito una "Petición de Resolución de Reclamación Previa", adjuntando la aceptación del cargo de Tutor. A posteriori habrá de presentarse en el plazo de 30 días, ante el Jdo. de los Social para presentar la demanda (me indica que podría ir un abogado).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-02-10','Ana: Me envían del CAM Fco. Pizarro por mail, la carta de revalorización de la PFHC para 2021: 399,20 €. ···· Archivo en el expte. digital y lo imprimo para los archivadores corespondiente, para futuras rendiciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-02-09','Ana: Correo de Juana, CTAEX: "Hola, Han llamado a Coral desde el Centro Penitenciario donde está Antonio Hidalgo Romo, para comentarnos que sale de prisión ya. Voy a anular la cuenta peculio para que no se pase dinero en el mes de marzo y espero nuevas instrucciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-02-10','TERESA ENVIO CAMBIO DE CUENTA AL SEPE YA DEPENDENCIA YA QUE ANTE LA PROBLEMATICA CON CAJALAMENDRAELJO SE HA ABIERTO CUENTA EN LIBERBANK','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-02-10','Ana: Conversación telefónica con Eloy, TS de Madroñera (927 319 192 /662 54 55 10). Acudirá al C. Salud para hablar con la compañera TS para la activación del protocolo para la realización de la PCR previa al internamiento involuntario decretado como medida cautelar. *Llevará el Auto y algún documento relativo a la asignación de plaza en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-02-10','miguel, me llama Belan Prieto Ts (0824903047) que ha tramitado todo y conoce la situación de la herencia de la tutelada.(también refiere a la Directora Marisa y a la Ts del centro de Siruela donde reside la tutelada Lola Bernal. Me comenta que el viernes traeran documentación (ya veré qué es servible y no) y se la dará Marisa la directora a Tere. La comento que mis pasos serán: -Pedir de nuevo la nota simple al registro de la propiedad de Madrid por nº de finca que viene en el documento de liquidación del IS que ha mandado la abogada de la nuera. -Hablar con la abogada a ver cuál es su posición y conocer el caso -Recabar la cdocumentación que traigan el viernes a Tere -Llamar la semana que viene a Belen Prieto Ts e informarla de si podemos poner ya en marcha la operación, consistente en preparar la escritura de herencia, y liquidación de IS, junto con busqueda de abogado de pago (no tiene derecho a uno de oficio), para que pida la aceptación judicial de la herencia, firma notarial de la misma, aprobación judicial posterior de la herencia, y posible venta posterior de los bienes o al menos llegar a un acuerdo con la nuera para resolver (comprarle el usufructo o al menos llegar a un acuerdo para el mantenimiento de los gastos)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-02-10','miguel, remito a Tere el siguiente email: Tere acabo de hablar por teléfono con Belén Ts que sabe de este asunto quién me ha confirmado que el viernes te traen documentación, que ya veré… Ya le he dicho que pediré de nuevo la nota simple al Registro de la propiedad, porque ha debido de haber un error puesto que en la documentación que te remitieron aparece en la liquidación del impuesto de sucesiones presentada por la abogada de la nuera figura un nº de finca registral de la vivienda de Madrid. Para tu conocimiento me confirma que ha dado de baja la luz de la casa de Talarrubias, todos los teléfonos fijo y móviles incluido los de los hijos, y sólo está dada de alta el agua de Talarrubias. Dice que Alfonsa lo paga todo que podemos verlo en los movimientos, creo me ha dicho del Bbva… Muy importante que avises a la parte económica para que no le hagan seguro de muertos porque ya lo tiene. Si miras la documentación que te remitieron e imprimistes tienes la póliza de Almudena Seguros (tlno 901242526) y nº de póliza 126505 (que no incluye lápida). Mira la intranet que lo he apuntado todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2021-02-10','miguel, envío email a Juana: sabes algo de si finalmente se llegará a un acuerdo para el reparto de la herencia de los padres de este curatelado? *************************************************** Contestación: Pues quedé con él en que su mujer iba a hablar con una amiga que tiene una inmobiliaria para que le oriente acerca de los precios en los que se mueve tanto el chalé de la Dehesilla como el local. Ahí estamos para saber si se puede aceptar el acuerdo que le ha propuesto su hermana.....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-02-08','miguel, remitido al Jzdo nº4 de Plasencia Solicitud de Internamiento Involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-02-08','miguel, remitido al Jzdo nº1 de Valencia de Alcantara Comunicación, junto a las siguientes peticiones: 1.-que no tengamos que proceder a la obra de reforma 2.-que nos permitan trasladar a la tutelada a un piso de alquiler 3.-que el nieto no pueda impedir el paso a la vivienda cuando la Ctaex lo solicite 4.-Caso que el tribunal deniegue las peticiones anteriores, soliciten al colegio de abogados uno de oficio para entablar procedimiento de jurisdicción voluntaria por gastos extraordinarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-10','Ana: Llamada de Damián (622 834 876): el contrato de alquiler del piso con el inquilino actual finaliza el 1/08/2021. Una vez finalizado quiere volver a alquilarlo. ···· Quiere hablar con Miguel, Asesor Jurídico al respecto. Se lo diré. ···· En cuanto la solicitud de valoración de dependencia, insiste en que hable con Ana Benabente en relación a los nuevo informes de psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALVES'and apellido2='MATEUS'),'2021-02-10','Ana: Envío correo a Rosa, Admvo. CSS-Plas: "Hola de nuevo Rosa, Aquí tienes escaneado el Consentimiento Informado para Administración de Contraste Endovenoso, relativo a José Alves Mateus, debidamente firmado y sellado por el representante legal. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-10','Ana: Correo de Paula, TS CRR-Plas. al ctutelar@: "Buenos días, os comunico que el lunes día 8 de Febrero ingresó en el CRR Francisco Cacho Garrido. Su estancia en el CRR está pensada con carácter temporal, pues está derivado a piso supervisado de Mérida, en espera de que pueda incorporarse a esta plaza. En las próximas semanas hablaremos del presupuesto mensual mientras esté en el CRR. Nos han remitido de sociosanitario copia de una sentencia en la que se nos informa de que está en cumplimiento de una medida legal hasta mediados de Marzo. Si creéis oportuno facilitarnos alguna otra información que pueda beneficiar a Francisco para su intervención, no dudéis en hacerlo. Un saludo Paula." ··········· Reenvío correo a Alberto, Miguel, Ángel, Julio y Juan Pedro, CTAEX, con las siguiente aclaraciones: "... Os reenvío este correo a varios destinatarios por la parte que toca a cada uno, jeje. - Julio y Juan Pedro: sólo para que sepáis este nuevo cambio y hagáis las modificaciones oportunas. Pasa temporalmente al CRR de Plasencia. De momento sigue siendo mío. - Alberto: como indican se pondrán en contacto con la sección económica en relación al presupuesto mensual de gastos. Como sabes, en el CRR no abonan la plaza. - Miguel y Ángel: en relación a la medida que está cumpliendo, ¿podéis informar a Paula al respecto? Yo por mi parte hablaré con el recurso en relación a otras cuestiones. ..." ························································································································································································· Ángel nos remite el siguiente correo: "Efectivamente, a Francisco se le impuso medida de 2 años de libertad vigilada, con sumisión a tratamiento ambulatorio, en la modalidad de hospitalización parcial o la que determine el SES, en vista de la evolución del tratamiento, así como la prohibición de aproximarse a Beatriz Pascual Montero (terapeuta de Proyecto Hombre en Plasencia, lugar en el que estuvo ingresado Francisco), a su domicilio, lugar de trabajo, no menos de 150 metros y prohibición de comunicarse con ella, por cualquier medio, oral o escrito, o con persona interpuesta , por plazo de 4 años (en sentencia dictada por el Juzgado de lo Penal 1, de Plasencia (Procedimiento 556/2017), el 18 de marzo de 2019." ····· Y envía un correo a Paula, TO del CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-10','respuesta de la parte Jurídica: Efectivamente, a Francisco se le impuso medida de 2 años de libertad vigilada, con sumisión a tratamiento ambulatorio, en la modalidad de hospitalización parcial o la que determine el SES, en vista de la evolución del tratamiento, así como la prohibición de aproximarse a Beatriz Pascual Montero (terapeuta de Proyecto Hombre en Plasencia, lugar en el que estuvo ingresado Francisco), a su domicilio, lugar de trabajo, no menos de 150 metros y prohibición de comunicarse con ella, por cualquier medio, oral o escrito, o con persona interpuesta , por plazo de 4 años (en sentencia dictada por el Juzgado de lo Penal 1, de Plasencia (Procedimiento 556/2017), el 18 de marzo de 2019','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2021-02-10','Ana: Envío correo-e a Alberto, Jefe de Secc CTAEX: "Hola Alberto, Me ha llamado Juan Luis Rubio, Secretario de Madrigalejo, al parecer hay algún problema con la entidad bancaria (UNICAJA), por el que no se está pasando el cobro de la plaza de Ana Priscila Saquero Sánchez. Según me dice les requieren en el banco alguna autorización para aplicar la actualización del abono de la plaza. Si necesitaseis hablar con Juan Luis, podéis poneros en contacto a través de esta dirección que me facilita: secretario@madrigalejo.es" ···················· Alberto pide a Belén, CTAEX, que se encargue. ················· Nº desde el que llama Juan Luis, Secretario: 672 614 666','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-10','Ana: Correo de Icíar: "Buenos días Ana, Tal y como me indica Alberto en su correo, te comento según su ficha José Manuel estará recibiendo lo 20 €/semana hasta el 23/5/2022, de hecho, esta fecha ya se la he comentado yo a él en repetidas ocasiones. Como Alberto da el OK a los gastos de higiene, necesitamos saber cuál será la cantidad que necesita retirar para hacerle la autorización, y el día, más menos, que puede pasarse con Futuex por la oficina de Liberbank." ················································································································································································································································· Envío correo a Toni-Futuex: "En relación al último correo que os remití a Alberto y a ti relativo a José Manuel Romero Mediavilla y la necesidad de comprar una serie de productos de higiene (incluidas mascarillas quirúrgicas, que no indiqué en el anterior correo pues no me lo dijo), a Alberto le parece bien. Por tanto, necesitaríamos saber qué compañera le podrá acompañarle (para facilitar datos al banco) y un presupuesto aproximado de gastos. Qué valoren con él los artículos. Así mismo agradecería que valoren si necesita realmente alguna otra cosa. Aprovecho para comunicaros que continúa a la espera para ingresar en el CRR de Badajoz. Está el 2º en la lista de espera, si bien me informaron que posiblemente él sea el próximo en acceder, pues la persona que está por delante tiene abierta la solicitud a toda Extremadura. A ver qué pasa. Por cierto, he intentado contactar con el CEDEX, en relación al tratamiento para reducción de consumo de tabaco, pero no me quieren facilitar información ni atender por teléfono. Por lo pronto voy a contactar con ellos por fax, si hay alguna novedad te informaré. Confírmame cuando puedas lo del acompañamiento y compra para decirle a Icíar." ························································································································································································································································· Tras intercambiar algunos correos más con Toni y Alberto, finalmente se aprueba la retirada del extra del 15 - 19 de febrero, le acomapañará Inés María, Educadora nueva de Futuex en sustitución de Virginia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='VIREL'and apellido2='GALEA'),'2021-02-10','TERESA REVIO INVENTARIO , ESTA EN LOS PISOS TUTELADOS DE ALCONCHEL TIENE 95 AÑOS Y SUFRA ALZHEIMER COBREA PENSION SOVI 437€ DE LOS CUALES APORTA AL PISO 332. EN GASTOS DE BOLSILLO SE LE ASIGNAN 50 EUROS TIENE UN SALDO DE 14458 EUROS EN IBERCAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-10','Ana: remito fax solicitando información a la Dra. María Victoria Boticario - CEDEX 927 22 02 03)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-10','miguel, en relación al alquiler de la vivienda del curatelado y teniendo en cuenta la imposibilidad de contactar con el Ayto de Málaga y por tanto de que nos faciliten información y documentación de las condiciones de dicho alquiler a efectos de intentar comprobar el incumplimiento del mismo...Y teniendo en cuenta que Ana Ts me facilitó el teléfono de una prima que se ofreció a ayudarnos (Alicia 635525519), la he llamado en el día de hoy para explicarle que si bien el curatelado nos remitió mucha documentación vía wasap, incluso físicamente, dicha documentación no estaba relacionada prácticamente con el alquiler y por tanto ni acreditaba el contrato completo, ni los pagos a realizar, ni los realizados, por lo que hablando con Alicia me comenta que a ella Damian le ha mandado mucha documentación (porque quiere que asuma la curatela). Quedamos en que ella va a intentar hacerse con toda la documentación posible con el ayuntamiento para intentar aclarar qué se ha pagado y qué no a efectos de reclamar al inquilino (si es necesario buscaremos un abogado para interponer un procedimiento de desahucio por impago) Me comenta que el alquiler termina en Agosto y Damian quería que se lo comunicaramos al inquilino. Le explico no es necesario porque la copia de dicho contrato debe tenerla el inquilino y que para entonces seguramente ya hayamos planteado el desahucio del mismo. Parece ser que el inquilino llama a Damian para ofrecerle comprar la vivienda. Su prima duda de sus intenciones. *********************************************************** La remito un email a efectos de que aquí en adelante nos comuniquemos por esta vía (aliciaasimas@gmail.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-10','miguel, comenta la parte económica que quieren desbloquear la cuenta de los 147.000€ y trasladarla a otra cuenta. Les comento que no pueden hasta que se resuelva el procedimiento judicial donde los 2 hermanastros solicitan su parte. Quedamos en que la semana que viene yo llame a Carlos Jurado Lena que es el abogado de la otra parte para que me acredite que son los hijos. Una vez eso ya veríamos cuándo y cómo se podrá desbloquear esa cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-02-10','Ana: correo que envía TS del Penitenciario de CC a Coral: "Adjunto remito solicitud del interno de este Centro Penitenciario Antonio Hidalgo Romo, tutelado por esa Comisión Tutelar de Adultos. Tiene prevista la libertad definitiva para el 25 de los corrientes y tiene previsto ir a vivir a C/Cristóbal Colón, nº 27 de Alcuescar (Cáceres), donde tiene vivienda en propiedad, que según manifiesta se encuentra en buenas condiciones de habitabilidad porque se la ha atendido un vecino y amigo. Durante su permanencia en este Centro Penitenciario no ha recibido visitas. Cuenta con dinero en su peculio para la salida en libertad. Se le ha informado en reiteradas ocasiones que el retorno al pueblo puede suponer un riesgo de reincidencia, ya que la orden de alejamiento de su hermano José Antonio no se extingue hasta el 3-03-21, pero no ha aceptado otra alternativa y en todo momento se ha mantenido en la idea de retornar a su casa, alegando que se mantendrá alejado del hermano y no quebrantará la orden de alejamiento. Tras el cumplimiento de la condena de prisión tiene una Libertad Vigilada y entiendo que le informarán desde el Juzgado sobre los términos y condiciones de la misma. Durante la estancia en prisión ha estado en el Departamento de Enfermería. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-02-11','Ana: Correo de Estrella, TS CSS-Plas. el día 9: "Buenos días, Ana. Paso a explicarte la situación de Juan Carlos: Como sabes estoy esperando que el SEPAD haga una serie de trámites para hacerle el PIA, pero según contestación de Soraya Masa, intuyo que su estancia aquí va para meses, ya que debe verlo también el Cadex para ver si tiene perfil RAE o RAL, y luego buscarle centro adecuado....que con los antecedentes de Juan Carlos creo que va a ser difícil que nos lo acepten en ninguno.... Ahora mismo lo ha estado viendo Maripaz, Psicóloga de la unidad y le ha manifestado su deseo de hablar con Pedro, al decirle ésta que no podía ser, ha interpretado que se le está engañando y se ha alterado mucho, teniendo que intervenir seguridad.... Maripaz solicita podáis hablar o tú o Pedro, unos minutos a la semana con él, ya que él ve como sus compañeros o bien hablan con su familia, o con sus respectivos centros.... ya me dirás, Ana..." ······························································································································································································ Mi respuesta: "Buenos días Estrella, Entiendo la situación y vuestra postura y planteamiento, pero Pedro se ha dado de baja, no sé por cuánto tiempo… yo, como sabes, no tengo inconveniente en hablar con él, pero como bien me dijo Pedro en su día, no podemos comprometernos y generar expectativas a las personas que tenemos a nuestro cargo con algo que no siempre se puede cumplir, no damos abasto, recordad que es una tutela administrativa y cada vez tenemos más expedientes (en torno a 200 cargos cada T.S.) y muchas gestiones y coordinaciones diarias… No obstante, podemos probar cada 10 - 15 días como dijimos anteriormente mientras siga ahí. Y tendría que hablar conmigo de momento, claro. Pedro que decida una vez se haya incorporado. Nos vamos coordinando para las llamadas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-02-11','Ana: Correo de Carmen, TS Ayto. Coria: "buenos días Ana, Emilia tiene corte de luz inminente, por favor llamame para ver como podemos agilizar tema pensión y pago de deudas. gracias un saludo." .... Se lo reenvío a Alberto, Jefe Secc. Ecca. ························································································································································································· Llamo a Carmen (927 50 80 00, Ext. 318 ): Será necesario domiciliar de nuevo los distintos recibos de suministros de la vivienda. *La pensión aún, aunque están pedido al INSS, no está reactivada. Mientras no le ingresen la pensión y los atrasos no se podrá hacer los abonos pendientes. *Carmen intentará hablar con Iberdrola para intentar mediar para que no le corten el suministro todavía. *Enviará las facturas al ctutelar a la A/A de la secc. ecca. ·············· Yo llamaré a Control de Pensiones del INSS, para preguntar si lo han recibido e intentar agilizar. ································ Llamo a Miguel, Jefe Secc. Control de pensiones - CC (927 62 00 49), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-02-11','Ana: Correo de Estrella Durán, TS del CSS-Plas: "Hola Ana. Ayer día 10 estuvo Isabel en Servicio de Traumatología del Hospital "San Pedro de Alcántara" en Cáceres concretamente con el Dóctor José Mª Solís y le dieron a firmar un consentimiento informado para una intervención quirúrgica, como suponemos que debéis firmarlo vosotros, por eso te informo.... " ························································································································································································· Mi respuesta: "Sí, sí, el consentimiento informado debe firmarlo el representante legal. Hacédnoslo llegar por favor y os los devolvemos debidamente firmado. Agradecería nos enviaseis también el informe médico de dicha consulta. Gracias. Seguimos." ························································································································································································· Nuevo correo de Estrella: "Ana, no tenemos el consentimiento informado,el informe te lo envío adjunto." ······ Al parecer el C.I. lo firmó ella misma allí. *Llamaré al hptal.','2');
