insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2021-02-15','Ana: Pilar Cerrillo me reenvía correo de María Álvarez, TS de Alcuescar y Aldea del Cano (tsocial7@mancomunidadsierrademontanchez.es): "SEGUIMOS PENDIENTES DE LA AUTORIZACION DE LA COMISION TUTELAR PARA EL COBRO DE LA CUOTA A MATEO, NO? HE SOLICITADO LA ACTUALIZACION DE SU PENSION A SEGURIDAD SOCIAL POR TANTO QUEDARIA DE LA SIGUEITNE FORMA: PENSION 2020: 1585.00 PENSION 2021: 1599.27 PENSION 2021 - IRPF + GRATIFICACION PERMANENCIA : 1599.27 - 161.16 + 5.93 = 1444.04 € EL LIQUIDO TOTAL A PERCIBIR - PENSION ALIMENTICIA: 1444.04 - 781.32 = 662.72 € TOTAL DE PENSION QUE RECIBE MATEO AL MES POR EL 75% QUE APORTA A LA RESIDENCIA 662.72€ x 75% = 497.04 € LA CUOTA MENSUAL DE LA RESIDENCIA SERIA DE UN TOTAL DE 497.04 €/ MES" ··················· Se lo reenvío a Alberto, jefe de secc. ecca. para que realicen la autorización del abono mensual de la plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-02-15','TERESA ENVIO SOLICITUD DE ORFANDAD AL INSS BADAJOZ y cambio de pia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-02-15','Ana: Llamada de Chema, Coordinador del Piso Tutelado de Menores de Plasencia gestionado por la Entidad Cerujovi (649 676 149). Darío ingresó en su recurso en julio de 2019, procedente del C.A.M. Valcorchero - Plas. *Ya han solicitado nuevo recurso para el joven. *Nos enviarán informe de la situación actual y el resto de la documentación solicitada para el inventario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-02-15','Ana: Pido a Tere que ponga para registro de salida el oficio-solicitud de Petición de RESOLUCIÓN DE RECLAMACIÓN PREVIA que remitiré a Carmen Curado, Jefa de Secc. de Reclamaciones del INSS, dirección provincial de BA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-15','Ana: Llamo a Paula, TO CRR-Plas. (682 704 401): no obtengo respuesta. ·············· Más tarde consigo hablar con ella. *En el informe de derivación que les hicieron de Francisco indicaba que no tenía ninguna medida legal, por lo cuál se sorprendioeron mucho al enterarse de la medida de alejamiento y libertad vigilada que debe cumplir. ··· En cuanto a la cuestión monetaria, llegaron a un acuerdo el día de la entrevista por videoconferencia, pero el segundo día en el centro ya solicitaba más dinero (aún estando en el aislamiento, por protocolo en el momento del ingreso) y presentó una actitud físicamente agresiva. ··· El tabaco que le habían comprado en el CSS para llevarlo al CRR no lo llevó, al parecer lo había repartido en el CSS, suponen que "lo debería" a algúnos compañeros. ···· Hoy ya ha salido del aislamiento. Ya veremos cómo se adapta y evoluciona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-02-15','Ana: correo de Sara Pozo, TS del HUC (sara.pozo@salud-juntaex.es): "...Con respecto a Isabel Mª, intenté hablar con el doctor Solís pero no estaba, hablé con el jefe de servicio, Ángel Vega, y éste no veía otra alternativa que firmar el consentimiento delante del médico. Cada traumatólogo que coge el teléfono tiene una opinión al respecto. Al final la mejor solución creo que será que hables con Dirección médica, con el doctor Alfredo Caro (56661)." ···························································································································· Llamo al Dr. Alfredo Caro - Direccion Médica (650 75 18 58 = Busca). Se pondrá en contacto con las TS del Hptal. para gestionar a través de ellas el C.I.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-02-15','En relación con el procedimiento INTERNAMIENTO 167/2021, seguido en el Juzgado de Primera Instancia nº 6, de Badajoz, nos envían Providencia en el nos comunican el alta de Cristofer, dejando sin efecto y archivando este procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-02-15','Ana: Llamo a Manuel Vasallo, Subinspector de la Oficina del DNI de la Policía Nacional-CC (927 629 092): No obtengo respuesta. Pruebo en otro número (927 626 544): Me informan que si ha perdido la nacionalidad primero hay que hacer los trámites correspondientes en el Juzgado - Registro Civil de Coria y una vez tenga un Certificado Literal en que indique que ha recuperado la nacionaliad ya se podrá realizarse una nueva inscripción para obtener el DNI en la oficina correspondiente. *Volver a llamarles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-02-15','Te informo de un par de asuntos relativos a Natalia Megías Millón para que estéis al corriente de ellos: 1) El pasado miércoles 10 de febrero hemos acudido a una citación por parte del Médico Forense relativo a un episodio de agresividad que tuvo con una monitora el 23 de octubre del año pasado. Natalia se mostró colaboradora con EL médico y le explicó lo ocurrido con bastante claridad, tanto es así que la médico se sorprendió de la frialdad y crudeza con la que relató los hechos. 2) Por otro lado durante este fin de semana ha tenido lugar un episodio de agresividad con una compañera del Servicio de Residencia con más necesidades de apoyo. Le ha dado un golpe en el ojo y lo tiene morado. Esto ha ocurrido un par de veces durante el fin de semana. Hoy hemos tenido que recurrir por urgencias al hospital con esta usuaria para ser valorada por el médico y se ha emitido por parte del médico un Parte Judicial de Lesiones. La verdad es que la situación con ella sigue siendo tan delicada y preocupante como siempre, el grado de ansiedad que siguen presentando usuarios y profesionales es muy elevado, y los recursos que consume en el día a día son altísimos también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2021-02-15','TERESA ENVIO ALTA A TERCEROS A PNC','2');
