insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-02-17','Ana: Correo de ayer (festivo en Mérida) de Mariví Clemente, TS CSS-Plas.: "Ante la inminente fecha de cumplimiento de la medida de internamiento judicial del Paciente Dº.Juan Sanguino Lancho ,7/03/2021, me pongo en contactos con esa CTAEX,para establecer los dispositivos o recursos, que con posterioridad a esa fecha, serán los que puedan acoger al Paciente. Una vez cumplida la medida de internamiento, el Paciente saldrá de alta de este CSS. Teniendo en cuenta la edad del enfermo y la falta de red social de apoyo entendemos que los dispositivos que puedan acogerle son los destinados a personas mayores. Espero podamos poder establecer una comunicación sobre los temas del Tutelado y coordinar su salida del CSS. Muchas gracias," ···························································································································································································· Mi respuesta: "Buenos días Mariví, Revisando el expte. de Juan, veo que tiene reconocido grado I de dependencia, por lo que no podría acceder a residencia de mayores a través de la Ley de Dependencia. Otra cuestión es que valoréis que se le puede solicitar revisión por empeoramiento, en el caso de que consideréis que es más dependientes a día de hoy, y por supuesto para ello necesitaríamos informes que lo acreditasen. No obstantes, si él quiere, también se puede buscar una plaza en residencia privada, pues percibe una pensión de incapacidad permanente absoluta con la que podría costear una plaza en habitación compartida en más de una residencia privada o pública de titularidad municipal. Habría que plantearle, en este caso, a qué localidades estaría dispuesto a trasladarse. Según me vayas diciendo vemos una u otra opción y hacemos las gestiones correspondientes. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-02-17','Ana: Llamo al Registro Civil de Coria (927 50 81 69): Si en su partida de nacimiento no consta que haya perdido la nacionalidad, no la habrá perdido, por tanto no hay que iniciar el expte. de recuperación de la misma. *En el margen del Cdo. de nacimiento no hay ninguna indicación al respecto. ······················································································································································································ Tras intentar contactar sin éxito con Sandra, TS Res., le envío un correo (sandraalfon@hotmail.com): "Buenos días Sandra, Como no he podido contactar por teléfono, te envío este e-mail intentando explicar todo lo mejor posible. En relación a los trámites de DNI de Mª Rosario González Jorna, decirte que, tal y cómo me indicaron desde la oficina del DNI de la Policía Nacional, he llamado al Registro Civil de Coria y aquí me indican que “si en su partida de nacimiento no consta que haya perdido la nacionalidad, no la habrá perdido, por tanto no hay que iniciar el expediente de recuperación de la misma.” He pensado en realizar la solicitud de desplazamiento de la Unidad Móvil de la Policía para la tramitación del DNI, enviársela junto con la documentación que se indica en el modelo de la solicitud: - Certificado médico oficial acreditativo de la imposibilidad de que el interesado/a puede realizar el desplazamiento. - Una fotografía, o dos si es por extravío o sustracción. - Si es primera inscripción, o renovación con cambio de datos filiatorios, partida literal de nacimiento, expedida por el Registro Civil con una antelación máxima de 6 meses a la fecha de solicitud del DNI y con la anotación de que se ha expedido a los solos efectos de su obtención. - Si ha variado el domicilio, certificado o volante de empadronamiento, expedido con una antelación máxima de 3 meses a la fecha de la solicitud del DNI. Este documento no será necesario si el interesado autoriza al equipo expedidor para que pueda comprobar su domicilio mediante consulta al Sistema de Verificación de Datos de Residencia. Una vez que vean el expediente, se pondrán en contacto con nosotros si observan alguna cuestión que requiera subsanación y ya nos dirán si tenemos que hacer algo más. ¿Podrías solicitar tú el Certificado Médico y el Certificado de Empadronamiento (aunque este último no es obligatorio, nos puede venir bien pues constará algún número de filiación) y de la foto? *Por cierto, el Certificado Literal de Nacimiento que te ha remitido la hija está firmado en Enero de 2020, por lo que no nos valdría, no sé si habrá sido un error o si lo tenía ella de antes, pero no puede tener más de 6 meses, ¿podrías contactar de nuevo con ella y consultárselo? Si no pudiera enviarnos uno actual, dímelo para solicitarlo desde la CTAEX, aunque esto se demore un poco más. Ante cualquier cuestión, no dudes en contactar. Gracias de antemano y un saludo."','2');
