insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-02-04','Ana: Correo-e de Estrella, TS del CSS, remitido al ctuelar" y a mi correo: "Buenos días. Solicitamos nos enviéis la autorización para poder retirar dinero del paciente, en la que conste: .-Cantidad permitida. .-Número de cuenta. .-Entidad bancaria. Y hagáis la llamada telefónica a dicha entidad bancaria para que estén advertidos de que vamos a ir a retirar dinero. Juan Carlos ha pedido que se le compre una radio, se le compró una hacer unos días, pero era con pilas y se las tragó. También quiere unos cascos y un reloj de actividad.... Gracias. Saludos." ·············· *Se lo reenvío a Alberto, jefe de secc. ecca. CTAEX, dando mi conformidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-02-16','Buenos días Teresa. Con respecto a la salida a casa de Libertad, te comento que existe la posibilidad de que se vaya con una trabajadora del centro que tiene que ir este jueves dia 18 a Badajoz y dice que se puede ir con ella. Solamente serían necesarios 50 euros para que tenga para sus gastos y pueda pagarle al menos 20€ de gasolina a la trabajadora. Ya me dices si es viable que pueda retirar esos 50€ entre hoy y mañana o lo que podemos hacer puesto que creo que va a ser muy precipitado, dejarles nosotros el dinero y después cuando vuelva que nos lo devuelva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-02-17','TERESA Libertad se irá mañana con la trabajadora del centro y le adelantamos nosotros el dinero para que se lleve a casa y cuando regrese el 1 o 2 de marzo, pues ya os lo recuerdo para que le autorices la retirada del dinero','2');
