insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-02-17','Icíar me pasa contacto de un Abogado, Pedro Antonio Zarco (670665150). Al parecer está llevando reclamaciones de tarjetas Revolving, para la devolución de los intereses usurarios que le cobran a Rosa. En principio no cobra nada, sólo si hay éxito en la demanda, se quedaría un porcentaje. Son unos intereses que las entidades deben devolverte, con lo que entiendo debemos hablar con el Abogado y reclamarlos por nosotros mismos, sin su intervención, así no perdería nada de lo que ya le han cobrado.','2');
