insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2021-02-18','Ana: Tras recibir llamada de Teresa Noguera, TS de Novaforma (662 337 460), remito el siguiente correo a Ángel y Miguel, Asesores jurídicos CTAEX: "... Me ha llamado Teresa Noguera, TS de Novaforma, en relación a la herencia de Felipe Blanco. Os reenvío este correo que os envió al ctutelar@ el martes, y me pide que os reenvíe y, por favor, le deis la respuesta por escrito, pues la va a utilizar para explicárselo a Felipe. Os envío también correo referido al mismo asunto en noviembre y abril del 2020. El de noviembre, también, según dice, con copia a Miguel. Ya me vais contando. ..." ························································································································································································ Respuesta de Ángel, Asesor Jurídico CTAEX: "...Este caso ya se ha hablado en varias ocasiones con el centro. A ver, Felipe, según su sentencia de incapacitación, padece: “Inclinación por la prodigalidad, con fugas del domicilio con cuantiosas cantidades de dinero, de una cuenta que tenía con la madre, para gastárselo de forma inapropiada y sin contar con la aprobación de ésta, con evidente tendencia al derroche y al despilfarro, necesitando de nuestra asistencia para asuntos patrimoniales”. Ahora bien, la sentencia no le prohíbe literalmente hacer testamento y en estos casos, si cuenta con el dictamen de dos facultativos que lo consideren apto para ello, podría hacerlo. En mi opinión y teniendo en cuenta lo que dice la sentencia de incapacitación, no creo que sea muy razonable que le permitamos poder otorgar testamento, siempre y cuando los facultativos así lo consideraran de entrada, por lo que la respuesta que se le debería dar al propio Felipe es que no puede otorgar testamento. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2021-02-18','Ana: llamada de Teresa Noguera,TS- Novaforma(662 337 460): quieren solicitar revisión de discapacidad al CADEX, nos remitirán la solicitud para la firma del representante legal. Aún están pendientes del informe médico para adjuntar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-02-18','Ana: conversación telefónica con Emilia Rodero, TS del CADEX-CC (927 00 55 05), a Toñi le correspondía ahora revisión del CADEX, dadas la pandemia actual, en los casos que consideran oportuno, están prorrogando automáticamente 2 años las resolución. Para ello piden la conformidad de la CTAEX. *No hay ningún inconveniente. **Nos remitirán la nueva resolución.','2');
