insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-02-17','Ana: correo de Chema, Coordinador del PP.TT. de Menores de Plas. gestionado por la Entidad Cerujovi (jm.gallego.coordinacion@gmail.com // 649 676 149): "Buenos días, Ana. Te adjunto la documentación de Darío López Gilarte que se ha pedido por escrito. Además, también se remiten documentos que te pueden ser de interés como la valoración del CADEX o el grado de dependencia. Por otra parte, como te comuniqué ayer por vía telefónica, en la actualidad Darío no está recibiendo ningún tipo de prestación. Sus saldos están a cero, esperando a recibir una beca de estudios." .... Lo reenviaré a Icíar, CTAEX, para el inventario. Pongo en copia también a Julio y Juan Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-18','miguel, me llama Alicia la prima de Damian, quién me ofrece un abogado para tramitar la reclamaciónes de impagos del alquiler de la vivienda y el desahucio o al menos la no continuación de dicho alquiler al finalizar el plazo del contrato de arrendamento social. Le pido que me ponga en contacto con un abogado y al tiempo me envía por email el contrato de arrendamiento. Al tiempo me explica que Damian le ha dado mucha docuentación entre la que se encuentra autorizaciones para muchas cosas. Le comento que al ser curatela nosotros y él tenemos que actuar al unísono. Quedo en que me pondrá en contacto con un abogado, al tiempo que yo remitiré email y físicamente requerimiento al ayuntamiento de Malaga de todos los pormenores de este contrato de alquiler ************************************************* Datos de contacto de Alicia prima de Damian tlfno 635525519;emails: aliciaasimas@gmail.com y acueto@asima.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-18','Ana: Devuelvo a Carmen Ferrer el recibí de la nota interior que me pasan: "...adjudicarle plaza en el piso supervisado de la localidad de Mérida. Con motivo de las dificultades en al gestión de dicha plaza y para ofrecer una alternativa residencial hasta su resolución, se deriva a plaza residencial en el CRR...", no solicitan documentación relativas a causas legales abiertas y/o juicios pendientes. ························································································································ Mediante nota interior les facilito copia de la Diligencia de notificación y requerimiento del Juzgado de Primera Instancia e Instrucción número 4 de Plasencia. (Libertad vigilada y orden de alejamiento)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-18','miguel, remito el siguiente email a la dirección que me ha enviado Alicia imv.paa@malaga.eu Buenos días, en relación a uno de sus contratos de arrendamientos sociales donde el arrendador es un curatelado de esta Comisión Tutelar de Adultos, Don Damián Salvador Granados Heredia y como parte arrendataria Don Antonio Pinto Estrada y Doña Mª Victoria Sánchez Navarro, siendo la dirección del inmueble c/ Dan nº9, Málaga, con ref. catastral 9931101UF6693S0157YL, inscrita al 100% de propiedad del curatelado en el registro de la propiedad de Málaga nº15, finca nº 6497, el cual adjuntamos, así como la acreditación de la representación por nombramiento judicial del mismo. Les solicitamos nos informen y aporten documentación acreditativa de todo lo concerniente a dicho arrendamiento (acreditación de los abonos, nº de cuenta en que se realizan, fechas, etc) ya que tras meses de queja de nuestro curatelado y habiéndonos llegado noticias de que alguien comunica a dicho ayuntamiento la normalidad en el cumplimiento de dicho contrato, entendemos como mínimo que se están produciendo irregularidades y posiblemente suplantación de identidad. De esta forma nos dirigimos a ustedes, al ser imposible contactar telefónicamente con los responsables del seguimiento de dicho contrato. Ruego a la mayor brevedad posible nos hagan llegar la documentación solicitada por esta vía o bien a la dirección: JUNTA DE EXTREMADURA SEPAD Avda de las Américas nº4, Cp 06800, Mérida (Badajoz) Quedamos a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-18','miguel, remito al único contacto con el que hablé, Antonio (alvargas@malaga.eu), el email que he remitido al ayuntamiento para que nos manden información y documentación relacionada con el contrato de alquiler. Buenas tardes Antonio, estuvimos hace meses hablando acerca del alquiler social cuyo arrendador es curatelado de la Junta de Extremadura, Damián Salvador Granados Heredia con DNI 53692319S y siendo los arrendatarios Don Antoni Pinto Estrada con dni 26825367V y Doña Mª Victoria Sánchez Navarro con dni 76753137K, para que en la mayor brevedad posible nos remitan toda la información posible acerca de cómo, dónde, de qué forma se han producido los abonos, los comprobantes de los mismos, etc, ya que según nos comenta el curatelado alguien está firmando como que los abonos se están produciendo y prácticamente desde el principio no le han abonado nada. Por favor, miren el email que he remitido más abajo y contéstenos en la mayor brevedad posible. Muy agradecido, quedo a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-18','Ana: Recibo informe médico del CADEX la Dra. Mª Victoria Boticario Villarroel: en el último seguimiento telefónico desde la consulta médica del Equipo de Conductas Adictivas, José Manuel refiere que ha vuelto a las pautas de consumo de tabaco que solía tener y continúa tomando bebidas energéticas (previamente había dicho que las iba a dejar. Y que había pasado al tabaco de liar). "Cree que no es buen momento para plantearse cambios"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-02-18','miguel, el curatelado amenaza con irse del centro...Amalia remite email del Centro. Tras comprobar la sentencia efectivamente afecta únicamente al ámbito patrimonial y por tanto puede irse en cualquier momento. trascribo su email: Buenos días , D. Pedro Sudón no es tutelado de la Comisión Tutelar . Le adjunto su sentencia judicial de incapacitación , el fallo le asigna una incapacitación parcial , estableciendo una curatela para la esfera exclusivamente patrimonial . Para el resto de de las esferas no está incapacitado , puede libremente decidir dónde quiere residir . Recordarles que a ese centro residencial decidió él libremente ingresar , si bien , fue orientado por su sobrina Cristina , la Comisión Tutelar no tuvo nada que ver en esa decisión. Si bien garantizamos el pago de la plaza , por estar incapacitado en la esfera económica. Comparto contigo , en que la mejor solución habitacional para Pedro es un centro residencial , donde tenga cubiertas todas sus necesidades básicas , pero no podemos intervenir en esa decisión , no tenemos competencia jurídica para ello . En mi opinión creo que sería apropiado contactar con sus familiares para que valoren y le orienten en este tema . Su sobrina Cristina ,una cuñada que reside en Badajoz y un hermano que vive en Alemania , son las personas de su entorno familiar que conocemos y con los que hemos hablado en alguna ocasión . Supongo que Pedro tendrá sus contactos. Antes de ingresar en vuestro centro estuvo en un piso de alquiler , supervisado por su sobrina Cristina que fue la que le "animó" a dejar el anterior centro residencial . Pero la situación derivó en numerosos problemas de convivencia que la hicieron desistir y lo volvió a ingresar en centro . Espero haberte ayudado en tu consulta . ***************************************** mi contestación: Buenas Ama, efectivamente es curatela estrictamente patrimonial, y por tanto puede marcharse del centro cuando quiera. Ahora bien, si supone un riesgo para él o para los demás, entonces tendríamos que solicitar la ampliación de la incapacitación a tutela al tiempo que se solicite otro procedimiento de internamiento involuntario para lo cual necesitaríamos informes médicos y sociales que lo aconsejen y acrediten y cualquier otra prueba (denuncias, etc)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-18','Ana: Recibo de la Res. Ntra. Sra. de la luz la documentación relativa al ingreso de Guadalupe. Pongo para la firma del D.Gerente: Contrato de Admisión, Reglamento de Régimen Interno y Autorización para la Vacuna de la Gripe. Paso a Alberto, Jefe de la Secc. Ecca: Autorización Bancaria. Y a Miguel, Asesor Jurídico, Documento LOPD (que pone para la firma) y Autorización de derechos de imagen, la cuál indica que hay que modificar pues la han redactado con carácter general. *Le indicaré que se pongan en contacto con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-02-18','LLevo una semana con un problemón tremendo con Nerea Da Costa , con reuniones con técnicos y jefes de menores .Esta chica está en un piso de menores con 6 niños más de entre 5 y 10 años . Con más de 5 ingresos en la UHB , agresiva con los niños y monitores. En uno de estos ingresos en el hospital , se ha infectado de covid y de los 7 monitores que tiene el piso , 6 de cuarentena . No había manera de garantizar el aislamiento suyo y el de los menores .... en fin , una buena movida que conseguimos resolver sacando a los niños a un campamento y dejandola a ella y al monitor en el piso . He mandado informes a la Sección de discapacidad para dar prioridad a este acceso y ayer nos concedieron plaza en Adiser Horizontes. Estoy a la espera de que me confirmen que la PCR que le he gestionado de negativo y procedo al traslado. Te explico todo esto porque he acordado con uno de los monitores del piso que la llevará en su coche y pasará una factura de kilometraje y dieta . Esta posibilidad me la plantearon desde el recurso y es la más apropiada y la más económica . Os pasaré la factura para que se abone . No sé si tendrá dinero en cuenta , creo que algo ha de tener , por favor comprobad si se le ha ingresado la PNC . Se la tramité hace meses , de registro se envió mal por error a otro servicio y también he tenido que solicitar y justificar a esa sección que nos tengan en cuenta el carácter retroactivo para que Nerea no pierda liquidez. Desde Adiser nos van a enviar un documento para que se abone el 75% de la PNC en concepto de copago de la plaza. Además se le ingreserán 100€ mensuales para cubrir todos los demás gastos . Y con esto , queda este presupuesto fijado . -------------------------------------- Se envia autorizacion para administrar vacuna covid','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-02-10','AMALIA : Hace unas tres semanas me llamó su hermano sobre la una del medio día para comunicar que estaba en el Peri en la casa del padre ,allí no se podía quedar porque tiene una O. de alejamiento del mismo y además este hermano y su familia se han ido a vivir allí. Había estado con sus " colegas " desde que salió de la cárcel pero por alguna razón regresó a la casa . Con plena ola de frio y pandemia no podía quedarlo en la calle . Empecé a contactar con todos los recursos posibles , y haciendonos un favor , conseguí que por la tarde se le hiciera de urgencias una PCR e ingresó en el Hostal Salud , reconvertido ahora en Centro de Emergencias social para personas sin hogar sobre las 19.00 Duró dos semanas , robó a un compañero y le pillaron consumiendo drogas en la habitación . Por lo tanto , fue expulsado. Le indiqué nuevamente todas las gestiones que tenía que hacer si realmente quiere encauzar su vida . Tenía que pedir cita a su médico para derivación a CEDEX y desde ahí solicitar plaza en una comunidad terapeútica para deshabituación. Además de volver a solicitar cita para obtener DNI y tarjeta sanitaria porque como sabes , los rompe para no ser localizado por la policía en caso de detención. No ha hecho nada de eso , nada más puedo hacer desde la parte social . Ahora ya depende de él , se exije su voluntariedad para iniciar este proceso . Me solicitó un extra para ropa pero lo convencí para que utilizara la ropa del ropero de Caritas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2021-02-17','Prudencio Casares Mariscal , me escribió Juana e Iciar para que cambiara sus pensiones a otro Nº cuenta que se le ha abierto . Hay que abonar el piso tutelado de mayores de Alburquerque , no sé si abona por transferencia o hay que facilitarle al centro el nuevo Nº CCC para que lo abonen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-02-18','miguel, 18/02/2021 no hay información completa de lo que Pedro y Soraya remitieron al Juzgado. Ana Ts me da varios sobres de NACE que llegaron días atrás, y que remito junto a la Providencia de citación a SORAYA y Angel para su conocimiento. No tengo más referencia del procedimiento con lo que a efectos de mi asistencia, me ratificaré en la documental aportada en la demanda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-02-16','Ana: Correo de Sonia Bernabé, Asindi: "Hola, quería informaros que esta semana habrán pasado 28 días desde que pusieran la primera dosis a los residentes, y la próxima semana comenzarán las visitas de los familiares. Muchos de ellos y tienen ganas porque al haber positivos la residencia ha estado cerrada. La familia de los hermanos Hernández Castaño, ha sido informada porque en alguna ocasión y, cumpliendo las normas ha venido a verles. ..."','2');
