insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-02-16','Ana: Correo de Sonia Bernabé, Asindi: "Hola, quería informaros que esta semana habrán pasado 28 días desde que pusieran la primera dosis a los residentes, y la próxima semana comenzarán las visitas de los familiares. Muchos de ellos y tienen ganas porque al haber positivos la residencia ha estado cerrada. ...Al padre de Aarón se le informará también para que, si quiere, pueda venir, ya que tiene buena relación con Aarón y ahora creemos que estará de manera más continua en el centro. Un saludo,"','2');
