insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-02-19','Ana: Envío correos a Ángel y Miguel, Asesores Jurídicos CTAEX, para que soliciten al Jdo. el ingreso involuntario no urgente en la UHDAC de Aarón. Les envío adjuntos: Informe actual del centro, Informe del Serv. de Psiquiatría y Documento de Aceptación de Derivación a la UHDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-02-19','Ana: Llamo a Control de Pensiones, de la Tes. Geranal de la Seg. Soc. (927 62 00 49), me informan que Emilia ya tiene rehabilitadas las 2 pensiones: viudedad y jubilación. Ayer dieron la orden de pago al banco, pero no sabe cuándo se hará efectivo en su cuenta. ················· Se lo comunico a Alberto e Icíar, CTAEX, mediante mail para que comprueben si ya tiene dinero en la cuenta y si aún no se hecho efectivo que estén pendinte. *Hay que domiciliar los recibos de los suministros. ············· Icíar confirma que aún no le han ingresado nada en la cuenta. ···················· Llamo a Carmen, TS SSASB de Coria (927 50 80 00, Ext. 318): ella envió ayer un correo a Iberdrola, pidiendo que no corten el suministro de luz. Me facilita la dirección y enviaré yo también otro correo: CobrosRiesgoExclusionSocial@curenergia.es **Esta dirección da error. Remito el correo a clientes@curenergia.es *Lo guardo en su extpe. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-02-19','Ana: Correo de Sandra, TS de la Res. Patronato de Coria (sandraalfon@hotmail.com): "Buenos días Ana, he hablado con la hija de Rosario González Jorna y ella se encarga de pedir otro Certificado Literal. Desde la Enfermería del Centro le pedirán a su Médico un Certificado que acredite la imposibilidad de Rosario de desplazarse. En cuanto tenga la documentación, me pongo en contacto contigo."','2');
