insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-02-19','Ana: Correo de Toni al ctutelar@ y al mío con última incidencia económica de Juan: "Adjunto se envía, nota informativa sobre la deuda acumulada de Juan Cahmorro Holguín en el establecimiento de UDACO Guadalupe, así mismo se adjuntan también, tickets y factura con número de cuenta. Ayer acudió a su cita con el psiquiatra en Cáceres, y sin incidencias, pero esto de lo que informamos se debe a una deuda que ha ido acumulando al reterirar comida del supermercado UDACO. Hasta ahora el, iba a comprar alguna cosa con sus 70 euros semanales y con el vale de comida de Caritas que le entregan cada quince dias también. Pero creemos que todo el follón se ha producido desde que le concedieron el programa de diputación ya que en octubre si que ha ido con el dinero de este programa, luego desde nuestro punto de vista tanto desde la tienda le han seguido dando sin supervisión como el ha seguido procediendo igual. El programa lo han cerrado sin opcion a poder imputar estas facturas, según nos dicen desde el SSB de Guadalupe. Por lo tanto se ha acumulado esta deuda. Tanto al propio Juan Chamarro como a la tienda se ha indicado que no se le de mas comida. A continuación en nota informativa explicamos el desarrollo: Con fecha martes 09 de Febrero de 2021, contactamos con la empresa UDACO (Juan Raúl Cano) para confirmar la información que Juan Chamorro nos ha proporcionado: que tiene establecida una deuda con este supermercado por importe de: 350,47 euros correspondiente a los meses de Noviembre, Diciembre y Enero. Se adjuntan los diferentes tickest facilitados por el establecimiento y su factura para saldar deuda, si procede. En este mismo día, nos ponemos igualmente en contacto con Raquel Moreno para comunicarle lo siguiente: A/A Raquel Moreno: Nuestra pregunta/duda es la siguiente: teniendo en mano una factura oficial de diversas compras realizadas entre noviembre, diciembre y enero por Juan, que es algo que el programa de ayuda social de la diputación de Cáceres contemplaba, ¿existe alguna posibilidad de que se pueda pasar la factura por este programa para volver a activarlo y que se pueda pagar la deuda con esta ayuda?. Esperamos tu respuesta a lo solicitado, para determinar otra forma de pago y justificación. Su respuesta es: No se puede pagar, el programa está cerrado, por no poder justificar los dos primeros pagos. Desde los SSB del Ayuntamiento, han cerrado el programa al completo, tanto para Juan como el resto de los usuarios, al no poder o saber, justificar la entrega de los 100 euros mensuales de Septiembre y Octubre de 2020. Restaban cuatro meses más. Lo que Juan no nos ha aclarado, por qué no acude a la tienda con su dinero disponible y se ajusta a la cantidad que disponga en la semana. Como se puede comprobar, se la ha ido anotando en cuenta y ha comprado sin control. Desde este equipo de apoyo social comunitario, se le ha explicado al supermercado UDACO, que no debe entregar ningún producto a Juan si no lo paga, que eviten agrandar esta deuda o comenzar una nueva."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-02-19','Ana: Correo de Mariví, TS CSS-Plas: "Su casa no reúne las más mínimas condiciones de habitabilidad, está declarada casi en ruinas. El Paciente está sólo y aunque es autónomo para muchas cosas, hay un riesgo de abandono de medicación y hábitos saludables, higiene, alimentación etc... La voluntariedad de Juan es aceptable en tanto se arregla su casa, le conceden plaza en la Residencia de su Pueblo, o plaza pública en Residencia de Validos, hasta entonces no se opone a estar en otro Centro. No es necesario el ingreso involuntario. La última opción que estamos barajando es la Residencia privada de Casas de Dº. Antonio, si tiene plazas libres, es buen Centro, cuesta sobre 1.300 €. mensuales. Como no sabemos los saldos de sus cuentas esperamos que lo valoréis vosotros para que pueda costearse la privada en tanto le conceden plaza pública. Un saludo," ·················· Pido a Alberto, jefe secc. ecca. CTAEX, que me confirme las posibilidades económicas de Juan a día de hoy para costearse esta residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2021-02-22','TERESA RECIBO CORREO DE ANTONIO NISA TS DE LA FUENTE DEL MAESTRE DONDE ME ADJUNTA AUTORIZACION VACUNA COVID FIRMADA POR EL EN NOMBRE DE LA COMISION TUTELAR, LA ARCHIVO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-22','Información sobre los acompañamientos de FUTUEX: Adjunto se envía nota informativa sobre el acompañamiento realizado el pasado 15 de febrero 2021 como reanudación de consulta presencial en psiquiatría con el doctor Calderón López. Que insiste en la toma adecuada de su tratamiento pautado (inyectables, ya gestionado y acompañamiento realizado, y topamax diario) siendo el control en su domicilio el que no se cumple adecuadamente. Recordamos que, desde salud mental, ya se ha derivado la solicitud para plaza en talleres ocupacionales en la Fundación Sorapán de Rieros, con al que hemos contactado para saber en qué situación está la solicitud. Se refleja en lo del abono pendiente de las plantillas ortopédicas, pero segun nos acaban de confirmar ya lo ha abonado la comision. Tb se refleja, la compra de un nuevo terminal móvil por parte de Alejandro (Iphone 12 por valor de 1000 euros) en la línea de sus compras compulsivas.. bueno o la madre o quien haya sido, poruqe la verdad no damos credito..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-02-22','Ana: Llamo a Esperanza, TS - ESM-Mérida (924 48 72 28): Me dicen que está haciendo un curso. Le dejarán nota para que me llame cuando ella pueda. ·············· Recibo llamada de Esperanza (85832). En 2017 le atendía era María Río, que ya no está. **Tenemos que pedir cita a través de atención primaria. Su médica de A.Primaria es Elena Balanzategui, C.S. Mérida Norte. *Diagnóstico en 2017: Trastorno Delirante con contenido persecutorio. No puede enviarme el informe. **Coordinadora del ESM Sara Peláez, Psicóloga. Fax: 924 48 72 42.','2');
