insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-22','Ana: Adelanto escaneados por email a Mary, Directora Res. Ntra. Sra. de la Luz, los siguientes documentos: Contrato de Admisión, Consentimiento para el Tto. de datos de carácter personal, Reglamento de Régimen Interno, Autorización Vacuna Gripe, Consentimiento LOPD. Debidamente sellados y firmados. ···· Juanpe, Admvo. remitirá los originales por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2021-02-22','miguel, remito email a Amalia y Alberto: Buenos días, ha llegado queja de un vecino de la Andrea indicando que hay problemas en su vivienda y nos pide arreglemos los desperfectos que parece vengan de la vivienda de Andrea. Necesito Amalia que solicites alguien se persone en la vivienda y o bien el seguro lo repare o caso no haya seguro, consigue un presupuesto que según el importe tendríamos que solicitarlo al juzgado. Mando copia a Alberto para tenga controlado si podemos disponer llegado el momento, de dinero para arreglo, incluso para gastos de abogado si fuera necesario.','2');
