insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-02-22','TERESA Se le comenta a Bartolomé que ahora tendrá que quitar internet en casa con Orange, y coger una compañía de telefonía móvil en la que pague unos 15€ al mes para tener internet y llamadas ilimitadas porque tiene que empezar a ahorrar en los gastos domésticos. Además de pagar el alquiler, que son solamente 23€, según cuenta el tutelado, tiene que hacer frente a las facturas de luz, agua y basura. HABLO CON ANTO PARA GESTIONAR ORFANDAD ABSOLUTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-02-22','Ana: Llamo a Nuria Carrasco, TS EVD-Trujillo (689 57 57 19): En relación al correo remitido por Carmen Gallego a Pedro, Jefes secc. CTAEX, sobre el extpe. abierto en Dependencia, para posible ingreso en centro de discapacidad de Juan, indico que ni Juan está dispuesto a ingresar ni tenemos Autorización Judicial para Ingreso Involuntario. Por tanto la solicitud no prospera. *Cerrarán el expte.','2');
