insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-22','miguel, hablo con el abogado Carlos Jurado Lena, y quedamos en intentar solucionarlo con acuerdo ya que me demostrará que las dos demandantes también eran hijas. El viernes a las 9h vendrá con la documentación para acreditarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-02-22','22/02/2021 Se envia solicitud de acceso a centro residencial por decreto Madex para firma del Gerente . Se adjunta I. Social , I. Médico , Sentencia incapacitación. Por dependencia no se puede pedir pq da un sin grado , a pesar de que tiene 65% G. discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-02-22','TERESA El pasado 18 de Febrero se recibe la llamada de Alfonso y Jorge, los veterinarios del centro de salud de Jerez de los Caballeros para comentar que ha habido un incidente con uno de los perros que Ramón González Hernández tiene en su domicilio. Ha mordido a una mujer que paseaba por la calle y ésta ha ido al centro de salud y se ha iniciado el protocolo de actuación en estos casos. Los veterinarios han ido a casa de Ramón para hablar con él y con su madre María, para pedirles la documentación del animal y comprobar así que estaba todo en regla. María les ha comentado que la perra es suya y que ella no tiene documentos ningunos sobre ella. (nos extraña que diga esto la madre de Ramón, suponemos será para protegerlo) Alfonso les comenta que el protocolo es el siguiente: la perra tiene que estar aislada en casa, sin salir durante 14 días. Y una vez que pase ese tiempo, tienen 10 días para ponerle la vacuna de la rabia o sino les caerá una sanción. Solo pueden hablar con María porque Ramón no se encuentra en casa cuando van a informarles. Seguidamente Alfonso y Jorge envían por email la misma documentación que le han entregado en mano a María, la madre de Ramón para que sepan cómo tienen que proceder. Se adjunta envía ese informe. Se ha telefoneado a Ramón para comentarle el incidente con una de sus perras y él ha negado que su perra haya mordido a nadie, pero ha comentado que él tiene la documentación de ese animal. Se le pide que coja la cartilla y se la lleve a los veterinarios del centro de salud para que revisen sin tiene todo en regla. Pero él no contesta nada y no se tiene seguridad de que lo vaya a hacer. No nos consta que la mujer haya presntado alguna denuncia, pero tampoco sabemos mas que el protocolo pertienente se ha iniciado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-22','miguel, hablo con Carlos Jurado Lena y le doy cita para este viernes para tratar el tema del reparto de la cuenta. Remito email a Amalia y Alberto: en relación a este curatelado, dos supuestas hermanastras interpusieron demanda de conciliación reclamando 147.500€ a repartir entre 3 partes. El juzgado nos citó sin acreditarnos nada y sin tiempo de estudiarlo, por lo que nos opusimos, y ahora si no llegamos a un acuerdo tendríamos que ir a juicio y buscar un abogado de pago a Alejandro. Hoy he hablado con el abogado con quién he quedado que se acerque el viernes a las 9h a la oficina con documentación para acreditar que son hermanastras, que no había testamento y por tanto el dinero es de los 3. Tras revisar la demanda de conciliación como el certificado del Santander veo que no coinciden las cuentas (debe de ser según me dice Belén que se trata de una cuenta del antiguo Banesto 0030…). Por tanto si me acreditan que ese dinero es el mismo aunque hayan cambiado los números de cuenta. Y lógicamente con libro de familia me acreditan que son hermanastros. Y a falta que me enseñen o soliciten declaración de herederos (ya que testamento no hay), pues tendríamos que darles la razón. Como veréis en el documento adjunto quedan unos 139.000€. Le he dicho que si nos lo acredita la Ctaex no se opondría a llegar a un acuerdo. Claro está necesitamos el consentimiento de Alejandro ya que se trata de una curatela. Por tanto en caso de que todo estuviera correcto, el siguiente paso sería que este abogado presentaría todo al Santander, quienes lo remitirían a su departamento de testamentaria quienes nos harían firmar a todas las partes el acuerdo de reparto (en nuestro caso harían firmar al gerente y a Alejandro, seguramente el mismo día…) Os comento todo esto por si queréis estar presente en la reunión y/o añadir algo al respecto. No estaría mal que tras la reunión Amalia se lo comentases a Alejandro Nuñez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-02-22','miguel, la fiscalia de la seccion terribotrial de Zafra, os remite físicamente hoy Decreto de archivo de 17-2-21, desestimando la denuncia de Elena por abusos sexuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-02-22','TERESA Me comunica Miguel la resolución Decreto de archivo de la denuncia de Elena, dice que teniendo en cuenta antecedentes contradictorios y no acreditados los hechos, lo archivan','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-02-22','Amalia : se recibe llamada tf de Isa , TS de la zona de San Lazaro . Nos va a remitir I.Social para rendición de cuentas. Ha hablado con su hermano y con su padre . Actualmente no saben dónde se encuentra , tras su expulsión del Centro de transeuntes desconocen su paradero . Verbalizan que se encuentra con consumo activo de drogas , y que se muestra muy agresivo con el mono . No acepta ayuda , no quiere dejar de consumir . Su hno. se ha separado y vive actualmente con su padre en la casa de éste .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-02-22','-Amalia : contacto con la TS de la zona del Peri y San Lázaro , Isa . Le hablo de situación de la familia ,pero no la tiene entre sus usuarios . No han acudido a SS. SS . Pepi necesitaría una valoración social y apoyo desde SS .SS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-02-23','Ana: Correo de Toni - Futuex, de ayer a última hora: "Te cuento a continuación, la poca información que pudimos recabar de la tutelada Ana Mª Rosco Ávalos (Mérida). También se adjuntan dos fotos correspondientes al portal y puerta del apartamento en el que reside la tutelada. Hicimos la visita el pasado 17 de Febrero. Tras varias llamadas telefónicas a la tutelada conseguimos que nos atienda, se muestra muy desconfiada a preguntar por su nombre y al identificarnos nos cuelga la llamada apagando el teléfono posteriormente. A pesar de ello, intentamos el contacto de forma presencial. Pudimos localizar la vivienda de la tutelada gracias a las indicaciones de varios vecinos, pues el número indicado en la dirección corresponde al portal de la urbanización. Ana Mª reside en un apartamento localizado en la parte de arriba de la urbanización, los únicos apartamentos que tienen una escalera en forma de caracol. Reside en el 2º piso en la puerta 18. No nos abre la puerta a pesar de tocar varias veces tanto al timbre como a la puerta. Se destaca la información obtenida por parte de los vecinos pues al preguntar por la vivienda de Ana Mª la respuesta general fue “No te va a abrir la puerta, inténtalo a ver si tienes suerte pero no te va a abrir”. Además, todos expresaron que debía tener cuidado porque Ana Mª es una persona violenta sobretodo verbalmente. Últimamente han tenido varios episodios en la urbanización causados por la tutelada. Aconsejan que no vaya sola al menos hasta que la tutelada nos conozca y tenga más “confianza” pues a priori no va a reaccionar de forma adecuada. Resaltan que hasta el momento no ha existido ningún altercado con agresión física pero sí que últimamente está muy alterada con problemas de conducta produciéndose principalmente agresiones verbales. Por último lugar, se ha intentado contactar de nuevo por teléfono con la tutelada sin conseguir que nos atienda la llamada. Es cierto que la tutelada nos daba toques al teléfono que cuando devolvíamos la llamada daba un tono y saltaba el contestador sin conseguir contactar con ella." ················ Respondo al correo informando acerca de la conversación mantenida ayer con Esperanza, TS del ESM y facilitando el contacto de Elisa, madre de Ana Mª. ······················································································································································································ Llamo a Ana María (635 608 658), a pesar de dar varias llamadas no responde al teléfono. Finalmente salta el buzón de voz y le dejo un mensaje exponiendo el motivo de mi llamada y pidiendo que se ponga en contacto conmigo, indico mi número directo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-02-18','Ana: Correo de Toni-Futuex a última hora: "17/02/2021 comparecencia en Juzgado de Plasencia, prevista: A primera hora de la mañana, acude a salud mental a su cita con la doctora Mª Jesús Gutierrez, tal y como se había organizado, aprovechando la citación judicial. En la consulta se muestra alterado, a la defensiva, indica, en todo momento, que no tiene patología de ningún tipo ni precisa de medicación alguna, que todo se lo han inventado para controlarlo y quitarle cosas, como está haciendo la CTAEX, que le está quitando su dinero… La doctora opta por variar la medicación, quedando la siguiente pauta: • Trevicta 525mg cada 12 semanas (3/3/2021-26/05/2021-18/08/2021) • Quetiapina 300mg (1-1-1) • Orfidal 1mg (1-1-1) • Invega 6mg (1-0-0) • Invega 9mg (1-0-0) Dando cita, para revisión, el 24 de mayo, ha quedado en enviar informe a la educadora, detallando, mejor, todos los datos de la revisión. A continuación, se acude a la citación judicial, Alfonso va algo nervioso y se va alterando más con el retraso de la comparecencia. Se pone bastante nervioso cuando se le intenta pautar sobre cómo responder a las preguntas en el juicio, pues estaba insultando a la persona que le denunció e indicando que lo único que quería era sacarle el dinero… Se le aconseja no insultar y hablar con respeto, establece que sabe muy bien cómo debe comportarse en el juicio, que lo tratamos como “subnormal” pero él es súperdotado, sólo que la CTAEX le quiere quitar su dinero y sus cosas y por eso le ha puesto la incapacidad… Es muy difícil acercarse al tutelado…, de hecho, se molesta con la letrada cuando le dice que debe pasar, la educadora, a la comparecencia. Durante la comparecencia alega que no se acuerda de lo que ocurrió, sólo que, en casa, dijo que estaba harto de todo y tomó muchas pastillas y alcohol, luego ya se despertó en la cama del hospital; se duda si es cierto todo lo que dijo, pues cuando preguntaron si consumía alguna droga, indicó que no. También comentó que no tiene patologías y todo es inventado, hasta el tratamiento, por eso no lo toma siempre… Tras tomarle la declaración, la abogada de oficio comenta que puede quedar archivado el caso debido a su trastorno o que se le impongan medidas cautelares que pueden ir desde el ingreso en centro, en psiquiatría o el requerimiento de que tome la medicación y sea revisado en consultas de salud mental. Lo más apropiado sería el ingreso, pues Alfonso se encuentra aparentemente descompensado y alterado. Es muy complicado acceder al tutelado, por lo que quizá, si se le aceptase el presupuesto para la compra de ropa, fuese más sencillo acceder, aunque su madre también supone un obstáculo. De hecho esta ha sido la segunda vez que la compañera lo ha podido ver en persona, desde que se le hace el seguimiento, dado que simpre esta en su cuarto cuando se le visita, y se obtiene informacion diferdia por su madre. Se adjunta, en documento a parte, el presupuesto para la compra de ropa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-23','Ana: correo de Alberto, jefe secc. ecca. en relación al correo que le reenvié acerca de los gastos de bolsillo de Guadalupe: "Se va a autorizar 20 €/semana. No da para más. El centro tendrá que trabajar con esta persona para el tema del tabaco y el café."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-02-23','Ana: Correo-respuesta de Alberto, jefe secc.ecc. CTAEX: "Hola Ana. El tutelado podría abonar los 1.300 €/mes en concepto de CENTRO. Alberto" ·················· Llamo a Mariví Clemente, Ts al CSS-Plas. xo no obtengo respuesta. Lo intento más tarde y ante la imposibilidad de habla con ella le envío un correo. ······················· Más tarde recigo llamada de Mariví: *Las llaves de la casa la tiene Estrella, la TS del SSASB de su Puebo. La casa la declararon casi en ruínas. No reúne condiciones de habitabilidad. El Ayto. realizó labores de mantenimiento. *En cuanto a la autonomía de Juan, establece que hay que estar pendiente de su aseo, de la toma de medicación, etc... Pero como la herramienta de Dependencia no valora de forma adecuada las patologías mentales, sólo dio grado I. **Hablará ella mañana con Estrella, TS SSASB, en relación al igreso en la Res., pues ella conoce al personasl de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-02-23','Ana: Gregoria reside en los PPTT de Calzadilla (Cáceres). Según el informe social "cuando ingreso en el centro, llegó con una situación económica muy extrema, no tenía dinero en sus cuentas, presentba deudas por descubiertos, tarjetas bancarias de crédito, después de haber vendido su vivienda, y cobrar mensualmente más de 1000€... intuímos que podía haber sido estafada". Es soltera y no cuenta con ningún tipo de apoyo familiar. Presenta RETRASO MENTAL MODERADO, según el Dictamen Técnico, con un grado de discapacidad reconocido del 65% - Carácter definitivo. ··················· Llamo a Gregoria (612 481 680): le explico por qué el juez la ha incapacitado y cuál es la finalidad de modo que pueda entenderlo. *Le indico también que podrá retirar todas las semanas 35€ del banco. Y que próximamente irá a visitarla una compañera. *Insiste que le engañaron los que vendieron el piso y que la han dejado sin nada. Hablaré con las compañeros asesores jurídicos. ························································································································································································· Hago derivación para apoyo y seguimiento mediante email a futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-02-23','miguel, conforme pide Escalona a Angel, remito email a Ana: Hola Ana, conforme al informe que en su día enviamos a abogacía general (Escalona) para pasar de tutela a curatela a Jesús Romero Perez, resulta que el juzgado no logra localizar a su hermano Zacarías y nos pide una dirección para lo cual la abogacía nos pide que en dos días le contestemos. Necesito que hables con Futuex y a ver si conocen otra dirección a parte de la que pusieron en el informe nº7.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2021-02-23','Ana: Recibo llamada de Jesús Manuel (635 336 539), con exigencias con respecto al cambio de vivienda. Le explico las posibilidades económicas y las indicaciones facilitadas ya a Futuex. Él tendrá que implicarse y colaborar en la búsqueda de un nuevo piso de alquiler, pero adaptándose al presupuesto (260€ máximo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-02-23','TERESA ME LLAMA PARA RECORDARME EL TEMA DEL DENTISTA LE PASO A BELEN LOS TELEFONOS PARA QUE SE PONGA EN CONTACTO CON ELLA LA CLINICA DENTAL TELEFONOS 722432418 PAREJA 644625593','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2021-02-23','TERESA HABLO JUAN EL ALBAÑIL 626386877 VA HA EMPEZAR LA OBRA EL JUEVES, LE FACILITO EL TELEFONO DE CANDIDO PARA QUE SE PONGA DE ACUERDO CON EL PARA ABIRLE TEL CANDIDO637193320 AVISO A M JOSE TS DEL SSB DEL INICIO DE LA OBRA Y LE SOLICITO AYUDA MUNICIPAL PARA TIRAR ENSERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-02-23','TERESA RECIBO DOCUMENTACIO DE EL HERMANO DE M ELENA, JUAN FRANCISCO 647215708 PARA FACILITAR UNAS CLAVES ADMINISTRATIVAS EN RALCION A LA VENTA DE UNOS GUARROS ME FACILITA EL TELEFONO DEL VETERINARIO LUIS MIGUEL 650440680 PARA QUE NOS EXPLIQUE PAR QUE SON QUE EN LLAMARLO EN PRESENCIA DE ANGEL EL COMPÑERO JURIDICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-02-23','Ana: Intento contactar de nuevo con Fracisco, Hermano de Saturnino Miguel (630 211 717 // arroyomolinos@protonmail.com). De nuevo el teléfono está ocupado. *Envío un correo facilitando mi teléfono directo para que se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2021-02-24','Ana: Según informe social para la rendición anual: Sofía Florentina en el último año tampoco ha recibido visitas por parte de sus familiares, quiénes en su día manifestaron que no quieren saber nada de ella. Continúa adaptada al centro, aunque con total desinterés por mantener relaciones sociales con el resto de residentes. Con los profesionales sólo se relaciona para demandar aquello que necesita. Pasa la mayor parte del día en su habitación leyendo revistas. Su estado de salud es bueno y toma la medicación de forma correcta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-02-23','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net)en ctutelar: "• Concepción Fernández Muñoz: me cuenta que ha llamado su hermano para decirla que se ha caído una pared del patio de su casa que la separaba de sus vecinos. Han ido ya unos albañiles para hacer un presupuesto, que según informan pagarían ambas partes. Cuando lo recibamos os lo envío. Supongo que no habrá ningún problema, pero por si acaso os dejo aquí el teléfono de su hermano Antonio (él tiene llaves de la casa y era el contacto cuando hablamos de hacer el posible peritaje de la vivienda) el teléfono de éste es 606883444." ······ Se lo reenvío a Alberto, Jefe de la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-02-23','Ana: Correo de Paula TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net) en ctutelar: "...• Flora Gutiérrez: ha recibido otra notificación del banco, en este caso solicitando actualización del documento de identidad de Modesta, su madre fallecida hace un par de meses. No se si tenéis que mandar algún certificado de defunción o modificar los datos en la cuenta, puesto que ambas compartían la misma. Ya nos diréis, estas cosas afectan a Flori y está nerviosa." ······ Se lo reenvío a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-02-24','Ana: Pongo para la firma del D.Gerente nuevo expte. de PFHC (Para personas jurídicas) así como Comunicación al INSS de cambio de domicilio "sólo a efecto de comunicaciones".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-02-22','Ana: Correo de Toni-Futuex: "Te traslado una información sobre el tutelado Alfono Marin de Cacers, que estuvimos intercambiando correso el viernes. Comunicación viaje a Madrid: Nos hacontactado la madre de Alfonso para comentar que el próximo miércoles, día 24, viajarán a Madrid, a casa de una de sus hermanas, a pasar un tiempo allí, pues precisa que le ayude con la niña. Isabel establece que prefiere que Alfonso se vaya con ella, pues con su hermana está más controlado y como ahora está tan alterado es mejor, también para ver si un cambio de aires le sienta bien y porque, según indica, cuando está allí fuma menos, ya que no le permiten hacerlo en el interior de la vivienda, por lo que, por un lado, consume meno y, por otro, se mueve algo más al tener que salir a fumar fuera del domicilio o en la terraza. Isabel consulta si hay posibilidad de que se lleve la ropa que reservó para Alfonso, se le dice que lo estaba valorando el area economica, que puede llamar a la tienda a preguntar si han recibido transferencia pero no podemos garantizarle que se pueda hacer para antes del miercoles. Igualmente por si fuera necesario solicitar autorizacion o por este tema, te dejo el tema de la madre del tutelado por aqui 680 78 44 90"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-02-24','Ana: Hablo con Miguel en relación al juicio al que asistión Alfonso. Aún no sabemos nada. Consultará al Jdo. ············· Si no determina que tenga que ingresar en el CSS, no podemos impedir que se vaya unos días a Madrid con su madre a casa de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-02-17','Ana: Llamo al C. Penitenciario de CC (927 18 14 07): Maite, TS, comunica que la salida definitiva de prisión será el próximo día 25 de febrero. Se trasladará a vivir a su casa, sito en la C/ Cristobal Colón, 27 de Alcuéscar. **Tiene una orden de alejamiento vigente de su hermano, que reside en el mismo municipio, pero finaliza el día 3 de marzo. **Maite dice que tendremos que llamar al Jdo. desde la CTAEX para conocer los términos de la Libertad Vigilada. ······· Presenta trastorno de la personalidad. Es alcohólico crónico. Reincidente. No tiene voluntad de colaboración y no quiere ningún tipo de control. ·············· En cuanto al presupuesto apróximado de gastos, dice que ella no puede hacerlo con él y que desconoce los posibles gastos que pueda tener. ··· Propone que enviémos un documento de comunicación a nombre del Curatelado indicando que a su salida de prisión debe contactar con la CTAEX al respecto y que ella se lo entregará. Nos devolverá copia firmada a modo de acuse de recibo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-02-24','miguel, envío a Escalona actual dirección del hermano del tutelado tal y como nos solicitó por el requerimiento del juzgado para que remitiesemos el domicilio actual de su hermano Zacarías. Tal como me ha enviado Toni de Futuex: " Hola buenos dias, os facilito la informacion recabada, acerca del requerimiento en el caso del tutelado Jesus Romero Perez y la nueva direccion de su hermano D. Zacarias Romero: Se estable contacto telefónico con D. Zacarías Romero Pérez (629809580) para solicitar una dirección postal actual de su domicilio, y hacerle llegar, notificación judicial del proceso en relación a su hermano Jesús Romero (remoción de tutela a curatela) D. Zacarías pregunta en qué le puede implicar dar su dirección y aceptar el envío de la notificación judicial. Que entiende que puede recibir la información, pues es su hermano, incluso nos dice que Jesús todavía tiene padre, pero que el no puede hacerse cargo de nada. La relacion entre ambos hermanos es bastante distante. Se le comunica que hasta donde nosotros sabemos, se trata de tramites de los procedimientos, pero seria conveniente hablar con el, si se necesita algo mas de él. A continuación nos da la nueva dirección: C/ Ebro nº 14 – puerta A 01128 AZÁCETA ÁLAVA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-24','miguel, se pone en contacto la Abogada que tramitará la reclamación de cantidad del contrato de alquiler del curatelado: Buenas tardes, Me pongo en contacto con Vd. porque Alicia Cuetos Granados, prima de Damián Granados Heredia, ha solicitado mis servicios profesionales para intervenir en una posible demanda judicial para resolver el contrato de arrendamiento por el que Damián tiene arrendada la vivienda de su propiedad aquí en Málaga, debido al incumplimiento de pago de los arrendatarios. Si bien Alicia me había facilitado un número de teléfono ( 924006057), no he recibido respuestas las veces que he llamado. Por ello le rogaría se pusiera en contacto conmigo en el 607650498. Sin otro particular, reciba un cordial saludo. Rocío Gracián Fernández ABOGADA C/ Alameda de Colón, 34, 2º-6 29001 Málaga Tlfs: 607650498 - 952600772 *************************************************** la respondo: Buenos días Rocío, gracias por contactar con nosotros. En próximos días me pondré en contacto con usted para tratar la reclamación de cuantía por alquiler de vivienda social de Damián. Por ahora estoy a la espera de dos emails que he enviado al ayuntamiento de Málaga requiriendo de información y documentación del pago del contrato de alquiler social. Ante la falta de contestación de dichos emails, hoy sale por carta certificada escrito de esta Comisión Tutelar requerimiento en los mismos términos a dicho Ayuntamiento de Málaga. En cuanto obtenga contestación la llamaré con dichos datos para poner en marcha la correspondiente reclamación de cuantía al inquilino y si es posible el desahucio del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2021-02-24','TERESA SE ADMINISTRA SEDACION PALIATAIVA EL 23 DE FEBRERO POR EMPEORAMIETNO DEL ESTADO GENRAL, INFORMA DIRECTA DE LA CASA MISERICORDIA ALICIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-02-26','REGISTRO(26/02/2021). SE PONE A RESTRO DE ENTRADA SOLICITUD DE ADMISION EN CENTROS DE ATENCION A PERSONAS CON DISCAPACIDAD POR CORREO INTERNO A LA GERENCIA TERRITORIAL DE BADAJOZ SEPAD. JUNTO CON DOCUMENTACIÓN ADJUNTA (INFORME MEDICO, INFORME SOCIAL Y SENTENCIA DE INCAPACITACION Y NOMBRAMIENTO)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-02-24','AMALIA : Envio email a : post@drv-rheinland.de Mié 24/02/2021 9:51 Por la presente , se le comunica que el Juzgado de 1ª Instancia e Instrucción Nº4 de Badajoz , dictó sentencia Nº 241 / 20 , 21 de julio , por la que se incapacita a DÑA. Mª LUISA ESPINAR DEL ARCO ; nombrando a la COMISION TUTELAR DE ADULTOS DE EXTREMADURA , tutor de la misma . Nuestra tutelada en perceptora de una prestación de jubilación de Alemania que actualmente tiene suspendida . Nos hemos puesto en contacto con su asesor ( Fco . Javier Romero Pavón ) quien nos comunica que les ha enviado hace unos meses una Fé de Vida , certificando que nuestra tutelada reside actualmente en el Centro Residencial " Puente Real " en Badajoz . Necesitamos que nos indiquen cómo proceder para activar la prestación de Mª Luisa , con la que abona su plaza residencial. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-02-24','Amalia : hoy se procede al traslado del Centro La Luz al Centro ASPACE . Pido a la seccion eco el cambio en el pago y a Julio en la base . En un mes se lo paso a Ana . Se ha puesto a firma documentación del contrato .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-24','miguel, a petición de Ana para saber cómo se encuentra el estado del procedimiento involuntario. Me confirman que las DPA Procedimiento abreviado quedó archivado en el jzdo nº3 de Cáceres, y quedó como falta leve. En cuanto al procedimiento civil de incapacitación lo está llevando el Jzdo nº2 de Cáceres, ICP Incapcitación 402/20, con pieza separada TDJ 2/2020, y tienen también nuestra solicitud de Internamiento Involuntari ITR 43/2021, donde estamos personados en todos ellos según me confirman. En cuanto al internmiento el 22-2-2021 el MF ha dictado Dictamen requiriendonos para le indiquemos si hay plaza en la Residencia de Brozas. Lo hablo con Ana y me comenta que allí no pero en Villa del Rey (Cáceres) sí. Por tanto cuando llegue escrito del MF, le contestaremos en esos terminos que no hay sitio en la de Brozas pero sí en la de Villa del Rey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-02-24','Ana: envío correo con escrito para Antonio a Maite, TS del C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es): "Buenos días Maite, Tal y como acordamos la semana pasada mediante conversación telefónica, te envío adjunto escrito a la atención de Antonio Hidalgo Romo. Agradeceríamos que se lo hagas llegar, para que pueda ponerse en contacto con nosotros a su salida de prisión a fin de establecer presupuesto aproximado de gastos mensuales y autorización de retirada de la asignación periódica que desde la sección económica de esta CTAEX se establezca. Gracias y un saludo." ··························································································································································································· Respuesta de Maite: "Adjunto remito el justificante de notificación de escrito a Antonio Hidalgo Romo. Se le ha leído el escrito y se le ha explicado que, a su salida en libertad, debe contactar con vosotros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-02-24','Ana: Recibimos Resolución de 16/02/21, de la Directora Gral. de Serv. Soc., Infancia y Familias, por la que se acuerda la formalización del acogimiento familiar permanente y en familia extensa, de su hija Ana Belén Cacho Caballero. ······ Escaneo el documento y archivo en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2021-02-24','TERESA: EXITUS comunican el fallecimiento de Álvaro R. Gutiérrez Gallego Ha fallecido en el hospital virgen del puerto, comunica Alicia directora del centro padre leocadio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2021-02-24','EXITUS El centro (Padre Leocadio), a través de su Dra., Alicia, nos informa de su óbito acaecido el 24/02/2021. Ha fallecido en el Virgen del Puerto de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-02-24','-Amalia : Hablo con su cuñada , se va encargar de la lápida , la cubre el seguro . Paso a la seccion eco temas relativos al seguro de decesos , hay que reclamar 800€ de la lápida que no ha usado , y las cuentas donde están con los dos hijos pequeños tb tutelados por nosotros. Hay otro hijo mayor , paso a seccion juridica consulta sobre el dinero en cuenta , le correspondería una parte ?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2021-02-24','-Amalia : he llamado al SSASB de Alburquerque,924400000 , Mª Victoria que es la TS de referencia está de vacaciones ,para cualquier cosa le doy mi contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-02-24','-Derivo el caso a Nerea : Buenos días , Nerea da Costa , es una tutelada que estaba residiendo en un piso de menores en Badajoz. Tras soliciar plaza de discapacidad al SEPAD , se le ha adjudicado ADISER HORIZONTES ( Casturera ) . Pasa pues a seguimiento de tu zona . Todo está ya cuadrado con el centro , se le ha pedido Atención psicológica del CADEx , ya se le ha vacunada de covid y todo lo relacionado con su plaza está gestionado . Ingresó hace dos semanas y la adaptación está siendo buenísima , profesionales y usaria están muy contentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-02-24','Ana: Llamo a Ana María (635 608 658): Me atiende una persona que no es Ana María, que no quiere identificarse. Tras presentarme, le pregunto si puede facilitarle mi número a Ana Mª pues preciso hablar con ella, responde con malas formas y empleando terminología jurídica en su discurso, que "Ana María no tiene que hablar con nadie, que ya ha presentado recursos y alegaciones, que no tiene que estar tutelada por ninguna comisión, que para algo existe la nulidad de pleno derecho..." Le explico que ha sido un Juez quién ha nombrado a la Comsión Tutelar para ejerecer el cargo. Pero no atiende a razones, elevando cada vez más el tono y diciendo que lo que tengo que hacer es hablar con mis superiores... Indico que no tengo por qué dar más explicaciones ni aguantar esas malas formas y doy por finalizada la conversación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-02-24','miguel, a petición de Ana, hablo con Mayte TS del Centro Penitenciario de Cáceres ya que mañana saldrá en libertad vigilada el curatelado. Nosotros no somos competentes en la esfera personal, sólo en la patrimonial y así se lo indico a Ana y Mayte TS. No obstante me pongo en contacto con el Jzdo de lo Penal de Cáceres nº2 para constatar que el contenido de alguna de las 4 ejecutorias accesorias que dice Mayte no hay nada que impida que vuelva a su casa. Coral me da lo que le envió Mayte Ts (que a su vez pidió el informe social para hacer la rendición de cuentas del 2020). Lo subo escaneado a la carpeta juzgados. Hablo con el Jzdo de lo Penal nº2 de Cáceres quien me confirma que ello sepan que sólo hay 3 ejecutorias: 85/18, la 132/18, 24/18(ésta última me dicen que es del Jzdo de lo Penal nº1). Me confirma que son ejecutorias por quebrantamiento de una resolución anterior que no le figura ni nº de procedimiento ni juzgado, pero que de las mismas no se desprende orden de alejamiento, y que seguramente le impusieron quebrantamiento de la orden de alejamiento del hermano pero sin que supusiera prisión. En conclusión, que de las ejecutorias no se desprende orden de alejamiento y por tanto este curatelado puede volver al pueblo, a su domicilio, y esperemos no pase nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-02-24','miguel, no ha sido posible conectarme vía videollamada con el Jzdo nº2 de Cáceres. Quedamos en que llame el viernes a Guadalupe del Jzdo para me confirme si puede hacerse o no por el Scace, caso contrario tendría que ir a Cáceres. Se aplaza la citación para la vista al 4-3-2021 a las 13,15h. ******************************************************** Preparo autorización del gerente para asistir','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-02-24','Ana: Recibo llamada de Ana, Directora del C.R. Cervantes (22233). Noelia, TS, ya no trabaja allí. Y de momento está sin nadie que la sustituya. Manifiesta que están teniendo problemas con Mª Luisa, pues está demandando dinero continuamente al resto de residentes. Ya ha habido varios familiares que han acudido a quejarse. "Últimamente está desvocada". La asignación semanal de 25€ que retira todos los viernes no le llega al domingo. *Cogió dinero un día a un residente del andador. *Hay dos abuelos a los que manipula y de los que consigue regalos e invitaciones a cafés, dulces, refrescos, a cambio de no saben muy bien qué tipo de favores... ······· Han determinado que baje a comer al comedor de la primera planta como siempre, pero que el resto del día lo pase en su planta. Donde también ha sala común con televisión, pero menos personas, pues la mayoría prefiere baja al resto de zonas comunitarias donde hay más vidilla pues también acuden las visitas. *El objetivo es que reflexione y conseguir un cambio en las conductas que está teniendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-24','miguel, me llega email de Antonio del Ayto de Málaga: Buenas tardes Los abonos realizados del expediente 1paa2388 son: 22/10/18 abonado 5.580,00€ (Importe anualidad 1 y 2 semestre) 2/10/19 abonado 2.160.00€ (semestre 3) 11/11/2020 abonado 1.620,00€ (semestre 4) 2/4/2020 abonado 1.890,00€ (semestre 5) Tenemos pendiente de abono 1.350,00euros que corresponde al 6ºsemestre. ******************************************** Reenvío el siguiente email a la Prima Alicia: Buenas tardes Alicia, desde el ayuntamiento de Málaga me remiten la siguiente y escueta información. Por favor, mira con Damian si esto es correcto y qué faltaría porque me aportaran e informaran desde el Ayuntamiento de Málaga. Gracias, saludos. Buenas tardes Los abonos realizados del expediente 1paa2388 son: 22/10/18 abonado 5.580,00€ (Importe anualidad 1 y 2 semestre) 2/10/19 abonado 2.160.00€ (semestre 3) 11/11/2020 abonado 1.620,00€ (semestre 4) 2/4/2020 abonado 1.890,00€ (semestre 5) Tenemos pendiente de abono 1.350,00euros que corresponde al 6ºsemestre gracias ***************************************************** Por su parte envío a Alberto el siguiente email para compruebe los abonos del contrato de alquiler: Alberto, para cuando puedas mira en la cuenta del curatelado si le han abonado estos importes en su cuenta en las siguientes fechas: 11/11/2020 abonado 1.620,00€ (semestre 4) 2/4/2020 abonado 1.890,00€ (semestre 5) Dicen en el ayuntamiento de Málaga que les queda pendiente de abonar el 6 semestre por importe de 1.350€. En cuanto me confirmes hablaré con la prima Alicia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-02-24','Ana: Ayer acudió Gloria-Futuex a visitarla, en relación al informe médico que le pedí a Toni que solicitara para adjuntar a la solicitud de valoración de dependencia y centro. **Dice que necesita gafas nuevas, ya no ve bien y además los cristales están muy rallados. También necesitará un móvil, pues el suyo no funciona bien. *Le indico que lo prioritario son las gafas. No obstante que envíen presupuestos de ambas cosas a las sección económica de la CTAEX a través Gloria o de la propia óptica. Gloria les ha dicho que les puede acompañar (su madre iría también).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-24','Ana: Llamo a Pilar Martín, TS del ESM-CC: No puede atenderme en ese momento, me devolverá la llamada más tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-24','Ana: llamada de José Manuel, dice que "Le han llamado de Vodafone y le han convencido para pasar de tarjeta a contrato, había dicho que sí, pero después ha llamado para anularlo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-02-24','Ana: Correo de Alberto, jefe secc. ecca.: "Hola. Tal y como hemos hablado, la situación ECO de Valentina no es sostenible. Gasta al año 3.090 € x encima de sus ingresos. No tiene ningún gasto significativo excepto el centro: 900 €/mes. FERMAR, Logrosán. Ingresos: PN Orfandad Absoluta de 726,70 €/mes x 14. Ana: • Ver si es plaza privada o pública (para ver si merece la pena solicitar la PRxHC). • Posibilidad solicitar nuevos ingresos. • Averiguar si visita la casa o no: no es importante, pero si no lo hace daremos de baja la luz. URGENCIA: tienes tiempo ya que, a día de hoy tiene suficiente saldo > 13.000 € + un depósito. En cuanto tengas datos nos comentas y actuamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2021-02-25','Ana: Remito a Longina, TS del SSASB por mail (ssbmadrigalejo@hotmail.com) carta de revalorización de P. Orfandad de Isabel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2021-02-25','Ana: Remito a Longina, TS del SSASB por mail (ssbmadrigalejo@hotmail.com) carta de revalorización de Pensión de Clases Pasiva de Anita Priscila. *Queda pendiente la de PFHC, pero no la hemos recibido. ··············· **Puesto para registro de salida oficio-solicitud del mismo al INSS. ························································································································································································ Ana: Llamo a Guadalupe Fuentes Benito, coordinadora del Piso Tutelado de Madrigalejo (605 918 070) en relación al cambio pendiente de IFAS a la Seg. Soc., pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-02-25','Ana: Envío correo-e a Mª Jesús Gómez Lozano, TS de la Mancomunidad Comarca Trujillo (ssb32mancomunidadcomarcatrujillo@hotmail.com): "Buenos días Mª Jesús, Espero que estés bien. Tan sólo te escribo para comunicarte que ayer mismo redacté un oficio solicitud para solicita al INSS el Certificado de Pensión de Isabel, pues ya hemos recibido la carta de revalorización de la mayoría, pero el de ella, entre otras personas, no. En cuanto nos lo hagan llegar te lo remito escaneado. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-25','Ana: Llamo a Pilar Martín, TS del ESM-CC (927 213 730): NO consigo hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='VINAGRE'and apellido2='REY'),'2021-02-25','Ana: Recibo llamada de Maite, TS del IMAS de CC (618 068 375), en relación a este caso le han pedido desde del Jdo. que le acompañen a la comparecencia, pero dice que ellas no le conocen el caso. No han iniciado ellas el expte. de incapacitación ni han intervenido nunca con la Sra. Su compañera acudió un día al domicilio, pero nadie abrió la puerta. Preguntan si ya hemos intervenido o si sabemos como acceder a la Sra. Le indico que la CTAEX sólo ha aceptaco el cargo de Defensa Judicial con las atribuciones que constan en el Fundamento de Dcho. Tercero del Decreto de Nombramiento: "...defensa de Antonia Vinagre Rey en el juicio de incapacitación 298/19."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-25','Ana: Correo que remite Juana, secc. ecca. CTAEX, a la Res. Ntra. Sra. de la Luz de Malpartida de Plasencia (administracion@residencialaluz.com): "...Efectivamente se ha activado una transferencia permanente al centro por importe de 80 euros mensuales, para los gastos de Guadalupe. Les llegará a primeros de mes puesto que es para cuando se ha dado la orden. En ese importe deberán ir todos los gastos incluidos, está calculado teniendo en cuenta que cobra una PNC y el pago del 75% al centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-02-25','Ana: Según los datos de la Base de la CTAEX, Valentina no está valorada de Discapacidad y tiene un grado I de Dependencia. En el expte. digital no hay más datos. *Pte. revisar el expte. papel. ·············· Envío correo a la Residencia Femar (residenciafemar2019@gmail.com) a la atención de Pilar Manzano, Coordinadora de la Res. planteando diversas cuestiones en cuanto a su estado de salud, dependencia y vivienda y solicitando copia del DNI actualizado y tarjeta sanitaria. ············ Aún no han remitido Informe para la Rendición Anual del Jdo. que les solicitó Coral, secc. ecca. ····················································································································································································· Llamada de Pilar Manzano, coord. Res. (927 360 430): me enviará informes médicos así como copia del DNI y Tarjeta Sanitaria por emial. *En cuanto a la Dependencia, aunque hay que estar pendiente para el aseo y otras cuestiones, es relativamente joven y aún bastante autónoma. *Ha hablado con la TS del SSASB y no consideran que vaya a dar mayor grado. *De momento no solicitaremos revisión de dependencia por empeoramiento, a no ser que el contenido de los informes médicos así lo recomienden. En cuanto a la vivienda, en su opinión, no conviene dar de baja el suministro de luz, este año ha dejado de acudir a la vivienda por motivo de la pandemia, pero en cuanto puedan comenzar a salir con mayor normalidad, harán como hacían antes, ella misma le acompañaba hasta su casa con frecuencia y la dejaba allí un ratito mientras hacía otras gestiones. Le viene muy bien. ················· A última hora recibo los informes médicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2021-02-25','Ana: Tras hablar con Teresa, TS NOVAFORMA, remito a Alberto, jefe secc. ecca. el siguiente correo-e: "Buenos días Alberto, He recibido llamada de Teresa, TS de Novaforma (662 337 460). Están organizando una salida para las personas residentes en semana santa. Tendría lugar de Jueves a Domingo de la misma. El coste de la actividad son 200€. En mi opinión es conveniente que vayan a la misma. Las personas tuteladas/curateladas propuestas son: - Felipe Blanco Guisado - Fermín García Pablo - Eduardo Rivera Torío - Manuel Blázquez Sandoval *En el caso de que alguno de ellos no pudiera asumir el gasto, desde NOVAFORMA ofrecen adelantárselo y que se les abone poco a la entidad. Podéis poneros en contacto con ella las gestiones oportunas en el teléfono indicado o en la siguiente dirección de correo: trabajadorasocial.novaforma@gmail.com"','2');
