insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2021-02-25','En relación con la aceptación de las herencias de sus abuelos, D. Jacinto Díaz Antequera y Dª. Antonia Palacios Domínguez, el Juzgado de Primera Instancia e Instrucción, nº 2, de Zafra, en Procedimiento X37 487/2021, archiva el procedimiento. Hablo con el abogado Antonio Francisco Chávez Díaz y me dice que ha sido un error del Juzgado, porque no le dieron plazo para contestar a un requerimiento. Hablo con la Letrada del Juzgado (María Reyes Fernández-Palacios Oconnor, muy amable), y me dice que efectivamente, que el Juzgado cometió ese error y que recomendó al Abogado para que no recurriera a la Audiencia, debido a que tardarían más de un año en resolver. Que lo volviera a presentar el expediente, y que como iría al Juzgado de Zafra, intentaría rescatarlo para darle trámite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-02-25','TERESA RECBIO LLAMADA DEL SOCIOSANITARIO MANUELA ME PREGUNTA POR EL ASUNTO DE LA PUERTA YA QUE BEATRIZ LE INSISTE EN QUE LA TIENE QUE PAGAR LE COMENTO QUE SE HA COMUNICADO TODO AL JUZGAO Y ESTAMOS ESEPRANDO DELIVACION YA QUE ELLA EN SU DIA MANIFESTO QUE LA PUERTA LA HAN ROTO UNOS AMIGOS DE ELLA Y ESO ES LO QUE HEMOS COMUNICADO AL JUZGADO ANTE LA DENUNCIA INTERPUESTA POR EL EX DE BEATRIZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-02-25','TERESA ME LLAMA MARIA DE LA PROVIDENICA PIDIENDO INFOMRAMCION SOBRE MARIA ANTONIA YA QUE VAMOS A INGRESARLA DE FORMA INVOLUNTARIA EN ESTE CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-02-25','Ana: Llamada de Sara, TS del HUC (927 153 844): La Dra. Villaverde, por indicación del Dr. Caro, se ha puesto en contacto con ella y le ha dicho que Isabel ha sido operada en el Hptal. de Plasencia por el Dr. San Román, y que por tanto no entiende que haya acudido a la revisión al HUC. *Si no hay ningún motivo médico o de traslado domiciliario, no tiene que acudir a las citas ni operarse en Cáceres, sino en Plasencia. ····· Indico que Isabel está ingresada en el CSS y a mí no me han indicado que vayan a darle el alta próximamente. ···· Sara hablará de nuevo con la Dra. y me dirá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-02-26','Ana: Correo de ayer a última hora de Iberdrola, en respuesta al que envié: "Buenas tardes Ana: Le agradezco que haya contactado conmigo a través de este canal. En relación a su e-mail, para poder solicitar la protección del contrato es necesario que contacten en el siguiente e-mail, si es tan amable: clientes_vulnerables@iberdrola.es Quedo a su disposición para cualquier consulta que desee realizarme. Que tenga una buena tarde. " ·············· Reenvío el emial adjuntado de nuevo el testimonio de aceptación. *Indico así mismo que Iciar ya ha procedido a domiciliar de nuevo los recibos en la nueva cuenta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-02-25','Ana: Correo de Ana, Directora de la C.R. Cervantes (anaisabel.rasero@salud-juntaex.es): "Hola, buenos días. Tal y como hablamos ayer por teléfono, te describo la situación que está sucediendo con la residente del Centro Residencial Cervantes de Cáceres, dª Mª Luisa Montaña Alisada, con el objetivo de que quede constancia por escrito de ello. La residente , en la actualidad, continua teniendo un comportamiento no acorde con las normas establecidas en el centro. Está continuamente pidiendo dinero, alimentos, enseres y todo lo que los demás residentes poseen, de manera sistemática. Aunque es verdad que algunos le dan de manera voluntaria, hay otros que se sienten presionados ante la insistencia de la residente, pues no podemos olvidar que existe una diferencia de condición entre los demás y ella. Es por este comportamiento, por lo que se le ha intentado hacer cambiar de actitud, siendo infructuosos todos los intentos. En todo momento se ha contado con la hermana, Carolina, pues pensábamos que ella, quizás por mayor cercanía que nosotros, podría corregir los malos hábitos que la residente ha adquirido el tiempo que lleva entre nosotros, pero ha sido en valde. Actualmente, los profesionales del centro siguen trabajando con ella con el fin de corregirla y que llegue a tener una adaptación completa . El seguimiento es diario y si empeorase o no hubiese ningún cambio significativo de aquí a un tiempo prudencial , volvería a contactar con la Comisión Tutelar para una posible solución. Espero que se entienda la situación, pues a nosotros nos está creando múltiples problemas, que esperemos se solucionen pronto. Gracias. Un saludo. Ana Rasero Directora Centro Residencial Cervantes Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2021-02-26','Envío a Bankia de Plasencia, (mvegab@bankia.com, oficina_4601@bankia.com) Declaración de Herederos de su difunto marido, a los efectos de tramitar la testamentaría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-02-26','Ana: Remito correo-e a Toni-Futuex: "Buenos días Toni, Te reenvío correo de Ana, Directora de la Residencia Cervantes, en relación a Mª Luisa Montaña. ¿Sería posible que cuando la Educadora le haga el seguimiento periódico aborde estas cuestiones con ella para intentar un cambio de conducta? En principio, además de los intentos del propio centro, no se me ocurre qué otra cosas podemos hacer. Por cierto, en el correo no lo pone, pero por teléfono me dijo que iban a probar a “aislarla” una temporada en su planta, donde también hay sala común multiusos, pero donde se quedan menos personas habitualmente. A la planta de abajo sólo bajará al comedor y el resto del tiempo probarán esta estrategia con el objetivo de que reflexione sobre su actitud y comportamiento. Ya me vais diciendo. Un saludo y buen día." ························ Se lo comunico por mail a Ana, Directora del C.R. Cervantes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-02-26','miguel, nos reunimos Alberto y yo con Carlos Jurado nos tiene que justificar: -PENSION COINCIDE QUE SE LA ABONABAN EN ESA CUENTA -QUE PASÓ CON LAS Q DESDE 2016 A 07-20189(PERIODO EN QUÉ DEJARON DE ABONARSELAS) -ACREDITE LA VINCULACIÓN O IDENTIFICACIÓN ENTRE AMBAS CUENTAS Y FECHAS. -No sabemos donde recibe los intereses del depósito. -La cuenta de fondos del Santander 0049-4990-61-2616303312 está abierta desde 2-8-2018','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-02-26','Ana: En respuesta al correo de Toni-Futuex (areasocial3@futuex.es), consultando el alcance de sus funciones con Antonio, le envío correo co el siguiente contenido: "...En primera instancia justo esto que tú planteas: “planificar una visita para la semnaa que viene, de dos compañeras, y que pongan en contacto con la ts” e “intentar hacer una planificación de gasto con el, para que vosotros después hicierais orden al banco para las retiradas mensuales o cuando fuera” Por lo demás, en todo caso, visitas espaciadas en tiempo para hacer seguimiento puntual por si necesita algo y para saber si está bien. Y decirle a la TS del SSASB que puede ponerse en Contacto con la CTAEX si lo estima oportuno. Recordándole, eso sí, que se trata de una curatela económica, y de hecho, atendiendo al Fundamento Jurídico Primero del Auto de nombramiento, se refiere, sólo, al auxilio y complemento para determinados actos patrimoniales. En el expediente no hay sentencias ni ningún otro documento que nos pueda servir. La única información extra que te puedo facilitar es la siguiente: Antonio cuenta con un grado de discapacidad de 55% debido a trastorno de personalidad mental de etiología idiopática y trastorno cognitivo por diagnóstico desconocido, teniendo reconocido un grado III de gran dependencia. Percibe una pensión no contributiva de invalidez. De todas formas, decirte, que justo te estaba escribiendo cuando ha venido Miguel, Asesor Jurídico, a informarme, pues le pedí que llamara al Juzgado. Según le han dicho: de las ejecutorias no se desprende orden de alejamiento y por tanto este curatelado puede volver al pueblo, a su domicilio. En la actualidad no le constan ninguna medida pendiente. Que no es lo que nos había dicho la Trabajadora Social del C. Penitenciario. ..." ····························································································································································································· Respuesta de Toni-Futuex: "...las compañeras del equipo, van en principio a intentar hacer este seguimiento el lunes... a traves del contacto con la ts y bueno un pco una primera aproximacion, de contacto, y de investigacion, puede intentar hablar con ese vecino amigo, al que alude en la nota y con diferentes personas del entorno comunitario para obtener informacion y por supuesto intentar tambien contactar con el tutelado in situ, asiuqe te comentaria que tal y que se obtiene este mismo lunes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-02-26','Ana: Recibo llamada de Juan Carlos desde la UHDAC: se alegra de hablar conmigo, vuelve a preguntar por Pedro, le apena que esté "malito", dice que esta samana ha ido a terapia, musicoterapia, a pasear por el recinto y a la cafetería. **También cuenta que ha "hecho una cosa mal", se ha tragado la parte extraible de la pulsera de actividades (reloj). Ya lo ha expulsado. Dice que se puso muy nervioso, se lo quitó y se lo tragó. Quiere otro, prometiendo que no volverá a hacerlo. Pero se le explica que durante un tiempo no podrá ser, que debe ganarse la confianza de nuevo y desmostrarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-02-26','Ana: Llamo a Pilar Martín, TS del ESM-CC (927 213 730): En Geriatría han valorado que Clementa, no presenta Deterioro Cognitivo. ··········· En cuanto a la plaza, Pilar lo consultará con la compañera y me dirá algo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2021-02-26','Ana: Recibimos Resolución aprobatoria de Reanudación de Pagos de la PNC, con fecha de efectos de 1/11/20. Se le abonará en concepto de atrasos 1259,93€. ··············· Reenvío a Juana, Secc. Ecca., Resolución escaneada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-02-26','-Amalia : la semana pasada ingresó en Placeat , en plaza RAL en San Gil . EStá pendiente enviarle la documentación al centro y ver desde la part eco como se paga la plaza . Al día siguiente del ingreso pidió un taxi y una ambulancia para irse al CSS . Mala adaptación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-02-26','Ana: REGISTRO DE ENTRADA nuevo expte. de PFHC (Para personas jurídicas) así como Comunicación al INSS de cambio de domicilio "sólo a efecto de comunicaciones". ······················································································································································································ Correo de Toni-Futuex: "... esta pendiente elaborar el informe sobre Gregoria Moreno Bermudez, que se hizo la primera visita de seguimiento en Calzadilla, en el dia de ayer, tiene pendiente un juicio por la estafa de la que fue victima el proximo dia 8 en Plasencia, te madare escaneado todo lo que obtuvimos ayer y la citacion por si acaso no os hubieran dado traslado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-02-26','Ana: Correo de Toni-Futuex: "... Y luego tambien como significativo y alarmante (aunque bueno no se ya que mas podais hacer con el) Romero Mediavilla... se ha comprado un movil de cerca de 1000 eu, que paga cada mes 70 eu o no se que.. dice que le llamaron de vodafone y que lo ha cogido y que bueno que si le quitais la asignacion pues no pasa nada (en fin, increible) de todos modos se acaba de enterar la compañera porque lo ha llamado, va a redactar la nota y si podemos obtener el contrato o algo o intentar que lo devuelva y te lo enviaria mas completo. Bueno dice que el que tenia lo vendió ayer por 50 eu asique que ahora se queda con este que no tiene telefon.."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-02-26','miguel, llega burofax del abogado. Se lo doy a Angel porque creo que es del expte judicial que él está llevando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-01','Ana: Respuesta de Iberdrola (clientes_vulnerables@iberdrola.es) a última hora el viernes: Buenas tardes, Informarles que ambos contratos se encuentran protegidos hasta el 26/03/21 a la espera de que puedan realizar las gestiones oportunas para el pago de la deuda. Gracias y un saludo," ·············· Se lo comunico a Icíar y Alberto CTAEX. y a Carmen, TS del SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='QUINTIN'and edp.apellido1='SANCHEZ'and apellido2='ALAMILLO'),'2021-03-01','TERESA HABLO CON INSS DE BADAJOZ Y ME DICEN QUE EN MADRID TARDA MUHCO LA DOCUMENTACION QUE SE LAS ENVIE A ELLOS QUE HARAN EL CAMBIO DESDE AQUI','2');
