insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-02-26','Ana: Llamada de Sara, TS del HUC (927 153 844): La Dra. Marta, Jefa de Traumatología del HUC, le informa de que la última intervención fue en el hptal. de Plasencia y que por tanto, conviene que la placa se la retiren también allí, el mismo traumatólogo que la operó. *Además la lista de espera para CC es muy larga y le tocaría esperar mucho tiempo, motivo añadido para que acuda en Plas. *Hay que solicitar cita a su médico de Att. Primaria para que la derive al especialista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-01','Ana: Conversación telefónica con Estrella, TS del CSS-Plas.: le transmito la información facilitada por Sara, TS del HUC. *Pedirán cita al médico de Att. Primaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='OSCAR'and edp.apellido1='BLAZQUEZ'and apellido2='PEREZ'),'2021-02-25','Ana: Llamada de Mariví Clemente, TS CSS-Plas, en relación al presupuesto ya aprobado para la compra del audífono para Oscar. La remito a Juana o Belén, secc. ecca. para las gestiones relacionadas con la factura y compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-03-01','Ana: Llamada de Juan José (667 958 878), dice que se encuentra mejor,ayer fue al CRPS y por a tarde a comprarse ropa con la monitora. Dice que está "utilizando el dinero como Dios manda". Espera que pronto nos envíen informe favorable para que podamos probar a realizar sus retiradas de asignación de forma quincenal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-01','Ana: Llamada de José Manuel (678 150 472): dice que al final cogió el teléfono y que lo vendió y se compró otro más barato... Lo ha vendido 320 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-01','Ana: Intento contactar de nuevo con Fracisco, Hermano de Saturnino Miguel (630 211 717 // arroyomolinos@protonmail.com): El número está ocupado. ··· Le remito el siguiente coreo-e desde el ctutelar@: "Buenos días Francisco, Mi nombre es Ana, Trabajadora Social de la Comisión Tutelar de Adultos de Extremadura. He tratado de ponerme en contacto con usted en relación a su hermano en diversas ocasiones, pero no ha sido posible. Le facilito mi número de teléfono directo para que se ponga en contacto conmigo cuando pueda si lo estima oportuno: 924 93 02 45 Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-03-01','TERESA EMAIL DE ADISER Comunicarte que Aitor, tal y como se había acordado llegó con su PCR- el viernes. Desde su llegada al centro ha estado totalmente alterado con problemas de conducta. Y el sábado día 27 a las 18.30 aproximadamente tuvimos que llamar al 062 y a la policía porque se había escapado del centro. Lo trajo la policía sobre las 22.30 horas. Pregunté si por nuestra parte teníamos que hacer algo y me comunicaron que no al haber sido una fuga voluntaria, no obstante tengo solicitados los partes tanto de la guardia civil como de la policía local. Somos conocedores del problema de consumo que tiene Aitor, y las salidas al domicilio de su madre y su pareja provocan que este consumo se incremente, porque aquí en el centro lo tenemos controlado. Entonces dime si desde la comisión veis correcto que estas salidas al domicilio se pospongan hasta que veamos por parte de Aitor un cambio de conducta. Mañana día 2 tenemos cita en el CEDEX de Castuera, una primera visita con la trabajadora social para iniciar el tratamiento, aunque Aitor no es partidario. Intentaremos firmar con él una especie de contrato con el tema de los permisos para salir. Esa misma noche de la fuga y ante su estado de alteración y nerviosismo pegó un portazo en la puerta provocando que ésta se rompiera por la parte del manillar. He solicitado presupuesto del arreglo en cuanto lo tenga te lo remito igualmente. Dime si es necesario que te remita todos los partes de incidencia y el resto de documentación o es suficiente con este correo y con la remisión al SEPAD de la documentación. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2021-02-09','Ana: Llamada de Montse, TS Mancomunidad de Sierra de Gata (927 14 34 11): El expte. aún está en periodo de inventario. *Se le ha solictado informe social desde la CTAEX. Sandra presenta un grado de discapacidad del 41% (Psíquica, física y sensorial). Por trastorno del Dllo. y Disminución de la Eficiencia Visual. ··············· Estuvo tutelada por Serv. de Protecc. de Menores. ·· Acudió a la Universidad y sólo le queda una asignatura de 3º para finalizar el Grado de Derecho. Quiere seguir estudiando y finalizar, pero cuando cerraron el recurso en que residía en Cáceres (Asociación Católica), tuvo que volver a su pueblo al domicilio familiar y por eso no finalizó. ···· Percibe PFHC. ···· Está inscrita como Demandante de Empleo con Discap. ······ A día de hoy reside con su padre, quien asume todos los gastos. Ella tienen ahorrado todo el dinero de la prestación en su cuenta. *Su madre fue transeunte y se encuentra en paradero desconocido. ·············· Su padre tuvo Covid hace unas semanas, pero ella no se contagió. Estuvieron cada uno aislado en una parte de la casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-03-02','miguel, llega citación para el 4-3-21 vía lexnet. Intento hablar de nuevo con Jzdo nº2 de Cáceres y con Scace Mérida sin éxito para confirmar la citación. Iré el jueves 4-3-21 al juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-03-02','miguel, del procedimiento X06 de Remoción del cargo 452/20 llegó Auto nº 57/21 no firme de fecha 3-2-21 "que desestima la pretensión de Raúl su hijo en cuanto a su solicitud de remoción del cargo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-02','Ana: Llamada de Francisco, hermano de Saturnino Miguel (630 21 17 17). Me facilita otro nº fijo de contacto: 927 24 42 05). Pide que su hermano no pueda contactar directamente con su madre, pues es muy mayor (90 años) y está muy delicada de salud. A ella le han dicho que se encuentra en un centro adecuado para él por su enfermedad. ······· En cuanto al ingreso en prisión, le gustaría conocer más sobre la causa y hablar con el Asesor Jurídico. *Pediré al compañero que le llame al respecto, él le informará de lo que considere oportuno. ········· En relación al piso que le arreglaron y le tenían cedido, dice que Saturnino lo ha destrozado; sofá rajado con la espuma por fuera, paredes pintadas con múltiples colorines y frases, electrodomésticos quemados... Lo está limpiando y arreglando ahora.**Dice que ya no contemos con dicho piso a su salida de prisión, pues viendo los destrozos en pocos meses no se lo va a ceder más. ··········· Ha estado en contacto con Luz, TS del Módulo en que está "Nino". Y le ha comprado y llevado ropa interior. **Indica que se podría dar de baja el teléfono móvil. ········· **De momento está en prisión preventiva. Una vez tenga lugar el jucio, si se confirma la pena de prisión se dará de baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-03-02','miguel, hablo con el Jzdo nº2 de Zafra para preguntar por el procedimiento de aprobación de herencia+autorización de venta X15 nº129/20 y me confirman que está en trámite para que se inhiban y lo remitan a los juzgados de Cáceres. En este momento dicen haber dado traslado a MF y Ctaex para que en 10 días aleguen lo que entiendan a su derecho','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-02-27','miguel, llega por fax a aceptación de incoación de procedimiento de internamiento involuntario por el Jzdo nº3 de Plasencia, procedimiento X00 Jurisdicción Voluntaria (Generico) 66/21. También indican que procederá el examen por el médico forense','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-03-01','miguel, Buenos días, no nos han citado. Si necesitas cualquier cosa mañana estaré en la oficina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-03-02','miguel, tras conversación con Elena donde me confirma que verbalmente el MF le ha confirmado que solicitará pena mínima 2,5 años y penas accesorias (indemnización+orden de alejamiento). Me pide que le envíe un email indicando nuestra postura de la Ctaex e informe a Secretaría General (MªGuerrero), así que pongo un email con copia a Pedro y Mª Guerrero dirigido a Elena Simón de Abogacía General: Buenos días Elena, conforme a vuestra petición te confirmo por escrito la posición de la Comisión Tutelar de Adultos a la propuesta que realice la Fiscalía con respecto a la rebaja de la condena si existe conformidad de la otra parte, que tal como te ha verbalizado Fiscalía no sería inferior a 2,5 años, además de la correspondiente indemnización a favor de nuestra tutelada. A falta de saber concretamente, por vuestra parte, las condiciones de Fiscalía, y que tal y como te ha verbalizado ,a fecha de hoy, todavía no tiene propuesta de conformidad concretada, pero que como mínimo va a proponer los 2,5 años de prisión…, entendemos que debido a la falta de pruebas más concluyentes es buen resultado la condena y si es posible la correspondiente orden de alejamiento de su hermano. Tal como hablamos cuando Pedro Jefe de Sección de la Comisión Tutelar de Adultos, cualquier condena sería bien visto por la Comisión, siendo conscientes de que las pruebas prácticamente se reducían a la palabra de uno con la de otro. Es por ello que estamos de acuerdo con la propuesta que realice Fiscalía a efectos de lograr una conformidad en el procedimiento. Pongo en copia a Secretaría General por si tuvieran algo que añadir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2021-03-02','TERESA HOY SE INCIA LA OBRA DE MEJORA EN LA VIVIENDA DE CANDIDO HABLO CON LA TS PARA QUE MANDE ALGUN OPEARIO PARA TIRAR LO QUE NO VALGA APROVECHANDO LA BAÑERA QUE HA PUESTO EL ALBAÑIL QUEDA PENDIENTE PRESUPUESTO DEL PINTOR QUE ME FACILITARA EL ALBAÑIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-03-02','Ana: llamada de Jairo: expresa que Soraya Cobos, Directora del CSS, ha dejado de trabajar en el centro, pero "como últimas voluntades" antes de marcharse, dejó a la TS, Emilia, la reclamación de Jairo con las cosas que según éste necesita... Pide gafas nuevas, chándal y zapatillas. Le indico que es Emilia quien debe ponerse en contacto con la CTAEX para comunicarnos realmente que necesita y en su caso hacernos llegar los presupuestos oportunos. *Le indico así mismo que se dará prioridad a las gafas si relamente nos remiten un informe de la óptica en que se indice la variación en su graduación y/o el más estado de las gafas y necesidad de cambiarlas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-03-02','Ana: Recibo llamada de Crístofer (605 163 003) , Amalia le ha facilitado mi número y le ha explicado que a partir de ahora debe hablar conmigo. *Cristofer dice que está bien en el nuevo centro, que se está adaptando "poco a poco" y que ya ha hecho nuevos amigos. ······················································································································································································· Recibo llamada de Ana Amor - Placeat (630 616 022): Crístofer le ha dicho que ya ha hablado conmigo y le ha facilitado mi teléfono. *Los primeros días en el centro han sido un poco durillos, con tendencia a escaparse. Pero ya va mejor. Cree que se adaptará bien al recurso. Participa en actividades y parece más contento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-03-02','Ana: Llamada de Eloy, TS de Madroñera (662 54 55 10): se encuentran allí con él en el despacho Rafael y Gloria, Ed. Futuex. Se muestra muy contenta con la intervención de esta última. **Ya han hecho la PCR a Rafael. Están esperando el resultado y la confirmación de que puede ingresar en el centro. A priori Rafael parece que va a acceder a ingresar de forma "voluntaria". **Mañana van a acudir a visitar la Residencia de Alcuescar, de forma previa al ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-02','miguel, hablo con Francisco hermano del tutelado, a petición de Ana-DATOS DE CONTACTO:FRANCISCO 630211717, 927-244205, email: arroyomolinos@prontonmail.com. Le comento que no sabemos juzgado ni procedimiento del que se está llevando el procedimiento. Tampoco sabemos si existen otras denuncias y procedimientos abiertos. Me comenta que enviará las denuncias que tiene (ignora si están o no en algún juzgado) Revisará las cartas que le llegan al tutelado por intentar averiguar juzgado y procedimiento de supuesta violación por la que se encuentra en prisión provisional desde el 12-12-20. Se ofrece para estar autorizado en su cuenta y llevarle la cantidad que necesite (le explico que se le dan 50€/semana de los casi 500€ que le quedan tras gastos de iberdrola). Comenta que las necesidades son continuas ya que le ha desaparecido (no ha llegado a la carcel, su cartera con ropa limpia, incluso sus gafas de lectura). Quedamos que escaneará toda la documentación que tenga y me la remitirá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-03-02','miguel, solicito a Coral que cuando le llegue los documentos de certificado de últimas voluntades, certificado de defunción, me los facilite para tramitar tal como piden Amalia y Alberto la herencia de este tutelado fallecido, porque tenemos en la Ctaex dos de sus tres hijos tutelados.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-02-25','miguel, para tramitar la herencia de este tutelado a petición de Alberto y Amalia, ya que tenemos en la Ctaex 2 de los 3 hijos, solicito a Coral certificado de defunción y últimas voluntades: Buenos días Coral, me pide Alberto que tendremos que tramitar la herencia del tutelado arriba indicado fallecido. Por favor ves pidiendo certificado de defunción y últimas voluntades, y cuando te llegue acuérdate de avisarme','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-03-02','miguel, remito email a Mely: Buenos días Mely, acabo de hablar con el juzgado nº2 de Zafra por lo del procedimiento de aprobación de la herencia y autorización de venta y me comentan que ahora tienen que dar traslado de la inhibición (incompetencia) a Ministerio Fiscal y nosotros por si queremos alegar algo y posteriormente resuelve el juez y remiten el expediente al juzgado que corresponda de Coria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-02-24','miguel, hablo con Estefanía la abogada de la otra parte y la propongo que tramite la parte correspondiente de la Ctaex, para ello la envío la escritura de herencia del marido que se firmó ante el notario de Talarrubias D luis Pablo Sanchez Martinez con º de protocolo 75 de 26-1-2018. La estudiará y me contestará la próxima semana. En principio le parece bien para unificar actuaciones y criterios a seguir ya que hará falta autorizacion y aprobación de herencia y autorización de venta llegado el momento de los bienes. Además hay que poner de acuerdo a ambas partes que son usufructuarias para ver cómo afrontar los gastos de administración de los bienes hasta que se resuelva todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2021-03-02','Ana: Conversación con Ana Amor - Placeat (630 616 022). María Rosa está muy bien. Ha pasado unos días más tristes porque se ha enterado 10 días después que ha fallecido una tía suya (hermana de quién le cuidaba, "su madre"). Pero por lo demás está bien, contenta en el centro. Continúa participando en activdades varias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-02-26','miguel, correos de la deuda de alquiler de Damian intercambiados con su prima Alicia y con Antonio del Ayto de Málaga: Ingresos del inquilino que sepamos en la cuenta de Damian no hay… Hola Alicia, al ser una curatela reciente no sabemos los pormenores del acuerdo con el inquilino. Intentaré averiguar por mi parte lo que podamos y contrastarlo con vosotros… Una vez que tengamos una cifra si os parece lo ponemos en manos de la abogada para que interponga la correspondiente Demanda. Saludos cordiales. De: Alicia Cueto >aliciaasimas@gmail.com> Enviado el: viernes, 26 de febrero de 2021 14:05 Buenas Miguel, yo no tengo forma de comprobar los ingresos de Damian, y él dice que tampoco. Vuestra parte de gestión económica? Las cantidades restantes, te las envié calculando los compromisos del Ayto y las reducciones según contrato escribió: Buenas tardes Alicia, intenta concretar con Damian mes por mes las cantidades que tendría que haber abonado el inquilino. Hay que dirigirse contra él. Una vez lo tengamos claro y ya dejando al margen, entiendo al Ayuntamiento, lo pondremos si os parece en manos de la abogada Rocio. Saludos. De: Alicia Cueto >aliciaasimas@gmail.com> Enviado el: jueves, 25 de febrero de 2021 20:40 Acabo de mirar los ingresos y si no hay ingresos por parte del inquilino, este debería haber abonado 4.140€ Del año 19. La deuda sería de 1.800€ Del 20. 2.340€ Muy buenas, Lo que me dice Damian es que esas cantidades efectivamente se las ha pagado el Ayto. Lo que le falta por cobrar, sería el tanto por ciento que le corresponde al inquilino. Según aparece en el contrato, el Ayto asume un porcentaje que va reduciendo conforme aumenta el tiempo de alquiler. Es decir ellos van pagando menos, y el inquilino más. No tengo forma de verificar esto. Supongo que el resto de ingresos hasta llegar a la cantidad mensual acordada, debe aparecer igualmente en la cta de Damian. Entiendo que, de no ser así, la deuda sería directamente con el inquilino, no el Ayuntamiento. Cabe también la posibilidad de que Damian se haya confundido de manera más o menos consciente. Por favor, si podéis confirmarlo, quedaría la duda resuelta y habría que continuar con el siguiente paso que es, advertir de la finalización del contrato en la fecha prevista. Muchas gracias escribió: Buenas tardes, me confirma la parte económica de la Comisión Tutelar que los abonos del 2020 que abajo te indiqué ayer están correctamente abonados en su cuenta del Santander. Dicha cuenta ya ha sido cancelada tal como pidió Damián y ya he enviado email al Ayto de Malaga para que los abonos que resten se los abonen en su nueva cuenta de Liberbank. Quedo a la espera que me indiques qué más podemos ir haciendo. Saludos. Buenas tardes Alicia, desde el ayuntamiento de Málaga me remiten la siguiente y escueta información. Por favor, mira con Damian si esto es correcto y qué faltaría porque me aportaran e informaran desde el Ayuntamiento de Málaga. Gracias, saludos. Buenas tardes Los abonos realizados del expediente 1paa2388 son: 22/10/18 abonado 5.580,00€ (Importe anualidad 1 y 2 semestre) 2/10/19 abonado 2.160.00€ (semestre 3) 11/11/2020 abonado 1.620,00€ (semestre 4) 2/4/2020 abonado 1.890,00€ (semestre 5) Tenemos pendiente de abono 1.350,00euros que corresponde al 6ºsemestre gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2021-03-02','Ana: Pongo para la firma del D.Gerente, la solicitud de nuevo expte. de PFHC (modelo personas jurídicas). ························································································································································································· Realizo a Toni-FUTUEX, mediate email, derivación del caso para apoyo y seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2021-03-03','TERESA ENVIO PRESTACION SANITARIA CON ALTA A TERCEROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FALCATO'and apellido2='LEÑADOR'),'2021-03-03','TERESA ENVIO PRESTACION SANITARIA CON ALTA A TERCEROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-03-03','TERESA ENVIO POR REGISTRO ENTRADA CAMBIO DATOS BANCARIO PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-03-03','Ana: coreo-e de Amalia, TS CTAEX, dirigido también a los Asesores Jurídicos y a Alberto, Jefe Secc. Ecca. CTAEX: "Buenos días , me informan desde el Servicio Social de Atención Básica que según informan los vecinos ,en la casa de María han entrado una pareja de ocupa . La señora se derivó a Centro residencial en Cáceres y el marido , también tutelado ( Antonio H. ) falleció el año pasado. Hay una señora que pregunta si la casa se va a vender porque estaría interesada, claro cuendo estuviese desocupada" ························································································································································································································································································································· Respuesta de Miguel, Asesor Jurídico: "Buenas tardes, no veo el perfil económico de la tutelada, ya que dependiendo del mismo se podría acoger o no a un abogado de oficio. Necesitaríamos que la parte económica nos indique qué cantidades ingresa mensualmente y si tiene algún ahorro. Por mi parte, si no es estrictamente necesario vender no lo haría por el coste y tiempo que supone los tres procedimientos a interponer: 1. Procedimiento judicial de desahucio 2. Autorización para aceptar la herencia, posterior escrituración notarial de la herencia (ella es 50% titular de la cuenta del marido cuya cantidad se desconoce, según inventario, y 50% propietaria de la vivienda). Una vez firmada solicitaríamos aprobación judicial de la herencia 3. Procedimiento de autorización de venta, para lo cual tendremos que aportar tasación de la vivienda al juzgado. Por tanto y debido a la burocracia, dinero y tiempo, pensad si sería suficiente con interponer procedimiento judicial de desahucio de los ocupas. Recordemos que esta tutelada tiene 90 años."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-03','Ana: Llamada de José Luis, hermano de José Manuel: Su hermano ha vendido el otro móvil por el que pagó ciento y pico de € y se ha comprado uno por 16€. Ahora pide que se l compre otro, pues con ese no puede tener WhatsApp. Le indico que después de sus últimas compra-ventas sin autorización no se va a autorizar la compra de ningún otro móvil. ······················································································································································································ Llamada de José Manuel: más de lo mismo, el móvil, la asingación de 20€, el acceso a centro, el apoyo de la Educadora nueva (no le gustaba la nueva, pero ésta ahora se ha despedido de él y dice que le "ha abandonado"), el consumo de tabaco, su negativa a hacer tratamiento en el CEDEX para reducir el consumo...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-03','Ana: Llamada de Damián; de nuevo expresa su miedo recurrente a perder la plaza en el CRR. Abordo otra vez esta cuestión, se trata de un pensamiento recurrente y un miedo infundado, ninguna profesional (ni del ESM, ni del CRR, ni de la CTAEX)le ha dicho que esto vaya a ocurrir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-03-03','Ana: Llamada de Ceferino; ha solicitado ya por escrito esta mañana el traslado al CRR de Mérida. Lo ha hablado previamente con Javier, Director y Carolina, Psicóloga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-03-03','miguel, contestación a la petición realizada por la parte Social de Ctaex: Buenas tardes, no veo el perfil económico de la tutelada, ya que dependiendo del mismo se podría acoger o no a un abogado de oficio. Necesitaríamos que la parte económica nos indique qué cantidades ingresa mensualmente y si tiene algún ahorro. Por mi parte, si no es estrictamente necesario vender no lo haría por el coste y tiempo que supone los tres procedimientos a interponer: 1) Procedimiento judicial de desahucio 2) Autorización para aceptar la herencia, posterior escrituración notarial de la herencia (ella es 50% titular de la cuenta del marido cuya cantidad se desconoce, según inventario, y 50% propietaria de la vivienda). Una vez firmada solicitaríamos aprobación judicial de la herencia 3) Procedimiento de autorización de venta, para lo cual tendremos que aportar tasación de la vivienda al juzgado. Por tanto y debido a la burocracia, dinero y tiempo, pensad si sería suficiente con interponer procedimiento judicial de desahucio de los ocupas. Recordemos que esta tutelada tiene 90 años.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-03-01','TERESA RECIBO EMAIL DE MERCEDES PLENA INCLUSION Me pongo en contacto para comentarte dos asuntos de nuestra usuaria Beatriz Muñoz Ruíz. En primer lugar, comentarte que Beatriz mantiene contacto telefónico con su hija mediante videollamadas una vez por semana siendo la relación con la abuela de la niña positiva, pero Beatriz plantea la posibilidad de hacerle una visita presencial puesto que la niña le pregunta frecuentemente qué cuándo va a ir a verla. En caso de que autorices la visita, habría que organizarla para hacerla al aire libre y respetando en la medida de lo posible las normas de seguridad, aunque será muy complicado mantener la distancia puesto que se trata de una menor y de una madre que no ve a su hija desde agosto. En segundo lugar, te comento que Beatriz tiene consultas periódicas en Planificación Familiar y tiene pautado un anticonceptivo inyectable trimestral y que cada vez que le toca inyectarse se pone muy nerviosa con temblores y resulta muy difícil ponerselo. Ahora tenemos el problema añadido de que han dejado de distribuirlo a las farmacias españolas y no tenemos posibilidad de conseguirlo, con lo cual las alternativas que nos plantean desde el equipo de Planificación Familiar es bien la píldora diaria, el parche mensual o el implante para tres años. Beatriz nos ha comentado tanto a la psicóloga de Centro Ocupacional como a mí que quiere hacerse la intervención quirúrgica consistente en la ligadura de trompas. En el expediente de Beatriz consta un AUTO de 28 de julio de 2017 en el que entre otros asuntos, se dicta lo siguiente: "b) se libre oficio al SES para que, en el momento del parto, se suministre a Dª Beatriz de medios anticonceptivos permanente con el fin de evitar embarazos no deseados futuros. Yo te traslado la decisión de Beatriz y ya me decis porque soy conocedora de que dicha intervención la tiene que autorizar un juez. Seguimos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-03','Ana: Correo de Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Comenté en la reunión de unidad la propuesta de Traumatología de Cáceres de que pidiéramos cita en Atención Primaria para que la citen de Traumatología de Plasencia. Me dicen que esto ya se intentó y se negaron los de Plasencia, que deben ser los de Cáceres los que se lo deriven a los de Plasencia directamente..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-04','Ana: Reenvío a Sara Pozo, TS del HUC (sara.pozo@salud-juntaex.es), el correo de Estrella y le pido de nuevo su colaboración para mediar con la Jefa de Traumatología o por lo menos que me facilite su número. ··························································································································································································· Respuesta de Sara Pozo, TS HUC: "...Acabo de hablar con Marta Villaverde y me ha dicho que vale, que ella lo va a canalizar. No creas que dan muchas explicaciones, por eso el tema se enreda y se tarda en solucionar. Estamos en contacto a ver si por fin arregla. No es ninguna molestia, cualquier cosa que yo pueda hacer ya sabes que estoy a tu disposición." ····························································································································································································· Se lo comunico a Estrella, TS del CSS-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-03-03','Ana: Correo de Toni-Futuex: "Buenas de nuevo Ana, te adjunto, información recogida ayer, y te actualizo porque la compañera ha asistido en el traslado que hoy finalmente se ha producido el ingreso de Rafael en Alcuescar, te paso nota, en cuanto la tengamos, pero se ha producido con normalidad, se ha montado en la ambulancia y la compañera lo ha acompañado con el coche y ha estado alli cuando ha llegado y todo sin novedad, ahora a ir adaptandose poco a poco. Te actualizo lo del ingreso en cuanto lo tengamos" ····························································································································· *Guardo en el expte. la nota de Futuex informando sobre todas las gestiones realizadas: Comparecencia ante el Jdo., PCR y gestiones previas al ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-03-04','miguel, nos confirman días anteriores que estamos citados para que acudamos a judicio donde va como testigo la curatelada, en procedimiento del juzgado de lo penal nº1 de Plasencia, procedimiento abreviado 486/20 por delito de apropiación indebida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2021-03-04','ICIAR: LLAMO A MONTSE TS DE LA MANCOMUNIDAD, LOS JUEVES SE ENCUENTRA EN PERALES DEL PUERTO- 927514164. NECESITAMOS EL DNI ACTUALIZADO DE SANDRA PARA PODER FACILITÁRSELO A LIBERBANK. ANTE LA IMPOSIBILIDAD DE PONERNOS EN CONTACTO CON LIBERBANK DE HOYOS LE HEMOS ENVIADO TODA LA DOCUMENTACIÓN PARA EL BASTANTEO A JUANA HERAS DE LIBERBANK MÉRIDA, A VER SI ELLA PUDIERA HACER ALGO PUES DESCONOCEMOS EL ESTADO DE SUS CUENTAS. VOLVERÉ A LLAMAR ALO LARGO DE LA MAÑANA A MONTSE PUES EN ESTE MOMENTO NO PUEDE ATENDERME','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-03-04','Solicitamos por correo electónico al Juzgado de Montijo (tomas.leon@justicia.es), testimonio de la firmeza de la resolución del procedimiento X00 (362), relacionado con el tratamiento hormonal para cambio de sexo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-02-24','Ana: Correo de Mariví Clemente: "Disculpa la tardanza en la respuesta, Juan está vacunado, tiene las 2 dosis puestas. Hoy he enviado a la residencia de Casas de Dº. Antonio la documentación básica que me han pedido, al siguiente email, por si quieres tenerle para vuestro conocimiento: administracion@centrodemayoressierradesanpedro.es El traslado de Juan sería el día 8 de marzo, al cumplir el 7 se tendría que ir ese día, pero como es domingo dejamos la salida para el lunes. El teléfono del Centro es 927 38 32 58. Los responsables son Modesto, con el que hemos hablado y María es la T.S. Al tener mucho equipaje, una guitarra y bastantes cosas de uso personal, acumuladas durante estos años de estancia en el CSS, el traslado proponemos hacerlo en taxis. Tiene dinero ahorrado (Durante la pandemia no ha salido de aquí y por tanto no ha gastado) y podría pagárselo, sin sacar nada de su cuenta. Seguimos en contacto, si necesitaras cualquier aclaración o información de cómo vamos con los trámites no dudes en llamarme."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-03-04','-Amalia : Pedro ingresó ayer en la R. M. Los Olivos en Mérida , con PCR negativo , tras ser expulsado de Caser Residencial Olivenza por incumplimiento de normas de régimen interno . Este ingreso se plantea provisional , máximo 1 mes , al ser inviable económicamente , llegando a los 1600€/mes . La familia está valorando otros centros más económicos o la opcion de irse en alquiler con supervisión de un sobrino. Hablo con Vanesa , Subdirectora de Los OLivos para aclarar la situación de Pedro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2021-03-04','ICIAR: CONSIGO HABLAR CON MONTSE, LE DICE A SANDRA QUE PASE MAÑANA VIERNES POR LIBERBANK A DIGITALIZAR SU DNI. NOS ESCRIBIRÁ PARA CONFIRMAR QUE SE HA REALIZADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-03-04','Ana: Remito correo-e a Alberto, Jefe Secc. Ecca, y a Julio y Juan Pedro, Adtvos. CTAEX, comunicando el ingreso de Rafael en Res. de Mayores. Facilito los datos de contacto para que desde la secc. ecca. se pongan en contacto con el centro para lo relativo a cuestione económicas. ·········· Residencia de Mayores Amada Corral de Alcuéscar. C/ 3 de abril. Telf. Directora: 699 19 81 86. ························································································································································································ Nuevo correo de Toni-Futuex: Con información detallada del ingreso. *Lo guardo en el expte. **Me facilita más datos de cotnacto de la residencia: Los contactos de la residencia son los siguientes: • Rosana (directora): 699 19 81 86 • Inco (gerente): 601 64 48 86 • Residencia Amada Corral: 927 83 00 42 En cuanto a la cuota que debe abonar, comunicaron que creen que es el 75% de la pensión, pero eso lo realiza la trabajadora social de la localidad, por lo podeis contactar con María (927 38 40 02) para consultarlo y gestionarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-03-04','miguel, nos comunica la letrada de la Junta Elena Sanchez Simón que no ha habido conformidad y por tanto continúa el juicio: Buenas tarde, no ha habido conformidad. El acusado no reconoce los hechos Notificaran señalamiento de día para el juicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-03-04','Ana: Llamada de Cristofer (605 163 003), dice que tiene "muchas cosas en la cabeza y un nugo garganta", dice que quiere irse a "un centro cerrado". Que se acuerda de su madre y se siente mal y se agobia. Se desahoga un poco. Le pregunto si ha hablado con alguien del centro sobre cómo se siente y dice que sí, que con Ana Amor. Le indico que eso está muy bien, que es lo que debe hacer, que en el centro le van a ayudar. Que además debe tener paciencia, pues lleva poquitos días y es normal que le cueste adaptarse a los cambios. Volveremos a hablar otro día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-03-04','Ana: recibo llamda de Chema, PPTT Menores Cerujovi (649 676 149): Le remitiré el Acuerdo de Autorización General de Salidas para las salidas habituales del recurso. En cuanto a la Semana Santa plantean que pueda irse a Toledo con su hermano, éste reside en casa de su tía, quién se haría responsable durante la estancia. A Darío le vendría muy bien, lleva casi tres años sin poder ver a su hermano, con quién tiene buena relación. *Lo pedirán por escrito. ····················································································································································································· Pongo la autoriazación gral de salidas para la firma electrónica del D-Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2021-03-04','Ana: Envío email a Toni-Futuex: "Buenos días Toni, En relación a Sandra Sandín, me comunican las compañeras de la secc. económica, que, a su vez, le han comunicado desde la entidad bancaria en la que Sandra tiene la cuenta, Liberbank, que tienen el DNI de Sandra caducado, por lo que debe acudir al mismo a digitalizar el actual (tiene uno con fecha de validez hasta marzo de 2023, o al menos nosotros tenemos copia de éste facilitado desde el SSASB). Estaría bien decírselo e incluso si fuera posible acompañarla. Gracias y buena mañana." ························································································································································································ REGISTRO DE ENTRADA en el Registro ORVE-SIR, la solicitud de nuevo expte. de PFHC (modelo personas jurídicas).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-03-05','miguel, a petición de Ana, indico a Toni de Futuex que acompañen a la curatelada y la pido información de la vista del lunes: Buenos días Toni, el lunes día 8/3/2021 nosotros intervendremos por videoconferencia. Si es posible sería bueno que alguien acompañase a la curatelada. No tenemos información alguna del objeto de procedimiento. Necesito toda la información posible de la vivienda (escrituras, notario ante el que se firmó, forma de pago de la venta). Nosotros no tenemos información ninguna. Si no hay documentación al menos a ver si puedes preguntarle al respecto y enviárnoslo por email. Si acaso en el lunes necesitara un abogado solicitaré la suspensión del procedimiento hasta que le nombren uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2021-03-05','Ana: Tras habernos comunicado Mariví que la Declaración Anual de Pensiones, la han remitido al CSS, cumplimento Comuniación de Variaciones, indicando Domicilio a Efecto de Comunicaciones, solicitando nos remitan todas las comunicaciones oportunas. *Pongo para la firma digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-03-05','Ana: Envío correo a José María Gallego, "Chema", Coordinador del PP.TT. de Menores de Plas. gestionado por la Entidad Cerujovi (jm.gallego.coordinacion@gmail.com) el siguiente correo con documento adjunto: "Buenos días Chema, Tal y como acordamos te remito adjunta la Autorización General de Salidas. Quedo a la espera de vuestra solicitud de salida en Semana Santa, para que los compañeros jurídicos puedan valorarlo, dada las circunstancias sanitarias actuales. Entiendo que habrá que esperar también las directrices desde Salud Pública y los respectivos Gobiernos, tanto autonómicos como estatal. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-03-05','Ana: Llamada de Cristofer (605 163 003), hoy se encuentra mejor. Ha estado en los talleres y ahora estaban al aire libre haciendo cosas también. Se le nota mejor tono de voz y humor. Se le anima a seguir participando en las actividades, seguro que cada día se encuentra un poco mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-03-05','Ana: Sandra, TS de la Res. Patronato de Coria, me remite por mail (alexandra.alfonso@coria.org *Usar este mail a partir de ahora) el informe médico para la solicitud de la Unidad Móvil de la Policía para la "renovación" del DNI. **Cuando la hija de Rosario le envíe el Cdo. Literal de nto. realizaré todas las gestiones pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-05','Ana: Tras hablar con Miguel, Jefe Secc. Control de Pensiones INSS (927 62 00 49). Le envío correo a Carmen, TS SSASB Coria (carmen.martinez@coria.org): "Buenos días Carmen, Comentarte que acabo de hablar con Miguel, Jefe de Secc. De Control de Pensiones del INSS. Me confirma que se rehabilitaron las 2 pensiones y se dio la orden de pago el día 18 de febrero. Pero que no es de extrañar que aún no se le haya hecho efectivo en su cuenta, que viene tardando unos 20 días… Hemos comprobado el número de cuenta con el certificado del banco y está bien también. Me dice que si a final de la semana que viene, siguen sin ingresárselo, que vuelva a llamarle… Pongo en copia a Icíar para que esté también al corriente y para que esté pendiente de los movimientos bancarios la semana que viene, a ver si por fin se lo ingresan. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GALLARDO'and apellido2='GONZALEZ'),'2021-03-03','EXITUS. COMUNICAN DESDE EL CENTRO SU FALLECIMIENTO EL 03/03/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-03-05','conclusiones reunión a 4 de Alberto, Miguel, Juana y Amalia: En relación con la situación del cutatelado JUAN CARLOS RUBIO GALÁN y la situación económica en la que se encuentra, que afecta también a su madre y también tutelada, ROSA GALÁN MERINO, nos reunimos telefónicamente, el día 05/03/2021: Amalia (Área Social), Miguel (Área Jurdídica) y Juana y Alberto (ambos del Área Económica): Se pone de manifiesto la crítica situación económica de Juan Carlos, que se verá aún más afectada por el ingreso en un centro, dado que no dispone de recursos económicos que le permitan pagar el coste de la plaza, sus gastos de bolsillo y los gastos asociados a sus 2 viviendas (una de las cuales está afectada por un préstamo): Se acuerda contemplar como primera opción alquilar la vivienda en la que hasta ahora residia Juan Carlos, e iniciar los trámites que nos permitan averiguar si es posible la venta de la otra vivienda (protección oficial) y en caso de ser posible, proceder a ello. Se realizarán: • Area eco: solicitar certificado deuda pendiente prestamo vivienda social ibercaja. • Area Juícia: hablar con vivienda (Inma Vivienda Badajoz) para averiguar si es posible proceder a la venta de la vivienda de protección social y como. • Amalia: tratar el tema del alquiler vivienda en la que reside Juan Carlos: 250 €/mes alquiler + fianza + Condonación 1º mes por arreglos vivienda • Amalia: Disminución gastos farmacia Se hace constar que la madre de Juan Carlos, temporalmente, debe seguir colaborando en el pago del préstamo de su hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-03-05','Ana: Correo de Felisa Custodio, TS del CAMF-Alcuéscar (trabajador_social_alcuescar@imserso.es): "Hola Ana, te adjunto correo de la Trabajadora Social del Ayuntamiento de Alcuéscar en relación al "novio" de la residente y tutelada por la CTAEX Isabel Debón. Se trata de un señor que hace poco reside en Alcuéscar y ha solicitado ayudas económicas de carácter económico según me dice la Trabajadora Social. La propia residente ha contado que su novio tiene antecedentes penales aunque ya ha cumplido condena por ello. Existe el rumor aunque no tengo confirmación de ello que este señor tiene otra pareja en el pueblo. Mantienen desde hace un año una relación solo por wapsa ya que el centro ha estado cerrado por la pandemia. El caso es que se quieren casar por lo que puedes leer más abajo, por lo que ruego me confirméis que estando incapacitada legalmente ello no es posible o no lo podéis autorizar o cual es el protocolo. Muchas gracias. Saludos. Pd. pongo copia de este correo a mi Directora porque es un asunto del que también está pendiente." ······················ Correo que le remitió María Álvarez Feria, TS del SSASB (tsocial7@mancomunidadsierrademontanchez.es): "BUENOS DIAS FELISA, VIENE AL AYUNTAMIENTO D. SEBASTIAN ALZAS MARIN, NOVIO DE MARIBEL LEBON, A COMUNICAR QUE QUIEREN CASARSE PERO QUE COMO MARIBEL ESTA TUTELADA QUE NO SSABEN CÓMO HACERLO. DICE QUE EN MULTITUD DE OCASIONES LE HA DEJADO SU NUMERO DE TELEFONO A LA ADMINISTRATIVA DEL CAMF PARA QUE TE LO DÉ Y QUE NO CONSIGUE QUE LE DEVUELVAS LA LLAMADA... TE ADJUNTO TELEFONO MOVIL PARA QUE OS COORDINEIS ENTRE VOSOTROS EN ESTA CUESTION SEBASTIAN: 642 27 02 27 GRACIAS, UN SALUDO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-02-18','Ana: Correo de Alfredo Moreno, Res. Plasenzuela (resiplase@gmail.com): "Buenos días. Nos ponermos en contacto con Ustedes para informarles que el paso martes 16/02/2021, se deriva a Urgencias del Hospital San Pedro de Alcántara de Cáceres a Doña ANTONIA SERRANO SUAREZ (Tutelada por Ustedes). El motivo de derivarla es poe enemas en miembros superiores y pulmonar. Ayer día 17/02/2021 nos comunican que de momento lo que le han detectado es una CARDIOMEGALIA (Corazón Grande) y que de momento la quedan ingresada. Si vamos recibiendo alguna noticia más se los comunicaremos. Un Salduo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-03-02','Ana: Correo de Alfredo Moreno, Res. Plasenzuela (resiplase@gmail.com): "Buenos días. Les comunicamos que ayer 01/03/2021 se produce el alta hospitalaria de Doña Antonia Serrano Suáres (Adjuntamos Informe de Alta). Un Saludo." ·············· Guardo informe en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-03-08','Ana: Envío correo-e a Alfredo Moreno Cebrian, en relación a los útlimos correos remitidos al ctutelar@: "Buenos días Alfredo, Gracias por mantenernos informados. Pedirte, eso sí, que para este tipo de cuestiones mejor me escribas a mi dirección (desde la que te contesto a este correo), para que no se me escapen, el otro lo usan más las secciones económica y jurídica. Por cierto, hace ya 2 años nos planteamos solicitar revisión del grado de dependencia. Hablando con Natalia acordamos que solicitarían cita al Médico de Familia para Antonia para que le derivasen a los servicios de Neurología y a Psiquiatría para valoración y si con los informes emitidos por éstos fuera pertinente se solicitaría desde aquí, adjuntando los mismos, la Revisión del Grado. No sé en qué quedó, pues no nos llegasteis a informar ni a enviar nada al respecto (que yo sepa). Por cierto, ¿sigue presentando alteraciones de conducta? Un saludo y buen día." ························································································································································································ Respuesta de Alfredo: "Buenos días, Ana. Nos se solicitó la revisión de Grado, puesto que ella está ocupando una plaza pública y tenga el grado que tenga lo que le van a hacer es mantener la plaza pública, por lo tanto la situación tanto para ella, como para la residencia va a ser la misma tenga el grado que tenga. De todas formas si pensáis que lo tenemos que solicitar me lo dices y la semana que viene (esta me es imposible) empezamos los trámites para la revisión de Grado. Un Saludo." ··························································································································································································· Mi respuesta: "Buenos días de nuevo Alfredo, Nosotros no tenemos mayor interés, tan sólo te preguntaba porque aquello quedó pendiente y no hemos vuelto a saber nada. Todo surgió a raíz de las incidencias acaecidas. Si vosotros, que la conocéis mejor y la atendéis en su día a día, consideráis que no es necesario lo dejamos estar. En cuanto a las alteraciones de conductas, puesto que no mencionas nada, supongo que está más tranquila y no han vuelto producirse incidencias. Ante cualquier cuestión, seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-01-11','Ana: Correo de Alfredo Moreno, Res. Plasenzuela (resiplase@gmail.com): "Buenas tardes. Les informo que el próximo miércoles 13/01/2021 procederán a la Vacunacion del COVI-19 en la Residencia "Padre Damián", se procederá a vacunar a sus 57 Residentes y a sus 24 Trabajadores/as. El motivo de informarles sobre esta vacunación porque en los Residentes se encuentran Dña Rosa Marín Laureano y Doñ Antonia Sánchez Serrano de las cuales la Comisión Tutelar de Adultos es su tutor. Para más información, pueden ponerse el contacto con el Teléfono 619 459 281 (Alfredo Moreno)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2021-01-11','Ana: Correo de Alfredo Moreno Cebrián, Res. Plasenzuela (resiplase@gmail.com): "Buenas tardes. Les informo que el próximo miércoles 13/01/2021 procederán a la Vacunacion del COVI-19 en la Residencia "Padre Damián", se procederá a vacunar a sus 57 Residentes y a sus 24 Trabajadores/as. El motivo de informarles sobre esta vacunación porque en los Residentes se encuentran Dña Rosa Marín Laureano y Doñ Antonia Sánchez Serrano de las cuales la Comisión Tutelar de Adultos es su tutor. Para más información, pueden ponerse el contacto con el Teléfono 619 459 281 (Alfredo Moreno)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-08','miguel, remito email a Ana y Alberto, tras conversación con Damian: Buenos días, tras conversación telefónica con Damian creo que ya podemos dar solución al tema del arrendamiento. Él ha hablado con Loreto que lleva el tema de viviendas de alquiler del Ayuntamiento de Málaga 951-926010. Me comenta que Antonio, que es el que nos indicó los pagos que se habían hecho de alquiler no es el que realmente lleva su expediente, siendo Loreto la jefa. En definitiva que Loreto le pide que para el abono del 6 y último semestre requiere que le enviemos a ella una autorización de la Ctaex solicitando que le hagan el abono de los 1.350€ en la cuenta de actual de él de Liberbank ES 08-2048-1086-12-3400079002. Podéis mandarlo al siguiente email a la A/A de Loreto. Email: imv.paa@malaga.es En otro orden leyendo el contrato y hablando con Damian ya tengo controlado lo que le debe el inquilino, por lo cual ya puedo hablar con su abogada en Málaga Rocío (recomendada por su prima Alicia y el propio Damián) para que ponga en marcha la reclamación de cantidad y si fuera preciso el desahucio judicial del inquilino. Según contrato de arrendamiento de 1-8-2018 (que os adjunto por si queréis ojarlo, y que está en su carpeta virtual, arrendamiento. Como digo esto es lo que tenía que haber abonado el inquilino: 1ª semestre 0€ 2ª semestre 45€/mes 3ª semestre 90€/mes 4º semestre 135€/mes 5º semestre 180€/mes 6ª semestre 225€/mes Según he hablado con él sólo ha recibido del inquilino 3 abonos de 45€ de fecha 27-6-2019, 19-6-2019, 15-4-2019. Por tanto le debe: 1ª semestre 0€ 2ª semestre: 135€ 3ª semestre 540€ 4º semestre 810€ 5º semestre 1.080€ 6ª semestre 225€/mes, por tanto de Marzo de 2021: 225€ TOTAL=2.790€ a los que habrá que sumarse los intereses de demora y las costas procesales por mala fe. En conclusión: -Alberto confírmame que puedo contratar los servicios de la abogada cuyos honorarios desconozco pero ponle 1.200€ (quiero hacerla el encargo hoy mismo) Y la parte económica preparad dicha autorización dirigida al Ayuntamiento de Málaga y enviarla al email indicado a la atención de Loreto. Una vez recibáis el abono bien la parte económica, bien la social me pide le enviéis un email al propio Damian para que se quede tranquilo. Cualquier duda me decís.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-03-08','Ana: Subo al portafirmas digital la Solicitud de Desplazamiento de la Unidad Móvil de la Policía Nacional para la gestión del DNI de Rosario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-03-08','Ana: Adelanto escaneado por mail a Sonia Bernabé - Asindi, el documento que nos remitió relativo a la protección de datos para aquellas personas que se inscriben por primera vez a participar en los JEDES, ya visado por Ángel, Asesor Jurídico, debidamente firmado por el D-Gerente. ··················· *Se envía también por correo certificado.','2');
