insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2021-03-08','-Amalia . Ha vuelto a ingresar en el hospital , aviso a su hija y se vuelve a poner cuidadora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-03-08','Amalia : Me llama Cristina Sudon ,su tío sigue muy ansioso y agresivo en Los OLivos y le han comunicado que lo van a expulsar. Hablo con la residencia ( Vanesa ) que me dice lo mismo . De madrugada han llamado al médico , le han puesto calmantes pero no lo han derivado a UHB pq no estaba agresivo . Opinan que necesita ingreso en psiquiatria o en R. M. con unidad de psiquiatria . Hablo con Ana MOreno , está en posicion plaza publica en Barcarrota pero si está expulsado no se la pueden dar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-03-08','TERESA RECIBO EMAIL DE FUTUEX PEDRO TOMAS SE ENCUENTRA INESTABLE, SU PAREJA HA INGERIDO PASTILLA Y HA SIDO INGRESAADA EN EL SOCI DE MERIDA, PASARA A UHR Y POSTERIOMENTE A CRR PEDRO TOMAS ESTA CONSUMIENDO ALCOHOL Y SE SOSPECHA QUE OTRAS SUNTACIAS, NO TIENE DINERO Y DEBE EL ALQUILER TELEFONO CASERO JESUS 625494248 ESTA PANGANDO UN SEGURO DE 500 EURSOS, ARCHIVO EN SU EXPDT NOS MANDA INFORME SOCIAL DESDE EL SSB EN EL QUE PROPONE INRESO EN CENTRO SOCIOCANITARIOÇ SE LO COMENTO A MIGUEL PARA QUE PISA AUTORIZACION INGRESO EL CCUAL ME PIDE INFORME DE SALUD MENTAL ARCHIVO INFORME SOCIAL EN SU EXPEDITE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2021-03-08','Buenos días , JOSE RAMIREZ , curatela ingresado durante años en un centro en la zona de Montijo de tratamiento para deshabituación de drogas, ha salido del mismo . Pasa a residir en el domicilio familiar en la zona de San Roque en Badajoz. ( INDICAR CAMBIO EN LA BASE DE DATOS ) Totalmente libre de drogas , durante años sin recaídas y muy compensado. Los padres solicitan un cambio para poder sacar el dinero de cuenta . Se mantendrá la misma cantidad , 800€ al mes , que administrarán sus padres . Irá acompañado con uno de ellos para el reintegro , os paso los datos : Padre: Fco. García García DNI 8720815C Madre : Antonia Ramírez Hernández 8725110Z Irán a la oficina de Ibercaja en la Avda. Ricardo Carapeto , San Roque , en Badajoz. Sigue el seguimiento médico en ESM DE Montijo , lo lleva su padre a las citas . Cada 3 meses se pone insyectable . Los padres se encargan de este seguimiento. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='CARNERERO'and apellido2='CARRILLO'),'2020-05-12','Ana: Según informe social del CSS para la rendición anual: "Julio Carnerero Carrillo continúa ingresado en el Centro Sociosanitario de Plasencia, desde el 26 de octubre de 1967. Sin contactos familiares. Tiene cuatro hermanos. Sin cambios con respecto al año anterior."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-08','miguel, remito email a la abogada Rocio: Buenos días Rocío, si puedes necesito hablar contigo a partir de la 13h. Necesito nos indiques aproximadamente tus honorarios para el caso de Damian para la reclamación de cantidad por impago de alquiler y posterior desahucio del inquilino. Nos ha hecho mucho hincapié Damian de que no quiere que se le renueve el contrato por lo que cuando le remitas el burofax así se lo deberás hacer constar. Tras hablar con su prima Alicia, y hoy con el propio Damian y leyendo el contrato ya tengo las cantidades que se le deben. Te adjunto contrato de arrendamiento. Según contrato de arrendamiento de 1-8-2018 esto es lo que tenía que haber abonado el inquilino: 1ª semestre 0€ 2ª semestre 45€/mes 3ª semestre 90€/mes 4º semestre 135€/mes 5º semestre 180€/mes 6ª semestre 225€/mes Según he hablado con él sólo ha recibido del inquilino 3 abonos de 45€ de fecha 27-6-2019, 19-6-2019, 15-4-2019. Por tanto le debe: 1ª semestre 0€ 2ª semestre: 135€ 3ª semestre 540€ 4º semestre 810€ 5º semestre 1.080€ 6ª semestre 225€/mes, por tanto de Marzo de 2021: 225€ TOTAL=2.790€ a los que habrá que sumarse los intereses de demora y las costas procesales por mala fe. Y lógicamente si deja desperfectos también le sean reclamados. Necesito que lo antes posible lo pongas en marcha y me digas tus honorarios para verlos con la parte económica y qué documentación necesitas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-03-08','miguel, voy a videoconferencia pero nos comunican que no es necesario que entremos porque ya han llegado a una conformidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-03-08','-Amalia : he puesto en firma la soliictud de extranjeria , y una autorización para el centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-03-08','-Amalia : puesto en firma PFHC . Falta la P. orfandad de Sole y lo enviaré todo al CAISS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-03-08','-Amalia : percibe PFHC , Sole enviará la P. orfandad y la pondré a firma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-09','miguel, recibo documentación en mi email del hermano del tutelado, recibos de móviles, un embargo y una multa. El único que me sirve es el de asignación de abogado de oficio por el Colegio de Cáceres, pero no indican cuál es el abogado. Le indico que sólo me envíe documentos de juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2021-03-09','Ana: Intercambio de correos con Novaforma: *Eduardo ya pasó por nueva revisión del CADEX: en resolución de diciembre de 2019 le reconocieron un grado de 75%.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-03-08','Ana: Correo de Paula, CRR (tocupacional.crrplasencia@grupo5.net): "Buenos días, quería comentaros que hemos finalizado (hoy) el periodo de "confinamiento" post-vacunación. En este sentido informaros de que Concepción Fernández Muñoz va a realizar una salida de una semana a casa de su hermana. Esta salida es de gran importancia para su tratamiento. En cumplimiento de todas las medidas, hemos solicitado los documentos relacionados con la permanencia de Conchi en el domicilio de Mª Isabel (su hermana), así como la asunción de un posible confinamiento en caso de que resultara positivo durante su estancia allí. Se han trabajado las medidas de prevención con Conchi, conociéndolas y respetándolas. La salida se producirá desde el 9 de Marzo hasta el 15 del mismo mes (ambos inclusive)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-03-08','Ana: Correo de Mariví Clemente, TS CSS-Plas.: "Con fecha de hoy el Paciente JUAN SANGUINO LANCHO, es dado de Alta Hospitalaria por cumplimiento de medidas de internamiento judiciales en el día de ayer. Se le acompaña para su ingreso en el Centro de Mayores " Sierra de San Pedro" en la Localidad de Casa de Dº. Antonio. Se traslada en TAXI, la factura original, de este gasto, junto a otros justificantes se enviarán, para rendimiento de cuentas a esa CTAEX por parte del servicio de admisión de este CSS.de Plasencia. El informe de alta del paciente queda en manos del psiquiatra que le ha atendido durante estos años y que enviará una vez lo tenga completado. Un saludo" ·································································································································································································· Correo al ctutelar@ de Modesto, Centro de Mayores Sierra de San Pedro: "Buenos días, soy Modesto, del Centro de Mayores "Sierra de San Pedro". Adjunto les envío los gastos de Juan Sanguino Lancho. Un saludo.". Adjunta factura del primer mes (plaza). ·············· Se lo reenvío a Alberto, Jefe de Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-03-09','Ana: En relación al correo que remite Modesto - C.Mayores Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es), al ctutelar@ con el contrato firmado por Juan, remito el siguiente correo desde mi cuenta: "Buenos días Modesto, La factura se la he reenviado al Jefe de la secc. Ecca. En cuanto al contrato que nos habéis envido, siento decirte que no tiene validez, pues aunque está bien que firme Juan, mostrando su conformidad (es decir, no se trata de un ingreso involuntario), no tiene plena capacidad legal para dicho acto por sí sólo, pues como sabéis está incapacitado legalmente y tutelado por la Comisión Tutelar de Adultos de Extremadura. Es necesario que nos remitáis uno nuevo, por duplicado, con los datos del Representante Legal, para que éste lo firme y os devolvamos una copia debidamente firmada y sellada. Lo correcto es que aparezcan los datos de ambos y que Juan también lo firme al final. Los datos del Tutor son: José Vicente Granado Granado, con DNI: 76015154Q, Vicepresidente de la Comisión Tutelar de Adultos de Extremadura, con domicilio en Avda. de la Américas, nº 4 de Mérida (Badajoz) Ante cualquier cuestión no dudéis en contactar. Por cierto, para temas que no sean económicas, ni jurídicas, agradecería que me escribierais a la dirección de email desde la que os contesto (ana.matamorosg@salud-juntaex.es), pues en la otra es fácil que se me escape algún correo. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-09','miguel, me remite email Rocío la abogada con el posible coste de reclamación de importe debido por alquiler: Buenos días, Miguel En respuesta a tu correo de ayer, no me venía adjunto el contrato de arrendamiento. Respecto a lo demás, te informo que los honorarios profesionales para el procedimiento de desahucio varían dependiendo de si se acumulan las acciones de desahucio con la de reclamación de las cantidades impagadas o si solo se solicita el desahucio con la recuperación de la vivienda. Para el procedimiento de desahucio con reclamación de las rentas impagadas, según el Baremo Orientador de Honorarios del Colegio de Abogados de Málaga, mis honorarios los dejo en 1.100 euros, y los honorarios de Procurador son 300 euros Para el procedimiento de desahucio sin reclamación de la renta debida, mis honorarios son 700 euros y los honorarios de Procurador 165 euros. Para el requerimiento previo, los gastos de Burofax son, más o menos, 35 euros. La documentación necesaria para interponer la demanda: -Contrato de arrendamiento ( junto con el Informe del Ayuntamiento de Viviendas incluidas en el Plan de Aydas de acceso a una vivienda) - Titulo de propiedad de la vivienda: acreditar la propiedad de Damián, bien con la escritura de compra o bien con nota simple del Registro de la Propiedad. - Justificante bancario del impago de las cantidades que se reclaman: Solicitar del banco extracto de movimientos de la cuenta indicada como forma de pago de la renta en el que aparezca los pagos realizados. En relación a la situación personal de Damián, tendrías que informarme si se encuentra con declaración judicial de incapacidad o no, a los efectos de una posible necesidad de solicitud de autorización judicial para la interposición de la demanda. He llamado varias veces al teléfono que aparece al pie de tu correo pero no responden. Si puedes llamarme lo hablamos mejor por teléfono. *************************************************** Reenvío dicho email a Alberto, a Damian y a su prima Alicia, y si las tres partes están de acuerdo hablaré con Rocio la abogada para iniciar los trámites de pago de deuda y posible desahucio del inquilino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2021-03-26','Llama Marisa, de Los Santos de Maimona (645971160), vecina de la casa de los hermanos Vázquez Corrales, interesada en la compra de la misma. Esta vivienda pertenecía a los hermanos, todos fallecidos, menos Juan. No está hecha la herencia de la hermana María, si de los hermanos Francisco y Gabino, con lo que hasta entonces no podríamos vender. Nos envía al correo de ctutelar oferta formal de compra. En función de la misma actuaríamos, teniendo en cuenta la edad de Juan (82), que tiene todas sus necesidades básicas cubiertas y que la vivienda se encuentra en mal estado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-03-09','Ana: correo de Chema, Piso de Menores CERUJOVI (jm.gallego.coordinacion@gmail.com): "Buenas, Ana. Te adjunto datos de la responsable de la salida y la dirección donde, en el caso que se pueda producir, Darío pasaría con su hermano y su tía paterna sus vacaciones de Semana Santa. Maria Belén Benito Sánchez 03879936C C/rio tajo, 4 Villaluenga de la Sagra Toledo Gracias. Un saludo." ····················································································································································································· Mi respuesta: "Gracias Chema, Tal y cómo hemos hablado, habrá que esperar a ver si decretan el cierre perimetral de las CC.AA. o qué indicaciones dan desde Salud Pública y los gobiernos autonómicos y/o estatal para la semana santa. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-03-09','TERESA Buenas tardes Teresa. Te comunico que Nerea ha tenido jueves, viernes, sábado mañana y sábado tarde crisis en las que ha sido necesario la intervención de la policía, guardía civil y el 112. En la última crisis que fue el sábado tarde, a la salida del podólogo (operación que no fue posible ante su nerviosismo y alteración), además de todos los servicios anteriores se activó el soporte vital con su traslado a Mérida; desde donde se pusieron en contacto conmigo, desde el servicio de psiquiatría para comunicar que la dejaban ingresada. A fecha de hoy aún no sabemos nada. Estoy preparando todos los partes de incidencia para remitirlos al SEPAD. Quería preguntarte igualmente si a través de nuestra entidad se le puede o debe facilitar información a la familia de Nerea en este sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-03-09','correo de Alberto: Ana ya tiene conocimiento, pero tanto Ángel como Miguel no. La situación ECO del tutelado no es mala pero tiene en trámite un tratamiento bucodental que supera los 7.000 €, y tenemos alguno que los 9.000 €. Para esos importes, a día de hoy no da. Me dice Iciar que el padre del tutelado tiene bastantes propiedades a su nombre y que están fallecidos tanto el padre como la madre del tutelado. Desconocemos si tiene hermanos, aunque sospechamos que pudiera tener uno en Plasencia. Podríamos iniciar los trámites para la herencia??? Xfavor, echádle un vistazo y lo hablamos. Ana: Xfa, insiste en hablar con el tutelado...creo que nadie del área social ha habladocon el. Además te paso el teléfono de un médico de Cáceres (creo que es alguien conocido en la ciudad) que ayuda bastante a este hombre: PEDRO PASTOR VILLEGAS (630 617 157) ************************************************************ contestación Miguel: Buenas tardes, este tutelado actualmente está sometido a un procedimiento que ha solicitado, a través nuestra, para ampliar su capacidad de tutela a curatela. Según podéis leer en la intranet tiene padre y hermanos (Julian que vive en Plasencia y Zacarías vive en el País Vasco) Su padre vive por tanto no hay herencia que se pueda hacer… Os adjunto el informe de futuex que utilizamos para solicitar que le pasen a Curatela. Miradlo y buscad otra solución económica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='GONZALEZ'and apellido2='OLIVERA'),'2021-03-09','miguel, nos envía Juana el certificado de fondo de inversiones de Santander que nos requirió el Juzgado. "Os reenvío el correo electrónico que ha llegado a ctutelar con respecto al fondo de inversión de Inés González Olivera, para dar contestación al Juzgado". ******************************************************* miguel, contesto al Area Económica: Hola de nuevo, os comento. En el email del 22-2-2021 que acabo de imprimir figura lo que pedía el Jzdo de 1º instancia nº3 de Almendralejo. A él se hacían las rendiciones de cuentas y resulta que en la última que enviasteis (no la final) indicásteis que era un activo (es decir que no se había liquidado y cerrado). Es por eso que en la rendición de cuentas final si lo pusisteis bien. Por tanto basta con indicar en un oficio (por fax) que hubo un error en la liquidación de cuentas que se rindió y que la correcta es la final, y se le adjunta este certificado que han mandado del Santander.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-03-09','Ana: Llamada de María, F. Autismo Sur (693 759 016): pregunta si tenemos respuesta de PNC, indico que aún no hemos recibido resolución alguna ni se han puesto en contacto de ningún modo. *La deuda de Costi cada vez es más y no pueden seguir afrontando sus gastos desde la entidad. *Me comunica que desde su centro se va a remitir una carta a la CTAEX exponiendo la situación y solicitando una solución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILIA'and edp.apellido1='SALGADO'and apellido2='DURAN'),'2021-03-08','Ana: Conversación con Emilia, TS del CSS-Plas.: Basilia necesita una silla de ruedas nueva que cubra sus necesidades. *Enviarán presupuesto al ctutelar@, a la Att. de la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='GONZALEZ'and apellido2='OLIVERA'),'2021-02-22','el juzgado nº3 Almendralejo nos requiere para aclarar la cuenta del Fondo de Inversión del Santander, porque en la rendición de cuentas del 2019 se decía que era un activo, y en la rendición final se dice que se canceló en 2016','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-09','Ana: Correo de Estrella, TS del CSS: "Buenas de nuevo. En reunión de equipo se ha decidido que sería bueno para Isabel Cano que fuera unos días a casa, se iría el lunes que viene día 15 hasta el siguiente lunes el día 22. Tenemos que enviar algún documento para que lo firméis? O alguna otra gestión?" ····························································································································································································· Mi respuesta: "A ver, dadas las circunstancias actuales, y en vista de que no ha salido ninguna nueva resolución al respecto, hemos decidido seguir utilizando el documento que empleó en las navidades para las salidas a los domicilio. Quizá salga uno para semana santa, pero de momento es lo que hay. Te adjunto el decreto por si no lo tienes a mano. Si recuerdas, se tenía que firmar por todas la partes (la dirección de vuestro centro, la personas familiar responsable del domicilio al que va y por nuestra parte el Representante legal). Si quieres, mañana que estoy en la ofi (hoy teletrabajando) lo cumplimento y pongo para la firma y te lo devuelvo ya con la firma de José Vicente, a expensas de la firma de la dirección de vuestro centro y familiar. La autorización está en las páginas 28 y 29, por si lo queréis ver/valorar. Es que si no, es hacerlo como antes de esta situación… en vuestro centro debe estar la autorización general de salidas, y además, cuando son salidas “terapéuticas”, si se autorizan desde ahí, desde la CTAEX no hay nada que decir, a no ser que se entienda que es perjudicial para la personas tutelada o no fuera viable por algún motivo. Ya me dices. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-03-09','Ana: Llamo a Ángel Santos Cordero, hermano de Miguel (605 030 973), pero no obtengo respuesta. ············· Llamo a Miguel Santos Antequera, hijo de Miguel (623 197 407): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-03-09','Ana: correo remitido por FUTUEX a Miguel, Asesor Jurídico y a mí: "Buenas tardes, a continuacion, se adjunta la informacion recabada por la compañera en la citación que tenía Gregoria en el juzgado de Plasencia. La tutelada llega algo nerviosa, de hecho, cita que no ha dormido bien. Al mismo se había citado a la acusada y a la Trabajadora Social de Piornal como testigo de Gregoria, pues fue quien inició el procedimiento enviando el primer informe a fiscalía. Finalmente, no tienen que declarar Gregoria, ni la Trabajadora Social mencionada, pues la acusada se declaró culpable, por lo que se le condenó a un año y pico de cárcel y debe indemnizar, a la tutelada, con 2.500€. La Trabajadora Social de Calzadilla, consultó para que se le deje de pasar el pago del IBI, pues se ha mantenido siempre, comentan que se puede modificar con un recibo o quizá sus tutores legales. Ahora queda la duda del poder notarial que le hizo Gregoria a Silvia, acusada, pues quizá, sería oportuno que existiese un documento que anulase o eliminase la validez de dicho documento (se adjunta a esta nota)" ··········· Guardo nota en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-03-09','Ana: Llamo a Jesús, sin éxito. ····· Llamo a Pedro Pastor, su amigo (630 617 157): enviará un mensaje a Jesús y le facilitará mi número para que me llame mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2021-03-09','TERESA ME LLMA DICIENDO QUE SE HAN ROTO LAS GAFAS SE AUTORIZA 60 EUROS PARA CONSULTA OCULISTA Y QUEDA PENDIENTE PRESUPUESTO GAFAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-03-10','-Hola Amalia, te paso el teléfono de ESTELA GRILLO MORAL, que es la persona interesada en alquilar la vivienda de Juan Carlos. TLFNO: 689115164','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GUTIERREZ'and apellido2='ALMARZA'),'2021-03-05','EXITUS. COMUNICAN DESDE EL CENTRO SU FALLECIMIENTO A FECHA 05/03/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-03-10','TERESA He hablado con el casero 625494248 y ya esta solucionado el tema de los pagos lo vamos a hacer por transferencia y evitamos que Pedro coja ese dinero y no haga buen uso. He hablado con Manuela Ts de salud mental de Mérida y me dice que Pedro ya pertenece al área de salud de Don Benito y que hable con ellos y le exponga el caso. No sé si vosotros habéis conseguido contactar, me ha facilitado dos teléfonos, mañana intentare contactar con ella pues me ha facilitado las extensiones y hoy estoy en casa. Vamos a comunicar la situación al juzgado pues desde la CTAex lo único que podemos solicitar es el ingreso involuntario, vamos a aportar el informe social y voy a intentar que me hagan un informe de salud mental y me que me den una cita preferente en esta área. Mañana concreto con Alberto la asignación pues no sabíamos los gastos que tenia de alquiler y consumos y me parece bien que hagamos como planteas de reintegro quincenal con acompañamiento y vemos cómo funciona hasta que consigamos o que lo vea el psiquiatra y valore o que autoricen el ingreso involuntario porque desde la comisión no vemos más opciones…. Sería ideal que asistiera a CEDEX pero es un recurso de acceso voluntario con lo cual no le podemos obligar, si quiere ir de buen agrado con el apoyo vuestro sería un paso importante, en cuanto el casero se entere que está bebiendo lo echa del piso, yo le he dado un poco de largas pues se ha mosqueado al decirle que le vamos a pagar por transferencia pues conoce a Pedro y su problemática con el alcohol. Creo que por el momento nada mas… Quedo pendiente: confirmarte asignación, pero ya puedes programar el acompañamiento para la primera semana de cada quincena. Entiendo que es Susana es quien acompañaría. Contactar con salud mental de Don Benito y a ver que me dicen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-10','miguel, pregunta el tutelado por el procedimiento de revisión de pensión alimenticia de los hijos (que pretende dejar de pagar) Pregunto a Angel y me comenta: Si, se presentó ya la demanda, en octubre del 20. Puedes ver en su expediente en la intranet, una carpeta, dentro de Juzgados, que pone Modificación de medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-03-10','reunión a tres Teresa, Alberto,Miguel, conclusiones: Solución sobre situación actual de CONSUMO sustancias de tutelado, ingreso pareja tutelado en CSS Mérida y deudas generadas por impago alquiler en Monterrubio, localidad en la que reside actualmente y de la que es procedente. NO tenemos conocimiento de existencia de contrato por lo que llegamos a la conclusión de que el mismo está a nombre de la pareja del tutelado. Dada la situación del tutelado y que estamos pendientes de la aporobación de un INGRESO INVOLUNTARIO (actualmente tramitándose por Teresa-Miguel), se decide: • Asumir el pago del alquiler hasta consecuciónn ingreso tutelado en centro. • Asumir el pago de las deudas existententes: pocos importes a día de hoy. • Reducir el REINTEGRO en la misma proporción en que se abona el alquiler y los consumos. Será QUINCENAL y se realizará con ACOMPAÑAMIENTO. Tere está en contacto con Trabajador Social de Monterrubio de la Serena: posibilidad empadronamiento, otros trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-03-10','Ana: Conversación con Jesús (633 447 172): ha estado esta mañana con Gloria-Futuex, en otras clínicas dentales, a ver si pueden obtener un presupuesto más económico para los tratamientos que necesita. ····· Por otra parte, dice que en el mes de diciembre, desde Futuex, remitieron al cututelar@ presupuestos para ropa (chandal, camisitas y pantalones) para aprovechar que había cobrado la extra, pero aún no ha obtenido respuesta. ············· Plantea también la compra de un filtro para el agua (tanto para la cocina como para la ducha), pues considera que es más saludable para beber y preparar comidas, así como para su piel, pues presenta dermatitis. *Con respecto a esto le hago ver que no es el momento más adecuado, el tratamiento dental es prioritario y su situación económica es delicada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL JESUS'and edp.apellido1='PECERO'and apellido2='GUERRERO'),'2021-03-10','miguel, llega auto 102/20 de 18/8/20 del jzdo nº4 Mérida, procedimietno X15 Autorización disposición bs discapacidado 95/20, no firme contra el que cabe recurso de apelación. Se lo dejo a Angel en su mesa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2021-03-10','Ana: Recibimos del INSS Cdo. de la P. de Orfandad (Clases Pasivas), pero no el Cdo. de la PFHC. **Juan Pedro, Admvo. CTAEX, pone para registro nuevo ofico-solicitud del mismo. ·········· Se lo comunico a Longina y le envío por mail el cdo. que hemos recibido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-10','Ana: Belén, secc. ecca. CTAEX, me confirma que ya han ingresado a Emilia los abonos de sus pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-11','Ana: correo a Alberto, Jefe secc.ecca.: "Buenos días Alberto, Te renvío correo de Carmen, TS de Coria, con la información de las deudas que tiene contraída Emilia Gutiérrez Serradilla (“Defensa Judicial para el manejo y administración de bienes y aspecto económico”). Hay que comenzar a abonar las deudas lo antes posible, o le darán de baja el seguro de deceso así como los suministros a partir del día 20. Creo que ya envié otro correo con presupuesto aproximado de gastos para establecer la asignación mensual. *En su cuenta ya le han ingresado los atrasos de las pensiones. E Icíar ya domicilió la luz y el gas en la nueva cuenta. Buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2020-11-26','Ana: Según informe social del CAMF de fecha 28/10/20 para la rendición anual, José Fernando lleva 35 años en el CAMF, donde se valora necesario que continúa residiendo para recibir los cuidados y atenciones que precisa. Carece de apoyo familiar y de relaciones afecticas con sus hermanos/as. Apenas participa en las actividades del centro. No se aprecian cambios respecto al año anterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2020-12-22','Ana: Según informe social del CAMF de fecha 28/10/20, para la rendición anual: Rosario es dependiente de tercera persona para la realización de las actividades esenciales de la vida diaria. Presenta el grado máximo y nivel de dependencia reconocido por el SEPAD (Grado III, nivel 2) y un 90% de discapacidad reconocida por el CADEX. Usuaria de silla de ruedas eléctrica. A penas tiene relaciones familiares, unos primos realizan muy escasas visitas. Madre fallecita y padre desconocido. No tiene hermanos. *Participa activamente en actividades lúdicas y socioculturales del centro. **Asiste a Terapia Ocupacional, Fisioterapia y Logopedia en el CAMF. *No conflicto convivencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-03-11','Ana: Reenvío a Alberto, Jefe de Secc. Ecc., el correo de Modesto, Res. Sierra de San Pedro, con los gastos aproximados de Juan, además del precio exacto de la plaza. ············· En otro correo, Modesto me remite el contrato de la residencia modificado. Enviarán el original por duplicado por correo postal y le devolveremos una copia firmada por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-11','Ana: envío correo a Clara Isabel Gómez Nestares, Jefa de secc. de Calidad de sistemas - Dependencia (clara.gomez@salud-juntaex.es): "Buenas tarde Clara, Espero que sigas bien. Quería hacerte una consulta. Saturnino Miguel Salgado Jiménez, tutelado por la CTAEX, recientemente ha ingresado en Prisión preventiva. Estamos a la espera de juicio y no sabemos finalmente cuánto tiempo tendrá que pasar allí. *Es perceptor de una prestación vinculada por dependencia (190 €) y obviamente ha dejado de recibir el servicio. Mi pregunta es, ¿se puede solicitar la interrupción temporal de la prestación o comunicamos directamente el cese, se le da de baja y llegado el momento se solicita de nuevo? Quedo a la espera de tu respuesta sobre cómo proceder o con quién hablar. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SETEFILLA'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-03-11','Ana: Según el informe social para la rendición anual de 2020, continúa ingresada en la Unidad de Mujeres de Psicogeriatría del Centro Sociosanitario de Plasencia. Dada la distancia y la escasez de medios, sus hijos la visitan sólo los veranos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-03-11','TERESA RECIBO RESOLUCIN DE TRATAMIENO PSICOLOGICO, SE LO ENVIO A ADISER','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2021-03-11','TERESA RECIBO COMUNICACION BAJA EN LA PFHC POR ALTA EN PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-03-12','TERESA Solución sobre situación actual de CONSUMO sustancias de tutelado, ingreso pareja tutelado en CSS Mérida y deudas generadas por impago alquiler en Monterrubio, localidad en la que reside actualmente y de la que es procedente. NO tenemos conocimiento de existencia de contrato por lo que llegamos a la conclusión de que el mismo está a nombre de la pareja del tutelado. Dada la situación del tutelado y que estamos pendientes de la aporobación de un INGRESO INVOLUNTARIO (actualmente tramitándose por Teresa-Miguel), se decide: • Asumir el pago del alquiler hasta consecuciónn ingreso tutelado en centro. • Asumir el pago de las deudas existententes: pocos importes a día de hoy. • Reducir el REINTEGRO en la misma proporción en que se abona el alquiler y los consumos. Será QUINCENAL y se realizará con ACOMPAÑAMIENTO. Tere está en contacto con Trabajador Social de Monterrubio de la Serena: posibilidad empadronamiento, otros trámites. Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-03-12','FUTUEX yer sorprendentemente nos encontramos la casa en mejor condiciones y el, muy dispuesto a colaborar y a todo.. esperemos que asi sea. Tenemos cita para el cedex el proximo dia 18, se le acompañara a sacar los 170 y a cedex tb, hemos mirado buses y formas de ir desde MOnterrubio a Castuera (dond esta cedex) y hay un taxi que le cobra 20 eu de ida y vuelta nos parece razonable. En los gastos que se organizaran con el, estaran la comida y tabaco para la quincena, acompañarle a comprarlo para que tenga para las dos semanas, ademas de dejar pagada farmacia (en principio no tiene mas gastos) el telefono esta domiciliado en la cuenta de la pareja, asiuqe le acompañaremos a una tienda para coger uno por prepago y con datos de internet, todo eso se puede hacer con los 170 eu. No sabemos como reaccionar al no tener dinero de bolsillo, si acaso le podemos dejar algo tipo 5 euros o 10, pero por ahora esta bastante dispuesto a todo. Al cedex y todo lo demas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-03-12','miguel, llega escrito del jzdo nº2 de Cáceres inidcando que se indique acerca de la lista de espera por T3 en la residencia de Brozas. Hablamos con centro de mayores Alfonso y May, para pedirles documento que acredite que está la nº1 de lista de espera de Villa Rey, ya que en Brozas no hay sitio. Y si fuera por emergencia social tendrían que darle cualquier destino. Recordemos que la PIA solicitando Brozas la rellenó la propia Clementa Amado Vivas. ********************************************* Preparo el documento y lo pongo a la firma para enviarlo al juzgado nº2 Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2005-04-22','Tiene dos hijos y los tiene en acogimiento sus padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-04-15','-SE PERSNA BRIGIDA Y OTRA COMPAÑERA DE SERVYSCOOP CON LAS FACTURAS DE ANDREA , ASCIENDEN A MÁS DE 1000€. SE LE EXPLICA QUE ESO NO LO PODEMOS PAGAR SIN ORDEN JUDICIAL , NO SÉ SI SE HABRÁ SOLICITADO. ELLA DICE QUE EL SERCICIO EN EL CENTRO SE LO PIDE ALGUIEN DEL CRR , Y ESE PTO . LO ACEPTÉ YO CON MARIA CLAROS , PENDIENTE QUE NOS ENVIARA EL PTO. PARA DAR EL OK DEFINITIVO. LUEGO PASA AL HOSPITAL , BRIGIDA DICE QUE SE LO PIDE LEONOR DEL CRR , LE DIGO QUE NO PQ LEO NO ESTABA EN ESA FECHA , ESTABA DE BAJA Y CON QUIEN YO HABLÉ FUE CON MARIA CLAROS. LUEGO RECTIFICA Y DICE QUE EFECTIVAMENTE AL PRINCIPIO HABLO CON MARIA . Y LUEGO FUE SU HNA TOÑI LA QUE CONTRATA EL SERVICIO , POR LO TANTO LE INDICO QUE DEBERÍA PEDIRSELO A LA HNA. HAY QUE CONCRETAR CÓMO SE VA A PROCEDER EN ESTE CASO. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-03-12','miguel, llega resolución negativa a la concesión de incapacidad permanente. Tras concretar con Alberto y Ana que habremos de comunicar al juzgado y debido a la emergencia social de la tutelada, tendremos que hacer paralelamente dos procedimientos: -Solicitud de internamiento involuntario -Procedimiento de reclamación ante el juzgado de los social. *************************************** Email que envío a Toni de Futuex: Buenos días Toni, según he comentado con Ana, necesitamos que os acerquéis al domicilio de Ana Mª Rosco Avalos para entregarle el documento que os adjunto. Somos conscientes de que es muy complicado hablar con ella, pero necesitamos que intentéis hacerle llegar este documento (resolución de la TGSS denegándole la prestación por incapacidad permanente, donde sólo dan 30 días para interponer demanda ante el juzgado de lo social. Ella no dispone de capacidad económica para contratar un abogado por lo que habría que solicitarla un abogado de oficio. Al ser ella quién en su día tramitó esta reclamación y nosotros desconocer todo el trámite de dicho procedimiento necesitamos que se ponga en contacto con mi compañera Ana Matamoros o con Angel o conmigo para nos haga llegar la documentación anterior para analizar si hemos de buscarle un abogado de oficio para que entable demanda ante el juzgado de lo social). Con el resultado de vuestra visita remitidnos un informe para adjuntarlo a la comunicación que haremos al juzgado. *********************************** email a Angel: Buenos días compi, necesito hablar contigo sin falta esta mañana acerca de esta tutelada. Te reenvío el email que he enviado a Toni de Futuex. Ha llegado una resolución administrativa firme desestimando la petición que en su día ella tenía por incapacidad permanente. Desconocemos el contenido total de dicho procedimiento administrativo. Dan un plazo de 30 días para entablar demanda ante el juzgado de lo social. He mandado a Toni para que intenten darselo en mano pero esta tutelada está ilocalizable. Por otra parte Ana intentó activar el 112, sin éxito. Y esta mañana nos hemos enterado que ha retirado en Marzo 504€ de los 534€ que tiene de pensión (renta básica) porque los otros 30€ el banco se lo cobra de comisión. Parece ser que los ha sacado sin orden pero la parte económica no quiere enviarles ningún documento porque desde Liberbank of OP Mérida le dicen que la tienen miedo. Tras hablar con Ana y Alberto la conclusión es que comuniquemos todo al juzgado. Esta mujer está ilocalizable y desestabilizada pues dice Ana que desde 2017 no acude a salud mental. Por tanto hemos pensado en que hagamos paralelamente Solicitud de internamiento involuntario, adjuntando los escritos que nos ha hecho llegar y tú tienes, por otro lado los informes que nos remita Futuex, y añadiendo todo lo que hay en la intranet sobre incidencias sumando la retirada de dinero este mes de Liberbank sin nuestra autorización. En dicho escrito añadiríamos que tras autorizar el internamiento en la UHB de Mérida, dicten las ordenes oportunas para que la policía la localice y la lleve allí. Paralelamente con el resultado de la visita de Toni (email que te dejo debajo de este) tendríamos que interponer Recurso ante el Juzgado de lo Social añadiendo documento justificativo de solicitud de abogado de oficio ante el Colegio de Badajoz, ya que esta mujer residía en Mérida. Por cierto no sabemos si era funcionaria interina (en cuyo caso con esta resolución seguramente habría perdido la opción de reincorporación al trabajo) o era funcionario de carrera (en cuyo caso tras esta desestimación tendría que haberse incorporado a su lugar de trabajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-03-12','Ana: Correo de Amalia a Amor-ASPACE (amor.lopez@aspacecaceres.es), me pone en copia: "Buenos días , adjunto documentos firmados para trámites de extranjería de Brahim El Kinty Sneiba. ¿ cómo se está adaptando al centro ? El caso pasa ya a seguimiento por la compañera de la zona de Cáceres , Ana . Un saludo "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-12','Ana: Tras realizar consulta a Clara, recibo correo de Jorge Morán Pilo - Dependencia (jorge.moran@salud-juntaex.es): "Buenos días Ana, Me ha remitido esta consulta Clara. Me surge una duda con este expediente, le tenemos resuelta una ayuda a domicilio desde junio del 2019. Sin embargo, acabo de hablar con la empresa que tenemos registrada que le presta ese servicio y me dicen que nunca llegaron a iniciar el servicio, y no tenemos constancia si está en otra empresa o nunca ha iniciado el servicio. Por tanto necesitamos saber si está prestándose el servicio con otra empresa, y si no es así le damos de baja la prestación desde junio del 2019 y tendría que devolver todo lo cobrado. En caso de estar en otra empresa, ya hablaría con ellos a ver desde cuando no se ha prestado el servicio y en función de las fechas te respondo a tu cuestión si damos de baja o suspendemos la prestación. Quedamos a la espera. Un saludo" ···························································································································································································· Mi respueta: "Buenos días Jorge, Pues me temo que, una vez comprobado, no ha llegado a recibir el servicio… aún no tenemos claro por qué. Se puede proceder a dar de baja. Dime, si no es mucha molestia, qué tenemos que hacer al respecto. En cuanto a la devolución del dinero, el jefe de la sección económica de la CTAEX, indica que se pondrán con ello en cuanto reciban la comunicación al respecto. No cree que se pueda devolver todo a la vez, pero sí poco a poco. Ya nos vais diciendo también. Gracias y un saludo." ······························································································································································································· Respuesta de Jorge Morán: "Pues entonces le damos la baja con fecha de efecto 27/06/2019. En primer lugar le mandaremos la resolución de extinción y posteriormente le mandamos la propuesta de pago indebido. Para poder fraccionar hay que esperar a la resolución, que la enviamos aproximadamente a los tres meses de la propuesta. Una vez se recibe la resolución tiene que presentar el escrito de aplazamiento o fraccionamiento y nosotros ya enviamos el expediente a Hacienda, que son quienes se encargan de gestionar ese aplazamiento. Si te parece cuando tengamos los documentos te aviso y pasas a recogerlo por la Unidad. Mi teléfono es el 924930415 para cualquier duda o consulta" ·········· Así lo haremos. Informo a Alberto, Jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2021-03-12','-Amalia : hago llamada seguimiento al CSS Mérida , sigue en la unidad de crónicos . En la declaracion anual PNC elimino al padre de la unidad de convivencia , siguen apareciendo juntos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-03-12','Ana: Correo de May Masegosa: "Buenos días de nuevo, esta señora esta pendiente de plaza pública en la R.M.M de Villa del Rey, a fecha de hoy es la única solicitante, estando todas las plazas conveniadas ocupadas. Teniendo en cuenta que las lista no son cerradas, pueden variar en función de las solicitudes que vayan entrando, ya que las plazas se asignan por grado y capacidad económica, el tener solamente este centro solicitado puede tardar en producirse el ingreso pues solo tenemos cinco plazas conveniadas, podéis solicitar hasta cuatro centros. Al que padecer la solicitante patología Psiquiátrica, necesitamos informe actualizado de la situación actual de la paciente donde se especifique que no padece alteraciones de conducta, sino fuera así, no podría ingresar en centros de mayores. Un saludo " ················· *Se lo reenvío a Miguel, Asesor Jurídico CTAEX, en relación al escrito que hemos recibido del Jdo. preguntando por la lista de espera del centro residencial y al que debe responder. ······················································································································································································· Tras hablar con Pilar Martín, respondo a May: "Buenas tardes ya, May, Miguel ya se pone con la respuesta al Juzgado. Gracias. En cuanto al informe de Psiquiatría, acabo de hablar con Pilar Martín, Trabajadora Social del Equipo de Salud Mental de Cáceres, y me dice que el informe que necesitáis tendréis que pedirlo por escrito a la propia Clementa, como solicitante de la plaza, pues sin su consentimiento, por la Ley de Protección de Datos, no se podrá enviar. Además me informa que su Psiquiatra, Ángela Carreira, está de baja, no sabe en este coso quién lo tendría que emitir. La Coordinadora del ESM es Julia García, por si queréis hablar con ella. Desde la CTAEX, como te he comentado, no podemos solicitarlo en tanto que a día de hoy no somos tutores legales. Sólo nos han nombrado Administradores de Bienes. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-03-12','TERESA ENVIO AUTORIZACION DE VENTA DE PORCINOS POR EMAIL A PETICION DEL HERMANO DE M ELENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-03-12','Ana: Correo de Paula, TO CRR-Plas., en respuesta a mi correo: "Buenas Ana, respecto a Toñi Bernardo la verdad es que la adaptación hasta ahora está siendo ejemplar. Manifiesta habilidades funcionales y de convivencia que han contribuido a mejorar el ambiente del Piso y han demostrado, hasta ahora, un desempeño y un nivel de autonomía muy bueno. Así mismo ha sido permeable a solicitar ayuda cuando la ha necesitado en situaciones en las que cualquier otra persona sin diagnóstico hubiera hecho. En Mayo os enviaremos como acordamos un informe completo para detallar la evolución, que esperamos continúe en esta línea y, para ir iniciando, tal y como acordamos en el plan de Toñi, la búsqueda de opciones para una vida autónoma en un piso (compartido o sola según sus posibilidades). Respecto a la dirección del piso, disculpa que no os la haya facilitado antes la documentación, pero en el caso de Toñi, con sus peculiaridades, ha habido un periodo de "prueba" previo al paso definitivo a la plaza de piso más amplio. Es el mismo piso (solo hay uno) en el que vive Félix Franco que también es tutelado vuestro. La dirección es Calle Puerta Berrozana nº2, 1ºA; 10600 Plasencia. Os adjunto el documento de aceptación de plaza. Los otros documentos como el del tratamiento de imágenes y datos, creo que no es necesario por la vinculación de ambos recursos. Un abrazo. Paula." ··························································································································································································· Respondo: "Muchas gracias Paula, Me alegro que se esté adaptando tan bien. Ayer, como habrás leído en otro corroe, me llamó y la noté muy bien. En cuanto al documento, lo cumplimentaré y pondré a la firma del D.Gerente. en cuanto lo tenga os lo envío. No obstante, siendo un recurso de carácter voluntario, no debería firmarlo ella también? Ya me dices. Un saludo." ························································································································································································ Con respecto a la llamada de ayer de Toñi, envío este correo a Alberto, Jefe Secc. Ecca. y a Paula, TO CRR-Plas.: "Buenos días Alberto y Paula, Ayer recibí llamada Antonia Bernardo Piris, tutelada por la CTAEX, expresa que le gustaría ayudar económicamente a su hija, le gustaría hacerle una transferencia de 250 €, me facilitó incluso el número de cuenta. No sé si económicamente puede permitírselo, ni si realmente es necesario ni producente, le dije que lo hablaría con la sección económica para ver sus posibilidades. Ella dice que no es la primera vez que le ayuda y es su deseo hacerlo. Por mi parte, si se puede doy el visto bueno, como hemos hecho en otro casos. No obstante, Paula, me gustaría que también valoraseis desde el recurso esta solicitud. *Por otra parte, indica que la cuenta de Caixabank la sigue teniendo abierta, y que le está cobrando comisiones, pregunta si es posible cerrarla para que dejen de cobrárselos y pasarle el dinero que hay en ella a la otra cuenta que la abristeis. **Si finalmente se aprueba la ayuda a la hija, decírmelo para que os pase los datos que ella misma me facilitó. Un saludo y buen fin de semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-03-15','Ana: correo de Amor López, TS Aspace: "Muchas gracias por la documentación Amalia, ha sido un placer conocerte y poder trabajar contigo, a partir de ahora como tu bien dices trataré todos los temas con tu compañera Ana. En referente a Brahim, su adaptación está siendo positiva; es evidente que requiere una persona pendiente de él las 24 horas del día porque no tiene la capacidad de diferenciar lo que es bueno o malo para él pero hay algunas rutinas que estamos intentando cambiar como la concentración en actividades/ talleres al menos durante un periodo corto de tiempo y descansar una hora después de la comida ( actividad que no había hecho hasta entonces) Lo que sí , puedo destacar es que es una persona cariñosa que le gusta el contacto y la estimulación multisensorial, cualidades que con más ratio de personal podriamos trabajarlas más tiempo al día pero 2 cuidadores para 7 personas con necesidades altas de apoyo es muy complicado ... pero bueno es cuestión de adaptarnos los unos a los otros y conocernos mejor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BRAVO'and apellido2='GARCIA'),'2021-03-11','ARCHIVADO El Jzdo. informa de la firmeza de la sentencia de ICP 118/20, de 27 de octubre, por la que se declara incapaz total a Dña. María y se nombra a su hija (Dña. Macarena García Bravo) su tutora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PULIDO'and apellido2='MERINO'),'2020-06-04','Ana: Según informe social del CSS-Plas. para la rendición anual, Antonio continúa residiendo en la misma unidad, no se han producido cambios significativos en su situación en el útlimo año y mantine contacto con su sobrino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-03-15','Disponemos del Auto autorizando la venta de la vivienda de Ceferino. No es firme. Una vez lo sea, nos envían Testimonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2020-09-14','Ana: Según informe social de fecha, 27/08/2020, para la rendición anual, "Amalia reside en la residencia de El Torno desde el 10 de junio de 2014", es natural de Navaconcejo, donde residió gran parte de su vida con sus hermanos. Tiene 3 hijos y 2 hermanos "Las relaciones entre los miembros de la unidad familiar pueden considerarse inestables y conflictivas, en algunos casos, debido en parte a los trastornos de algunos de sus miembros..." En la actualidad, a penas tienen contacto con los familiares, recibe llamadas de Gema, una de sus hijas, aproximadamente cada tres meses, quien con anterioridad a la pandemia también la visitaba cada 3 meses (durante el año 2019). Ésta ahora reside en Las Hurdes. Con sus otros 2 hijos no tiene relación. Aunque su hijo Juan Carlos comenzó a visitarla 1 vez al mes en 2019 acompañado de su novia. Su hermano Juan la visitaba cada dos meses al principio, pero desde 2017 no ha vuelto a visitarla. Sus hermanos actualmente residen en Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-15','Iciar- Comprobando cuenta de Jose MAnuel le han cargado recibo de Vodafone por cantidad de 7,11 € con fecha 11/3/21, supongo que será el primero de la contratación que ha dicho haber realizado por su cuenta. Lo devuelvo con fecha 15/11/21. Iré comprobando la cuenta para devolver cada recibo que le pasen de Vodafone.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-03-15','TERESA ME COMUNICA DEL CID Y VILLAFAINA QUE CON FECHA CON 23 DE FEBRERO HA PEDIDO CERTIFICADO DE ULTIMAS VOLUNTADES HAY QUE AVISAR A JOSE ANTONIO PARA QUE LO LLEVE CUANDO LE LLEGUE AL DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-15','Ana: Tras hablar con Isabel Mª y con Estrella, TS CSS-Plas.: Envío correo a Icíar, secc.ecc. CTAEX: "Buenos días Icíar, Como sabes, he recibido llamada de Isabel María Cano, está pasando unos días en el pueblo con su madre, dice que necesita dinero para comprar algunas cosas. Acabo de hablar con Estrella, TS del C. Sociosanitario de Plasencia, y me confirma que no se ha llevado nada de dinero, pues esta mañana no estaba ella y tampoco estaban las personas que suelen estar en admisión. No sé cómo está su cuenta, pero si es posible, ¿podéis realizar autorización de retirada de 50 € en la sucursal de Trujillo para mañana o pasado? Te lo envío directamente a ti porque me ha dicho Teresa que no está Alberto hoy. Le pongo en copia para que lo vea mañana. Confirmarle por favor del día qué puede ir al banco y cuanto puede retirar: Tlf. 649 642 635 Gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-15','Ana: Tras hablar con José Manuel, envío correo a Toni-Futuex: "Buenos días Toni, En relación a José Manuel romero Mediavilla, dos cuestiones: - Le gustaría saber cuándo va a tener de nuevo educadora para seguimiento, ya sabéis lo demandante que es. - En relación a la necesidad de podólogo, ¿podríais gestionarle presupuesto y cita, con el mismo podólogo al que ha ido otras veces? Enviáis por favor el presupuesto a la otra dirección de correo a la atención de la secc. Ecca. como es habitual. Pongo en copia a Alberto, jefe de la secc. Ecca. para que esté al corriente de dicha necesidad y que se ve a enviar. Ya me vais informando. Espero que estéis bien. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-03-15','Ana: Tras hablar con Mar - del HUC (927 256 200 // mariamar.declara@salud-juntaex.es), me remite correo con 2 C.I. para anestesia: "Hola Ana; tal como hemos quedado te remito los consentimientos para firmar de la paciente Rosa Gomez Nevado; por favor digitalizadlos a color tras ser firmados. un saludo. Mar Declara Peña Lista de Espera Quirúrgica. Hospital Universitario de Cáceres Teléfonos 56.005 / 927.256858". ················· Se ponen a firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-03-15','Ana: Correo de Alfredo Moreno Cebrián: "Buenos días, Ana. Tal como te comenté por teléfono, hemos contactado con un hermano de Antonio Serrano Suárez, que se encuentra en una residencia de Madrigal e la Vera, el viernes tuvieron una videollamada y muy bien, ya que hacía tiempo que no tenían contacto. El Hermano se llama Genaro. Teléfonos de contacto: Genaro: 666 349 011. Residencia Madrigal de la Vera: 927 56 53 14 (El Director se llama Juan Blanco). Un Saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LORENZO'and apellido2='FERNANDEZ'),'2020-01-14','Ana: Según informe para la rendición anual, José continúa ingresado en el Centro Sociosanitario de Plasencia. Mantiene escasa comunicación con la familia. No ha habido cambios significativos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2021-03-16','Ana: Conversación con Fermín (llamada programada con Teresa, TS de NOVAFORMA): Está muy contento en el centro, dice que ha pasado por muchos y éste es el mejor de toda Extremadura. *Pero en estos momentos está preocupado por no poder salir solo de paseo, como hacía antes de la pandemia por Covid. *Muestro comprensión y le explico que de momento hay que mantener estas medidas una temporada, hasta que indiquen otra cosa desde Salud Pública y la Junta. *En cuanto a su asignación, quieren que se la aumenten a 5€ los martes y jueves, que es cuando les dan el dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-03-16','Ana: Recibo llamada de Luismi, Policía Nacional de Plasencia (927 42 62 55), necesitan ponerse en contacto con Emilia, por una orde de alejamiento que tiene a su favor, en relación a una denuncia que puso en Plasencia por malos tratos. Facilito el número de teléfono actual y domicilio para que la puedan localizar e informar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PATILLA'and apellido2='CASTRO'),'2021-03-14','EXITUS. Comunican desde el Centro su fallecimiento a fecha 14/03/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-03-16','miguel, tras la remisión por Amalia de la sentencia (que según el abuelo era denergatoria al derecho de las hermanastras de la cuenta donde está de titular Alejandro, de los 147.000€). Veo que no es eso lo que dice la resolución, ya que habla de medidas solicitadas por ausencia del padre: Hola a ambos, adjunto aquí la resolución que ha enviado el abuelo, que nada tiene que ver con la denegación de disposición e la cuenta con el Santander que decía, ya que el procedimiento es acerca de medidas en diciembre de 2018, debido a la ausencia del padre (después de declarado fallecido). En dicho procedimiento la hermanastra Gema solicita al juzgado que solicite la reactivación de la pensión de su padre desaparecido, y que le autorice a realizar las transferencias correspondiente a la pensión alimenticia (entiendo que de la madre de ésta), así como a la cuenta de Alejandro (que era menor de edad en ese momento). El juez denegó esas 3 peticiones a Gema (la hermanastra), como representante del padre ausente, por lo siguiente: 1.-la reactivación de la pensión: que fuera ella directamente la que se dirigiera al Invifas 2.-hablara con el Santander para las transferencias de la pensión alimenticia (entiendo que a su madre) 3.-Ella no puede encargarse de administrar la cuenta de Alejandro ya que la representante legal en ese momento (menor de edad) era la madre biológica del mismo. Por tanto, seguimos igual que antes, no nos han acreditado que esta cuenta es únicamente de él y que judicialmente le han denegado a la hermana que fuera también de ellos, como digo, no es eso lo que dice la resolución judicial. Recordad que llegado el momento y si el abogado de las hermanastras demuestran que el dinero de esa cuenta era del padre,…al ser curatela necesitamos el consentimiento de Alejandro Nuñez Bono para repartir su cuenta entre los 3 hermanos, por lo que si él no está de acuerdo tendrá que pagar por su cuenta un abogado. En mi opinión hasta que esto se resuelva ajustar los gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-03-16','miguel, tras lograr hablar con la jurídico de la Consejería de Vivienda, Ana, me comenta que la única solución pasa porque pongamos a la venta la vivienda, no siendo necesario pedir autorización de venta: Buenas tardes, acabo de hablar con Ana (Jurídico) de la Consejería de Vivienda en Badajoz. Me comenta que la solución pasa porque pongamos a la venta la vivienda. La junta por los años que han pasado no hay que pedir autorización de venta, pero sí de renuncia de tanteo (a través de un modelo que hay en internet, en su web) Una vez que tengamos comprador tendremos que enviar por registro de salida (carta certificada): 1.-Modelo relleno de renuncia de derecho de tanteo (firmados por el curatelado y nosotros) 2.-Fotocopia Dni de compradores 3.-Fotocopia de las escrituras de la compra que hizo Juan Carlos. 4.-Justificantes de nuestra representación de curadores. Recordad que necesitamos nos firme Juan Carlos todos los documentos… para ponerlo en venta en inmobiliaria, para acordar las condiciones de venta (el precio tendrá que ser superior al valor de mercado, por lo que si la Inmobiliaria Colón, que es quién la está vendiendo por la zona estima que son 60.000€ y por tanto que coincide con lo que compró, pues perfecto). También tendrá que firmar la documentación que he mencionado arriba y que habremos de enviar a la Junta, y por último la venta en notaria. Los únicos gastos que debería conllevar la venta, a parte de la cancelación económica de la hipoteca, son los gastos según ley de la escritura notarial de venta y la plusvalía. Por tanto, si lo consideráis oportuno se puede poner en las inmobiliarias que consideréis oportuno, yo opino que una de ellas sea la de la zona, Inmobiliaria Colón. Ya me decís.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-16','Ana: Tras hablar con Carmen, TS, SSASB Coria: carmen.martinez@coria.org / Tlf. 927 50 80 00, Ext. 318, hablo con Alberto, Jefe secc. ecc.: Acordamos, como medida de urgencia, aprobar una retirada de efectivo de 120€, que intentarán que esté mañana mismo. *Carmen se lo comunicará a Emilia. ······················································································································································································· Carmen me facilita el contacto de su hijo Nacho: 642 51 79 61) ····························································································································································································· Envío a Toni-Futuex, correo-e para derivación al Programa de Apoyo Comunitario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-03-16','Ana: Llamada de Felisi, pide extra para ropa y su cumpleaños. Como ya le hemos explicado tanto Juana, secc.ecca. como yo, en múltiples ocasiones, vuelvo a explicarle, de modo que entienda, que con su pensión (PNC) se abonan las facturas de luz, agua, seguro de deceso, alquiler de la vivienda... y se le da, repartido en sus asignaciones semanales lo que queda de la pensión. Le recuerdo también que ya no percibe la PFHC, pues el causante, su hijo, ya es mayor de edad y está también tutelado por la CTAEX y reside en un centro, se la ingresan a él. Parece entenderlo, aunque insiste en que va a ser su cumpleaños y necesita ropa. Le indico que a partir de ahora, puesto que no podrá tener extras, debe ir ahorrando ella unos euros cada semana para cuando necesite comprarse algo de ropa. **Hablo con Alberto, jefe de secc. ecca. y excepcionalmente se le autorizará esta semana un extra 25€ por el cumpleaños, pero será la última vez. *Juana, secc. ecca., le llamará y se lo dirá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-17','Ana: Llamada de José Manuel (678 150 472), dice que se encuentra mal, que le duelen las piernas y está cansado. Le han mandado unas analíticas, tiene que ir a hacérsela el miércoles. Aún tiene pendiente la colonoscopia. **A parte de esto dice que ayer estuvo pidiendo en la calle, junto a un estanco. ··························································································································································································· Correo de Pilar Martín, TS del ESM-CC: "Ana buenos días, han visto a José Manuel pidiendo en la calle en concreto en Avda./ de Alemania. He hablado con el padre Fernando de la residencia" Padre Leocadio" de Pino franqueado y me dic que caso que a través del SEPAD se puede acoger y con la pertinente autorización vuestra la admite en su residencia provisionalmente hasta la disposición de su plaza en CRR. Me puedes llamar al corto-54612, e incluso mejor si lo hablas antes con Mª Luz Madrigal. Un abrazo." ························································································································································································ Acudo a la Unidad de PP.AA.,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2021-03-17','miguel, email de Tere: Nos ha llegado la comulación de PNC de Saul Rodriguez Ramos. Se celebro el juicio pero no tenemos la firmeza, me puedes confirmas si seguimos siendo tutores? Ya que en el caso de que ya no seamos no firmaría JOSE Vicente la comunicación ********************************************************** mi contestación a Tere, Alberto: Buenos días, ayer solicitamos vía fax dicha firmeza. Acabo de hablar con dicho Juzgado por teléfono y me confirman que es firme y que por tanto no somos ya tutores. Dicha contestación de firmeza nos la remitirán en unos días. Por tanto no podemos hacer ya nada más de este expediente. Tere, indica a Tesorería que tendrán que dirigirse a su familiar Juana Rodriguez Garcia que es quién la tiene. Pongo en copia a Alberto para que sepa que ya no somos tutores de este señor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-17','miguel,recibo email de Alberto: Ana hablará con T.Social centro penitenciario para indicarle que NO se pueden abonar más deudas y que tiene que ajustarse a lo autorizado...200 €/mes. Ana hablará con HERMANO para preguntar x teléfono (90 €/mes de media). Ana, si puedes que hermano tramite baja. Podemos devolver recibos. Ana/HERMANO: • AUTO: BAJA COCHE + damos de baja los seguros???... MIGUEL, XFA, COMO VA EL TEMA JURÍDICO DE IMPEDIR QUE PUEDA CONDUCIR...PODEMOS DAR DE BAJA SEGURO Y COCHE??? • tutelado está pagando luz/agua...seguimos pagando??? ********************************************************* contestación a email de Alberto: Hola, no tengo constancia de este expediente, pongo en copia a Angel por si puede añadir algo entorno a lo que decís de cómo va el trámite de quitarle el carnet de conducir. Pongo copia también a Juan P. por si nos puede ayudar, porque no veo en la carpeta de incapacitación el nombramiento de la Ctaex y la aceptación del cargo. Adjunto el documento de incapacitación donde veo que tiene esquizofrenia. También hay una carpeta sobre sobre conducción de vehículo que contiene los dos documentos que adjunto, donde el informe médico de aptitud ya indica que tendrá que ser el centro de reconocimiento de conductores el que dictamine si está o no capacitado para conducir. El resto de lo que indicáis en vuestro email son cuestiones económicas, si hago una observación, …por lo que leo en la intranet, si va a tener que devolver ayudas, ojo! Porque si gana menos del SMI no pueden embargarle, es decir, se quedaría la Junta sin recuperar ese dinero entregado, ya que por lo que veo en la rendición última de cuentas al Jzdo nº2 de Cáceres, tiene una prestación por orfandad y por hijo a cargo que no serán más de 600 o 650€, y unos ahorros mínimos de 1.700€… Ya me decís si desde la parte Jurídica tenemos que hacer algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='CRESPO'and apellido2='CRUZ'),'2021-03-17','Ana: Según el informe social del CSS-Plas. para la rendición de 2020, está muy integrada en el centro, mantiene buenas relaciones con compañeras y participa en las actividades organizadas. ·· En cuanto a la situación familiar, sus padres fallecieron hace años. Tiene dos hermanos que residen en Nuñomoral que la visitan muy poco debido a la edad y a las relaciones personales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-17','17/03/2021:BELEN: RECIBIMOS LLAMADA DE SONIA DE ABANCA EN CORIA927504237,PARA INDICARNOS QUE, LA TUTELADA HA IDO HOY A RETIRAR LOS 120€ CON SU HIJO, Y QUE HA HABIDO UN ALTERCADO EN ELLOS Y QUE NO ES LO MÁS ADECUADO PARA LA OFICINA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-17','Ana: Llamo a Carmen (927 50 80 00, Ext. 318 ): explico que ya a habido un incidente en el banco, con el hijo, desde el banco han llamado a Belén, secc. ecca. **Carmen hablará con ellos. Vamos a intentar que Nacho, hijo, no entre en el banco. *Le informo también que ya está hecha la derivación a FUTUEX. *Valorará también la posibilidad de asignar SAD, para abril. **Barajaremos además la opción de acuerdo con un supermercado o cátering (esto ultimo no lo tiene tan claro). ······················ Me informan que proceden de una familia acomodada, bien posicionada económicamente, sin antecedentes en los servicios sociales. Emilia preseta deterioro cognitivo. Nunca habían ido al médico (no sabían quién era su médico de atención primaria), han comenzado a asistir y ya han acudido a alguna cita con especialistas, aunque también han perdido alguna. *La familia extensa no quiere saber nada por los problemas que genera el hijo. Quién ya ha pasado por varios centros, pero aún tiene problema de consumo. ···· *Nunca han cocinado, comen en los bares','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-03-17','Ana: Correo de Alberto, jefe secc. ecca. en respuesta al mío: "Hola Ana, buenos días. En relación con la ayuda a la hija de la tutelada (ALBA VAQUERO BERNARDO), te informo que ya hemos procedido este último año a transferile 600 € (2 transferencias de 300 en abril y septiembre de 2020 (de momento semestrales). La tutelada cobra una PNC y lo único que hace que tenga una situaciaón ECO adecuada es que no abona centro (CRR Plasencia). Yo entiendo que toda madre quiere ayudar a su hij@ pero, en mi opinión, como mínimo, deberiamos contar con un informe social de algún tipo (SSBB o similar) que avale las necesidades dque pueda tener la hija de la tutelada (lo cual no pongo en duda). Repito, mientras esté en CRR no hay problema ECO, pero evidentemente en cualquier otro sitio sería NO VIABLE. Creo que deberiamos poder justificar la necesidad de ayuda que requiere hija. No se si CRR nos puede ayudar con eso. Hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-03-18','Ana: Llamo a Paula, TO CRR-Plas. (682 704 401), varias veces, sin éxito. Le reenvío el correo de Alberto y pido me responda o me devuelva la llamada cuando pueda. ····························································································································································································· Respuesta de Paula: "Buenas Ana, si te parece puede ser interesante que habléis de esto con ella. Nosotras lo hicimos previamente exponiendo argumentos muy similares a los que comentaba Alberto, puesto que ya se había planteado el dilema la última vez que se había accedido a realizar la trasferencia. Como ella ha contactado directamente con vosotros pensamos que hablarlo exponerle las dudas podría estar bien y después que ella valore si quiere pedirle a su hija que solicite un informe de necesidad y aclarar si en esta ocasión el objetivo era éste (y no por ejemplo, que fuera su cumpleaños u otro motivo). Es bueno que ella pueda tener información, ya que en su proyecto a medio plazo (si es posible para este mismo año, si continúa evolucionando de la misma forma que hasta ahora) es poder vivir de forma autónoma en un piso, dónde sus gastos serán mayores, pudiendo necesitar su pensión completa para sufragarlos. Gracias por comunicar, llevo una semana que los correos me funcionan mejor (aunque cruzo los dedos) pero no he visto las llamadas, si eran ocultas a lo mejor no se han quedado registradas (nuestros teléfonos son antiguos no smartphones) en cualquier caso disculpa. Si hablas con Toñi me dices, nosotras haremos lo mismo." ·························································································································································································· Llamo a Toñi (617 223 527) varias veces, pero no obtengo respuesta. ··············· Llamo al PP.SS. (677 40 78 93): me pasan con Toñi, explico la situación y parece entenderlo y aceptarlo. ··························································································································································································· Correo a Alberto, Jefe secc.ecc. y Paual: "Buenos días, de nuevo, Acabo de hablar con Toñi, le explicado la situación y parece haberlo entendido perfectamente. A día de hoy NO se le hará dicha transferencia a su hija. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-03-18','Ana: Envío a Mar Declara Peña, Aux. Admvo. Admisión Lista de Espera HUC (mariamar.declara@salud-juntaex.es), los C.I. para anestesia loco-regional y general relativos a Rosa, debidamente sellados y firmados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-03-18','miguel, recibo email de Jesús Bueno remitiendo Auto firme de las 5 fincas que faltaban. Dicho Auto es firme por lo que veo, no obstante, el primer auto (que recogía sólo 2 fincas) no tenemos la firmeza, por lo que me ha remitido otro email con la remisión al juzgado de solicitud de testimonio de firmeza de ambos autos. ********************************************************** Remito a Ainés (hna del Tutelado y a su abogada Ana de Pablo) ambos Autos y les comento que estamos a la espera de que nos remita el Abogado el testimonio de firmeza solicitado. Asimismo les indico que tendrán que indicarnos notaria y fecha de firma de ventas para coordinar con la notaria de Mérida, para que podamos ratificar las escrituras desde aquí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-18','miguel, recibo email de la abogada de Damian, Rocio (tlfno 607650498) Buenos días, Miguel Alicia Cueto me confirma que podemos iniciar las acciones legales con la conformidad de Damián Granados. Para ello necesito la documentación que te relacioné en mi anterior correo. También es necesario que Damián apodere a la Procuradora, lo cual puede realizar o bien mediante poder notarial o por comparecencia apud acta aquí en el Juzgado de Málaga. Espero tu respuesta. He intentado en varias ocasiones llamar al teléfono que consta en tu correo pero no responden. Mi número es 607650498. Rocío Gracián Fernández','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-18','ICIAR:HABLO CON AQUANEX 900 202 038: ME CONFIRMAN DE QUE NO ESTÁ EL CONTRATO A SU NOMBRE SINO AL DE UN TAL JESÚS GALLEGO ALEMÁN ( EN EL EMPADRONAMIENTO APARECE IGNACIO GALLEGO GUTIÉRREZ) ME LLAMARÁN EL 30/3/21 A LAS 9:45 PARA GESTIONAR TRAMITES NO TIENE AVISO DE CORTE DE AGUA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-03-18','miguel, remito al Jzdo n2 de Cáceres contestación al requerimiento que hicieron de lista de espera en residencia.','2');
