insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-03-12','Ana: Dado que Ana María no ha llegado a acudir al SEPAD en el mes de marzo, y nos extraña, Belén, secc. ecca., comprueba su cuenta bancaria y, a pesar de no haber enviado al banco autorización para retirada de efectivo este mes, retiró unos días antes 500€. *Icíar, secc. ecca., nos informa de que desde la Sucursal Bancaria han manifestado tener miedo a esta Sra. y por ello le han dado dinero aún sin autorización.','2');
