insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-03-18','Ana: Llamada de Tomás, Coordinador de Caldidad - Dirección Gerencia SEPAD (924 008 493): en relación a Costi Alexandru, han remitido un Burofax desde la Fundación Autismo Sur, reclamando la deuda que está generando Costi en su entidad (Ropa, calzado, farmacia, desplazamientos tramitación Pasaporte...). Le informo sobre cómo está a situación. Continúa sin ingresos de ningún tipo. Estamos a la espera de recibir respusta de PNC de la Delegación de Málaga. *Se lo comunicará a José Vicente - D.Gerente. No saben si podrán pagarlo/adelantar dinero de alguna manera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-18','Ana: Llamo a Luz, TS del C. Penitenciario de CC (927 181 407), Maite, TS, me indica que ahora es ella quién lleva el Módulo 2 (en el que está Saturnino). Le indico que debido a deudas y multas varias de Saturnino Miguel (Tráfico y Salud Pública), no se le puede aumentar la asignación, pues no puede afrontar de por sí todos los gastos. Tiene que ajustarse a lo autorizado...200 €/mes. ·············· Maite solicita se lo comuniquemos por escrito al propio tutelado. *Lo pediré a la sección económica. ·························································································································································································· Llamo a Francisco, hermano de S.Miguel (630211717, 927-244205 // arroyomolinos@prontonmail.com): Puesto que no consigo contactar por teléfono, le envío un correo para que se ponga en contacto conmigo cuando pueda.','2');
