insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2021-03-22','Ana: Adelanto escaneado por correo electrónico a Modesto, Res. de Mayores Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es), el Contrato de Admisión en Centro Residencial. ············· Preparo oficio y lo pongo para registro de salida. ·························································································································································································· Respuesta de Modesto-Residencia: "Hola Ana!!!!!!!!!!!!! Recibido, muchísimas gracias. Por aquí genial y Juan ni te cuento, está hecho un chaval. Lo único que me pregunta mucho por saber de sus extractos bancarios pero ya le tengo dicho que no se preocupe que todo está bien. Un abrazo!"','2');
