insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-03-22','. Morón Hernández, José María. salida por cumplimiento de medida El 26 de Mayo de 2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-03-22','EMAIL FUTUEX En relación a lo que me has mandado de Emilia Morales Botello, te actualizo la info con lo que nosotros hemos averiguado, al parecer no está en el Hostal Senero... ni tiene intención de estar, ya está con su novio en otro hostal al parecer hasta el jueves, aunque ninguno de los dos tienen dinero y ella si supiera que tiene reservada esta opcion tal vez la aprovecharia.. pero ambos son dos buscavidas.. y estan alli hasta el jueves que piensan volver a Don Benito, te pongo por aqui su numero 622 83 76 84 y el 722 43 24 18, (este es el que usa mas por lo visto) por si necesitas hablar con ella y te cuento la situacion en contexto de la que hemos tenido informacion: los pasados 15 y 16 de Marzo se llama al móvil de Emilia Morales Botello en varias ocasiones sin obtener respuesta porque se encuentra apagado. Por lo que se llama al móvil de Miguel Ángel Mateo Martínez (644 62 55 93), su novio de Don Benito. Cuando se le pregunta por Emilia, él responde que está ingresada en Mérida desde la semana anterior. El pasado 17 de Marzo se llama a la UHB de Mérida y se habla con una enfermera de la unidad, que confirma que Emilia Morales está ingresada allí desde el día 9 de Marzo. Comenta que el médico que la está tratando es el Dr. David Gimeno y le pasa la llamada para que se pueda conversar un rato con él. El Dr. David comenta que la tutelada se encuentra mejor que cuando ingresó, que sucedió porque ella llamó al 112 desde la casa de su novio en Don Benito y pidió que la trasladaran a Mérida. El Dr. David Gimeno comenta que la tutelada ha pedido que se la incapacite de manera total para estar mas protegida y cree que es algo muy positivo por su parte. Se coincide con el doctor en este punto pero se le comenta que el proceso es un poco largo y que aunque empiece a tramitarse ahora, tardaría meses en hacerse efectivo. Se le recomienda que contacte con la Comisión Tutelar para comentarles la predisposición de Emilia al cambio de curatela a incapacidad para que ellos le faciliten más datos al respecto. El Dr. David Gimeno también comenta que está pensando en darle el alta a Emilia el domingo día 21 de Marzo y que ella le ha dicho que se irá a Don Benito con su pareja porque ahora mismo se encuentra muy bien con él. Aunque le ha reconocido que tienen una relación complicada y discuten muy a menudo. Por último se conversa con Inma (924 80 20 06), la trabajadora social del centro de salud Don Benito Oeste. Para cancelar la cita que se tenía con ella esa misma mañana con la intención de buscar un centro para Emilia. Se le informa de que Emilia está ingresada en el hospital de Mérida y ella comenta que llamará por teléfono para estar informada de su estado y de su evolución. El pasado 18 de Marzo se llama en varias ocasiones al Dr. Gimeno al hospital de Mérida y se le dejan varios mensajes pero no se consigue hablar con él. El pasado 22 de Marzo se llama a Emilia Morales porque se tiene una llamada perdida suya del domingo día 21. Ella coge el teléfono y cuenta que le dieron el alta de la UHB el día anterior y comenta que se ha quedado en Mérida con su pareja a organizar unas cuantas cosas. Emilia comenta que quiere hablar con la comisión porque tiene que cambiarse de gafas ya que con las que tiene cada vez ve peor. Y la ópticas en Don Benito son muy caras por lo que le gustaría comprárselas allí en Mérida. Se le pregunta a Emilia dónde se están hospedando, ella responde que en el Hostal Anas, de la Avenida Reina Sofía, 9, Teléfono: 924 31 11 13. Cuenta que les cuesta 35€ la noche y la noche del domingo al lunes la han pasado allí. Emilia comenta que la idea que tienen es la de quedarse en Mérida hasta el jueves 25 que será cuando su novio Miguel Ángel cobrará su pensión, supuestamente pagará las cuatro noches de pensión, que sumarán 140€ y se marcharán a Don Benito. Emilia cuenta que no le queda nada de dinero de su asignación porque se gastó casi 80€ hace unas semanas comprando comida. - Se llama al hostal Anas de Mérida y se habla con Tania, la recepcionista. Ella cuenta que Miguel Angel, el novio de Emilia es un asiduo del hostal ya que se hospeda una o dos noches al mes mínimo. Tania cuenta que siempre se ha portado muy bien en el local y le ha pagado religiosamente. En esta ocasión, Miguel Ángel le ha comentado que el jueves día 25 de Marzo cuando cobre su pensión, irá al hostal y pagará las cuatro noches. Se le pregunta a Emilia por las comidas que están haciendo y cómo las están pagando, ella responde que por ahora los desayunos los están dejando fiados porque no tienen dinero y tienen intención de pagarlo cuando Miguel Ángel cobre su pensión. Se le intenta explicar que cuánto más tiempo pasen en Mérida, más deudas van a generar por lo que deberían irse a Don Benito lo antes posible, pero Emilia contesta que irán a por comida a Cáritas y que no disponen de dinero ni para pagar el billete de autobús a Don Benito por lo que se esperarán hasta el jueves que es cuando Miguel Ángel cobra para pagar las deudas que tengan y para comprar los billetes de bus para volver a Don Benito. Emilia demanda a la comisión que vuelvan a darle la asignación de manera semanal ya que mensualmente le dura menos el dinero. Aunque comenta que la oficina de Liberbank de Don Benito ponía pegas cuando ella iba a retirar su asignación de manera semanal por lo que pide que se hable con la oficina de Don Benito para que pueda retirar dinero semanalmente sin problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-03-22','teresa Buenos días Teresa. Es en relación a permitir una salida para las vacaciones de Semana Santa a Aitor. Hemos hablado con él sobre el problema que siempre nos encontramos a su regreso del domicilio familiar. La psicóloga y yo como trabajadora social queremos darle una nueva oportunidad. Vamos a firmar con él un contrato conductual en el que Aitor se compromete a su regreso: - al respeto hacia nosotras y al resto de compañeros - al respeto de las normas de funcionamiento del centro en cuanto a medidas de higiene y distanciamiento establecidos por protocolo a su regreso - a la asistencia a las sesiones del CEDEX, con el que hemos iniciado su intervención. Te adjunto y si lo veis correcto, el documento para que firme el tutor su autorización de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-03-18','Ana: Correo de Toni-Futuex: "...Desideria y Angel llevan tiempo sin acudir al sociosantiario, les vienen haciendo el seguimiento desde salud mental del centro de salud, el luis de toro. Pero hay novedades en este caso, y precisamente la compañera hoy esta en Plasencia, hemos organizado un seguimiento de urgencia, porque al parecer la pareja de Desideria (Angel) está ingresado en UHB de Hospital Virgen del puerto de Plasencia desde el viernes.. Eso hace que Desi este sola en casa y aunque es funcional, es muy dependiente de el, por esto, aunque no le tocaba retirar dinero (que es la gestion principal en la que se les apoya desde aqui) hemos ido para allá. Desi esta bien, en cuanto a las cosas fundamentales, tiene bien de comida y estaba aseada, en apariencia, tiene todas las necesidades cubiertas. Pero en cuanto a su estado mental, esta con sus habituales delirios de persecucion (compartidos con el marido) y tal vez un poco agravados por estar sola (no coje el telefono porque dice que la espian, esta muy desconfianda de todo y dice que no quiere salir de casa porque la vigilan.. por ej) De modo cotidiano ella tambien tiene un discurso alejado de la realidad, pero claro, no sabemos si esta situacion puede hacer que se descompense (más). Iremos nuevamente a verla la semana que viene, mientras siga ingesado su pareja., Hemos comunicado esto a su psiquiatra del Socio,Rosa, y dice que ella va a coordinarse con el LUis de Toro, pero que lo hagamos nosotros tambien (que no entiendo muy bien esto pq la comapañera esta llamando y no consigue hablar con nadie de salud mental..) pero vamos a intentar comentar la situaicon que hemos observado alli, y suponemos que le haran un seguimiento de salud mental y en caso de que consideren, la ingresaran. Pensaba obtener alguna informacion mas para trasladartelo todo, poruqe esto sucedió ayer y la visita se ha realizado hoy por la urgencia, pero basicamente, todo esto es lo que sabemos hasta ahora.. que a pesar de estar sola, Desi, tiene comida y está aseada (ella es funcional para estas tareas) y ahora pues esperemos que desde salud mental le hagan un seguiminento para comprobar que no se desestabilice mas... y decidir un ingreso en tal caso. Nostros volveremos proxima semana a verla y hay un amigo de ellos (peluqero del sociosanitario) que es amigo de la pareja, y que va a ver a casa a menudo a casa. Te seguire comentando a medida que tengamos mas info!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-03-22','La sentencia conseguida por Amalia (que le ha remitido el abuelo del tutelado), no incide en la posibilidad de que las hermanastras tengan derecho a 2/3 de la herencia del padre. Decisión: se anulan los 450 €/mes de ayuda al alquiler y se mantiene la entrega de la totalidad de pensión. AMALIA se lo comunica a el abuelo/tutelado y JUANA anula el rintegro con efecto 01/04/2021. EXTRA: sólo para cuestiones imprescindibles. Básicamente SANITARIO y como máximo 1 paga extra (ya se han consumido 80 € para un tema de ortopedia). Alberto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-03-22','Ana: Recibo llamada de Mª Jesús, Psiquiatra del ESM Plas. (74951). Desideria tiene cita el día 26/03/21. Pregunta si se le podrá acompañar. Le indico que si es posible acudirán del programa de apoyo comunitario de Futuex, desde el que le hacen seguimiento. Tenían planteado ir a visitarle esta misma semana, probablemente el miércoles. Me pide el nº de Sonia - Futuex, para coordinarse con ella al respecto. Le facilito el de la oficina y que pregunte por Toni, la coordinadora. ···················· Llamo a Toni y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-22','Ana: Envío correo a Alberto, Jefe Secc. Ecca. e Icíar: "Buenas de nuevo, Acabo de hablar con Toni, en relación a Emilia Gutiérrez Serradilla, a mediados-finales de esta semana irán a verla por primera vez de FUTUEX, y a partir del lunes de la semana que viene podrá retirar Gloria, Educadora Futuex, el dinero en el banco, como propuso Alberto y luego entregárselo a ella. (Nos enviará nota con los datos de ella para la autorización) *De momento mañana tendrá que ir de nuevo ella, la propia Emilia, a retirar el efectivo (ENVIAD LA AUTORIZACIÓN). La TS le ha dicho al hijo que él no entre en la entidad bancaria, otra cosa es que luego lo cumpla… Tenemos pendiente aún cerrar, o bien cáterin o bien “depósito” en supermercado. Volveré a hablarlo con la TS y Gloria pedirá presupuestos de cáterin para plantear opciones “cerradas”. Dependiendo de qué valoren también con Emilia iremos cerrando cosas." ·············· Después llamo a Carmen, TS SSASB, para confirmarle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-03-22','Ana: llamada de Conchi (651 557 072), dice que su hermano ha enviado una factura de 1000€ por el arreglo de la pared que se había caído de su casa. Puesto que es compartida con la vecina, la factura la pagarán a medias. *Puala, T.O., del CRR ya envió un correo al respecto en su día. ······················································································································································································ Lo comunico a Alberto, Jefe Secc. Ecca. mediante mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2021-03-22','Ana: Pongo para la firma del D.Gerente el informe PAI (Plan de Atención Individualizado) que remiten desde Cruz Blanca. En el mismo se expone que "...hay pérdida de su capacidad física y funcional", su inactividad y aumento de sedentarismo durante la pandemia, "ha hecho que perdiera agilidad, resistencia, flexibilidad, destreza motora, equilibrio, coordinación y que avance su proceso de envejecimiento a mayor ritmo que antes". Por otra parte "permanece bien adaptado y con buen ajuste psicosocial", "Mantiene buenas relaciones sociales denro de la casa, tanto con trabajadores como con residentes, estas relaciones son significativas". "Es independiente en las ABVD", "Se observa un aumento de apatía en los últimos meses. Hay que insistirle para que participe en las actividades..." "...no ha presentado ninguna alteración de conducta en los últimos meses"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='FAJARDO'and apellido2='ABRIL'),'2021-03-22','-Amalia : Buenas tardes , os reenvío la factura que envía Fernando Sosa , " ahijado " de Dolores Fajardo . La Sra. está ingresada en Puente Real I , este señor se encargaba de cuidarla , es vecino suyo y está en desacuerdo con la tutela ,porque quería que se le nombrase a él . Tiene llaves de la casa , se las facilitó Dolores y va a visitarla semanalmente . Refiere que es el heredero de Dolores . Dolores tiene 3 perros en su casa que él está cuidando y quiere seguir haciéndolo pero pide el dinero del pienso para los perros. En la cuenta de esta señora dice que están domiciliados todos los pagos : residencia , seguro decesos , IBI fraccionado en dos , agua ... Si lo consideráis oportuno se le tendrían que abonar el dinero para la comida de los perros . Amenaza con que si le cuenta a ella que nos deshacemos de sus animales solicitará el alta de la residencia . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-03-22','-Amalia : vuelvo a comunicar al ESM que Mercedes tiene unos episodios de delirios muy agudizados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-03-22','-Amalia , escrio de nuevo al ESM : Buenas tardes , espero que estéis bien . Te escribo en relación a Mercedes Pérez Pinna , mi compañera Juana ha hablado hoy con ella por temas económicos y me traslada su preocupación por sus delirios . Verbaliza que no duerme por las noches , que permanece sentada porque "entran en su casa para robar y violarla " . Hace poco te escribí por el mismo tema , el psiquiatra consideró que es residual de su enfermedad pero sería conveniente que lo supiese por si tiene que ajustar la medicación. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-03-22','2021/03/22 VIVIENDA PROTECCIÓN OFICIAL: VENTA. MIGUEL, tras hablar con Vivienda, indica que es viable la venta de la vivienda de protección oficial. DECISIÓN: proceder a la venta de la vivienda. Miguel hablará con una posible compradora (Cindy) y si esto no prospera pasaremos a la INMOBILIARIA COLÓN que es la que trabaja en la zona y vende viviendas similares (tb Miguel). Veremos las condiciones de la Inmobiliaria. 2021/03/22: VIVIENDA LIBRE: ALQUILER Hay 1 opción de alquiler. Inquilinos arreglan vivienda a cambio de no pagar fianza ni 1º y 2º meses: 190 € x 3. Valorar esta opción dentro de 1 mes para ver adecuación tutelado a nuevo centro + rapidez venta vivienda libre. Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='DIAZ'and apellido2='DIAZ'),'2021-03-22','Ana: Correo de Emilia Almodovar, TS CSS-Plas. (emilia.almodovar@salud-juntaex.es) al ctutelar@ : "Comunico que José Diaz Diaz ha ingresado el sábado día 20 de Marzo en el Hospital Virgen del Puerto de Plasencia, por rotura de cadera. Según informa supervisora de enfermería en el día de hoy no necesita acompañamiento, la operación será mañana si cambian las circunstancias nos avisarán para que el paciente sea acompañando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2021-03-23','teresa archvio resolucion de pnc y envio copia al centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-03-23','Ana: llamo a Felisa Custodio Hernández, TS CAMF de Alcuéscar (trabajador_social_alcuescar@imserso.es // Tfno. 927 38 41 25 -- Ext. 46138) en relación al correo que envió a Ángel, Asesor Jurídico CTAEX, consultando la pertinencia de salir a pasear con su pareja y/o que éste le visite en el centro, Felisa corrobora que además de no ser el mejor momento dada la pandemia actual, no se relación beneficiosa para Felisa, en la que se entreveé algún tipo de interés (seguramente económico) por parte de este señor. Tras llegar a un acuerdo, envío un correo-e a Felisa, con copia a Ángel, Asesor Jurídico CTAEX, exponiendo el mismo: "Buenos días Felisa, Tal y como hemos acordado mediante conversación telefónica, te envío este correo para responder a vuestra consulta. Dadas las circunstancias sanitarias, no se considera procedente que Isabel salga del centro con este señor, pues están limitadas las reuniones con personas no convivientes y no se trata de un familiar directo. No obstante, tal y como hemos hablado, dada la importancia que tienen para Isabel estos encuentros, y para no generar mayor malestar en ella, se autorizan las visitas, una vez a la semana con una hora de duración en la recepción del CAMF, siendo un entorno contralo y en el que además se pueden extremar las medidas anticovid. Ante cualquier otra cuestión, no dudes en volver a contactar. Un abrazo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-03-09','Ana: habiéndo trasladado a Ángel, Asesor Jurídico la consulta de Felisa Custodio, ambos intercambian correos. Felisa remite informes médico y psicológico y Ángel le explica/argumena los motivos por los que no conviene que Isabel contraiga matrimonio (*Todo guardado en el expte. digital)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-23','Ana: Llamo a Eva, Secc. Salud Mental, U.PP.AA.; no obtengo respuestas. Le envío un correo: "Buenos días Eva, Te he llamado al personal, perdona pero estoy teletrabajando y el nº que aparece a tu nombre en el directorio (924 00 84 20), dice que no existe… Supongo que estarás ocupada. Tan sólo quería preguntarte si os han confirmado si se puede usar las habitaciones reservadas por Covid de los CRR, como me comentaste el jueves. José Manuel llama todo los días para preguntar, como tú ya sabes, necesitaría estar en un recurso, la vedad. Ya me dices cuanto puedas." ··························································································································································································· Llamada de José Manuel, si no pudiera ingresar en breve en el CRR, acepta ingresar de forma temporal en el Centro Padre Leocadio de Pinofranqueado. ······························································································································································································ Respuesta de Eva Paredes: "Hasta ahora no he tratado el tema con Soraya, pòrque ayer no tuve que venir al final. Te cuento: Le he explicado que según la última normativa publicada en DOE, los centros menores de 50 usuarios, no tienen que tener reservada la plaza de COVID, no es obligatorio ya. Ella me dice que aún así tenemos que tener cautela, proque se nos pueden dar situaciones de tener que aislar a un caso COVID, etc., y si el centro no tiene esa habitación puede dar problemas. Por otro lado, en el CRR de Badajoz están ya todos vacunados y me plantea Soraya que podríamos hablar con el ESM de Cáceres haber si podríamos desde el area de salud de Cáceres acelerar su vacunación para cuando le demos plaza en CRR al menos que vaya vacunado, pero la verdad no se si eso será posible o no. Yo creo que sería mas rápida su vacunación una vez sea usuario de CRR Badajoz. Mañana retomaré este tema a ver si te podemos dar una respuesta más clara, porque como ves no se ha dejado cerrado el tema de si cubrimos o no la plaza de COVID en Badajoz."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-18','Ana: Conversación con Eva Paredes, Psicóloga Secc. Salud Mentral, U.PP.AA.: están pendiente de que les confirmen el lunes si se pueden utilizar ya las habitaciones reservadas en los CRR por el Covid. *Si fuera así, José Manual podría ingresar en el CRR Ba. ···· No obstante, pos si no pudiera ser, planteo la opción de la Casa de la Misericordia del Padre Leocadio de Pinofranqueado. Contemplarían esta posibilidad, tienen un acuerdo con dicho centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-03-23','Ana: Toni-Futuex me adelanta por mail, Informe de Salud para la solicitud de Valoración de Dependencia. *Me enviará por correo postal el original.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-03-23','Ana: Envío correo a Sandra, TS de la Res. Real Patronato (alexandra.alfonso@coria.org): "Hola de nuevo Sandra, En relación a la gestión para el DNI de Teresa González Jorna, ya tengo preparada y firmada la solicitud de la Unidad Móvil de la Policía Nacional, pero seguimos sin tener el Certificado Literal de Nacimiento con fecha de este año. ¿Has vuelto a hablar con la hija al respecto? Si crees que no podrá tenerlo, lo que se me ocurre, aunque también tarden algo en enviarlo, es pedirlo directamente por escrito desde la CTAEX. Ya me dices. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORCILLO'and apellido2='HERRERO'),'2021-03-23','Ana: Tras llamada de Sandra, TS de la Res. Real Patronato de Coria y consulta posterior con los compañeros (Asesores Jurídicos y Amvos.), envío correo-e a Sandra (alexandra.alfonso@coria.org): "Buenas tardes Sandra, Tras haber realizado la consulta con los compañeros, me comunican que seguimos sin recibir la firmeza de la sentencia, sin la cuál no podemos intervenir. Ya la han pedido en varias ocasiones. Me indican que lo único que pueden hacer al respecto es seguir insistiendo al Juzgado. Les he pedido que lo hagan. No obstante, considero, como ya hablamos esta mañana por teléfono, que no está de más que preguntes tú también a fiscalía, independientemente de que mis compañeros vuelva a solicitarlo, pues puede resultar más efectivo. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-03-24','email recibido por Iciar por Blas Rodenas Gonzalez >rodenasgonzalezb@gmail.com: Buenos días Iziar Necesito hablar contigo con urgencia por favor llámame. Necesito al menos 200€, pues aún no he podido renovar el carné de conducir, además tengo que comprar fruta, pagar a la panadera, y darle algún dinero a Isabel. Recuerdas que tenía 150€? Pues le di a Isabel dinero para el garaje atrasado ( 60€ y 50€ a cuenta para lo que le debo del local, así que ya le debo solo 20€ del garaje de este mes y darle algún dinero para lo atrasado del local, que con lo que le di último queda pendiente aún 1.300€. He tenido que comprar las 7 pipetas anti pulgas para mis gatos y de lo poco que le quedaba a Blas, las he pagado, y tb he pagado gasoleo para el coche ya q estaba en reserva y aunque esté parado no se puede dejar sin ningún combustible, y he tenido q coger una botella de butano, y necesito coger otra de reserva. Si sumas verás que Blas ha colaborado y mucho, pero como ya no le ingresan nada de pensión pues tenemos que arreglarnos con lo mío. La factura del pan que me trae la chica de la furgoneta te la mandó cuando me la de y la nota de la panadería tb te la mando para pagar las dos cuando cobre el 25 de este mes. Pero lo del carné, lo de Isabel, la bombona de repuesto y la fruta lo necesito ya por favor. 200£ y no se si sobrará algo que lo dudo, compraré un cachito de queso para Blas, ya que compramos un quesito fresco para mis cenas y a Blas ese queso le da fatiga. Aparte que ese el que toma el, solo lo venden en Coviran. No habría forma de distribuir el dinero de la comida, entre el súper del DIA y el de COVIRAN?? Es que en el día no tienen cosas que necesitamos y si lo tienen en Coviran comprendes?? Y por último, necesito saber si se le ha pagado a Pepita y a Maribel, e informarme de a que acuerdo habéis llegado para pagar a los bancos y demás trampas porfa. Una cosa que no te he dicho, es que como los dos tenemos una máquina para la Apnea de sueño y Blas encima tiene oxígeno, la Junta nos ingresa en la Caixa cada dos meses unos 40 € aproximadamente, así que por favor, comprueba si desde que tenéis mi administración lo han así ingresado vale? Creo que no se me olvida nada, pero si no es asi, ya te mando un correo cortito. Bueno espero tu llamada para que me confirmes que has leído el mensaje porfa. Te deseo un lunes maravilloso y que te cuides mucho ok? ******************************************************* Alberto remite a Amalia y Miguel: Amalia y Miguel: únicamente tened en cuenta lo que hace referencia a la RENOVACIÓN DEL CARNET DE CONDUCIR. Nos pide dinero para renovación carnet + creo que no tiene seguro de coche (habría que hacerlo) + combustible. Os informo de que el marido parece que está en silla de ruedas. Es URGENTE decidir sobre esta cuestión y para ello debemos estar las 3 partes de acuerdo. ********************************************************** Contestación Miguel: Buenos días, añado a Angel a estos email. Según veo en la intranet Angel apuntó el 18-11-20 el siguiente apunte donde queda claro que podemos oponernos: “Email de Angel , jurídicio sobre el tema de renovar el carnet de conducir : En la Sentencia de Incapacitación, esta persona, a pesar de sufrir incidencias de fibromialgias, distimia, estrés adicional, trastorno depresivo de base y trastorno por acumulación, éstas no inciden en el gobierno de su persona, gozando de suficiente estabilidad psíquica para mantener el juicio. Está sometida a tratamiento médico y psicofarmacológico, acudiendo regularmente a consultas concertadas. Es aquí donde podemos comprobar si de los medicamentos que toma, en los prospectos limitan o incluso prohíben conducir, tal y como hicimos con José Florencio (podéis ver la contestación que se hico al Juzgado en su expediente). En ese caso, podríamos oponernos a que pudiera conducir. No olvidemos que esta es otra de las ya conocidas curatelas (como la de Rafa Santos, Alejandro Nuñez, etc), donde estamos para SUPERVISAR, APOYAR Y ASISTIR, cualquier acto económico y patrimonial”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-03-24','TERESA HABLO CON LOLA TS DE PLENA I Y ME COMENTA QUE TIENEN PREVISTO DSDE LA UDHAC TRASLADO DE ANDRES PARA EL 5 AL 12 DE ABRIL. NO HARA AISLAMIENTO SE AUTORIZA 50 ERUOS PARA CELBRAR SU CUMPLEAÑOS QUEDO A LA ESPERA NOS COMUNIQUEN COMO SE HARA EL TRASLADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2021-03-24','TF. DE LA MADRE ( ANTONIA ) 924254893/630620162','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SIXTO NICANOR'and edp.apellido1='ALMODOVAR'and apellido2='JIMENEZ'),'2021-03-24','Buenos días , he recibido llamada de un sobrino de SIXTO ALMODOBAR JIMÉNEZ , ingresado en CSS Mérida. Su sobrino es Jose Mª , tf 649863685 . Al parecer el tutelado es usufructuario de una casa en Gárgaligas que quieren vender por encontrarse en malas condiciones . Quieren información en lo que respecta a su tío . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-03-24','Ana: Envío correo a Paula, TO PPSS asociado a CRR Plas (tocupacional.crrplasencia@grupo5.net): "...Teníamos pendiente también enviarte el documento de Aceptación de Ingreso en Piso Supervisado relativo a Toñi Bernardo Piris, debidamente firmado digitalmente por su representante legal. Adjunto lo remito. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-03-24','Ana: respusta de Sandra, TS de la Res. Real Patronato (alexandra.alfonso@coria.org) en relación al Cdo. Literal de Nacimiento: "Pues me llamó la semana pasada y ha quedado en traerlo en estos días. Gracais"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-03-24','email de 11-3-21 de Mª Martin Rivero del Encinar de las Cruces: Buenos días, desde el centro para mayores Encinar de las Cruces, como trabajadora social del centro, informo a la comisión de que nuestra usuaria MARIA ANDREA DAZA REGALADO tiene una cita médica con Neumología el día 15 de marzo a las 11:00. Para dicha cita precisa un acompañamiento por personal del centro, lo cual se factura aparte y son aproximadamente unos 30 €. Solicitamos permiso para facturarle, por domiciliación bancaria, este gasto. A la espera de su respuesta. Un saludo ******************************************************* email de Alberto 11-3-21: Ficha de Andrea Daza hecha. No se puede mantener situación...gasta más de lo que ingresa, y además no tiene fácil solución. ÁNGEL: Juana aclara esta situación con el TERE: no puede pagar el importe del centro 427 €/mes....cobra una PNC (402,8 x 14)..HABLA CON ANA sobre precedentes. ************************************* email de 12-3-21 de Teresa: POR LO QUE HE VISTO EN LA INTRANET ANDREA HACE AÑOS QUE NO VIVE EN ESTA VIVIENDA CUANDO COGIMOS LA TUTELA ELLA ESTABA EN CRR, LUEGO SE HAN DESENCADENADO UNA SERIA DE CIRCUNSTANCIAS QUE HA LLEVADO A QUE TERMINE EN UN PLAZA SOCIOANITARIA DESDE EL 2019 DE LA JUNTA DE EXTREMADURA EN LA RESIDENCIA EL ENCINAR DE LAS CRUCES. ADREA NECESITA ESTE TIPO DE PLAZA LLAMADA SOCIOSANITARIA POR LOS CUIDADOS QUE NECESITA, EL CÁLCULO DE ESTA PLAZA SE HACE DE MANERA DIFERENTE A LAS PLAZAS RESIDENCIALES PUES TIENEN EN CUENTA LAS PAGAS EXTRAS PARA EL CÁLCULO. ESTE APUNTE EN LA INTRANET HABLA DE LA COMPRA DE DICHA VIVIENDA A PESAR DE QUE ELLA YA NO VIVE EN ELLA ESTA FECHA En relación con la factura abonada el 15/12/2016, a la notaría de María del Pilar Carrascal Peñuela, de Villanueva de la Serena, con motivo de la escritura de compraventa del 50% de la vivienda de protección oficial, sita en C/. Infanta Cristina, nº 35, de Navalvillar de Pela, solicito a la notaría nos envíen copia de la escritura, con nº de protocolo 1.633. En Registro de la Propiedad de Puebla de Alcócer, aparece como titular al 100% de esa vivienda. En el catastro, aparece como titular al 100% de otra vivienda, en la misma calle pero en el número 40. Al parecer, según el Ayuntamiento, es la misma vivienda. Nos envían certificado. Teresa: Hablo con vivienda (924332456) para averiguar en concepto de que se paga la cantidad de 71.98€, me comentan que tiene una vivienda en propiedad de VVP, que este concepto corresponde al precio que está pagando en forma de préstamo a la junta de Extremadura por la compra de esta vivienda la cual compro en noviembre de 2016. SOSPECHO QUE LA VIVIENDA ESTA SIENDO UTLIZADA POR SUS HIJOS ****************************************************** email de 12-3-21 de Alberto: Hola Tere No importan (relativamente los conceptos)...podemos dejar de pagar o intentar contar con hijos o quién sea para pagar a medias la compra de la casa. ASÍ Y TODO: NO PUEDE PAGAR EL IMPORTE DEL CENTRO + DECESO + OAR VIVIENDA....NO DA...ASÍ QUE TENEMOS QUE ENCONTRAR UNA SOLUCIÓN QUE PODRÍA SER VENDER LA CASA (MIGUEL: NO SE SI ESTO ES POSIBLE). Si os parece, el jueves lo vemos los 4 y decidimos. TERE: SERÍA INTERESANTE CONTACTAR CON LOS HIJOS Y COMUNICARLES LAS NECESIDADES DE SU MADRE. Alberto. Pd: Miguel, te meto a ti en este asunto porque ya sabes de que va, a raiz del tema de Juan Carlos Rubio... ********************************************************* contestación miguel 17-3-21: Buenos días, desconozco este asunto, no sé si Angel solicitó en su día copia de las escrituras notariales por lo que indicáis en vuestros emails. A modo informativo, ayer hablé con una jurídico de la consejería de vivienda quién me comentó que en este tipo de situaciones se puede vender siempre que sea por precio superior al de mercado y hayan transcurrido más de 10 años desde que compró. Si lo creéis necesario ponedla en venta y cuando haya un comprador habría que notificarlo a la Junta (consejería de vivienda) para que renunciara a su derecho de tanteo. ***************************************************** contestacion Angel 17-3-21: Buenos días, Efectivamente, solicitamos a la Notaría de Villanueva de la Serena, donde se formalizó la compraventa del 50% restante, por parte de Andrea, que nos enviaran la escritura. Está en su expediente. Un saludo. ****************************************************** email de Alberto 18-3-21: TERE: hablará con mayores para informarles de que dada la situación económica de tutelada no es viable el pago de la plaza. • posibilidad de que se baje el precio de la plaza según necesidades de tutelada. • posibilidad de atribuirle otra plaza. Tenemos en cuenta que está pagando la compra de una vivienda que dejará de pagar en 11/2024...a 72,12 €/mes. Hoy, día 18/03/202 faltarían por pagar 3.173,28 € Además estamos pagando gastos relacionados con la vivienda (IBI, agua, residuos). MIGUEL: investigará el tema relacionado con la posible venta de la vivienda y los antecedentes de la compra. ********************************************************** 18-3-21 contestación Miguel: Hola en mi opinión, ella según la copia simple que está en el expediente compró el 100% de la vivienda. Hemos quedado que Tere y uno de los jurídicos suba a mayores a intentar buscar una solución. Caso de que no la haya yo hablaría con la jurídico de la Consejería de Vivienda (Ana) para preguntar por la posibilidad de ponerla en venta. En 2016 que se compró valía unos 24.000€ y con las bonificaciones correspondiente, se quedó la deuda en poco más de 7.000€. A fecha actual le quedan unos 3.000€ por pagar. En dicha escritura adquiere el 100% (no el 50%). En mi opinión la opción no pasa por vender, entre otras cuestiones porque necesita una solución inmediata ya que sólo cobra una PNC. Para poder vender en el mejor de los casos (que nos autorizara la consejería de vivienda por ser VPO a la venta y renunciaran al derecho de tanteo), habría que solicitar autorización judicial para vender ya que se trata de una tutela y suponiendo que el Colegio de Abogados aceptase asignar un abogado de oficio, entre que nos lo asignasen y la duración del procedimiento no creo que todo tardase menos de 1,5 año. Por tanto la solución a mi entender pasa por hablar con mayores y que acepten se abone al Centro menos importe o cambiarla de centro. ******************************************************* email de Alberto de hoy 24-3-21: Hola. Ayer, día 23/03/2021, Tere informó que ha conseguido que cambien a tutelada a una plaza en la que únicamente le van a cobrar el 75 % de su pensión. Eso haría que su situación ECO fuese sostenible de momento. El problema es que su situación ECO nunca sería positiva en el sentido de poder generar ahorro que nos permita asumir gastos extraordinarios (acompañamientos hospitalarios o similares). Por este motivo, en mi opinión, deberíamos seguir adelante con la VENTA de la vivienda y así estar preparados para el momento en que comiencen a llegar nuevas eventualidades...pero ya sin la prisa de solucionar el problema de forma inmediata. Cuando Tere nos diga que el tema del centro ya está solucionado nos reunimos y decidimos que hacer. ********************************************************* contestación Teresa 24-3-21: ME PAERECE BIEN LA VENTA PUESTO QUE ANDREA NO VA A VOLVER A SU CASA, EN CUENTO TENGA SOLUCIONADO EL TEMA DE LA PLAZA OS LO COMUNICO *********************************************** miguel, pregunto a Angel trámite a seguir: Pues creo que lo primero que deberíamos hablar es con vivienda (Junta) y exponerles el caso, para que renuncien a ese derecho de tanteo y autoricen la venta. En cuanto al comprador, podríamos indicarle que no disponemos de ninguno, toda vez que no podemos ponerla en venta, hasta entonces y hasta contar con la autorización judicial, por el importe de la tasación, o por el precio que determine vivienda (Junta). En cuanto al abogado de oficio por mi lo vamos pidiendo ya, por lo que tardan en concederlo. *********************************************** miguel, tras consultar con Consejería de Vivienda en Badajoz (Ana, Jurídico) me confirma que ellos no resolverán la autoriación de venta y renuncia de derecho de tanteo hasta que tengamos la resolución judicial autorizando a la venta. Por tanto hablo con Alberto de los pasos a seguir: 1.-Enviar escrituras a la Inmobiliaria para ver cuál es el precio de venta 2.-Solicitar abogado de oficio 3.-Una vez el abogado de oficio tramite la venta judicial solicitaremos autorización de venta y renuncia de derecho de tanteo a la junta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2021-03-24','Ana: Adelanto escaneado por email a Paz Boticario, TS Cruz Blanca (et-caceres@cruzblanca.org), el PAI firmado por el D.Gerente. *Oficio puesto para Registro de Salida. *Pido a Juan Pedro, Admvo. CTAEX, que lo remita por correo certificado cuando nos devuelvan el oficio registrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-03-23','EMAIL FUTUEX e Pedro Tomás, en el CEDEX no nos dieron mucha solucion la verdad, ahora paso a detallartelo un poco, lo bueno es que aparentemente parece que esta respondiendo bien al tema del apoyo en la gestion de dinero y no parece que este bebiendo o consumiendo nada, en apariencia claro está, tambien estamos pendiente de que se le de la cita en salud mental en don benito, pero te cuento como fue la visita al cedex: El día 18 de marzo nos cita la trabajadora social del CEDEX (Sila) para conocer presencialmente a Pedro Tomás e informarle de las posibilidades de tratamiento. Nos indica que el tratamiento ambulatorio no se puede iniciar sin tener un apoyo familiar o social que acompañe al tutelado en todo el proceso, ya que no pueden pautar medicación con riesgo de que no cese el consumo de alcohol. Como inicio a la intervención la trabajadora social le recomienda ingresar en la Unidad de desintoxicación de Plasencia, ingreso que tiene que ser voluntario por parte del tutelado. Pero en esta opción también es indispensable tras el alta, tener los apoyos familiares y sociales para seguir con el tratamiento ambulatorio ya que seguir el proceso de desintoxicación en otro recurso es una opción que el tutelado rechaza al no querer estar institucionalizado. Pedro Tomás indica que el único apoyo con los que puede contar son dos amigos de la localidad. Mª Ángeles y José que son pareja, según afirma Pedro no son consumidores y llevan una vida estable, aunque José también padece una enfermedad mental. Nuestra idea es conocer en la proxima visita para acompañarlo a sacar dinero a estos amigos.. En el CEDEX nos vuelven a citar el 16 de abril, con el fin de concretar el itinerario a seguir y saber si esta pareja de amigos son el apoyo adecuado para que Pedro Tomás pueda iniciar tratamiento ambulatorio con éxito. Se les reitira que no cuenta con apoyo social, pero que parece estar motivado para acudir. Desde Salud Mental de Mérida le realizaron seguimiento telefónico el pasado día 17, le dijeron que las próximas citas se programarían desde el equipo de Salud Mental de Don Benito. Desde el programa de apoyo social comunitario hemos llamado en multitud de ocasiones a la trabajadora social pero no conseguimos hablar con ella para conocer si el expediente de Pedro Tomás ha sido trasladado a esta área de salud y las citas van a ser presenciales con el psiquiatra que le deriven en Don Benito. En relación a su situación socio sanitaria, lo encontramos más estable y la vivienda la mantiene en unas condiciones óptimas. Con la retirada de 170 euros que tiene pautado quincenalmente se compran las necesidades básicas para cubrir 15 días, se paga el taxi que lo traslada del CEDEX a su domicilio, se le dejan 5 euros de gastos de bolsillo y se guardan 18,50 euros para pagar dos recibos pendientes del seguro de decesos. El dia 22 de marzo le han cortado la línea de teléfono que estaba contratada a nombre de su pareja. En la próxima visita, se gestionará el acceso a una línea prepago. Se ha puesto en contacto con nosotros a traves de una wifi publica, por el whatsapp, para indicarnoslo y justo despues de la semana santa le hemos dicho que iremos para sacar el dinero y gestionar todo esto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-03-24','Ana: Llamada de Rosana, Res. de Alcuescar (699 198 186): En relación a Rafael Casares Gía, necesita acudir a hacerse un chequeo completo, pedirán cita a Médico Internista. Tiene ASISA, pero no le cubre desplazamiento a la consulta a Cáceres. Habrá que abonar el taxi. También tiene que renovar el DNI, hay que pagar también la tasas y si fueran distintos días desplazamiento en taxi. *Pediré a Toni-Futuex, que Gloria le acompañe. ········ Por lo demás, me informa que Rafael se está adaptando muy bien. ························································································································································································································································ Llamo a María, TS SSASB - Alcuescar (927 38 40 02): no obtengo respuesta.······················································································································································································································································ Consulto a Alberto, jefe secc. ecca., si tiene hecha ficha de Rafael y si se está abonando ya el centro: Aún no se está abonando el centro. Se dará de baja una tarjeta bancaria. Se hará consulta al habilitado sobre ingreso mensual de 70 €/mes. Informos de próximos gastos por cita médica y renovación de DNI. *Yo llamaré de nuevo a la TS en relación al abono de la plaza residencial. *Habrá que reducir la asignación, a un máx. de 200€/mes, distribuido semanalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-03-24','Amalia : Lun 22/03/2021 16:51 Buenas tardes , espero que estéis bien . Te escribo en relación a Mercedes Pérez Pinna , mi compañera Juana ha hablado hoy con ella por temas económicos y me traslada su preocupación por sus delirios . Verbaliza que no duerme por las noches , que permanece sentada porque "entran en su casa para robar y violarla " . Hace poco te escribí por el mismo tema , el psiquiatra consideró que es residual de su enfermedad pero sería conveniente que lo supiese por si tiene que ajustar la medicación. Un saludo Respuesta del ESM: MARIA DEL MAR SANCHEZ GARCIA Mar 23/03/2021 11:55 Buenas tardes, Por aquí seguimos funcionando. Espero que también estéis bien. Con Mercedes P.P. siempre se ha trabajado la adherencia con los profesionales de S.M. Aunque la llamamos con cierta asiduidad y sabemos de ella. No conseguimos que acuda a las consultas con regularidad a consultas de enfermería para ponerse el inyectable, nos refiere que se lo pone a nivel privado (servicio contratado por ella), respecto a las consultas de psiquiatría, siempre le indicamos que debe venir de forma presencial, a veces acude y otras la tenemos que llamar. Estuvimos en su domicilio para trabajar la conciencia y adherencia de que debe de acudir a las consultas programadas en el equipo. La sintomatología, como me detallas y otras veces hemos hablado, es residual, cronificada. Un cambio de tratamiento farmacológico no va evitar los síntomas productivos. Es importante, teniendo en cuenta las dificultades para seguir tratamiento en el equipo de salud mental, así como para la realización de otras gestiones, el modificar su curatela por una tutela total, lo hemos propuesto en varias situaciones y creo que sería un medio de protección y apoyo para ella. Saludos, Mar Sánchez','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-03-24','miguel,remito el siguiente email a Angel: Hola, he hablado con Ana (jurídica) de la Consejería de Vivienda de Badajoz comentándole el caso de que se compró en noviembre de 2016, me comenta que tiene que pasar los 5 años para que nos autoricen a la venta (transcurrido los 5 años no habría problema para que renuncien a derecho de tanteo al ser causa justificada la solicitud, ya que no tiene dinero y está definitivamente en el Centro el encinar las cruces de Don Benito… Ahora bien, ellos no resuelven dichas autorizaciones (al menos así funcionan con las solicitudes que les hacen desde menores)hasta que tengamos la resolución judicial autorizando la venta y que como sabes tendremos que tener un precio de venta, a lo cual me comenta ella que hablemos con la Inmobiliaria para que nos indique el precio. Yo he pensado todo lo que supere el precio por el que compró y buscar inmobiliaria de la zona como es Colón (igual que haremos con el caso de Juan Carlos Rubio Galan). Según el certificado de la junta unido a la escritura de compraventa que te adjunto en el email el precio era de 24.035€, y si te fijas en el valor catastral (certificado de catastro) el valor es de casi los 24.000€. La finca es de Navalvillar de Pela, la nº 7419, del Rgtro de la Propiedad de Puebla de Alcocer… Voy a ir por tanto solicitando abogado de oficio al Colegio de Badajoz…y en cuanto al precio si te parece habría que hablar con inmobiliaria suroest o con una tal Vanesa Vaquez Cano (tlfno:636180404) que son los únicos que aparecen en mil anuncios…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-03-25','Buenas, Hemos insistido por todas las vías posibles para que acuda al ESM a ponerse inyectable, llamadas de teléfono, acompañamiento, acudimos al domicilio para valorar la importancia de venir con regularidad, todo sin éxito. La incapacitación es por la situación de vulnerabilidad que tiene Mercedes, carece de apoyo familiar, seguimiento en el equipo sin adherencia, dificultad para comprobar si se toma la medicación pautada. Entendemos que aunque no garantice el acceso a otros recursos, si lo vemos como una protección hacia otras situaciones. Lo veo con su Psiquiatra de referencia. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-03-25','Buenas , quizás sería más conveniente para garantizar que se pone el inyectable convencerla para que acuda a enfermería del ESM , a nivel privado no sabemos si estará cumpliendo el tratamiento. El tema de la incapacitación total ya lo vistéis con Pedro, el jefe de Sección , si lo consideráis oportuno podeís enviar informes actualizados al Juzgdo. Aunque en la práctica , como sabes , con una tutela tampoco se podría garantizar adherencia al tratamiento . Ni siquiera ingreso en centro en el que se exige la voluntariedad del usuario , independientemente o no de tener más limitada su incapacitación. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-03-24','-Amalia: le comunico a su abuelo lo que ha acordado desde la sección eco . Está en desacuerdo , quiere que se le siga dando el dinero extra hasta que agote sus ahorros. Le informo tb de la reclamacíon de la herencia por parte de las hnas. de Alejandro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-24','Ana: Llamo a Francisco, hermano de S.Miguel (630211717, 927-244205 // arroyomolinos@prontonmail.com): El nº móvil comunica. En el fijo me responde una Sra. que dice que Francisco no llegará hasta las 18h. ·············· *Remito nuevo correo-e: "Buenas tardes Francisco, De nuevo he intentado contactar con usted, y me ha sido imposible, tanto en el móvil como en el fijo, donde una Sra. me dice que no llegará hasta las 18h. Agradecería se ponga en contacto conmigo en horario de mañana en el número que aparece en la firma, pues necesitamos hacerle una consulta con respecto a al móvil de tu hermano Saturnino y suministros. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-03-24','Ana: Recibo llamada de Ana Benavente, TS ESM (74955): Conchi ha acudido a consulta. Le ha solicitado la Tarjeta de Transporte. *La solicitud se hizo en 2019. *Ahora falta en anexo I. Me lo remitirá para que lo ponga a la firma del D.Gerente. *También falta la fotografía y el Modelo 50, preguntará al centro si se ha abonado, pues Conchi decía que sí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-03-24','-Amalia : llamo a Carmen Diaz , del ESM de Valdepasillas , solicito que promuevan la subcomisión de casos que se quedó pendiente . Se va a concretar para despues de S. Santa y solicitará que estén todos los sectores implicados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-24','Ana: Conversación con Eva, Psicóloga de Acceso a RR. Salud Mental, Ud. PP.AA.: Parece que finalmente José Manuel podrá ingresar en el CRR-Ba. Enviarán el expte. y tendrá que pasar la entrevista con la Directora del recurso. En cuanto a la vacuna Covid, Pilar Martín, TS del ESM-CC, ha consultado a la médica de atención primaria si es factible que se vacune antes del ingreso. Está a la espera de respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-03-24','Ana: Tras conversación con Ana Isabel Amor Serrano, Psicopedagoga de PLACEAT (637 765 028 // ana@placeat.org) envía, tal y como acordamos el siguiente correo a ctutelar@ a la att. de la secc. ecca.: "Buenos días, el pasado sábado día 20 de marzo el tutelado Cristofer Montero Vázquez cogió un taxi para ir del centro Residencial Placeat de San Gil al hospital de Plasencia. Sin que ningún cuidador/a del centro lo supiera. Nos llaman de la Policía para que fuéramos a recogerle allí, que le había llevado un Taxi. Os envío la factura del taxi para que se abone a su cuenta de gastos personales de Placeat, desde donde se ha pagado. La tutora Ana Matamoros está informada de esta incidencia. Un saludo" ······························································································································································································· Nuevo correo de Ana Isabel Amor Serrano, Psicopedagoga de PLACEAT (ana@placeat.org): "Hola Ana, Te informo que me he puesto en contacto con Cruz Blanca de Cáceres, y vamos a realizar la primera visita a Alejandro el día 5 de abril a las 9.45h. Un abrazo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-03-25','Ana: Tras llamada de Mineva, nueva TS de la Resi. Cervantes-CC (927 005 575), envío correo a Toni-Futuex con copia a Alberto, Jefe Secc. Ecca.: "Buenos días Toni, ¿Qué tal el comienzo de la mañana? Acabo de hablar con Minerva, nueva T.S. de la C. Residencial Cervantes (Cáceres), me comunica que Mª Luisa Montaña Aliseda, necesita ropa interior, pero la tienda en la que a veces piden para los residentes de allí, tienen un estilo para personas mucho mayores de lo que es María Luisa y no le va a gustar. ¿Sería posible que la acompañe Gloria un día a comprarla? *Alberto, te pongo en copia para tu conocimiento y para que os organicéis con Toni en relación al abono de la ropa. Un saludo." ··························································································································································································· Por otra parte, Minerva me informa de que Mª Luisa lleva unos días muy tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-03-25','Ana: Llamada de Minerva, nueva TS Resi. Cervantes (927 00 55 75 / 22237), tal y como me comentó la semana pasada en otra conversación telefónica, Mª Eugenia sigue insistiendo en solicitar cambio de centro residencial. Su compañero sentimental, Pedro Campos Javier, ha solicitado cambio a la Res. San Francisco de Plas., en la que al parecer reside su hermano Antonio. *Mª Eugenia también quiere pedir el traslado a dicho centro. *Puesto que se trata de una Curatela Económica, puede realizar esta petición y firmarla ella misma. Posiblemente lo hagan hoy mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2021-03-25','TERESA Paula López Ruiz ingresó anoche, otra vez en el hospital y está muy grave,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-03-25','Ana: correo de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Buenos días Ana, te informo que vuestro tutelado Miguel Santos Cordero tiene cita con su psiquiatra el próximo día 9 de abril a las 12 horas. Un saludo." ·························································································································································································· Se lo comunico a Toni-Futuex, para que informen a Miguel y le acompañen a dicha cita. ···································································································································································································· Respuesta de Toni: "Ok, pues estuvimos la semana pasada alli, ahora te paso nota que ya la tengo, con el tema este de la cita acabamos de hablar con el hijo que tenia muchisimo interes en acompañar al padre al psiquiatra, pero resulta que no podria ir con el pq tiene clases, pero se lo va a comunicar y nosotros también, creemos que puede poner alguna pega, pero confiamos en que acceda y nosotras le encontrariamos alli, para ir no tendria problema poruqe el suele ir habitulmente a Caceres en bus, dede Guadalupe." ·········· Nuevo correo de Toni con nota (guardo en el expte): "Como te comentaba en el otro email, se le ha visto recientemente, adjunto nota y documentos de la visita. Nos expone y demanda lo siguiente: Ha recibido un REQUERIMIENTO DE PAGO – aviso de suspensión de suministro con Iberdrola por un importe de 177,83 del contrato de luz en esta vivienda. Miguel comunica que este contrato debería estar domiciliado y no entiende el requerimiento. (Se adjunta copia factura) Así mismo, demanda una mayor asignación mensual, no está conforme con los 400 euros, de hecho comunica que tiene deudas con algunos amigos, pues con la cantidad asignada no llega a cubrir sus necesidades. (esto no es nada nuevo, lo de siempre, vaya) (Adjuntamos facturas ya pagadas y que quiere enviar para que sepa dónde se gasta el dinero) de varios gastos que ha tenido, entendemos que para el arreglo de una moto. También se observa que el vehículo de su propiedad sigue aparcado en la calle, con el deterioro que eso significa. Ha estado en todo momento correcto, pero molesto por su tutela. Comenta que ha pedido a su hijo iniciar un proceso de remoción de tutela, y si no son aceptadas estas demandas que expone, quiere presentar demanda al juzgado por no cubrir sus necesidades diarias con la pensión que tiene al mes." ················ Como casi todo es cuestión económica, se lo reenvío a Alberto, jefe de secc. ecca. ·························································································································································································· Por otra parte, según se informa en la nota de Futuex: "Desde el mes de diciembre ya está viviendo en su domicilio en C/ Caballeros de la Virgen nº 7, ha dejado por tanto de convivir con su padre y hermano.", "Con la ayuda de su hijo Miguel, ha estado limpiando y organizando la vivienda que no presentaba condiciones óptimas de habitabilidad. Nos ha permitido entrar y observamos que ha mejorado sobre todo en las zonas de patio trasero de la vivienda, aunque todavía necesita seguir el proceso de limpieza general para mejorar las condiciones. Según su hijo Miguel se acomoda a la situación tal como está, tanto en relación a su aseo y aspecto personal, como la organización de la casa. Cuando él le puede ayudar, le obliga a llevar un ritmo y horario adecuado, pero estando solo a Miguel le cuesta más llevar su vida diaria mejor estructurada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2021-03-25','Teresa Luis Mi, ha dejado el trabajo que tenía en el Centro para centrarse en sus estudios','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-03-25','Ana: Llamo a María, TS SSASB - Alcuescar (927 38 40 02), me dicen que María hoy atiende en Aldea del Cano (927 38 30 02), me indican este otro número directo 927 38 31 25: María me informa que el cobro de la residencia lo realizan por adelantado, es decir, ahora le cobrarán el mensualidad de abril más la parte proporcional del mes de marzo que aún no le han cobrado. Lo realizan mediante cargo en cuenta. Como ya tienen el nº no hay que hacer nada desde la secc. ecca. En el cálculo *TIENEN EN CUENTA TAMBIÉN LAS PAGAS EXTRA. **Realizan 14 cobros al año. *Como además de la P. de Incapacidad Permanente percibe 72 € de IFAS para ayuda a medicamentos (según ha expresado el propio Rafael), este dinero también se tendrá en cuenta para el cobro. **Me extraña mucho lo de las extra siendo plaza conveniada con el SEPAD. Consultaré a mayores. ······························ Envío correo a Alberto, jefe secc. ecca. y a Icíar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2021-03-24','RECIBIMOS DEL JUZGADO FIRMEZA SENTENCIA DE REMOCION TUTOR A LA CTAEX Y NOMBRAMIENTO A SU PRIMA HERMANA COMO NUEVA TUTORA (JUANA RODRIGUEZ GARCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-25','Ana: Tras recibir llamada de Francisca, madre de Isabel (639 019 336) envío correo a Alberto e Icíar, secc. ecca.: "Hola de nuevo Alberto e Icíar, Os comento a ver qué valoráis y qué hacemos. He recibido llamada de Francisca, madre de Isabel Cano Blázquez. Por la cuenta en la que está también ella, pasaban el recibo de telefonía, se abonaba con la PFHC de Isabel. El contrato es de Jazztel y está a nombre la propia Isabel. Incluye 2 líneas móviles, 1 línea fija y Wifi. *Tiene permanencia de 2 años, no sabe decirme cuándo hicieron el contrato, pero dice que no hace mucho… no sé. La factura se la pasan entre el 25 y 28 de cada mes y ella dice que no puede pagarla. *Como se ha hecho la transferencia hoy de la PFHC, no se podrá abonar la factura. *Francisca refiere que percibe una P. Viudedad de 370 € y abona 320€ de alquilar, más agua y luz. Su pareja es quien se encarga del resto de gastos (comida, productos de higiene/limpieza y la diferencia de las facturas cuando no llega con su pensión. **Sé que ellos no nos competen, pero es que hice también la consulta al CSS. Y esta es la respuesta que me dio en primera instancia Estrella, TS: “…comenté con el Equipo el tema del móvil de Isabel y se comentó que si ella se beneficia de alguna manera de ese móvil, es decir, con él la llama su madre, pues sí sería bueno que lo conservara....” Isabel en el Socio no usa el teléfono, lo usa cuando va a casa, y es cierto que la madre lo usa para poder hablar con Isabel, lo cuál, como dicen en el CSS le beneficia. Lo que se me ocurre que se podría mirar es el cambio, cuando se pueda por la permanencia, de contrato a tarjeta y eliminar fijo y wifi. Y mientras tanto hacer transferencia periódica de la nueva cuenta de Isabel a la anterior del importe dela factura de teléfono. Ya me dices que opinas Alberto. Seguimos!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-03-25','Ana: Envío correo-e a Ana Benavente (anamaria.benavente@salud-juntaex.es) con el anexo I para la solicitud de la tarjeta de transporte firmado digitalmente por su representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-03-25','Ana: Correo de Alberto, secc. ecca, en cuanto al abono del taxi de la "fuga" de Crístofer del centro: "JUANA: En esta ocasión se PAGARÁ si la situación ECO lo permite. JUANA: Xfa, pon un correo al centro haciéndoles saber que en la próxima ocasión el pago se hará con la asignación del tutelado (les pasamos 65 €/mes para gastos personales)...ANA, yo no se como está este tutelado en cuanto a su "dolencia", así que esta advertencia la haremos SALVO que tengas algo que decir al respecto. Alberto." ··························································································································································································· Llamada de Cristofer, dice que ahora está mejor, pero que tiene "que confesar que esta mañana se ha escapado del taller, ha salido del centro" Hablo con él con respecto a este incidente así como a el del sábado. Dice que va a intentar adaptarse y no hacerlo más. Echa la culpa a su "mente enferma", le indico que aunque su mente pueda estar un poco enferma hay muchas cosas que él puede controlar "lo sé" responde. Dice que intentará no hacerlo más. *Además le recuerdo la buena noticia que le han dado hoy. Irá el día 5 a visitar a su hermano Alejandro. Se muestra contento por ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-03-25','Ana: Toni-Futuex: envía presupuesto para comprar una máquina de afeitar a Rafael, necesidad expuesta por el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-03-25','Ana: Toni Futuex, solicita a la secc. ecca., un extra de 20€ para comprar unas zapatillas a Eugenia, para las actividades físicas que realiza en el centro. *Ya ha visto probado dos pares de zapatillas con Gloria, Educadora (adjunta imagen con precios).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2021-03-25','Ana: recibo llamada de Julio, compañero CTAEX, le han llamado la directora actual del CSS-Plas., le ha pasado la llamada a Ángel, Asesor Jurídico. Margarita ha referido que otro residente del CSS le ha violado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2021-03-26','CORREO. Se remite por e-mail a la trabajadora social del centro, consentimiento informado para anestesia. Además, el original se ha enviado por correo ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-03-26','Ana: Envío correo-e a Estrella, TS del CSS (estrella.duranc@salud-juntaex.es): "Buenos días Estrella, Te remito adjuntas, escaneadas, debidamente firmadas y selladas por el Representante Legal, las Autorizaciones de Pase relativos a: - Remedios Chaves Masero - Andrés Silva Bonifacio Dime si necesitas que ten envíe también los originales por correo certificado. Un saludo y buen día." **Acudirá a su centro de referencia Plena Inclusión A-3, del 6 - 20 de abril.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-03-26','Ana: Envío correo-e a Estrella, TS del CSS (estrella.duranc@salud-juntaex.es): "Buenos días Estrella, Te remito adjuntas, escaneadas, debidamente firmadas y selladas por el Representante Legal, las Autorizaciones de Pase relativos a: - Remedios Chaves Masero - Andrés Silva Bonifacio Dime si necesitas que ten envíe también los originales por correo certificado. Un saludo y buen día." ···· **Acudirá a su centro de referencia Plena Inclusión Cabeza del Buey, del 5 - 12 de abril.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-26','miguel, pido cita a José Vicente (Gerente) para firma de poder apud acta para procedimiento de desahucio. Y remito petición al juzgado de Mérida para cita el 7-4-21 a las 9h. ******************************************************* envío email a la abogada Rocio: Buenos días, he cogido cita para el otorgamiento de poder apud acta el 7-4-21. Comentarte que el poder será específico para procedimiento de desahucio, si crees que hay que incorporar algo más dímelo. Por otra parte he pasado a la parte económica la provisión de fondos que han de hacerte. Les he dicho que pongan el nombre de provisión de fondos procedimiento de desahucio de Damian en concepto, si quieres que pongan otra cosa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-26','miguel, recibo email que remito a la parte económica para la provisión de fondos de la abogada para el procedimiento de desahucio: Buenas tardes Miguel, De acuerdo a lo que me indicas, quedo entonces a la espera de recibir el apoderamiento a procuradoras por vuestra parte para interponer la demanda. Entre tanto, voy a enviar burofax al arrendatario requiriéndole de pago y comunicando la voluntad de Damián de no renovarle el contrato de arrendamiento (lo cual le ha insistido mucho a Alicia), al objeto de impedir la enervación de la acción que reconoce el art. 22.4 de la LEC. También voy a solicitar del Registro de la Propiedad nota simple de la vivienda para acreditar el título de propiedad de Damián. Para hacer frente a los gastos e iniciar estas gestiones previas os facilito mi número de cuenta bancaria solicitando una provisión de fondos de 300 euros sobre el presupuesto que os envié en mi correo de fecha 9 de marzo: ES75 0049 6007 3028 9502 1011','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-03-26','Ana: Llamada de Jairo, no está de acuerdo con lo que se ha aprobado para comprar de ropa. *Tras consultar con Alberto, jefe secc. ecc., quien me informa que Juana, secc. ecca., ya ha hablado con el CSS y que "se ciñen a lo pactado", se lo comunico a Jairo, quien no se queda nada conforme y habla de "estimar recursos", de "necesidades", del dinero que hay en su cuenta... *Hablará con su TS de referencia del CSS. ······························································································································································································ Correo de Emilia Almodóvar, TS CSS-Plas: "Buenos días Ana. Comunicarte que tenemos serios problemas con Jairo Puertas, y en concreto con su situación económica. Necesitaría un documento escrito por la Comisión Tutelar donde se reflejen las pautas a seguir económicamente con el paciente. Es decir, la cantidad económica mensual para su gasto, cada cuanto tiempo podrá solicitar dinero para ropa y cuánto dinero podrá gastar (fijar una cantidad concreta y un tiempo). Este documento tendrá que ser visto por el paciente pues, genera un problema para el personal del centro y los demás pacientes, ya que su actitud provoca tensiones y enfrentamientos ante la falta de conocimiento por esta cuestión, pues Jairo considera que todo es una manipulación, visualiza que hay pactos ocultos en su contra, etc.... aumentando su ansiedad y frustración. Por otra parte, me gustaría poder realizar una videollamada con Jairo y con el tutor, si fuera posible." ·········· Conversación con Emilia al respecto. Intentaremos una videollamada con Jairo el martes día 6 de abril. ···· En cuanto a la cuestión económica que plantea, lo comunicaré/solicitaré a la secc. económica. ················ Reenvío a Alberto, con copia a Juana, secc. ecca., el correo de Emilia, TS, con alguna aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-26','miguel, escribo email informando a la prima de Damian, Alicia: Buenos días, ya está en marcha con la abogada los trámites de reclamación de cantidad a inquilinos de Damian. La abogada Rocio interpondrá el burofax previo y transcurrido el plazo legal de los 30 días podrá interponer la correspondiente demanda de desahucio. Desde la Comisión Tutelar otorgaremos el correspondiente poder apud acta para que pueda intervenir en nombre de Damian. Nos ha pedido provisión de fondos de 300€ que ya he pasado a la parte económica para que se lo abonen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-26','Ana: Llamada de Paula, TO del CRR-Plasencia. Informa que Damián quiere solicitar traslado al CRR-Mérida. Puesto que se trata de una Incapacitación Parcial, para la gestión patrimonial y para la administración de la medicación, él puede tomar dicha decisión y firmar por sí mismo la solicitud. ··········· *Por otra parte, Paula plantea el que él mismo comience a custodiar y gestionar su medicación diaria, como parte de su proceso terapéutico. **Le indico lo que pone en la sentencia, "...privación de la capacidad para administración de medicación...", como insiste, la remito a Miguel, Asesor Jurídico CTAEX, a quién paso su nº para que la llame al respecto. *Miguel dice que no pueden hacerlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2021-03-26','Ana: Recibimos Resolución Aprobatoria de PFHC: 399,20€/mes x 12 pagas. Fecha de efectos: 01/04/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2021-03-26','-ACLARACION SENTNCIA: Efectivamente, se trata de una curatela amplia. Pedro cuenta con retraso mental ligero, discapacidad del 54%, que le impide el autogobierno de su persona y bienes. Tiene afectada sus capacidades psíquicas, que si bien le permite una cierta autosuficiencia en el plano personal, le impide la valoración adecuada y toma de decisiones ante situaciones que revistan cierta complejidad. La incapacidad parcial, está pensada para que le protegan sus intereses, tanto personales como pecuniarios. Le impide realizar por si solo actos que puedan afectar a sus derechos fundamentales. Precisa de ASISTENCIA de la CTAEX, en cualquier declaración o comparecencia que tenga que realizar ante organismo públicos, desde la tramitación de cualquier tipo de expediente ante organismo públicos, como ante actuaciones ante órganos jurisdiccionales. En mi opinión, debemos firmar ese consentimiento ambos, tanto el curatelado como nosotros y, siempre bajo el criterio técnico médico que considere dicha intervención la más adecuada para el beneficio de la salud de Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-03-26','TERESA Buenos días Teresa. Te informo que, ADOLFO GARCIA CRUZ, tiene previsto el alta la semana posterior a la de Semana Santa. Se lo lleva su hermano a vivir con él y sería conveniente que lo pusierais en conocimiento de la delegada de FUTUEX que tenía adscrita, para continuar con el seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-03-26','Me confirman desde el Jzdo de Valencia de Alcantara que les ha llegado a ellos la Solicitud de Internamiento involuntario que remití a Alcantara y que al no tener jzdo allí hay que remitirlo a Cáceres. Envío de nuevo, esta vez a Cáceres, la solicitud de internamiento involuntario al Jzdo Decano de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-03-26','miguel, remito por carta a Fiscalia de Cáceres solicitud dº imagen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-03-26','miguel, remito por carta al Jzdo nº2 Cáceres solicitud de retirada del carnet de conducir','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-25','Ana: Correo de Toni-Futuex: "Buenas tardes Ana, te paso la nota de la primera visita de ayer con Emilia Guitierrez en Coria, al principio algo reacía pero creemos que puede ser que se consigan cosas, con ella de cara a la administracion del dinero. Al principio no, pero luego parece que la idea el catering le pareceria bien, vamos a pedir presupuesto, al hijo (Nacho) le dijomos que mientras se haga el seguimiento que no se preocupe que el puede estar a sus cosas, asi estariamos solo con la madre que seria el objetivo, también nos comentaron que el tiene que entrar en prisión 6 meses que ha recibido una carta, asique seria bueno que nos aceptaran para antes que pase esto, porque se quedaria la tutelada sola. Accedieron a que el lunes, vaya la compañera para allá a sacar el dinero, y acordaron con la ts sacar 100 euros a la quincena, si al final se pone catering la verdad que la semana que no toquen los 100 para compras y demás se podria poner una cantidad algo mas baja, porque tendrian todo cubierto, se puede mover la asignacion, pero bueno en todo caso a ver si se coge catering primero y funciona (a la ts que le parecia mala idea el catering ahora le parece lo mas adecuado..jiji, ya sabes como son estas cosas) En la nota de todos modos, esta todo detallado mas extensamente. Estos serian los datos de la compañera para la hacer la autorizacion de cara a la retirada de dinero, Gloria Sampedro Riscado, educadora del equipo de apoyo social comunitario de caceres, del Programa del Sepad, Mejora del acceso a los sistemas de proteccion publicos de las personas tuteladas y curateladas de Extremdura, con DNI 07050328T buena tarde!" ·············· Guardo nota en el expte. digital. Mañana se lo remitiré a Alberto, Jefe de secc. ecca. y hablaremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-03-26','Ana: Llamada de Carmen, TS de SSASB de Coria, Pregunta por el catering para Emilia. Le informo que aún nos han remitido la propuesta/presupuesto formal, pero sí nos han informado de las cantidades, si se puede asumir, en ppio. se aceptará el caterin con entrega diaria (240 €), pero hay que hablarlo con Alberto, jefe secc. ecca. para que haga cuentas. ···················· Como Emilia ya ha ido a preguntarle esta mañana, le dirá que todavía no está contratado el catering y que tiene que esperar al lunes a la visita de Gloria, Educadora de Futuex, con quién además podrá ir a hacer compra cuando retiren el dinero del banco. ························································································································································································ Envío correo a Alberto, jefe secc. ecca: "Buenas de nuevo Alberto, Te reenvío correo de Toni-Futuex, te subrayo los datos de Gloria, Educadora, para la retirada de efectivo del banco. Ha acordado con la Trabajadora Social, en inicio, si tú das el visto bueno, en hacer la retirada de efectivo de 100 € cada 15 días y contratar el Cáterin. *Plantean también el que Emilia, las semanas alternas, pueda sacar algo de efectivo (Poco porque sus necesidades estarían cubiertas a priori), pero esto tienes que verlo tú. *Del catering aún no tenemos la propuesta formal, pero en la nota adjunta, vienen detalladas las distintas posibilidades. Lo ideal a priori sería que le llevasen a casa la comida a diario, con un coste de 240 €, ya nos dices si es factible. *En cuanto al hijo, durante un tiempo, no va a ser un problema, dado que pronto tendrá que ingresar 6 meses en prisión, de modo que facilitará la intervención de la educadora con ella. Hablamos!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-03-26','miguel, a petición de Ana, solicito a Paula del CRR relación de los sitios por los que ha pasado y que según me coenta Paula ahora está en piso tutelado y que pronto se la dará el alta. A la espera que manden un informe detallado sobre Mayo, le solicito que nos remitan uno más breve haciendo mención por donde ha pasado y que conforme a los motivos de mejora ya está en pisco tutelado y que en un futuro cercano se le dará el alta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-26','miguel, a petición de Ana, hablo con Paula del CRR quién me comenta que quieren dentro del proceso terapeutico de Damián, darle autoronomia poco a poco para que se administre la medicación. La idea es pasarlo en poco tiempo a un piso tutelado donde tendría que ser él mismo el que se administrara la medicación. Pido a Paula me remita un informe con lo beneficioso que es para su proceso terapeutico esto a efectos de comuncarlo al juzgado a los efectos de que nos autorice ya que la sentencia hablaba de "la privación de la capacidad de administración de medicación"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-03-26','TF CRISTINA SUDON 677773233','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-03-26','Ana: Tras acordarlo con Amalia, TS CTAEX, remito un correo a Toni-Futuex para derivar al programa de apoyo comunitario a Brahim: "Buenas de nuevo Toni, Espero que el viernes vaya bien. Procedo a hacerte una nueva derivación, sería para seguimiento, pero sobre todo para sacarlo a pasear y apoyos en ese sentido, es un chico con gran dependencia que necesita muchos apoyos. Ha ingresado hace poco en el nuevo centro donde no pueden proveerle toda la atención que requiere y les gustaría. Los datos son: BRAHIM EL KINTY SNEIBA Centro: ASPACE JARAIZ DE LA VERA. AVDA. TORREMENGA, S/N. JARAIZ DE LA VERA (CÁCERES) Tlf. Del centro: 927460469 TS de referencia: Amor López – Tlf. 690 79 16 38 Ante cualquier cuestión, hablamos. Un saludo. Seguimos." ·························································································································································································· Llamo a Amor, TS ASPACE, como salta el buzón de voz, le dejo un mesaje informándole de la derivación y el motivo de la misma. ············· Me devuelve la llamada, lo consultará con la dirección del centro, pero a priori le parece bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-03-26','Ana: Con respecto al desglose de la relación de deuda acumulada en el Autismo Sur y que indicaban en el escrito remitido a la CTAEX por mail y a la D.Gerencia por Burofax, Juana, secc. ecca., llamó para aclarar los conceptos. Alberto me informa mediante email: "Hola Ana. Te aclaro conceptos. Juana ha hablado ya con el centro: -CONCEPTOS DEUDA CON FUNDACIÓN AUTISMO SUR: - TUTORIZACIÓN INCORPORACIÓN: LE PONEN UN ACOMPAÑANTE TODAS LAS HORAS DEL DÍA PARA SU ADAPTACIÓN AL CENTRO (YA NO SE REPETIRA MAS) - APORTACIÓN VEHÍCULO PASEO: APORTACIÓN A VEHÍCULOS TRANSPORTE QUE LES LLEVA A DISTINTAS ACTIVIDADES. (ESTO SI LO MANTENDRÍAN EN EL TIEMPO) - MEDICINAS: AL SER EXTRANJERO TIENE QUE PAGAR TOTALIDAD MEDICINAS. (ESTO SI LO MANTENDRÍAN EN EL TIEMPO) - SOCIO PROTECTOR: ACOMPAÑAMIENTOS A DETERMINADAS ACTIVIDADES O GESTIONES (ESTO SI LO MANTENDRÍAN EN EL TIEMPO) Varias cuestiones: • NO creo que sea viable mantener a esta persona en este centro con estos gastos añadidos al coste de la plaza (75%). Imposible de afrontar salvo que alguna administración esté dispuesta a hacerles frente. • El día que vengas concierta una cita con el Gerente o con el Asesor y subimos los 2 a aclarar todas estas cuestiones y como quieren afrontar esta situación. Alberto" ······························································································································································································ Llamo a Tomás, Coordinador de Caldidad - Dirección Gerencia SEPAD (924 008 493 / 68493) para solicitar cita con él y/o José Vicente - D.Gerente, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-29','Ana: Damián ha remitido al ctutelar@ por mail, Resolución Desestimatoria de Revisión de Situación de Dependencia (Mantienen "Sin Grado". *Adjunta también último informe del Servicio de Psiquiatría, de su última consulta en el ESM, con la Dra. Mª Jesús Gutiérrez Fco. (26/03/2021). Ambos documentos guardados en expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-03-29','Ana: Llamada de Francisca (639 019 336), madre de Isabel, dice que ha cambiado el contrato de teléfono a otra compañía, a Masmóvil, y lo ha puesto a su nombre. Mantiene 3 líneas móviles e Internet a menor precio. Le pregunto por la permanencia que me dijo que tenía el contrato a nombre de su hija y dice que se encarga la nueva compañía, que como mucho le cobrarán 100€. ···················· *Lo comunico a Alberto, jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-03-29','Ana: Celia, TS del HVP-Plas. (927 42 83 02 // 78206), me informa que Andrés ya no está ingresado en el hptal. Me pasa con la UHB y hablo con una enfermera, quien dice me remitirá el informe de alta por fax. ··························································································································································································· Envío correo-e a Emilia y Mariví, TS del CSS: "Buenos días Emilia y Mariví, Dado que Estrella no trabaja estos día, os pido por favor a vosotras, que en la salida de Andrés (Paula) Silva Bonifacio, a su centro de Cabeza del Buey, programada para el próximo lunes día 5, no se lleve el teléfono móvil, tal y como nos solicitan desde el propio centro. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-03-30','-Amalia : respuesta Futuex : Referente a lo comentado de Mª del Carmen Ruiz Larena, la información que nos facilita la tutelada al hablar con ella por teléfono es que el piso de alquiler por 150€ es de su tutor Pedro Gracia López. Supuestamente él se iba a marchar del piso y se lo alquilaba por dicha cuantía con gastos de comunidad. Ella diciendo:" sii Pedro mi tutor, es el que me ha dicho este piso, me lo dijo hace tiempo" (obviamente creemos que es una especie de delirio o distorsión de la realidad de ella, por que a ti no te suena que hubiera hablado con Pedro alguna vez de algo de pisos no?) Al preguntarle por la dirección nos dice que cree que se ubica en Calle Virgen Begoña en Mérida. (Hemos buscado la dirección y no encontramos ninguna calle llamada así). Se destaca el interés por ir a limpiar su casa del pueblo. Insiste mucho en dicha casa, pues quiere irse a vivir unos días allí de vacaciones. (Aunque ya sabemos que es poco menos que un solar) Esta es la información que hemos podido obtener de Mª del Carmen. Tras valorar la situación de la tutelada y dada la dificultad de encontrar pisos de alquiler en Mérida , como sabes por otros tutelados es casi mision imposible, que se ajusten económicamente a la situación de la tutelada como la dificultad añadida por los prejuicios al ser una persona incapacitada judicialmente, valoramos como una buena opción el ingreso en una residencia, aunque al ser involuntario tendra su efecto aversivo, pero creemos que puede adaptarse bien al recurso. Comentando con la compañera cree incluso que se podría intentar abordar y trabajar con la tutelada para ganar confianza y adherencia a dicha alternativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-03-30','-Amalia: Se envia autorizaciones de salida a la parte juridica para autorización judicial','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2021-03-30','-Amalia : tras varias llamadas al Ctro penitenciario de Segovia ( 921414900 ext 427792 Sara ) no he podido contactar para comentarle el último cambio en cuenta peculio . Ya se habló con él el mes pasado y se acordó que a partir de marzo se le pasarían a peculio 350 euros en lugar de los 220 euros, con esta subida ya no pediría más extras. Me llama todos los días siempre para lo mismo, y es que, aunque le quisiéramos dar extras no puede asumirlos, porque cada dos por tres le cargan embargos de hacienda y la cuenta está prácticamente a cero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-03-30','-Amalia : No se puede solicitar R. Mayores por PIA , tiene un Grado 1 . El PIA que le concedieron de SAD no se aceptó por no tener dinero para el copago. Se solicitará por decreto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-03-30','TERESA ME LLAMA LOLA LA TS DE PLENA INCLUSION Y ME PREGUNTA SI SABEMOS QUE ANDRES ESTA EN EL HOSPITAL POR INGESTA DE UN TORINILLO. LA COMISION NO TIENE CONOCIMIENTO DE ESTE HECHO SE LO COMUNICO A ANA COMPAÑERA QUE LLEVA ESTE CENTRO DESDE LA CTAEX PARA QUE SE PONGA EN CONTACTO CON EL HOSPITAL Y NOS FACILITEN INFORMACION NOS COMUNICAN DESDE LA UHB QUE NO ES PACIENTE DE ESA UNIDAD QUE ESTA EN OTORRINOLARINGOLOGIA ANA HABLA CON LA TS DEL HOSPITAL PARA PEDIR INFORME PERO LE DICEN QUE NO SE LO PUEDEN FACILITAR EN ULTIMA INSTANCIA LO PIDE A LA UDHAC YA QUE NADIE NO INFORMA DE LO OCURRIDO A ULTIMA HORA ME LLAMA LOLA QUE SE HA POSPUESTO EL TRASALADO DE ANDRES PARA EL PROXIMO 12 DE ABRIL, NOS PIDEN QUE SOLICITEMOS QUE VAYA SIN TELEFONO MOVIL Y QUE EL TRASALADO LO HAGA CON ROPA DE CALLE Y NO CON EL PIJAMA DEL HOSPITAL. INSTO A LOLA QUE HAGA UN COMUNICADO TANTO A LA CTAEX COMO A LA JEFA DE SECCION MANUELA RELATANDO TODO LO OCURRIDO EN ESTA SEMANA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-01-20','REUNION MANTENIDA CON LOS SIGUIENTES PROFESIONALES ALMUEDAN TS DE FEDERACION DE PI ALBERTO PQUIATRA DE SM DON BENITO MATILDE PI EXTREMADURA MAITE PSICOLO PI CABEZA DEL BUEY PILI "" "" ROCIO MONITORA PI CABEZA DEL BUEY LUDY SERV RESIDENCIA LOAL TS PI CABEZA DEL BUYER ANA TS CTAEX TERESA TS CTAEX ANDRES ES UN CASO DIFICIL PORQUE A SU PATOLOGIA SE LE SUMA SU HISTORIA DE VIDA SE TIENE PLANIFICADA EL ALTA EN UDAHC PARA EL 15 DE ABRIL Y POSIBLE PRIMERA VISITA AL CENTRO PARA EL 6 DE ABRIL MAITE Y PILI EXPONEN UNA PRESENTACION DEL PLAN DE APOYO CONDUCTAL POSITIVO QUE HANE ELABORADO AFIRMAN QEU LOS COMPAÑEROS NO QUIEREN QUE ANDRES VUELVA AL CENTRO YA TIENE PLAZA RAE PERO NO ES SUFICIENTE POR LA INTENSIDAD DE LA DEMANDA QUE EXIGE COMENTA MATILDE QUE LAS INTERVENCIONES DEL 112 NO SUMAN SINO QUE HACE QUE RETROCEDA EL PROCESO DE APRENDIZAJE SE HABLA SOBRE LA CONTENCION MECANICA, SI SE PUEDE APLICAR - EN PLENA INCLUSION NO HAY RECURSOS PARA APLICAR ESTAS TECNICAS -SE COMENTA QUE USA EL 112 COMO CANAL DE SALIDA DEL CENTRO ALMUDENA COMENTA QUE EL APEGO CON SU MADRE LE CONDICIONA MUCHO LO CUAL HACE QUE DESTRANSITE A FECHA DE HOY NO TIENE CLARO EL CAMBIO DE SEXO, NO TIENE CLARO SI QUIER SER MUJER, EL PSIQUIATRA NO VE NADA CLARO QUE QUIERA SER MUJER SE PLANTEA SI HAY POSIBILIDA DE QUE SE AUTORICE LA UTILIZACION DE SUJECION MECANICA','2');
