insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-30','miguel, a petición del curatelado remito de nuevo el email enviado por Iciar solicitando el abono del 6º semestre de alquiler a Loreto de vivienda del Ayto de Málaga (tlfno 951-926153): En relación a la persona curatelada por esta Comisión Tutelar de Adultos de la Junta de Extremadura, , D. Damián Salvador Granados Heredia, nif 53692319-S, adjunto remito la autorización firmada por su representante legal solicitando que le hagan el abono de los 1.350 €, correspondiente al 6º semestre de alquiler, así como los sucesivos, en la cuenta de Liberbank que se detalla, de la que es titular. Asimismo, adjunto contrato de arrendamiento y testimonio de aceptación del cargo de curador de la Comisión Tutelar de Adultos de Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-03-30','-AMALIA. Gestiono solicitud centro residencial de mayores ( 66 años ) por Decreto , por depend. tiene G. I . Envio documento con las causas que lo motivan a seccion juridica . Cumplimento solicitud en portafirma Pte. I. médico .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-03-30','TERESA: EMAIL FUTUEX Hoy 30 de Marzo se recibe una llamada de Emilia Morales Botello, que reside actualmente en Don Benito. Comenta que la pasada noche su novio Miguel Ángel había bebido y estaba algo agresivo, de hecho le pegó una patada en una nalga y en un brazo y ella llamó al 112 pidiendo una ambulancia y a la policía. Al cabo de un rato se presentó una ambulancia con la médico y una enfermera y un coche patrulla de la policía. Los sanitarios revisaron a Emilia y vieron algunos hematomas en el brazo y otras partes del cuerpo, le preguntaron si iba a presentar una denuncia por malos tratos y ella respondió que no, que no quería. A él se lo llevaron al calabozo y ella se quedó con Antoñeta, una amiga suya de la localidad ( 652 48 82 16 ) Sus maletas y todas las posesiones de Emilia se quedaron en la casa de Miguel Ángel y tiene pendiente ir a recogerlas acompañada de alguien en el día de hoy o mañana. Se ha llamado a dos hostales para pedir presupuesto: 1. Hostal El Paraíso ( 924 80 34 59 ) Se ha hablado con Juan Carlos que ha comentado que la habitación individual costaría 23€ si se reserva para una semana. El total de una semana serían 161€. El hostal dispone de restaurante que sirve desayuno, a 2,25€ por un café y una tostada. La comida, es menú del día a 9,50€ y la cena sería un bocadillo y un refresco por 6€. El total de un día sería 17,75€ y el de una semana sería 124,25€ Juan Carlos ha comentado que para hacer la reserva ellos necesitan que se haga el ingreso de la semana completa por adelantado. Ya que son una empresa muy pequeña y necesitan el efectivo para poder seguir funcionando. 2. Hostal Galicia ( 924 80 35 28 ) Se ha hablado con Rosa y ha comentado que la habitación individual costaría 22€ si se reserva para una semana. El total sería 154€. En el hostal no disponen de servicio de restaurante ni tienen contacto con alguno para poder reservar a Emilia las comidas y las cenas. Se le ha preguntado a Rosa si aceptan el pago por transferencia y no ha puesto ninguna objeción. El caso sería que para la comida Emilia tendría que contar con un dinero semanal o algo así para poder costeárselo. Se acaba de recibir una llamada de Antoñeta, la amiga con la que se está quedando Emilia, para comentar que la han llamado de la policía y más concretamente del Departamento de Violencia de Género. Le han comunicado que se va a proceder a la toma de testimonio de lo acontecido anoche en el domicilio de la pareja de Emilia y ella tendría que declarar delante del juez. Desde el departamento demandan que la tutelada vaya acompañada debido a la gravedad de los hechos. La compañera acaboa de llegar al juzgado y Emilia y la ex pareja han declarado ya. Le comentan el abogado de oficio de Emilia que un patrulla de la policía la va a acompañar a recoger sus cosas. Al parecer segun me dice la expareja sale en libertad y no hay orden de alejamiento. Seria urgente dado que vienen estos dias de fiesta, saber si puede acudir alguno de los hostales propuestos, ya que se queda en la calle.. y la otra opcion seria un centro de transeuntes.. pero tal vez pueda hacer frente a el pago de la pension algunos dias, no se.. OPTAMOS POR EL HOSTAL EL PARAISO SE LO COMUICO A FUTUEX, QUEDAMOS PENDIENTE QUE NOS INFORME DESDE SALUD MENTAL COMO VA LA GESTION DE ALGUN RECURSO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-03-31','Ana: Correo de Toni-Futuex: "Desideria Barbero Bueno ingresó el pasado viernes 26 de marzo en el área de salud mental del hospital Virgen del Puerto. Actualmente están ingresados tanto Ángel como Desideria y la idea desde Salud Mental es derivar a ambos a la Unidad de Media Estancia. El ingreso se produce tras no acudir a la consulta de salud mental en el centro de Especialidades Luis de Toro e intentar el contacto con la tutelada sin éxito. Es su psiquiatra quien activa el protocolo, la Dra. Mª Jesús Gutierrez. Teléfono de contacto Hospital Virgen del Puerto: 927428300 A ver si les manda a la UME porque en casa al final, difilmente pueden estar esta pareja..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-03-29','Acudimos al juicio con Nace, en relación con su oposición a llevar a Soledad, junto con los otros 2 tutelados que viven con ellos, a CO Down. Basan principalmente sus motivos en la negativa a ir, por parte de las tuteladas, a este centro y así lo expone la propia Soledad a preguntas del Juez y Fiscal. Insisten en que la CTAEX pretende obligarles a ir a este centro. Nuestra exposición se basa principalmente en lo contrario, intentamos hacerle ver al Juez y Fiscal que este centro, puede ser complementario a la formación que reciben en Nace y puede ser beneficioso, porque de esta manera pueden relacionarase con más personas con las que viven en Nace, pueden recibir una formación laboral alternativa y que en ningún caso va a suponer la marcha del centro Nace, sino tan solo unas horas. Queda pendiente de resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-03-31','TERESA:EMAIL FUTUEX PROCEDA A NO EFECTUAR EL PAGO DEL HOSTAL POR EL MOMENTO, anoche Emilia pernoctó con su pareja a la que el dia anterior habia denunciado por malos tratos, esta mañana dice que si que se quiere ir al hostal pero es dificil saber que va a pasar y no anda precisamente bien de dinero. Se supone que hasta hoy el hostal no la admitia porque si no se le paga por adelantado no accedia, por mas que lo intentamos, pero anoche hubiese tenido, de haberlo querido la casa de la amiga para dormir. Te detalló como fue todo: Ayer 30 de Marzo sobre las 19:45h se recibe una llamada de Antoñeta, la amiga de Emilia con la que se iba a quedar esa noche. Antoñeta cuenta que ha estado llamando a Emilia durante media hora y cuando ha conseguido que le coja el teléfono, no era Emilia la que ha contestado, sino Miguel Ángel, su expareja o pareja no sabemos. Cuando Antoñeta le pregunta a Miguel Ángel dónde está Emilia, él le contesta que está en su casa y se está dando una ducha. Tanto Emilia como Miguel Ángel le piden a Antoñeta que les lleve las pastillas y las pocas cosas que tiene en su piso de haber pasado la noche anterior allí. Antoñeta comenta que se pasará por el piso de Miguel Ángel para dejarle las pastillas a Emilia y para comprobar que ella se encuentra bien. Hoy 31 de Marzo se llama a Emilia Morales ( 622 83 76 84 ) para hablar con ella, Emilia comenta que se quiere ir al hostal esa misma mañana y que ya tiene hecha la maleta. Se le pregunta por qué ha pasado la noche con Miguel Ángel en su casa y ella contesta que ha sido un error y que no lo va a volver a repetir. Dice que él es muy pesado y que no la deja de agobiar y al final ella accedió a quedarse con él esa noche pero nada más. No se si seria bueno que antes de nada, hablaras con ella para cerciorarte, con la compañera ha terminado medio enfadada, cuando le ha recriminado esta conducta. Se habla con Carmen la enfermera de salud mental del centro de salud Don Benito Oeste y se le comenta todo lo acontecido con Emilia desde ayer, ella cuenta que hablará con Inma, la trabajadora social e intentarán buscar un alojamiento para Emilia por emergencia social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2021-03-31','Coral.Se escanea y guarda en su expediente, informe social que recibe Teresa Blanco del centro Penitenciario de Madrid. En el informe se detalla que permanece y ha permanecido en prisión a fecha de 08/10/2014 a 14/11/2014 y de 15/03/2018 a fecha de 5 de marzo de 2021 que se firma el informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-03-30','Ana: Correo de Mariví Clemente, TS del CSS-Plas. (victoria.clemente@salud-juntaex.es): "...información respecto a la tutelada por esa CTAEX, DESIDERIA BARBERO BUENO. En el día de hoy ingresa en la UME de este CSS, trasladada desde la UHB del HVP de Plasencia. Viene a ingresar junto a su marido. Quedan, pues, los dos ingresados en el UME de este Centro. Por ahora la Paciente no ha transmitido ninguna necesidad que deba transmitiros e imagino que de ser así podemos contactar con FUTUEX. Un saludo,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-03-31','Ana: Envío correo a Mª Dolores Venegas, TS del EVD-Coria, Secc. Dependencia II, Plas. (dolores.venegas@salud-juntaex.es): "Buenos días Dolores, Me pongo en contacto contigo en relación a una solicitud de revisión de valoración de Dependencia (al parecer la valoraron en el 2015 y dio sin grado) de una personas tutelada por la Comisión Tutelar de Adultos. Registré la solicitud, a fecha de 03/02/21, sin informes, por ir agilizando, pues aún no disponía de ninguno y no quería retrasarlo más. Se llama Julia Morón Hernández. Ayer finalmente recibí el informe médico y puesto que en los últimos meses no ha habido Trabajadora Social en el SSASB correspondiente y no he conseguido informe social, excepcionalmente, como en algún otro caso excepcional que me indicó Clara Nestares, Jefa de Sección de Calidad, cumplimenté yo misma el Anexo IV, Informe Social y puse todo para registro de ENTRADA, para la Secc. Dependencia. A ver si es posible priorizar el expte. Si quieres, cuando me devuelvan la documentación de registro, te lo remito todo escaneado. Ya me dices. Gracias y un saludo." ··························································································································································································· Respuesta de Dolores: "Hola Ana, Buenos días Te comento desde el equipo NO podemos priorizar ningún expediente, tan solo, si quieren solicitar plaza pública Centro de Dia del SEPAD de Moraleja, porque casi siempre disponemos de vacantes Le he remitido tu correo a nuestro Jefe de Sección, hasta ahí te puedo contar. Un saludo Nota: No nos dices el motivo de la priorización del expediente." ······························································································································································································· Mi respuesta: "Hola de nuevo, Dolores, Perdona, no lo he especificado porque se detalla en el informe. Las relaciones familiares (convive con los progenitores) son conflictivas, especialmente con el padre. Hace menos de un año que desde la CTAEX se aceptó el cargo de Tutela, según información de otros recursos e informes previos, siempre ha sido una familia mal estructurada y poco funcional. Otro de sus hijos también está tutelado por la CTAEX y un tercero tutelado por los padres (ambos hijos institucionalizados). En la infancia/adolescencia hubo indicios de malos tratos por parte del padre y desde que se ostenta el cargo desde la CTAEX ya han surgido incidentes en el hogar. El deseo de Julia Morón es el de residir en un recurso, en el que pueda realizar actividades/talleres y relacionarse con otra personas. En su pueblo casi no sale y se relaciona casi en exclusiva con su madre, sin más ocupación que las tareas domésticas y dar algunos paseos. Desde la CTAEX consideramos que es necesario sacarla del entorno y que acceda a recurso residencial, a poder ser de Discapacidad, pero entendemos que es en el CADEX donde deben valorar el perfil. Ante cualquier otra cuestión, no dudéis en contactar. Reitero que si queréis, os remito escaneado todo cuando me lo devuelvan de registro. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-03-31','TERESA Buenas de nuevo, te paso el contacto para localizar a Inma, Susana ha estado hablando con ella y le ha comentado que está elaborando el informe social para pedir un ingreso para Emilia por emergencia social. Y necesitarían que la comisión firmara la documentación. Asique están esperando que os pongais en contacto practicamente Salud Mental Don Benito Oeste ‎+34 924 80 20 06 SE RESERVA HABITACION EN EL HOSTAL EL PARAISO DE DON BENITO UNA SEMANA','2');
