insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-03-31','Ana: Recibo llamada de Alberto Arias Bueso, Técnico del EVD-Brozas. Ya han quedado horas libres de SAD y Julián Ramón puede acceder. Enviará un correo a Pilar Márquez, TS del SSASB de Valencia de Alcántara y me pondrá en copia. *Después tendré que ponerme en contacto con ella para ver qué día puede comenzar el servicio y los horarios. **En cuanto al copago por el SAD en este Ayto. es "Cero". ·························································································································································································· Llamo a Belen, Secc. Ecca. CTAEX, pues seguimos pendientes de la limpieza profunda del domicilio, hablará de nuevo con la empresa de limpieza. ························································································································································································· Correo de Alberto Arias, EVD para Pilar Márquez, me pone en copia: "Buenos días Pilar, Julián Ramón estaba en lista de espera de SAD del SAAD y han quedado horas libres. Tiene derecho a 45 horas al mes. Está tutelado por la Comisión Tutelar de Adultos por lo que ellos se pondrán en contacto contigo para ver la fecha de inicio del servicio y copago. Cuando sepáis fecha de inicio me lo comunicáis. Un saludo y muchas gracias como siempre por la colaboración."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-03-31','Ana: Llamada de Jairo, dice que el objetivo que tiene ahora es el de trabajar, y así en el futuro poder costearse los estudios. Que quiere nuestro apoyo para ello. Le indico que para ello hay que estar preparado y que también conlleva un proceso. Inscribirse como Demandante de empleo en el SEXPE,acudir a sesiones de orientación, elaborar el CV, realizar una búsqueda activa de empleo... Y previo a eso, ver su pérfil, de qué quiere trabajar y comprobar si neceita alguna formación específica/cualificación, pues hoy en día se requiere formación y titulacion para casi todas las ocupacioes laborales. También le recuerdo que primero debe cumplir la medida judicial actual. Dice que se va a comprometer y que quiere contar con nuestro apoyo. Le digo que también será necesario que el psiquiatra informe que está en condiciones de realizar este proceso. Y le recuerdo que había solicitado pasar a CRR, una vez finalice la medida. Comienza a divagar hablando de la vida que llevaba antes, los trabajos que ha desempeñado en el pasado, la importancia de los estudios en el desarrollo que según dice es su máxima prioridad, los años que lleva en el centro. Los recursos que quiere hacer en cuanto a la asingacion económica que se le da. Que quiere dejar de fumar y comprarse ropa con el dinero que se le da para tabaco..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-03-31','miguel, nos indica Lorena del Ayto de Málaga que nos pongamos en contacto con ella para el abono del 6º semestre, y me confirma Iciar que ya lo ha solucionado ya que la pedian la sentencia de incapacitación. ***************************************************** Me escribe Damian: Se me olvido contarle que itziar y ana matamoros les llego el papel del ultimo dia del siquiatra que tengo y pone el grado de incapacidad de un 52% y le envie tambien que queria un cambio que sea pronto al CRR de merida y tambien os envie la negativa por tercera vez el grado minimo el 1 seria interesante por mi situacion de que vea usted estos papeles y seria importante que lo hablara con su equipo del sepad que deseo cambiar de aire y estoy mas cerca de malaga estando en merida.muchas gracias don miguel por la conversacion tan educadamente que me ha tratado y le aprecio mucho estoy muy contento por toda su informacion y su ayuda a ver si me puede echar un cable para el cambio del recurso y en las valoraciones anteriores no se presento el 52% discapacidad y lo minimo que yo creo por la ley con un 33% te pueden conceder el grado 1 que le pasen sus compañeros el informe del siquiatra reciente que me vio el pasado 8 de marzo y la carta del siquiatra fui a recogerla el pasado 26 de marzo el otro dia y el sepad hay datos que no tiene por ejemplo el ultimo informe del siquiatra a ver si puede recopolar el papel con fecha de febrero que lo recibi el 17 de marzo y desestima por tercera vez el grado 1 y claro la carta del siquiatra es posterior a la ultima denegacion que ellos no tienen constancia del ultimo informe del siquiatra por eso a lo mejor me la denegaron de nuevo.ana matamoros recibi un correo que habian recibido escaneado que yo lo escanee que llega mas directo eso lo envie el viernes y ana me contesto el lunes que le llegaron los dos papeles el de la denegacion que es previo y la carta del siquiatra y como poder usted ayudarme porque apenas tengo familia y en el centro de aqui de plasencia dice la directora que ya rellene el formulario para mi deseo de cambio de CRR si puede por favor estara mandado a algun lado de la comision en el correo electronico ya exprese junto al informe de denegacion y carta del siquiatra puse en ese mismo correo mi deseo de pedir el traslado a merida valla que lacarta que yo rellene y puse la cruz en cambio de CRR merida a ver si encuentra ese formulario que ellos han mandado no tengo ninguna constancia si por el camino el formulario se ha perdido el papel y puede expresar que la siquiatra en consulta dia 8 de marzo dice que con mi situacion siquiatra no estoy para vivir solo y ladoctora la siquiatra que es el centro luis de toro la doctora maria jesus gutierrez puede preguntarle a la siquiatra pero no tengo el numero de telefono del centro de consultas de siquiatria donde siquiatricamente me atiende la doctora gutierrez no tengo a mano el telefono.con todos mis respetos necesitaria el cambio al CRR de merida pero don pedro creo que esta de baja y hay lista de espera y yo con toda mi buena voluntad y agradecerle todo lo que hace usted por mi porque mis padres aunque esten difuntos seguro y voy a pedir al corazon de jesus que os proteja a usted al equipo y a toda lsu familia voy a pedir al corazon de jesus que os proteja del covid y os traiga la vida con todo mi corazon mucha salud y los suyos.es usted un corazon con muy buenos valores humanos eso se lo digo de corazon y es un autentico profesional y un caballero que se viste por los pies su buena persona de buen corazon y agradecerle porque estoy muy solo y le pediria que moviera pronto por mi patologia el cambio de CRR de plasencia a merida a ver lo que puede usted hacer por mi y disculpe por mi enfermedad al hablar por telefono quiero abarcar tanto y me pongo tan nervioso porque hay cosas que se me olvida.usted perdone si le echo sentir mal por llamarlo tanto cuando pueda mañana ultimo dia laborable puede ponerse en contacto conmigo y que mi discapacidad es alta un 52% a ver si mañana puede ponerse en contacto conmigo y mi comportamiento cuando este en merida ya es mas facil promover y que el cambio a merida sea pronto y ya vemos para pedir una cuarta revision ya que la ultima carta de siquiatria es posterior en mi reclamacion que hize la reclamacion el verano pasado y me vine abajo que la solicitud con fecha en que me revisaron mi reclamacion el pasado 17 de febrero el 17 de marzo recibi la desestomacion de peticion degrado 1 este informe de desestimacion e informe siquiatra me mando un fax ana matamoros que habian recibido y me confirmaron que le llego tanto la desestimacion de grado e informe muy reciente del siquiatra todo esto me lo confirmo el lunes ayer creo me confirma ana matamoros por un correo que ella me manda que correo electronico tanto desestimacion como informe reciente del siquiatra con fecha 8 de marzo revisado en consulta presencial que yo pedi para que me lo dieran me loe tregaron el pasado viernes y ambos informes el mismo viernes lo mande a la comision y ayer lunes me mando que ambos informes que mande en una papeleria de plasencia para facilitaros el trabajo y sea seguro lo envie incluso en el informe se desea el cambio de CRR ya don pedro hace mucho tiempo que gracias a la comision y a el no me beia en la calle y ana matamoros me confirmo por un correo electronico que habian recibido ladocumentacion.otracosa por eso quiero que vea el informe que me pone lasiquiatra que no puedo tocar y ser autonomo con mi medicacion tras ocurrir esto y pido su ayuda y sentirme protegido me dijo paula que iban a preguntar al juez si yo en minimas cantidades pueda yo manejar en pequeños blister le van a pedir permiso al juez para yo firmar que yo maneje medicacion otra cosa que necesito sentirme protegido yo entre por primera vez con tutela y entonces todavia no me habia cogido la comision y no podia defenderme yo os llevo conociendo desde hace un año con lacomision y me vais conociendo y antes deconocerlo a usted el 24 de junio del 2019 entre en el centro por emergencia social por estar en la calle y aprovecharon y a los pocos dias de entrar me cambiaron la tutela y me pusieran curatela y no le tenia yo de apoyo ya que no estaba todavia a usted como abogado para defenderme y tengo miedo porque el juez puso como voluntad suya que yo no toque medicacion y ahora quieren pedirle al juez con un 52 por ciento de discapscidad medijo ayer paula que tras deseo del equipo tecnico expresado en revision con paula van a hacer un escrito por voluntad del equipo tecnico que yo firme el papel en estos dias protejame por favor y me defienda para que yo no firme ese papel yprotejame que yo a traves de pilar beiro asistencia social entre aqui por tutela y me lo cambiaron por curatela necesito su apoyo y me llame personalmente a mi porque cuando cuando no caiga bien el equipo y me quitan la tutela y ponen la curatela en junio2019 protejame don miguel con toda mi nobleza hacia usted y le aprecio que me ayude a no firmar ser yo un poco autonomo con la medicacion y sin su consentimiento ayudeme que no me encuentro preparado para yo manejar mi mi medicacion en pequeñas dosis ayudeme pars no firmar ese papel que mi deseo con un 52% de minisvalia me ayude a recuperar mi tutela que podia ser mi prima alicia y yo no estoy conforme por mi enfermedad estar tutelado y no curatelado como mecambio el centro y conseguir el grado1 y protejame por favor se lo pido que yo con mi enfermedad como dicto el juez es ser tutelado y no curatelado y no permita con mucha educacion defenderme de que yo no estoy preparado para que firme o pregunten al juez porque el equipo quiera hacer esto conmigo e intentar lo antes posible el traslado a merida y poder estar tutelado para amarrar bien mi bienestar que dios le bendiga y gracias po su ayuda y su buen corazon ahora mismo es usted mis manos y mis pies y necesito volver a la tutela si puede llameme mañana por favor antes de hablar con nadie si pregunta al centro mi comportamiento es muy bueno cuando me ayude a conseguir el cambio a merida estamos mejor para atar todo.muchas gracias muy señor nuestro mañana espero su llamada se lo pido con mucha ilusion de recibir su ayuda y sentirme protegido por usted.gracias buenas noches y un saludo de todo corazon.buenas noches señor miguel le deseo mis mayores deseos salud para usted y protejame.buenas noches muy señor nuestro.hasta mañana ************************************************** Tras consultar Ana de que lo tiene que ver ella me comenta que lo que pide Damian es ver si yo lo puedo recurrir, y me indica lo que se ha hecho. **************************************************** Contestación mía a Damian: Damian, el lunes le llamo con las dos cuestiones que plantea aunque ya le voy adelantando lo siguiente: 1) En cuanto a la cuestión de hablar con la abogada, es independiente de este abono, ya que este abono es el que le hace el ayuntamiento y la reclamación que tenemos en trámite es por la cantidad de dinero que no le está abonando desde el inicio del contrato de arrendamiento el inquilino. 2) En cuanto a la reclamación que creo entender que me requiere a su denegación comentarle que es a la parte social a quién corresponde informarle de estas cuestiones, y que me confirma mi compañera Ana que ya le ha informado. Por lo tanto, el que le den o no el grado de dependencia es independiente de la plaza que ocupa y que no va a perder dicha plaza que ocupa. En segundo lugar el que sea que tenga % de discapacidad no significa que automáticamente se le conceda un grado de dependencia, son cosas diferentes que ya le habrá explicado mi compañera Ana. Y por último el cambio de recurso que solicitó al CRR de Mérida, me confirma mi compañera que ya lo ha remitido Paula y que todavía no se ha resuelto, y por tanto debe tener paciencia porque ya le contestarán. Espero haber aclarado sus dudas, de todas formas si tiene alguna más puede llamarme el lunes y hablarlo.','2');
