insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-03-31','Ana: Tras llamada de Beatriz, Psicóloga-Coordinadora del CRR-Ba (924 231 645 // bgonzalez.sanmiguel@hospitalarias.es), en relación a la entrevista previa al ingreso de Josér Manuel en el CRR-Ba, me envía más tarde un correo de confirmación: "Buenas tardes Ana, Hemos fijado el viernes día 9 de abril la entrevista telefónica con José Manuel, acudirá al despacho de Pilar para poder realizarla. He intentado contactar con él, pero el teléfono que viene en el informe social (667384817) está ya a nombre de otra persona, podrías facilitarme el que tiene actualmente? Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-04-05','Ana: Envío a Mayores, Serv. Centrales, la siguiente consulta por email (mayores.sscc@salud-juntaex.es): "Buenos días, Espero que estéis bien. Quería haceros una consulta en relación a una personas cuyo cargo de Administrador de Bienes ostenta la CTAEX y que recientemente ha ingresado en plaza pública municipal por emergencia social, en la Res. De Mayores de Alcuéscar, se trata de Rafael Casares García. Según información facilitada por la Trabajadora Social del SSASB, le van a cobrar 14 veces al año (es decir, también le cobran el 75% de las pagas extras) y además, como está en IFAS y le ingresan 72 euros mensuales más para medicación/traslados a consultas médicas, también van a añadir esta cantidad para hacer el cómputo total de ingresos y cobrarle la parte proporcional. ¿Podríais, por favor, aclararme, si esto es así siendo plaza concedida a través del SEPAD? Me parece desproporcionado y además, según me traslada el Jefe de la Sección Económica de la Comisión, no podrá hacer frente al resto de gastos habituales, relativos a ropa, medicación, seguro de decesos y gastos de bolsillos, así como a cualquier otra cuestión que pueda necesitar de manera extraordinaria. Ya me informáis cuando podáis. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-05','miguel, hablo con Damian para indicarle lo mismo que le puse en el email del 31-3-21. Sus quejas se resumen en 3 cuestiones: 1.-No se considera capacitado para tomarse por sí sólo la medicación. 2.-No quiere que le manden a ningún sitio (piso, etc). Tiene solicitado el traslado al CRR de Mérida, y le indico que la denegación de Grado (tal como comentó Ana) no tiene que ver con que le den o no el traslado al CRR de Mérida, independientemente de su % de discapacidad.Dicha solicitud se está tramitando según me confirma Ana. 3.-La petición que ya hicimos al Ayuntamiento del abono del 6º semestre que sigue pendiente que le abonen. Comenta que no está bien en el centro, que le tienen envidia, que ayer perdió la pastilla (que se empeñan en que se tome él sólo la medicación y él por sentencia no puede hacerlo todo), que no quiere irse del CRR porque en un piso él se gastaría rápido el dinero en tragaperras o dejando dinero a deber. Que le da por correr y fumar compulsivamente y se siente mal. ********************************************** Le explico que estoy esperando informe de Paula para trasladar al jzdo con los pros y contras de dicha delegación que quiere hacer el centro para que Damian se tome las pastillas sólo. También hablo con Ana en relación con la conversación mantenida con Damian. ********************************************************* Quedo pendiente que a lo largo de la semana Damian me remita un escrito con sus peticiones y lo fundamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-05','miguel, recibo email de Damian: Soy damian en el año y nueve meses que llevo aqui lo he pasado mal porque habia monitores que atendian mas tiempo a otros usuarios y yo me quedo con la tristeza de no poder hablar los monitores muchas veces me han dejado el ultimo por ejemplo en la merienda me miraba un monitor de una forma enterada y mala mirada.digo al levantarme muchas veces esperar una sonrisa y algunos no me responden ***************************************************** Cuando estoy en el desayuno paso miedo y guardo silencio valla que diga algo que moleste yo soy como un niño muy efusivo y voycontinuamente a cada paso lo que tengo que hacer no mirando por mi sino no mostrarme como soy porque tengo buen corazon y en tiempos anteriores era muy pesado con los monitores y ya algunos me dan de lado porque yo no puedo vivir solo ya que por ejemplo el sabado u otros dias que salgo dos horas y dos horas por la tarde me incho de cafe en la calle y me endeudo con los bares que no tengo dinero me lo gasto todo en cafe y llevo 2 meses fumando y estoy siempre endeudado con losbares y con compañeros del centro yo pediria que me subieran la asignacion del mes 50 euros mas me dan 400 pero fumo y queria pedir 500 euros paraechar el mes un poco mas de dinero en la asignacion para no endeudarme ******************************************************* No pedi pizza el otro dia porque no teniadinero para cafe.el sabado me despendolo y para mi obsesion por meterme en loscasinos y la obsesion con estar delgadohace que cuando estoy solo mi vidaes un caos me voy a torremolinos eso cuando no estaba en la residencia y mantenia relaciones sexuales sin control y meacuesto cuando estoy solo hago cosas que no tengo voluntad de controlar y me tiro al rio por eso como la siquiatra me decia que yo no autogobernar mi vida como me decia la siquiatra que yo no puedo vivir solo porque me meto en el mundo de la noche y acabo pidiendo por lacalle por eso entre en el CRR por emergencia social me siento aqui en el centro sin cariño','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-04-05','-Amalia : llama Africa , del comedor social de Mérida , Jonathan está comiendo allí. Al parecer quiere retomar citas en CEDEX . Se le explica cómo proceder para solicitar estras económicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-03-30','Ana: Registro de ENTRADA a través del SIREX (en el registro del SES), solicitud de Equipo Móvil para tramitación del DNI a la Dirección Provincial de la Policía Nacional de CC. (Lo envían en papel porque no les aparece la dirección del organismo en el ORBE).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-03-26','Ana: Correo de Choni (Ascensión Montero Pérez) T.S. del SSASB de Miajadas y responsable temporal de los PP.TT. (Tfno: 927 347 000 Ext.: 3401 e-mail: servicios.sociales@miajadas.org): "Buenos días Ana, como quedamos por teléfono, te remito informes de Esteve Pascual, hasta ayer no me enviaron el informe de su médico de atención primaria, que no recoge las incidencias del pasado día 18 de marzo. Ya lo he enviado a Salud Mental y ahora lo enviaré también a la Unidad de Gestión de Programas Asistenciales. Saludos". ······························· Objeto del informe: "Informar sobre las alteraciones de conducta que presenta el paciente Esteve... alteraciones que constituyen una amenaza para sus cuidadores y el resto de residentes".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-03-22','Ana: Correo de Pilar Martín, TS del ESM-CC: "Ana, según me dice la compañera de Miajadas, un interno del CO y de los pisos Esteve Pascual Ramos, tutelado por vosotros ha presentado problemas y nos plantea derivación a CRR. Yo mañana intentaré hablar con su psiquiatra. Un abrazo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-04-05','Ana: Envío a Choni (Ascensión ), TS del SSASB Miajadas, escaneada mediante correo-e, copia de la solicitud de revisión al CADEX registrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-05','Ana: llamada de José Manuel, tiene nuevo nº de teléfono: 627 788 797. Se lo comunico a Beatriz, Coord. del CRR-Ba, mediante mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2021-04-05','Ana: correo de Lidia, TS del C. Salud Valencia de Alcántara (lidia.cabanillas@salud-juntaex.es): "Buenos días Ana, Me pongo en contacto contigo en relación a una tutelada vuestra, CONCEPCIÓN NEVADO PACHECO, es residente de un dispositivo de salud mental en Cáceres ( FEAFES) no ha acudido hoy al centro, refiere que no quiere ir más porque solo hay drogadictos, os lo pongo en conocimiento para que realicéis las gestiones pertinentes. Un saludo." ······················································································································································································· Mi respuesta: "Buenos días Lidia, Muchas gracias por informar. Consuelo estaba pasando una temporada con su familia, pero en teoría tendría que regresar a su plaza. Si bien es cierto, que su centro de referencia es el CRR (Centro de Residencial de Rehabilitación Psicosocial), no sé si sabrás por la prensa, que es el centro de Gestión Privada (FEAFES) que ha intervenido el SEPAD, por impagos a trabajadores y demás cuestiones… Es un centro de acceso voluntario. Trataré de contactar con ella, peros si vuelve por allí, por favor, dile que no tome la decisión definitiva sin contactar con la CTAEX, pues tienen otras opciones, como pedir traslado a otro centro. En principio no es muy recomendable que se quede en el domicilio familiar, sin los apoyos que puede necesitar. Un saludo y buena semana." ···················································································································································································· Envío correo a Toni-Futuex: "Buenos días Toni, ¿Podríais hacer, en cuanto os sea posible, seguimiento y apoyo a Consuelo Nevado Pacheco? Como sabéis reside en el CRR-Cáceres, pero en estos momentos está de visita en el domicilio familiar. La cuestión ahora es que Consuelo no quiere volver, pero sabemos que para ella, el apoyo de las y los profesionales del recurso es fundamental, así como la ayuda en el control de la administración de la medicación. Si bien es cierto, que el recurso en cuestión, no pasa por los mejores momentos…. Sabéis que es el que ha intervenido el SEPAD, y aún no se sabe en qué va a deparar todo, pero podríais trabajar con ella la importancia de los apoyos que allí recibe y que en cualquier caso, si no quiere regresar a este con carácter definitivo, hay otras opciones, como solicitar cambio de centro o incluso, si su proceso terapéutico lo permite, probar en Piso Supervisado. Pero para esto tiene que regresar a su plaza. Consultaré en la Ud. de Programas Asistenciales cómo está la situación y de qué tiempo dispondría Consuelo para regresar. Ya os iré diciendo. Seguimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2021-04-05','Ana: Se envía al CAMF, por correo certificado, la declaración jurada de ingresos anuales remitida previamente por el CAMF, debidamente firmada y sellada por el D.Gerente, y que ya adelanté por mail la semana pasada a Felisa Custodio, TS.','2');
