insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-04-05','Ana: Se envía al CAMF, por correo certificado, la declaración jurada de ingresos anuales remitida previamente por el CAMF, debidamente firmada y sellada por el D.Gerente, y que ya adelanté por mail la semana pasada a Felisa Custodio, TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GALAN'and apellido2='MERINO'),'2021-04-05','- Amalia , está muy grave en el hospital . El hijo de Barcelona cubrirá el sepelio . tf. 647192478 66182446','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-06','miguel, recibo los siguientes emails de Damian: Desde que llevo aqui no molesto a los monitores y he mejorado pero por mi enfermedad de control de los impulsos cuando me acercaba al despacho de latrabajadora socio cultural o a la spicologa y me ponen mala cara ahora no puedo atenderte incluso he idoal despacho tenia una duda y me trataban sin amabilidad incluso me cerraban la puerta en la cara eso es un motivo por lo que me quiero ir de este sitio no son amables y mecambiaron de tutora porque mi antiguatutora del centro me atendia muy desagradablemente ********************************************* Cuando me vinieron a revisarme el sepad estuvo una monitora y la señora monitora diciendo que a mi lo que me ocurria era que no entraba en conflicto y yo por dentro me trague las lagrimas y como le di aentender a la revisora de sepad que ni siquiera miro a fondo mi patologia me dieron cero grados lo reclame por segunda vez y tambien me lo denegaron *************************************************** Siempre voy pidiendo dinero a los compañeros u por ejemplo me dieron 20 euros para comprarproductos delimpieza y el lunes me dan 16 euros asignacion y el viernes 15 pues hoy he cobrado los 16 euros de hoy lunes y llevo muchas meses en casi dos años que vivo aqui el mismo dia que cobro si estoy en mi tiempo libre invito a compañeros aparte de los productos de higiene 20 y ya son las 14.21 y me queda solo 1 euro en el bolsillo *********************************************************** Hay muchos compañeros que me rechazan por mi forma de ser y en vez de acudir a los monitores del centro por miedo hablo con la comision porque confio mucho en el equipo de la comision y mi relacion con los monitores hola y adiosy no molesto ni dolor ni nada ************************************************** Soy damian hay que informarse que he tenido dos cuentas la del santander que no se que ingresos hubo por esa cuenta de lo que me pago el ayuntamiento como los ingresos que tuve en la nueva cuenta de liberbank.en cuanto la pension al cobrar la absoluta por ese lado estoy exento de hacer declaracion si nos interesa que lecomente a itziar para si por lospagos que he tenido tengo que declararlos de ambas cuentas la que se anulo de santander como la de liberbank.gracias **************************************************** Me acabande poner los moldesque esta pagado para ir poniendome los dientes esta todo pagado pero e seguido las 0directritces de itziar que no me haga nada sin consultarlocon alberto.digale que hay un importe pendiente de cuando me sacaron la muela por urgencias tengo muchas citas para hacerme de lo que ha pagado la comision pero hasta que no me de permiso alberto e itziar lo autorice hasta que no se haga un pago atrasado por urgencia de una muela que me daba infecion y lacomision estuvo intentar de localizarla a itziar y yo soy obediente tengo muchascitas todasestan estan pagadas pero tengo quepedir permiso y no me puedohacer nada porque hay un importe pendiente y obezdezco aitziar y es una pena porque ya loque me estan haciendo que ya esta pagado que es hacerme la corona ya estas proximos 4 citas esta pagado que son citas para la reconstruccion de un diente comentele a alberto e itziar hasta que no hagan el pago de la extraccion del diente aquella extraccion itziar y y alberto lo autorizen no puedo pedir cita y he borrado 4 citas que tenia porque falta pagar el importe de la extraccion comenteselo por favor que hable con enrique el gerente de la clinica para que hagan el pago por eso aunque este pagado lo que me estan haciendo no podemos avanzar y he anulado 4 citas por no aurorizar y pagar la extraccion digale por favor que hagan el pago para poder seguir arreglandome los dientes gracias que dios le bendiga ******************************************************** Estoy que aunque el PYR de mis avances es verdad pero muchas veces por miedo lo hago para portarme bien y los compañeros menos mi compañero de cuarto nuevo es una bellisima persona y es la unica persona que me trata con cariño que lleva en mi habitacion 1 par de semanas el resto de la gente compañeros y monitores me miran de una manera que me daña el alma y cuando pido la pastilla por lanoche el protectorde estomago hay monitores que no me complemento y me lo dan de una forma agradable yo calladito ************************************************** La semana pasada uncompañero me rechazo porque primero cada vezque un compañero me ha intimidado me puesto a pedir en voz alta necesito ayuda por el sentimiento de panico.por todos estos motivos quiero a ver si me pueden hacer una nueva revision al sepad y pido el traslado a merida porque el CRR de plasencia que llevo 1 año y nueve meses es un calvario los compañeros no se hacercan paracharlar solo pedir dinero y por el interes sin embargo mi compañero de piso que hay un respeto mutuo hay una relacion sana y con los demas sin agresividad trago y me quedo callado no se defenderme en la vida por mis patologias tengo tambien urtraltimo informe medico por eso pido una revision como dice la siquiatra me desmadro y doy dinero y me voy a los casinos y me pierdo en la vida ***************************************************** Mis avances es cara a los monitores para que digan que bueno soy pero se que en el fondo salir de aqui es tirarme a malos habitos y la medicacion administrarme mas soy capaz para relajarme mas la dosis del medio dia yal rato sin consulta medica me tomo yfuera de hora la pastillas eso no ha llegado a ocurrir porque no estoy autorizado gracias al juez que me limito a tocar limitacion pero si me dan patctra mi autonomia yo tener mi medicacion igual que loscafes dar dineror a terceros ida etc......mi vida es un caos pido que me intententen trasladarme a merida porque la novia de un compañero estaalli y se esta muy bien estoy falto de cariño. ****************************************************** Hace faltaque le mande mas mensajes para su documentacion se lo he mandado muy rapido para facilitarle el trabajo contesteme cuando pueda y si necesita algun dato mas que nos pueda ayudar el sepad y el juez comprenda que yo solo me desmadro tengo falta de dopamina de nacimiento en el cerebro.cuando pueda contesteme si estos datos le sirven.gracias muy señor nuestro ***************************************************** De todo lo que hemos hablado don miguel no cuente nada ni en el centro y por supuesto tampoco mi prima con secreto profesional si se enteran aqui tecnicos y nonitores me van a cogerrree mania.gracias por su ayuda y su buen corazon y no olvide que estoy ilusionado por algun dia conseguir el traslado a merida y que con el nuevo informe de siquiatria pedir una revision ******************************************************** Se me olvidaba comentarle otra minunsvalia me dan estos ultimos dias mucha ansiedad porque cuando tengo que hacer varias cosas a la vez n dia que tengo cocina poner lavadora y hacer hacer el pastillero que son los miercoteles y el sentirme solo tengteo mucha falta de cariño al no tener a mis padres a veces lloro en silencio.le felicito por su buena educacion y que usted es un señor que se viste por los pies un caballero y tiene muy buen corazon usted don miguel se lo agradezco de todo corazon su ayuda muchisimas gracias y que le pido al señor que hcisse estado jueves y viernes santo y he pedido mucha salud a usted y toda su familia y todo el equipo.muchas gracias que pase buen lunes de pascua ************************************************** Porejemplo me presto voluntario para poner la mesa y la monitora ni una sonrisa por mostrar mi intencion de ayudar que no me toca a mi y su mirada me hace venirme abajo me he sentido fartal **************************************************** Yo en todo momento hasta que no dieran el permiso no me levantaba y me dice la monitora con una actitud muy negativa levantate hombre¡ con muy malas formas casi chillandome que yo soy respetuoso y no habia escuchado que me tenia que levantar no tuvo corazon conmigo señor miguel y me lleve un malrato no estoy aqui para ser recibido una contestacion tranquila y pausada *************************************************** Estoy con una sonrisa mostrando mi buen corazon y voy con mucha educacion para darme las pastillas para dormir me puso una cara como diciendo me estoy sintiendo molesto y yo solo iba a pedir lo que me corresponde y me senti ofendido *************************************************** Estoy hablando con una monitora con mi buen corazon y dar cariño no me coge en el despacho para aclarar y me deja con la palabra en la boca por eso quiero irme a merida un muchacho que esta aqui en el piso tutelado su novia esta en el CRR y tengo miedo a contar toda la verdad digo para no entrar en conflicto y me da reparo pedir ayuda y pegar en la puerta de la sala porque estan siempre ocupadas *********************************************************** Lo mismo esta tarde los compañeros mas malitos son cariñoso y gastan bromas y a mi me gustaria sentirme en familia y he dicho de muy buena fe cuando ha entrado el monitor y he dicho con una sonrisa de mi hacia el buenas noches victor le dijo y me trato como un mueble ****************************************************** Otro monitor me dijo de lejos y con voz prepotente venga a recoger la lavadora sin tratarme con un trato amable y me lo dijo de lejos y me lleve un malrato porque no me senti respetado me trato como un perro como si fueras a darle confianza de sentirme tranquilo y decir las cosas de otra manera por poco de los nervios me da un ataque de ansiedad.me ven noble y eso les repatea le he dado todos los motivos porque la vida aqui por los desprecios y el ambiente de envidia me hace sentirme solo y abandonado por los monitores yo siempre mi actitud correcta y el director don javier que lo han subido de categoria es muy buena persona si le pregunto algo y no me puede atender me dice no puedo ahora y ya al señor lo dejo pasar que ya me han regañado y me han dicho que acose a una monitora porque tenia tantas ganas de contarle mis cosas que le impedirle salir a la calle y en otra situacion nevesitaba abrir la puerta del despacho porque no me querian atender porque buscaba cariño y comprension y me dijeron que las dos situaciones en dos tiempos de meses de diferencia en vez de intentar calmarme me dijo que forzar la puerta de los monitores es un acoso y yo solo buscaba desahogarme y no me dejaron ni tuvieron corazon en preguntarme por la muela cuando me la sacaron y el sabado me cai corriendo en un parque les enseñe los rasgunyos en a los monitores y no tuvieron corazon en preguntarme por mi salud por eso estoy mal y quiero irme a merida ***************************************************** Me he confundido al enviarle antes ese que pone cariño a secas disculpe la molestia señor don miguel soy muy respetuoso le di a enviar sin querer y perdone.buenas noches.gracias ********************************************************* Buenas noches don miguel cuando haya cualquier acontecimiento y se lo he escrito para guardar mi confidencialidad como mi abogado todos estos mensajes que le he enviado incluso de cuando haya plazas en merida ya me contesta siempre en confidialidad porque los monitores tienen malas pulgas y hay que mantener el secretoy recopile todos los mensajes incluso lo del dentista porque haber si itziar hace el pago atrasado porque tienen que seguir trabajando con mi arreglo de la boca y la proxima cita es 10 dias si se soluciona esta falta de pago por la extraccion la clinica dental ya podra con el permiso de alberto y reciba el visto bueno de alberto y se ponga en contacto conmigo o itziar me lo autorice sino estan todas las citas anuladas hoy me han tomado molde del diente para la corona pero la corona si esta pagada solamente y de mi parte disculpa a todo el equipo economico lo siento mucho por hacerme aquella extraccion sin consultarlo con alberto y perdoneme usted señor miguel lo hice sin pensar.en el momento que podamos a ver si me pueden hacer otra revision y me desee suerte que salga plaza en merida para poder estar en un sitio que yo me sienta agusto y con mi voluntad de hacer todos los talleres que me pongan alli y poner toda la carne en el asador en mi comportamiento positivo y activo.a mi me lleno este verano el corazon cuando os ayude ha hacer todas las domiciliaciones telefono.comunidad de mi piso cambiar por mi propio pie los cambios de IBI y cuando itziar en verano no conseguia contactar con el antiguo banco la central en torremolinos y muy agradecido por facililitaros pasar la nomina en liberbank gracias en aquel tiempo me pidio itziar el favor de como anular la cuenta del banco santander y yo cabile porque los de torremolinos no hacian caso pero mi mayor alegria es que consegui hablar con paco falcon trabajador del santander de plasencia enfrente del hotel alfonso VIII que me acerque tratando a este caballero con mucho respeto le pedi que llamara a itziar e itziar al facilitarle yo el numero de la comision le mando itziar toda la documentacion para pasar de la cuenta del santander a la cuenta que ustedes me abristeis en liberbank donde todo el dinero se saco de alli gracias a paco falcon y la ayuda tambien de cerrar la cuenta que a lo mejor los ingresos del ayuntamiento hay que declarar tambien en el 2020 lo que cobre en santander por lo que me ingreso el ayuntamiento que no se cuantos pagos del alquiler se hizieron parte primera del año en santander y otra ultima parte del año por liberbank hay que mirarlo.me siento muy feliz y contento con usted don miguel y todo el equipo porque tambien tuve que mandar documentacion a loreto para cambiar la domiciliacion del pago del ayuntamiento no la hagan por el santander y le di a loreto porque me da ilusion facilitaros el terreno y tras varias cartas al ministerio de la vivienda un escrito a vivienda para pasar cuenta a liberbank asi por mi cuenta en verano tuve que mandar a la institucion para que no me pasen el IBI que hay que recuperarlos para la declaracion de la renta los pagados en santander y cuando yo hize el esfuerzo para ayudaros a pasar el IBI a liberbank que tuve que mandar una pila de cartas certificadas y me costo yo solito hacer todo esto por que los pague por liberbank y mandar numero de cuenta a liberbank para que el IBI .dinero del ayuntamiento para cobrar el alquiler por parte del ayuntamiento el telefono mandar a la comunidad de propietarios el cambio de cuenta a liberbank que tuve que msndarle a garcia prieto el cambio de lacomunidad de mi piso que son 80 euros ya al dejaros todo esto arreglado que me da felicidad como le dijesoe antes ya todo va por el liberbank me siento muy contento y feliz cambiarlo todo lo hize con mucho agrado y sobre todo el ayudaros me hace ser feliz y por eso confio plenamente en todo el equipo y escribiendo este mensaje me hace feliz porque me gusta ayudar a personas buenas como todo el equipo de la parte juridica usted don miguel muy agradecido don pedro don alberto ana matamoros e itziar y personas que no conozco de la comision yo me siento y lo hize este verano cambiarlo todo al liberbank me costo sudores y lagrimas y a la vez contento y daros mi buen corazon y muchas diaculpas el estar solo os molesto mucho don miguel en mi nombre pido que me perdoneis por mi enfermedad de ser repetitivo y llamar mucho a ana matamoros e itziar y ustroed no lo hago sin ningun tipo de mala intencion eso lo juro por la educacion que me han dado mis padres pero no tengo control del impulso y nopuedo vivir solo.muchisimas gracias y de todo corazon don miguel le tengo mucho respeto a usted sin miguel y todo el equipo y cuando hablamos por telefonos son tantas palabras que tengo que decir y le interrumpo y le falto el respeto pero mi base de mi educacion le pido de todo corazon que me perdone que le aprecio a usted de todo corazon con mi buena base que me inculcaron mis padres muy señor nuestro gracias y buenas noche.que descanse y le deseo toda la salud para uated y su familia.gracias.*********************** Otra cosa que queria tratarconfidencial es que los 16 euros que me dieron ayer ya me los he gastado y tengo deudas con compañeros para ponerlo en su conocimiento pero con confidencialidad me dan 400 euros al mes y era para que el juez intentara cambiarme los pagos en vez de 16euros los lunes y 15 los viernes repartido en mas asignaciones porque paula no queria permitirme el cambio gracias************ Confidencialmente lo que le escriba usted tenia que hablar por calidad humana y sin ser cansino que me atendieran porque no sabia organizarme el tema de ir acomprar ropa se lo pregunto pocas veces y no me permiten ni una palabra mas que necesitaba apoyo sentimental al no tenerfamilia y pedi disculpas y eso es en cita privada que la tengo el dia 9 con la sicologa y en la cita me pongo nervioso y el dia 16 con paula y me sento mal aunque despuesua ordene la ropa e hice una lista por eso llamo tanto a ana matamoros y la comision porque no tengo el tiempo 5 minutos centrarnos y ayudarme y eso me hace sentir muy triste*****************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-04-06','Ana: Llamada de Cristofer (605 163 003): dice que quiere tener su propia custodia e irse a vivir solo, a una casa a Cáceres. Le explico que él requiere unos apoyos y que por eso está viviendo en un centro. Argumenta que no tiene apoyos en el centro, que necesita más... Intento hacerle ver que él mismo reconoce que necesita apoyos, que a día de hoy no reúne los requisitos para vivir de forma independiente. Se intenta explicar de forma que él entienda su situación y que todas y todos los profesionales tanto de la CTAEX como del centro lo que queremos esté bien. *Comienza a insitir que se va a ir a vivir solo y que quiere hablar con el Juez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-04-06','TERESA ENVIO NO ACEPTACION PIA A LA SECCION DE DEPENDENCIA YA QUE HA DADO UN GRADO UNO Y ACTUALMENTE ESTA EN RESIDENCIA DE MAYORES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-04-06','TERESA Te adjunto el recibí del viaje a Trujillo que hizo la cuidadora acompañando a Beatriz con motivo de la visita de su hija. La visita fue muy bien, estuvieron en el parque segun lo acordado con la abuela y la niña estuvo muy cariñosa y contenta con Beatriz. Después pasaron a ver a los padres un rato y todo correcto. Comentarte que la madre de Beatriz me llamó ayer y me dijo que ella quería que Bea se fuera a casa de forma permanente y que ella quería volver a recuperar la tutela. Le dije que ese tema estaba complicado y que lo hablase con la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-04-06','TERESA JESUS CADENA MURILLO PROPIETARIO DEL ALQUILER 648261571','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-06','Ana: Tras llamada de Francisca, madre de Isabel (639 019 336), envío correo a Alberto e Icíar, secc. ecca.: "Buenos días Alberto e Icíar, Espero que vuestra mañana vaya bien. A vueltas con este tema. De nuevo he recibido llamada de Francisca, madre de Isabel, puesto que no se abonó la última factura de telefonía, cuyo contrato estaba a nombre de Isabel, no se ha hecho efectivo el cambio de contrato y compañía que ella reailizó. Por lo tanto pide que se abone la factura pendiente para que pueda volver a gestionar el cambio. Yo creo que debería de abonarse para que se cierre ya el contrato a nombre de Isabel y no le genera más deuda. Si no estás de acuerdo, Alberto, en cualquier caso habría que hacer algo con dicho contrato y el gasto que genera a Isabel, quien sólo utiliza su móvil cuando sale de permiso del centro. Ya me dices. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-06','Ana: En relación a la consulta que me realiza Pilar Martín, TS del ESM por mail, escribo a Ángel y Miguel, Asesores Jurídicos CTAEX: "Buenos días compañeros, ¿cómo va la mañana? En relación a Clementa Amado Vivas, me dice Pilar Martín, TS del Equipo de Salud Mental de Cáceres, textualmente en un correo-e: “El pasado 29 al parecer, por no ser posible la comparecencia vuestra (Comisión Tutelar) se suspende el juicio y ahora tiene que hacer otro señalamiento, con el consiguiente retraso. Por favor intenta ver qué pasa.” ¿Podéis aclararme algo al respecto? Gracias." ········································································································································································································ Tras consultar a los compañeros, respondo a Pilar: "Buenas tardes Pilar, Esta es la respuesta que me dan ambos compañeros, ninguno de los tenía constancia de dicha comparecencia. Por favor, cuando puedas responde a todos, a ver si así aclaramos esta cuestión. Yo imagino que tendrá relación con la solicitud que realizó Miguel al Juzgado sobre el internamiento involuntario, no es así? Y al parecer lo único que saben es sobre el requerimiento al que contestó Miguel. Pongo a ambos en copia. Ya nos dices. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-04-06','Ana: llamada de Cristofer, (605 163 003), hoy dice que quiere tener su "custodia" y que se quiere ir a vivir sólo a Cáceres.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-06','Ana: Llamada de José Manuel, de nuevo insistiendo que necesita un nuevo teléfono y que quiere que le aumenten la asignación. *Cuando ingrese en el nuevo centro, posiblemente se pueda acordar otra asignación con el equipo técnico. Y lo del teléfono según evolucione en el CRR y si demustra "que lo merece" se podrá volver a valorar. De momento, dada su trayectoria, las incidencias y todos los móviles que ha vendido en los últimos meses ya saber cuál es la respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2021-04-06','Ana: Llamo al CRR-CC (663 402 616), hablo con Paloma, TO, Cosuelo ha regresado hoy al CRR, pero ha vuelto sin PCR hecha y han tenido que aislarla. *El no querer volver al centro o irse a vivir con su familia es una ides recurrente en ella, pero en el fondo sabe que no es viable. ························································································································································································· Escribo a Lidia, TS del Centro de Salud, y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-04-06','Ana: Recibo llamada de May, Jefa de secc. Recursos de Mayores (924 003 174), han concedido plaza a Agustín en el C. Mayores de San Vicente de Alcántara. Pregunta si sigue interesado, le inidico que como es uno de los que solicitó imagino que sí. Contactaré con el CRR. *La PCR debe realizarla entre 24-48 h antes del ingreso en el nuevo centro. ···························································································································································································· Llamo al CRR-CC (663 402 616 // 679 936 087), hablo con Paloma, T.O., se lo transmitirán hoy a Agustín, para que se vaya haciendo a la idea (le cuestan los cambios) y se vaya preparando y organizando la maleta. Mañana llamarán a su Médica de Atención Primaria. Para esta misma semana será precipitado el ingreso, por lo tanto, intentarán que la cita se la den para el lunes, el martes el resultado y el miércoles podría ingresar. **Me confirmarán una vez hayan contactado con la médica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-04-06','Ana: llamada de Jairo, hoy quiere solicitar la remoción de cargo, dice que Emilia, TS del CSS, le ha dicho que nos pida la documentación pertinente. Contesto que es la personas o entidad que interesada en solicitarla quién debe ir al Juzgado al comuniarlo e informarse y a solicitarla. *Después vuelve a hablar de la idea de trabajar y del hombre que le contrató cuando tenía 16 años... finalmente, tras divagar con varias cuestiones, dice que será mejor solicitarlo cuando haya finalizado su medida judicial...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2006-06-30','En el día de hoy se recibe llamada telefónica de un vecino de Jesús para informar que lleva unos días asomado a la ventada y dando voces a todo el que pasa. Los vecinos están asustados y piden que intervengamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GALAN'and apellido2='MERINO'),'2021-04-07','EXITUS El centro comunica que su hijo ha informado de su fallecimiento, acaecido en el hospital de Mérida el 07/04/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-04-07','TERESA Te comento que ha contactado conmigo Susana, la compañera que hace el seguimiento de Adolfo, parece ser que ha contactado con ella María Barrasa trabajadora del sociosanitario para comentar que Adolfo sale de alta este viernes día 9, ya que el hermano ha estado a visitarle en distintas ocasiones y les ha dicho que él se hace cargo de Adolfo, que se lo va a llevar a su casa. No tengo ni idea de cómo estando Adolfo tutelado y no siendo el hermano el tutor, le hacen caso y sobre todo sabiendo que el llevárselo a su casa es algo que previsiblemente no va a durar mucho, no solo por los conflictos, también por entender que Adolfo va a querer irse a su casa y el hermano no va a tener capacidad de retenerle. Con el trabajo que nos costó, que os costó, el que se ingresara....... creo que sería conveniente que hablaseis con el sociosanitario y veáis el tema antes de que le den el alta, creo que tiene que haber alternativas más acordes con las necesidades y realidad de Adolfo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2021-04-07','TERESA ARCHIVO AUTO INTERNAMIENTO INVOLUNTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2021-04-07','TERESA ARCHIVO CONTRATO SAD','2');
