insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2021-04-07','email de Alberto: Hola a todos. Tere acaba de hablar conmigo y me comenta la posibilidad de tramitar el traslado de la tutela de Jesús Bermejo Tello a la CCAA de Castilla León. Me informa de que está en un centro de Ávila desde hace unos cuantos años y que no va a volver. Xfa, echadle un vistazo y hablamos sobre esa posibilidad de traslado que propone Tere. Un saludo. ******************************************* Contestación Angel: Buenos días, En relación a estos expedientes, tuvimos un caso similar con Margarita Antich, precisamente intentando trasladar la tutela a Castilla y León, cosa que no conseguimos. En cuanto a este caso, habría que ver el motivo por el que este señor está en Ávila. ¿No hay recurso para él en Extremadura? ¿Qué arraigo tiene en Ávila? ¿Él es originario de Extremadura o de Castilla y León? ¿Tiene aquí a su familia o allí? El resto de Comunidades Autónomas son muy reacias a asumir tutelas que vienen de otras Comunidades Autónomas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-07','contestación de Pilar: Buenos días, no, creo es sobre la incapacitación el 402/2020 del Nº 2. Un abrazo. Intenta llamar al corto o al móvil 695-194-573 es por hablar de otros casos. Un abrazo. **************************************************** miguel, a petición de Ana llamo al Jzdo nº2 de Cáceres para intentar aclarar lo que dice Pilar, pero comunica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-07','miguel, voy con el gerente a hacer el poder apud acta a los juzgados de Mérida (para el 1º instancia de Plasencia para el Procedimiento de Desahucio) Se lo envío a Rocío (la abogada vía email) y por carta el original','2');
