insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-07','Ana: En relación a la "reunión" mantenida con Alberto, envío a Estrella, CSS-Plas, el siguiente correo-e (estrella.duranc@salud-juntaex.es): "Buenos días Estrella, En reunión mantenida con el Jefe de la Sección Económica de la CTAEX, se ha decidido que a Isabel Mª Cano Blázquez se le compre un terminal móvil económico y una tarjeta de prepago, pues no se va a mantener contrato de telefonía alguno. ¿Sería posible que os encargaseis de esta cuestión desde ahí? Como en el centro no lo puede usar, ¿se le podría custodiar y entregar cuando salga de visita? Por otra parte, cuando Isabel vaya a tener pase de salida a su domicilio familiar, sería conveniente que ya llevara dinero desde ahí, en lugar de tener que ir al banco una vez llegue a su pueblo. Y en el caso de que sea su madre quien acuda a visitarla, si desde el equipo terapéutico así se estima oportuno, y ésta no tuviera dinero para el traslado, agradecería que nos lo dijeseis con cierta antelación también, para valorar si se le pudiera dar algo de la cuenta de Isabel a tal fin. Ante cualquier cuestión no dudes en llamar. Ya me dices cuando puedas. Gracias y un saludo." ···································································································································· Llamada de Francisca, madre de Isabel, pregunta por las facturas de teléfono a nombre de su hija Isabel, le indico, tal y como se ha establecido con el Jefe de la Secc. Ecca., que no se van a abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-04-07','Ana: Correo de Estrella, TS del CSS-Plas (estrella.duranc@salud-juntaex.es): "Te escribo porque ayer una Auxiliar y yo acompañamos a Ángel Pérez Manzano, pareja de Desi al domicilio para que recoger ropa para ambos y tirara basura. El domicilio se encontraba en unas condiciones deplorables de limpieza y orden, ropa por todas las estancias de la casa, armarios con ropa desordenada de tal manera que no encontraba pantalones de Desi, por lo que está pidiendo que se le compren 2 o 3, así que si lo estimáis oportuno, se prevea en la autorización que está pendiente de enviar Gestión Económica a Rosa Admisión... En la cocina, había comida fuera de la nevera en malas condiciones, en ésta 4 litros de leche empezados y poca comida. En la terraza, mucha basura acumulada que no bajarían desde hacía muchos días...En definitiva, se vislumbraba escasa organización doméstica. Ángel me dice que tienen una chica que les va a hacer la limpieza...no lo parecía...A mi modo de ver, creo que más que alguien que le haga la limpieza, necesitarían una persona que les enseñe a esa organización doméstica. Saludos, Ana" ······························································································································································································ Mi respuesta: "Buenas de nuevo Estrella, Acabo de leer tu correo. Gracias por informar. Estas cuestiones ya se comenzaron a trabajar con el apoyo de las compañeras de FUTUEX (Terapeuta Ocupacional y Trabajadora Social) cuando el matrimonio residía en la anterior vivienda en régimen de alquiler. Antes de esto, desde la CTAEX se solicitó en 2018 SAD, pero ellos nunca quisieron, Ángel prefería pagar a alguien por su cuenta para las tareas domésticas. Y desde que se trasladaron al la vivienda nueva, no han dejado entrar a la compañeras de FUTUEX (no sé si habrá habido algún cambio en los últimos meses… con la situación de pandemia lo dudo) La intervención en este caso es complicada, dado que como sabéis, están casados, conviven juntos y padecen un delirio compartido, pero en la CTAEX sólo recae el cargo de tutor de Desideria Barbero Bueno. Con Ángel no hay por qué intervenir ni tomar decisiones, no obstante, desde el programa de apoyo comunitario de Futuex, indirectamente se interviene, pues dadas las circunstancias, no es posible hacerlo de otra manera… Lo trasladaré a la coordinadora del programa, para qué puedan abordar de nuevo la cuestión de las limpieza y el orden (apoyo y seguimiento en las tareas si es que les permiten entrar en el domicilio) y que les ayuden a valorar de nuevo la pertinencia de contar con una auxiliar de ayuda a domicilio. Seguimos en contacto. Un saludo." ··························································································································································································· Envío correo a Toni-Futuex: "Buenas tardes Toni, En relación a Desideria Barbero Bueno, te reenvío el correo que me ha enviado Estrella, TS del Sociosanitario y mi respuesta. Ya me decís si, cuando les den de alta, hay posibilidades de intervenir al respecto con la pareja en el domicilio. Gracias de nuevo. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-04-07','miguel, remito al Jzdo de 1º instancia nº1 de Mérida Comunicación a los efectos oportunos de los hechos y situación de Ana Mª Rosco Avalos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-04-07','miguel, remito al Colegio de Abogados de Badajoz, solicitud de abogado de oficio para solicitud judicial de autorización de venta de inmueble de Navalvillar de Pela. Mientras lo asignan poner en inmobiliaria para ir poniendo a la venta. Una vez lo nombre tendrá que interponer solicitud judicial de autorización de venta de inmueble de Navalvillar de Pela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-07','Ana: Envío correo a Toni, Futuex, con copia a Pilar Martín, ESM,: "Buenas tardes Toni, Tras reunión mantenida al respecto con Alberto, jefe de sección, te comunico, que dado que Clementa Amado Vivas está incapacitada legalmente, la CTAEX tienen asumido el cargo de Administrador de Bienes y que no acaba de procederse a ingreso en centro de Clementa, desde la CTAEX se iniciarán en breves los correspondiente trámites bancarios, que hasta el momento no se han realizado por las circunstancias en las que se encontraba la propia Clementa. Por tanto, os agradeceríamos que desde el Programa de Apoyo Comunitario realizaseis en cuanto podáis nueva visita a Clementa, para informarle de que se va a proceder a: - La cancelación de las tarjetas bancarias. - Al bloqueo de la cuenta Y para realizar un presupuesto aproximado de gastos, detallando: - Por un lado el gasto de bolsillo que se le va a autorizar a ella - La aportación económica para manutención que se realizará a la hija, dado que convive actualmente con ella. Sería bueno pedirle nº de cuenta para realizarle transferencia periódica. Enviarlo por favor al área económica cuando lo tengáis y ponerme en copia para que esté pendiente y ante cualquier cuestión, como siempre, no dudéis en contactar. Pongo en copia a Pilar Martín, TS del Equipo de Salud Mental de Cáceres, para que esté al corriente de los próximos movimientos. Un saludo y buena tarde."','2');
