insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2021-04-08','TERESA ARCHIVO DECLARACION JURANDA PAGO DE KMS A SU HERMANO POR TRASLADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-08','miguel, emails de Damian: Buenas tardes he encontrado entre mi ropa limpia una pastilla para administrarmela yo solo y estaba con su aluminio cerrada con el sueño por la mañana me ha pasado varias veces que el antes de ayer de dia se me tuvieron que abrir las pastillas la monitora porque son muy chiquininas y no las veia aparte lo de esta tarde habia una pastilla en la lavadora que otras veces no se ni donde la pongo y doy fe que acabo de sacar la lavadora para tenderla y estaba alli la pastillas motivo no se manejarme con la medicacion acabo de entregar la pastilla a la monitora ellos lo escriben y esto se lo comenta al juez muy importante ****************************************************** Otra noticia sobre medicacion una monitora ha encontrado hoy dia 7 a las 17.40 horas un pariet en mitad del salon de la residencia porque se me callo 3 veces el otro dia de madrugada gaste tres y hoy la monitora me ha dicho quetengo que ser mas responsable para decirselo al juez.el otro dia muy simpatica me la dio por 2 veces el otro dia por lamañana porque del sueño se me caian al suelo y esta pastillaqueha encontrado ahora mismo lleva por los suelos3 dias la monitora se la ha encontrado esto no lo controlo.mchas gracias señor miguel vamos recopilando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-08','Ana: Envío correo-e a Toni-Futuex: "Buenos días Toni, En relación al correo que te envié ayer a última hora, me pide desde el área económica que tratéis de averiguar también la información relativa a los siguientes gastos/facturas/deudas: o IBERDROLA: en CCC es imposible poder presupuestar ya que:  Hay recibos y devoluciones de los mismos (quién ha dado orden de devolución).  NO hay cargos de LUZ o GAS desde 05/2020: posibilidad de CORTE suministro. Que FUTUEX averigüe si hay deudas: importe y como pagarlas...tb si hay aviso corte.  COMUNIDAD PROPIETARIOS x vivienda y x garaje: da la impresión de que puede haber deudas...Que FUTUEX averigüe lo que sea y como mínimo un contacto de la Comunidad Propietarios: C/ GARCIA PLATA DE OSMA 21 4 D Y GAREAJE 17 o OAR: que FUTUEX pregunte a tutelada x posibles deudas o embargos de los que tenga conocimiento o EMBARGO: tiene un pequeño embargo de 6,17 €: Sabe tutelada por qué? o El reintegro mensual medio que viene realizando la tutelada (básicamente a través de tarjeta) es de 791€/mes. Esto es excesivo, habrá que trabajarlo. o IMPORTANTE: no veo un solo gasto relacionado con TELEFONÍA ¿? Recordar que la tarjeta se cancelará y la cuenta se limitará. Hay que explicárselo bien a ella, pues no sabemos si ella tiene claro aún en qué consiste la “Administración de Bienes” que ha dictado el Juez. Seguimos. Buen día." ······························································································································································································ Cumplimento comunicación de variación de datos banarios al INSS y pido a los compañeros que lo pongan para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-04-08','Ana: Llamada de Cristofer (605 163 003) cuenta que ha cogido un cuchillo del comedor con el que quería pincharse y quitarse la vida, pero que al llegar al baño un educador se lo ha quitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-04-08','Ana: Llamo a Pilar, TS de Valencia de Alcánara (627 34 11 19 / 927 580 326, ext.8) varias veces, pero no obtengo respuesta. *Volveré a intentarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-04-08','Buenos días , te comento las últimas incidencias con este usuario: -Hoy ha sido expulsado del Hostal por consumo de drogas . -Está asistiendo algunos días al comedor social de Mérida , la mayor parte de los días es su hermano Antonio el que le proporciona la comida -He hablado por tf con Antonio y con Jonathan , se compromete a pedir cita médica a su centro de salud y al CEDEX . -Le he facilitado teléfonos de todos los centros para pedir cita . -La semana que viene acudirá a ellas acompañado de su hermano . -He hablado por telefono con el Centro de emergencia social para drogas y los CEDEX de Badajoz y Mérida para exponerles el caso . Actualemente habría plaza , sólo dependen que él quiera ingresar . Todo ello se le ha comunicado a su hermano , él no tiene tf. móvil , pero ha estado presente y escuchando toda la conversación. -La cita para el lunes en la Comisión queda anulada , todas las acciones posibles ya se han gestionado . Su recuperación depende exclusivamente de él , se exige la voluntariedad absoluta para iniciar tratamiento de desintoxicación.','2');
