insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-04-08','-Jonathan acude a CTAEX , Alberto le ha autorizado un extra de 75€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-08','Ana: Llamo a Raquel, TS de Valverde de la Vera (667 068 078), está conduciendo, pues visita varios pueblos. Acordamos volver a llamar mañana entre 9:30 y 11:00 h. ······· Le envío un correo-e (ssasbrpa@gmail.com) con mi número directo. ····························································································································································································· En el Fundamento de Derecho Tercero de la Sentencia de Incapacitación, leemos textualmete: "...Visto el informe médico forense según el cual “sería conveniente su ingreso en centro adecuado donde queden atendidas sus necesidades existenciales”, de conformidad asimismo con lo solicitado por el Ministerio Fiscal en su escrito de demanda, no existe inconveniente para el citado ingreso de la misma en un centro adecuado donde queden cubiertas sus necesidades existenciales, por entender, que ello puede ser una medida beneficiosa para la demandada." Se indica de nuevo en el FALLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-08','Ana: Tras connversación con Minerva, TS del C.R. Cervantes (927 005 575): Envío a Alberto, jefe secc. ecca.: "Hola de nuevo Alberto, En relación a Guillermo Galán Gilgado, solicitan desde la Residencia que se le asignen, a poder ser, 15 €/semana para gastos de bolsillo, realizándose la retirada de efectivo una sola vez al mes. Desde el centro se lo irán administrando con carácter diario, para cafés y similar. Si es posible a mí me parece bien, si no pudiera ser dicha cantidad, pues un poquito menos. **Para la retirada de efectivo lo ideal sería que le acompase Gloria, Educadora de Futuex, confirmarlo con Toni, por favor. Mañana me confirmas si es viable para que yo pueda comunicarlo al centro. Seguimos." ···························································································································································································· Envío correo a Toni-Futuex: "Buenos días de nuevo Toni, En relación a los residentes del C. Residencia Cervantes, a cargo de la CTAEX, procedo a indicar (a modo de recordatorio) la necesidad de acompañamiento por parte de Gloria, Educadora, para varias gestiones: ... - Guillermo Galán Gilgado: Acompañamiento al banco para retirada e efectivo para gastos de bolsillo (cuando esté aprobada la asignación solicitada)... Pongo en copia a Alberto, jefe de sección, para que está al tanto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-04-08','Ana: Envío correo a Toni-Futuex con copia a Alberto, Jefe secc.ecca.: "Buenos días de nuevo Toni, En relación a los residentes del C. Residencia Cervantes, a cargo de la CTAEX, procedo a indicar (a modo de recordatorio) la necesidad de acompañamiento por parte de Gloria, Educadora, para varias gestiones: - Mª Luisa Montaña Aliseda: Acompañamiento a comprar ropa interior ...·','2');
