insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-04-08','TERESA HABLO CON MARIA BARRASA 24005 CON RELACION AL ALTA DE ADOLFO LA DOCTORA HA LLEGADO AL ACUERDO DE QUE SE VAY A VIVIR CON SU HERMANO Y SEA EL QUIEN LO CUIDE PUES HA INSISTIDO MUCHO EN QUE SE HACE CARGO DE SU HERMANO. VAMOS A PROBAR COMO FUNCINAN LOS DOS JUNTOS CON EL APOYO DE FUTUEX EL HERMANO HA ESTDO MUY PENDIENTE DE ADOLFO DURANTE SU ESTANCIA EN EL SOCIOSANITARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-04-08','Ana: correo de Estrella, TS del CSS: "Hola de nuevo. Siento comunicarte que Remedios Chaves Masero que como sabéis se fue una semana de pase a su centro de Aprosuba 3, me comunica su Psicóloga y Coordinadora de la Unidad que, esta mañana otro residente le regaló una chapa, cuando fue al baño, la ingirió, expulsándola ella misma, pero no obstante desde el centro Aprosuba 3 la llevaron a Urgencias del Hospital de Badajoz. Seguiré informando..." ··············· Se lo reenvío a Amalia, TS CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2021-04-08','Ana: correo de Juana, CTAEX, "Buenas Ana! Se le ha abierto una cuenta nueva a Antonia Bravo Patilla en Liberbank, además ha coincidido con el fallecimiento de su madre, con lo que hay que cambiar las pensiones a la nueva cuenta. Yo me encargaría de cambiar la orfandad, pero no sé si tienes pensado pedir la orfandad absoluta, en ese caso ya lo hacemos todo junto.... Ya me dices...." ································································································································································································ Mi respuesta: "Buenas tardes Juana, He estado mirando su última rendición anual y de momento, puesto que tiene dinero y en principio no necesita más, no le voy a pedir la P. Orfandad Absoluta. Si llegado el caso, desde la secc. Ecca. o desde la social, ser valorase necesario, se la solicitaría. Me encargo del cambio de la Prestación Familiar. Cuando puedas, porfa, facilítame el número de cuenta nuevo. Disfruta de la tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2020-07-21','Ana: Según informe del Centro de la Asociación Vera para la rendición anual de 2020, Antonia participa más en los talleres, aunque siempre como respuesta a la incitación verbal de los responsables de taller, no por inciativa propia. Sigue necesitando supervisión para el aseo personal, pues sigue siendo deficitario por su parte, aún no tiene adquiridos adecuados hábitos de higiene. Continúa con problemas de hipertensión arterial, no haciendo caso a las recomendaciones alimentarias. Asiste a las consultas del Programa PADDI y de Salud Mental en Plasencia. Presenta mayor estabilidad conductual pero inestabilidad en cuanto a la aceptación de normas. *Con los compañeros con los que hubo disputas previas muestra un comportamiento más disruptivo. Requiere supervisión conductual continua. La situación familiar no ha sufrido cambios hasta ahora.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2021-03-15','Ana: fallecimiento de su madre, Encarnación Patilla Castro a fecha de ayer, 14/03/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-08','Ana: Correo de Estrella Durán, TS CSS, en respuesta la mío de ayer: "Ana, lo del teléfono sí se lo podemos comprar nosotros aquí, sí nos gustaría que nos dijerais sobre qué precio. Y sobre la cuestión de que le demos aquí el dinero para gastos bolsillo cuando vaya a domicilio, también lo hacemos nosotros. Y se os informa cuando la madre quiera venir a visitarla si demanda dinero de la cuenta de Isabel para tal fin. Seguimos..." ················· Le indico que para el móvil se dispone de entre 80 - 100 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-04-08','-Amalia : incidencia ocurrida en Ap3 tras el perido de dos semanas de salida terapeutica desde UHDAC: Informar de la siguiente incidencia ocurrida con la usuaria del servicio RAE de Aprosuba3, Remedios Chaves Masero, tutelada por la Comisión Tutelar de Adultos de Extremadura. Remedios, que actualmente continúa ingresada en UHDAC, llegó el lunes a media mañana a nuestra residencia San Javier, tras coordinación con UHDAC, para pasar dos semanas a modo de “salida terapéutica” de UHDAC para ir viendo como se va adaptando de nuevo al centro con la finalidad de que en un futuro no muy lejano tenga el alta de UHDAC y pueda regresar a Aprosuba 3. Desde que llegó, ha manifestado estar muy contenta. Se le observa tranquila y con ganas de quedarse, manifestando que no va a volver a hacer ingesta para no volver a UHDAC. Ayer, y siguiendo todas las pautas de trabajo marcadas desde UHDAC, tuvo videollamada con su madre como así estaba establecido debido a su buen comportamiento. En la mañana de hoy se ha levantado diciendo que quiere ir con su madre, pero tras ese momento, ha estado tranquila. Tras desayunar, se ha ido, junto con el resto de compañeros y cuidadores, al baño para el aseo dental, a dicho que entraba en un wc para orinar (actualmente el cuarto de baño es mixto, por lo que cerró la puerta del wc) y cuando ha salido del wc ha empezado a vomitar y al preguntarle que le ocurría ha dicho que se había tragado una chapa de tamaño medio (tipo broche). Tras exploración se observó que la tiene atascada en la garganta dificultándole el habla. Inmediatamente se contactó con 112. Mientras venían, consiguió expulsarla con la ayuda de un cuidador, no obstante, manifestaba dolor en la garganta, por lo que la ambulancia se la ha llevado al hospital acompañada por un cuidador de residencia, donde, tras placa y exploración ha sido dada de alta a las 12:10 h. Según nos ha contado ella y su compañera de habitación, que también tenía otra chapa, se las había regalado otro usuario perfil RAE esta mañana. En su habitación, a su llegada, se han retirado todos los objetos tanto suyos como los de su compañera, los cuales puedan suponer un peligro para Remedios por poder tragárselos. La psicóloga está trabajando con ella todos los días lo recogido en el documento que se adjunta “Pautas de Actuación”. Documento el cual también se ha facilitado al resto de trabajadores para que tengan muy en cuenta principalmente el tema de los objetos a su alcance y los posibles cambios en su comportamiento que nos puedan poner sobreaviso. Destacar que desde su llegada, en ningún momento se le ha visto nerviosa, ni ha pedido ayuda tal y como se viene trabajando con ella. Seguiremos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-09','Hola Amalia, te paso el teléfono de JUAN CARLOS: 601409862','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-04-09','nformar nuevamente de una incidencia de nuestra usuaria del servicio de RAE Remedios Chaves Masero. Anoche, sobre las 22:15 de las noche dijo haberse tragado un cristal de sus gafas de ver. Se llamó al 112. Mientras acudían, un cuidador, que consiguió ver el cristal cuando Remedios abrió la boca, consiguió extraerlo puesto que estaba muy atrás pero aun no había conseguido tragárselo totalmente. No obstante, cuando llegó la ambulancia la llevaron al hospital para exploración. Un cuidador fue con ella (en su coche) para acompañarla en el ingreso. Tras la exploración se decidió que regresara al centro, llegando al mismo sobre las 00:30 h. A la 1:30 h de la madrugada se la encontraron en su habitación vomitando, había intentado tragarse la mascarilla quirúrgica que lleva (ya que debe tenerla por estar con distancia social) pero no fue capaz de ingerirla totalmente y eso le provocó el vómito. Se tomó la decisión de que una cuidadora pasara la noche junto a ella en una sala para evitar nueva ingesta. Estamos en contacto con UHDAC para acordar como proceder con Remedios, si continúa más tiempo en el centro o si regresa ya a UHDAC. Remedios ha manifestado que quiere que la ingresen en la UHB del Hospital porque allí la tratan muy bien…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-04-09','RESPUESTA UHDAC Tal y como hablamos ayer después de la primera incidencia, considero que lo más oportuno es su retorno a la UHDAC. Estamos en contacto. Saludos. MªPaz Casado Rabasot','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-04-09','TERESA SOLICITO CAMBIO DE PIA TRAS HABLAR CON LA SECCION DE DEPENDENCIA DE VILLANUEA 924174307 PARA QEU LA PASEN A PLAZA T4 Y PAGAR MENOS QUEDO PENDIENTE DE HABLAR CON ALFREDO O LUCIA PARA QEU PRIORICEN LA GESTION DESDE MERIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-09','Ana: Llamo a Raquel, TS de Valverde de la Vera (927 57 38 47 // 667 068 078), tras mantener conversación sobre la situación de Florencia y la necesidad de Internamiento Involuntario..... ···························································································································································································· Imprimo Informe Social actual, Sentencia de Incapacitación con indicación de ingreso en centro adecuado, Informe Médico Forense e informes remitidos en su día a Fiscalía al inicio del procedimiento (Informe Social SSASB e Informes Médicos). Y **se los llevo a Soraya Masa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-04-09','Ana: Recibimos informe del ESM. Indican que Ana María no acude a consultas desde 2017 y aportal el informe de dicha última consulta. *Se guarda en el expte. digital. ············· Se lo entrego a Miguel, Asesor Jurídico, para que pueda remitirlo al Jdo.******************************* miguel, hago oficio de salida para incorporación como Doc nº4 de la Solicitud de Internamiento Involuntario de la tutelada al jzdo nº1 Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-09','miguel, recibo email de la abogada indicando que esta mal dirigido el apud acta porque tiene que ser a los juzgados de Málaga. Le contesto que conforme su email de 25-3-2021 me indicó que había que dirigirlo a primera instancia del domicilio del curatelado (por tanto Plasencia...) Le indico que lo interpongan ante Plasencia y si no es competente, que éste lo dirija a Málaga... ***************************************** contestación de la abogada: La competencia territorial para el conocimiento de procedimientos de desahucio es de los juzgados donde radica la finca ( art. 52.1.7º le la LEC), o sea Málaga. Por esa razón voy a llevar yo el tema, pues si pudiera interponerse en Plasencia se habría contratado los servicios de un abogado de allí. En mi correo os exponía claramente que lo que habría que solicitar allí por vosotros es la autorización judicial para la interposición de la demanda, que según vuestro criterio no es necesaria. La propuesta de interponer la demanda allí y que de oficio la remitan a Málaga no existe jurídicamente, es completamente inviable. Los juzgados de allí se van a declarar incompetentes y van a archivar la demanda directamente. Como previamente voy a enviar un burofax a los inquilinos para evitar la enervación de la acción, hay tiempo para que se subsane el poder. *************************************** mi contestación: Precisamente intenté contactar esa misma mañana porque dicho email da lugar al error ya que el artículo 62 de Ley 15/15 dentro del capítulo VIII habla de que debe ser en el lugar de residencia del representado… En cualquier caso por lo que indicas hay que hacerlo de nuevo. Me puedes confirmar si hay que modificar algún dato más de dicho apud acta para evitar nuevas sorpresas? ******************************** Pido de nuevo cita a la secretaria del Gerente para el 21-4-21 a 9h','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-04-09','miguel, reunión con parte económica. Al estar mal el burofax, ellos (Belén)pedirá presupuesto honorarios a la asesoría de la tutelada para abogado para desahucio. Una vez lo tenga me pondré en contacto con él para remitirle la documentación que requiera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-04-09','miguel, Ana me da el informe social que remitiré al Jzdo nº1 Mérida...completando la comunicación enviada hace unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-04-09','mi contestación: he hechado un vistazo tanto a la designación judicial que nos hacen desde el juzgado como defensores judiciales cuando en realidad nos están nombrando administradores de bienes, como a la carpeta de inventario y la comparativa que comentas en tu email en la discrepancia entre registro de la propiedad y catastro. En mi opinión, esta mujer ha debido ser hija o esposa de constructor ya que en el término de Moraleja es usufructuaria (no propietaria) de multiples terrenos por título de cesión, reparcelación, segregación…(todas esas escrituras se hicieron en la misma notaria y ante el mismo notario de Coria que la herencia…sería bueno acceder a su contenido) Por otra parte en cuanto a la discrepancia que comentas entiendo que la dirección te la pueden aclarar en la notaria al igual que los % de propiedad de la notaria. Entiendo que quién está desfasado es el registro de la propiedad, creo que sí es coincidente el bien de catastro con el del registro de la propiedad. De hecho el administrador te confirma que en el 2018 sí pagó parte de la deuda. Ahora bien, si ves los documentos del ayuntamiento (servicios sociales y polícia) podrás ver que vive sólo con uno de los hijos (drogadicto), con el otro no tiene trato y la sobrina lleva los mismos apellidos que ellos. Te lo comento porque para salir de dudas de titularidad y demás sería recomendable cuando hables con la notaria de Coria (no conozco a nadie allí) comentarles que tienes que ver el título de herencia mencionado en la nota simple del año 28/7/2008, ante el notario de Coria D. Eduardo Hijas Cid protocolo nº238, por que a partir de dicha herencia y ante el mismo notario se han hecho las demás escrituras cesión, segregación, reparcelación…que yo vea por notas simples hasta el 2012… Me da que esa herencia le viene a ella no por marido sino por padre…porque si tiene dos hijos (la sobrina no sabemos si es o no de alguno de los hijos…)los % no cuadrarían… Seguimos indagando, habla con la notaria coméntales el caso y a ver si te mandan esa escritura de herencia. email de Angel: No sé si viste este correo que nos envió Itciar, referente a unas deudas que tiene esta señora con la Comunidad de Propietarios de varias fincas. El caso es que iba a contestarle a la Comunidad de Propietarios, en función de la información que he visto en el Registro de la Propiedad y en el Catastro. Pero antes quería llamar a la Notaría de Coria, donde se formalizaron las escrituras de estas fincas, para preguntar a quién pudiera corresponder el resto de porcentajes. ¿Conoces a algún oficial de la Notaría de Coria? Échale un vistazo no obstante a la información que te digo y me comentas. Finca registral 9792/BIS: Dª. Emilia Gutiérrez Serradilla dispone del 50% (2/4) del pleno dominio por título de herencia y del 50% (2/4) del usufructo por título de herencia. Finca registral 7869: Dª. Emilia Gutiérrez Serradilla dispone del 50% (2/4) del pleno dominio por título de herencia y del 50% (2/4) del usufructo por título de herencia. Finca registral 5917: Dª. Emilia Gutiérrez Serradilla no dispone a su nombre de esta finca en Registro de la Propiedad. En catastro si consta inscrita a su nombre una vivienda, con el 100 de propiedad, pero situada en Calle Almanzor 2, Es: 0, Pl:02, Pt: 04. Es un residencial de 78 metros cuadrados (la C.P. indica nº 27).¿Podría tratarse de la misma vivienda? email de la Cdad propietarios del día 5-4-21: A/A Sección Jurídica Buenos días: Les facilito información relacionada con la persona a quien ustedes están prestando la ayuda para administración de sus bienes. Si requieren algún otro detalle o comentar como van a hacer frente a los pagos pendientes pueden llamarme. Las dos deudas han sido reclamadas judicialmente y han generado unos gastos. Si bien podemos llegar a un acuerdo con el fin de reducir los costes el máximo posible teniendo en cuenta las especiales circunstancias de Dña Emilia. Quedo muy pendiente de su respuesta y de atender cuanto precisen para solucionar estos trámites. Atentamente COMUNIDAD DE PROPIETARIOS PLAZA DE LA PAZ, 3 NIF: H 10118859 Dña. Emilia Gutiérrez Serradilla titular del piso 4º D, fincas registrales 7.869 y 9.792/BIS en término de Coria, provincia de Cáceres adeuda a la comunidad Plaza de la Paz, 3 las siguientes cuotas: La cuota ordinaria aprobada para el año 2018 correspondiente al piso 4º D es de OCHOCIENTOS CUARENTA Y CINCO EUROS CON DIECIOCHO CÉNTIMOS (845,18 €), una vez restados los ingresos que irregularmente van efectuando los copropietarios quedarían pendientes DOSCIENTOS CUARENTA Y UN EUROS CON CUARENTA Y DOS CÉNTIMOS (241,42 €). La cuota aprobada para el año 2019 correspondiente al piso 4º D es de OCHOCIENTOS TREINTA Y TRES EUROS CON SESENTA Y DOS CÉNTIMOS (833,62 €). No ha sido abonada y queda pendiente en su integridad. La cuota aprobada para el año 2020 correspondiente al piso 4º D es de DOSCIENTOS CINCUENTA Y DOS EUROS CON CUATRO CÉNTIMOS (833,62 €). No ha sido abonada y que pendiente su integridad. La cuota extraordinaria aprobada para el año 2020 correspondiente al piso 4º D es de CUATROCIENTOS SESENTA EUROS (460,00 €). No ha sido abonada y queda pendiente en su integridad. La cuota aprobada para el año 2021 correspondiente al piso 4º D de los cuatro primeros meses del año es de TRESCIENTOS EUROS CON SESENTA Y NUEVE CÉNTIMOS (300,69 €). No ha sido abonada y queda pendiente en su integridad. La cuota extraordinaria aprobada para el año 2021 correspondiente al piso 4º D es de DOSCIENTOS CUARENTA EUROS (240,00 €). No ha sido abonada y queda pendiente en su integridad. COMUNIDAD DE PROPIETARIOS ALMANZOR, 27 NIF: H 10196954 Dña. Emilia Gutiérrez Serradilla como titular del piso 2º D, finca registral 5917 en el término de Coria, provincia de Cáceres adeuda a la comunidad Almanzor, 27 las siguientes cuotas: La cuota ordinaria aprobada para el año 2019 correspondiente al piso 2º D es de DOSCIENTOS NUEVE EUROS CON NOVENTA Y CINCO CÉNTIMOS (209,95 €), una vez restados los ingresos que irregularmente va efectuando la propietaria quedarían pendientes SESENTA Y NUEVE EUROS CON OCHO CÉNTIMOS (69,08 €). La cuota aprobada para el año 2020 correspondiente al piso 2º D es de DOSCIENTOS SESENTA Y NUEVE EUROS CON DOS CÉNTIMOS (269,02 €). No ha sido abonada y queda pendiente en su integridad. La cuota extraordinaria aprobada para el año 2020 correspondiente al piso 2º D es de CUATROCIENTOS VEINTITRÉS EUROS CON TREINTA Y CUATRO CÉNTIMOS (423,34 €). No ha sido abonada y queda pendiente en su integridad. La cuota aprobada para el año 2021 correspondiente al piso 2º D de los cuatro primeros meses del año es de OCHENTA Y NUEVE ERUOS CON SESENTA Y SIETE CÉNTIMOS (89,67 €). No ha sido abonada y queda pendiente en su integridad. Alberto José Clemente Pérez Abogado Administrador de Fincas Avda de Extremadura 4A 1º C 10800 CORIA (Cáceres) tfnos: 927 503 843 608 690 120','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-09','miguel, llega este email de Damian: Buenos dias hoy se me ha vuelto a perder la pastilla el protector de estomago.le llegaron los mensajes? Me he quedado preocupado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2021-04-09','-Amalia : envio a Plena Inclusion Montijo solicitud y contrato de Habilitación Funcional firmado , guardo copia en su expediente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-04-09','Buenos días Amalia: Os notificamos que un taxi recogerá a Remedios a las 15:20 le acompañara una Cuidadora de residencia. El servicio tiene un coste de 200 euros, por la tarifa del taxi. Ha resultado imposible disponer una furgoneta, ya que hoy hay servicios de trasporte planificados en co, cd y comedor, y además seria necesario dos profesionales, un conductor y un cuidador. Agradezco que confirmes recepción. Un saludo. Catarina Mª Ferreira Barbedo Servicio de Apoyo a Familias Aprosuba 3 Plena Inclusión Badajoz Tfno.: 610292594 www.aprosuba3.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-09','miguel, a petición de Ana y debido a que el equipo de salud mental hablaba de que había habido una citación a la que no habíamos acudido, y ante el desconocimiento por nuestra parte de dicha citación, llamo al Jzdo de Cáceres nº2 quién me informa que no existe dicha citación y que lo único que hay es el requerimiento que nos hicieron y les contestamos acerca de la lista de espera en Centro. Por tanto ahora sólo queda esperar a que resuelva el juez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-04-09','miguel, conforme me pide Ana, llamo sin éxito (comunica) al Jzdo nº1 de Valencia de Alcantara, con el que ya hablé y no me supieron concretar nada sobre el escrito que les remitimos el 8-2-2021. Les remito por fax solicitud de contestación urgente a dicho escrito y les adjunto el escrito que remitimos junto con su oficio y registro de salida, pero sin los documentos adjuntos. Quedo a la espera de contestación por el juzgado.','2');
