insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-04-09','Ana: En relación al corro de Paloma Reyes, TO del CRR-CC, envío correo a May, Jefa de Secc. Mayores (margarita.masegosa@salud-juntaex.es // mayores.sscc@salud-juntaex.es): "Buenas tardes May, En relación al próximo ingreso en Centro Residencial de Agustín Castaño Tornavaca, tutelado por la CTAEX, tras los contactos y gestiones oportunas, me informa Paloma Reyes, Terapeuta Ocupacional del CRR, que ayer tuvieron cita con su MAP para solicitar la realización de la PCR. Se la harán el próximo lunes día 12, por lo que entendemos que el ingreso tendrá lugar el miércoles 14. Si queréis contactar desde la Unidad con Paloma, estos son los números de contacto: 927 181 109 - 687 487 675 Por favor, mantenedme informada. Un saludo y buen fin de semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-04-09','miguel, escribo a la abogada Estefanía: si es posible, a ver si podemos ir viendo este expediente el próximo martes por la mañana. La llamaré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-04-09','Ana: Llamo a Ana Isabel Amor Serrano, Psicopedagoga de PLACEAT (637 765 028), Cristofer está realizando llamadas de atención monumentales contínuas. Lo del cuchillo fue otra llamada de atención. Cogió uno que no cortaba y estaba esperando en el baño a que llegara algún educador. **Ayer llamó él mismo al 112 y allí se presentó la ambulancia. *Han determinado requisarle el teléfono, pues sin él está mucho más tranquilo. *Él no está conforme con nada y cuando le llevas la contraria se enfada. . **La visita con su hermano estupendamente, pero al retornar al centro comenzó de nuevo a realizar llamadas de teléfono a todos los sitios que se le ocurrían demandando atención. Participa en las salidas, pero no en la actividades, no logran convencerlo para que participe en ellas. **El día 20 de abril tiene cita con la Psiquiatra. Ayer le pusieron el inyectable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-09','Ana: Correo de Pilar en relación a la entrevista mantenida entre José Manuel y Beatriz, directora del CRR-BA: "Ana, todo bien, en principio el martes podemos saber los resultados de la PCR que se hará el lunes a las 8,30. Creo que sería conveniente que fuera en taxi y evitar mejor el contagio que si lo hiciese en autobús. Un abrazo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2021-04-07','Ana: Correo de Estrella Durán, TS del CSS-Plas, al ctutelar@: "Buenos días. Soy Estrella Durán, la Trabajadora Social de la UHDAC del Centro Socio-Sanitario de Plasencia. Como sabréis está en lista de espera de dicha unidad Mª PILAR SÁEZ BERMEJO, la cual fue derivada por el UHB del Hospital de Cáceres, siendo tutelada vuestra, necesito me comuniquéis si seguís interesados en dicho ingreso y si no es así, enviéis renuncia. Saludos." ··········· Se lo reenvío a Teresa CTAEX, pues por zona ya le corresponde a ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2021-04-09','Ana: Correo de Teresa, TS CTAEX: "...YA HE HABLACO CON LA TS Y SE ENCUENTRA BIEN NADA DE ALTERACIONES DE CONDUCTA ASI QUE LA QUITAMOS DE LA LISTA YA ME ENCARGO YO DE MANDAR LA RENUNCIA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-12','TERESA ME ENTREGA TONI DOS MULTAS, UNA DE ELLA VIENE POR HACIENDA POR HABERSE PASADO EL PERIDIO DE PAGO LA OTRA LA VA HA RECURRIR ANGEL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-04-12','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "... Aaron Rosado Alarcón tuvo que ser derivado a Salud Mental debido a que tuvo alteración de conducta grave con agresión a una residente. Actualmente, permanece ingresado y, según me dice el técnico de ASINDI que ha hecho el seguimiento, el psiquiatra que le atiende considera que debe ingresar en la UDAD ya que en poco tiempo ha tenido varias conductas de agresivas hacia residentes y profesionales, que cada vez son más frecuentes y de mayor gravedad. Aaron el día que le derivaron manifestaba que no podía controlarse, se tuvo que personar la guardia civil y hay parte de lesiones de la residente a la que agredió. Desde ASINDI vamos a informar al SEPAD de estos hechos porque, como te indico, cada vez son más graves, y nos preocupan. Se podrá valorar la posibilidad del ingreso en otro recurso como la UDAC. Creo recordar que él tenía solicitada y aprobada el ingreso allí, pero por falta de cama no pudo entrar. Hablé con tu compañero Angel y me dijo que los trámites para solicitar la autorización judicial de ingreso involuntario están en marcha desde marzo. Mi teléfono es el 669 60 29 20. Me gustaría hablar contigo y ver cómo está la situación. Un saludo," ············ Tras reenviar el correo a Soraya Masa, jefa de U.PP.AA., escribo a Sonia Bernabé: "...Acabo de escribir a Soraya Masa, jefa de Unidad de Programas Asistenciales, la llamaré igualmente a lo largo de la mañana, a ver qué se puede hacer. Como Ángel te ha comentado, se encargaron ya de la solicitud de autorización para el ingreso involuntario “no urgente”, pues es lo que se pedía en el documento que se nos entregó. Entiendo, que sí ahora sí es urgente, a priori no haría falta dicha autorización judicial no urgente y podría pedirla el Psiquiatra, igual que para la UHB. En cualquier caso ya nos irán diciendo. No te llamo de momento, pues no puedo darte más información. En cuanto hable con Soraya te llamo. Espero que las personas a las agredió se encuentren bien. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-04-12','TERESA ME COMUNICA LOLA TS PLEN INCLUSION QUE ANDRES SERA TRASLADADO DURANTE UNA SEMANA EL PROXIMO DIA 20','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-12','En relación con la solicitud de internamiento involuntario el Juzgado de Castuera aún no ha resuelto. Al parecer el Juzgado pensaba que habíamos pedido la autorización para ingresarlo en el CSS de Plasencia, sin embargo, en la solicitud, no especificamos centro, tan solo indicamos "centro de discapacitado".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2021-04-12','TERESA TRAS CONVERSAICON CON TS DEL HOSPITAL DE SANTIAGO ME COMENTA QUE PILAR ESTA BIEN ADAPATADA AL CENTRO Y NO PRESENTA PROBLEMAS DE CONDUCTA CON LO CUAL ENVIO RENUNCIA PARA QUE LA QUITEN DE LA LISTA DE ESPERA DE LA UHDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-04-12','Se ponen en contacto, con el programa de Apoyo Social Comunitario, desde la Residencia La Salud (Lupe - gobernanta). Nos indican que José Antonio tiene cita el día 14 de abril para la intervención para la retirada de la bolsa de colostomía. El dia 8 de abril le realizaron el TAC de contraste, hoy día 9 le han realizado las pruebas de la pre anestesia, el día 10 le realizaran la PCR y el martes día 13 de abril ingresa en el Hospital de Don Benito - Villanueva. A todas estas pruebas ha ido acompañado de la cuidadora Julieta. Han indicado a la trabajadora social del Hospital la situación de José Antonio, por tener una discapacidad intelectual y estar tutelado, con el fin de que lo pueda acompañar la cuidadora durante estos días, pero aún no han obtenido respuesta, ya que están prohibidos, por la Covid, todos los acompañamientos hospitalarios en Extremadura y este hospital concretamente tiene activo un brote en la actualidad La mayor urgencia que me comenta, es en relación a la autorización que tiene que firmar Comisión Tutelar, ya que le han informado (anestesista) que sin ella no se realizaría la intervención. Según informa Lupe, ya la han enviado a Comisión desde el hospital, pero no sabe concretamente si por vía postal o email.','2');
