insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GUTIERREZ'and apellido2='ALMARZA'),'2021-04-12','-Amalia : envian desde el C. Residencial factura del sepelio que derivo a sección eco para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-12','-Amalia : envio email a Soraya Maya , Jefa de Unidad de Gestión de la Actividad Asistencial del SEPAD : Lun 12/04/2021 12:02 Buenos días Soraya , se ha planteado una subcomisión de casos desde el ESM de Valdepasillas ( Badajoz ) para ALEJANDRO NÚÑEZ BONO , curatelado por la Comisión Tutelar . Tiene un 63% G.Discapacidad por Inteligencia Límite, Trastorno del desarrollo y alteración de conducta. Adjunto resolución denegatoria del CADEX para acceso a plaza RAL por consumo activo de drogas, que solicitó en 2018 la Dirección General de Política Social , Infancia y Familia . Presenta un " sin grado " en valoración de depencia. Fue tutelado por menores y estuvo residiendo en los pisos tutelados que gestiona HOFA. Las últimas incidencias acaecidas en su domicilio familiar , donde reside con su madre , han motivado a la solicitud de una subcomisión de salud mental donde podamos estar representantes de todos los recursos implicados para orientar una intervención. Sigue consumiendo marihuana , se ha conseguido que acuda a las citas del CEDEX acompañado de delegada tutelar pero con reticencias constantes. Con seguimiento desde ESM con escasa adherencia a tratamiento . Muy agresivo verbal y físicamente con su madre y abuelos , se ha llegado a avisar a la policía en varias ocasiones . Me pongo en contacto contigo a petición de Carmen Díaz , TS del ESM, para que si se estima oportuno pueda estar presente en esta subcomisión , que se hará por videoconferencia , algún representante del CADEX o de la Sección de discapacidad. Se ha puesto en contacto con la Dtra. CADEX que le informa que tiene que ser a través de una derivación de esa Unidad. Se ha solicitado presencia de psiquiatra, TS ESM , CEDEX , UHDAC , CTAEX , delegada FUTUEX y CADEX . ---------------------------------------------------------- Respuesta de Soraya : Hola Amalia, pues en este caso creo que si el consumo está activo, sería más perfil de otras redes. De otro lado si es una persona sin grado también parece difícil que pueda llegar a los centros residenciales del SEPAD, y de discapacidad. Si el Cadex va a estar y vosotros también, creo que en principio nosotros no debemos estar. Participamos en todas las comisiones regionales, y creo que en las que son de área , si ya estáis vosotros no hace falta más. En estas condiciones y con consumo activo, es necesario que sea atendido en otras redes (drogodependencia) antes de venir a la nuestra. Saludos. Soraya Masa Moreno Unidad de Gestión de Programas Asistenciales Dirección Gerencia SEPAD soraya.masa@salud-juntaex.es JUNTA DE EXTREMADURA ----------------------------------------------------------- Vuelvo a escribir : Buenos días , en principio como bien dices , su consumo activo de drogas veta todos los recursos residenciales del SEPAD , pero está asistiendo a CEDEX , vamos a ver si la situación revierte . Mª Ángeles del CADEX , es la que ha comentado a la Trabajadora Social del ESM , que la petición para asistir a la subcomisión tiene que ser solicitada desde el SEPAD . Creemos que sería conveniente que estuviese algún representante del CADEX , para orientar una intervención futura llegado el caso . Un saludo','2');
