insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-12','email de Damian: Anoche no pedi el protector de estomago y esta mañana encontre en mi habitacion una pastilla me la tome por mi cuenta del suelo.y por la mañana muchas veces al no encontrar la pastilla no la pido porque se me olvida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-12','miguel, me llama Damian pregunta que quién lleva y cuándo se va a resolver su petición para su traslado al CRR de Mérida, insiste en si podemos ayudarle para que le trasladen al CRR de Mérida, le insisto que desconocemos quién lo está resolviendo y el tiempo que tardarán en hacerlo. Ante la insistencia con la revisiónd de su grado le vuelvo a aclarar que para esta solicitud de traslado no es necesario dicho grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-04-13','miguel, me llega email de la abogada Estefanía: Buenos días Miguel, ya estuve repasando la documentación. Entiendo que lo primero que habría que hacer es la escritura de herencia de los dos hijos, pues ambos están fallecidos. Respecto de Agustín, el hijo que falleció primero, desconozco si falleció con testamento o no, y si se ha hecho algún trámite al respecto (supongo que de haberse realizado tuvo que ser la misma notaría que adjudico la herencia del esposo de Alfonsa). Mercedes también lo desconoce, aunque me ha confirmado que falleció soltero y sin descendencia. En ppio, no tenía tampoco ningún tipo de bien pues vivía en casa de sus padres. En cuanto a Juan Felipe, Dña. Alfonsa es heredera universal y Mercedes legataria de la parte del usufructo que le correspondía. En este caso necesito ver como se valoraría el usufructo de Mercedes, dado que, como se deduce de la escritura de herencia del padre, los bienes que tenía Juan Felipe lo eran en nuda propiedad correspondiendo el usufructo a Alfonsa. Es decir, existen dos usufructos y tengo que estudiar si el de Alfonsa anula el de Mercedes, o bien, se pueden valorar como usufructos sucesivos y darle algún tipo de valor, porque veo complicado que registralmente se pueda inscribir dicho usufructo. Voy a hablar con una Notaría con la que trabajo, a ver que me dice y si alguna vez se les ha dado ese caso. Obviando dicha situación, una vez se pueda realizar la Escritura de Adjudicación de Herencia de ambos hijos, debería solicitarse mediante un expediente de jurisdicción voluntaria, la aprobación de dicha Escritura (es un trámite sencillo que ya he hecho en alguna ocasión). Al mismo tiempo que se somete a aprobación dicha Escritura, lo ideal sería poner a la venta los inmuebles adjudicados, para ir adelantando, dado que ésta también necesitaría autorización judicial. Esto supone un nuevo expediente de jurisdicción voluntaria, y al mismo habría que acompañar un informe pericial que acreditarse que el valor del mercado del inmueble y una oferta de venta que se adecue al mismo para que nos autoricen dicha venta. Respecto de nuestros honorarios, te enviaría entre hoy y mañana una propuesta, pero antes necesitaría saber si se ha hecho o no algún tramite en relación a la herencia de Agustín. Por otro lado, también me gustaría consultar que ocurre con el usufructo de Mercedes sobre los bienes adjudicados a Juan Felipe en nuda propiedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-04-13','miguel, llega rechazado la solicitud al Jzdo de Cáceres (1º instancia por turno que corresponda) porque de oficio lo ha debido de remitir el Jzdo de Valencia de Alcantara a Cáceres. Lo lleva el jzdo de 1º instancia nº3 de Cáceres procedimiento ITR 419/21. ************************************ Archivo por tanto el registro que llega del Servicio Comun del Jzdo de Cáceres denegando la solicitud de internamiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2021-04-13','miguel, recibo de Amalia por email citación del jzdo nº1 de Mérida en relación a DPA Diligencias previas Procedimiento Abreviado 459/20, en relación a la denuncia que interpuso la tutelada. Tras consulta con Angel me confirma: "La citan a ella para ratificarse en la denuncia y reconocimiento forense. Si sigue adelante e procedimiento, supongo que ya si tendríamos que ir. He comunicado al centro que la acompañen ese día al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2021-04-13','emails de Juana a Jose A. de Tecnicasa: Buenos días José Antonio, No sé si recuerdas que te comenté hace un par de semanas cuando coincidimos en el CC de Conquistadores, que teníamos un tutelado pendiente de repartir una herencia con su hermana. Este es el chalé en la Dehesilla de Calamón del que te hablé, te mando word con la ubicación exacta del google maps y datos catastrales. Si pudieras hacer una valoración a groso modo te lo agradeceríamos porque estamos un poco perdidos. Sup. gráfica parcela: 5.360 m2 Superficie construida: 438 m2 Uso local principal: Residencial Valor suelo: 895,90 € Valor construcción: 113.970,86 € Valor catastral: 114.866,76 € Año valor: 2020 Muchas gracias Saludos Juana María Esperilla Hierro Sección Económica Comisión Tutelar de Adultos ********************************************** Contestación de Jose A. de Tecnicasa: Teniendo en cuenta que no la he visitado “in situ” y valorándola con las fotografías aportadas, estando en una urbanización muy cercana a Badajoz, asfaltada, con agua de red y careciendo de piscina y por otras similares que hay o pudieran haber estado a la venta recientemente, estimo un precio aproximado de 220-230.000€. Para cualquier duda o aclaración estoy a tu disposición. ************************************************ miguel, me llega email de Juana: Reenvío correo de José Antonio de Tecnicasa acerca de la valoración que ha hecho del inmueble de la Dehesilla de Calamón, entre 220.000 y 230.000 euros, no varía mucho de la que nos dijo Yolanda cuando habló con su amiga de la inmobiliaria 240.000 euros. Por el local José Antonio me dijo, que estaría sobre los 1000 euros el m2, con lo que no se puede pedir más de 60.000-65.000 euros. La hermana le había ofrecido su parte del local más 68.000 euros a cambio del campo, en mi opinión debería de ofrecer al menos 80.000 euros para compensar según los importes de las valoraciones que estamos hablando. Podemos ir moviendo esto cuanto antes, si se llega a un acuerdo, podría Javier empezar a cobrar el alquiler íntegro del local..... **************************************************** miguel, conclusiones de reunión con Juana y Alberto: Reunión 13/04/2021: Juana, Miguel y Alberto. Asunto: venta vivienda Dehesilla de Calamón por parte del tutelado a su hermana. En relación con la oferta y contraoferta económica para la venta de esta vivienda, se propone realizar una contraoferta en los siguientes terminos: • Se acepta una valoración aproximada de la vivienda Dehesilla de Calamón x 230.000 € aprox. (coincide también con la valoración que la amiga de Yolanda ha realizado (también trabaja en una inmobiliaria). De los cuales 115.000 € serían el valor de la parte del tutelado. • Si aceptamos que el local puede tener un valor de 60.000 €, de los cuales 30.000 € serian los cedidos por la hermana a nuestro tutelado, faltarían 85.000 €. Solicitaremos 90.000€ negociables hasta 85.000 € • La hermana ha ofrecido 68.000 €, además del local. Por tanto debemos exigir, para igualar los valores de las propiedades que aporte 22.000 € más, que serían los 90.000 € Juana redactará borrador contraoferata, Miguel lo supervisará, veremos entre los 3 el definitivo y se pasará a firma del Director Gerente. También se exigirá la firma del curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-13','Ana: Tras haberse detectado una incidencia con la PFHC de Isabel y recibir llamda de Juan Luis Rico Aguilar,de PFHC, intercambiamos correos (juan-luis.rico@seg-social.es), finalmente me remite éste último: "Buenas tardes Ana, En la Dirección Provincial de Badajoz no tienen constancia de la solicitud de la prestación. Hemos procedido a procesar la baja del expediente nº 10-2016-2018 a nombre de Francisca Blázquez Borreguero cuyo causante es Isabel María Cano Blázquez con D.N.I 028980228K ya que se encuentra incapacitada judicialmente y tutelada por la Comisión Tutelar de Adultos. La baja tendrá efectos del 01-07-2021 lo cual permite si lo consideras oportuno enviar una nueva solicitud antes del 30-06-2021 para que no se vea interrumpido el cobro de la prestación por la causante que es quien la está percibiendo. Un saludo." ·································································································································································································· Cumplimento y pongo para firma del D.Gerente, nueva solicitud de PFHC (modelo para entidades jurídicas).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-14','Ana: Llamada de Damián (622 834 876), hace dos días tuvo que acudir al dentista a que le extrajesen una muela por dolor intenso, fu con carácter de urgencia, por lo que no se envió presupusto previo. *Lo comunico mediante mail a Icíar y Alberto, secc. ecca. ····················· Por otra parte, vuelve a repetir su discurso en torno a todas sus preocupaciones habituales: plaza del CRR, traslado a Mérida, Piso en alquiler, gestiones con el Ayto. de Málaga...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-13','Ana: Correo de Alberto, jefe de secc. ecca., a Belén: "Hola BELEN: Modificación de la ASIGNACIón de GALAN GILGADO, GUILLERMO: A partir de 01/05/2021: 60 €/MES, con acompañamiento (Gloria, Educadora de Futuex): xfa confirmaselo a Toni (FUTUEX). ANA: hasta ahora tenía 33 €/quincena así que, en realidad, le estamos dando menos dinero. Hablamos. Alberto." ················ Confirmo a Minerva, TS, CR Cervantes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-12','Ana: Toni, Futuex, envía correo con información acerca de la entrevista de José Manuel con el CRR, la cuál fue bastante bien. Adjunta presupuesto de taxi para el traslado del miércoles 14 al centro. **Se lo reenvió a Alberto, jefe secc. ecca., marcado como importante y urgente, dando el ok por mi parte. Para que hagan las getiones oportunas y se lo confirmen a Toni.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-14','Ana: Llamo a Toni-Futuex, Virginia acaba de confirmarle que José Manuel estaba subiendo ya al taxi. Todo ha ido bien. *Pido a Toni, que al menos, al principio, sigan visitando y haciendo seguimiento a José Manuel. ························································································ Llamada de José Manuel (627 78 87 97), va de camino en el taxi. Está contento pero un poco nervioso. Por otra parte dice que va sin dinero y sólo lleva 2 cigarros. (Además se fumó 1 mientras esperaba al taxi y otro antes de subir al mismo). *Le recuerdo que desde el CRR envirán, una vez lo hayan establecido, una propuesta de presupuesto mensual para gastos de bolsillo. ································································································································································································································································· Correo de Beatriz, Coordinadora del CRR-CC(bgonzalez.sanmiguel@hospitalarias.es): "Buenos días Ana, Hoy ha ingresado en la residencia José Manuel R. M, viene sin dinero por lo que necesitaríamos que nos enviaráis una autorización para poder sacar 100 euros de su cuenta hasta hacer presupuesto con él (por favor ponednos en copia cuando se la enviéis a Liberbank)." ·············· *Se lo reenvío a Alberto, Jefe de Secc. Ecca. e indico además que deben *dar de baja el Cáterin. Un saludo." ························································································································································································································································· Envío correo a Julio, Juan Pedro y Amalia, CTAEX: "... Hoy también ha tenido lugar el ingreso en el CRR de Badajoz, de José Manuel Romero Mediavilla. Ya tenéis los datos para hacer el cambio en la base. Amalia, lo mismo que con el otro caso, me encargo yo hasta que haya pasado el periodo de adaptación. Ante cualquier cuestión, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2021-04-14','miguel, recibo email de Tere de un interesado del pueblo en comprar los bienes de la tutelada, Carlos: BUENOS DIAS MI NOMBRE ES CARLOS ALBERTO PASCUAL VECINO DE MONROY. ME PONGO EN CONTACTO CON USTEDES POR QU ESTARIA INTERESADO EN ADQUIRIR UNA VIVIEDA Y UN CORRAL QUE TIENE INES MUÑOZ ALIAS EN MONROY ME HA PASDO EL CONTACTO LOS PRIMOS DE INES QUE DICEN QUE ESTO LO LLEVAN USTEDES ME GUSTARIA SAVER LO QUE PIDEN POR LA VIVIENDA Y POR EL CORRAL . EL CORRAL LLEVAMOS NOSOTROS CON EL CEDIDO DESCE HACE MAS DE 20 AÑOS POR QUE MIGUEL MUÑOZ ALIAS SE LO TENIA DEJADO A MI PADRE DANIEL PASCUAL ALIAS COMO AGRADECIMIENTO A LA AYUDA QUE LE PRESTAVA Y PUESTO QUE ELLOS NO LO UTILIZAVAN. NOS GUSTARIA PODER QUEDARNOS CON EL EN PROPIEDAD, EL CORRAL ESTA UBICADO EN LA CALLE LA CHARCA y ESTA EN RUINAS. LA VIVIENDA ESTA EL LA CALLE LAS ARTES SERIA PARA UN CUÑADO MIO PERO ME HA QUEDADO ENCARGADO A MI DE Averiguar LA Situación DE LA VIVENDA, SI SE Podría IR A VER, Y EL PRECIO QUE Tendría SIN MAS ESPERO SU Contestación MUCHAS GRACIAS MI NUMERO DE TELEFONO ES 627973926 ********************************************************* email de Alberto: En relación con la propuesta de compra de la vivienda informaros de que la situación ECO de la tutelada es muy favorable. NO sería necesario proceder a la venta. Dicho esto, la propiedad de la vivienda tampoco nos aporta nada, por lo que sería factible proceder a su venta (quizás evitemos problemas a posteriori por vivienda en mal estado o situaciones similares). También, a los efectos de no generar mucho trabajo, podríamos encargar la venta a una gestoría (si se lo encargamos a una inmobiliaria quizás encarecería mucho la venta x la comisión). Eso sí, Miguel tendría que solicitar autorización al juzgado. Si os parece, mañana lo hablamos. ******************************************************* miguel, mi contestación a Tere y Alberto: Buenos días, mañana lo hablamos como dice Alberto. En su día ya comentamos que es una mujer mayor sin familia(sólo un primo lejano en Madrid que nos aportó documentación) y como veréis en la intranet ya se interesaron anteriormente dos personas Jacinto y un tal David. Éste último quedó en ponernos en contacto con una gestoría del pueblo para que tramitara la herencia de sus padres…ya que no disponemos de información, y nunca más se supo de él…Yo os adelanto que veo innecesario hacer cualquier trámite cuando esta señora ya dispone de capacidad económica. Con lo que acordemos mañana llamaré al interesado, Carlos…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-14','miguel, email de Damian: Los monitores no estan atentos a ver si me he tomado noches atras me la dieron y una mañana no me la tomaria que los monitores pasaron y me acaba de aparecer el protector de estomago con el emboltorio cerrado en mi mesilla de noche ni me acorde hace dias atras que un dia no me la tome','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-04-14','Ana: Llamada de Jairo, se ha apuntado a un taller de costura de lunes a viernes en el propio CSS. Le van a abonar por ello 80€/mes. ··························································································································································································· Conversación con Emilia, TS del CSS: me informa de que el taller de costura aún no está organizado y cerrado, Jairo está propuesto para el mismo en un inicio, pero aún no es seguro. Además, lo del dinero no es como Jairo lo plantea, serán uno 10-15 €/semana, en función de la actividad/tareas que realicen. *Por otra parte, el acuerdo al que se ha llegado desde el CSS con la secc. ecca. es de 100€ cada 6 meses para ropa, en función de su necesidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-04-12','Ana: María Glez. Palomo, TS de F. Autismo Sur, me indica que desde PNC les han solicitado que presentemos solicitud de revisión del grado de discapacidad (al parecer lo piden para todas las personas que solicitan PNC, según indica) así como un "informe" sobre la situación legal del joven.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-04-14','Ana: Se pone para firma del D. Gerente la solicitud de Revisión del Grado de Discapacidad de Costi Alesandru solicitada. ···················································································································································································································································· Redacto y subo al portafirmas gigital "Informa" sobre la situación actual de Costi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-14','Ana: Llamo a Minerva, TS del C.R. Cervantes (927 005 575) varias veces a lo largo de la mañana, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-04-14','Ana: correo de Estrella, TS CSS-Plas.: "Buenos días, Ana. Esta mañana ha estado en nuestro centro Gloria de Futuex con objeto de ver a Desideria y contactar también con nosotros.... Hemos quedado en que a lo mejor sería interesante, que presentarais solicitud de dependencia, con objeto en principio de que pudieran beneficiarse de servicio de Promoción de la Autonomía ...pudiera Terapeuta o Educador orientarlos en temas domésticos y de gestiones...o incluso apuntó la Psiquiatra en un futuro necesite un CRR o algún otro recurso residencial..., pues ya tendría el grado, si es que da, claro... Qué te parece. Espero tu respuesta." ···························································································································································································· Mi respuesta: "Buenas Estrella, Pues por mi parte no hay inconveniente. Cuando puedas me envías la solicitud cumplimentada para la firma del D.Gerente, entiendo que desde ahí podréis aportar los informes de salud, social y cualquier otro que consideréis oportuno (como por ejemplo de Psiquiatría), y a ver si da grado. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-04-14','TERESA ARCHIVO RESOLUCION PNC 602.4€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-04-14','Ana: Llamo al CRR-CC (663 402 616 // 679 936 087), hablo con Paloma, T.O., el ingreso de Agustín en el Centro de Mayores e ha producido con normalidad, esta mañana estaba emocionado, pues la despedida con los compañeros ha sido muy emotiva, le han organizado un desayuno especial. ··········· *Reenvío el resultado negativo del PCR a la secc. de mayores. ································································································································································································· Envío correo a Julio, Juan Pedro y Amalia, area soc. CTAEX: "...Comunicaros que hoy se ha producido el traslado de Agustín Castaño Tornavaca, desde el CRR de Cáceres a la Residencia de Mayores de San Vicente de Alcántara. Actualmente “Puente Real”. Os anoto los datos: Residencia Puente Real San Vicente Camino de Piedrabuena, 13. San Vicente de Alcántara. 924 41 08 35 La directora es Ángeles Crisóstomo Amalia, de momento, durante el periodo de adaptación, yo estaré pendiente, así como de los documentos pertinentes al ingreso. Después ya pasará a tu zona. Ante cualquier cuestión, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-14','Ana: En relación a la llamada de Francisca, madre de Isabel, envío corre a Estrella, TS CSS-Plas.: "Buenas tardes Estrella, Fcra, madre de Isabel, me ha llamado esta mañana diciendo que le han autorizado para ir a visitar a Isabel el próximo sábado y diciendo que necesita dinero para ir a verla, que le hagamos una transferencia a su cuenta. Por favor, cuando puedas confirmarme si es procedente tanto la visita (si se le ha autorizado realmente) y si consideráis conveniente que sea Isabel quién sufrague el traslado (pide entre 20 – 30 €). Si lo consideras, hablamos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-04-14','Ana: Correo de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net) reenvía correo de Blanca, Psicóloga de Asindi: "Hola, Sonia. Acabo de hablar con el doctor Molina, el psiquiatra que está llevando a Aaron durante su estancia en la UHB. Por lo que me cuenta, Aarón está tranquilo, pero le nota muy expansivo y con conductas infantiloides, por lo que va a hacer un ajuste de medicación para su abordaje. En cuanto al ingreso en la UDAC, el doctor se puso en contacto con este recurso para trasladarles la necesidad del ingreso de Aarón en el mismo. Desde allí, se comunicó que tenía la plaza aceptada, pero que está en este momento en lista de espera en la posición quinta, por lo que la fecha de su ingreso no se puede estimar. Aarón durante su ingreso en la UHB, manifiesta no querer volver a ASINDI, ya que según dice no se encuentra a gusto y no quiere seguir con la pareja actual, pero que tampoco sabe cómo dejarla. Expresa querer irse a casa una temporada con su padre, éste, por su parte, no tiene claro que sea positivo que esté todo el día en casa, y propone la opción de venir solo al Centro Ocupacional como externo. De momento Aarón permanece al menos hasta el viernes en la UHB, a esperas de que con el ajuste de tratamiento se estabilice algo. El jueves vuelven a contactar para informarnos sobre su estado y posible regreso." ···························································································································································································· Llamo a Sonia Bernabé - Asindi (669 602 920), pero el número no está disponible. ························· Le envío un correo: "... Ayer estuve hablando personalmente con Soraya, Jefa de Unidad de Programas y Recursos Asistenciales, me viene a decir lo mismo que os ha transmitido el Dr. Molina. La UHDAC está llena y hay lista de espera. Puesto que no tiene opción de ingreso con carácter de urgencia, no queda otra opción que esperar a que llegue su turno. Por tanto, cuando el médico considere darle el alta tendrá que volver a vuestro centro. Ya sabéis que en el momento que vuelva a hacer falta, tendréis que activar nuevamente el 112 y, si fuera necesario, poner denuncias (ojalá que no hiciera falta…) En cuanto al hecho de irse a casa de su padre, si quieres lo hablamos mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2021-04-15','TERESA RECIBO EMAL DEL PISO . Necesito confirmación y autorización para iniciar tratamiento en el recurso de CEDX para M Mar Gordillo Santana. Pues refiere tener necesidad de consumo de cannabis y considero necesaria la intervención del equipo con ella. SE AUTORIZA Y ENVIO AUTORIZACION FIRMADA DIGITAMELTE POR EMAIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2021-04-15','TEREAS ENVIO AUTORIZCION PARA PONESER UN PEARCING','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-04-15','-Amalia : envio email a Alberto Martín , Jefe de sección económica : Buenos días , con respecto a Pedro , está ocupando plaza residencial privada en Los Olivos de Mérida , con un coste de 1600€. Establecimos un mes para buscar otra alternativa residencial que fuese viable económicamente. Se le está tramitando plaza pública en esa misma residencia , y sanearía sus cuentas . Se necesita un informe médico de psiquiatría para el que tienen cita para la próxima semana . Mientras se gestiona esta opción y a espera de la resolución final del SEPAD ,me he puesto en contacto con Jose María (administración y socio-propietario de la Residencia ) . Creo que económicamente se puede permitir abonar dos meses en plaza privada , si para entonces no tiene resolución de la plaza pública negociaré con ellos una bajada de precio , hoy he hablado con él y estarían dispuestos . Te parece bien ? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2021-04-15','miguel, llega sentencia absolutoria del jzdo nº6 de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-04-15','Ana: Llamada de Pilar Álvarez, Jefa de sección de dependencia de Vva. de la Serena (20337). Comunica que a Aitor, dado que ya ha cumplido la mayoría de edad, le van a hacer la Revisión de Oficio del Grado de Dependencia. La semana que viene enviarán a la CTAEX, a la atención de Teresa, un escrito comunicándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-15','email de Angel: Acaban de llamarme, de nuevo, los abuelos de Alejandro, para transmitirme los problemas que padecen, según dicen, con él. Relatan continuos episodios de violencia, inestabilidad, falta de tratamiento médico, situación que les está llevando a no poder vivir tranquilamente, padecer estados de ansiedad, impotencia y desesperación, amén de quejas en general por nuestra actitud hacia él. También insisten en que no le damos su paga, que es suya y que van a llamar al periódico y a Vara. Creo que debemos poner en conocimiento del Juzgado todas estas incidencias, a los efectos de quedar constancia y de solicitar la modificación de su capacidad, para pasar a tutela y así poder solicitar un internamiento involuntario, pero por otro lado carecemos de recursos para personas que consumen sustancias, como creo es el caso y sin olvidar las modificaciones que van a producirse en las funciones tuitivas, pasando todas a curatelas. *********************************************** email de Miguel: Buenos días, tenemos reunión con el abogado Carlos Jurado Lena el viernes 23-4-2021 para abordar el asunto del dinero que le reclaman sus hermanastras. Si os parece una vez se realice dicha reunión podemos comunicar todo al juzgado. Al ser una curatela, estemos o no a favor en dicha reunión, la decisión tendrá que estar refrendada por el curatelado y recordemos que si no está de acuerdo necesitará ir a juicio asistido de abogado de pago porque no cumple los requisitos para abogado de oficio…Por eso es importante que si quedara claro que ese dinero es de sus hermanas y de él y por tanto a dividir entre 3, llegar a un acuerdo. *********************************************************** email de Amalia: quedamos a la espera de lo que se acuerde en esa reunión . Luego se lo comunicaríamos a Alejandro y su familia , él no sabe que tiene una herencia del padre , para evitar que retirara el dinero . Con la respuesta que dé , si está de acuerdo o no , se le explican las posibilidades que tiene a nivel judicial .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-15','email de Alberto: Informaros que desde 03/2021, el juzgado nº 4 de Cáceres nos está ingresando en la CCC del tutelado 200 € (08-marzo y 09-abril). Además el mismo juzgado el mismo mes de marzo-2021 nos abona 7,14 €, cuyo motivo desconozco. Nosotros seguimos abonando la pensión alimenticia de 200 €/mes al mismo juzgado. Hay ya resolución a través de la cual debamos dejar de abonar la pensión??? Teneis conocimiento de cual puede ser el motivo del abono del juzgado en la ccc del tutelado??? *********************************************** email de Angel: Ayer me llamaron del Juzgado, en el procedimiento de Ejecución de Título Judicial 159/07 para comentarme que ya se ha pagado todo lo que debía a la exmujer en concepto de pagos de pensión atrasadas, más intereses y por eso se están devolviendo cantidades. Envié correo a la oficial para que me facilitara la cuenta de la exmujer y abonar la pensión de alimentos de 200 euros mensuales, hasta que se resuelva el procedimiento de modificación de medidas, que en estos momentos no se ha resuelto. Cuando la reciba os la paso. ************************************************ email de Alberto: Por tanto, corrígeme si me equivoco, Ángel, desde ECO debemos seguir pagando 200 €/mes a la exmujer del tutelado en la CCC que ella nos de una vez que nos pongamos en contacto con ella a través del nº de teléfono que nos has facilitado Si más adelante te llega la comunicación del juzgado con la modificación de las medidas ya nos avisas tu. Iciar este es el correo del juzgado que nos remite Ángel donde figura el teléfono de la exmujer del tutelado y su nº de CCC "Tal como hablamos por teléfono, y en relación al procedimiento ETJ 159/07 seguido contra D. José Manuel Romero Mediavilla, le comunico que Dª Lourdes Carretero Jiménez ha mostrado su conformidad en que le traslademos su número de teléfono para contactar con ella, en caso de que sea necesario, y es el siguiente: 645639474. Asimismo, solicita que los pagos que deban efectuarse a la misma en concepto de pensión , se hagan mediante transferencia a su número de cuenta: ES05 2048 1202 01 3400003567". Ángel, xfa, dinos únicamente desde que mes le tenemos que pagar a ella e Iciar ya se pone en contacto con ella para que le de el CCC. ************************************************** contestación de Angel: Así es. Seguimos pagando los 200 € en la nueva cuenta que nos dio el Juzgado. Hablad antes con la mujer para confirmarla. Una vez se resuelva el procedimiento de modificación de medidas os digo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-15','Ana: Correo de Beatriz, Coordinadora del CRR-Ba (bgonzalez.sanmiguel@hospitalarias.es): "Hola Ana, El ingreso se ha producido con normalidad, ya tenemos que por aquí a José Manuel. ························································································································································································································································· Llamada de José Luis, hermano de José Manuel, esta misma mañana le ha llamado diciendo que ha estado a punto de hacer las malestas y marcharse... Por otra parte piden que de momento no se dén de baja los suministros del domicilio (en eso estamos de acuerdo). Que el lunes le dio 100€ para que se comprara un móvil y también dinero para tabaco... **En cuanto al seguros de decesos, me dice que José Manuel está en la póliza con él y su mujer. ··········································· Informo a Alberto, Jefe de Secc. Ecca. Un saludo y gracias." ······················································································································································································································································· Correo de Eva Paredes, Psicóloga Ud. PP.AA. (eva.paredes@salud-juntaex.es): "Buenas Ana, ayer ingresó ya por fin José Manuel Romero Mediavilla en el CRR de Badajoz, aún no tengo el Certificado de ingreso pero nos lo ha comentado la directora del CRR. Esperemos que vaya bien el periodo de adaptación. Estoy con la Resolución de su plaza, en cuanto la tenga firmada te la hago llegar para su expediente." ································································································································································································································································ Correo-e de Coral, CTAEX, en relación al Seguro de Decesos, José Luís, hermano de José Manuel, lo tiene incluido en su póliza: "Hola el hermano y la mujer insisten en que para ellos no es problema tenerlo incluido en su póliza. Le he insistido que cualquier cambio que tengan que hacer que afectara a la cobertura de nuestro tutelado, lo hagan saber."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-15','Ana: Llamo a Minerva, TS del C.R. Cervantes (927 005 575 // 22237), hoy tocaba renovar la demanda de empleo a Guillermo. *De nuevo No tengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-04-15','Ana: Llamo de nuevo a Pilar, TS de Valencia de Alcánara (627 34 11 19 / 927 580 326, ext.8) me comunica que tienen una Aux. de baja, por tanto están cubriendo con las que tienen el servicio que dispensal al resto de personas usuarias. *Le indico que, en cualquer caso, estamos pendiente de cerrar presupuesto con una empresa de limpieza, así como día de la misma. **Indico que será necesaria la atención para aseo personal y de ropa así como limpieza y mantenimiento del domicilio. **Volveré a ponerme en contacto con ella cuando esté cerrada la limpieza con la empresa privada para fijar fecha de incio del servicio así como días y horario de atención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-15','Ana: Correo de Estrella, TS del CSS-Plas.: "Buenos días, Ana. Sí, viene el próximo sábado, se le permite pasear por el recinto e ir cafetería del propio centro, salir fuera no. Lo hablamos en reunión el otro día, el tema del dinero y sí estamos de acuerdo en que se le proporcione esa cantidad..." ······················ Se lo cumunico a Alberto, se le apruban 20 €, Belén, secc. ecca. CTAEX, hace la transferencia y se lo confirma a Francisca. ·································································································································································································· Llevo a REGISTRA DE ENTRADA al ORVE (registro SES), solicitud de Prestación Familiar por Hijo a Cargo, modelo para personas jurídicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-04-15','Ana: Pongo pora la firma del D.Gerente la Solicitud de Valoración de Dependencia de Desideria. El informe de salud que me envía Estrella, TS del CSS, no está firmado, se lo comunico respondiendo a su correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-04-16','Ana: Envío a Toni-Futuex, correo-e, para derivación: "Buenos días Toni, Procedo, por fin, a las nuevas derivaciones que te comenté. En primer lugar, el joven Darío López Gilarte, de 19 años de edad. Presenta trastorno del Desarrollo y Trastorno de la afectividad por trastorno bipolar. Tienen un hermano que reside con una tía en Toledo, a quién tiene ganas de ver, pues lleva casi 3 años sin verlo. Se había previsto una visita en semana santa, pero dada la situación sanitaria y las restricciones, no pudo realizarse. Se intentará organiza una visita cuando sea posible. Ya tienen solicitado un nuevo recurso residencial, pero aún no sabemos para cuándo se le podrán asignar. El objeto de la derivación es que Darío cuente con otro apoyo externo al piso, fomentar el desarrollo de más y mejores habilidades sociales, procurar una búsqueda de nuevas actividades de ocio y/o formativas, en función de sus intereses y posibilidades, acompañarle a gestiones y cuestiones puntuales y apoyarle en el tránsito y traslado de recurso residencial llegado el momento. Reside en los Piso Tutelado de Menores de Plasencia, gestionado por la entidad Cerujovi Avda. de la Vera, 5. El coordinador se llama José María Gallego (Chema). Telf.: 649 676 149 Ante cualquier cuestión, como siempre, no dudéis en contactar. Un saludo." ··················· Comunico a Chema, mediante mail, que he realizado dicha derivación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-16','Ana: Correo Derivación al Programa de Apoyo Comunitario-Futuex: "Buenos días de nuevo Toni, Procedo con al siguiente derivación: Florencia Dávila García, de 79 años (aún en fase de inventario, no faltan documentos aún…), valorada de discapacidad con un 64% (valorada en el año 1992), diagnóstico, según dictamen técnico del CADEX: Alteración de la conducta por trastorno obsesivo-compulsivo. En base a la información que disponemos a día de hoy: Reside con un hermano, Cesáreo, quien pasa el día en el campo, tienen terrenos y ganado. Como Florencia no quiere ir con él, pasa casi todo el día sola. Un tercer hermano que falleció, es quién se encargaba de atender las necesidades de los tres. Desde 2016 se ha intentado intervenir con la unidad familiar, tanto desde los SSASB como desde Atención Primaria de Salud, pero ha sido complicado. Además, el procedimiento de incapacitación, iniciado en 2017, lo iniciaron profesionales que ya no están (ha cambiado tanto la Trabajadora Social como el Médico de referencia que conocían bien la situación). - Desde el SSASB, dudan que tenga localizado ningún documento personal (DNI, Tarjeta sanitaria…) - Florencia, cuando está en su casa, no suele permitir la entrada en la vivienda, desde la puerta se observa desorden, acumulación de enseres y suciedad. También carece de hábitos de higiene personal. En su sentencia, se autoriza el “internamiento involuntario en centro adecuado” de Florencia, pero desde los SSASB no han solicitado plaza de ningún tipo ni valoración de dependencia. Hablé con Soraya Masa al respecto y dice que no se le puede internar directamente en C. Sociosanitario por la edad que tiene… Yo voy a tratar que desde el C. Salud soliciten el internamiento en UHB para valoración, diagnóstico y estabilización clínica. A parte voy a tratar de hacerme con los documentos necesarios para la solicitud de valoración de dependencia y plaza residencial. Y en estos puntos es donde entráis vosotras desde el programa. El objeto de la derivación es comenzar a intervenir con Florencia de cara al ingreso y el apoyo en el contacto con los profesionales y solicitud de documentación, en su caso (os iré diciendo). Entiendo que también será necesario, en su momento, apoyo para otras gestiones y puede que alguna compra (p.ej. ropa) La Trabajadora Social actual es Raquel Pérez, quién acude a la localidad sólo cada 15 días (normalmente los jueves). Telf. 667 068 078 (es su teléfono personal, pero en Valverde no tiene teléfono, y dado el caso no le importa que le llamamos en horario laboral) La Alcaldesa del pueblo, según dice Raquel, se implica mucho también en el caso, se puede contactar con ella. Reside en Valverde de la Vera C/ Real, nº 36. No tenemos teléfono de contacto personal (no sé si tiene, imagino que no) Ante cualquier cuestión, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-04-16','Ana: Llamo a Mª Jesús Gómez Lozano, Trabajadora Social del SSASB Mancomunidad Comarca Trujillo (621 247 237): En relación a Javier, reside en Puerto de Santa Cruz, un pueblecito muy pequeño, pero a día de hoy se encuentra en paradero desconocido. En febrero, le llamó Cristina, TS del ESM de Trujillo, pues no ha acudido a la cita. Contactaron con los vecinos, quienes le dicen que hace mucho tiempo que no le ven por allí y el suelo de su entrada y el buzón está lleno de cartas. Javier no suele relacionarse con nadie. El Alcalde del pueblo, le ha informado que hace tiempo que no saben nada de él. Ya se ha llamado a la Guardia Civil, desde donde dijeron que pasarían por la vivienda. El Alcalde también llamó y el sargento de la Guardia Civil le dijo que sin una orden judicial no pueden entrar en el domicilio. *No suele abrir la puerta a nadie. *Es un chico joven, tiene 38 años (nació el 27/01/83), tiene hermanos en Cataluña, con quienes no tiene relación. Su padre falleció (Aunque la relación no era nada buena, era su único apoyo). **Mª Jesús me enviará iforme social. Yo pediré Informe a Salud Mental. Y pondrémos todo en conocimiento del Juzgado, a quién se solicitará desde la CTAEX orden judicial para que la Guardia Civil entre en el domicilio, para descartar que no esté en su interior. En caso de no encontrarlo allí, se pedirán que le localicen y pueda llevarse a UHB para valoración, diagnóstico y en su caso estabilización clínica. **En opinión de Mª Jesús, lo más adecuado para este joven sería un ingreso en recurso residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2021-04-16','Ana: Llamo a Margarita Montero, TS de la Mancomunidad Sierra de Montánchez (927 221 206), varias veces, en relación a la información que me solicita Juana, secc. ecca. CTAEX; necesitamos saber si el hermano de Isabel reside en la vivienda y en caso negativo, si se pondrían dar de baja los suministros. *NO obtengo respuesta. Volveré a intentarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-04-16','Ana: Llamo al C.R. Cervantes (927 005 570), dado que con Minerva no consigo hablar, pido que me pasen con Ana, Directora, quien tampoco está en ese momento. *Dejarán una nota a Minerva. ······················· Más tarde recibo llamada de Minerva, TS del C.R. Cervantes (927 005 575 // 22237): *De nuevo las renovaciones de la demanda de empleo las han puesto automáticas hasta el 30 de abril. *Le comunico la nueva asignación de Guillermo, acordo a lo que habían solictado. ············· **Me comunica que se ha incorporado una compañera nueva, que llevará a Guillermo: Toni, TS (927 66 30 10 // 22270). *Estará pendientes de la renovación de la demanda de empleo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-04-16','Ana: Conversación con Minerva, TS del CR Cervantes (927 005 575): El miércoles acudirá virgina, Ed. Futuex a visitar a Mª Luisa (retoma el segumiento tras su baja) y le acompañará a pedir presupuesto para la ropa que necesita. *Minerva le entregará a Virgina un listado con las prendas necesarias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-04-16','Ana: Conversación con Minerva, TS del C.R. Cervantes (927 005 575 // 22237): Me comunica que se ha incorporado una compañera nueva, que llevará a Eugenia: Toni, TS (927 66 30 10 // 22270). *Al parecer Eugina pensaba que el traslado a la Res. San Francisco de Plasencia sería inminente una vez solicitado, y ahora está un poco deprimida. Abordarán esta cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-16','miguel, recibo email de Damian: Muy señor nuestro le envio las fotos de los documentos en los que me deniegan por cuarta vez el grado de dependencia.un saludo Atentamente.damian salvador granados heredia DNI 53692319 letra s ********************************************** descargo dicha documentación en su carpeta virtual personal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-04-19','Ana: Conversación con Soni Bernavé - Asindi (669 602 920): Felisa está adaptándose, poco a poco va a mejor, en las últimas semanas se muestra más tranquila y alegre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2021-04-19','miguel, contesto a Juana y a Alberto en relación al borrador preparado con Juana y que me remitió el 14-4-2021 en relación a la contraoferta de este Curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-19','Ana: Llamada de José Manuel (627 788 797), dice que ayer cogió un cargador de móvil que no era suyo, cuando se lo reclamó su sueño, le dió un "guantazo a uno"... *Hablamos de lo inadecuado de su comportamiento. *Beatriz, directora, va a hablar con el SEPAD al repecto. Expresa tener mucha ansiedad y que se quiere ir a su casa, que no aguanta más en el centro. *Intento hacerle entrar en razón, pues no lleva ni una semana, está en periodo de adaptación y el aislamiento inicial no es fácil. ····························································································································································································································································· Conversación con Beatriz, Coordinadora del CRR, ya ha hablado con Mariluz, Jefa de Secc. de Salud Mental, en relación al incidente de José Manuel con el otro residente. Mariluz le ha dicho que le dan otra oportunidad por estar en el periodo de prueba, pero que a la próxima tendrá que abandonar el recurso. ·························································································································································· En cuanto al periodo de aislamiento, Beatriz dice que están siendo "súper flexibles" con él al respecto. Sale a pasear con algún monitor, le dejan salir a un patio a fumar, a sentarse en un banco que hay en frente del centro en la misma C/ Menacho. *Opina que José Manuel no puede estar sólo, de hecho él le ha pedido el alta voluntaria, y en principo ella le ha dicho que no se lo va a dar. *Por parte de la CTAEX, tampoco apoyamos el alta voluntaria. **Pero cree que José Manuel estaría mejor en una Ud. especializada, como las que tienen las Hermanas Hospitalarias en otras comunidades, en Extremadura no existe tal recurso. ··························································································································································································································································· Conversación con Pilar Martín, TS ESM-CC (54612): también ha hablado con José Manuel, éste no deja de insistir en que se le cambie la medicación. Le ha dicho lo mismo que yo al respecto, que hasta que no tenga cita con el Psiquiatra debe mantener la medicación pautada. *Le informo de lo hablado con Beatriz, Coordinadora del CRR-Ba. **Tanto la Psiquiatra como la Coordinadora del ESM, le han dicho, que como José Manuel abandone el CRR, si vuelve a las andadas, se le derivará a la Ud. de Crónicos del CSS-Plas.··············· Mantendremos las 3 el mismo discuros, No al alta voluntaria, la única opción alternativa al centro es la Ud. de Crónicos, y en cuanto ala medicación debe esperar a la cita con el Pisquiatra. ························································································································································································································································ Envío correo a Beatriz (bgonzalez.sanmiguel@hospitalarias.es): "Hola Beatriz, Ya se lo he comunicado a las compañeras de las Secc. Ecca. Por otra parte, ¿podríais por favor, enviarme un Certificado de Ingreso en Centro relativo a José Manuel? Lo necesitan mis compañeros jurídicos para comunicar al Juzgado que José Manuel ya ha accedido al recurso que tenía solicitado. Por cierto, he hablado también con Pilar Martín, Trabajadora Social del Equipo de Salud Mental de Cáceres, José Manuel también le ha llamado a ella. NO le ha dicho nada del incidente con el otro residente, pero sí con respecto a la medicación, que quiere que se la cambien. Pilar le ha dicho lo mismo que le dije yo el otro día, que hasta que no tenga cita en Psiquiatría la medicación que se le administrará será la pautada. Te lo comento para mantener todas el mismo discurso (que hasta ahora así ha sido), al igual que con su planteamiento de Alta Voluntaria. Por último comentarte que tanto la Psiquiatra que tenía en Cáceres como la Coordinadora del ESM, le han dicho a Pilar, que como José Manuel tenga que abandonar el C RR, la única alternativa posible sería la Unidad de Crónicos en el C. Sociosanitario de Plasencia (dónde él tampoco quiere ir), por si te vuelve a comentar algo y se lo quieres decir. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2021-04-19','Condenan a José María (Ejecutoria 146-21, seguida en el Juzgado de lo Penal 1, de Plasencia), al pago de una indemnización de 2355 euros, más 20 meses de internamiento en centro adecuado a su patología.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-04-19','TEREA RECIBO LLAMADA DE M CARMEN MADRE DE NATALIA (666898994) ME LLAMA PARA INTERESARSE POR LAS SALIDAS DE NATALIA COMENTA QUE YA NO TIENE RELACION CON LA FAMILIA PATERERNA Y QUE SOLO VA A CASA DE SU ABUELO MATERNO COMENTA QUE EL ABUELO ESTA MUY MAYOR Y QUE ELLA QUIERE QUE NATALIA VAYA A SU CASA, SOLICITA UNA REUNION EN EL SEPAD PARA ESTABLECER VISITIAS Y QUE SE QUEDE A DOMIR EN EL DOMICILIO DE SU MADRE LE COMENTO QUE ACTUALEMENTE LAS VISITAS ESTAN RESTRINGIDAS POR LA PANDEMIA, EN EL MOMENTO QUE SE PLANTEE UNA SALIDA LO VALORAREMOS Y NOS PONDREMOS EN CONTACTO CON ELLA SE ESTÁ TRAMITANDO TRASLADO DE CENTRO POR LOS PROBLEMAS DE CONDUCTA DE NATALIA EN EL CENTRO Y POR LA MALA INFLUENCIA QUE HA EJERCICICO LA MADRE SOBRE ELLA POR ELLO SE HA SOLICITADO LA ZONA DE CACERES PARA QUE ESTE LEJOS DE LA MADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-04-19','Ana: Una vez recibiio el informe de salud firmado/sellado, pongo para REGISTRO DE ENTRADA, la solicitud de Valoración de Dependencia, junto con toda la documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-04-19','Ana: Llamada de Sonia Bernavé - Asindi (669 602 920): El viernes le dieron el alta a Aarón y regresó al centro. Ahora está más o menos tranquilo, además al estar en aislamiento, en esta semana no tendrá contacto casi con nadie. **Su padre, Julio, le ha llamado, porque quiere tramitar el bono de la luz, pide fotocopia del DNI y Certificado de Discapadidad del CADEX. *Consultaré a Miguel, Asesor Jurídico, pues él está empadronado y residiendo en el centro de Asindi. ······························································································································································································· Envío correo a Sonia (trabajosocial@asindi.e.telefonica.net): "Buenos días de nuevo Sonia, Miguel, Asesor Jurídico, entiende que lo que solicitan al padre de Aarón para el Bono Social, son los datos de la Unidad de convivencia, y Aarón, al estar residiendo y empadronado en vuestro centro, ya no forma parte de la unidad de convivencia, por tanto, a estos efectos no se le puede facilitar la documentación que os solicita. Ante cualquier otra cuestión, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2021-04-19','miguel, llega por registro de entrada documentación requerida por el Colegio de Abogados de Badajoz: remito email a Angel para que me indique cómo hacerme de toda la documentación ya que alguna la tenemos en el expediente pero el resto no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-04-13','Ana: Correo de Paula, TO- CCR-Plas. (tocupacional.crrplasencia@grupo5.net): "Flora Gutiérrez: por fin se pueden llevar las cenizas de su madre al cementerio de su pueblo de origen en Badajoz. Un profesional la acompañará para realizarlo, junto con el operario de la funeraria. Además, al ser un pueblo cercano a Badajoz y la acompañaremos para que pase por su casa a recoger alguna cosilla que necesitaba."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2021-04-13','Ana: Correo de Paula, TO- CCR-Plas. (tocupacional.crrplasencia@grupo5.net): "M.ª Angeles Santos: gracias a las actuales medidas en residencias (ella está vacunada) podría, por fin, realizar una salida planificada a la casa de su padre de un fin de semana (irse el viernes 23 de Abril y volver el lunes 26 del mismo mes). En la residencia hemos trabajado las medidas de prevención del covid y se llevaría mascarillas y gel para poder seguirlas aún en el domicilio. En esta situación no necesita realizarse PCR. Vamos a contactar con el padre para ver esas fechas serían posibles."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-19','miguel, remito email a la abogada Rocío Gracian adjuntando los movimientos bancarios (junto con los recibos de alquiler abonados) y su provisión de fondos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-19','-Amalia : El dia 21 ingresa en el CAMP de D.Benito , ira en taxi acompañado de D. Tutelar . La 1ª dosis de la vacuna ya se la han puesto , la 2ª ya en D. Benito , se comunica a TS del CEntro ( Antonia Escobar ) Se le ha pedido complemento de Orfandad Absoluta desde el SSASB , pendiente de resolución. Hay dos copias de las llaves de la casa , una se la llevará el y otra se queda en el SSASB . Irá la auxiliar SAD a cerrar y quedar todo los suministros apagados . El Centro de dia se paga 50€ al mes y este mes ya se ha abonado. Al estanco se le pagarán 80€ de este mes y se llevarán el tabaco restante. Hoy se le hace PCR , pero se obliga a 7 dias de aislamiento en el centro para todos los ingresos nuevos. Quedo pendiente enviar documentación de J. Carlos al CAMP .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-04-16','Ana: Correo de Alfredo Cebrián, Res. de Plasenzuela (resiplase@gmail.com): "Buenos días, Ana. Te informo que se va a derivar a urgencias a Antonia Serrano Suárez, debido a que tiene úlceras de tipo vascular en talón y empeine del pie derecho (estas ulceras vino con ellas del hospital la última vez que estuvo ingresada). Según la enfermera las úlceras están necrosadas y por eso se la deriva a urgencias para que valore cirugía vascular. Te iré informando de su evolución. Un saludo. Alfredo Moreno."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2021-04-19','Ana: Correo de Alfredo Moreno Cebrián, Res. de Plasenzuela (resiplase@gmail.com) el viernes a las 22:50h: "Buenas noches, Ana. Me acaban de llamar del hospital universitario de Caceres para preguntar por algún familiar o tutor de Antonia Serrano, porque van a tener que proceder a la amputación del pie. Les he dicho que está tutelada por la Comisión Tutelar, supongo que intentarán ponerse en contacto con vosotros. De todos modos si quieres contactar con ellos llama tu al hospital universitario de Caceres, nosotros la hemos dejado está mañana en urgencias, pero supongo que ya estará en planta. Un saludo. Alfredo." ······································································································································································································· Nuevo correo de Alfredo el sábado: "Buenos días, Ana. Es urgente que os pongais en contacto con el Hospital Universitario de Cáceres. Gracias." ······························································································································································································ Conversación con Alfredo hoy (619 45 92 81): A Antonia le han tenido que amputar de urgencias el pie derecho. Finalmente lo hicieron sin la autorización de la CTAEX (Al ser una Tutela administrativa, los fines de semana no hay nadie disponible). *Piden desde la Residencia una autorización general, para que puedan actuar como Guardadores de Hecho en este tipo de situaciones de Urgencia en Ausencia de la CTAEX (por festivos y fines de semana) ······················ consulto a Miguel, Asesor Jurídico CTAEX, lo hablará con Ángel, compañero, y me darán una respusta. ································································································································································································ Envío correo-e a Alfredo: "...*En cuanto a la Autorización General que nos solicitáis, mis compañeros Jurídicos exponen que desde la CTAEX no puede otorgarse Consentimientos Generales para cuestiones médicas. Es más, en intervenciones médicas, en que existe controversia entre distintos especialistas médicos (por ejemplo, Cirujano y Anestesista), desde la CTAEX se comunica al Juzgado que es quién debe tomar en estos casos la decisión. En la cuestión que tú planteas, dado que se tratan de Tutelas Administrativas (el personal no está disponible fines de semana y festivos) son los médicos quienes deben tomar la decisión, cuando se trata de situaciones graves o extremas y de carácter inmediato. ..."','2');
