insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-04-19','-Amalia : hablo por tf con ESperanza , TS del ESM de Mérida .Ildefonso no ha pasado por el equipo , no hay nada en su expediente . Por Jara puede leer que el día 7/04/2021 acudió a las urgencias del Hospital de Mérida , solicitando ingreso en CSS . Pero no consintió en hacerse las analíticas que establece el protocolo , ni el control de tóxicos. Rompe el cristal de admisión y se marcha de allí corriendo . El dia 14 de abril ha vuelto a acudir por malestar general .No sabemos dónde se está quedando . No coge el tf. -Pregunto a los jurídicos si han enviado ya el informe a Juzgados .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-04-19','-Amalia : Hablo con la TS del ESM de Mérida , Jonathan no ha acudido por allí ni hay expediente suyo . -Pregunto a los jurídicos si han enviado el informe al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-19','-email de Carmen Diaz ( TS de ESM Valdepasillas ) Buenas tardes Amalia, no te contesté a los correos porque intenté llamarte. Lo que plantea Sroraya, de alguna comunidad terapéutica de drogodependencia, ya me dijo, desde el principio, Obdulia que no lo veía por la vulnerabilidad que tiene y el perfil de estas comunidades. Amalia de todas maneras te lo envío. Un abrazo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-19','emails de Damian: Para que le diga al juez queacabo de perder un paquetito de plastico con 130 euros estaba andando medio dormido llame a los monitotes para comentarle el problema pierdo el dinero hasido ahora mismo ******************************************************** Doy fe señor miguel y que hable mañana con itziar super importante se han ofrecido los voluntarios a acompañarme y se han portado muy bien pero yo por ser mas autonomo fui con 130euros para cambiarle la pantalla al telefono lo llebaba en un plastico liado y cuando llevaba un rato andando perdi los 130 doy fe y usted como abogado le comento que he perdido el dinero integro y ese dimero se ha cogido de los extras ya de abril yo le pido ayuda para poder coger mas dinero porque la medicacion tambien me deja muy dormido y poerdo la memoria itziar es muy buena pero muy recta.ahora no se si tiene potestad para que antes que por la mañana itziar decirle que doy fe que el dinero lo he perdido se lo comenta tambien a ana matamoros y que le diga esto es privado que no tengo capacidad de que no es la primera vez la cartera o las llaves de la taquilla pero al final lo encuentro me he puesto muy nervioso y llame al centro y me dijo que no llamara tanto por telefono y valla para la residencia tire el bolso y saque todo lo que habia dentro me puse nervioso y ya me dieron los nervios y perdi la cartera mis compañeros pendientes a mi y me dicen damian que has perdido la cartera fue todo seguido al final la compañera como me puse tan nervioso antes de perder ñs cartera me dice un compañero damian que te dejas el carnet de identidad en el banco.ya me puse nervioso y no dabaas de si me busque por la mochilita de mano el telefono dije he perdido lacartera comentele a itziar que los profesionales se portaron muy bien conmigo y he mantenido el comtrol de gritar chillar menos cuando llame 5 veces al centro ahi me puse atacado menos.doy fe que mis compañeros no me lo han quitado me hsn ayudado en todo momento y con el cariño que me dio mi compañero me relaje y para olvidarme de los problemas nos tomsmod un cafe tranquilito a tomar un cafe y conchi la monitora me dijo que no deberia de ir a tomar cafe pero yo necesitaba relajarme y no salir nervioso corriendo hacia la residencia alterado y llamando la atencion reflexione y pido que como hay 13500 euros y he perdido del segundo semestre 250 se han cogido 130 tras que me lo entrega la monitora y doy fe que se perdio en el camino .importante el posi que me escribio la monitora con la direccion del centro para hacerme factura a mi nombre para entregar ese gasto de 130 euros para cambiar la pantalla digale que como he perdido el dinero inocebtemente porque llevo un bolsito grande de piel y tiene muchos broches y cada vez con los nervios al tirar todo en latienda y despues en la calle porque eso queda entre usted y yo compre a la tirnfa para comprar un bote de cafe que lo uso en mi cuarto para ponerme mas despierto como vacie el bolso en la tienda y no encontre el dinero cuando me doy cuenta al ir a pagar el cafe me di cuenta que habia perdido el dinero me tiro al suelo habro todos los broches lo saco todo y en ese momento me di cuenta que habia perdido el plastiquito donde dentro doy fe habia 130 euros porque yo se que tras salir del centro cogi el dinero subi por la sudadera y ya me fui de la tienda me sente en un banco y abri todos los bolsillos del bolsito tiro todo al suelo me dejo carnet de identidad en el banco que el compañero me dijo damian te dejas el carnet en el banco.banco de sentarse de madera no banco de sucursal bancario donde uno se sienta y esta en lugar publico y cuando recojo todo y seguimos hablando e hize 5 llamadas al centro y me dijeron que me subiera al centro yo no hago caso ya que conchi la monitora me dijo que me fuera para la residencia no hize caso porque necesitaba quitarme la negatividad y fui como 10 minutos a tomarnos un cafe me despeje hable con mi prima y no me podia atender he quedado con mi prima mandarle mendajes solo los dias 1 y 15 y le dije perdona he tenido este problema y ya colgue y le dije perdona cogimos nos venimos al centro y buscamos por mi cuarto por todo la habitacion doy fe que el dinero no me lo deje en la habitacion porque el dinero lo cogi a las 5 y cuarto que me dio el dinero en un plastiquito y subi para arriba porque hacia un poco de fresco en la calle para coger yo una sudadera la cogi corriendo y doy fe que yo en ningun momento el paquetito con el dinero no lo deje en la habitacion lo llevaba en el bolsito y doy fe que la tendera busco y yo busque el dinero al haber abierto el bolso y cogi el dinero para pagar el cafe en ese mismo momento me doy cuenta que he perdido los 130 euros y lo buscamos primero en la tienda y despues en la calle y doy fe que fue una perdida pero no sabemos si fue en el trsyecto hasta la tienda o en ls tienda lo perdi mis compañeros hizieron hasta el puente verde el csmino s la inversa a ver si se me habia caido al suelo y tampoco hay dinero Yo a conchi la monitotora no le he dicho que entre en la tienda porque no le podiia decir que habia comprado un paquete de cafe ya que esta prohibido meter enseres de comida al centro.otro problema he leido y se lo he dicho a alicia que he recibido un mensaje del inquilino amenazandome que yo como propietario y dice que tiene papeles para confirmar que me dio dinero he llamado a alicia y le he mandado el mensaje al imquilino.el inquilino en una de las amenazas dice que si yo no firmo la resdincion por termino de contrato y firmo en el ayuntamiento el no se va del piso por el motivo que el inquilino poensa y me dice en amenaza que si yo no firmo las resdicion del contrato el no se va el 1 de agosto y pide papeles que el tiene pone que me dejo dinero y si no le pago el dinero me amenaza y no se va del piso.muy importante transmitirle el tema de los 130 euros y que si se pueden coger otros 130 porque ha sido un acto de buena fe e involuntario que he perdido el dinero y no he gastado ni un duro en ninguna parte.','2');
