insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-20','llega email de Damian: Buenos dias don miguel hoy del susto y los monitores me han dado sabanas limpias se portan todos el equipotecnico muy bien conmigoy los monitores.anoche me hize pis en lacama de los nervios y una pena que se mejayan perdido130 euros para comprar pantalla del movil mi concienciatranquila porque no he dicho ningun engaño lo que si es verdad que los7meses cuando vivia en caritas me orinaba todos losdias mañana tengocita con latrabajadoraso social a las 10 de la mañana ya me estan damdo el protector de estomago que me lo den porla mañana en cuanto pueda me llama el inquilino me ha amenazado','2');
