insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-04-20','Ana: Llamo a la Res. Puente Real San Vicente de Alcántara (924 41 08 35), hablo con Ángeles ("Vere"), Directora de la Res. Hoy ha salido de Aislamiento, los primero días los ha pasado bien, tranquilo, le pusieron una TV en su cuarto. Es repetitivo,debido a su patología, pero todo bien. *Su hija ya ha llamado para comunicar que acudirá a visitarle. *En cuanto al contrato, lo ha firmado él. Le comunico que debe firmarlo el Representante Legal. Me lo enviará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-04-20','Ana: Según la Sentencia de Incapacitación: "...D. Javier mantiene su autonomía personal o aptitud para realizar por si solo funciones de nutrición, aseo, cuidado personal, etc, pero ello no con carácter absoluto, requiriendo para las mismas la supervisión y el apoyo de terceras personas. Así como que carece totalmente de capacidad para la administración de sus bienes y para tomar decisión alguna de contenido económico, ello con la excepción de la facultad que mantiene de poder manejar cantidades de bolsillo, con un máximo de doscientos euros al mes. Y que carece totalmente de capacidad para su autogobierno en el ámbito de la salud." FALLO: "...DEBO DECLARAR y DECLARO, con todos los efectos procedentes en derecho, que D. Javier Agudo Cumplido tiene totalmente anulada su capacidad para los actos y competencias que se relacionan en el Fundamento Jurídico SEGUNDO de la presente resolución, al que expresamente me remito, preservándose la autonomía y capacidad de D. Javier Agudo Cumplido para las habilidades y competencias que igualmente se describen y relacionan en el Fundamento Jurídico SEGUNDO"','2');
