insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-04-21','Ana: Llamo al ESM-Trujillo (927 32 07 69), me comunican que Cristina, TS, no está hoy, acude martes y jueves (volveré a llamarla mañana). ·························································································································································································· Envío FAX al ESM (927 32 21 56) a la att. del Dr. Medina, Psiquiatra y Médico Coordinador, solicitando nos comuniquen fecha de la última consulta a la que asistió, citas más recientes a las que no ha acudido e informe de la última consulta. *Se adjunta documentación pertinente.','2');
