insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-21','email de Damian: Buenos dias don miguel ayer estuve en urgencias por ataque de ansiedad ahora le mando por correo escaneado el informe para presentarselo al juez no se si este es su correo electronico conformeme si le ha llegado. *************************************************** Hago nuevo poder apud acta en Juzgado a favor de juzgados de Málaga y envío por email a Rocio la abogada y por carta el original','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-04-21','Ana: Devuelven de registro la Solicitud de Valoración de Dependencia REGISTRADA DE ENTRADA a fecha de 20/04/21. ················· Se lo reenvío escaneado a Estrella, TS del CSS-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-21','miguel, me llama el abuelo de Alejandro Pedro Gomez Mena tlfno 650-632836 ( el de su mujer 606-817-819) Me pregunta por el dinero objeto de disputa con sus hermanas, le explico que la resolución que nos mandó no indica que fuera una donación, y que no hay por escrito que así lo indique y que al no haber testamento por ley el dinero si lo demostrara la otra parte sería de los tres hermanos. Que el viernes le llamaré con el resultado de la reunión con el abogado de la otra parte Carlos Lena Jurado y que en caso de que demuestren que el dinero es de los 3 nuestra posición sería hablar con ellos (curatelado) para decidir si llegar a un acuerdo o ir a juicio (el abogado sería de pago ya que no tiene derecho a abogado de oficio). Habla durante 40 minutos desahogandose de lo duro que es la situación y que el curatelado no pone de su parte, que todo son exigencias, que a la hija no le llega con el dinero y que no debemos retenerle la paga (las extras) porque no les llega. Que él quería para su nieto un piso (no para su hija que vivirá con una amiga), pero que tras este nuevo varapalo que a ver si Amalia consigue un sitio (una vivienda) donde pueda vivir su nieto. Quedo en hablar con Amalia y él el viernes con el resultado de la reunión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-21','Ana: Llamo a Raquel, TS SSASB Valverde de la Vera (667 068 078), le expongo lo tratado con Soraya Masa. Acordamos que le enviaré un correo electrónico especificando los pasos a seguir. *Me comunica que mañana tienen cita con Virgina-Futuex (en base a la derivación al programa). ································································································································································································· Llamo al Consultorio Local de Valverde de la Vera (927 567 270), hablo con la Médica, Raylin Pinales, no conoce a la paciente, hablará con la enfermera y mirará en el expte. Acordamos que mañana, cuando Virginia-Futuex, se reúna con Raquel, TS del SSASB, se pongan en contacto con ella e incluso que pasen por el consultorio a hablar con ella. ····· A parte de esto, le explico la situación y solicito las dos cuestiones: 1- Elaboración de Informe de Salud para la Valoración de Dependencia. 2- La necesidad de activación por su parte del 112 para Internamiento Involuntario en la UHB para valoración, diagnóstico y en su caso, estabilización clínica. Raylin se muestra colaboradora. ···························································································································································································· Vuelvo a llamar a Raquel, TS, el consultorio está al lado de su despacho en Valverde de la Vera, mañana se pasará por allí con Virginia y llevará el modelo de Informe de Salud impreso, por si acaso. ·········· Envío correo a Raquel (ssasbrpa@gmail.com): "Buenas tardes ya, Raquel, De acuerdo a la conversación telefónica mantenida hoy, paso a redactar los distintos pasos a dar en la intervención con Florencia Dávila García, tutelada por la Comisión Tutelar de Adultos, 1- Dada las negativa desde la Unidad de Programas Asistenciales del SEPAD de acceso directo a Centro Sociosanitario, por la avanzada edad de Florencia, debemos solicitar plaza de Mayores en Centro Residencia, a través de la Dependencia. Como no está valorada: a. Cumplimentar Modelo de Solicitud de Valoración de Dependencia (cumplimentaremos entre las dos el modelo, como hemos acordado, cuando puedas me envías lo que tengas y yo completo lo que falte, lo pongo para la firma del Representante Legal y lo registro de Entrada junto con la documentación pertinente) b. En la solicitud marcaremos la opción de plaza residencial para mayores c. Necesitamos Informe de Salud, cuestión que ya le he comunicado a la Médica de Atención Primaria Raylin Pinales. (Como mañana os reuniréis con ella, supongo que no habrá problemas. Ante cualquier cuestión no dudéis en llamarme) 2- Puesto que con el Dictamen Técnico del CADEX de Florencia, el diagnóstico es el de “Alteraciones de la conducta por Trastorno Obsesivo-compulsivo”, no le van a conceder a priori plaza residencial para Mayores, es necesario que la valoren y diagnostiquen en el Servicio de Psiquiatría. **Ya he comunicado la Dra. Pinales, que será necesario que active el 112 para ingreso involuntario en la UHB, con objeto de valoración, diagnóstico, estabilización clínica, en su caso y pauta de tratamiento médico. Seguimos en contacto y ante cualquier cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-04-21','miguel, remito por carta certificada al jzdo nº2 de Mérida informe de Amalia indicando la imposibilidad para ejercer la función de curador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-15','Ana: Conversación con Soraya Masa, Jefa de Ud.PP.AA.; considera que dada la edad de Florencia (79 años), no se le puede ingresar directamente en un CSS. Entiende que tendrá que acceder a Centro de Mayores. **Indico que en Mayores, tampoco la van a aceptar debido a las alteraciones de conducta que presenta según Dictamen Técnico y e informes del expte. **Habrá que solicitar ingreso en la UHB para valoración y diagnóstico. Una vez esté estable tendrían que aceptarla en recurso de mayores.','2');
