insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-04-21','TERESA LLAMO A LOLA TS PLENA INCLUSION 690 04 14 05 PARA PREGUNTAR POR LA LLEGADA DE ADNRE/PAULA ME COMENTA QUE ESTA BIEN CONTENTO Y TRANQUILO A LA UNA LO LLAMO TAL Y COMO HEMOS ACORADO QUIERE QUE ME DIRIJA COMO PAULA, ME PREGUNTA QUIEN SOY Y QUE NO SE QUIERE IR A LA UUHDAC SE MUESTRA PARCO EN PALABRAS Y ME CUETA MUCHO ENTENDER LO QUE ME DICE PORQUE HABLA CON MUCHA DIFICULTAD LE PREGUNTO QUE HA ESTADO HACIENDO Y ME DICE COSAS SUELTAS ME PIDE QUE QUIERE COMPRAR ROPA FEMENINA Y PINTURAS Y QUE CUANDO VOY A IR A VERLA REFIERE QUE TIENE UN DOLOR EN EL PECHO COMO ES LA HORA DE COMER ME DESPIDO Y ME PREGUNTA QUE CUANDO LE VOY A LLAMAR DE NUEVO. TRAS LA CONVERSAICON VUELVO A LLAMAR A LOLA Y LE COMENTO LA CONVERASACION Y SE QUEDA EXTRAÑADA. MAS TARDE ME LLAMA LOLA Y ME COMENTA QUE HA HECHO EL PARIPE PARA HABLAR CONMIGO QUE LUEGO HA ESTADO HABLANDO PERFECTAMENTE LA PROXIMA LLAMADA LA REALIZAREMOS EL LUNES TAL Y COMO ESTRA PROGRAMADA EN EL PLAN','2');
