insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CORONADA'and edp.apellido1='GORDILLO'and apellido2='MONROY'),'2021-04-22','EXPTE. CERRADO por desestimación de la demanda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-12','-Amalia : email que envio a Soraya y Carmen Diaz , TS de ESM Valdepasillas .De: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Enviado: lunes, 12 de abril de 2021 11:02 Para: Soraya Masa Moreno >soraya.masa@salud-juntaex.es> Cc: CARMEN INMACULADA DIAZ MURILLO >carmen.diaz@salud-juntaex.es> Asunto: COMISIÓN TUTELAR Buenos días Soraya , se ha planteado una subcomisión de casos desde el ESM de Valdepasillas ( Badajoz ) para ALEJANDRO NÚÑEZ BONO , curatelado por la Comisión Tutelar . Tiene un 63% G.Discapacidad por Inteligencia Límite, Trastorno del desarrollo y alteración de conducta. Adjunto resolución denegatoria del CADEX para acceso a plaza RAL por consumo activo de drogas, que solicitó en 2018 la Dirección General de Política Social , Infancia y Familia . Presenta un " sin grado " en valoración de depencia. Fue tutelado por menores y estuvo residiendo en los pisos tutelados que gestiona HOFA. Las últimas incidencias acaecidas en su domicilio familiar , donde reside con su madre , han motivado a la solicitud de una subcomisión de salud mental donde podamos estar representantes de todos los recursos implicados para orientar una intervención. Sigue consumiendo marihuana , se ha conseguido que acuda a las citas del CEDEX acompañado de delegada tutelar pero con reticencias constantes. Con seguimiento desde ESM con escasa adherencia a tratamiento . Muy agresivo verbal y físicamente con su madre y abuelos , se ha llegado a avisar a la policía en varias ocasiones . Me pongo en contacto contigo a petición de Carmen Díaz , TS del ESM, para que si se estima oportuno pueda estar presente en esta subcomisión , que se hará por videoconferencia , algún representante del CADEX o de la Sección de discapacidad. Se ha puesto en contacto con la Dtra. CADEX que le informa que tiene que ser a través de una derivación de esa Unidad. Se ha solicitado presencia de psiquiatra, TS ESM , CEDEX , UHDAC , CTAEX , delegada FUTUEX y CADEX .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-22','Amalia : -No es posible ingreso en CADEX , hay solicitud denegatoria de perfil ( en su expediente ) por el consumo de drogas. -No ha dado grado de dependencia . -Obdulia de ECAS Valdepasilla no lo ve perfil de C. Terapeutica por su vulnerabilidad ( le pediré informe por escrito ) - La única opcion en UHDAC , pendiente de derivacion por su psiquiatra ( Pablo ) . -Con la respuesta última informaré al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMPARO'and edp.apellido1='ORTEGA'and apellido2='GALAN'),'2021-04-22','EXPTE. CERRADO. Se nombra tutor a su sobrina, Dña. Concepción Ortega Salgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-22','llega email de Damian: Buenos dias don miguel le queria preguntar si le ha llegado escaneado el informe de urgencia de siquiatria para enseñarselo al juez.gracias mandeme correo de confirmacion yo a la comision le he mandado otro.gracias buen dia ************************************************** Mi contestación:Buenos días Damian están llegando todos sus emails incluido dicho informe. Comentarle que la abogada tiene todo (incluido el poder del procurador) para poder interponer el procedimiento de desahucio del inquilino)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2021-04-22','En relación con el juicio sobre delitos leves nº 36/2021, seguido en el Juzgado de Primera Instancia e Instrucción, nº 2, de Villanueva de la Serena, celebrado el día 20/4, se ha dictado sentencia absolutoria. Nos la envían por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-04-22','Ana: Solicito, mediante email, al CADEX-CC, nos confirmen si Valentina está valorada de Discapacidad. ······························································································································································································· Cumplimento y pido que pongan para la firma del D-Gerente, la solicitud de Prestación Familiar por Hijo a Cargo (Modelo personas jurídicas).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-12','Ana: Recibo correo de Toni-Futuex, con nota de visita a Clementa el día 08/04/21: "Se realiza visita de seguimiento en casa de Pilar, hija de la tutelada, situada en la Avenida Alfonso Díaz Bustamente nº 18 1ºB, para transmitirles las decisiones y las medidas a tomar por el área económica de la comisión tutelar de adultos, en el domicilio se encuentra Clementa, Pilar y el marido de esta, Roberto. Se les transmite por tanto que e procederá al bloqueo de la cuenta y la cancelación de la tarjeta, y s preciso realizar un presupuesto de gastos de bolsillo y manutención para sufragar los gastos que su madre esta generando en la vivienda. Resulta complicado llegar a un acuerdo con respecto a las cantidades necesarias para la manutención de Clementa dado que según relatan genera mucho gasto porque es muy delicada para comer y los productos que consume tienen un precio elevado, explican también que le han adelantado en torno a 1000 o 15000 euros desde el pasado mes de enero que está residiendo con ellos, pero no disponen de facturas, tickets o similares que se puedan aportar a este informe. ..." A continuación detallan desglose de gastos y propuesta que hace la hija de presupuesto para aportar como manutención y gasto de bolsillo (Total 500 €) A parte se detalla gasto de hipoteca y deudas en Iberdrola, Comunidad, Seguro de Decesos... ·················· *Reenvío correo a Alberto, Jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-04-22','TERESA Os informamos de una incidencia ocurrida con fecha 21 de abril de este año en la que vuestro tutelado A.S.B. no ha mantenido la distancia de seguridad que le había sido explicada con anterioridad, y ha mantenido un contacto estrecho con E.G.G. mediante besos en la boca. Destacamos la importancia de este incidente no sólo por la posibilidad de contagio por covid-19 sino porque EGG es portador de un virus contagioso con el consiguiente riesgo para la salud de ASB. Añadir además, que EGG tiene una patología asociada de psoriasis y de diabetes que hace que tenga la piel con algunas heridas, con el riesgo de contagio que esto supone. Tras esta información solicitamos orientación sobre las medidas a adoptar con dos de vuestros tutelados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-04-23','-Amalia . Adjunto email de la TS del ESM según lo acordado. Buenas tardes Amalia, OK, esta mañana me ha llamado María Paz y ella tb, ha llegado a la conclusión nuestra, hacemos una derivación a la UHDAC y que valoren, y si no están deacuerdo, entonces planteamos una subcomisión de casos. buena tarde','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-23','-Email de Futuex : Pertenencias que se entregan en centro: - Un juego de llaves de la vivienda de Juan Carlos ubicada en C/constitución, 13. (El otro juego de llaves lo tienen en el Ayto. de Guadiana, Inmaculada la TS). - 25€ que tenía Carlos de los 50€ que le dejó su hermano en el funeral de su madre. Este dinero se lo gestionan en el centro para gastos de bolsillo. - 5 paquetes de tabaco también gestionados por el centro. - Móvil y cargador más libreta con números de contacto. - Medicación y hoja de tratamiento. - Cartilla vacunación Covid19. Le falta la 2ª dosis que se la gestionarán desde centro. - DNI y tarjeta sanitaria. Por otro lado, la documentación importante que tenía Carlos en su vivienda la tenemos el equipo de apoyo social comunitario para hacerla llegar a la Comisión tutelar de adultos de Extremadura. Además, reflejar la incidencia producida ayer en el momento en que recogemos a Juan Carlos en su domicilio. Tras recoger la medicación en el centro de día y el tabaco para el mes de Abril, al llegar a su casa nos encontramos a un señor con la televisión llevándosela a su coche. Este, es Manolo primo de Juan Carlos residente en Pueblonuevo. A pesar de indicarle que Juan Carlos está tutelado por la comisión tutelar de adultos de Extremadura y no puede llevarse las pertenencias del mismo, hace oídos sordos y se la lleva excusándose que si se necesita la devuelve. Asimismo, nos comenta Soledad auxiliar de ayuda a domicilio, que el pasado domingo, el mismo primo de Juan Carlos se llevó de la vivienda el frigorífico. Por lo que hemos podido averiguar ha sido Javier hermano de Juan Carlos quien ha indicado a su primo Manolo que puede llevarse de la vivienda lo que necesite, en este caso la TV y el frigorífico. Indicamos el teléfono de contacto de Manolo primo de Juan Carlos: 647 885 840 En el centro nos indican que en las habitaciones no hay televisión que si quiere el residente es quien la tiene que llevar por ello Juan Carlos llama a su hermano para que su primo le lleve la TV pero no sabemos muy bien cómo va a proceder su hermano ante esta situación. Por último, adjuntamos la factura correspondiente al traslado y número de cuenta para proceder al pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2021-04-23','- Amalia : pido opinión a Futuex para hacer la obra del patio que solicitan desde el SSASB . Tengo el pto. en el email. Con la respuesta se lo pasaré a sección eco y juridica pq supera los 3000€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-23','llegan varios emails de Damian: El inquilino me dijo de muy mala manera que le devuelva y eso fue un dinero que no me acuerdo cuanto es ese dinero el dice que en cuanto le de los 1700 euros le debe me amenazo diciendo que el tiene tambien en mano a su favor e importante dice que si yo no firmo la resdicion del cotrato osea para echarlo sin mi firma el se puede quedar un año mas el se va pero quiere dinero fue un mensaje de voz que me dio un poco de miedo******************************* Buenas noches don miguel fui por la mañana a pedir el protector de estomago me abrio la puerta el monitor y me dijo ahora te lo doy ven un poco mas tarde y eso fue a las 8 y media de la mañana pues son ahora las 8 y media de la tarde se lo he recordado a los monitores de tarde porque ahora me he acordado y yo no estoy bien si yo me despisto tenian que tener un poco de sendibilidad humana y es tanto por mi parte como por parte de los monitores no me siento bien atendido pido por favor por urgencia que valla a un sitio que yo me sienta ayudado y los monitores se vuelcan con algunos y conmigo la relacion justa y hasta se le olvida por favor se lo pido urgentemente el cambio a merida se lo ruego por favor ya no puedo mas******************** Yo estoy con la obsesion de no engordar y esta noche claro yo estoy delgado con 82 kilos me peso a diario y cuando estaban repartiendo la comida y echarme una mano sabiendo que tengo el problema y necesito cariño y animos y me podian a ver dicho.damian come mas que has cenado muy poco yo les dije que no iba a comer mas bueno falta de calidad humana .podian haberse preocupado y decirme hombre come un poco mas que has comido muy poco y muy alto con otros compañeros si comen menos se preocupan por ellos por favor yo estoy muy mal aqui en plasencia sin un poco de calidad humana ya no aguanto mas por favor no quiero irme por mi cuenta porque yo solo no puedo estar y yo necesito sentirme integrado en una residencia estar bien hable con el sepad que me manden a merida ya estoy muy quemado llevo in año y diez meses sin recibir visitas de familiares me siento abandonado.ayudeme a irme a meridad porque usted tiene mucha calidad humana y mi comportamiento aqui no es malo es bueno pero con mis despistes que estando solo si no aguanto me gasto todos los dineros y yo quiero estar mas cerca de mi prima si me voy a verla o ella viene a verme y son casi dos años pasando mucho.y sin padres ni nimgun tipo de familia.se lo agradeceria don rmiguel usted sabe que tengo buen corazon y confio plenamente en usted porque es usted un señor muy buena persona y le tengo mucho respeto.un saludo muy señor nuestro.buenas noches********************************* Le he enviado un mensaje de voz que me mando el inquilino y el mensaje lo abri y me senti amenazado que dice que si yo no le pago el dinero que le debo y ese dinero se lo di cuando me fui arruinado por la gente que se me mete alrededor cuando consegui en abril 2018 echar a los delincuentes iba con trampas que a mi nombre pusieron los prestamos que he resuelto gracias al CRR eso fue cuando me vine 2018 abril que me dieron la total.entre en caritas y me echaron porque me engañaron y les di mi dinero que era del pago del 100 por cien el ayuntamiento me dijeron esta pareja que estaban alli conmigo en caritas me fui con ellos y me prometieron una familia y me dijeron vete para la estacion de tren y despues te damos el dinero se gasto ellos se llaman inmaculada y bautista pusimos la denuncia y el juicio no se ha llegado a realizar lo iba ha hacer por video conferencia aqui en los juzgados de plasencia ya que mi expediente y lo ocurrido fue el robo en merida pero mi caso esta en caceres se llevaron unos 5000 euros y volvi acaritas llorando y ya la directora del centro tuve una pequeña pelea mal entendido por culpa de un chico y me expulsaron del centro.despues un compañero que vivia en centro vida que se fue del centro vida sin hacer caso a sus padres Su pretension era alwuilarde un pido conmigo en un barrio marginal de caceres era aldea moret estsba yo en la calle y este chico habia encontrado la oportunidad de engancjarse a mi el se ocupo de busvar un particular y lo alquilamos en noviembre del 2018 entre los dos pero nos ibamos al salon de juegos y no tenia control de mi me vevia cervezas me gastaba el dinero en maquinas de azar eso ya viviendo a la emtrada de aldea moret yo todo lo que me pedia se lo daba y se lo gastaba tanto el como yo en el salon de juegos sportium que estaba al lado de donde nosotros alquilamos en aldea moret y claro este chico se engancho a mi seria esto diciembre 2018.entonces este chico para ganar dinero era invierno encontro una pareja y les alquile una habitacion para dinero suyo hasta una vez se lo llevaron esposado que fui a recogerlo al juzgado de caceres porque a sus hijos no le habia pasado la manuntencion y una de sus mujeres lo denuncio.esto puede ser noviembre2018 .siguiente punto este muchacho encontro una pareja para vicios seria a una pareja y se ganaba un dinero para sus vicios y disfrute del piso que habiamos alquilado.mi compañero le alquilo una habitscion a esta pareja y yo les dije inocentemente a finales de mayo voy a sacar el dinero del piso para pagar el alquiler de enero del 2019.una mañana muy temprano fuimos al cajero y saque lo poco que habia 900 euros se llamaban javi y juani actualmente viven en plasencia y me los tropiezo y yo por el trastorno de miedo y panico no les pido el dinero.total volvemos al pasado le di el dinero a la pareja pagar el alquiler y confie en que me iban a guardar el dinero me engañaron fui al piso lo haboan recogido toda su ropa y se quedaron con el dinero del alquiler en enero nos tuvimos que ir del piso porque me habian vuelto a engañar.me fui a la calle por mi cuenta y ya el siquiatra hablo con pilar beiro para buscarme un techo .la asistenta social de caceres en ronda del carmen iba a diario a preguntar cuando me sale la plaza en CRR .total me fui con juanjo un borracho propietario del piso un sexto sin ascensor en lo mas malo de aldea moret coincidiendo que un chico o señor juan pedro se vino con nodotros a vivir con juanjo propietario .juan pedro y yo.jusn pedro me obligo a yo darle mi tarjeta bancaria y estaba pendiente para que apenas me separarara de el para sacarme el dinero.yoreligiosamente le pagaba a juanjo la hsbitacion que tambien me sacaba dinero nos ibamos al bar me daban cervezas wiski y me llevaron a rastras al piso.despues pedi arreglar para pedir revision al año que me ayudo a pasar mi pension a caceres y le entregue a santi buenisima persona funcionario que era voluntario en centro vida caritas .estuve secuestrado desde enero del 2019 hasta mayo 2019 y todo el rato pilar beiro claro que yo nunca habia estado en CRR y no salia la plaza fui al tribunal medico y me llamaron para decirme que el 6 de mayo previamente me mandaron la carta para revision yo le dije señora esto es un barrio de gente humilde y de mucha droga y gitanos y gente baja esto fue que me llamo la seguridad social pars el 6 de mayo yo de todas maneras a santi que me conocio en caceres me ayudo en tema de papeleo.total me dice la señora pasese mañana 7 de mayo perdi el carnet en el banco que lo recupere y yo iba muy muy muy malo por la vida que llevaba sin estar controlado enseñe el 7 de mayo mi carnet de conducir.el inspector me pregunto varias preguntas y le enseñe documentacion que ponia que no me manejo bien con el dinero y le dije que tenia ansiedad para morirme y me vio tan malo que dijo vamos a intentar subirte la pension porque la total me la dieron en malaga cuando yo vivia en mi piso desde caritas el 1 de agosto del 2018 se alquila a peticion del inquilino a alquilar el piso por la ayuda del ayuntamiento pero sin contrato estuvo abril 2018 hasta 31 de julio sin papeles de ningun contrato en abril dice el inquilino que me entrego 1700 euros y el mes de junio del 2018 no me pago nada .total que msndaron cuando yo en agosto estaba encaritas mandaron documentacion al centro vida donde yo vivia para firmar el contrato a traves de mensajeria y me entregaron el contrato de tresaños de los primeros de tres años que mi contrato era del antiguo que no estaba obligado a alquiler 2 años mas los contratosque se hicieron posteriori estaba el propietario obñigado a renovar 2 años mas el mio no es mi caso.total que pase la revision el 7 de mayo del 2019 y a mediados de mayo llame a preguntar y paso el mismo 16 de mayo el tribunal me concede la subida de pension con la absoluta yo al final tuve que ir a recoger el papel que redacta osea la resolucion que hizieron y pase a cobrar 1460 a partir 16 mayo que sale mi expediente y dice que no tengo que pasar revision a no ser que yo pida una revision por motivos y quiera trabajar por ejemplo con la absoluta no puedo trabajar en nada osea el mes de mayo del 1 al quince de mayo me pagaron la proporcion a lo que corresponde a la total y del 16 de mayo hacia adelante cobre la absoluta en junio cobre como unos 1300 porque no cobro todavia el mes entero acababa de pasar la revision y a finales de junio cobre la absoluta entera 1460 que ahora ya en dos años me han subido y ahora cobro 1484 euros aquel mes finales junio cobre la paga integra por primera vez por 2 veces coincidia con la paga de verano total al tener la absoluta me escape de aldea moret y me fui a malaga sin que los que me securstraron se dieran cuenta cogi el autobus y durmiendo en la puerta del albergue en lacalle total milagro me llama la asistenta social decaceres de ronda delcarmen en caceres y me dijo que salio una plaza en plasencia y le dije despues dije yo ya no la cojo y ana pineda ttrabajadora social y mi prima alicia como estaba con deudas hasta arriba y entonces llame a pilar beiro la asistenta social y le dije que si que cogia la plaza mi prima me pago 40 euros de su bolsillo que por eso quiero que alicia sea mi tutora y cogi el autobus de malaga a plasencia que sali por la tarde y llego de madrugada por despiste cogi maleta equivocada y la mio siguio hasta asturias en primer lugar estuve unos dias viviendo en caritas de plasencia y me atendio consuelo la directora y me tuve que quedar 3 dias porque tenia que superar unos dias antes del 24 de junio del 2019 y me hizieron la entrevista paula y blanca se portaron muy simpaticas eso es la entrevista si daban el visto bueno para entrar en CRR de plasencia aprove la entrevista y me admitieron y entre en el CRR de plasencia el 24 de junio del 2019 ahora el 24 de abril de este 2021 hago un año en el CRR de plasencia a la espera de ahora en la actualidad que me concedan la plaza en merida esta es mi vida cuando vivo solo yo no puedo vivir solo don miguel porque siempre acabo en la ruina.muy señor nuestro buenas noches***************** Se me olvidaba yoentre aqui en CRR como me solicito pilar beiro delcentrode siquiatria de ronda del carmen por emergencia social al no tener familia ya que ni mi prima la tenia cabreada y no tenia familia a pesar que me dejara 40euros para llegar a plasencia no me hablaba y poco a poco la estoy recuperando y quieroactualmente que sea mi tutora******************************************** Buenos dias don antonio el mensaje tan largo que le envie a usted tan largo era para que usted se lo enseñe al juez mandeme mensaje si lo ha recibido un cordial saludo****************************************Son todos los correos que le emvie ayer enseñarselos al juez.gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-04-23','Ana: Recibimos resolución de la Pensión de Viudedad solicitada: Importe líquido mensual a percibir: 323,65€. Primer periodo (15/01/2021 - 30/04/2021)= 1148,44 €. ············ **No me cuadra ni la cuantía (pues la P.Jubilación del marido ascendía a 835,80 en 2020) ni el periodo de reconocimiento. **Puesto que hoy es festivo en Cáceres, llamaré la semana que viene al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-04-15','Ana: Registro en el ORVE, Solicitud de Revisión del grado de discapacidad - Consejería de Igualdad, Pª Sociales y Conciliación de la JUNTA DE ANDALUCÍA. ·························· Se lo adelanto escaneado a María, TS de F. Autismo Sur junto con el INFORMA de la situación de Costi solicitada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-13','Ana: Registro de ENTRADA en el ORVE Comunicación de variaciones (cambio de CCC)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-04-22','-Amalia : le conceden plaza publica T4 en Los Olivos de Mérida . Escribo a la seccion eco: Buenos días , os confirmo que finalmente le han concedido plaza publica en Los Olivos . Jose Mª ha estado hoy en la Gerencia , va a proceder de la siguiente manera : -Como se ha concertado la plaza desde el dia 22 abril , devolverá a su cuenta los días que restan hasta el dia 30, que ya le cargó por plaza privada ( en torno a unos 400€ , tiene que calcularlo). -Al final de mes le cargará del 22 al 30 de abril como precio público ( en torno a unos 200€) -El precio de la plaza privada es de 1600 , al pasar a plaza pública abonará 772,67€/mes . El dinero restante hasta totalidad de la pensión será para gastos de bolsillo , sobre todo para gastos de tabaco . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-04-23','Ana: Recibo llamada de Esther, TS del SSASB de Cilleros (927 51 20 37), su contrato es de sustitución por maternidad, en principio estará hasta junio. La TS que se incorporará tabién es Marta. ···· Julia la ha llamada para preguntar por su plaza en centro, qué cuándo la van a valorar y le van a dar plaza... Explico la situación actual, las gestiones realizadas hasta la fecha, el funcionamiento de la CTAEX y le informo además del segumiento que le hace Gloria-Futuex. Seguiremos en contacto. ··························································································································································································· Juanpe, Admvo. CTAEX, mira en SIDEX y todavía no aparece gravada la solicitud de dependencia de Julia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-04-23','Ana: Llamo a Mª José Polo, TS del SSASB (664 018 209): dice que está en una reunión, intentaremos hablar en otro momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-04-23','Ana: Entrego a Juan Pedro, Admvo. CTAEX, contrato de ingreso en residencia firmado por el D.Gerente por duplicado, para que lo remita por correo certificado a la Residencia Puente Real San Vicente de Alcántara. ························································································································································································· Llamada de Vere, Directora de la Res. Puente Real San Vicente (638 490 750): Ayer acudión la hija de Agustín por primera vez a visitarle. La visita en sí bien. Pero Agustín le entregó 250 € de los que traía del CRR y se había guaradado él. Agustín se quedó con 25€ para gastos de bolsillo. La hija pide ahora que se entreguen también los otros 455€ que tiene custodiados Vere (los que guardaron a su llegada). **Le indico que de ninguna manera, ese dinero es de y para Agustín, para lo que pueda necesitar y se lo debe seguir custodiando y gestionando el centro.···· *Por otra parte, Agustín ya ha salido a su paseo de una hora. Ha vuelto a su hora correspondiente, todo bien. En el centro le proporcinaron una tarjeta con sus datos y la dirección del centro, por si se desorientara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-23','Ana: Llamada de José Manuel, dice que haga un escrito para que le dejen irse a su casa, que no se adapta al CRR. Le digo que desde la CTAEX no vamos a hacer ningún escrito en ese sentido, pues no estamos de acuerdo en solicitar el Alta Voluntaria, pues consideramos que lo adecuado para él estar en un recurso. Argumento además que lleva poco más de una semana en el CRR, qué aún está en periodo de adaptación, seguro que irá haciendo amistades y conociendo más la ciudad. En cuanto que ahora puede salir poco del CRR, le recuerdo que se debe a la situación acutual de pandemia, que en cuanto la situación se normalice podrá salir más (como cuando estuvo en el CRR-Mérida). Y le recomiendo que valore todas la cosas positivas que tiene estar ahí en comparación de en su casa: La comida le gusta más que la del cáterin, puede ducharse con agua caliente sin problemas de la caldera, no está todo el día solo, cuenta con profesionales de apoyo, le ayudan a gestionar el dinero y el tabaco (tiene todos los días), no tiene problemas con su hijo... *Finalmente admite que tengo razón y dice que va a seguir intentándolo. ············· Por otro lado informa de que el miércoles 21 le han puesto la primera dosis de la Vacuna y que el día 12/05/21 está previsto que le pongan la segunda. *Le digo que es otro motivo más para que permanezca en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-23','Ana: Correo de Estrella, TS CSS-Plas: "Buenos días, Ana. Te reenvío correo con la lista de la compra que el Psicólogo confeccionó con Isabel, para los días de pase a su casa. Buen finde" ········· El pase de salida para ir a su domicilio es del 27 abril al 4 mayo. *Envían presupuesto desglosado con un total de 123,90€. ············· Se lo reenvío a Alberto, Jefe de la Secc. Ecca. No sé si peude permitírselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-23','miguel, llamo a inmobiliaria Colon para que vendan la vivienda y me comentan que me llamarán para asesorarme de posible precio de venta. Les comento que solicité el año pasado precio máximo de venta a vivienda y me comentaron que teníamos nosotros que decirles precio de venta y aportarles dni de compradores. Hablo con Juana y Alberto y la situación es extrema pues ya ha ingresado en Centro y no tiene capacidad económica************************************ Buenos días. Situación del tutelado hoy 23/04/2001 • Saldo en Caja Rural (su CCC): 72,72 € • Saldo en Ibercaja (1/2 con su madre): 36 € INGRESOS: 399,02 + 210,80= 609,82 €/mes GASTOS: • el día 25/05/2021: le pasan el centro 457,5 € • el día 01/05/2021: el centro solicita 80 €/mes para tabaco • el día 04/05/2021: le pasan el prestamo de 254,57 € de la vivienda. (PENDIENTE DE AMORTIZAR EN 2021: 33.000 €). • TOTAL: 792,07 €/mes FIJOS • Otros gastos: farmacia, OAR, embargos (indeterminados): No es posible determinar. HOY: NO podemos pagar la parte proporcional de centro del mes de abril NO podemos pagar el tabaco que nos solicitan en este momento. MAYO: • Nos vemos obligados a realizar transferencia para pago de préstamos el mismo día de cobro de pensiones x 254,57 € • X tanto NO da para pagar el centro y tampoco el tabaco....ni farmacia o imprevistos: habría que ESCOGER que se paga y que no. JUANA VA A PONERSE EN CONTACTO CON IBERCAJA (PRÉSTAMO) Y PLANTEAR OPCIÓN DE QUE, DURANTE UN TIEMPO, ÚNICAMENTE COBREN LOS INTERESES (pero no debemos contar con esto) JUANA: TRAS CONVERSACIÓN CON EL BANCO HAY QUE DECIDIR SI MODIFICAMOS O CANCELAMOS LA TRANSFERENCIA A IBERCAJA PARA EL PRÉSTAMO JUANA: facilitar a MIGUEL datos ECO para comunicar a JUZGADO que NO hay dinero. AMALIA: XFA, HABLA CON EL CENTRO Y COMUNÍCALES ESTA CUESTIÓN: • QUE PAGAREMOS LA DEUDA QUE SE GENERA CUANDO VENDAMOS LA VIVENDA Y MIENTRAS TANTO IREMOS PAGANDO LO QUE PODAMOS. • IMPORTANTE: CENTRO DEBE DECIDIR LA PRIORIDAD DE PAGO: O BIEN CENTRO O BIEN TABACO. AMALIA: Miguel necesita un certificado del centro con la fecha en la que se ha incorporado. MIGUEL: XFA, ACELERA LOS TRATOS CON INMOBILIARI. RECUERDA EL TEMA DE LA VALORACIÓN OFICIOSA. OTRAS OPCIONES QUE PREFIERO NO VALORAR: • QUE VUELVA A SU VIVIENDA. • DEJAR DE PAGAR PRÉSTAMO ***************************************** Les pido un resumen-informe de la situación económica, certificado de residir en el Centro y yo aportaré lo que me envíe inmobiliaria Colon. Una vez tenga la documentación enviar COMUNICACIÓN AL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-26','llega emails de Damian: Mañana tengo cita con el medico por telefono el de cabezera porque llevo muchss veces al orinar me lo hago encima se podria pasar para decirselo al juez que me ayude por este motivo por lo menos desde febrero y mucho antes y en enero y navidades con esto me pueden dar en una revision para que consigamos el grado 1 demostrar con el papel de uirgencia puede servir para una proxima revision.muchas gracias don miguel**************************************************** Esta semana que me tienen que hacer analiticas porque se me sale cuando orino llego alcentroahora mismo y una monitora no mepodia atender pero la monitora ni me miro a la cara sbi y me duche para decirselo al juez quedarme con la necesidad por algo que debo ser atendido.comenteselo al juez las estoy pasando muy mal.gracias que el señor le bendiga por su progesionalidad y buen corazon.feliz dia le deseo.comunique la desatencion que hay que me ha pasado con esto en concreto.uncordial saludo************************************ Tema para itziar y usted todavia no me ha ingresado los 1350 estoy preocupado************************************************************************************************************** He perdido los cascos de musica y estoy mal cuando me di cuenta fuimos con la monitora sobre las 6 de la tarde a devolver un chandal que le quedaba mal y claro vuelvo al centro me pongo enfadado pero siempre el respeto por delante por ambas partes le dije al monitor victor por favor buscame los cascosa ver si estan en el coche con todo mi cariño y humildad y estaban echsndo un torneo de pin pon yo perdi el primero el torneo y el monitor me quejo porque cuando teniamos que entrar para adentro y yo estaba amargado por perder los casco y se me cayeon al entrar al coche y cusndo dijo entrad me dijo sin tener calidad humana y cariño venga para adentro no me dijo ni por favor.la monitora le daba igual a pesar que ella se preocupo y miro pero como molesta yo procuro decir ni una palsbra cuando esta esta monitora por miedo vivo asustado y es que mi compañero de cama es un compañero como usted muy buena persona pero aparte del despiste que he perdido tantas cosas es que en el tono de voz que me hablan es mas seco que con otros compañeros.por favor ayudeme salir de aqui digaselo al sepad que yo necesito irme a merida cuando se pueda.el director antiguo le tengo un gran aprecio a paula y blanca el equipo tecnico pero no estoy bien gracias al compañero que tengo estoy mejor cuando charlamos en la habitacion y me trata muy bien lo que es positivo y bueno tambien lo digo.del tono que me hablan algunas personas por mi proceso y enfermedad me vivo las cosas como un ataque*********************** *********************************************************** Acabo de perder las llaves de la taquilla esta misma noche a esta hora','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2021-04-26','EXITUS La madrugada del sábado al domingo, falleció Paula López Ruiz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-04-26','TERESA EMIAL TS PLENAINCLUSIO Tras los primeros días de estancia de ASB en nuestra entidad Plena Inclusión Cabeza del Buey te informamos que: Paula se encuentra de pase de la UDAC desde el día 20 de abril, al llegar se mostraba somnolienta e inestable al estar de pie. Han ido pasando los días y se muestra más activa y nerviosa, cambiando de estado emocional constantemente (quiere estar aquí, no quiere, está contenta, al momento triste), además han aumentado sus obsesiones recurrentes y constantemente solicita cosas que no están a su alcance. Además del acercamiento ya descrito en un correo anterior hacia uno de sus compañeros del centro, el día 22 de abril, hizo tres intentos de ingestas de material no comestible (una pulsera). Tampoco respeta el espacio personal de los demás ni cumple las medidas de seguridad por situación de covid-19 yendo a habitaciones de compañeros sin tener puesta la mascarilla. En las salidas al entorno tampoco cumple medidas covid-19, escupiendo por la calle, tocando animales ajenos y queriendo entrar en establecimientos a pesar de nuestras recomendaciones. Te informamos también que el traslado de vuelta a la UDAC previsto para el próximo martes 27, se realizará en ambulancia; saldrá de Cabeza del Buey sobre las 9 de la mañana e irá acompañado por dos cuidadores del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-04-26','FUTUEX Hace una semana cuando se visitó a Ramón González Hernández en su > domicilio de la Calle Toledillo Bajo de Jerez de los Caballeros, se > comprobó que le llegó una carta certificada de los juzgados de > Jerez. Al abrirla, se pudo leer que un vecino de la localidad le > había denunciado porque según él, Ramón le había intentado robar > uno de sus perros, y como lo pillaron en el acto, al intentar llevarse > al perro por la fuerza, lo asfixió. Seguidamente Ramón se escondió > hasta que el dueño del perro se fue. Esa es la versión del > denunciante, pero cuando se le pregunta a Ramón si conoce a este > hombre, Ramón contesta negativamente y no se le quiere dar más > información sobre la citación para que no se ponga nervioso y no > vaya a contactar con este señor antes de ir a los juzgados. > > Se adjunta remite la citación escaneada. > > El lunes la compañaera ira con el, al juzgado y de paso comprara la','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-04-26','Ana: tras leer el correo de Sonia-Asindi (trabajosocial@asindi.e.telefonica.net), del viernes: "Hola, nos ha llamado varias veces el padre de Aaron para solicitarnos la documentación: D.N.I. y certificado de discapacidad que le piden para tramitar el bono social de la luz. No he sido capaz de contactar con él para indicarle que al estar empadronado Aaron en Alcántara y residir aquí la mayor parte del tiempo no le sirve su documentación para este trámite, y no se la vamos a facilitar. No sé si vosotros podríais ver este tema con él. Se llama Julio y su teléfono es 678 24 11 37. Un saludo," ················· Llamo a Julio y escribo a Sonia: "Buenos días Sonia, Acabo de hablar con Julio, padre de Aarón y ya se lo he comunicado. Seguimos en contacto. Buen día y semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2021-04-21','Ana: Llamo de nuevo a Margarita Montero, TS de la Mancomunidad Sierra de Montánchez (927 221 206), varias veces, en relación a la información que me solicita Juana, secc. ecca. CTAEX; necesitamos saber si el hermano de Isabel reside en la vivienda y en caso negativo, si se pondrían dar de baja los suministros. *NO obtengo respuesta. Volveré a intentarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2021-04-26','Ana: Llamo a Margarita Montero, TS de la Mancomunidad Sierra de Montánchez (927 221 206), me informan que le pasarán nota, pues a ella ya no se le localiza en este número, pero tampoco me pueden facilitar otro. ···················· Recibo llamada de Margarita: El domicilio en que vivía Isabel, pertenece tanto a ella como a su hermano (por herencia) y actualmente está deshabitado, el hermano vive en la misma calle pero en otra vivienda más arriba. *Se pueden dar de baja los recibos de los suministros. ··········· Se lo comunico a Juana, secc. ecca. CTAEX. ································································································································ Margarita, TS, me informa en un correo (tsocial4@mancomunidadsierrademontanchez.es): "en Montánchez estoy Martes, Miércoles y Jueves puedes localizarme en el Tfno 637 099 759"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-04-26','Ana: Llamada de Jairo, está muy contento porque ya se ha comprado ropa nueva con los 90€ aprobados (varias comisetas, bermuda y pantalones). Por otra parte dice que necesita comprarse una gafas nuevas. *Al igual que ya le indiqué en su día, debe enviar a la secc. ecca. de la CTAEX, a través de Emilia, TS, o de la propia óptica, Informe donde se indique qué le ha variado la graduación y es necesario hacer una gafas nuevas junto con al menos un par de presupuestos. ········ Por otra parte comunica que le ha solicitado al Psiquiatra un cambio de Unidad Hospitalaria y que éste le ha dicho que lo va a valorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-26','Llamada de Beatriz, Coordinadora del CRR-Ba (924 23 16 51): José Manuel vuelve a insistir en que quiere pedir el alta voluntaria, está muy convencido de que no quiere estár allí y no se adapta y que además "él en su casa puede hacer lo que quiere y cuando quiere, levantarse a la hora que le dá la gana y hacer lo que le da la gana". Está claro que no acepta ningún tipo de normas, límites ni control. En en el CRR le han explicado que está en un proceso de rehabilitación y que si él no colabora ni pone de su parte no tiene mucho sentido que permnezca allí... *Le cuento lo que hablé yo con José Manuel el viernes, y acordamos que intetnarán al menos que permanezca allí hasta que se haya puesto la 2ª dosis de la vacuna Covid. ··································································································································································································· Llamada de José Manuel: Hoy ha ido a visitarle Virginia, junto con Teresa, Toni y Sonia - FUTUEX. A pesar de ello vuelve a decir que se quiere volver a casa, que el fin de semana ha estado muy bien, pero que esta noche no ha dormido y se se siente mal, le ha "dado el bajón". Le explico que segurametne un motivo para sentirse así es el no haber dormido, pues esto afecta mucho al estado de ánimo. De nuevo repasamos los motivos por los que quería ir a centro y recordamos lo negativo de estar en su casa y que si decide volver, en el futuro no va a tener más opciones de recurso que el CSS. Finalmente, entra en razón, y expresa que lo volverá a intentar. *Por otra parte le informo también que he hablado con Beatriz esta mañana y que hemos acordado que hasta que no se ponga la segunda dosis de la vacuna (12/05), no se valorará la opción de alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-26','Ana: Llamada de Francisca, madre de Isabel (927 76 14 24), dice que no le demos nada de dinero a su hija, que no hace falta, pues como han ingresado la PFHC en la cuenta en la que están las dos, ha pagado lo del teléfono y ha sacado todo lo demás, con lo cuál ya tienen dinero para gasoil y para lo que necesite comprar su hija cuando vaya a casa. ······························································································································································································ Informo mediante mail a Alberto, Jefe Secc. Ecca. Pongo en copia a Estrella, TS CSS. ······························································································································································································ Respuesta de Estrella: "Gracias, Ana. Se lo reenvío a Borja Psicólogo que informará a su vez a Isabel."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2021-04-26','En relación con la herencia y venta del inmueble de la misma, hablo con el Abogado designado, Luis Balanzategui Nogales (646067171), que tras enviarle toda la documental de la que disponíamos y contactos con herederos y Notaría de Valencia de Alcántara, me dice que ha intentado en innumerables ocasiones hablar con los herederos para que le faciliten más documentación que necesita, pero que no lo consigue. Va a intentar solictarlo via judicial con unas Diligencias Previas. También me dice que ya no forma parte del turno de oficio, pero que sigue llevando los expedientes que inció cuando formba parte de el, como en este caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-04-26','Ana: Llamo a Mª José Polo, TS del SSASB (664 018 209): Le informo que ya es firme la Resolución de Internamiento Involuntario de Florencia, si bien en la parte dispositiva indica "...internamiento involuntario NO URGENTE...". Florencia está valorada con grado II de Dependencia, pero no se le ha solicitado nunca plaza residencial. *Hablará con las compañeras de dependencia las posibilidades de ingreso en los centros cercanos a la localidad y volveremos a hablar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-04-26','TERESA ME COMUNICA MERCEDES TS QUE LIBERTAR VA A EMPEMZAR A TRABAJAR LIMPIANDO UN PORTAL 9 HORAS MENSUALES ME QUEDO A LA ESPERA ME ENVIE CONTRATRO PARA COMUNICAR A PNC TAMBIEN PROPONE SUBIDA ASIGNACION A 100€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-04-26','Ana: Recibo llamda del Enfermero del C. de Salud de Trujillo (927 320 769): el Psiquiatra ya ha elaborado el informe, me lo remitirán vía fax. Intentarán también hacérmelo llegar a mi email (no está seguro si hay correo coorporativo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-04-26','Ana: Llamada de Julia. De nuevo pregunta por la valoración de Dependencia, pues está deseando irse a un centro... Vuelvo a recordar que ha de tener paciencia. ······································································································································· Envío a Clara I. Gómez Nestares, Jefa Secc. Dependencia, solicitud de valoración de dependencia, junto al informe social y el informe de salud, ya registrados y pregunto si es posible priorizar el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-04-26','TERESA PROXIMIA VISITA BEA A SU HIJA EL 1 DE MAYO DE 2021 A LAS 12.00 HORAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2021-04-27','Ayer no me cogieron el teléfono en Ibercaja, pero he podido hablar con ellos esta mañana, y me cuentan que ayer Pipi sacó los 225 € que le correspondían, no sé cómo dice que no le daban el dinero, mira de verdad… Ya les he comentado que antes del 25 de mayo les mandaremos autorización para que vuelva a poder retirar los 300 €. Iciar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-27','email de Damian: Hecorridoyhevueltoahorosmo tripamal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-04-27','Ana: Recibimos Resolución aprobatoria de PFHC a nombre del Representante Legal, Isabel como causante. Fecha de efectos del cambio: 01/07/2021','2');
