insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-04-26','TERESA ARCHVIO RESOLUCION EN LA QUE APRUEBAN LA SUBRAGACION MORTIS-CAUSA DE LA TITULARIDAD DEL CONTRATO DE ARRENADIMIENTO DE LA VIVIENDA SOCIAL QUE ANTERIORMENTE ERA DE SU PADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-04-27','TERESA NOTA FUTUEX El pasado 20 de Abril se conversó con Lorenzo García, el hermano de Adolfo García Cruz de Villafranca de los Barros, para preguntarle cómo había pensando organizarse con respecto a los cuidados de su hermano refiriéndonos a la compra de comida, productos de aseo y demás. Lorenzo comenta que él se ocupa de comprar los alimentos y de preparar la comida a diario para su hermano, y además se encarga de abastecerle de productos de aseo personal y de todo lo que él necesite, por lo que propone que sea él la persona que recoja en el banco la asignación mensual de Adolfo. Comenta incluso que lo ha hablado con la comisión tutelar aunque ellos no le han dado una contestación definitiva aún. Se quiere comentar también que debido a la visita que se realizó a Adolfo el pasado 16 de Abril en Villafranca, no nos quedó muy claro si realmente el tutelado está viviendo con su hermano en su piso o se ha trasladado a casa de su madre y Lorenzo va a llevarle la comida y a echarle un vistazo. Ya que la relación entre los hermanos es cordial pero siempre ha habido conflictos y Adolfo tiene una cierta dependencia a la casa de su madre, por lo que no nos queda claro que se haya mudado al piso de su hermano. Dicho esto, lo que sí se tiene claro es que Lorenzo se encarga de hacerle la comida a Adolfo y de comprarle los productos de aseo que le hagan falta. Pero no se considera que sea buena idea que Lorenzo retire la asignación íntegra de Adolfo ya que podría convertirse en un conflicto entre ellos, porque Adolfo está acostumbrado a ir al banco solo a retirar su dinero. Una idea podría ser que desde la cuenta de Adolfo se le transfiriera a Lorenzo alrededor de unos 200€ para los gastos de comida y asuntos vario o la cantidad que la comisión . Así le quedarían a Adolfo entre 100-80€ para sus gastos mensuales. Ya que la asignación mensual que tiene aprobada Adolfo asciende a 300€. Otra idea sería firmar un contrato con Adolfo en el que se comprometiera a entregarle a su hermano una cantidad de dinero mensual para que comprara la comida y otros productos que le pudieran hacer falta. Pero se corre el riesgo de que pasados unos meses, Adolfo se niegue a entregarle dinero a su hermano y este hecho se convierta en una problemática grave entre los hermanos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-27','Ana: En relación al intercambio de correos con Alberto, jefe de secc. ecca. CTAEX, envío correo a Toni-FUTUEX: "Buenos días Toni, En relación a Clementa Amado Vivas, esto es lo que se ha determinado desde las áreas económica y social: Puesto que hay que hacer frente, además de a la hipoteca, comunidad y seguros de deceso, a las distintas deudas que tiene acumuladas, no se le puede entregar a la hija todo lo que pide. Quedando las cuantías así: - HIJA MANUTENCIÓN: TRANSFERENCIA PUNTUAL 225 €/MES: MES MAYO 2021 - REINTEGROS PUNTUALES PARA GASTOS DE BOLSILLO: 20 €/SEM *¿Gloria, que la conoce, considera que es necesario el acompañamiento al banco? yo en principio he dicho que no, excepto que consideréis otra cosa. - En cuanto a los gastos de farmacia, se ha estimado abonar directamente a la misma mediante transferencia la medicación de Florencia (todo lo que se le haya recetado). El resto de productos de parafarmacia que pueda necesitar, que lo abone de su asignación. *¿Podríais acompañar a Florencia a su farmacia habitual y explicarle el procedimiento? (tanto a Florencia y a su hija previamente como a posteriori en la farmacia). Como ya sabéis tendrían que enviarnos factura a nombre de Clementa a la atención de la secc. ecca. a ctutelar@salud-juntaex.es, indicando nº de cuenta bancaria. Con respecto a este caso, creo que de momento es todo. Seguimos en contacto. Buen día!" ······························································································································································································ Respuesta de Toni-Futuex: "Le hace el seguimiento Virginia, nosotros no creemos que sea factible el acompañamiento al banco, esta mujer tiene bastante caracter pero sobretodo poca movilidad, a lo poco que sale de casa le suele llevar el yerno en coche Nosotros podriamos a cercarnos la farmacia si nos decis cual es, o le preguntamos a ella a cual suelen ir, y comentar esta forma de proceder, que solo se pagaría mediante transferencia lo que tenga en receta electronica, cualquier otro producto deberian abonarlo en efectivo, ella o la hija o quien acuda a la farmacia. ... le comentamos a la hija lo que se ha acordado al respecto de la manutencion,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-04-27','-Amalia: regstro documento cambio nº cuenta en el INSS Bjoz. No me dan copia , se quedaron el original . Tengo copia del documento firmado en su expediente escaneado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2021-04-27','-Amalia : registro de entrada en el INSS BADAJOZ , Declaracion de ingresos y acreditación para complemento a minimos . copia en su expediente papel .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='MORUNO'and apellido2='GALLO'),'2021-04-27','-Amalia : hablo con el doctor Jose Mª Tena 645832899 para valorar posible cirujía nasal . Necesita anestesia general y tiene dudas sobre su respuesta cardiologica. Primero va a pedir cita al cardiologo para valorar . Luego con los resultados de esa cita hay que volver a pedir cita para preanestesia donde se valorará la cirujía . Le he facilitado mis tf . y mi email. Le he indicado que tendrán que valorar ellos lo mejor para el usuario , puesto que ésto es una tutela instituional . Si tiene dudas no aceptaremos la intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='MORUNO'and apellido2='GALLO'),'2021-04-27','-Amalia : le comento a Maribel del CSS la conversación con el médico anestesista del hospital de Mérida . Me dice que en el CSS hay médicos somáticos que tb pueden valorar la conveniencia o no de la operación. Le comento que seguiremos las indicaciones de los médicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-27','Ana: Pongo para la firma del D-Gerente, las solicitudes de Dependencia y la de Plaza Residencial para Mayores. ······················································································································································································· Correo de Raquel Pérez, TS del SSASB (ssasbrpa@gmail.com): "Quedé con la médica que cuando tuviera los informes que los llevará a la Ayuntamiento para hacérmelos llegar. Cuando estuvimos con ella, no había mirado nada del expediente de esta señora, le lleve todos los informes que tenía yo en el expediente de servicios sociales, a los cuales hizo copia, me dijo que tenía que verla, que iría con la ATS, pero no me concretó cuando. Referente al 112, le referí la segunda vez que acudí al centro de salud, (a recoger mis informes), así como para hablar de la situación que nos habíamos encontrado, que vista la situación y por lo que vió Virginia, era complicado convencerla y que todo apuntaba a que debía ser a través de activar el protocolo de 112. Le dije que no obstante, te pondrías en contacto con ella. Mi percepción es que no creo que haya hecho nada. Ayer hablé con el ayuntamiento y no me dijeron nada al respecto, ya que saben que el tema es urgente. Vamos y ya te digo yo, que si hubiera llevado los informes, me los hubieran llamado o enviado un correo. Te agradecería que la hicieras una llamada a la Médica, a ver si ya la han visto o qué." ······························································································································································································· Llamo a Raquel, TS (667 068 078): la médica no ha ido aún a visitar a Florencia ni ha elaborado los informes pertinentes para la solicitud de plaza. *Por otra parte cree que Florencia aún, a pesar de su edad, no se ha puesto la vacuna Covid. **Acordamos que, antes de llamar yo a la Dra. llamará ella a Esperanza, Alcaldesa, de quién me facilita el nº por si hiera falta llegado el momento. **Por otra parte, me informa también, por si fuera necesario, que la Coordinadora de la Zona Sanitaria, es Elena, se le localiza en el C. Salud de Vva. de la Vera. ··························································································································································································· Nuevo correo de Raquel, TS: "Ya ha hablado Esperanza la Alcaldesa con la médico, le decía que estaba pendiente de que yo le llevara unos modelos (cosa que no es cierta, porque se los dí). Acabo de hablar con la médica y efectivamente tenía los modelos en su poder. Me ha comentado que va a programar una visita, a la cual ya ha quedado Esperanza con ella que la avise para acompañarla. Le he referido que a lo largo de la mañana ibas a llamarla tú, por el tema de activar el 112 y que te diga cuando ha programado la visita. Te paso el teléfono de la médica para que no tengas que buscarlo, 927567270." ····························································································································································································· Llamo a la MAP, Raylin Pinales, con el resultado de la conversación envío correo a Raquel: ".... Acabo de hablar con la Dra. Raylin Pinales, ya ha acordado ir a visitar a Florencia Dávila mañana al final de la mañana al domicilio acompañada “de una persona que la conoce” (entiendo que es Esperanza). En función de la visita cumplimentará los informes de salud. Iremos paso a paso. Seguiré en contacto con ella (mañana al final de la mañana no creo que pueda llamarla, pero sin falta lo haré pasado). Seguimos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-04-23','llega firmeza de resolución favorable de Internamiento Involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-04-27','llega resolución negativa de SUSPENSIÓN de plazos de TGSS ************************************************ Quedo pendiente del recurso contra la resolución interpuesto ante la TGSS la semana pasada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-04-27','Ana: Tras leer y escaner el informe emitido por el Dr. Miguel Medina, Psiquiatra ESM-Trujillo, y que nos remiten por fax, se lo paso a Miguel, Asesor Jurídico, para que pueda añadirlo a la comunicación al Jdo. ····························································································································································································· Llamo al ESM-Trujillo (927 32 07 69) Cristina, TS, está ocupada, le dejarán nota para que me devuelvan la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-27','recibimos email de Tony de Futuex por citación para este viernes 30-4-21 del tutelado: "Buenas tardes, se adjunta la citación judicial que tiene el tutelado Jose Manuel Romero Mediavilla, para este viernes 30 en Cáceres, que nos comunicó él cuando aún estaba en Cáceres y que hoy nos han comentado desde CRR, por una denuncia, se le ha estado visitando en CRR junto con los otros tutelados y estaba bien dentro de todo, quejandose como habitualmente, "que se quiere volver a Caceres" etc.-.. siendo un perfil como sabemos muy complejo, aunque creemos que podemos trabajar con el para la adherencia, ahora al tener este asunto, y al llevar tan poco tiempo en el recurso, no creemos que sea del todo pertienente que acuda por lo que puede significar (ganas de no volver) pero tampoco sabemos si tiene que comparecer obligatoriamente y de ser así como se haria el traslado hasta Cáceres, sería viable la opción del taxi como para cuando ingresó? o se le buscan los horario de buses y trenes para ver si encaja??" *********************************************************** Tras hablar con el juzgado (no se encuentra la persona que lo lleva y me piden envie un email con los datos de contacto del Centro desde donde pueda hacerse la videoconferencia. Ana llama y se hace con dichos datos y yo remito el siguiente email al email que me envían desde el jzdo Jzdo de 1º inst e intrucc nº4 Caceres, Servicio Común de Ordenación del Procedimiento, LEV JUICIO SOBRE DELITOS LEVES 56/20, recibido hoy, siendo el denunciado nuestro tutelado. "Buenas tardes, en relación al procedimiento arriba adjuntado, esta Comisión Tutelar de Adultos ejerce el cargo de tutor del denunciado D. José Manuel Romero Mediavilla. Dicha persona se encuentra residiendo en el CRR Hermanas Hospitalarias de Badajoz. Debido a la distancia, falta de transporte unido a lo que nos indica la psicóloga de Futuex, Antonia Maria Ramirez: …“siendo un perfil como sabemos muy complejo, aunque creemos que podemos trabajar con el para la adherencia, ahora al tener este asunto, y al llevar tan poco tiempo en el recurso, no creemos que sea del todo pertinente que acuda por lo que puede significar (ganas de no volver)”. Es por ello, y conforme he hablado por teléfono con su juzgado, que solicito la videoconferencia con el tutelado a través de dicho centro donde reside, donde indican a través de la trabajadora social de esta Comisión Tutelar, que sí pueden hacer dicha videoconferencia. Los datos de contacto con el centro son los siguientes: Beatriz, Coordinadora del CRR-Ba (924 23 16 51) Email: bgonzalez.sanmiguel@hospitalarias.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-04-26','Ana: Correo de Paula, TO - CRR-Plas.(tocupacional.crrplasencia@grupo5.net): "Buenos días, comentaros acerca de : - Conchi Fernández. Ha tenido un problema dental que ha necesitado desplazamiento (hoy) con carácter de urgencia a Badajoz para valoración de Maxilofacial. Os seguiremos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-04-26','Ana: Correo de Paula, TO - CRR-Plas.(tocupacional.crrplasencia@grupo5.net) al ctutelar@: "- Flora Gutiérrez. Por fin ha podido ir a llevar las cenizas de su madre al cementerio de su pueblo. Al hacerlo se ha comprobado el lamentable estado de la lápida por lo que se pide presupuesto y le dicen que unos 600 _ 700 euros más IVA (inscripciones de sus padres). Si estais de acuerdo les decimos que adelante y que os envíen un correo con la factura." ··············· Contesto a Paula y reenvío correo a Alberto indicando: "Buenos días Alberto, En relación Flora Gutiérrez García y el gasto que plantean relativo a la lápida de sus padres, si económicamente puede asumirlo, por mi parte, doy el visto bueno. Por favor CONFIRMAR si se acepta o no a Paula, CRR-Plasencia. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-04-28','Ana: Envío correo-e a Beatriz, Coordinadora CRR-Ba (bgonzalez.sanmiguel@hospitalarias.es): "Buenos días Beatriz, En relación a José Manuel Romero Mediavilla, ¿podríais remitirnos Certificado de Ingreso en vuestro centro? Te lo pedí en otro correo, pero se te habrá pasado y ayer cuando hablamos se me olvidó a mí recordártelo. Gracias de nuevo y que paséis buen día." ················· Beatriz me envía el Certificado de Ingreso y se lo remito a Ángel y Miguel, Asesores Jurídicos, para que lo comuniquen al Juzgado. ···················································································································································· Llamada de José Manuel (627 788 797), hoy dice que, aunque le está costando, está un poquito mejor. Ya le han explicado que asistirá a la comparecencia del viernes a través de Videoconferencia. ······ Pregunta también por el presupuesto que envió la T.O., yo no sé nada aún. Preguntaré a Icíar/Alberto. ········ Por último dice que ha dormido mal, que a ver cuándo tiene la cita en Psiquiatría para pedirle algo par dormir mejor. *Igualmente, le digo, que aunque no sea lo mismo, puede pedir en el centro tila o valeriana antes de ir a dormir, que al menos le ayudará a relajarse y eso no es nocivo. ···························································································································································································· Envío correo a Toni-Futuex, comunicando cómo se procederá para la comparecencia (videoconferencia) además de los últimos argumentos que he utilizado con José Manuel para promover su permanencia en el centro. ························ Respuesta de Toni: "De acuerdo! muchas gracias por avisar Nos acabamos de enterar un ratito antes de recibir tu email por el propio Jose Manuel. Como somos consicientes de lo complejo del caso y creemos que merece la pena intentar de la mejor forma que podamos que se haga una buena adherencia al recurso y su posterior transición a Olivenza, vamos a dedicarle un poquito más de atención, si cabe que al resto, porque ahora mismo creemos que pude venirle bien, yo me estoy implicando personalmente también junto con la delegada de la zona, y el viernes volveremos a verlo antes del juicio, para prestarle esa atencion personalizada que demanda. A ver si entre todas coneguimos que se le quite la idea esta de volver a Cáceres y se integre un poquito, porque sabemos que esta es su ultima oportunidad en este tipo de recursos. En la llamada ha demandado dinero, que dice que ya no le queda, creo que Leo desde CRR iba a solicitaroslo, ya que necesitaria dinero para tabaco sobretodo y gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-04-23','Ana: Correo en ctutelar@, de Ana, TS Gerovida (gerovida2010@hotmail.com): "Buenos días; Soy Ana, la Trabajadora Social del Centro Residencial Virgen de la Asunción de Torre de Don Miguel. Me pongo en contacto con ustedes en relación a una residente que ha sido recientemente incapacitada y adjudicada du tutela a la Comisión Tutelar de Mayores. La persona a la que hago referencia es Dª Ángeles Justina Virtudes Martínez Gavilán. Comunicar que con fecha 23/abril/2021 hemos recibido por parte de la Directora del Centro Sociosanitario de Plasencia un documento en el que se nos indica el ingreso de 15.405 euros en su cuenta bancaria de Liberbank (se adjunta documento) así como una relación de Joyas que han quedado custodiadas en el Centro (se adjunta documento). Se informe de que ella posee al menos otra cuenta Bancaria en La Caixa. Del mismo modo solicitar que nos comuniquen la cantidad de dinero mensual del que ella puede disponer para hacer frente a varios gastos personales (peluquería, podología, estética…). Gracias, Un saludo. Ana Belén Tovar Zanca Trabajadora Social Centro Residencial Virgen de la Asunción." ··············· *De momento es Defensa Judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-04-28','Amalia . Se recibe resolucion RAL y VT apta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GIL'and apellido2='RIVAS'),'2021-04-28','Buenas , podéis confirmar la propiedad de esta casa ?? si es solo suya autorizo que pinten algo. Piden documentos a RP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-28','-Email Futuex : Ya tenemos planificado lo de la tv, está en el ayuntamiento de Guadiana, mñana se pasa la compañera a partir de las 8.00 y la lleva a Don Benito al Camp , ya hemos avisado también y luego ella sigue su ruta a Quintana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2021-04-28','Ana: Conversación con Sandra, TS Res. Real Patronato Coria (927 50 80 00), Rogelio renovará ya su DNI el próximo día 4 de mayo. Le han dado cita con la Unidad Móvil de la Policía Nacional. *El DNI se lo entregarán la semana siguiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-04-28','Ana: Llamada de Juan José, se encuentra un poco mal, ha tenido pinchazos en el pecho, dice que se está cuidando pero que tiene que dejar de fumar y necesita que alguien le ayude. *Le emplazo a pedir cita con el médico de cabecera, por si puede recetarle/recomendarle algún medicamento que le ayude. ·············· Por otra parte, sigue con la idea de administrar sólo su dinero. Le recuerdo que cuando nos remitan informe en que indiquen que es adecuado, probaremos con las retiradas quincenales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-04-28','Ana: Llamo al INSS-CC, P. Viudedad (927 620 056): en relación a la Resolución Aprobatoria de la pensión, me dicen que la BASE REGULADORA de la pensión de su esposo fallecido era muy bajita. **No obstante, no sabe por qué no se le ha mirado el complemento mínimos. Lo mirará y me llamará o escribirá. ······························································································································································································ Recibo correo de Antonia Mª Román Morgado (antonia-maria.roman@seg-social.es): "Buenos días de nuevo Ana. Revisado el expediente de María te informo que efectivamente no se le han reconocido mínimos ya que en la solicitud no ha declarado ingresos. Si ese campo queda vacío directamente el aplicativo no le calcula los mínimos. Es necesario, por tanto que solicitéis una revisión del expediente de viudedad aportando la declaración de ingresos. Si no hay ingresos se pone 0.00. Te adjunto las formas en que podéis presentar la documentación." ····························································································································································································· Mi respuesta: "Buenas tardes Antonia María, Claro, al carecer de ingresos lo dejé en blanco. Disculpad mi error. ¿Podrías decirme qué documento es el que tengo que presentar para solicitar la revisión del expediente? Y en cuanto a la Declaración de Ingresos, hay algún modelo específico en el INSS? Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2021-04-28','TERESA RECIBO LLAMADA DE INES DE PLENA ICLUSIN Y ME COMENTA QUE LA PIRMA DE JUANA LE HA REGALADO UN TELEFONO. NO SE FIAN MUCHO DE ESTE TIPO DE REGALOS YA QUE SIEMPRE ANDAN CON HISTORIAS CON LOS TELEFONOS, ME COMENTA INES QUE LE VA A PEDIR QUE FIRME UN PAPEL EN EL QUE ASEGURA QUE ESTE TELEFONO NO CONLLEVA NINGUN COSTE ADICIONAL PARA JUANA YA QUE ES UN REGALO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-04-28','miguel, recibo email de Alberto: Hace unos meses falleció MODESTA GARCIA PIÑERO, tutelada de la CTAEX y madre de FLORA GUTIERREZ GARCIA. Modesta era propietaria de una vivienda en C/ GABRIEL Y GALAN, 7 (BADAJOZ). Creo que Modesta tiene otra hija, evidentemente, hermana de FLORA. Los pongo en vuestro conocimiento x si considerais iniciar trámites HERENCIA. ********************************************************** mi contestación: Buenos días, según veo en la intranet el 5/1/21 hablaron con la Ctaex Rosa del CSS e iba a mandar la documentación relacionada con la testamentaria (certificado de defunción, etc) y veo que este mes habéis mandado la rendición de cuentas final que adjunto de la curatela de Modesta Garcia Piñero. Veo que Flora Gutierrez Garcia, es una de las dos hijas y tutelada nuestra 3/T/17. Viendo el dinero que ha dejado y teniendo en cuenta que se requiere autorización judicial para la aceptación de herencia, trámites de firma en notaria de adjudicación de herencia, posterior aprobación de herencia ante el juzgado y posterior puesta en venta de la vivienda (que también requiere previa autorización judicial y acuerdo con la otra hermana). Por tanto, si os parece buscamos un abogado de Plasencia que le tramite su parte porque no tiene derecho de abogado de oficio (viendo el inventario donde aparecen unos ahorros de unos 16.000€, y además en su última rendición de cuentas del 2019 tenía ahorrados casi 9000€).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2021-04-28','Ana: Llamo al INSS-CC, PFHC (927 62 00 27/28), en relación a la PGHC, no tienen cosntancia, no les aparece en el sistema ni como causante. **Dado que su P. Orfandad es de Clases Pasivas, a favor de familiares de militares, puede que la PFHC también lo sea. **Hay que llamar a MUFACE. ································································································································································································· Llamo a MUFACE (927 75 05 26) varias veces a lo largo de la mañana, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-28','recibo email de Alberto: Adjunto documento banco con embargo en CCC de Juan Carlos (la que compartía con su madre Rosa Galán Merino, tutelada y fallecida el pasado 07/04/201). Se trata de un embargo a nombre de ROSA GALAN de un JUZGADO y creo, confirmanoslo Miguel, que es x más de 9.000 €. Creo que esto agrava aún más esta situación. No se si este embargo puede afectar a Juan Carlos o a esta CCC en la que tenemos el PRÉSTAMO. Miguel, puedes averiguar esto con el Juzgado???. Quizás no sepan que ha fallecido la tutelada. *********************************************** mi contestación: Buenos días, a ver, tranquilidad, tanto la fallecida Rosa como su hijo unico Juan Carlos no pueden ser embargados en sus cuentas puesto que sus pensiones no llegan al SMI, por tanto lo más que pueden hacer es embargar los bienes de la madre (que creo que no tiene) y lo que sí tendríamos que hacer es renunciar a la herencia ante notario de la madre. De esa forma no podrían intervenir ningún bien de Juan Carlos. Mañana lo vemos en persona y hablamos con la notaria que venga mejor a Juan Carlos (preguntale Amalia) Por otra parte estoy a la espera que me llame inmobiliaria Colón (que me confirmaron que no habían vendido ningún adosado con las características de VPO que le comentábamos). Ya les he llamado 3 veces, a ver si me llama la que me dicen que lo llevaría. En otro orden, y aunque mañana lo veamos, comentaros que se puede hablar con el banco y decirle que no le vamos a seguir pagando, que hay que llegar a un acuerdo. (existe el Código de buenas conductas, quita del préstamo, posible carencia por 2 años de la deuda, etc) Mañana Alberto si quieres me das el número de teléfono y tanteamos las posibilidades (será más rápido que intentar vender por lo que ya estoy viendo). **************************************************** email de Amalia: Buenas , Miguel , la notaria que mejor vendría ahora a J. Carlos porque entiendo que él tendría que firmar algún documento , tendría que estar ubicada en D. Benito , está en el CAMP desde el día 21. Por otro lado , comentarte que el día del traslado, un primo suyo se llevó del domicilio la TV y el frigorífico, según él con el permiso de su primo Fco ( hno. de J. Carlos ) que dice ser el dueño de todo . Le escribí al hno. y le dije que necesitábamos la TV para J. Carlos , en el CAMP no tienen en las habitaciones y no tiene dinero para comprar otra . Al día siguiente llevó la TV al Servicio Social , mañana la llevan las compañeras de Futuex al centro . El frigorífico no lo devuelve hasta que le aclaremos su propiedad . Nos vendría bien si finalmente se alquila esa casa , pero tengo la duda sobre quién sería heredero de la misma . Por parte del padre Fco. renunció a toda herencia . Esa casa y el mobiliario cómo se repartiría ?? ************************************* Email de Alberto: Miguel, si le pueden embargar...acabo de remitirte el recibo. ********************************************************* email de Miguel: No pueden, mañana hablaré con ellos para que le devuelvan el dinero…Eso que hacen son rastreos masivos y se llevan de las cuentas el dinero que haya. Es importante que firmemos lo antes posible ante notario la renuncia a la herencia de la madre. El padre vive no? En caso contrario tendrías que decirme si dejó dinero o inmuebles. Pasos a dar por mi parte: 1.-Hablar con el juzgado para enterarme del nº de procedimiento 2.-Hablar con el OAR y remitirles un escrito adjuntándoles la renuncia a la herencia (en cuanto lo firmemos ante notario). Mientras hablaré con la notaria de Don Benito y remitiré nuestra documentación (sentencia de incapacitación y nombramiento para me confirmen que no necesitan autorización judicial y me den un día de firma. En cuanto sepa día y hora te lo digo Amalia) 3.-Hablar con el banco y decirles que no les podemos seguir pagando 4.-Ponerlo en venta en Inmobiliaria Colón 5.- Comunicar todo lo anterior al Juzgado. ********************************************************* email de Amalia: Buenas , Miguel , la notaria que mejor vendría ahora a J. Carlos porque entiendo que él tendría que firmar algún documento , tendría que estar ubicada en D. Benito , está en el CAMP desde el día 21. Por otro lado , comentarte que el día del traslado, un primo suyo se llevó del domicilio la TV y el frigorífico, según él con el permiso de su primo Fco ( hno. de J. Carlos ) que dice ser el dueño de todo . Le escribí al hno. y le dije que necesitábamos la TV para J. Carlos , en el CAMP no tienen en las habitaciones y no tiene dinero para comprar otra . Al día siguiente llevó la TV al Servicio Social , mañana la llevan las compañeras de Futuex al centro . El frigorífico no lo devuelve hasta que le aclaremos su propiedad . Nos vendría bien si finalmente se alquila esa casa , pero tengo la duda sobre quién sería heredero de la misma . Por parte del padre Fco. renunció a toda herencia . Esa casa y el mobiliario cómo se repartiría ?? **************************************************** Email de Amalia: Miguel , el padre falleció hace tiempo , acuérdate de las carpetas que te traje del domicilio con escrituras y demás documentación. Por eso ellos tienen tantos embargos , son deudas del padre. El otro hno. renunció a la herencia del padre , pero no se ha hecho nada aún con respecto de la madre , ni sabemos cómo actuará su hno. *************************************************** mi contestación: Entonces si os parece lo organizamos para que renuncie a ambas herencias. Necesitaré certificado de defunción y últimas voluntades de cada uno de ellos Miraré en el expte físico mañana a ver si están sino habría que pedirlos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-04-28','Ana: Llamo a la Oficina del DNI de CC (927 626 54), en relación a la expedición del DNI de Mª Rosario. Me indican que este tema lo lleva directamente el Subinspector Manuel Vasallo (927 629 092), pero en este momento ha salido. *Volver a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-04-23','Ana: Correo de Toni-Futuex: "Buenos dias Después de contactar con diferentes empresas de limpieza, las únicas que dan respuesta son limpiezas Adarve y Grupo Fissa; desde limpiezas Adarve (606 466 819) comentan que primero necesitan ver la vivienda para hacer valoración y crear el presupuesto, el coste de hacer dicha valoración son 60€, en caso de que luego se contraten los servicios lo descontarían del coste final. Por el contrario, Grupo Fissa, se acerca a la vivienda sin coste alguno y sin poner objeción, realizando la visita el día 19 y facilitando el presupuesto en el día de hoy, con un coste de 1039,25€, se adjunta documento de presupuesto, en documento a parte. Álvaro (responsable de limpieza, 672 021 472), comenta que una vez aceptado el presupuesto, en un máximo de 15 días realizarían la limpieza. Nos resultó un poco elevado, pero realmente la casa esta en unas malas e insulabres condiciones. En un primer momento el tutelado no estaba dispuesto a que nadie entrara en la casa, pero finalmente accedió, y creemos que colaboraria en el caso de que se llegue a efectuar la limpieza, suponemos que se haria en uno o varios dias, pero que no seria necesario en principio que el tutelado pernoctara fuera, aunque esto tendremos que consultarlo con la empresa si se llega a confirmar el presupuesto, para hablar con la pension de pueblo para una noche o dos. Qeudamos a la espera, del parecer del area economica, Gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-04-26','Ana: En relación al correo remitido por Toni el viernes (26/04), le contesto poniendo en copia a Alberto, Jefe secc. y Belén, secc. ecca.: "Buenos días Toni, Muchas gracias. A ver qué le parece a Alberto. Yo entiendo que aunque el precio es un tanto elevado, es necesaria hacer la limpieza y desinfección, y dadas las dificultades para encontrar empresa que se comprometa a realizarla y que llevamos más de un año ya detrás del servicio, habría que aceptarlo y hacerlo. Además, si tardamos mucho corremos el riesgo de perder el servicio de SAD asignado por la Dependencia. NO conviene demorarlo más. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-04-27','Ana: Correo de Alberto, Jefe de Secc. Ecca. en relación al presupuesto de limpieza del domcilio de Julián Ramón: "Hola OK a presupuesto. Pago de una sola vez a trabajo finalizado (si es posible)." *Belén contactará con Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-28','Ana: Correo de Raquel Pérez, TS del SSASB (ssasbrpa@gmail.com): "Buenos días Ana, perfecto, me mantienes informada. Mañana estaré pendiente de hablar con Esperanza, para cuando lleven al ayuntamiento los informes, adelantartelos por correo electrónico. Posteriormente te llegarán por correo, carta certificada. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-04-28','-Amalia : hablo con la TS de Aexpainba ( Alejandra ) sobre el caso . Es curatela esfera exclusivamente patrimonial y supervision salud. Huérfano de madre y padre desconocido . Tiene un hno. en Badajoz con una hija pero no tienen apenas contacto. Tiene contactos con una tia pero escaso , creen que por interes economico. Tiene P. orfandad , y en cuenta más de 30000€ según la TS . Una casa propiedad de la madre y la tia . Le explico el alcance de la curatela , le envio sentencia , le aclaro el tema del PADDI que habían consultado y quedmos a la espera de inventario para fijar presupuesto .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-04-28','Ana: Envío correo a Ana, TS Gerovida (gerovida2010@hotmail.com): "Buenas tardes Ana, Disculpa la demora en contestar. Tras haber consultado con los Asesores Jurídicos de la CTAEX, me indican que: Hemos recibido un Auto dictado por el Juzgado de Primera Instancia e Instrucción, nº 2, de Coria, por el que se dictaron medidas cautelares. Seguimos siendo Defensores Judiciales, no tutores, porque la sentencia por la que nos nombran, aún no es firme, por lo que no podemos aceptar el cargo, aunque si comenzar a actuar. Te envío adjunto dicho Auto con las Medidas Cautelares. *Ya se lo han pasado también al Jefe de la Secc. Ecca. para que comiencen a solicitar información bancaria y resto de datos y documentos para el Inventario. En cuanto a de qué cuantía puede disponer, entiendo que hasta que las compañera de la secc. ecca. no tengan acceso a las cuentas de Ángeles Justina Virtudes (tienen que incluir al Representante Legal en las mismas), ni conocimiento de ingresos, no se podrán fijar ni aprobar. *No obstante, por ir agilizando en lo posible, sería conveniente que fueseis elaborando un PRESUPUESTO DE GASTOS APROXIMADO (incluidos gastos de bolsillo) y enviándolos a la Atención de la secc. económica (ctutelar@salud-juntaex.es). Si queréis podéis ponerme en copia para que esté al corriente. Ante cualquier cuestión no dudes en contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-04-28','Ana: Tras intercambiar correos con Alberto y Juana, secc. ecca., envío el siguente a Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Buenas tardes Paula, En relación a la solicitud de gasto relativos a la Lápida de los padres fallecidos de Flora. Alberto me ha comentado que en principio, como poder, puede asumirlo, pero si sumas el IVA es bastante dinero y la cuenta se quedaría después un poco ajustada… Dado que se pretende desde la CTAEX iniciar los trámites de la herencia de la madre, me proponen, y a mí me parece buena idea, esperar a que esté resuelto lo de herencia y planeárselo entonces a también a su hermana para que asuman el gasto de la lápida entre las dos. ¿Podrías hablarlo con ella e indicarnos qué le parece (a ella y a vosotros)? Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-04-29','Ana: Pongo para la firma del D-Gerente la Declaración Jurada para el Derecho a Mínimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-04-29','Ana: Recibimos, remitido por Asindi, Consentimiento Informado para Intervención Quirúrgica Programada, "Exéresis de la 1ª uña de la mano derecha". *Lo pongo para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-04-29','Ana: Llamo a la MAP, Raylin Pinales (927 567 270): acudieron al domicilio pero no dieron con ella. *Han acordado desde el Ayto. en avisarla cuando la vean por la calle, les ha dicho que da igual la hora que sea, que la llamen y acudirá. Por lo poco que ha podido ver del domilicio, expresa que las "condicones de higiene son lamentables". **Cuando vaya a verla activará el 112 y pedirá que acuda la Guardia Civil. Una vez se la hayan llevado ella redactará los informes. **Le indico que lo ideal sería que mientras permanezca en la UHB, le asignen plaza residencial, para que cuando le den el alta la trasladen directamente a la Residencia y no vuelva a su casa. Para ello necesitamos agilizar la solicitud de plaza por emergencia social, siendo requisito aportar sus informes. ······································ Informo mediante mail a Raquel, TS SSASB. ················· Respuesta de Raquel: "Perfecto. Cuando pueda Esperanza me llamará y la pongo al día del asunto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-04-29','Ana: Conversación con Carmen, TS del SSASB-Coria (927 50 80 00 Ext: 318): La sobrina de Emilia le ha preguntado por las deudas con la Comunidad de Propietarios, indicando que se podrán sufragar los gastos poco a poco. Le indico que sé, por las anotaciones que hay, que los compañeros jurídicos ya han contactado con el Administrador de fincas. *Le facilito el contacto de Ángel y Miguel, Asesores Jurídicos CTAEX. *No obstante, le digo que ellos ya habrán pasado la informació a la Secc. Ecca., desde donde se irán realizando los pagos pendientes conforme se vayan pudiendo asumir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-04-29','Ana: Llamo al Subinspector Manuel Vasallo (927 629 092): Me comunica que la semana que viene, cuando acuda la Ud. Móvil al Ayto. de Coria, acudirán también a visitarla a ella a la residencia para la expedición del DNI. Pero les falta la fotografía. **Pediré ahora mismo a la Residencia que se la envíe. ···················· Llamo de Sandra, TS Residencia de mayores de Coria (927 508 000 - Ext.: 283), como no obtengo respuesta, le remito correo-e: "Buenos días Sandra, Te estoy llamando, pero estarás ocupada. He hablado con el Subinspector de Policía de la Oficina del DNI de Cáceres de la Policía Nacional. *Intentarán ir la semana que viene, cuando acudan al Ayto., a la Residencia vuestra también para expedir el DNI a Mª Rosario. Pero NECESITAN YA LA FOTOGRAFÍA para el DNI. ¿Podríais remitirla por correo postal urgente lo antes posible a la siguiente dirección?: Oficina del DNI – Dirección General de la Policía Nacional A/A: Manuel Vasallo - Subinspector Av. Pierre de Coubertin, 13, 10005 Cáceres Esperemos que llegue a tiempo. La necesitan antes del día 5 de mayo. Ya me dices. Gracias y un saludo." ·························································································· Respuesta de Sandra, TS: "Buenos días Ana, mañana viene el fotógrafo a hacerle las fotos y las mando a Cáceres a la dirección que me has dado. Gracias y un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-04-29','miguel, llega recepción de autorización de derecho de imagen de Fiscalía de Cáceres (Carmen Barquilla)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-04-29','miguel, respuesta de Iciar: He vuelto a hablar con la clínica dental para que nos envíen factura, me comentan que han tenido algún problema con el correo y por eso no lo han podido enviar. (ya les he llamado varias veces y escrito correo, me voy a volver como Damián!!!) Por su parte no hay ningún problema, y no se debe mucho dinero solo una extracción, en fin… Lo de la declaración lo lleva Juana, ya se lo comento ***************************************************** llama Damian que reenviará varios informes médicos que no ha enviado y me pide traslade a Alberto e Iciar lo siguiente: Buenos días, me ha llamado Damian hoy y me comenta os traslade que le recuerdan desde la clínica que debe mucho dinero para que lo abonemos. También quiere que habléis con la gestoría que le hizo la declaración de la renta para que se la haga de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2021-04-29','TERESA ME INFORMA M FERNANDA TS DEL SSB QUE CARMEN DE NUEVO ESTA INGRESADA EN LA UHB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2021-04-29','miguel, me llama Soledad Olmos del Colegio Ntra Señora de la Luz para decrime que esta tarde se firmará la venta en la notaria de Badajoz donde la curatelada es una de los 3 vendedores. Pregunto por email a Jesús Lara (asesoría mediador) pero no me aclara demasiado, ya que le insto a que informe sobre las condiciones de la venta y me indique quién es el trabajador de la notaria que está elaborando la escritura. Al no concretarme nada, llamo a la notaria de Timoteo Diez Gutierrez de Badajoz y hablo con Antolina que me da su email y me confirma que se venderá en 5.00€ sin saber aclararme la forma de pago, ni poder facilitarme teléfono de contacto del comprador. Llamo al cuñado de la curatelada (teléfono que hay en la intranet) y me da el teléfono del hermano de la curatelada (Juan Fco 617-836710) quién me indica que los papeles ya no los lleva la asesoría de Jesús Lara, y que él y el comprador son los que están entregando la documentación en la notaria. Me confirma que la forma de pago es una transferencia que se hará en su cuenta personal y que tras la firma él hará el ingreso en la cuenta de sus otros dos hermanos. Le explico que ya he remitido la sentencia de incapacitación, y nombramiento de curadores a la Comisión Tutelar de Adultos, al tiempo que le aviso que hasta que el dinero no esté en la cuenta de la curatelada no procederé a firmar la ratificación de la venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2021-04-29','miguel, envío al Colegiod e abogados de Cáceres, autorización para comprobación de datos económicos telemáticamente **************************************** El abogado asignado es Jos Luis Martín Sanchez (c/Sorvalentina Mirón nº25, Badjo, Plasencia, tlfno 927-424452)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-04-29','Ana: Llamada de Lucía, TS de la Residencia El Conquistador de Trujillo (660 963 767) en relación a Félix, tutelado recientemente por la CTAEX. *Están tramitándole la Prestación Vinculada al Servicio Residencial y Toñi, de la Gerencia Territorial de Cáceres (927 00 42 00) le ha dicho que necesitan la Declaración de la Renta. ······ Por otra parte, llegaron a un acuerdo en su día con el SSASB para ingresar antes de ostentar la Tutela en la CTAEX en dicha Residencia, cobrándole sólo 1050€ (en lugar de lo que re corresponderíar por cuidados a Gran Dependiente Grado III. Le cobrarán esa cuantía hasta que se le conceda la prestación vinculada. ·············· *Presenta Deterioro Cognitivo. *Ultimamente está teniendo mareos y su MAP cree que pueden ser microictus. ·························································································································································································· Llamo a Toñi Jabato, Gerencia Territorial de Cáceres (927 00 43 70), me comunica que este Sr. es INCUMPLIDOR con HACIENDA según les salta en el sistema, por lo tanto no pueden hacer el cálculo. **Necesitan que presentemos la DECLARACIÓN DE LA RENTA DE 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2021-04-29','Ana: Llamo a MUFACE (927 75 05 26) varias veces, sin respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-04-29','Ana: Tras ver notas de seguimiento y fotos de la vivienda de Antonio (Insalubridad y sin condiciones mínimas de habitabilidad) llamo a Toni-Futuex. Elaborarán y firmarán un informe y solicitarán otro a la TS del SSASB, para poder ponerlo en conocimiento del Jdo. así como solicitar ampliación de la Tutela de Ingreso en Centro Adecuado. ···························································································································································································· Correo de Toni-Futuex: "Buenas tardes Ana, tal y como hablado antes, te extracto, lo ulitmo que teniamos subido a la herramienta del tutelado Antonio Hidalgo Romo, pendiente de que la compañera haga un nuevo informe y más pormenorizado. El lunes irá para Alcúescar. Te adjunto también la cartilla bancaria que este le mostró en la primera visita, de la que no tengo constacia absoluta si esta tutelada dicha cuenta, estaba a cero cuando se la enseñó y es la que se utilizó para poner la prestación de SEPE, que se nos ocurren? dos posiblidades, que bien este cobrando la prestación porque le haya entrado por ahi y no diga nada o bien que no este cobrando nada y este viviendo de algun trapicheo como sospechamos, ya que al parecer la PNC le debe entrar por una cuenta distinta a la que adjunto no? La compañera habló con la ts de la localidad y le dijo que avisaria a la policia local para que estuvieran al tanto de el, si anda en algun lio y demas. Al respecto de algun tipo de ingreso, ratificar que tendra que ser involuntario, ya que no accedió ni a que se le viese en salud mental ni nada, no quiere ningun tipo de control. El lunes cuando vayamos hablaremos con la ts para indicarle que seria bueno que ella hicera un informe tb, de cara a comunicarlo al juzgado, si no esta de acuerdo o no le parece, te lo comentare para que se lo puedas solicitar por escrito. Y Gloria, hara con la informacion que recabe y la que se tiene un informe mas completo, adjuntando las fotos tal y como hemos quedado antes. -- 25,26 y 29/03/2021 Asunto prestación por desempleo: El día 25 se acude a la cita que se solicitó en el SEPE, se consulta el modo de proceder del tutelado para poder cobrar la prestación y la posibilidad de realizar los trámites por internet. Comenta que si no tiene aceptado el paro o ha realizado alguna actividad, durante su estancia en prisión, que le aporte dicha compatibilidad, primero debe inscibirse como demandante de empleo, en caso de no estarlo y una vez se tenga la tarjeta de demanda, se debe esperar un mes para poder solicitar el subsidio. El día 26, se contacta con la trabajadora social, se le pide a María que averigüe si Antonio está inscrito como demandante de empleo, se le comenta lo indicado en el SEPE, para que comprenda la urgencia de la situación. María comenta que tiene prevista una visita, se lo consultará y lo comunicará. Se le dice que, aún así, se hará la presolicitud por internet, por si se pudiese ir adelantando algo. El día 29, se realiza la presolicitud de la prestación por desempleo, vía internet, tal y como indicaron en el SEPE, por si cabe la posibilidad de poder adelantar el trámite. María contacta para comunciar que Antonio ha indicado que no está inscrito como demandante, se le dice que se intentará gestionar sin hacerle ir a Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-04-29','Ana: Recibo llamada de Critina, TS del ESM - Trujillo (CAR Trujillo. De momento no hay novedades. Buscará número de familiares y tratarán de contactar, por si podemos indagar por ahí. Seguiremos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-04-30','miguel, recibo email de Alberto: Miguel: te adjuntoa el correo de ANA, porque tambien debemos tener en cuenta el temas de las joyas que aún están en poder del CSS. Buenas Alberto, ¿recuerdas que hablamos de este tema? Como puedes leer a en el correo de Icíar, le han preguntado. Finalmente no hicimos nada, no lo teníamos claro e ibas a consultar mejor a los jurídicos… la primera consulta con Miguel, dijo que había que hacer un inventario ante notario en el C. Sociosanitario, o algo así… Precisamente hoy has enviado el correo en relación a la Herencia por la madre fallecida, y como sabéis hay una hermana que vive fuera. Hay que añadirlo al tema en cuestión para abordarlo y darle solución. Yo no sé qué hay que proceder. Hablamos. Un saludo. Por un lado, creo que debemos hacer lo más rápidamente posible el tema de la herencia y por otro, o bien le pedimos al CSS que mantenga la posesión de las joyas o buscamos otra alternativa que no nos genere mucha inversión de tiempo y esfuerzo ******************************************************** Mi respuesta: Buenos días, esta cuestión lo que os comenté es que enviaramos a alguien para que junto a sus herederos abrieran al mismo tiempo la caja o donde se encuentren las joyas (para que no haya mal entendidos, y lo que sea la parte de la tutelada habrá que guardarlo en la caja fuerte (como se viene haciendo no?) No veo otra opción ya que este tipo de cosas, el ajuar, no entran dentro del reparto, oficial (escritura de adjudicación de herencia) por ser bienes de poco valor (salvo que hubiera por ejemplo un cuadro de Picasso, etc)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-04-30','miguel, recibo email de Juana: Os adjunto el borrador que he redactado para solicitar la carencia en Ibercaja en relación al préstamo de Rubio Galán... Compi Miguel, como no pudimos hablar el otro día, te comento que estuve hablando con el Director de la oficina y le expliqué todo.. me dijo que lo pidiéramos por escrito porque lo tiene que elevar a la entidad, no puede solucionarlo a nivel de oficina... Si me dais el visto bueno, lo mando hoy mismo... ************************************************** Buenos días, lo veo perfecto, envíalo. Yo moveré a apartir de hoy la renuncia de herencia de los padres. En cuanto a la inmobiliaria ni me llaman ni se les espera (ya les llamé 3 veces…) *************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2021-04-28','Ana: Recibimos correo-e de Rosa, CSS-Plas.: "Os adjuntamos Auto de Notificación que ha sido entregado a Margarita Anticha y firmado con el Psicólogo Clínico (como Centro -guardadores de hecho-). Por parte del Centro se han tomado las medidas oportunos para que se cumpla la orden de alejamiento." *Adjunta el Auto: Orden de Alejamiento para LUIS ALFONSO GÓMEZ DELGADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-04-28','Ana: Correo de Toni-Futuex en respuesta al mío: "La compañera habia quedado ahora a ultima de la mañana, para ir a la casa y explicarselo, luego paso nota pormenorizada, pero por telefono el yerno, a terminado tarifando... que eso era muy poco, que ellos le habian adelantado un dinero y etc etcc (te puedes imaginar) No obstante le hemos explicado y asi lo haremos en persona con la tutelada y la hija, que es una decesión en firme tomada por el area economica, fundamentada en los pagos pendientes y deudas que tiene la tutelada, que no hay otra opcion. Asique nada, luego te cuento!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-04-30','Ana: REGISTRO DE ENTRADA en el ORVE, la Declaración Jurada para el Derecho a Mínimos en la Prestación de Viudedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-04-30','Ana: Entrego a Julio, para que den Registro de Salida y envíen a ASINDI Consentimiento Informado para Intervención Quirúrgica debidamente firmado y sellado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-04-26','Ana: Corre de Alberto, Jefe Secc. Ecca., para Icíar y para mí: "Hola ICIAR: • AVERIGUAR CONSUMOS TENIENDO EN CUENTA TEMAS DE AYUDAS (SABES ALGO ANA???...SE LO CUENTAS A ICIAR) • AVERIGUAR SI TIENE SEGURO DECESO. SI NO DISPONE...SE LO PASAS A CORAL. ICIAR-DENTISTA: • ANA: SI ACEPTAMOS PRESUPUESTO DENTISTA NOS FUNDIMOS LA TOTALIDAD DE SUS AHORROS. (BIEN ES CIERTO QUE NO ESTAMOS TENIENDO EN CUENTA LOS INGRESOS QUE PUEDA TENER PROCEDENTES DE LA ADMINISTRACIÓN X AYUDAS AL ALQUILER). SOLO NOS METEMOS EN ESTO SI DAS TU OK. • ICIAR: SI ANA DA OK, SE ESCOGE PRESUPUESTO MÁS BARATO (COINCIDE CON EL QUE LE GUSTA AL TUTELADO): HABLAS CON DENTISTA Y ACLARAS TOTALMENTE EL TEMA DEL PAGO. ESTAMOS EN DISPOSICIÓN DE HACER EL 1º PAGO EN SU TOTALIDAD Y EL 2º PAGO DEPENDERÍA DEL MOMENTO." ···················································································································································································· Mi respuesta: "Buenas tardes, Entiendo que es un tratamiento necesario y que habrá que realizarlo, por tanto, por mi parte Ok. Ya iremos viendo luego cómo reajustar gastos si fuera necesario…. En cuanto a la Ayuda de Alquiler, lo desconozco y en el expte. digital no hay nada al respecto… consultaré el de papel y ya os voy diciendo si averiguo algo. Hasta mañana!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-04-30','TERESA Finalmente se ha decidido que se va a intentar trabajar con él, pero en el caso de que la situación se complicara os avisaríamos. El precio establecido sería de 1850,46 € ( I.V.A. incluido. Si finalmente decidís que ingrese en el centro, me lo comunicas y te envío la información y documentación necesaria. también te puedo enviar más información del centro. Y si necesitáis algo más, no dudes en llamarme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-04-30','TERSSA Destacar que tanto desde el área de psicología como del servicio de Centro Ocupacional y de Residencia se ha establecido un plan de apoyo conductual positivo y de modificación de conductas sin obtener resultados satisfactorios. En las últimas reuniones multidisciplinares mantenidas se concluye que a pesar de la elevada capacidad que la usuaria tiene en todas las habilidades adaptativas se niega a desarrollarlas resultando muy difícil avanzar en la consecución de los objetivos propuestos. No conozco de primera mano la situación sociofamiliar de su familia y su entorno, así como, las causas que motivaron el ingreso de Libertad en un centro pero, considero preciso analizar otras alternativas que posibiliten su desarrollo personal y social pues su permanencia en el centro en los momentos actuales solamente propician su estancamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-04-30','TERESA NOTA FUTUEX pasado 26 de Abril se acompañó a Ramón González Hernández, que vive en la calle Toledillo Bajo, 3 de Jerez de los Caballeros, a los juzgados para que declarara en calidad de investigado. Un vecino de su localidad le había denunciado por haber intentado robar un perro suyo y en el proceso lo había matado. Cuando se llegó a los juzgados se subió a la primera planta que estaba la sección de lo penal y se habló con el personal administrativo. Allí comentaron que iban a llamar al abogado de oficio que estuviera de guardia para que acompañara a Ramón durante su declaración en la sala de vistas. Cuando llegó la abogada de guardia, estuvo conversando un rato con Ramón y luego con la delegada del equipo social comunitario. Al cabo de una hora, pasó a declarar la parte denunciante, y cuando acabó, llamaron a Ramón para que pasara a la sala, permitieron que entrara con él la delegada de apoyo por si Ramón se ponía nervioso y había que calmarlo un poco. La jueza le hizo una serie de preguntas a Ramón sobre el denunciante, si le conocía o si tenía una buena relación con él. Ramón comentó que es vecino suyo desde hace muchos años y que siempre se han llevado bien. La jueza preguntó al tutelado si él se había llevado un perro del campo del denunciante a lo que Ramón contestó rotundamente que no, y dijo que eso se lo había inventado su vecino porque él no roba a nadie y menos mata a perros durante el proceso porque él ama a los animales. Seguidamente la abogada le hizo una serie de preguntas relacionadas con el día de los hechos, a lo que Ramón respondió que pasó todo el día en el campo y luego estuvo en su casa con su madre, atendiéndola, no estuvo en ningún otro lugar. Cuando Ramón terminó de declarar, la jueza le hizo unas preguntas a la delegada del equipo social comunitario sobre la enfermedad mental del tutelado, su pauta de medicación y su comportamiento en la vida diaria. Cuando salieron de la sala, el personal del juzgado les comentó que podían marcharse, y les dijeron que a Ramón le llegaría una carta para informarle de que o bien se había archivado la denuncia o bien seguiría su curso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-04-30','TERESA NOTA FUTUEX La consulta es con la trabajadora social del CEDEX (Sila). Aunque no posee red social de apoyo, que es requisito muy importante en el tratamiento ambulatorio, valoran las posibilidades de intervención con el tutelado decidiendo el equipo profesional del CEDEX iniciar la intervención dándole de alta la trabajadora social ese mismo día, creándole historia clínica con número de historia (1523), añadiendo en la misma sus datos personales, familiares y profesionales. Al existir consumo de alcohol y cocaína debe ir a controles de orina todos los lunes. En horario de 9:00h a 13:30h, si no acude a estos controles se considera como positivo. Al tener que desplazarse a Castuera esto supone un gasto extra de 20 euros por el servicio de taxi, es decir, 80 euros aproximados al mes. Los viajes realizados el 18 de marzo, el 16 y 19 de abril se han cubierto sin problemas con las retiradas estipuladas quincenalmente. Como se le acompaña a las retiradas nos encargaremos de guardarle el dinero para el taxi o bien pagar al taxista varios viajes juntos como fue el caso. Desde el CEDEX la trabajadora social consigue localizar a Inma (trabajadora social del Equipo de Salud Mental de Don Benito), le indica que están gestionando los trámites para pasar el expediente de Pedro Tomás a esa área, pero aún tiene programada la cita de psiquiatría en Mérida, siendo el día 18 de mayo a las 11:20 horas de forma presencial. Refiere que no existe cita en el área de Don Benito antes. Desde el equipo valoramos la dificultad de asistir a Mérida, ya que las comunicaciones desde su localidad son muy limitadas y el taxi le va a suponer un gasto extra elevado. La psiquiatra que le corresponde en Don Benito es Rosa Merchán. El próximo 4 de mayo a las 11:00 horas le vuelven a citar en el CEDEX para la valoración inicial por el médico. A la consulta también debe ir acompañado, nos indican que la información del tutelado solo no la pueden facilitar personalmente en las consultas debido a la confidencialidad. Se solicitará previamente a su médico de familia, la analítica general donde le realicen la prueba de la tuberculosis, VIH, hepatitis B y C. A esta cita se le acompañara desde el equipo, ya que tendran tambien que retirar dinero y hacer compra por ser principios de mes. Los objetivos planteados son iniciar protocolo para ingreso en la unidad de desintoxicación (Plasencia) a la cual el tutelado ingresa voluntariamente, el tiempo estimado para el ingreso es aproximadamente un mes y tras el alta seguir tratamiento ambulatorio en el CEDEX de Castuera (el riesgo de recaída es alto al no tener apoyos sociales y/o familiares), hasta la fecha de ingreso todos los lunes tiene que asistir a los controles de orina. Desde el CEDEX estarán en coordinación con el equipo de Salud Mental al ser protocolo por patología dual. Antes del ingreso en Plasencia debe realizarse una PCR. Al estar tutelado, indican que desde Comisión tutelar se realice un documento donde se accede y recomienda que es adecuado iniciar con el tutelado el protocolo de ingreso en el centro de desintoxicación de Plasencia y tras el alta seguimiento ambulatorio en CEDEX Castuera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-04-30','Ana: María Glez. Barroso, TS de ASPACE (maria.gonzalez@aspacecaceres.es) envía presupuesto para ropa (reenvío a Alberto) y consulta para Programa de Apoyo Comunitario (Futuex). ························· Envío correo-e a Toni-Futuex: "Buenos días Toni, Desde ASPACE Cáceres, me pregunta en un correo por el “programa de acompañamiento semanal”, jajaja. Como se ha derivado a Brahim, en la otra localidad, preguntan también para otro joven tutelado. La idea sería prestar el mismo apoyo, hacer seguimiento pero sobre todo sacarlo a pasear principalmente y otros posibles apoyos puntuales. Entiendo que no es el objetivo principal de vuestro programa, pero yo no lo veo mal y así tendríais otro usuario más dado de alta. Se trata también de es un chico con gran dependencia que necesita muchos apoyos. Nombre: Santiago Eduardo Mayoral Suárez (responde a Santi). Tienen 20 años. Presenta: RETRASO MENTAL GRAVE + PARALISIS CEREBRAL Residente de ASPACE CÁCERES. Calle Acuario, 2, 10001 Cáceres Teléfono: 927 23 47 68 Persona de contacto: María Glez. Barroso, TS de ASPACE (maria.gonzalez@aspacecaceres.es) Ya me confirmas, yo de entrada cuento con ello. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-04-29','Ana: Correo-e de Paula, TO CRR_Plas.: "Hola Ana, comentarte que las hermanas de Flori sufrieron malos tratos por parte de su madre, por lo que no querían tener ningún tipo de contacto con ésta. Con esta situación dudo que puedan estar interesadas en compartir los gastos de la lápida. No sé si la parte económica revisó el desembolso de 2000 euros de la incineración de la madre de Flori, puesto que Flori nos asegura que ambas tenían seguro de decesos y habría que asegurarse que no se ha pagado dos veces (a través del seguro y otra vez a través de la cuenta compartida de Flori y Modesta) la incineración. Por favor cuando lo sepáis me decís, puesto que para Flori es importante poder poner la lápida y si los 2000 euros hubieran sido un error no habría problema en poner la lápida. Un saludo." ······························ Agradezco a Paula la información y lo reenvío al Jefe de la Secc. Ecca. y a Juana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-04-30','TERESA RECIBO LLAMADA DE BEATRIZ, ESTE DE PASE EN CASA DE SUS PADRES ME COMENTA QUE NO QUIER IR A PISO QEU SE QEUIRE IR A VIVIR CON SUS PADRES Y ME INSISTE EN LA RECURPERACION DE SU CAPACIDAD LE CONVENZO PARA QUE VAYA A PISO UNA VEZ RECIBA EL ALTA PARA QUE TERMINE DE RECUPERARSE Y MAS ADELANTE VEMOS ME SOLICITA QUE LA VISITE LA DELEGADA TUTELAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-04-30','TERESA ME LLAMA ANA PARA COMUNICARME QUE HAN RETIRADO LA DENUNCIA QUE HABIA CONTRA NATALIA Y POR LO TANTO SE ARCHIVA LA CAUSA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='SANTANTON'and apellido2='GOMEZ'),'2005-04-21','Discapacidad del 71%. La pensión (PNC por invalidez) la cobra por Banesto en Valverde de Llerena. Nº de cuentq: 0386984273. Solicitar todo lo general y solicitarle un Centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2021-04-29','email de Tony: Buenas tardes adjunto nota de seguimiento Jesús Ramos Ramos Bargon, adjunto También la notificación del juzgado. Se realiza seguimiento presencial en el domicilio del tutelado y explica que ha recibido una notificación del juzgado (la cual se adjunta a esta nota) mediante la cual se le reclama la cantidad de 1273,72 € y tiene un plazo de 20 días (lo recibió el pasado 14 de abril de 2021) para abonarlo o realizar reclamaciones. Según cuenta el propio tutelado, es de una tarjeta que contrato en Carrefour hace años y los recibos han sido devueltos, el cree que se devolvieron porque su padre cancelo la cuenta a la estaba asociada dicha tarjeta. Se adjunta copia escaneada para que se abone o reclame dicha deuda según se estime oportuno desde el área económica y/o jurídica de la Comisión Tutelar de Adultos. El tutelado expresa que lo más adecuado es que se abone la deuda ya que según dice hay más de 3000 € en la cuenta, se le recuerda que serán los responsables del área económica quienes deben decidir el procedimiento más adecuado. Con respecto al resto de áreas acude aseado como es habitual, y se muestra bastante más agradable que en la mayoría de la visita previa, acude con carácter conciliador y realiza la petición de forma adecuada. Insiste en que necesita información para la revocación de su curatela y que debe ser la CTAEx quien se la proporcione, por lo que solicita que se establezca contacto con él. (A esta petición, como es lógico, no le hacemos mucho caso) ****************************************************** Buenos dias, vuelvo a enviar esto porque tiene un plazo y el tutelado está además muy demandante llamando cada dia , para preguntar si se ha abonado ********************************************** Alberto contestación: Ángel/Miguel: no hemos hecho nada al respecto, ni teníamos conocimiento hasta ahora. Xfa, indicádnos si tenemos que pagar esto, como (nº CCC y concepto) y a quién. El tutelado está muy alterado con esto, ya le conoceis, verbaliza que hay que pagar y que si no lo hacemos se pondrá en contacto con el juzgado. Ya me decís. En caso afirmativo Iciar pagará mañana. ****************************************** Según veo, le están reclamando unas cantidades por un préstamo que firmó en agosto de 2013, sin embargo, en esa fecha ya se encontraba incapacitado para administrar sus bienes, la sentencia es de septiembre de 2012. Por este motivo, enviaremos escrito al Juzgado para considerar nulo el contrato firmado, al no intervenir en la firma del contrato sus padres, que en aquella fecha tenían rehabilitada la patria potestad. ****************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-04-30','miguel, llega por email del abogado Jesús Bueno, resolución de firmeza de aprobación de herencia y autorización de venta. Se lo reenvío a Ainés y a la abogada Ana de Pablo. Le indico en email a Jesús que envíe la minuta a la Att parte Económica la minuta con copia a mi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-04-30','miguel, email de Belén: Buenos días, compi!!!! Solo para que sepas el seguimiento, comentarte que en la carpeta de propiedades de Carmen Leal Benito, he puesto email que ha enviado Toni(Futuex) relacionado con la vivienda de alquiler. Genial con el escrito que hemos enviado al ayto., puede incluso que haya ocupas!!. seguimos ********************************************************** email de Amalia: Buenos días , adjunto información que envian desde Futuex de un piso que Carmen alquiló por su cuenta , sin consultarlo con esta Comisión a pesar de que ya se le habia advertido que no lo hiciese. Ya le pasó con otro piso que tuvo . Se le envió un burofax a la inquilina y tras varias visitas se marchó del piso debiendole meses de alqulier . Luego la vendió , acuerdate Angel , creemos que en la inmobiliaria la estafaron , no sabemos ni por cuánto la vendió ni dónde está el dinero si es que se lo dieron . Fui a la inmobiliaria en cuestión y habian cambiado el nombre , me dijeron que volviese y cerraron literalmente la agencia . Ahora tiene el mismo problema , los inquilinos no le han pagado y ahora hay otros que no saben ni quienes son . Os lo envio por si se puede hacer algo juridicamente . **************************************************** mi email: Buenos días , adjunto información que envian desde Futuex de un piso que Carmen alquiló por su cuenta , sin consultarlo con esta Comisión a pesar de que ya se le habia advertido que no lo hiciese. Ya le pasó con otro piso que tuvo . Se le envió un burofax a la inquilina y tras varias visitas se marchó del piso debiendole meses de alqulier . Luego la vendió , acuerdate Angel , creemos que en la inmobiliaria la estafaron , no sabemos ni por cuánto la vendió ni dónde está el dinero si es que se lo dieron . Fui a la inmobiliaria en cuestión y habian cambiado el nombre , me dijeron que volviese y cerraron literalmente la agencia . Ahora tiene el mismo problema , los inquilinos no le han pagado y ahora hay otros que no saben ni quienes son . Os lo envio por si se puede hacer algo juridicamente . ********************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ZANCA'and apellido2='SANDIN'),'2021-04-30','Ana: Con respecto a este nuevo cargo, Icíar, secc. ecca., que está conformando el inventario, me informa que hemos recibido Certificado Negativo tanto de PNC como del INSS. *Como aún no tenemos acceso a las cuentas, tampoco podemos mirar movimientos bancarios. ················· Llamo a Emilia, TS del CSS (24205), pues según Informe Social, percibe una PNC. Consultará y se pondrá de nuevo en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-04-27','Ana: Recibo llamada de Alma, Enfermera de la Residencia (699 929 953). Rosa presenta una úlcera váscular por un golpe que se dió. Hay un medicamtento, que aunque es un poco más caro, favore y acelera la curación de las mismas. *Enviará informe y presupusto de farmacia. *Por mi parte, si el medicamento es asumible, doy el ok al presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-04-30','Ana: Llamo a Maite, TS del C. Penitenciario de CC (927 181 407): con respecto a la cita programa en el ESM de CC, para el día 10 de mayo a las 8:50 h. me dice que no sabe si le están haciendo segumiento en Prisión de Salud Mental. *Me indica que llame al Servicio Médico de Prisión: 927 18 10 52. Llamo y el Dr. que me atiende dice que se puede anular esa cita, pues le atenderá la Psiquiatra en prisión, a través de Telemedicina. Pasa consulta una vez al mes. *No sabe si le atnderán en mayo o junio. **Para solicitar informe hay que hacerlo por escrito al fax: 927 18 11 50. ·························································································································································································· Llamo a Jesús, Admvo. del ESM-CC (54600): Anulo la cita de Psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-05-03','Ana: Correo de Sonia Bernabé, ASINDI, el viernes por la tarde: "Hola Ana, quería informarte que Aaron Rosado está ingresado, desde anoche, en la unidad de Salud Mental de Cáceres. Ayer tuvo conducta agresiva principalmente hacia una de sus compañeras a la que agredió y tiró del pelo. Un profesional les separó rápido, pero se vivió un momento muy tenso para todos. Las compañeras tuvieron que llamar al 112. Aaron lleva, desde su último ingreso en Salud Mental, 2 semanas en el centro, y una de ellas en aislamiento. Hay parte de las lesiones hacia su compañera. Es una situación que nos preocupa mucho. El lunes mi compañera hablará con el psiquiatra que le hace el seguimiento en Salud Mental para ver cómo evoluciona. Os iré informando. Un saludo," ·················· Respondo: "Buenos días Sonia, Espero que estés bien. Acabo de leer tu correo, la verdad es que es una situación complicada. Por favor, comunicarlo de nuevo, si no lo habéis hecho ya, a la Unidad de Programas Asistenciales. Informarle también del parte de lesiones. Ya me vais diciendo cómo va evolucionando Aarón. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-05-03','Ana: Recibo correo-e de Alma, Enfermera de la Res. San Pedro (enfermeriaspa@valenciadealcantara.es): "Buenos días; Como comentamos telefónicamente, adjunto informe de la unidad de enfermería así como ficha técnica del fármaco: "Iodosorb polvo", el cual no entra por seguro médico pero es necesario para las curas de la residente. Rogamos la valoración de la autorización de compra del mismo, ya que supondría una mejoría en su estado de salud así como la mejor evolución de la úlcera vascular. Sin más quedamos a su disposición. Unidad Enfermería Residencia San Pedro de Alcántara" ················ Se lo reenvío a Alberto, Jefe de Secc. Ecca., dando mi visto bueno a la compra. ······························································································································································································ Correo-e de Alberto, jefe secc. a Belen, secc. ecca: "Hola Belen. OK a la compra del medicamento que nos pasa Ana. Hablas con el centro y cierras con ellos el tema del pago. Y LES PIDES UNA ESTIMACIÓN ECONÓMICA APROXIMADA. ya que no han enviado el precio del medicamento, ni la previsión temporal de utilización."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-05-03','Ana: Tras recibir llamada de May, Jefa de Secc. RR. Mayores (68496), diciendo que han concedido plaza en R.Mayores Conventual San Francisco de Plas. (donde solicitón Isabel en el 2016) llamo a José, Director de la Residencia de Jaraicejo (608 962 782): al parecer Isabel hace tiempo que cambió de idea y ya no quiere trasladarse de centro. No obstante va a hablar con ella después del desayuno al respecto para corroborarlo. Me volverá a llamar. ······························································································································································································ En cuanto a la Sentencia, en la que absuelven de los delitos leves a Isabel, pero acuerdan como medidas cautelares la prohibición de aproximarse a menos de 100 metros de la otra Sra. durante 6 meses, así como a residir en la misma localidad, ante la que os Asesores Jurídicos CTAEX enviaron un escrito solicitando cumpla la medida en la residencia en que resida. Miguel, Asesor Jurídico, llama al Jdo.: **La otra parte ha interpuesto RECURSO ANTE LA AUDIENCIA PROVINCIAL, pero aún no hay resolución. *Ahora está parado el proceso mientras no haya resolución. ·························································································································································································· Vuelvo a hablar con José, Director del centro y hablo también con Mª Jesús, TS del SSASB: **Puesto que no podemos obligar a Isabel a cambiar de recurso residencial, permanecerá en Jaraicejo, donde está totalmente adaptada. ···· *Si finalmente, por Sentencia Judicial, tuviera que abandonar el pueblo, se valoraría el trasaldo temporal a otra residencia del mismo grupo o se pediría nueva plaza por emergencia social a Mayores aportando la Resolución Judicial e Isabel tendría que ir dónde le asignasen plaza. ························ Lo comunico a Mamen, Ud. Gestión de Control de la Actividad Asist. y Sist. de Información (68423)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-05-03','-Amalia : se le da un extra de 50€ el dia 30 de abril , se acuerda ésto con la sección eco : Si te parece bien, la próxima vez que me llame , le propondré subir a 80€ semanales , sin ningún tipo de extra de este tipo , sólo un pequeño extra en Junio y diciembre coincidiendo con la extra. Te daré respuesta . Seguimos ...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-05-03','miguel, me llama Mely para preguntar por el procedimiento X15 nº129/20 del Jzdo nº2 de Zafra. Hablo con dicho jzdo para ver si se han inhibido ya y me contestan que remitireron al Jzdo Mixto de Coria el expte y su acuse de recibo es del jzdo nº1 de Coria. Hablo con dicho jzdo nº1 de Coria y me comentan que sólo les ha llegado el Auto de inhibición. Y que han solicitado oficio el viernes pasado,al jzdo de Zafra les remitan todo el expte en papel o lexnet. Vuelvo a llamar al Jzdo nº2 de Zafra y me confirma que él lo ha enviado y que llamará al de Coria para explicarselo. Hablo con Mely y la pido me llame a final de mes para recordarmelo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-05-03','miguel, solicito a la notaria de Don Benito por email para la renuncia de herencia de los padres. Doy a Belén para Juana email para localicen el embargo y hablar con Oar para decirles que no pueden embargar la cuenta del curatelado por deuda de la madre. Sigo pendiente que me llamen de inmobiliaria Colón para la la venta de casa de VPO de Guadiana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2021-05-03','miguel, tras confirmar con la parte económica el ingreso del importe correspondiente a nuestra tutelada (por transferencia de su hermano Francisco), intento hablar con la notaria de D. Timoteo en Badajoz (Antolina) a quién pido por email los datos de la venta así como a quién ha remitido las escrituras. Me contesta que a Ana de notaria de romero leal, a quién llamo sin éxito y la envío un email, nuevamente pidiendole los datos de la venta para poder hacer la Autorización del Gerente a mi para poder vender.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2021-05-03','Ana: Subo al portafirmas digital la Solicitud de Subvención de Tarjeta de Transporte remitida por Ana Benavente, TS ESM-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-05-03','Ana: A petición de Juana, secc. ecca. CTAEX, cumplimento Comunicación de variaciones de PFHC por cambio de cuanta bancaria y lo pongo para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-05-03','Ana: Correo de Toni-Futuex (areasocial3@futuex.es) con información de la última visitas y gestiones realizadas por Virginia - Ed. Futuex: Como era de esperar, el yerno manifiesta objecione y quejas en relación a todas las decisiones tomadas desde la CTAEX, a pesar de que les explican que es necesario dada las deudas acumuladas de Clementa, así como al resto de gastos que debe hacer frente. *Deja patente el interes económico que existe por parte del yerno. NO obstante Virginia deja claras todas la indicaciones y explica que no es negociable. **Facilitan en el correo-e el nº de cuenta bancaria del yerno y datos de contacto tanto del matrimonio (Roberto Moretón González Tf.:693 768 890 y Pilar Tf.:638 530 172) , como de la farmacia. *Guardo correo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-05-04','TERESA el proximo pase de Andrés es del 10 al 24 de este mes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2021-05-04','Ana: Envío correo-e a Ana Benavente (anamaria.benavente@salud-juntaex.es): "Buenos días Ana, Te envío adjunta la solicitud de transporte de Carmen Solana Chanclón firmada digitalmente por su representante legal. Ante cualquier otra cuestión, hablamos. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-05-04','miguel, remito email a Belén: , me ha llamado el abogado de Carmen para lo del procedimiento de desahucio. Necesitaré para ayudarle la siguiente información y documentación, que no está en el expte virtual (a ver si está en el físico): 1.-Comprobar en sus movimientos de cuenta si desde el 2011 se le cargan recibos de luz y agua. Caso contrario intentar localizar el contrato de luz de endesa y pedir los últimos recibos. 2.-Contrato de alquiler de 2011, no lo veo en el expte virtual. El abogado lo necesitará para poder hacer una previsión de los gastos del procedimiento. 3.-Sabemos si estaba alquilado la vivienda y cochera juntos o por separado? He localizado un documento del antiguo gerente Juan Carlos Campon donde autorizaba al cambio de cerradura de la cochera al inquilino de entonces (en 2011), un tal Juan Gonzalo Silva Garcia con dni 8834571H. 4.-Podemos conseguir las declaraciones últimas de las rentas de IRPF de la tutelada para comprobar qué y cómo declara el alquiler o alquileres (Vivienda y cochera)?. El abogado Jorge Calvo (móvil 644340448) se decanta por hacer un burofax de no renovación, al cuantía debida en el mejor de los casos sólo podría pedirse los 4 o 5 últimos años (y seguramente por insolvencia del inquilino no se pueda recuperar ese dinero). El procedimiento sería un procedimiento de desahucio: la parte buena es que todos los desahucios con la crisis se han paralizado porque el riesgo de exclusión social (previo informe de servicios sociales) y que era compensado con una ayuda a propietarios que daba el estado. Esta situación llegará hasta junio según me comenta. Por tanto, urge conseguir el contrato de alquiler e intentar comprobar si hay consumo de luz. Mañana miramos si quieres en el expediente físico a ver qué hay. También me comenta que cree que Carmen declaraba el alquiler anualmente en las declaraciones de la renta de IRPF (así se lo comentó). Dice también que no cree que tenga el contrato de alquiler porque él le dio su email y nunca se lo envió','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-05-04','Ana: Llamada de José Luis, hermano de José Manuel (687 581 061) dice que su hermano no está bien y quiere volver a casa. *Ambos coincidimos en que en casa tampoco estaba bien, ni lo va a estar si vuelve. NO le viene nada bien estar solo y lo más adecuado es que esté en un recurso. ················ Llamada de José Manuel (627 788 797): mismo discurso de otros días; no está bien y quiere volver a casa. Le recuerdo que en casa estaba peor, llegó a pedir ir a recursos que no quiere (Pinofranqueado y Sociosanitario) y a protagonizar intentos autolíticos... entiendo que no le esté resultando fácil, son muchos cambios, así como horarios, límites y normas que antes no tenía. Además aún no conoce bien la ciudad ni ha hecho amistades. También tiene pendiente cita en Psiquiatría y es posible que haya que ajustar la medicación. *Teresa, Ed. - Futuex va a tratar de que le adelanten la cita. **Una vez más acordamos que va a intentar tener más paciencia y poner de su parte para adaptarse. ······················ *Informo por mail de ambas conversaciones tanto a Pilar Martín, ESM-CC como a Toni, Futuex y Beatriz, CRR. ··································································································································································································································································· Correo-e de Beatriz, Coord. CRR-Ba: "Buenos días Ana, Normalmente a José Manuel le veo todos los días por la mañana, le ayuda a estar más tranquilo y a ordenarse a nivel emocional. Hasta ahora aunque se muestra insistente con el tema de irse a casa, nos resulta fácil reconducirle, pero el impulso de llamar a diferentes personas, hermano o 112 le cuesta controlarlo. Está empezando a relacionarse con otros compañeros, aunque suele estar la mayor parte del tiempo solo. Creo que sólo hay que darle tiempo para que pueda adaptarse y transmitirle confianza en que puede hacerlo, la cita con el psiquiatra la tiene en junio. Hoy hemos estado comentado su deseo de adelantarla y la conclusión que hemos sacado es que al igual que ha estado en multitud de recursos también ha cambiado en numerosas ocasiones de pautas farmacológicas buscando la eliminación del malestar y ninguna lo ha conseguido. Ha accedido a ir haciendo pequeños cambios para estar menos mal. En definitiva, esta última semana ha sido mejor que la anterior a pesar de que él continúa demandando irse. El mensaje que desde aquí le estamos dando es que entendemos que su forma de transmitirnos su malestar es pedir continuamente irse a su casa y nosotros podemos ayudarle a gestionarlo. Un saldo y buena semana." ································································································· Correo-e Toni-Futuex: "Buenos dias De acuerdo en todo, tan solo puntualizar que la compañera educadora, Teresa, en ningún caso le ha comentado que trataria de adelantarle la cita, en ese repecto solamente ha tratado de tranquilizarle explicandole que ya queda poco, apenas un mes, para que lo vean, eso tanto en el dia de ayer, mientras le acompañó a retirar la asignación del banco, como hoy a través del telefóno, pero supongo que el ha podido tergiversar esa información. Nosotras desde el programa, igual que haciamos en Cáceres, le prestaremos determinados apoyos, intensificando sus seguimientos hasta que se genere una buena adherencia con la educadora de aqui, y pudiendo contribuir en la medida de nuestras posibilidades a su mejor adaptación al entorno, visitandolo siempre que no exista inconveniente desde CRR todas las semanas, y atendiendo sus demandas telefonicas. Muchas gracias y buen dia!" ·········································································································································· Mi respuesta a ambos correos: "Buenas tardes a todas, Beatriz, muchas gracias por vuestra implicación e intervención diaria. Confío en que poco a poco se vaya reduciendo su malestar y adaptándose. Toni, que también he leído ya tu correo, lo mismo, las gracias a Teresa por su apoyo e intervención. *Él afirmó que Teresa iba a tratar de agilizar la cita de Psiquiatría, y esta información sí que suele trasladarla bien, pero sabemos que otras veces no es así, disculpad, pues lo di por hecho. En este punto, ¿consideráis que deba de adelantarse dicha cita? Lo digo por, en ese caso, tratar de hablar con el Equipo de Salud Mental, pues quizá sirviera de ayuda, sino me temo que el mismo día 12 va a hacer todo lo posible por marcharse de allí. Y ni qué decir tiene que desde la CTAEX no estamos de acuerdo con esta decisión y menos con el poco tiempo que ha transcurrido desde que ingresó en el Centro. Ya me decís si lo dejamos estar o si lo intentamos cambiar. A ver cómo evoluciona. Seguimos en contacto. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-04','Ana: Llamada de Damián (622 834 876), dice que la semana pasada estuvo ingresado unos días en el hospital. ···· Lleva una semana sin fumar. ················ Por otra parte, que es lo que le agobia más hoy, que en el Ayto. de Málaga le han dicho que no podrá cobrar la parte de subvención (Ayuda al alquiler) correspondiente a este último periodo mientras no vaya el inquilino a firmar un papel (no sabe cuál). *Se lo comunico a Miguel, Asesor Jurídico CTAEX mediante mail, para que se ponga en contacto con Loreto, Técnica del Ayto. ······················· Respuesta de Miguel: "Buenos días Ana, como este trámite lo está realizando Iciar la pongo en copia. Iciar puedes preguntar al Ayto de Málaga el motivo por el que no le abonan la última mensualidad? A ver si nos lo dan por escrito por si hay que recurrir…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-04','miguel, recibo email de Damian: Muy grave he importante que me llame a pesar de todas las gestiones que ha echo usted de buena fe e itziar he hablado ahora mismo con carmen del equipo de pago le he esplicado que yo no puedo firmar y ya hablo itziar que se enfado porque hablo unas cuantas veces con loreto y parece que se habia resuelto el problema despues de hablar toda la panafernalia con carmen consulta con loreto que ya varias semanas antes hablo con itziar.contestacion del ayuntamiento señora carmen tras consultar hace un momento con loreto y equipo de loreto y me comentan esto.tiene que ir el inquilino a firmar un papel para que me paguen del ayuntamiento el sexto semestre el pago le corresponde al ayuntamiento y el ayuntamiento tendremos que hablar con rocio para interponer una demanda ya que en la situacion de enfado que esta el inquilino pone esta trampa en si no firmo damian no cobra del ayuntamiento por lo tanto no me pueden echar eso pienso yo lo que piensa el inquilino y el ayuntamiento no hace caso a lacomision tutelar esta siendo el ayuntamiento hipocritas como muchos alli en el sur.hay que hablar con rocio y de que forma se obligue que no lo va a hacer para ir a firmar porque el ayuntamiento nos esta engañando lo pongo en mano de itziar y usted para que me ayuden por favor que no haga falta que el inquilino firme y dependa su firma para cobrar algo que es mio.el tema del pago del sexto semestre lo tiene el ayuntamiento pagado una estrategia para no firmar el inquilino.llameme urgentemente o hable con rocio es muy serio y hay que ponerse de nuevo en marcha el proceso de ingresarme religiosamente lo que me tiene que abonar el ayuntamiento.muchas gracias por su buen corazon.llameme urgentemente ya he hablado con ana matamoros pongase en contacto con ella acabo de hablar con ella.gracias buen dia de martes mis mejores deseos para usted y todo el equipo un saludo atentamente **************************************************** recibo email de Ana: A ver, he recibido llamada de Damián. Al parecer en el Ayto. de Málaga le han dicho que no podrá cobrar la parte de subvención (Ayuda al alquiler) correspondiente a este último periodo mientras no vaya el inquilino a firmar un papel (no sabe cuál). ¿Sería posible que hablases con Loreto, Técnica del Ayuntamiento para aclarar esta cuestión? Teme y con razón que el inquilino no acuda y pierda esa cuantía. *************************************************** remito email a Iciar con copia a Ana: Buenos días Ana, como este trámite lo está realizando Iciar la pongo en copia. Iciar puedes preguntar al Ayto de Málaga el motivo por el que no le abonan la última mensualidad? A ver si nos lo dan por escrito por si hay que recurrir…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-05-04','Ana: Correo de Estrella, TS CSS (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Acabo de mirar el SIDEX, programa del SEPAD donde aparecen solicitudes de valoración de dependencia, PIA etc., con objeto de ver si han subido ya la solicitud de Desideria. No está subida. No sé si tú podrías hablar, si es conoces en que servicio o qué profesional lo lleva a cabo, para que lo agilicen y así la podamos valorar desde este Centro Socio-Sanitario por Instrucción 47, porque como la tenga que valorar cuando esté en casa de alta, se va a eternizar, ya que hay una lista de espera de un año..... Ya me dices....si sabes a dónde o quién debo dirigirme, llamo yo...." ·············· Reenvío el correo a Clara I. Gómez Nestares, Jefa Secc. Depend., para que lo reenvíe a quien corresponda. Pongo en copia a Estrella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-05-04','Ana: correo de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Ana buenos días, en relación a Clementa Amado Vivas se señala juicio para el 28 de junio por el procedimiento de incapacidad y en el otro procedimiento de internamiento involuntario, me parece que van a pediros parecer sobre la residencia. (Villa del Rey). Un abrazo." ················· *Se lo reenvío a Miguel, Asesor Jurídico CTAEX y a Toni-Futuex, para que estén al corriente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-05-04','Ana: Correo-e de Ángela Bueno, Directora de Asuntos Soc. Placeat (directora@placeat.org): "Buenos días Ana, te adjunto el informe de adaptación de Cristofer Montero Vazquez al haber transcurrido ya los 45 días de su periodo de adaptación al servicio residencial de San Gil. Saludos". ··········· Guardo en el expte. digital el informe. Es muy detallado y especifica las intervenciones pautadas (protocolo de intervención en el recurso) según la actitud y actuación de Cristofer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-05-03','Se aprueba presupuesto de la clínica dental Garias y Delgado, en Avda de España. *En cuanto se haga transferencia de la primera parte podrá iniciar el tratamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-05','Ana: Correo-e de Raquel, TS del SSASB Valverde de la Vera (ssasbrpa@gmail.com): "Buenos días Ana, el motivo del presente mensaje es preguntarte sobre el tema de Florencia, desde la última vez que hablamos, no he vuelto a saber nada del tema. Cuando desde el ayuntamiento no me han llamado y no me han comunicado nada, es porque no ha habido nada nuevo. Ya me dirás si se han realizado gestiones al respecto. Un saludo" ························ Tras llamar a Toni- Futuex, le envío el siguiente correo-e con copia a Raquel: "Buenos días Toni, Tal y como hemos acordado, te anoto el número de contacto de la Raylin Pinales (927 567 270), MAP del C. Salud de Valverde de la Vera, para que intentéis acordar una visita conjunta con ella cuando os sea posible, a ver si así localizan a Florencia y la Dra. hace los informes pendientes. No obstante, si hubiera algún avance de aquí hasta entonces, pues yo volveré a llamarla, te informaría al respecto. Pongo en copia a Raquel, TS del SSASB, para que esté al corriente. Seguimos en contacto." ······················· Nuevo correo de Raquel: "Buenas Ana, seguimos igual que la semana pasada. Pues mañana intento ver a la médica, y hablar otra vez con Esperanza, etc. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-05-05','Ana: Correo de Estrella, TS CSS-Plas: "Ha estado Remedios Chaves recientemente en Oftalmólogo y en Óptica y le ha subido la graduación 4 dioptrías, o sea que tiene 7 en un ojo y en el otro, no recuerdo..., pero también bastante...Como tiene el problema de las ingestas, ha estado mucho tiempo sin ponerse las gafas por eso también le habrá subido tanto...Le hemos encargado unas,(70 euros) porque así no puede estar, hemos dado indicaciones al personal Auxiliar, para que cuando se las den estén muy pendientes de ella...pero claro es un peligro que las lleve....Así que en reunión de UHDAC se propuso os comunicara la posibilidad de que pudieran operarla de miopía...qué os parece a vosotros? Ya me cuentas...." ························· Mi respuesta: "Buenos días Estrella, Pues, aunque a mí me parece buena idea, creo que no puede permitírselo económicamente, no sé exactamente a qué precio están hoy en día dichas intervenciones, pero si no ha variado mucho de unos años para acá, me temo que no es factible. ¿habéis consultado precio en clínicas? Si es así, por favor informarnos al respecto. No obstante, pongo en copia a Alberto, jefe de sección económica, para que esté al corriente y pueda comprobar sus saldos. Así como a Amalia, TS de referencia de Remedio, acorde a su centro habitual. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-05-05','Ana: Envío correos a Toni-Futuex: "… ¿qué tal ha ido la visita de la compañera? Ya me iréis diciendo novedades. Lo que no acabo de entender es lo de la cuenta, pues resulta que sí es la que hay en la CTAEX y sí que tiene dinero en ella… es en la que percibe la PNC. En cuanto me enviéis el informe se prepara escrito desde la CTAEX para comunicarlo al Jdo. y solicitar ampliación de incapacidad e ingreso involuntario, pues en esas condiciones no puede seguir viviendo. ¿Por cierto, la TS se ha mostrado colaboradora en relación al informe? Para saber si tengo que solicitarlo por escrito o no." "Por cierto, En cuanto a su manutención, habrá que establecer un presupuesto de gastos y una asignación. Como sabéis se le indicó en Prisión, antes de salir, que me llamara para acordarlo, pero no lo hizo… independientemente de su trapicheos, debería dársele una cuantía al menos para la comida o casi mejor aún, contratar un cáterin. Pues no sabemos cuánto van a tardar después en resolver desde el Juzgado. Y viendo en qué estado está su cocina, creo que lo mejor sería que le llevaran la comida hecha. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-05-05','miguel, de la documentación que le ha entregado el abuelo del curatelado a Amalia y que remitió y por error se la devolvió al Sepad de Badajoz. Amalia la remitirá físicamente. Mientras adelanta una ejecución del procedimiento Ejecución forzosa en Procesos de Familia 130/2011 (Procedimiento origen divorcio contencioso 597/2007), donde la ejecutante es la madre del curatelado, Doña Mª Belén Bono Contreras. ******************************************************** Viene a reunirse con Alberto y conmigo de nuevo el abogado de la otra parte Carlos Lena Jurado, y se analiza la situación: 1.-Entre septiembre de 2015 a septiembre de 2019 el invifas había dejado de ingresar la pensión del padre a la primera esposa, y sus hijas. Esto llevó a que una de las hijas, Gema (hermanastra de Alejandro (como representante del padre))reclamase ante el juzgado que intercediera para reclamar la continuación de esos pagos, para ello requirió al SCH para le indicara en febrero de 2019 el saldo que había en cuenta y cuándo fue el último pago y recurrió al Invifas para abonase con carácter retroactivo las cantidades de la pensión. Mientras abrió una cuenta en la Caixa y el invifas hizo dichos abonos. Pero en septiembre de 2019 la comunicaron desde Invifas a raiz de que se había dictado Auto de Fallecimiento del Padre, que debía devolver todos los importes con carácter retroactivo hasta 4 años, lo que conllevo que todo el dinero de la cuenta de la Caixa que abrió la hermanastra unido a las retenciones recibidas en la cuenta de la madre (1º esposa) en ibercaja, fueron abonadas a Ministerio de Hacienda. Posible motivo por el que se interrumpió el pago de sept de 2015 a sept 2019 fue por que una cosa es la Declaración de Ausencia (que no debe interrumpir el pago) y otra el Auto de Fallecimiento (que sí interrumpe el pago). Paralelamente a esto la 2º mujer MªBelén Bono Contreras (madre de nuestro curatelado)obtuvo en 2011 derecho de ejecución d 39.956,99€ (11987 de intereses y costas)+8.746,98€ de principal+2624€ de intereses y costas. En Octubre de 2011, solicitaron a la Subdireción General de Gestión de Clases Pasivas, solicitaron en base a dicha Ejecurción Forzosa el abono de las mensualidades pero les contestaron "que el D. Francisco Nuñez Mure, ya se encuentra sujet a otras retenciones judiciales o administrativas", motivo por el cual quedó anotado el embargo preventivo en su orden de prelación, e informarían al juzgado de 1º instancia nº4 de Badajoz el inicio de la retención solicitada cuando finalicen las retenciones que se están practicando(que dictó la orden de ejecución forzosa a favor de la madre del curatelado) *************************************************** Quedamos en lo siguiente: El abogado Carlos Lena pondrá a alguien del SCH para nos pida lo que necesite a efectos de que nos justifiquen la relación entre las cuentas de origen y de Fondos de Inversión para acreditar que es la misma cuenta. Él hablara con la abogada del caso de Ejecución de la madre del curatelado Soledad Carreres para ver si tiene algo que alegar. Por mi parte esperaré la documentación que remetirá Amalia a efectos de comprobar si hay algo más que alegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-05','Ana: Llamo a la Embajada de Mauritania (915 75 70 06), la persona que me atiende me dice que sin el libro de familia o documento familiar oficial de Mauritania no es posible hacer el pasaporte. Para que nos lo pongan por escrito, habría que solicitarlo previamente por escrito (según me indica) por correo postal a la embajada y entienden que nos darán respuesta. ······························································································································································································· Redacto escrito-solicitud para la Embabaja de Mauritania en Madrid y la subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-05','miguel, a la petición que hice a Iciar de que averiguara con el Ayto de Málaga el abono del 6º semestre me comenta lo siguiente: He hablado con la abogada que lleva el tema de los planes de ayuda al alquiler del ayto de Málaga ( Rosa 951 928743 – rilopez@malaga.es ). Me comenta que el 16/2/21 se envió una declaración responsable al inquilino, debe ser firmada por inquilino y propietario, donde se certifica que el inquilino efectivamente ha hecho los pagos correspondientes. Esta declaración no se ha devuelto firmada al ayto, por lo tanto, la subvención (el 50% del alquiler) no se le ingresa a Damián, pues solo lo hacen si el inquilino paga su parte. Hasta aquí puedo contar. Miguel, si quieres hablar con la abogada te dejo ahí el contacto. Es un poco lioso todo ************************************* la contesto: Intentaré hablar con ella y si no lo abonan se lo pasaré a la abogada que ya está tramitando el procedimiento de desahucio********************************** recibo email de Damian: No me van a ingresar el sexto semestre los inquilinos porque la jefa de seccion no quiere arreglemelo de todo corazon llameme cuando pueda e intentado contactar con usted.un cordial y educado saludo.gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-05','miguel, escribo a la dirección que me remitió Iciar: rilopez@malaga.es(abogada del Ayto de Málaga) Buenas tardes, he intentado localizarla sin éxito. Soy compañero de Iciar compañera de la Sección Económica de la Comisión Tutelar de Adultos de la Junta de Extremadura, a quién le ha comentado que no puede hacérsele el abono del 6 semestre de alquiler (cuando los anteriores si los han realizado). Necesitaría que me remita por esta vía los motivos por los que no pueden realizarle dicho abono y si puede ser lo fundamenten legalmente. Este alquiler actualmente está en manos de una abogada de Málaga quién ha iniciado los trámites para un procedimiento de desahucio. El inquilino prácticamente no ha pagado nada del contrato de alquiler desde su inicio, motivo por el cual no firmará nada, como forma de presión para que el arrendador Damian (curatelado) no lo desahucie. Por todo ello, necesitamos que nos acrediten con el mayor detalle posible el motivo por el que no se puede abonar dicha cantidad adeudada al arrendador y curatelado Damian, a efectos de incluirlo la abogada en su escrito de demanda de desahucio. Para acreditar nuestra representación de curadores, adjunto sentencia de incapacitación, aceptación de cargo y contrato de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-06','miguel, emails de Damian: Estuve tras el ingreso muy malito el fin de semana y se me caian de sueño no me senti querido y ayudado por un monitor ni me pregunto como estaba de salud por estar hospitalizado no es justo por detras una cara y por delante entre semana a los tecnicos otra cara **************************************************** Por favor don miguel me he dado cuenta que aqui en plasencia la vida dura es mejor segun me dicen los operadoras de proyecto hombre que han hablado contigo y me han dicho que no me valla a merida porque mi prima era el detonante y ella dice que no le importa que este un poco mas lejos mas vale malo conocido qie buena por conocer confie en mi aqui sufro pero la vida es asi******************************** Me puede ayudar a desahacer el nudo que he echo la directora queria ponerla a prueba a ver si verdaderamente ella me quiere aqui en este centro mañana llame al centro sobre a las once de la mañana porque tengo cita con la psicologa y le he cogido cariño.llameme por favor me dice muchas veces que me va a llamar y despues no me llama eso sienta mal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ZANCA'and apellido2='SANDIN'),'2021-05-06','Ana: Emilia Almodóvar, TS del CSS-Plas (emilia.almodovar@salud-juntaex.es), me traslada por mail la siguiente información: "Este es el número de cuenta de Jesús Zancas. ES2120481204113000004177 Jesús Zancas es autónomo en el manejo del dinero, tiene un gasto de bolsillo mensual, que él mismo gestiona mes a mes, sin problema. De todas formas, si necesitáis informes en alguna cuestión sobre el paciente os lo realizamos." ················· Se lo comunico a Icíar y Alberto, secc. ecca. ···················· Correo de Icíar, secc. ecc: " nos ha llegado justo hoy cdo de pensión, tiene incapacidad permanente 671,63 €"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-06','Ana: Envío correo a Raquel, TS del SSASB Valverde de la Vera (ssasbrpa@gmail.com): "Hola de nuevo Raquel, Acabo de hablar con la Dra. Raylin Pinales, de nuevo insiste en que le avisarán desde el Ayto. cuando la vean por la calle, que lo acordó con Esperanza. Y sino va a programar una visita con Virginia, Ed. Futuex, para buscarla la semana que viene (es lo que acordé yo con Toni, coordinadora del Programa, pues esta semana ya les era imposible por tener otras gestiones y visitas programadas). Confío en que, en el peor de los casos, puedan conseguirlo la semana que viene con el apoyo de Virginia. Veamos…" ······································································································································ Respuesta de Raquel: "... ya he hablado con Virginia, hemos quedado para el martes a las 10:30. Ya te iré contando. Luego me reúno con Esperanza y hablaré del tema con ella." ······················ Llamada de Raquel (667 068 078 nº personal) finalmente, tras hablar con Esperanza, Alcaldesa, han ido a buscar a Florencia, llamado a la Doctora y ésta al poco de verla, como no le ha permitido reconocerla mínimante, ha activado el 112. ··············· Me mantendrán informada. ················ Más tarde recibo nueva llamada de Raquel, los técnicos del 112 no quieren tocar a Florencia sin su consentimiento y están espearando a la Guardi Civil, quién a su vez pregunta que en base a qué tienen que llevarser a Florencia. ··············· Llamo a Esperanza, Alcaldesa (664 28 55 19 = nº personal), en este transcurso llega la Guardia Civil, ponen el manos libre para que pueda hablar con ellos, les explico y se la llevan al Hospital de Plasencia, para que la valoren en Urgencias, en Psiquiatría. *Esperanza les entrega copia de la Sentencia de Incapacidad y Autorización de Ingreso Involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-06','Ana: Envío correo-e a la Embajada de Mauritania (ambarim@embajadamauritania.es): "Buenos días, En relación a D. Brahim El Kinty Sneiba, tutelado por la Comisión Tutelar de Adultos de Extremadura, le remito la siguiente documentación: - Escrito solicitud relativo a la renovación de su pasaporte, debidamente firmado digitalmente por su Representante Legal - Permiso de Residencia en Vigor - Testimonio de Aceptación del Cargo de Tutor Esperamos su respuesta a la mayor brevedad. Gracias por su atención y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-07','Fax Embajada Mauritania: 91 435 95 31','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-05-06','TERESA LLAMA MINERVA TS RESINDENCIA Y PLANTEA QUE LA HIJA ESTA EN UN PSIO SUPERVISADO Y RECLAMA VISITAR A SU MADRE EL CENTRO NO OPORTUNO ESTA VISITA POR LAS CONSECUENCIAS QUE PUEDE TERNER SOBRE M LUISA CON LO CUAL ACORAMOS NO AUTORIZAR DICHA VISITA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-06','Ana: Correo de Mª Jesús Gómez Lozano, T.S., SSASB Mancomunidad Comarca Trujillo (ssb32mancomunidadcomarcatrujillo@hotmail.com): "Buenos días Ana: Me han llamado del Ayuntamiento de Puerto de Santa Cruz porque les han llamado del Consulado Belga. Parece ser que ha aparecido Javier Agudo Cumplido en Bélgica. Dice que ha estado en París, que le han robado y que ahora está en Bélgica. Que no tiene dinero ni medios de ningún tipo. Puedes ponerte en contacto conmigo?l telefono: 621.24.72.37". ···················· La llamo por teléfono, ella no ha ha llegado a hablar con el Consulado, aunque sí le han facilitado su nº en el Ayto. La personas que ha hablado del Ayto. (Pedro) con la Persona del Consulado, expresa que ésta úlitma le ha dicho que Javier está bien, pero sin dinero y que parece "un buen chico". ················· Llamo al Ayto. de Puerto de Santa Cruz (927 34 20 05): No tienen contacto del Consulado, no aparecía nº en el teléfono ("Anónimo") ni saben el nombre de la persona que ha contactado, no lo han preguntado. *Pero sí le han facilitado el nº de Mª Jesús, TS y de la Guardia Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-05-06','miguel, Soledad indica por email que va a remitir cerficado de defunción y últimas voluntades. Le pido el teléfono del 3º hijo. Contestación: El teléfono que tengo es 638 927 150. No sé si estará operativo. Hace mucho tiempo que no hablo con el por teléfono. Si no estuviera operativo, su tía Vale puede que te lo pueda facilitar. Su teléfono es 663 90 97 91.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-05-06','miguel, recibo email de Amalia donde Soledad del Colegio de la Luz quiere se la informe del porqué ahora está el asunto en el juzdo de lo Penal y que no le hemos remitido docummentación. La contesto que le remito a Elena su duda ya que nosotros sólo tenemos la citación que ella nos remitió. Elena me contesta que cuando vaya a preparar el caso se pondrá en contacto y que el motivo por el que está en el juzgado de lo penal es porque ha finalizado la fase de instrucción (es decir ha habido apertura de juicio oral)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-05-06','Ana: Correo-e de Juana, secc. ecca. a Paula, TO CRR-CC (me pone en copia): "Buenos días Paula, En relación a la lápida que Flori quiere poner a su madre fallecida, tenemos que esperar a que los compañeros del área jurídica tramiten las gestiones correspondientes a la herencia de Modesta. Ahora mismo, la cuenta que tiene Flora es la que comparte con su madre, y no se puede tocar hasta que no esté hecha la herencia. Se ha procedido a la apertura de una nueva cuenta a nombre de Flora en Liberbank, ya os avisaremos cuando se hayan ingresado las pensiones en la misma para que Flori pueda retirar la asignación de su nueva cuenta. Por otro lado, en relación a los gastos de funeral, una vez esté hecha la declaración de herederos, se le presentará a la compañía con la que Modesta estaba asegurada, para que proceda a la devolución del importe correspondiente. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-05-07','-Amalia : Se envia solicitud de eleccion de centros a Manuela y Maribel Ramos por email . Guardo copioa en expediente .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-07','miguel, llega email de Damian Llameme por favor señor miguel esta mañana necesito comunicarle lo que me ha dicho loreto y su equipo del ayuntamiento y comtacte con rocio para decirle lo que yo voy a decirle a usted*************************** Esta noche me he orinado en la cama no puedo por mi mismo y los ataques de ansiedad estar pendiente de lo de la orina.llameme cuando pueda por favor','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-07','miguel, hablo con Damian y le comento que envié un emial antes de ayer a la abogada Rosa del Ayto pero me dio error. No he logrado hablar con ella hasta ahora pero me tendrá que explicar porqué no puede cobrar el 6º semestre (dónde viene eso regulado). Me comenta que Carmen del equipo del Ayto lo consultó y Loreto le confirmó que si el documento que le dieron al inquilino (Declaración Responsable) no está firmado por ambas partes (como justificante de cumplimiento de ambas partes hasta esa fecha de dicho contrato) no puede cobrar ese dinero. ****************************************** Hablo con Rosa del Ayto 951928743, quién me da su email correcto rilopez@malaga.eu: Le pregunto el motivo por el que no cobrará el 6º semestre Damian. Conoce el caso y a Damián que llama a menudo alli. Me dice que han recibido firmado por ambas parte los 5 primeros semestres, le comento que no era la firma de Damian, me contesta que ellos no son Olografos, y que si voy a juicio por Desahucio y se demuestra falsedad de firma que aunque sea el beneficiario de la ayuda el inquilino, al estar abonandose en la cuenta de Damian, irian contra él, reclamandole los 5 semestres anteriores, por lo que me recomendaba que lo mejor era comunicar al inquilino que no renovara incluso reclamandole el pago del 6º semestre. ****************************************************** Llamo a la abogada que represnta a Damian en el futuro procedimiento de Desahucio (Rocio Gracian), le comento lo que he hablado con la abogada del Ayto de Málaga. Me comenta que ella me va a mandar por email el burofax que envió donde sólo ponía la cantidad adeudada (no desglosaba concepto, importes, fechas)y que en el párrafo siguiente dejaba claro que no se renovará el contrato de alquiler. Me dice que el inquilino mantiene conversaciones con ella cordiales (y va a intentar que así sigan). Que el inquilino le va a mandar justificantes de pagos a Damian, así como de arreglos que ha hecho a la casa. Que quedó con Damian que iría haciendo las reparaciones a la casa porque estaba en muy malas condiciones y se lo descontaría de su parte a abonar. Ella cree que puede haber algunos de los justificantes firmados por el propio Damian. Y también hace mención el inquilino de la veracidad de las palabras de Damian del que dice que debe dinero a gente de allí (ha habido gente que ha ido a reclamarlas al piso, según cuenta el inquilino). El inquilino le comenta que él tampoco quiere renovar y que se irá. Por otra parte coincidiendo con el estado de Alarma el estado ha publicado un RD alargando la prohibición de desahucios otros 3 meses. Por tanto ella no hará nada hasta llegado el cumplimiento del contrato y comprobar si se ha ido o no el inquilino (ya que no se le puede desahuciar por ahora). Quedamos en que mantenga informada a la prima Alicia y que por ahora no digamos nada a Damian. Que el día que tengamos un resultado se lo diremos a Damian. ************************ Por tanto y debido a que llevamos más de un año en estado de alarma y desde el principio se publicó un RD prohibiendo los desahucios, supone que no podríamos echarlo tampoco antes. Remito toda esta anotación para su conocimiento por email a Ana y Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-07','Ana: Correo de ayer a última hora de Alfonso Rodilla, Consulado Gral. de España en Bruselas (alfonso.rodilla@maec.es): "Buenas tardes, El Sr Javier Agudo Cumplido se ha presentado en este Consulado con evidentes síntomas de discapacidad y desearía contactar con sus servicios para explicar la situación y ver de qué manera se puede colaborar para ayudarle a regresar a España. He intentado hablar con el teléfono 924 93 02 45 pero no obtengo respuesta. Pueden contactarme a mi número de teléfono móvil personal 0032 496 806 801 Saludos cordiales" ··················· Intentamos desde la CTAEX llamar a Alfonso, pero las llamadas al extranjero está restringidas tanto desde el fijo como desde el móvil de la secc. soc. ··········· Intentamos consultar en la Dirección Gerencia, pero no obtenemos respuestas a las llamadas. ·························· Envío correo a Alfonso: "Buenos días Alfonso, Ayer tuve el final de la mañana bastante complicado, disculpe. En cuanto a hoy, prefería llamarle y explicarle verbalmente, pero resulta que tenemos las llamadas al exterior restringidas y no podemos llamar. Estamos, desde primera hora, tratando que nos habiliten la llamada. En cuanto a Javier Agudo Cumplido, se le ha incapacitado judicialmente y desde la Comisión Tutelar de Adultos se ha aceptado el cargo de tutor a fecha de 18 de marzo de 2021. Desde entonces, no hemos conseguido dar con él, se hallaba en paradero desconocido, tal y como se ha comunicado desde aquí al Juzgado. Supongo que ni siquiera sabrá, a día de hoy, de la Sentencia de Incapacitación y de su tutela, pues ni Mª Jesús, su trabajadora social de referencia, ni en la CTAEX, hemos tenido ocasión de explicárselo. La Policía también intentó comunicarle la sentencia hasta en 3 ocasiones, pero no dio con él. Por otra parte, informar que aún estamos en fase de inventario, el Juzgado nos da 60 días para conformarlo, y aunque mis compañeras de las sección económica están en ello, no han conseguido tener acceso a sus cuentas bancarias. En estos momentos desconocemos su situación económica ni podemos hacer ninguna gestión bancaria. Por último, decir que esta Comisión Tutelar de Adultos no tiene partida presupuestaria alguna, desde la misma se gestiona el patrimonio de la personas tuteladas o con Curatelas de contenido económico-patrimonial. Así pues, no sé de qué manera podremos ayuda a Javier a retornar a España. Si finalmente me dan acceso, le llamaré a lo largo de la mañana. O si te es posible llámeme usted, aunque sé que en mi teléfono no siempre es fácil contactar. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-10','miguel, emails recibidos de Damian: Estoy sin tomarme la medicacion de la mañana porque he ido ha hacerme una analitica y ya he llegado a las diez y media de la mañana y se me ha olvidado tomarme la medicacion fecha hoy 10 de mayo 2021 para que se lo diga al juez que ni los monitores se han acordado de darme mi medicacion matutina gracias don miguel******************************************** Buenas noticias y para que no se entere todo el mundo investigando yo con mi movil he conseguido hablar con sonia de merida de informacion a la dependencia y me ha pedido los datos y ella corrovora con su ordenador que me han denegado por varias veces la ley de la dependencia con los informes nuevos que os mandé de urgencias y achacando el tema de que al forzar me hago de cuerpo al forzar para orinar me van a hacer pruebas ********************************************** Esta señora me ha visto por telefono hoy llorar voy al grano digale con los informes de denegacion e informes de urgencia me ha pedido sonia que ana matamoros vuelva a echar los papeles para pedir la ley de dependencia que los eche de nuevo sin susto que ya me los revisan ademas los informes de urgencia son importantes.gracias cuando haya informado muy señor nuestro don miguel que haya enviado el escaneo de urgencias que lo mande tambien a la comision todos los papeles de urgencias y que ana matamoros vuelva a presentar el recurso de ley de dependencia a lo mejor con esto nuevo que tengo me lo puedan conceder importante los papeles que usted le mandé todo escaneado tambien los envié a la comision para que ana mande todo lo de urgencias a sonia usted se lo explica a ana matamoros gracias y que disfrute del fin de semana************************************************** Buenos dias don miguel le he dejado su correo electronico porque ha encontrado un inquilino que me pagaria 550 euros de alquiler y son de fiar esta prima es muy respetuosa por parte de madre y alicia es por parte de padre.esta prima toñi heredia que le escribirá es por parte de madre es muy agradable.le escribira correo y ya vamos viendo los pasos esta tiene un caracter mas tranquilo que alicia y me interesa alquilarlo.esto lo he hablado esta mañana a ver si echamos al inquilino muchas gracias don miguel.******************* Como esta tarde me habia dado un malrato una monitora y no tenia dinero me he puesto a pedir por la calle.no podia evitarlo como hacia hace 3 años*********************** Tengo ahora porque me gasto todo y he pedido esta mañana por la calle porque aqui no me encuentro bien comenteselo al juez que por mi cabeza no estoy bien y pido por la calle y me gustaria que el juez tomara cartas en el asunto con 14000 euros que tengo ahorrados yo solo no puedo sin familia salir adelante.gracias no se le olvide apuntarlo para el juez gracias es usted muy buena persona.enormemente agradecido estoy ******************************************* La noche del 8 al 9 de mayo me oriné sin ser yo conciente durmiendo de noche tuve la dependencia de pedir ropa de cama nueva a las 2 de la mañana yo ya prevei y dije a la monitora que me diera un moja pipi para no empapar el colchon al otro dia se lo recorde solo una vez y no estuvo pendiente y se fue y no le deje dicho a los compañeros***************** Me ha afectado sicologicamente y seguidamente me he ido esta tarde de domingo 9 de mayo antes de salir en el horario de salida de 17.30 a 19.30 en la merienda de las cinco me hablo a un enfermo mental de mala manera que me habia calentado la leche sin lactosa y fui con una actitud muy educada y le dije que lo queria mas caliente se puso echa una furia de un caracter que afecto mi sensibilidad y me dijo que yo estoy siempre con sarcasmo yo como usted sabe y me conoce don miguel soy muy educado.despues mas tarde de mala idea hacia mi estaba en una conversacion con el limpiador y le dijo rosa la monitora la misma que me paso con ellaen la cocina con el tema de calentar la leche.total que le dice mas tarde al limpiador rosa al limpiador le dice osea la monitora le dice si te molesta me lo dices rosa con amenazas que me impide tirar para adelante busco la soledad lloro sin que nadie me escuche y con esta señora no se puede sentarse y aclarar con ella porque no quiere saber nada de mi si estoy mal obien pero por lo menos pido y le diga usted al juez que esta señora me trate con respeto como usted me conoce y decirletodo esto al juez que me maltrata sicologicamente a un enfermo mental ayudeme por favor verdaderamente ahora el proximo 24 de junio llevo 2 años en el CRR y por esta señora llevo aguanntando el maltrato sicologicamente.en navidadedes la noche buena otro maltrato psicologico dijo que nos podiamos les vantar de la mesa y yo no habia escuchado y me quedé educadamente sentado como me educaron mis padres vino hacia a mi con lacara desencajada que no mequede sentado en la mesa chillandome y me afecto mucho usted me conoce don miguel que soy un hombre educado y esta persona se lo dice al juez yo soy educado muy educado y he sufrido mucho con esta persona por su actitud de cogerme por banda y maltratarme sicologicamente*********************************** Bajo dando todo mi corazon e intentento de hablar con rosa y me corta no estas con los cascos pues tranquilizate y es que estaba muy feliz bailando sin hacer daño a nadie y le intenté explicar que este fin de semana estoy mucho mejor que el pasado porque la semana pasada con el cambio de medicacion me sento los primeros dias me tuve osea el sabado 1 me moria desueño y porque las pastillas eran muy fuertes y la semana pasada que estaba conchi que se porto muy bien conmigo y le dije conchi estoy que me muero de sueños y me trató muy bien. Este fin de semana estaba rosa y me dijo que me tranquilizara.yo con todo el cariño de mi corazon despues de la cena le dije con todo mi cariño y me dijo sogue con los cascos de musica y le dije que los tenia puestos pero apagado y me dice vete y tranquilo me lo vivi como un maltrato sicologico y es la verdad no se preocupo ni deciirme como estas esta semana ni nada me fui con ganas de llorar y triste no me senti escuchado por rosa yo queria expresarle todos mis deseos de que estoy mejor y ella esta alli para ayudarme y no hizo su trabajo ayudandome sicologicamente con un rato de charla************************************** Otra vez me tengo que duchar y cambiarme de ropa porque al apretar y hacer piss se me salen las heces fecales mañana me sacan sangre para analizar un analisis especifico de intolerancia a la lactosa y si soy celiaco*********************Don miguel yo llevo aqui casi 2 años la directora me anima a que me valla se llama blanca pero informele al juez o a servicios sociales que los maltratos sicologicos y aqui todo el mundo se queda callado y estancompinchado los monitores por eso nadie protesta pero este tipo de personas siento mucho miedo no me pongo a llorar solamente bailo alegramente pero ayudeme por favor necesito su ayuda nunca lo he dicho aqui pero estando aqui me dan ganas de tirarme a los coches y quitarme la vida por este tipo de personas*********************************** Le comente que tenia que hablar con el abogado para que hable con el juez y se puso repursiva y violenta diciendome que quieres decir con eso! Claro como ella sabe que no esta haciendo las cosas bien pues piensa que voy ha hacer algo del maltrato que me da.pero despues ya le dije para seguir siendo correcto y educado le dije falsamente no me dirijia a usted**************************************** Yo no puedo vivir asi por favor socorrame y hable con el juez o sepad para mandarme a merida son 2 años de pesadilla************************ Buenas noches o buenos dias son la 4 de la mañana y me acabo de orinar encima para tambien que lo sepa el juez.gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-10','Ana: Llamo a Chema, Coordinador del Piso Tutelado de Menores de Plas. gestionado por la Entidad Cerujovi (649 676 149): Ya ha hablado con Maribel, Directora de la Vivienda Tutelada de Incluisives Vva. Serena. Acudirán a visitar el recurso y tener la entrevista inicial el jueves 13 a las 11:00 h. El ingreso se producirá la semana siguiente. Mientras tanto irán abordando el traslado con Darío desde el piso, pues se le hacen duros los cambios. *En cuanto a la Beca de Estudios que ha percibido Darío, esperan poder mantenerla, pero para ello debería finalizar el curso y aprobar. Hablarán con el centro educativo, pues realmente faltan pocas semanas para la finalización del curso escolar, propondrán el que puedan evaluarle a distancia. *Chema hablará con Virginia-Futuex para que les apoye en el cambio de recurso. **Yo se lo comunicaré a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-10','miguel, me llega el burofax que envió la abogada de Damian al inquilino: Buenos días Miguel, Tal y como hablamos por conversación telefónica, adjunto te remito el contenido del Buro fax enviado al arrendatario de Damián, por el que se le reclama la cuantía global ( sin desglosar) así como se le notifica la voluntad de no renovar el contrato y la obligación de dejar libre la vivienda con la entrega de llaves el día 31 de julio ( el contrato es de fecha 1 de agosto 2018). Seguiré en contacto con el inquilino intentando que se vaya voluntariamente y de " buenas formas". Si para el 1 de Agosto no ha abandonado la vivienda procedemos a interponer el desahucio por expiración de la duración del contrato y obviamos la reclamación de la renta por las razones que sabemos. Seguimos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='VARGAS'and apellido2='SUAREZ'),'2021-05-10','TERESA REGISTRO SALID ALTA A TERCEROS Y NUMERO DE CUENTA PARA PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-05-10','TERESA Buenas tardes, se informa que, en el día de hoy, se ha procedido a la vacunación con Janssen de su tutelado: MORON HERNANDEZ, J.M.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2021-05-10','TERESA El paciente GUSTAVO ALFREDO CASTAÑO SOTO se encuentra de salida de larga duración con su familia por lo que no ha podido vacunarse en el día de hoy. Dado que el equipo móvil se desplazará de nuevo dentro de 20 días, aprovecharemos para que se vacune ese día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2021-05-10','-Amalia : recibo llamada de su madre , Teresa Barco , tf. movil 659064628. Lo llama a diario , y lo visita cuando puede , vive en Badajoz . Quería saber dónde están las llaves del piso , le comento que las tenemos en la CTAEX .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-07','Ana: Correo de Maite Gómez, TS Secc. RR. Discapacidad (UD. PP.AA.): "He hecho la derivación de Darío López Gilarte a la VT de INCLUSIVE de Villanueva. Les he dado el teléfono de la técnico de menores, Rosa, y le tuyo para que realicen el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-05-10','Ana: Llamada de Jairo: hoy lo primero que dice es que va a realizar la prueba de acceso a la Universidad, después estudiará 4 años de ADE y por último se presentará a unas oposiciones para trabajar. Y todo lo quiere hacer en Mérida... En cuanto se le dan argumentos que no acompañan sus deseos se enfada. De repente dice que quiere trabajar en una tienda y que quiere comenzar a buscar empleo 3 meses antes de que finalice su medida judicial. Al final de la conversación manifiesta que quiere revocar su tutela y que va a denunciar a la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-10','Ana: Llamada de Luis, Cabo de la Guardia Civil de Ibahernando (927 33 00 73). Pregunta por la situación de Javier, si hay alguna novedad, pues quieren informar al Jdo. *Hace días entraron en su vivienda con una Orden Judicial, para comprobar que no estuviera allí. ······························································································································································································· Recibo correos de Alfonso Rodilla, Consulado en Bruselas (alfonso.rodilla@maec.es), al parecer está intentando llamarme, pero no me entran las llamadas... **Respondo y pregunto por la situación. **Volveremos a hablar con la D. Gerencia para que nos intenten facilitar el hacer la llamada. ······························································································································································································ Nuevo correo-e de Alfonso Rodilla, Consulado de España en Bruselas (alfonso.rodilla@maec.es) en respuesta a uno mío: "La última vez que vino al Consulado el Sr Agudo fue el pasado jueves 6 de mayo. Anteriormente ha estado en Francia. En el Consulado de París se le expidió un pasaporte. Se le informó de los centros para personas sin hogar donde podría dormir. Si se volviera a presentar, ruego den indicaciones o mensajes a transmitirle desde la Junta de Extremadura. Saludos cordiales"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='FERNANDEZ'and apellido2='GARCIA'),'2021-05-10','TERESA ENVIO CONSENTIMIETO IFNORMADO DE COLONOSCOPIA AL CAMPF','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2021-05-10','miguel, recibimos email de Mª Guerrero que nos remite a su vez de la letrada de la Junta mariadolores.garcia@juntaex.es con lo siguiente: Buenos dias Maria Espero que te encuentres bien que hace tiempo que no hablamos. Me han asignado el procedimiento que te indico en asunto, sobre una presunta agresión sexual ocurrida en el Centro sociosanitario de Plasencia. Tanto la denuciante como el denunciado están incapacitados legalmente y bajo la tutela de la Comision Tutelar de adultos, a la que ya se ha mandado la poca documentación que nos consta. Por providencia de 29 de abril se requiere a dicha Comision para hacer el ofrecimiento de acciones, por lo que solicito INFORME al respecto indicando si debemos personarnos en dicho procedimiento y ejercitar las correspondientes acciones, puesto que ambos incapacitados dependen de la Comision Tutelar y entiendo que puede haber un conflicto de intereses. Espero pronta respuesta *************************************************** nos reenvía dicho email Mª Guerrero: Buenos días. El pasado jueves me remitieron el presente correo. Desconozco el asunto y si tenéis una posición en concreto. Quedo a la espera de respuesta. Muchas gracias, María Guerrero ************************************************* Angel, me confirma ya ha contestado al juzgado en cuanto a dicho ofrecimiento de acciones: Es el DPA 145/2021, de Margarita Antich. Ya he contestado al Juzgado nº1 Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-05-10','-Amalia : hablo con Gloria ( TS IMSS Bjoz ) sobre el caso . Han promovido la remocion del cargo ellos ,su hija con la que vive no la atiende correctamente . Tiene 4 hijos y están con el P. Familia . Maria quiere ingresar en centro . Quedo con la TS en que me va a enviar solicitud por decreto firmada y se pedirá plaza por emergencia social . No está valorada por dependencia. Preguntaré a los juridicos si es necesario solicitar la autorización judicial .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-05-10','-Amalia : llama la madre de Alejandro , 650632836. Ayer la agredió Alejandro , dice que no puede vivir con ella .Avisó a la policia . Ha pasado la noche en el hostal ,pero allí tampoco quiere estar . Le digo que acuda provisionalmente al Ctro. Hno. pero tampoco quiere ir allí . Quiere que se le compre un piso a su hijo donde pueda vivir. Le digo que el dinero de la herencia de su padre lo están reclamando sus hermanastras y no sabemos con qué dinero se pueda contar . Le pido a la delegada tutelar de Futuex que investigue sobre lo sucedido . Si quisiera tb podría ingresar en el Centro de Camino a la vida , pero el ingreso tiene que ser voluntario .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-05-10','Belén. Declaración de ingresos mensuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-05-10','-Amalia : escrio a Carmen , TS del ESM para saber si hay respuesta de la UHDAC. Buenos dias Carmen , he hablado con la madre de ALEJANDRO NUÑEZ , ayer la agredió y llamó a la policia, dice que su hijo no puede vivir con ella . Ha pasado la noche en el hostal pero tampoco le gusta ese sitio. Le he dicho que acuda al Ctro . Hermano , también lo declina . Insisten en el tema de la compra del piso para él , les informo que el dinero de la herencia del padre no se puede tocar , sus hermanastras están reclamando su parte . No sabemos finalmente de esa cantidad qué le puede quedar. Si quisiera tb podría ingresar en el Centro de Emergencia Social de Drogas de Camino a la vida , en Montijo, para desintoxicación de drogas . Pero el ingreso es totalmente voluntario . Puede también ingresar en otras comunidades terapéuticas , hay una en Badajoz , a nivel privado y podría abonarlo ,pero no creo que quiera empezar el tratamiento. Desde el ESM el psiquiatra solicitó derivación a la UHDAC en Plasencia , han dado alguna respuesta ?. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-10','Ana: Coordinación con May, Secc. Mayores y Clara, Dependencia. *A priori no da perfil. Informo de la conversación mantenida el viernes con la Psiquiatra del Hptal. Virgen del Puerto de Plasencia. ····· Desde la Territorial se coordinarán en relación al informe y diagnóstico. ··························································································································································································· Hablo con Raquel, TS de SSASB, ya ha hablado ella con Pedro y le han enviado algún otro documento que éste le ha pedido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-11','miguel, emails de Damian: Cuando vine de correr me dijo la monitora que se me habia olvidado tomar las pastillas**************************** Cuando fuerzo y se molesta el compañero porque hago mis necesidades en la ducha como hoy en todo el dia me he tenido que cambiar continuamente de ropa interior y exterior porque por mi enfermedad me hago piss de noche y de dia hay momentos que siento muchos gases y las heces fecales que se me salen hoy me ha llevado una monitora que si me aprecia y me acompañó a hacerme una analitica esta mañana dia 10 de mayoa las 8 y media de la mañana y me han sacado sangre para hacerme las pruebas de intolerancia a la la lactosa y si soy celiaco cuando hacen las cosas bien y me siento ayudado por los monitores me siento agradecido y usted don miguel va ha hacer mucho para que intenten echarme de aqui porque no doy problemas.aunque la directora me ha mirado muy serio tenia que entrar al taller de autonomia verde asi se llama el taller y cuando iba a entrar no pude llegar a entrar porque me habia echo caca a ver si podemos pedir otra peticion para que por lo menos me den el grado 1************************* Por mi nueva voluntad le pido mañana que hable con blanca la directora para hacerle saber que mi prima no le importa desplazarme hasta merida para verme por lo tanto y lo que usted que tenga que mover mi prima no me ha pedido que cambie de centro alicia tiene la voluntad que yo siga en plasencia le pido urgentemente por favor que comunique mañana a la directora y al sepad que no quiero cambio de plaza porque ya no me hace falta.tiene usted un corazon de oro el mejor de toda la comision************************** Esta noche del dia 10 al 11 me he orinado 2 veces en la cama a lss 2 y 6 de la mañana.un saludo y buenos dias don miguel digaselo tambien al juez******************************* No comente todavia nada el cambio sigue en pie prefiero irme a merida************************************************ Queria comentarle que me han llamado que he llamado al telefono uno especial del sepad y YA ME HAN DADO LA PLAZA EN MERIDA.****************************************************','2');
