insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCOS'and edp.apellido1='GARRIDO'and apellido2='PEREZ'),'2021-03-17','SALIDA eL 17/03/2021. Participa en una salida terapéutica por el campo junto con otros compañeros y trabajadores, siguiendo todas las medidas de seguridad e higiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2021-03-17','SALIDA El 17/03/2021. Participa en una salida terapéutica por el campo junto con otros compañeros y trabajadores, siguiendo todas las medidas de seguridad e higiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-11','miguel, llama Damian para comunicarme dos cuestiones: 1)Le han llamado del Sepad (Eva) para indicarle que le han concedido plaza en el CRR de Mérida (me dice que no dirá nada hasta que no esté echo en el CRR de Plasencia) Me pide se lo comunique a Ana Matamoros (aquién se lo digo verbalmente) 2)Otra prima suya se pondrá en contacto vía email conmigo para proponernos otro alquiler, comenta que por 550€ a partir de Julio... Le indico que estas cuestiones tiene que verla con la parte económica, no obstante si me llega cualquier email se lo enviaré a la parte económica. Por último me pregunta por la situación actual de la reclamación de desahucio al inquilino. Le comento que cuando sepamos algo se lo diremos ya que la abogada anda en conversaciones con el inquilino. Dice haber recibido al principio dinero del inquilino (no concreta) y teme que el inquilino se lo reclame (como parece que ha hecho ya por teléfono, según el curatelado)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-10','Ana: Correo de Alfonos Rodilla, Consulado de España en Bruselas (alfonso.rodilla@maec.es): "La última vez que vino al Consulado el Sr Agudo fue el pasado jueves 6 de mayo. Anteriormente ha estado en Francia. En el Consulado de París se le expidió un pasaporte. Se le informó de los centros para personas sin hogar donde podría dormir. Si se volviera a presentar, ruego den indicaciones o mensajes a transmitirle desde la Junta de Extremadura. Saludos cordiales"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2016-05-12','Solicitamos al Registro de la Propiedad de Zafra, notas simples de las propiedades de Andrea. Las hemos recibido y las correspondientes a las urbanas, no coinciden con los datos que tenemos del Ayuntamiento. Mañana (13/05/2016), vuelvo a llamar al Ayto de Fuente del Maestre, para hablar con el padron municipal y me lo aclaren.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2016-05-13','Hemos solicitado al Ayuntamiento de Fuente del Maestre, un certificado aclaratorio a cerca de dos propiedades de Andrea. En el Registro de la Propiedad vienen con un domicilio y en el certificado del ibi viene con otro. Consultado con el Ayuntamiento nos indican que se trata de los mismos, pero no coinciden porque el catastro da unos números y el registro de la propiedad otros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-05-11','miguel, llega email del Jzdo de Coria nº1 que es quién asume la inhibición del procedimiento de aprobación de herencia que se estaba tramitando en el jzdo nº2 de Zafra. El procedimiento es el siguiente X15 AUTORIZAC JUD DISPOSIC BS DISCAPAC 95-2021','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-11','Ana: Tras hablar con Alfonso Rodilla, Consulado de España en Bruselas (0032 2 512 89 16); me informa que ha contrastado que pasó previamente por el Consulado de París, donde le expidieron un Pasaporte. Javier expresó haber perdido la cartilla bancaria (cuenta en la oficina de La Caixa de Trujillo) y estar sin dinero. Ha viajado en autobús. ···· Acordamos que nos **enviarán un comunicado desde el Consulado informando acerca de los contactos que han mantenido con Javier. Y si vuelve por allí le informarán acerca de su nueva situación legal y de que sería conveniente que se pusiera en contacto con la CTAEX. ······· Después, tal y como acordamos, le envío el siguiente correo (alfonso.rodilla@maec.es): "Buenas tardes Alfonso, Tal y como hemos hablado, te envío adjunta la siguiente documentación relativa a D. Javier Agudo Cumplido: - Testimonio de Sentencia Firme - Acuerdo de Aceptación del Cargo de Tutor Agradecemos que, en el caso de que vuelva a contactar con vosotros en el Consulado, se lo hagáis llegar, para hacerle conocedor de su nueve situación legal. Ante cualquier cuestión seguimos en contacto. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-05-11','Ana: Llamada de Ana Benavente, TS ESM-Plas.(74955) : ha hablado con Isabel y con la hermana de ésta. Ahora al parecer Isabel se arrepiente de haber renunciado a la plaza, dice que le entró mucho miedo en su día. *Le explico que ya ha perdido la plaza y en todo caso tendría que solicitarla de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-05-11','Ana: llamada de Toni, TS (927 66 30 10 // 22270): Eugenia ha solicitado salir mañana de paseo con Pedro, su pareja, pues acudirá a visitarla. *Saldrá en el horario establecido para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-05-11','email de Juana: Acabo de recibir una llamada del coordinador de Caja Almendralejo en Badajoz, por el caso de Pinna. No quieren que Mercedes siga teniendo cuenta en la entidad, hoy han tenido que llamar a la policía, casi le pega a un compañero, tiene a todas las demás personas de la oficina amenazadas y ya no piensan aguantar durante más tiempo este tipo de actitud. Le he dicho que lo ponga por escrito tanto el incidente de hoy, así como las acciones que van a tomar.... Por otro lado, ayer me llamó, tiene no sé cuantas cosas rotas del piso, yo le he dicho que pida presupuesto porque ya no sé que decirle, dice que cómo todo eso lo tiene que pagar la casera, se lo va a descontar del alquiler o directamente le va a dejar de pagar.. así que en breve también tendremos movida con el piso...además siempre está poniendo en tela de juicio nuestra gestión, lo mismo que le hace a Caja Almendralejo según me acaban de comentar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-05-11','miguel, llama el abuelo Pedro (650632836) para saber cómo va lo de su nieto. Le comento que el otro abogado y yo hemos quedado en hacernos con un certificado del SCH que acredite la relación entre las cuentas de origen y la actual. Al tiempo sigo pendiente que llegue la documentación que Amalia remitió el viernes, y que si encuentro algo más para rebatir al abogado, así lo haría*************************** El abuelo se ha emocionado varias veces porque es consciente que si el curatelado no se deja ayudar no se puede hacer nada. Le comento que los internamientos involuntarios se solicitan al juzgado cuando son tutelas previo informe de psiquiatra y trabajadores sociales. Y que para internar y tratar a una persona no sólo basta con que sea tutela sino que no puede tener dependencia de otras sustancias, ya que sino los psiquiatras no pueden tratarlos, es decir que son personas que si no se dejan ayudar pueden acabar en la cárcel.******************************************* Me comenta que tienen que estar continuamente pagando sus gastos, que se mete en deudas (por ejemplo compra un reloj y tienen ellos que pagarlo. Dicho reloj luego lo revende el curatelado) Le aconsejo que no le paguen nada, en la medida de lo posible, y que le digan que se dirija a la Comisión para cuestiones económicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-05-12','miguel, se pone en contacto su sobrina Evelin tlfno 622253784, pendiente de llamarla porque pide extracto bancario entiendo de su tío para desbloquear cuenta de liberbank','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN SEBASTIAN'and edp.apellido1='CANO'and apellido2='ARROYO'),'2021-05-12','Belén. Consentimiento informado para colonoscopia y sedación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-05-06','Ana: Varios correos-e de Toni-Futuex, con informes y fotos que guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-05-12','Ana: Envío correo-e a Toni-Futuex: "Buenos días Toni, En relación a Antonio Hidalgo Romo, ¿podríais confirmarme si la TS del SSASB ha acordado enviarnos informe social? Es para adjuntarlo al comunicado que se haga al Juzgado junto con el informe vuestro. Dime si es preciso que yo la llame y/o se lo pida por escrito (no sé qué os dijo). En cuanto a la asignación, informarme cuando podáis, si Antonio finalmente acepta catering y si hay posibilidad de ello en su pueblo, así como del presupuesto aproximado de gastos que la compañera elabore con él ( asignaciones para gasto de bolsillo incluidas). Sé que lo ideal sería sacarlo de ese domicilio, pero como no sabemos lo que tardarán en dar respuesta desde el Juzgado, de momento tendremos que intentar cubrir mínimamente sus necesidades básicas…. Aunque hasta el momento él lo haya hecho a su manera…" ··························································································································································································· Envío correo a Miguel y Ángel, Asesores Jurídicos de la CTAEX: "Buenos días compis, ¿cómo ha empezado el martes?? En relación a Antonio Hidalgo Romo, Incapacitado parcialmente “para regir sus bienes”, os paso informe de seguimiento de Futuex y otros documentos: comunicado de salida de prisión y escrito de la CTAEX que se le entregó antes de su salida y con el que se le indicó que debía ponerse en contacto conmigo para establecer un presupuesto aproximado de gastos. Algo que no hizo. No sé le está dando nada desde la CTAEX (no está claro de qué vive además de los alimentos facilitados por Cáritas y Cruz Roja). Ya pedí que elaboren con él un presupuesto de gastos y la opción de catering (al menos de momento que pueda comer medio en condiciones). Las condiciones de la vivienda son totalmente insalubres y hay indicios de consumo de alcohol y otras sustancias tóxicas. Voy a pedir a Toni-Futuex, que nos envíe el informe firmado y sin los documentos que incluye como imagen que se ven fatal, intentaré que me hagan llegar los informe médicos por otra vía. *Le propusieron ingreso por una herida grave en un dedo y se negó (eso sí se lee más o menos bien, podéis verlo). En su expte. hay más fotos guardadas (aunque en las del informe se aprecian bien las condiciones en las que vive). Por otra parte, queremos que la TS del SSASB nos envíe también informe, pues realizó visita conjunta con la Delegada de Futuex. Veremos. En mi opinión hay que comunicarlo al Juzgado, solicitar ampliación de incapacidad e ingreso involuntario. Como podéis leer en la Intranet, hubo poco tiempo para intervenir con él antes de ingresar en prisión. Está valorado por Dependencia, reconocido con un Grado III GRAN DEPENDENCIA. También se le solicitó y concedió plaza residencial en Centro de mayores. Se le reconoció, con fecha 10/01/2017, en el CR El Cuartillo. Ingresó en el mismo pero lo abandonó a fecha de 20/02/2017. *Os paso también Certificados del CADEX y de Dependencia (está todo en su expte. digital, pero así lo tenéis más fácil) Ante cualquier cuestión me vais diciendo. En cuanto tenga el informe nuevo de Futuex, los informes médicos/enfermería y, en su caso, el del SSASB, os lo paso también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-05-12','Ana: Correo de Estrella, TS del CSS-Plas (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. El día 14 de abril presenté en el registro del Sepad de aquí de Plasencia, el PIA de Juan Carlos Ruíz García, te lo digo por si te quieres interesar por cómo va la búsqueda de centro para éste. El día 21 de abril escribí correo con este fin a Manuela González Delgado, a día de hoy no me ha contestado. Intentaré hablar con ella hoy, a ver si tengo suerte.... Gracias." ·················· Mi respuesta: "Buenos días Estrella, Ok. Dime si consigues hablar con ella hoy. Si no, mañana, que estaré en la ofi, me acerco yo en persona a la Unidad y pregunto a la compañera que esté. Seguimos. Buena mañana." ······························································································································································································ Nuevo coreo-e de Estrella: "Me ha contestado al correo, me dice que tiene muchas cosas urgentes y que le cuente algo de él, así que se lo pasé a Maripaz para que informe sobre el funcionamiento del paciente.... De todos modos, si quieres hacer tú un poco de presión también, pues mejor porque si no, se "olvidan" de él y no me parece que tenga que estar aquí encerrado cuando puede estar beneficiándose de vivir en un Centro de Discapacidad, más abierto que lo que le ofrecemos aquí...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-12','Ana: Llamo a Mª Jesús Gómez Lozano, TS SSASB Mancomunidad Comarca Trujillo (621 247 237): Le informo de la conversación de ayer con Alfonso. Ella también habló con él. **La intervención desde la CTAEX con Javier, será complicada mientras no quiera volver. No podemos obligarle ni hacer nada al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-05-12','Ana: Conversación con Mª Jesús Gómez Lozano, TS SSASB Mancomunidad Comarca Trujillo (621 247 237): Isabel, además de tener un carácter fuerte, es muy abierta y sociable, está totalmente adaptada a la Residencia de Jaraicejo y al pueblo en sí, se relaciona con toda la gente, todo el mundo le saluda y le tiene cariño. Le extraña que haya dicho que le entró miedo ante la opción de aceptar la plaza de la residencia de Plasencia, pues una de las cosas que verbalizó el día que hablaron con ella al respecto, fue que no quería que su hermana se enterara de que iba a rechazar, pues le daba miedo que su hermana lo tomara mal y se enfadara con ella. ·························· *En cuanto a la sentencia judicial de orden de alejamiento y abandono del municipio, estamos a la espera de la Audiencia Provincial (recurso interpuesto por la otra parte)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2021-05-12','Belén. Se envía al centro la resolución de ingreso en Centro de Atención a personas con discapacidad.','2');
