insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-05-12','TERESA RECIBO LLAMADA DE LA POLICIA LOCAL MERIDA PARA PREGUNTARNO POR UN COCHE QUE ESTA ABANDONADO EN LA CALLE LEGION V, ESTA SIN SEGURO Y ABANDANADO EL DUEÑO AFIRMA NO TENER LAS LLAVES Y EL SOCIOSANARIO TAMPOCO LAS TIENE DESCONOCEMOS DONDE SE ENCUENRARN LAS LLAVS VALORAMOS LA VENTA DEL VEHICULO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-05-12','Ana: Correo-e de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Hola Ana, te escribo para comentarte la posibilidad de que Conchi Fernández pueda salir al domicilio de la hermana durante este fin de semana para visitar a su hija (se iría viernes 14 y volvería domingo 16). Creemos que es muy importante para ella realizar esta visita, por lo que si estáis de acuerdo pasaremos a planificarla con ella. Espero vuestra respuesta. Un abrazo." ······························································································································································································ Mi respuesta: "Buenos días Paula, Dado que las circunstancias actuales lo permiten y que desde el equipo lo consideráis necesario para ella, por mi parte no hay inconveniente. Podéis proceder. Doy por hecho que insistiréis en que adopte la medidas necesarias frente a la propagación del Covid. Ya me vais informando al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-13','Ana: Recibimos Resolución APROBATORIA de la PFHC: 399,20 € X 12 pagas. Fecha de efectos: 01/07/2021. ······························································································································································································· Maite, TS de Secc. Discapacidad, me trae Resolución de Plaza en VV.TT. y C.O. de INCLUSIVES Vva. Serena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2021-05-13','Belén. Certificado de prestaciones, PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2021-05-13','Ana: Recibimos del INSS notificación de EXTINCIÓN de la PNC, por incompatibilidad con la P.Orfadad concedida. Como se la aprobaron en diciembre pero la fecha de efectos es de 1/09/20, percibió ambas pensiones durate el periodo comprendido entre 01/09 y el 30/11. **Hay que DEVOLVER 1384,60€ de cobro indebido. ***Se lo paso a Alberto, Jefe de Secc. Ecca. CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2021-05-13','-Amalia : para la reforma de la casa hay que pedir autorizacion judicial . Buenos días, Hay que pedir autorización judicial para realizar gastos extraordinarios por importe de 3.500 euros. En el año 2014 ya pedimos autorización para realizar gastos extraordinarios en la casa sita en C/ Federico Garcia Lorca n. 9 de Puebla de la Calzada. Un saludo.Angel ---------------------------------------------------------- Buenas , en otras ocasiones se ha hecho como dice Alberto para evitar pedir esa autorización judicial . Se puede hacer este año unas cosas y el año que viene continuar con la reforma . Si hay que pedir la autorización judicial finalmente podéis iniciarlo . Un saludo','2');
